                (f"{ay} Q1", ay, "Quarter", 1, f"{yr}-01-01", f"{yr}-03-31"),
                (f"{ay} Q2", ay, "Quarter", 2, f"{yr}-04-01", f"{yr}-06-30"),
                (f"{ay} Q3", ay, "Quarter", 3, f"{yr}-07-01", f"{yr}-09-30"),
