sessions = {}

def create_session(user_data):
    sid = str(uuid.uuid4())
    sessions[sid] = {**user_data, 'created': time.time()}
    return sid

def get_session(sid):
    if not sid: return None
    s = sessions.get(sid)
    if s and time.time() - s['created'] < 86400:
        return s
    return None

def get_sid_from_cookie(headers):
    # First check custom header (more reliable cross-browser on localhost)
    sid = headers.get('X-Session-ID', '').strip()
    if sid:
        return sid
    # Fallback to cookie
    cookie = headers.get('Cookie', '')
    for part in cookie.split(';'):
        part = part.strip()
        if part.startswith('sbs_sid='):
            return part[8:]
    return None

# ─── API HANDLERS ─────────────────────────────────────────────────────────────
def api_login(data):
    username = data.get('username', '').strip()
    password = data.get('password', '').strip()
    pw_hash = hashlib.sha256(password.encode()).hexdigest()
    conn = get_db()
    user = conn.execute(
        "SELECT * FROM users WHERE username=? AND password_hash=? AND active=1",
        (username, pw_hash)).fetchone()
    conn.close()
    if user:
        sid = create_session({'id': user['id'], 'username': user['username'],
                              'full_name': user['full_name'], 'role': user['role']})
        return {'ok': True, 'sid': sid, 'user': {
            'username': user['username'], 'full_name': user['full_name'], 'role': user['role']
        }}
    return {'ok': False, 'error': 'Invalid credentials'}

def api_dashboard(session, node=None):
    conn = get_db()
    # Per-unit dashboard: every financial figure is filtered by the viewer's unit
    # scope (and an optional requested node), uniformly through unit_id — so a unit
    # head sees their own unit's position, a provost their college's roll-up, and an
    # Admin / university user the whole institution. Consistent because budgets,
    # projects, commitments and actuals are all unit-attributed.
    def F(alias):
        try:
            return (_ucc_gl_scope_clause(conn, session, node, alias)
                    if '_ucc_gl_scope_clause' in globals() else ('', []))
        except Exception:
            return ('', [])
    pf, pp = F('projects')          # projects table (no alias in query → use table name)
    cf, cp = F('cmt')               # commitments alias
    af, ap = F('actuals')           # actuals table
    qf, qp = F('quarterly_budgets') # quarterly_budgets table
    stats = {}
    stats['total_projects'] = conn.execute("SELECT COUNT(*) FROM projects WHERE 1=1" + pf, pp).fetchone()[0]
    stats['active_projects'] = conn.execute("SELECT COUNT(*) FROM projects WHERE status='Active'" + pf, pp).fetchone()[0]
    _proj_budget = conn.execute("SELECT COALESCE(SUM(budget_ghs),0) FROM projects WHERE status='Active'" + pf, pp).fetchone()[0] or 0
    # Approved departmental quarterly budgets are part of the institution's total
    # allocation ("All departments"). They live in quarterly_budgets, separate from
    # project budgets, and only count once approved through the workflow.
    _qb_budget = 0
    try:
        _qb_budget = conn.execute(
            "SELECT COALESCE(SUM(annual_total),0) FROM quarterly_budgets "
            "WHERE COALESCE(is_deleted,0)=0 AND approval_status='Approved'" + qf, qp).fetchone()[0] or 0
    except Exception:
        _qb_budget = 0
    stats['total_budget_ghs'] = _proj_budget + _qb_budget
    stats['project_budget_ghs'] = _proj_budget
    stats['dept_budget_ghs'] = _qb_budget
    # Quarterly budgets still awaiting approval (shown so uploads are visible pre-approval)
    try:
        stats['pending_budget_ghs'] = conn.execute(
            "SELECT COALESCE(SUM(annual_total),0) FROM quarterly_budgets "
            "WHERE COALESCE(is_deleted,0)=0 AND COALESCE(approval_status,'Draft')<>'Approved'" + qf, qp).fetchone()[0] or 0
    except Exception:
        stats['pending_budget_ghs'] = 0
    stats['total_committed'] = conn.execute("SELECT COALESCE(SUM(MAX(0, cmt.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=cmt.id AND COALESCE(_ax.is_posted,0)=1),0))),0) FROM commitments cmt WHERE COALESCE(cmt.status,'') NOT IN ('Cancelled','Fully Paid')" + cf, cp).fetchone()[0]
    stats['total_actuals'] = conn.execute("SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE 1=1" + af, ap).fetchone()[0]
    stats['fx_gain'] = conn.execute("SELECT COALESCE(SUM(fx_gl_ghs),0) FROM actuals WHERE fx_gl_type='Gain'" + af, ap).fetchone()[0]
    stats['fx_loss'] = conn.execute("SELECT COALESCE(SUM(fx_gl_ghs),0) FROM actuals WHERE fx_gl_type='Loss'" + af, ap).fetchone()[0]

    ppf, ppp = F('p')
    projects = [dict(r) for r in conn.execute("""
        SELECT p.*,
            COALESCE(SUM(CASE WHEN c.status='Open' THEN c.amount_ghs ELSE 0 END),0) as committed_ghs,
            COALESCE((SELECT SUM(amount_ghs) FROM actuals a WHERE a.project_id=p.id),0) as actual_ghs
        FROM projects p
        LEFT JOIN commitments c ON c.project_id=p.id
        WHERE 1=1""" + ppf + """
        GROUP BY p.id ORDER BY p.created_at DESC LIMIT 10
    """, ppp)]

    division_summary = [dict(r) for r in conn.execute("""
        SELECT division,
            COUNT(*) as project_count,
            COALESCE(SUM(budget_ghs),0) as total_budget,
            COALESCE(SUM(CASE WHEN status='Active' THEN budget_ghs ELSE 0 END),0) as active_budget
        FROM projects WHERE 1=1""" + pf + """ GROUP BY division
    """, pp)]

    conn.close()
    return {'stats': stats, 'projects': projects, 'division_summary': division_summary}


# ── API: Quarterly Budgets ─────────────────────────────────────────────────
def api_get_budget_periods(session):
    if not session: return {"error":"Not authenticated"}
    conn = get_db()
    rows = conn.execute("SELECT * FROM budget_periods ORDER BY start_date").fetchall()
    conn.close()
    return [dict(r) for r in rows]

def api_get_quarterly_budgets(session, dept_code=None, academic_year=None):
    if not session: return {"error":"Not authenticated"}
    conn = get_db()
    q = "SELECT qb.*, c.account_name, c.code as account_code FROM quarterly_budgets qb LEFT JOIN chart_of_accounts c ON qb.coa_id=c.id WHERE 1=1"
    params = []
    if dept_code:    q += " AND qb.dept_code=?";      params.append(dept_code)
    if academic_year:q += " AND qb.academic_year=?";  params.append(academic_year)
    q += " ORDER BY qb.dept_code, qb.category, qb.description"
    rows = conn.execute(q, params).fetchall()
    conn.close()
    return [dict(r) for r in rows]

def api_save_quarterly_budget(data, session):
    if not session: return {"error":"Not authenticated"}
    conn = get_db()
    bid = data.get('id') or str(uuid.uuid4())
    conn.execute("""
        INSERT INTO quarterly_budgets
          (id,dept_code,academic_year,period_id,quarter,coa_id,category,description,
           q1_amount,q2_amount,q3_amount,q4_amount,currency,approved_by,notes,created_by)
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        ON CONFLICT(id) DO UPDATE SET
          category=excluded.category, description=excluded.description,
          q1_amount=excluded.q1_amount, q2_amount=excluded.q2_amount,
          q3_amount=excluded.q3_amount, q4_amount=excluded.q4_amount,
          notes=excluded.notes, approved_by=excluded.approved_by
    """, (bid, data['dept_code'], data.get('academic_year','2025/2026'),
          data.get('period_id'), data.get('quarter'),
          data.get('coa_id'), data.get('category',''),
          data.get('description',''), float(data.get('q1_amount',0)),
          float(data.get('q2_amount',0)), float(data.get('q3_amount',0)),
          float(data.get('q4_amount',0)), data.get('currency','GHS'),
          data.get('approved_by',''), data.get('notes',''),
          session.get('username','')))
    conn.commit(); conn.close()
    return {"ok": True, "id": bid}

def api_delete_quarterly_budget(bid, session):
    if not session: return {"error":"Not authenticated"}
    if session.get('role') not in ('Admin','Finance Officer'):
        return {"error":"Insufficient permissions"}
    conn = get_db()
    conn.execute("DELETE FROM quarterly_budgets WHERE id=?", (bid,))
    conn.commit(); conn.close()
    return {"ok": True}

def _ensure_budget_upload_batch_id(conn):
    """Idempotently add batch_id to budget_uploads so uploaded batches can be rolled back."""
    try:
        cols = [r['name'] for r in conn.execute("PRAGMA table_info(budget_uploads)").fetchall()]
        if 'batch_id' not in cols:
            conn.execute("ALTER TABLE budget_uploads ADD COLUMN batch_id TEXT")
            conn.commit()
    except Exception:
        pass

def api_upload_budget(data, session):
    """Parse uploaded budget data (from Excel/CSV parsed client-side) and bulk insert."""
    if not session: return {"error":"Not authenticated"}
    if session.get('role') not in ('Admin','Finance Officer'):
        return {"error":"Insufficient permissions"}
    rows = data.get('rows', [])
    dept_code = data.get('dept_code','')
    academic_year = data.get('academic_year','2025/2026')
    if not rows: return {"error":"No rows to import"}

    conn = get_db()
    _ensure_budget_upload_batch_id(conn)
    batch_id = str(uuid.uuid4())
    upload_id = str(uuid.uuid4())
    imported = 0; failed = 0; errors = []

    for i, row in enumerate(rows):
        try:
            # Resolve COA code to ID — auto-create if missing
            coa_id = None
            if row.get('account_code'):
                r_coa = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?",
                                 (str(row['account_code']).strip(),)).fetchone()
                if r_coa: coa_id = r_coa[0]
            # Auto-assign COA if no code provided but we have account_name/category
            if not coa_id and row.get('description'):
                try:
                    auto_code, _, _, _ = auto_assign_coa_code(
                        row.get('description',''),
                        row.get('category',''),
                        'Expense',
                        row.get('sub_category',''),
                        conn
                    )
                    # Check if this code exists
                    r_ac = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?",
                                       (auto_code,)).fetchone()
                    if r_ac:
                        coa_id = r_ac[0]
                    else:
                        # Create it
                        new_coa_id = str(uuid.uuid4())
                        conn.execute(
                            """INSERT INTO chart_of_accounts
                               (id,code,account_name,account_type,category,sub_category,
                                description,is_active,created_by)
                               VALUES(?,?,?,?,?,?,?,1,?)""",
                            (new_coa_id, auto_code, row.get('description',''),
                             'Expense', row.get('category','Miscellaneous'),
                             row.get('sub_category',''),
                             f"Auto-created via budget upload",
                             session.get('username','system'))
                        )
                        conn.commit()
                        coa_id = new_coa_id
                except Exception:
                    pass  # Continue without COA link
            conn.execute("""
                INSERT INTO quarterly_budgets
                  (id,dept_code,academic_year,coa_id,category,description,
                   q1_amount,q2_amount,q3_amount,q4_amount,currency,approved_by,notes,upload_batch,created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """, (str(uuid.uuid4()),
                  row.get('dept_code', dept_code),
                  row.get('academic_year', academic_year),
                  coa_id,
                  row.get('category',''),
                  row.get('description',''),
                  float(row.get('q1_amount',0) or 0),
                  float(row.get('q2_amount',0) or 0),
                  float(row.get('q3_amount',0) or 0),
                  float(row.get('q4_amount',0) or 0),
                  row.get('currency','GHS'),
                  row.get('approved_by',''),
                  row.get('notes',''),
                  batch_id,
                  session.get('username','')))
            imported += 1
        except Exception as e:
            failed += 1
            errors.append(f"Row {i+2}: {str(e)}")

    conn.execute("""
        INSERT INTO budget_uploads(id,filename,dept_code,academic_year,rows_imported,rows_failed,status,error_log,batch_id,uploaded_by)
        VALUES(?,?,?,?,?,?,?,?,?,?)
    """, (upload_id, data.get('filename','upload.xlsx'), dept_code, academic_year,
          imported, failed, 'Success' if failed==0 else 'Partial',
          '\n'.join(errors[:20]) if errors else None, batch_id, session.get('username','')))
    conn.commit(); conn.close()
    return {"ok": True, "imported": imported, "failed": failed, "errors": errors[:5], "batch_id": batch_id}

def api_quarterly_performance(session, dept_code=None, academic_year=None, quarter=None):
    """Quarterly performance: budget vs actuals vs variance."""
    if not session: return {"error":"Not authenticated"}
    conn = get_db()
    ay = academic_year or '2025/2026'
    q = int(quarter) if quarter else None

    # Get quarterly budgets
    budgets = conn.execute("""
        SELECT qb.dept_code, d.dept_name, qb.category, qb.description,
               qb.q1_amount, qb.q2_amount, qb.q3_amount, qb.q4_amount, qb.annual_total,
               c.account_name, c.code as account_code
        FROM quarterly_budgets qb
        LEFT JOIN departments d ON qb.dept_code=d.dept_code
        LEFT JOIN chart_of_accounts c ON qb.coa_id=c.id
        WHERE qb.academic_year=?
        """ + (" AND qb.dept_code=?" if dept_code else ""),
        [ay] + ([dept_code] if dept_code else [])
    ).fetchall()

    # Get actuals by quarter (based on expense date)
    actuals_q = conn.execute("""
        SELECT p.division as dept_code,
               c.sub_category as category,
               CASE
                 WHEN strftime('%m', a.expense_date) IN ('01','02','03') THEN 1
                 WHEN strftime('%m', a.expense_date) IN ('04','05','06') THEN 2
                 WHEN strftime('%m', a.expense_date) IN ('07','08','09') THEN 3
                 ELSE 4
               END as quarter,
               SUM(a.amount_ghs) as actual_amount
        FROM actuals a
        INNER JOIN projects p ON a.project_id=p.id
        LEFT JOIN budgets bud ON a.budget_id=bud.id
        LEFT JOIN chart_of_accounts c ON bud.coa_id=c.id
        WHERE strftime('%Y', a.expense_date) = substr(?, 1, 4)
        """ + (" AND p.division=?" if dept_code else "") + """
        GROUP BY p.division, c.sub_category, quarter
    """, [ay[:4]] + ([dept_code] if dept_code else [])).fetchall()

    # Build actuals lookup: {(dept_code, category, quarter): amount}
    actuals_map = {}
    for row in actuals_q:
        key = (row['dept_code'], row['category'] or '', row['quarter'])
        actuals_map[key] = actuals_map.get(key, 0) + (row['actual_amount'] or 0)

    result = []
    for b in budgets:
        row_data = dict(b)
        for qi in [1,2,3,4]:
            budget_q = b[f'q{qi}_amount'] or 0
            actual_q = actuals_map.get((b['dept_code'], b['category'], qi), 0)
            variance_q = budget_q - actual_q
            pct_q = (actual_q/budget_q*100) if budget_q > 0 else 0
            row_data[f'actual_q{qi}'] = actual_q
            row_data[f'variance_q{qi}'] = variance_q
            row_data[f'pct_q{qi}'] = round(pct_q, 1)
        result.append(row_data)

    conn.close()
    return result

def api_get_budget_uploads(session):
    if not session: return {"error":"Not authenticated"}
