def api_delete_budget_upload(upload_id, session):
    """DELETE /api/budget-uploads/<id> — rollback an uploaded quarterly budget batch."""
    if not session: return {"ok": False, "error": "Not authenticated"}
    if session.get('role') not in ('Admin','Finance Officer'):
        return {"ok": False, "error": "Insufficient permissions"}
    if not upload_id:
        return {"ok": False, "error": "No upload ID provided"}
    conn = get_db()
    _ensure_budget_upload_batch_id(conn)
    row = conn.execute("SELECT * FROM budget_uploads WHERE id=?", (upload_id,)).fetchone()
    if not row:
        conn.close()
        return {"ok": False, "error": "Budget upload not found"}
    keys = row.keys() if hasattr(row, 'keys') else []
    batch_id = row['batch_id'] if 'batch_id' in keys else None
    deleted_rows = 0
    if batch_id:
        cur = conn.execute("DELETE FROM quarterly_budgets WHERE upload_batch=?", (batch_id,))
        deleted_rows = cur.rowcount if cur.rowcount is not None and cur.rowcount >= 0 else 0
    conn.execute("DELETE FROM budget_uploads WHERE id=?", (upload_id,))
    try:
        _audit(conn, session, 'DELETE_BUDGET_UPLOAD', 'budget_uploads', upload_id,
               f"{row['filename']} | removed {deleted_rows} imported quarterly budget line(s)")
    except Exception:
        pass
    conn.commit(); conn.close()
    if batch_id:
        return {"ok": True, "deleted_rows": deleted_rows,
                "message": f"Upload deleted; {deleted_rows} imported budget line(s) removed."}
    return {"ok": True, "deleted_rows": 0,
            "message": "Upload log deleted. No batch id was stored for this older upload, so imported lines were not auto-removed."}


