def auto_assign_coa_code(account_name, category, account_type, sub_category, conn):
    """
    Auto-assign next available COA code based on category/type mapping.
    Returns (code, range_start, range_end) or raises ValueError.
    """
    # Build lookup key from category + sub_category + account_type
    keys_to_try = []
    for val in [sub_category, category, account_type, account_name]:
        if val:
            keys_to_try.append(val.lower().strip())
            # Also try first word
            keys_to_try.append(val.lower().strip().split()[0] if val.strip() else '')

    range_start, range_end = None, None
    matched_key = None

    for key in keys_to_try:
        if key in COA_RANGES:
            range_start, range_end = COA_RANGES[key]
            matched_key = key
            break
        # Partial match - check if key starts with any COA range key
        for coa_key in COA_RANGES:
            if coa_key in key or key in coa_key:
                range_start, range_end = COA_RANGES[coa_key]
                matched_key = coa_key
                break
        if range_start:
            break

    if not range_start:
        # Default to miscellaneous expense
        range_start, range_end = 6700, 6799
        matched_key = 'miscellaneous'

    # Find next available code in range
    existing = {
        int(r[0]) for r in conn.execute(
            "SELECT code FROM chart_of_accounts WHERE CAST(code AS INTEGER) BETWEEN ? AND ?",
            (range_start, range_end)
        ).fetchall()
        if r[0].isdigit()
    }

    # Find first gap
    code = None
    for candidate in range(range_start, range_end + 1):
        if candidate not in existing:
            code = str(candidate)
            break

    if not code:
        raise ValueError(f"No available code in range {range_start}-{range_end} for category '{matched_key}'")

    return code, range_start, range_end, matched_key


def api_auto_assign_coa(data, session):
    """
    Auto-assign COA code and optionally create the account.
    Input: dept_code, account_name, category, account_type, sub_category
    Optional: create=True to also insert into COA
    Returns: code, range, matched_key, created (bool)
    """
    if not session:
        return {"error": "Not authenticated"}

    account_name  = data.get('account_name', '').strip()
    category      = data.get('category', '').strip()
    account_type  = data.get('account_type', '').strip()
    sub_category  = data.get('sub_category', '').strip()
    dept_code     = data.get('dept_code', '').strip()
    create        = data.get('create', False)

    if not account_name:
        return {"error": "account_name is required"}

    conn = get_db()
    try:
        # Check if account already exists (same name + same type)
        existing = conn.execute(
            """SELECT id, code, account_name FROM chart_of_accounts
               WHERE LOWER(account_name) = LOWER(?) LIMIT 1""",
            (account_name,)
        ).fetchone()

        if existing:
            return {
                "ok": True,
                "code": existing["code"],
                "account_name": existing["account_name"],
                "coa_id": existing["id"],
                "created": False,
                "message": f"Account already exists with code {existing['code']}"
            }

        code, range_start, range_end, matched_key = auto_assign_coa_code(
            account_name, category, account_type, sub_category, conn
        )

        result = {
            "ok": True,
            "code": code,
            "range": f"{range_start}–{range_end}",
            "matched_category": matched_key,
            "account_name": account_name,
            "created": False
        }

        if create:
            coa_id = str(__import__('uuid').uuid4())
            conn.execute(
                "INSERT INTO chart_of_accounts (id,code,account_name,account_type,category,sub_category) VALUES(?,?,?,?,?,?)",
                (coa_id, code, account_name,
                 account_type or _infer_account_type(matched_key),
                 category or matched_key.title(),
                 sub_category or '')
            )
            conn.commit()
            result["created"] = True
            result["coa_id"] = coa_id
            result["message"] = f"Account {code} created and added to Chart of Accounts"
        else:
            result["message"] = f"Suggested code: {code} (not yet saved — pass create:true to save)"

        return result

    except Exception as e:
        return {"error": str(e)}
    finally:
        conn.close()


def api_bulk_auto_coa(data, session):
    """
    Bulk auto-assign COA codes for multiple accounts.
    Input: rows = [{account_name, category, account_type, sub_category, dept_code}]
    Returns: results with assigned codes + created accounts
    """
    if not session:
        return {"error": "Not authenticated"}

    rows = data.get('rows', [])
    if not rows:
        return {"error": "No rows provided"}

    create = data.get('create', True)
    conn = get_db()
    results = []

    for i, row in enumerate(rows):
        try:
            account_name  = row.get('account_name', '').strip()
            category      = row.get('category', '').strip()
            account_type  = row.get('account_type', '').strip()
            sub_category  = row.get('sub_category', '').strip()
            dept_code     = row.get('dept_code', '').strip()

            if not account_name:
                results.append({"row": i+1, "error": "Missing account_name", "input": row})
                continue

            # Check existing
            existing = conn.execute(
                "SELECT id, code FROM chart_of_accounts WHERE LOWER(account_name)=LOWER(?)",
                (account_name,)
            ).fetchone()

            if existing:
                results.append({
                    "row": i+1, "code": existing["code"],
                    "coa_id": existing["id"], "account_name": account_name,
                    "created": False, "message": "Already in COA"
                })
                continue

            code, range_start, range_end, matched_key = auto_assign_coa_code(
                account_name, category, account_type, sub_category, conn
            )

            if create:
                coa_id = str(__import__('uuid').uuid4())
                conn.execute(
                    "INSERT INTO chart_of_accounts (id,code,account_name,account_type,category,sub_category) VALUES(?,?,?,?,?,?)",
                    (coa_id, code, account_name,
                     account_type or _infer_account_type(matched_key),
                     category or matched_key.title(),
                     sub_category or '')
                )
                conn.commit()
                results.append({
                    "row": i+1, "code": code, "coa_id": coa_id,
                    "account_name": account_name, "created": True,
                    "matched_category": matched_key,
                    "message": f"Created {code}"
                })
            else:
                results.append({
                    "row": i+1, "code": code, "account_name": account_name,
                    "created": False, "matched_category": matched_key,
                    "message": f"Suggested: {code}"
                })

        except Exception as e:
            results.append({"row": i+1, "error": str(e), "input": row})

    conn.close()
    created  = sum(1 for r in results if r.get('created'))
    existing = sum(1 for r in results if r.get('created') == False and 'code' in r)
    errors   = sum(1 for r in results if 'error' in r)

    return {
        "ok": True,
        "results": results,
        "summary": {"total": len(rows), "created": created, "existing": existing, "errors": errors}
    }


def _infer_account_type(matched_key):
    """Infer account type from matched COA range key."""
    income_keys = {'revenue','income','grant income','subvention','getfund','igf','fees',
                   'tuition','consultancy','interest income','grant','donor'}
    asset_keys  = {'asset','cash','bank','receivable','inventory','prepayment','fixed asset','ppe'}
    liab_keys   = {'liability','payable','accrual','tax payable','deferred','loan'}
    equity_keys = {'net asset','equity','reserve','surplus','deficit','restricted fund'}
    if matched_key in income_keys: return 'Income'
    if matched_key in asset_keys:  return 'Asset'
    if matched_key in liab_keys:   return 'Liability'
    if matched_key in equity_keys: return 'Net Asset'
    return 'Expense'  # default

def api_get_departments(session):
    if not session: return {"error":"Not authenticated"}
    conn = get_db()
    rows = conn.execute("""
        SELECT d.*,
          COALESCE((SELECT SUM(a.amount_ghs) FROM dept_allocations a WHERE a.dept_code=d.dept_code),0)
          + COALESCE((SELECT SUM(qb.annual_total) FROM quarterly_budgets qb
                WHERE qb.dept_code=d.dept_code AND COALESCE(qb.is_deleted,0)=0 AND qb.approval_status='Approved'),0) as total_allocated,
          COALESCE((SELECT SUM(ac.amount_ghs) FROM actuals ac
            INNER JOIN projects p ON ac.project_id=p.id WHERE p.division=d.dept_code),0) as total_spent,
          COALESCE((SELECT SUM(cm.amount_ghs) FROM commitments cm
            INNER JOIN projects p2 ON cm.project_id=p2.id WHERE p2.division=d.dept_code),0) as total_committed,
          COALESCE((SELECT COUNT(*) FROM projects p WHERE p.division=d.dept_code AND p.status='Active'),0) as active_grants
        FROM departments d ORDER BY d.dept_code
    """).fetchall()
    conn.close()
    return [dict(r) for r in rows]

def api_save_department(data, session):
    if not session: return {"error":"Not authenticated"}
    if session.get('role') not in ('Admin','Finance Officer'):
        return {"error":"Insufficient permissions"}
    conn = get_db()
    dept_id = data.get('id') or str(uuid.uuid4())
    conn.execute("""
        INSERT INTO departments(id,dept_code,dept_name,head_name,head_email,total_allocation,academic_year,status,notes)
        VALUES(?,?,?,?,?,?,?,?,?)
        ON CONFLICT(id) DO UPDATE SET
          dept_name=excluded.dept_name,head_name=excluded.head_name,
          head_email=excluded.head_email,total_allocation=excluded.total_allocation,
          academic_year=excluded.academic_year,status=excluded.status,notes=excluded.notes
    """, (dept_id, data['dept_code'], data['dept_name'], data.get('head_name',''),
          data.get('head_email',''), data.get('total_allocation',0),
          data.get('academic_year','2025/2026'), data.get('status','Active'), data.get('notes','')))
    # Mirror into org_units (keyed on code) so newly added departments/units also
    # appear in the UCC organisational tree. Additive and best-effort: a failure
    # here must never block the legacy department save (which feeds the
    # projects.division join graph). unit_type/parent_code are optional hints.
    try:
        _upsert_org_unit(conn, {
            'code': data['dept_code'],
            'name': data['dept_name'],
            'unit_type': data.get('unit_type'),
            'parent_code': data.get('parent_code') if 'parent_code' in data else None,
            'head_name': data.get('head_name', ''),
            'head_title': data.get('head_title', ''),
            'head_email': data.get('head_email', ''),
            'status': data.get('status', 'Active'),
        })
    except Exception as _mirror_exc:
        print('  org_units mirror warning:', _mirror_exc)
    conn.commit(); conn.close()
    return {"ok": True, "id": dept_id}

