def api_dept_summary(session):
    if not session: return {"error":"Not authenticated"}
    conn = get_db()
    rows = conn.execute("""
        SELECT d.dept_code, d.dept_name, d.head_name,
          COALESCE((SELECT SUM(a.amount_ghs) FROM dept_allocations a WHERE a.dept_code=d.dept_code),0)
          + COALESCE((SELECT SUM(qb.annual_total) FROM quarterly_budgets qb
                WHERE qb.dept_code=d.dept_code AND COALESCE(qb.is_deleted,0)=0 AND qb.approval_status='Approved'),0) as allocated,
          COALESCE((SELECT SUM(ac.amount_ghs) FROM actuals ac
            INNER JOIN projects p ON ac.project_id=p.id WHERE p.division=d.dept_code),0) as spent,
          COALESCE((SELECT SUM(cm.amount_ghs) FROM commitments cm
            INNER JOIN projects p2 ON cm.project_id=p2.id WHERE p2.division=d.dept_code),0) as committed,
          COALESCE((SELECT COUNT(*) FROM projects p WHERE p.division=d.dept_code AND p.status='Active'),0) as active_grants,
          COALESCE((SELECT SUM(p.budget_ghs) FROM projects p WHERE p.division=d.dept_code),0) as grant_budget
        FROM departments d WHERE d.status='Active' ORDER BY d.dept_code
    """).fetchall()
    conn.close()
    return [dict(r) for r in rows]

def api_get_projects(session, params=None):
    conn = get_db()
    rows = [dict(r) for r in conn.execute("""
        SELECT p.*,
            COALESCE(SUM(CASE WHEN c.status='Open' THEN c.amount_ghs ELSE 0 END),0) as committed_ghs,
            COALESCE((SELECT SUM(amount_ghs) FROM actuals a WHERE a.project_id=p.id),0) as actual_ghs,
            COALESCE((SELECT SUM(budget_ghs) FROM budgets b WHERE b.project_id=p.id),0) as budgeted_ghs
        FROM projects p
        LEFT JOIN commitments c ON c.project_id=p.id
        GROUP BY p.id ORDER BY p.created_at DESC
    """)]
    conn.close()
    return rows

def api_save_project(data, session):
    conn = get_db()
    pid = data.get('id') or str(uuid.uuid4())
    pcode = data.get('project_code') or f"UCC-{datetime.now().year}-{str(uuid.uuid4())[:3].upper()}"
    budget_ghs = float(data.get('budget_fcy', 0)) * float(data.get('fx_rate', 1))
    if data.get('id'):
        conn.execute("""UPDATE projects SET title=?,donor=?,division=?,start_date=?,end_date=?,
            currency=?,budget_fcy=?,fx_rate=?,budget_ghs=?,status=?,pi_name=?,notes=?
            WHERE id=?""", (data.get('title',''),data.get('donor',''),data.get('division',''),data.get('start_date',''),
            data.get('end_date',''),data.get('currency','GHS'),float(data.get('budget_fcy',0) or 0),float(data.get('fx_rate',1) or 1),
            budget_ghs,data.get('status','Active'),data.get('pi_name',''),data.get('notes',''),pid))
        action = 'UPDATE_PROJECT'
    else:
        conn.execute("""INSERT INTO projects(id,project_code,title,donor,division,start_date,end_date,
            currency,budget_fcy,fx_rate,budget_ghs,status,pi_name,notes,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (pid,pcode,data.get('title',''),data.get('donor',''),data.get('division',''),data.get('start_date',''),
             data.get('end_date',''),data.get('currency','GHS'),float(data.get('budget_fcy',0) or 0),float(data.get('fx_rate',1) or 1),
             budget_ghs,data.get('status','Active'),data.get('pi_name',''),data.get('notes',''),session['username']))
        action = 'CREATE_PROJECT'
    _audit(conn, session, action, 'projects', pid, data.get('title',''))
    conn.commit(); conn.close()
    return {'ok': True, 'id': pid}

def api_get_budgets(session, project_id=None):
    conn = get_db()
    q = """SELECT b.*, p.project_code, p.title as project_title, p.currency as proj_currency,
        c.code as coa_code, c.account_name, c.category,
        COALESCE((SELECT SUM(MAX(0, cm.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=cm.id AND COALESCE(_ax.is_posted,0)=1),0))) FROM commitments cm WHERE cm.budget_id=b.id AND COALESCE(cm.status,'') NOT IN ('Cancelled','Fully Paid')),0) as committed_ghs,
        COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id),0) as actual_ghs
        FROM budgets b
        JOIN projects p ON b.project_id=p.id
        JOIN chart_of_accounts c ON b.coa_id=c.id"""
    args = []
    if project_id:
        q += " WHERE b.project_id=?"
        args.append(project_id)
    q += " ORDER BY b.created_at"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows

def api_save_budget(data, session):
    conn = get_db()
    try:
        bid = data.get('id') or str(uuid.uuid4())
        bcode = data.get('budget_code') or f"BDG-{str(uuid.uuid4())[:6].upper()}"
        if not data.get('coa_id'):
            return err('Select a chart-of-accounts (expense) line for this budget.')
        budget_ghs = float(data['budget_fcy']) * float(data['fx_rate'])
        if data.get('id'):
            conn.execute("""UPDATE budgets SET project_id=?,coa_id=?,budget_fcy=?,currency=?,fx_rate=?,budget_ghs=?,notes=?
                WHERE id=?""", (data['project_id'],data['coa_id'],float(data['budget_fcy']),
                data['currency'],float(data['fx_rate']),budget_ghs,data.get('notes',''),bid))
        else:
            conn.execute("""INSERT INTO budgets(id,budget_code,project_id,coa_id,budget_fcy,currency,fx_rate,budget_ghs,notes)
                VALUES(?,?,?,?,?,?,?,?,?)""",
                (bid,bcode,data['project_id'],data['coa_id'],float(data['budget_fcy']),
                 data['currency'],float(data['fx_rate']),budget_ghs,data.get('notes','')))
        _audit(conn, session, 'SAVE_BUDGET', 'budgets', bid, f"Project {data['project_id']}")
        conn.commit()
        return {'ok': True, 'id': bid}
    except Exception as _e:
        try: conn.rollback()
        except Exception: pass
        return err('Budget save failed: ' + str(_e))
    finally:
        try: conn.close()
        except Exception: pass

def api_get_commitments(session, project_id=None):
    conn = get_db()
    q = """SELECT c.*, p.project_code, p.title as project_title,
        b.budget_code, coa.account_name, coa.code as coa_code
        FROM commitments c
        JOIN projects p ON c.project_id=p.id
        LEFT JOIN budgets b ON c.budget_id=b.id
        LEFT JOIN chart_of_accounts coa ON b.coa_id=coa.id"""
    args = []
    if project_id:
        q += " WHERE c.project_id=?"
        args.append(project_id)
    q += " ORDER BY c.created_at DESC"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows

def api_save_commitment(data, session):
    conn = get_db()
    cid = data.get('id') or str(uuid.uuid4())
    ccode = data.get('commit_code') or f"CMT-{str(uuid.uuid4())[:6].upper()}"
    division = data.get('dept') or data.get('division') or ''
    # project_id is optional - find or create a "General Fund" project for dept
    if not data.get('project_id') and division:
        conn_tmp = get_db()
        proj = conn_tmp.execute("SELECT id FROM projects WHERE division=? AND status='Active' LIMIT 1", (division,)).fetchone()
        if not proj:
            # Create a General Fund project for this department
            gf_id = str(uuid.uuid4())
            gf_code = f"GF-{division[:4].upper()}"
            conn_tmp.execute("""INSERT OR IGNORE INTO projects
                (id,project_code,title,division,donor,currency,budget_fcy,fx_rate,budget_ghs,
                 start_date,end_date,status,created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (gf_id, gf_code, f"General Fund — {division}",
                 division, 'UCC/GETFund', 'GHS', 0, 1.0, 0,
                 '2024-01-01', '2030-12-31', 'Active', session.get('username','system')))
            conn_tmp.commit()
            data['project_id'] = gf_id
        else:
            data['project_id'] = proj['id']
        conn_tmp.close()

    # Budget availability check
    if data.get('budget_id'):
        budg = conn.execute("""SELECT b.budget_ghs,
            COALESCE(SUM(CASE WHEN c.status='Open' THEN c.amount_ghs ELSE 0 END),0) as committed,
            COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id),0) as actual
            FROM budgets b LEFT JOIN commitments c ON c.budget_id=b.id AND c.status='Open'
            WHERE b.id=? GROUP BY b.id""", (data['budget_id'],)).fetchone()
        if budg:
            available = budg['budget_ghs'] - budg['committed'] - budg['actual']
            new_amt = float(data['amount_fcy']) * float(data['fx_rate'])
            if new_amt > available and session['role'] != 'Admin':
                conn.close()
                return {'ok': False, 'error': f'Insufficient budget. Available: GHS {available:,.2f}'}

    amount_ghs = float(data['amount_fcy']) * float(data['fx_rate'])
    if data.get('id'):
        conn.execute("""UPDATE commitments SET project_id=?,budget_id=?,commit_date=?,vendor=?,
            description=?,currency=?,amount_fcy=?,fx_rate=?,amount_ghs=?,reference=?,status=?
            WHERE id=?""", (data['project_id'],data.get('budget_id'),data['commit_date'],
            data['vendor'],data['description'],data['currency'],float(data['amount_fcy']),
            float(data['fx_rate']),amount_ghs,data.get('reference',''),data.get('status','Open'),cid))
    else:
        conn.execute("""INSERT INTO commitments(id,commit_code,project_id,budget_id,commit_date,
            vendor,description,currency,amount_fcy,fx_rate,amount_ghs,reference,status,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (cid,ccode,data.get('project_id'),data.get('budget_id'),data.get('commit_date') or str(__import__('datetime').date.today()),
             data['vendor'],data['description'],data['currency'],float(data['amount_fcy']),
             float(data['fx_rate']),amount_ghs,data.get('reference',''),'Open',session['username']))
    _audit(conn, session, 'SAVE_COMMITMENT', 'commitments', cid, data.get('description',''))
    conn.commit(); conn.close()
    return {'ok': True, 'id': cid}

def api_get_actuals(session, project_id=None):
    conn = get_db()
    q = """SELECT a.*, p.project_code, p.title as project_title,
        b.budget_code, coa.account_name, coa.code as coa_code,
        cm.commit_code
        FROM actuals a
        JOIN projects p ON a.project_id=p.id
        LEFT JOIN budgets b ON a.budget_id=b.id
        LEFT JOIN chart_of_accounts coa ON b.coa_id=coa.id
        LEFT JOIN commitments cm ON a.commitment_id=cm.id"""
    args = []
    if project_id:
        q += " WHERE a.project_id=?"
        args.append(project_id)
    q += " ORDER BY a.created_at DESC"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows

def _settle_commitment(conn, commitment_id):
    """Close a commitment as 'Fully Paid' ONLY when cumulative POSTED payments settle it.
    A partial payment leaves the status unchanged (Open/Approved) so its unpaid balance
    stays encumbered against the budget; replaces the old unconditional 'Fully Paid' flip
    that released the unpaid portion on the very first (possibly partial) payment."""
    if not commitment_id:
        return
    try:
        r = conn.execute("SELECT amount_ghs FROM commitments WHERE id=?", (commitment_id,)).fetchone()
        if not r:
            return
        amt = float(r['amount_ghs'] or 0)
        paid = conn.execute("SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE commitment_id=? AND COALESCE(is_posted,0)=1", (commitment_id,)).fetchone()[0] or 0
        if amt > 0 and float(paid) >= amt - 0.01:
            conn.execute("UPDATE commitments SET status='Fully Paid' WHERE id=?", (commitment_id,))
    except Exception:
        pass

def api_save_actual(data, session):
    conn = get_db()
    aid = data.get('id') or str(uuid.uuid4())
    acode = data.get('actual_code') or f"ACT-{str(uuid.uuid4())[:6].upper()}"

    pay_fx = float(data.get('pay_fx_rate', 1))
    commit_fx = float(data.get('commit_fx_rate', pay_fx))
    amount_fcy = float(data['amount_fcy'])
    amount_ghs = amount_fcy * pay_fx
    currency = data.get('currency', 'GHS')

    fx_gl = 0; fx_type = 'None'
    if currency != 'GHS':
        fx_gl = abs(amount_fcy * pay_fx - amount_fcy * commit_fx)
        fx_type = 'Loss' if pay_fx > commit_fx else ('Gain' if pay_fx < commit_fx else 'None')

    has_vat   = int(data.get('has_vat', 0))
    has_whvat = int(data.get('has_whvat', 0))

    # ── Tax calculation ──────────────────────────────────────────────────────
    # VAT + WHVAT both set:
    #   Amount entered is VAT-INCLUSIVE.  ex-VAT = amount_ghs / 1.2
    #   VAT is embedded — vat_amount stores the extracted VAT component.
    #   Net Payable = amount_ghs (VAT-incl.) − WHVAT − WHT − UCF
    #
    # VAT only (no WHVAT):
    #   Amount entered is ex-VAT.  VAT 20% is an add-on.
    #   ex-VAT base = amount_ghs.  vat_amount = amount_ghs * 0.20
    #   Net Payable = amount_ghs + vat_amount − WHT − UCF
    #
    # Neither:
    #   Net Payable = amount_ghs − WHT − UCF
    # ─────────────────────────────────────────────────────────────────────────

    ex_vat = round(amount_ghs / 1.2, 4) if has_whvat else amount_ghs

    # VAT amount: extracted component when WHVAT, add-on when VAT only
    vat_amount = round(amount_ghs - ex_vat, 2) if has_whvat else (round(amount_ghs * 0.20, 2) if has_vat else 0)

    # WHVAT = 7% of ex-VAT base → Acc 21100024 VAT Withholding (WHVAT Payable)
    whvat_amount = round(ex_vat * 0.07, 2) if has_whvat else 0

    # WHT = rate% of ex-VAT base → Acc 21100014 Ghana Revenue Authority (WHT)
    wht_type = data.get('wht_type', 'None')
    wht_rate_map = {'None':0,'WHT-Goods':0.03,'WHT-Service':0.075,'WHT-Income':0.10,
                    'WHT-Sitting':0.20,'WHT-Works':0.05}
    wht_rate = wht_rate_map.get(wht_type, 0)
    wht_amount = round(ex_vat * wht_rate, 2)

    # UCF = 5% of (ex-VAT − WHT − WHVAT) → Acc 21100027 UCC Common Fund
    has_ucf = int(data.get('has_ucf', 0))
    ucf_base = ex_vat - wht_amount - whvat_amount
    ucf_amount = round(max(0, ucf_base) * 0.05, 2) if has_ucf else 0

    # VAT add-on (only when VAT-exclusive invoice, i.e. VAT checked but WHVAT not)
    vat_addon = vat_amount if (has_vat and not has_whvat) else 0

    conn.execute("""INSERT OR REPLACE INTO actuals(id,actual_code,project_id,budget_id,commitment_id,
        expense_date,payee,description,currency,amount_fcy,commit_fx_rate,pay_fx_rate,amount_ghs,
        fx_gl_ghs,fx_gl_type,has_vat,vat_amount,has_whvat,whvat_amount,has_ucf,ucf_amount,
        wht_type,wht_rate,wht_amount,receipt_no,created_by)
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (aid,acode,data['project_id'],data.get('budget_id'),data.get('commitment_id'),
         data['expense_date'],data['payee'],data['description'],currency,amount_fcy,
         commit_fx,pay_fx,amount_ghs,fx_gl,fx_type,has_vat,vat_amount,has_whvat,whvat_amount,
         has_ucf,ucf_amount,wht_type,wht_rate,wht_amount,data.get('receipt_no',''),session['username']))

    # Mark commitment paid if linked
    if data.get('commitment_id'):
        _settle_commitment(conn, data['commitment_id'])

    _audit(conn, session, 'SAVE_ACTUAL', 'actuals', aid, f"{data.get('payee','')} {amount_ghs:.2f} GHS")
    conn.commit(); conn.close()
    return {'ok': True, 'id': aid}

