def api_save_fx_rate(data, session):
    conn = get_db()
    rid = str(uuid.uuid4())
    conn.execute("""INSERT OR REPLACE INTO exchange_rates(id,rate_date,currency,rate_to_ghs,source,entered_by)
        VALUES(?,?,?,?,?,?)""", (rid,data['rate_date'],data['currency'],float(data['rate_to_ghs']),
        data.get('source','Bank of Ghana'),session['username']))
    _audit(conn, session, 'SAVE_FX_RATE', 'exchange_rates', rid, f"{data['currency']} {data['rate_to_ghs']}")
    conn.commit(); conn.close()
    return {'ok': True}

def api_get_fx_rate_for_date(currency, date_str):
    if currency == 'GHS': return 1.0
    conn = get_db()
    row = conn.execute("""SELECT rate_to_ghs FROM exchange_rates
        WHERE currency=? AND rate_date<=? ORDER BY rate_date DESC LIMIT 1""",
        (currency, date_str)).fetchone()
    conn.close()
    return row[0] if row else 1.0

def api_get_coa(session):
    conn = get_db()
    rows = [dict(r) for r in conn.execute("SELECT * FROM chart_of_accounts ORDER BY code")]
    conn.close()
    return rows

def api_save_coa(data, session):
    if session.get('role') != 'Admin':
        return err('Admin access required')
    conn = get_db()
    cid = data.get('id') or str(uuid.uuid4())
    code = data.get('code','').strip()
    name = data.get('account_name','').strip()
    if not code or not name:
        conn.close(); return err('Code and account name are required')
    # Validate code conforms to SBS COA numbering scheme
    # Accepts both 4-digit (1xxx) and 8-digit (1xxxxxxx) codes — leading digit must be 1/2/3/4/6
    try:
        code_int = int(code)
        leading = str(code_int)[0]
        valid = leading in ('1', '2', '3', '4', '6')
        if not valid:
            conn.close()
            return err('Account code %s is outside the valid SBS COA ranges. '
                       'Leading digit must be 1 (Assets), 2 (Liabilities), 3 (Funds & Reserves), '
                       '4 (Revenue/Income) or 6 (Expenses)' % code)
    except ValueError:
        conn.close(); return err('Account code must be numeric')
    if data.get('id'):
        conn.execute("""UPDATE chart_of_accounts SET code=?,category=?,sub_category=?,
            account_name=?,account_type=?,vat_applicable=? WHERE id=?""",
            (code, data.get('category','Operating Expenses'),
             data.get('sub_category',''), name,
             data.get('account_type','Expense'),
             1 if data.get('vat_applicable') else 0, cid))
        _audit(conn, session, 'UPDATE_COA', 'chart_of_accounts', cid, code)
    else:
        existing = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (code,)).fetchone()
        if existing:
            conn.close(); return err(f'Account code {code} already exists')
        conn.execute("""INSERT INTO chart_of_accounts(id,code,category,sub_category,account_name,account_type,vat_applicable)
            VALUES(?,?,?,?,?,?,?)""",
            (cid, code, data.get('category','Operating Expenses'),
             data.get('sub_category',''), name,
             data.get('account_type','Expense'),
             1 if data.get('vat_applicable') else 0))
        _audit(conn, session, 'CREATE_COA', 'chart_of_accounts', cid, code)
    conn.commit(); conn.close()
    return ok({'id': cid})

def api_delete_coa(coa_id, session):
    if session.get('role') != 'Admin':
        return err('Admin access required')
    conn = get_db()
    used = conn.execute("SELECT COUNT(*) FROM budgets WHERE coa_id=?", (coa_id,)).fetchone()[0]
    if used:
        conn.close(); return err('Cannot delete: account is used in budget lines')
    conn.execute("DELETE FROM chart_of_accounts WHERE id=?", (coa_id,))
    _audit(conn, session, 'DELETE_COA', 'chart_of_accounts', coa_id, '')
    conn.commit(); conn.close()
    return ok({})

def api_reset_coa(session):
    """Remove all COA accounts NOT referenced by any transaction, then re-seed system defaults."""
    if session.get('role') != 'Admin':
        return err('Admin access required')
    conn = get_db()
    # Find accounts that are safe to delete (not referenced anywhere)
    used_ids = set(
        r[0] for r in conn.execute("""
            SELECT DISTINCT coa_id FROM budgets WHERE coa_id IS NOT NULL
            UNION SELECT DISTINCT coa_id FROM general_ledger WHERE coa_id IS NOT NULL
        """).fetchall()
    )
    all_ids = [r[0] for r in conn.execute("SELECT id FROM chart_of_accounts").fetchall()]
    deletable = [i for i in all_ids if i not in used_ids]
    if deletable:
        conn.execute(f"DELETE FROM chart_of_accounts WHERE id IN ({','.join('?'*len(deletable))})", deletable)
    deleted_count = len(deletable)
    kept_count = len(used_ids)
    _audit(conn, session, 'RESET_COA', 'chart_of_accounts', 'SYSTEM', f'Deleted {deleted_count}, kept {kept_count} in-use')
    c = conn.cursor()
    _reseed_coa(c)
    conn.commit(); conn.close()
    return ok({'deleted': deleted_count, 'kept': kept_count, 'message': f'Reset complete: {deleted_count} old accounts removed, {kept_count} in-use accounts preserved, standard SBS accounts restored.'})

