def api_get_report(session, report_type, project_id=None):
    conn = get_db()
    if report_type == 'project' and project_id:
        proj = dict(conn.execute("SELECT * FROM projects WHERE id=?", (project_id,)).fetchone())
        budgets = [dict(r) for r in conn.execute("""
            SELECT b.*, c.account_name, c.code as coa_code, c.category,
                COALESCE(SUM(CASE WHEN cm.status='Open' THEN cm.amount_ghs ELSE 0 END),0) as committed_ghs,
                COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id),0) as actual_ghs
            FROM budgets b
            JOIN chart_of_accounts c ON b.coa_id=c.id
            LEFT JOIN commitments cm ON cm.budget_id=b.id
            WHERE b.project_id=? GROUP BY b.id""", (project_id,))]
        actuals = [dict(r) for r in conn.execute(
            "SELECT * FROM actuals WHERE project_id=? ORDER BY expense_date", (project_id,))]
        commitments = [dict(r) for r in conn.execute(
            "SELECT * FROM commitments WHERE project_id=? ORDER BY commit_date", (project_id,))]
        fx_gain = conn.execute("SELECT COALESCE(SUM(fx_gl_ghs),0) FROM actuals WHERE project_id=? AND fx_gl_type='Gain'",(project_id,)).fetchone()[0]
        fx_loss = conn.execute("SELECT COALESCE(SUM(fx_gl_ghs),0) FROM actuals WHERE project_id=? AND fx_gl_type='Loss'",(project_id,)).fetchone()[0]
        conn.close()
        return {'project': proj, 'budgets': budgets, 'actuals': actuals,
                'commitments': commitments, 'fx_gain': fx_gain, 'fx_loss': fx_loss}
    elif report_type == 'centre':
        projects = [dict(r) for r in conn.execute("""
            SELECT p.*,
                COALESCE(SUM(CASE WHEN c.status='Open' THEN c.amount_ghs ELSE 0 END),0) as committed_ghs,
                COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.project_id=p.id),0) as actual_ghs
            FROM projects p LEFT JOIN commitments c ON c.project_id=p.id
            GROUP BY p.id""")]
        divisions = [dict(r) for r in conn.execute("""
            SELECT division, COUNT(*) as proj_count,
                COALESCE(SUM(budget_ghs),0) as total_budget,
                COALESCE(SUM(CASE WHEN status='Active' THEN budget_ghs ELSE 0 END),0) as active_budget
            FROM projects GROUP BY division""")]
        fx_summary = conn.execute("""SELECT
            COALESCE(SUM(CASE WHEN fx_gl_type='Gain' THEN fx_gl_ghs ELSE 0 END),0) as total_gain,
            COALESCE(SUM(CASE WHEN fx_gl_type='Loss' THEN fx_gl_ghs ELSE 0 END),0) as total_loss
            FROM actuals""").fetchone()
        conn.close()
        return {'projects': projects, 'divisions': divisions,
                'fx_gain': fx_summary[0], 'fx_loss': fx_summary[1]}

def api_get_audit(session):
    conn = get_db()
    rows = [dict(r) for r in conn.execute(
        "SELECT * FROM audit_log ORDER BY timestamp DESC LIMIT 200")]
    conn.close()
    return rows

def api_change_password(data, session):
    conn = get_db()
    old_hash = hashlib.sha256(data['old_password'].encode()).hexdigest()
    user = conn.execute("SELECT * FROM users WHERE id=? AND password_hash=?",
                        (session['id'], old_hash)).fetchone()
    if not user:
        conn.close()
        return {'ok': False, 'error': 'Current password incorrect'}
    if len(data['new_password']) < 6:
        conn.close()
        return {'ok': False, 'error': 'Password must be at least 6 characters'}
    new_hash = hashlib.sha256(data['new_password'].encode()).hexdigest()
    conn.execute("UPDATE users SET password_hash=? WHERE id=?", (new_hash, session['id']))
    _audit(conn, session, 'PASSWORD_CHANGE', 'users', session['id'], '')
    conn.commit(); conn.close()
    return {'ok': True}

def api_export_csv(table, session):
    conn = get_db()
    if table == 'projects':
        rows = conn.execute("SELECT * FROM projects").fetchall()
    elif table == 'actuals':
        rows = conn.execute("SELECT * FROM actuals").fetchall()
    elif table == 'commitments':
        rows = conn.execute("SELECT * FROM commitments").fetchall()
    elif table == 'budgets':
        rows = conn.execute("SELECT * FROM budgets").fetchall()
    else:
        conn.close()
        return None
    if not rows:
        conn.close()
        return ''
    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(rows[0].keys())
    for row in rows:
        writer.writerow(list(row))
    conn.close()
    return output.getvalue()

def _audit(conn, session, action, module, record_id, details):
    conn.execute("""INSERT INTO audit_log(id,username,user_role,action,module,record_id,details)
        VALUES(?,?,?,?,?,?,?)""",
        (str(uuid.uuid4()), session.get('username','system'),
         session.get('role',''), action, module, record_id, details))


