def _v523_invoice_profile():
    is_aoi = 'AOI_UNITS' in globals()
    return {
        'code': 'AOI' if is_aoi else 'UCC',
        'name': 'Africa Ocean Institute' if is_aoi else 'University of Cape Coast',
        'subname': 'University of Cape Coast, Ghana',
        'system': 'AOI Financial Management System' if is_aoi else 'University of Cape Coast Financial Management System',
        'prefix': 'AOI-INV' if is_aoi else 'UCC-INV',
        'address': 'University of Cape Coast, Cape Coast, Ghana',
        'email': 'registrar@ucc.edu.gh',
        'phone': '+233 (03321) 32440'
    }

def _v523_invoice_migration(conn):
    conn.executescript('''
    CREATE TABLE IF NOT EXISTS invoices (
        id TEXT PRIMARY KEY,
        invoice_no TEXT UNIQUE NOT NULL,
        invoice_type TEXT DEFAULT 'Donor Project',
        project_id TEXT,
        client_name TEXT NOT NULL,
        client_address TEXT,
        client_email TEXT,
        client_contact TEXT,
        client_reference TEXT,
        contract_no TEXT,
        po_no TEXT,
        invoice_date TEXT NOT NULL,
        due_date TEXT,
        service_start TEXT,
        service_end TEXT,
        currency TEXT DEFAULT 'GHS',
        fx_rate REAL DEFAULT 1.0,
        subtotal_fcy REAL DEFAULT 0,
        tax_rate REAL DEFAULT 0,
        tax_amount_fcy REAL DEFAULT 0,
        discount_fcy REAL DEFAULT 0,
        total_fcy REAL DEFAULT 0,
        total_ghs REAL DEFAULT 0,
        payment_terms TEXT,
        payment_instructions TEXT,
        bank_account_id TEXT,
        status TEXT DEFAULT 'Draft',
        notes TEXT,
        prepared_by TEXT,
        approved_by TEXT,
        created_by TEXT,
        created_at TEXT DEFAULT (datetime('now')),
        updated_at TEXT DEFAULT (datetime('now'))
    );
    CREATE TABLE IF NOT EXISTS invoice_lines (
        id TEXT PRIMARY KEY,
        invoice_id TEXT NOT NULL,
        line_no INTEGER DEFAULT 1,
        description TEXT NOT NULL,
        quantity REAL DEFAULT 1,
        unit TEXT DEFAULT 'Each',
        rate_fcy REAL DEFAULT 0,
        amount_fcy REAL DEFAULT 0,
        revenue_account TEXT,
        cost_centre TEXT,
        deliverable_ref TEXT,
        FOREIGN KEY(invoice_id) REFERENCES invoices(id) ON DELETE CASCADE
    );
    ''')

def _v523_float(v, default=0.0):
    try:
        if v in (None, ''): return float(default)
        return float(str(v).replace(',', ''))
    except Exception:
        return float(default)

def _v523_next_invoice_no(conn):
    prof=_v523_invoice_profile(); year=datetime.now().strftime('%Y'); pfx=f"{prof['prefix']}-{year}-"
    row=conn.execute("SELECT invoice_no FROM invoices WHERE invoice_no LIKE ? ORDER BY invoice_no DESC LIMIT 1", (pfx+'%',)).fetchone()
    seq=1
    if row:
        try: seq=int(str(row['invoice_no']).split('-')[-1])+1
        except Exception: seq=1
    return f"{pfx}{seq:04d}"

def api_get_invoices(session, status=None, project_id=None):
    conn=get_db(); _v523_invoice_migration(conn)
    where=[]; args=[]
    if status: where.append('i.status=?'); args.append(status)
    if project_id: where.append('i.project_id=?'); args.append(project_id)
    sql='''SELECT i.*, p.project_code, p.title AS project_title, p.donor AS project_donor,
           b.account_name AS bank_account_name, b.bank_name, b.branch, b.account_number, b.currency AS bank_currency
           FROM invoices i LEFT JOIN projects p ON p.id=i.project_id LEFT JOIN bank_accounts b ON b.id=i.bank_account_id'''
    if where: sql += ' WHERE ' + ' AND '.join(where)
    sql += ' ORDER BY i.invoice_date DESC, i.created_at DESC'
    rows=[dict(r) for r in conn.execute(sql,args).fetchall()]
    for r in rows:
        r['lines']=[dict(x) for x in conn.execute('SELECT * FROM invoice_lines WHERE invoice_id=? ORDER BY line_no',(r['id'],)).fetchall()]
    conn.close(); return rows

def api_get_invoice_detail(invoice_id, session=None):
    rows=api_get_invoices(session)
    for r in rows:
        if r.get('id')==invoice_id or r.get('invoice_no')==invoice_id: return r
    return None

def api_save_invoice(data, session):
    if not isinstance(data, dict): return err('Invalid invoice payload')
    if not data.get('client_name'): return err('Client / donor name is required')
    lines=data.get('lines') or []
    if not lines: return err('Add at least one invoice line')
    conn=get_db(); _v523_invoice_migration(conn)
    iid=data.get('id') or str(uuid.uuid4()); inv_no=(data.get('invoice_no') or '').strip() or _v523_next_invoice_no(conn)
    currency=(data.get('currency') or 'GHS').upper(); fx=_v523_float(data.get('fx_rate'),1) or 1
    clean=[]; subtotal=0.0
    for n,line in enumerate(lines,1):
        if not isinstance(line,dict): continue
        desc=str(line.get('description') or '').strip()
        if not desc: continue
        qty=_v523_float(line.get('quantity'),1); rate=_v523_float(line.get('rate_fcy') or line.get('rate'),0); amount=_v523_float(line.get('amount_fcy'),qty*rate)
        subtotal+=amount; clean.append((str(uuid.uuid4()),iid,n,desc,qty,line.get('unit') or 'Each',rate,amount,line.get('revenue_account') or '',line.get('cost_centre') or '',line.get('deliverable_ref') or ''))
    if not clean: conn.close(); return err('Add at least one valid invoice line')
    tax_rate=_v523_float(data.get('tax_rate'),0); tax=_v523_float(data.get('tax_amount_fcy'),subtotal*tax_rate/100); disc=_v523_float(data.get('discount_fcy'),0); total=max(subtotal+tax-disc,0); total_ghs=total*fx
    vals=(inv_no,data.get('invoice_type') or 'Donor Project',data.get('project_id') or None,data.get('client_name'),data.get('client_address',''),data.get('client_email',''),data.get('client_contact',''),data.get('client_reference',''),data.get('contract_no',''),data.get('po_no',''),data.get('invoice_date') or date.today().isoformat(),data.get('due_date',''),data.get('service_start',''),data.get('service_end',''),currency,fx,subtotal,tax_rate,tax,disc,total,total_ghs,data.get('payment_terms') or 'Payment due within 30 days from invoice date.',data.get('payment_instructions') or '',data.get('bank_account_id') or None,data.get('status') or 'Draft',data.get('notes',''),data.get('prepared_by') or (session or {}).get('username',''),data.get('approved_by',''))
    if conn.execute('SELECT 1 FROM invoices WHERE id=?',(iid,)).fetchone():
        conn.execute('''UPDATE invoices SET invoice_no=?,invoice_type=?,project_id=?,client_name=?,client_address=?,client_email=?,client_contact=?,client_reference=?,contract_no=?,po_no=?,invoice_date=?,due_date=?,service_start=?,service_end=?,currency=?,fx_rate=?,subtotal_fcy=?,tax_rate=?,tax_amount_fcy=?,discount_fcy=?,total_fcy=?,total_ghs=?,payment_terms=?,payment_instructions=?,bank_account_id=?,status=?,notes=?,prepared_by=?,approved_by=?,updated_at=datetime('now') WHERE id=?''', vals+(iid,))
        conn.execute('DELETE FROM invoice_lines WHERE invoice_id=?',(iid,))
    else:
        conn.execute('''INSERT INTO invoices(id,invoice_no,invoice_type,project_id,client_name,client_address,client_email,client_contact,client_reference,contract_no,po_no,invoice_date,due_date,service_start,service_end,currency,fx_rate,subtotal_fcy,tax_rate,tax_amount_fcy,discount_fcy,total_fcy,total_ghs,payment_terms,payment_instructions,bank_account_id,status,notes,prepared_by,approved_by,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)''', (iid,)+vals+((session or {}).get('username','system'),))
    conn.executemany('''INSERT INTO invoice_lines(id,invoice_id,line_no,description,quantity,unit,rate_fcy,amount_fcy,revenue_account,cost_centre,deliverable_ref) VALUES(?,?,?,?,?,?,?,?,?,?,?)''', clean)
    try: _audit(conn, session or {}, 'SAVE_INVOICE', 'invoices', iid, inv_no)
    except Exception: pass
    conn.commit(); conn.close(); return ok({'id':iid,'invoice_no':inv_no,'total_fcy':round(total,2),'total_ghs':round(total_ghs,2)})

def _v523_esc(v):
    s='' if v is None else str(v)
    return s.replace('&','&amp;').replace('<','&lt;').replace('>','&gt;').replace('"','&quot;')

def _v523_money(v,c='GHS'):
    try: a=float(v or 0)
    except Exception: a=0.0
    return f"{c} {a:,.2f}"

