def api_invoice_html(invoice_id, session=None):
    inv=api_get_invoice_detail(invoice_id, session)
    if not inv: return '<html><body><h2>Invoice not found</h2></body></html>'
    prof=_v523_invoice_profile(); cur=inv.get('currency') or 'GHS'
    line_rows=''.join([f"<tr><td>{int(l.get('line_no') or i+1)}</td><td>{_v523_esc(l.get('description'))}<div class='muted'>{_v523_esc(l.get('deliverable_ref') or '')}</div></td><td class='right'>{float(l.get('quantity') or 0):,.2f}</td><td>{_v523_esc(l.get('unit'))}</td><td class='right'>{float(l.get('rate_fcy') or 0):,.2f}</td><td class='right'>{float(l.get('amount_fcy') or 0):,.2f}</td></tr>" for i,l in enumerate(inv.get('lines') or [])])
    bank=f"<div class='box'><h3>Payment / Bank Details</h3><p><b>{_v523_esc(inv.get('bank_account_name') or '')}</b><br>{_v523_esc(inv.get('bank_name') or '')} {_v523_esc(inv.get('branch') or '')}<br>Account No.: {_v523_esc(inv.get('account_number') or '')}<br>Currency: {_v523_esc(inv.get('bank_currency') or cur)}</p></div>" if (inv.get('bank_name') or inv.get('account_number')) else ''
    return f'''<!doctype html><html><head><meta charset="utf-8"><title>{_v523_esc(inv.get('invoice_no'))}</title><style>body{{font-family:Arial,Helvetica,sans-serif;color:#172033;margin:0;background:#f5f7fb}}.sheet{{max-width:920px;margin:28px auto;background:#fff;padding:38px;border:1px solid #e4e8f0;box-shadow:0 16px 45px rgba(15,23,42,.12)}}.header{{display:flex;justify-content:space-between;gap:24px;border-bottom:5px solid #061b3a;padding-bottom:18px}}.brand{{display:flex;gap:16px;align-items:center}}h1{{margin:0;color:#061b3a;font-size:30px}}h2{{margin:0;color:#061b3a;font-size:18px}}.muted{{color:#667085;font-size:12px}}.invno{{text-align:right}}.pill{{display:inline-block;background:#f1c232;color:#061b3a;padding:5px 10px;border-radius:20px;font-weight:700}}.grid{{display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:22px}}.box{{border:1px solid #e5e7eb;border-radius:12px;padding:16px;margin-top:16px}}.box h3{{margin:0 0 8px;color:#061b3a;font-size:14px;text-transform:uppercase}}table{{width:100%;border-collapse:collapse;margin-top:22px}}th{{background:#061b3a;color:#fff;text-align:left;padding:10px;font-size:12px}}td{{border-bottom:1px solid #e5e7eb;padding:10px;vertical-align:top}}.right{{text-align:right}}.totals{{margin-left:auto;width:360px;margin-top:16px}}.grand td{{font-weight:800;background:#f8fafc;color:#061b3a;font-size:16px}}.footer{{margin-top:28px;font-size:12px;color:#667085;border-top:1px solid #e5e7eb;padding-top:14px}}@media print{{body{{background:white}}.sheet{{margin:0;box-shadow:none;border:0}}}}</style></head><body><div class="sheet"><div class="header"><div class="brand">{_v523_ucc_logo_svg()}<div><h2>{_v523_esc(prof['name'])}</h2><div>{_v523_esc(prof['subname'])}</div><div class="muted">{_v523_esc(prof['address'])} · {_v523_esc(prof['email'])}</div></div></div><div class="invno"><h1>INVOICE</h1><div class="pill">{_v523_esc(inv.get('status'))}</div><p><b>No:</b> {_v523_esc(inv.get('invoice_no'))}<br><b>Date:</b> {_v523_esc(inv.get('invoice_date'))}<br><b>Due:</b> {_v523_esc(inv.get('due_date'))}</p></div></div><div class="grid"><div class="box"><h3>Bill To</h3><p><b>{_v523_esc(inv.get('client_name'))}</b><br>{_v523_esc(inv.get('client_address'))}<br>{_v523_esc(inv.get('client_email'))}<br>{_v523_esc(inv.get('client_contact'))}</p></div><div class="box"><h3>Project / Contract</h3><p><b>{_v523_esc(inv.get('project_code') or inv.get('invoice_type'))}</b><br>{_v523_esc(inv.get('project_title') or '')}<br>Contract: {_v523_esc(inv.get('contract_no') or '-')} · PO: {_v523_esc(inv.get('po_no') or '-')}<br>Service period: {_v523_esc(inv.get('service_start') or '-')} to {_v523_esc(inv.get('service_end') or '-')}</p></div></div><table><thead><tr><th>#</th><th>Description / Deliverable</th><th class="right">Qty</th><th>Unit</th><th class="right">Rate</th><th class="right">Amount</th></tr></thead><tbody>{line_rows}</tbody></table><table class="totals"><tr><td>Subtotal</td><td class="right">{_v523_money(inv.get('subtotal_fcy'),cur)}</td></tr><tr><td>Tax / VAT ({float(inv.get('tax_rate') or 0):.2f}%)</td><td class="right">{_v523_money(inv.get('tax_amount_fcy'),cur)}</td></tr><tr><td>Discount</td><td class="right">{_v523_money(inv.get('discount_fcy'),cur)}</td></tr><tr class="grand"><td>Amount Due</td><td class="right">{_v523_money(inv.get('total_fcy'),cur)}</td></tr><tr><td>Total GHS Equivalent</td><td class="right">GHS {float(inv.get('total_ghs') or 0):,.2f}</td></tr></table><div class="grid"><div class="box"><h3>Payment Terms</h3><p>{_v523_esc(inv.get('payment_terms'))}</p><p>{_v523_esc(inv.get('payment_instructions'))}</p></div>{bank}</div><div class="box"><h3>Notes</h3><p>{_v523_esc(inv.get('notes') or 'This invoice is issued electronically by the University of Cape Coast financial management system and is valid without manual alteration.')}</p></div><div class="footer">Prepared by: {_v523_esc(inv.get('prepared_by'))} | Approved by: {_v523_esc(inv.get('approved_by') or 'Pending approval')}<br>Generated: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')} · {_v523_esc(prof['system'])}</div></div></body></html>'''

def api_export_invoices_csv(session):
    rows=api_get_invoices(session); out=io.StringIO(); w=csv.writer(out)
    w.writerow(['Invoice No','Type','Client/Donor','Project','Invoice Date','Due Date','Currency','Subtotal','Tax','Discount','Total FCY','Total GHS','Status','Contract No','PO No'])
    for r in rows: w.writerow([r.get('invoice_no'),r.get('invoice_type'),r.get('client_name'),r.get('project_code') or r.get('project_title'),r.get('invoice_date'),r.get('due_date'),r.get('currency'),r.get('subtotal_fcy'),r.get('tax_amount_fcy'),r.get('discount_fcy'),r.get('total_fcy'),r.get('total_ghs'),r.get('status'),r.get('contract_no'),r.get('po_no')])
    return out.getvalue()

# ─── HTTP REQUEST HANDLER ─────────────────────────────────────────────────────
class Handler(BaseHTTPRequestHandler):
    def log_message(self, format, *args):
        pass  # suppress default access logging

    def log_error(self, format, *args):
        pass  # suppress broken pipe noise

    def send_json(self, data, status=200):
        body = json.dumps(data).encode()
        self.send_response(status)
        self.send_header('Content-Type', 'application/json')
        self.send_header('Content-Length', str(len(body)))
        self.send_header('Access-Control-Allow-Origin', '*')
        self.end_headers()
        try:
            self.wfile.write(body)
            self.wfile.flush()
        except (BrokenPipeError, ConnectionResetError):
            pass

    def send_file(self, path, content_type='text/html'):
        import os as _os
        size = _os.path.getsize(path)
        self.send_response(200)
        self.send_header('Content-Type', content_type + '; charset=utf-8')
        self.send_header('Content-Length', str(size))
        self.send_header('Cache-Control', 'no-cache')
        self.end_headers()
        try:
            with open(path, 'rb') as f:
                while True:
                    chunk = f.read(65536)  # 64KB chunks
                    if not chunk:
                        break
                    self.wfile.write(chunk)
                    self.wfile.flush()
        except (BrokenPipeError, ConnectionResetError):
            pass  # client disconnected — not an error

    def read_body(self):
        length = int(self.headers.get('Content-Length', 0))
        if length:
            return json.loads(self.rfile.read(length).decode())
        return {}

    def get_session(self):
        return get_session(get_sid_from_cookie(self.headers))

    def do_OPTIONS(self):
        self.send_response(204)
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS')
        self.send_header('Access-Control-Allow-Headers', 'Content-Type, Cookie, X-Session-ID')
        self.end_headers()

    def do_GET(self):
        parsed = urlparse(self.path)
        path = parsed.path
        qs = parse_qs(parsed.query)

        # Serve frontend
        if path == '/' or path == '/index.html':
            frontend = Path(__file__).parent / 'index.html'
            if frontend.exists():
                if '_TRAINING_MODE' in dir() and _TRAINING_MODE:
                    # Inject training banner into HTML response
                    try:
                        _html = frontend.read_text(encoding='utf-8')
                        _tbanner = (
                            '<script id="training-mode-active">'
                            '(function(){'
                            'var d=document.createElement("div");'
                            'd.id="__training_banner";'
                            'd.innerHTML="\u26a0\ufe0f\u2002TRAINING MODE\u2002\u2014\u2002"'
                            '+"Data is isolated from the live system. "+'
                            '"Actions here do NOT affect real records.";'
                            'd.style.cssText='
                            '"position:fixed;top:0;left:0;right:0;z-index:99999;'
                            'background:linear-gradient(135deg,#DC2626,#B91C1C);'
                            'color:#fff;text-align:center;padding:9px 16px;'
                            'font-family:system-ui,sans-serif;font-size:13px;'
                            'font-weight:700;letter-spacing:.3px;'
                            'box-shadow:0 2px 8px rgba(0,0,0,.35);pointer-events:none;";'
                            'var _fn=function(){'
                            'document.body.appendChild(d);'
                            'var s=document.createElement("style");'
                            's.textContent="body,#root,#app,#content{padding-top:42px!important}";'
                            'document.head.appendChild(s);'
                            'document.title="[TRAINING] "+document.title;};'
                            'if(document.body){_fn();}'
                            'else{document.addEventListener("DOMContentLoaded",_fn);}'
                            '}());</script>'
                        )
                        _html = _html[:_html.rfind('</body>')] + _tbanner + _html[_html.rfind('</body>'):]
                        _body = _html.encode('utf-8')
                        self.send_response(200)
                        self.send_header('Content-Type', 'text/html; charset=utf-8')
                        self.send_header('Content-Length', str(len(_body)))
                        self.send_header('Cache-Control', 'no-cache')
                        self.end_headers()
                        try:
                            self.wfile.write(_body)
                            self.wfile.flush()
                        except (BrokenPipeError, ConnectionResetError):
                            pass
                    except Exception as _te:
                        print('Training banner inject error:', _te)
                        self.send_file(frontend)
                else:
                    self.send_file(frontend)
            else:
                self.send_response(404)
                self.end_headers()
            return

        # Public utility routes for local/direct server mode
        if path in ('/healthz', '/api/health'):
            self.send_json({'ok': True, 'status': 'ok', 'app': 'UCC-FMS', 'version': '5.0.28-deployment-stability'})
            return
        if path == '/favicon.ico':
            body = b''
            self.send_response(204)
            self.send_header('Content-Length', '0')
            self.end_headers()
            return

        # API routes
        session = self.get_session()
        if not session and path != '/api/login':
            self.send_json({'error': 'Not authenticated'}, 401)
            return

        if path == '/api/dashboard':
            self.send_json(api_dashboard(session))
        elif path in ('/api/control-cockpit','/api/financial-integrity'):
            self.send_json(api_control_cockpit(session))
        elif path == '/api/projects':
            self.send_json(api_get_projects(session))
        elif path == '/api/budgets':
            pid = qs.get('project_id', [None])[0]
            self.send_json(api_get_budgets(session, pid))
        elif path == '/api/commitments':
            pid = qs.get('project_id', [None])[0]
            self.send_json(api_get_commitments(session, pid))
        elif path == '/api/actuals':
            pid = qs.get('project_id', [None])[0]
            self.send_json(api_get_actuals(session, pid))
        elif path == '/api/fx-rates':
            self.send_json(api_get_fx_rates(session))
        elif path == '/api/fx-rate':
            currency = qs.get('currency', ['GHS'])[0]
            date_str = qs.get('date', [str(date.today())])[0]
            self.send_json({'rate': api_get_fx_rate_for_date(currency, date_str)})
        elif path == '/api/coa':
            self.send_json(api_get_coa(session))
        elif path == '/api/coa/delete':
            coa_id = qs.get('id',[''])[0]
            self.send_json(api_delete_coa(coa_id, session))
        elif path == '/api/coa/reset':
            self.send_json(api_reset_coa(session))
        elif path == '/api/report':
            rtype = qs.get('type', ['project'])[0]
            pid = qs.get('project_id', [None])[0]
            self.send_json(api_get_report(session, rtype, pid))
        elif path == '/api/audit':
            self.send_json(api_get_audit(session))
        elif path == '/api/jvs':
            filters = {k: qs.get(k,[None])[0] for k in
                       ('jv_type','status','period','project_id','date_from','date_to') if qs.get(k)}
            self.send_json(api_get_jvs(session, filters or None))
        elif path.startswith('/api/jvs/') and path != '/api/jvs/workflow':
            jv_id = path.split('/')[-1]
            self.send_json(api_get_jv_detail(session, jv_id) or {'error':'Not found'})
        elif path == '/api/general-ledger':
            filters = {k: qs.get(k,[None])[0] for k in
                       ('coa_id','coa_code','period','project_id','date_from','date_to') if qs.get(k)}
            self.send_json(api_get_general_ledger(session, filters or None))
        elif path == '/api/ledger-summary':
            period = qs.get('period',[None])[0]
            unit = qs.get('unit',[None])[0] or qs.get('unit_code',[None])[0]
            self.send_json(api_get_ledger_accounts_summary(session, period, unit))
        elif path == '/api/financial-integrity':
            self.send_json(api_financial_integrity(session))
        elif path == '/api/accounting-periods':
            self.send_json(api_get_accounting_periods(session))
        elif path == '/api/bank-accounts':
            self.send_json(api_get_bank_accounts(session))
        elif path == '/api/fund-receipts':
            pid = qs.get('project_id', [None])[0]
            self.send_json(api_get_fund_receipts(session, pid))
        elif path == '/api/bank-statement':
            acct_id = qs.get('account_id', [None])[0]
            df = qs.get('date_from', [None])[0]
            dt = qs.get('date_to', [None])[0]
            if acct_id:
                self.send_json(api_get_bank_statement(session, acct_id, df, dt))
            else:
                self.send_json({'error': 'account_id required'}, 400)
        elif path == '/api/bank-reconciliations':
            acct_id = qs.get('account_id', [None])[0]
            self.send_json(api_get_bank_reconciliations(session, acct_id))
        elif path.startswith('/api/export/') and path not in ('/api/export/payroll','/api/export/actuals-full','/api/export/projects-full'):
            table = path.split('/')[-1]
            csv_data = api_export_csv(table, session)
            if csv_data is not None:
                body = csv_data.encode()
                self.send_response(200)
                self.send_header('Content-Type', 'text/csv')
                self.send_header('Content-Disposition', f'attachment; filename="{table}.csv"')
                self.send_header('Content-Length', len(body))
                self.end_headers()
                self.wfile.write(body)
            else:
                self.send_json({'error': 'Unknown table'}, 400)
        elif path == '/api/me':
            self.send_json({'user': session})
        elif path == '/api/payroll/employees':
            self.send_json(api_get_employees(session))
        elif path == '/api/payroll/register':
            month = qs.get('month', [None])[0]
            self.send_json(api_get_payroll_register(session, month))
        elif path == '/api/payroll/months':
            self.send_json(api_get_payroll_months(session))
        elif path == '/api/payroll/settings':
            self.send_json(api_get_payroll_settings(session))
        elif path == '/api/payroll/schedules':
            month = qs.get('month', [None])[0]
            if month:
                self.send_json(api_get_statutory_schedules(session, month))
            else:
                self.send_json({'error': 'month required'}, 400)
        elif path == '/api/payroll/payslip':
            reg_id = qs.get('id', [None])[0]
            self.send_json(api_get_payslip(session, reg_id))
        elif path.startswith('/api/payroll/photo/'):
            emp_id = path.split('/')[-1]
            photo = api_get_photo_url(emp_id)
            if photo:
                self.send_json({'photo': photo})
            else:
                self.send_json({'photo': None})
        elif path == '/api/payroll/payslip/html':
            reg_id = qs.get('id', [None])[0]
            show_photo = qs.get('photo', ['1'])[0] == '1'
            rec = api_get_payslip(session, reg_id)
            if rec:
                html = payslip_html_single(rec, show_photo)
                body = html.encode('utf-8')
                self.send_response(200)
                self.send_header('Content-Type', 'text/html; charset=utf-8')
                self.send_header('Content-Length', len(body))
                self.end_headers()
                self.wfile.write(body)
            else:
                self.send_json({'error': 'Not found'}, 404)
        elif path == '/api/payroll/payslips/all':
            month = qs.get('month', [None])[0]
            show_photo = qs.get('photo', ['1'])[0] == '1'
            if not month:
                self.send_json({'error': 'month required'}, 400)
            else:
                records = api_get_payroll_register(session, month)
                # Return all payslips as a single HTML page
                all_html = ''.join(
                    payslip_html_single(r, show_photo) +
                    '<div style="page-break-after:always"></div>'
                    for r in records
                )
                body = all_html.encode('utf-8')
                self.send_response(200)
                self.send_header('Content-Type', 'text/html; charset=utf-8')
                self.send_header('Content-Length', len(body))
                self.end_headers()
                self.wfile.write(body)
        elif path == '/api/export/payroll':
            month = qs.get('month', [None])[0]
            records = api_get_payroll_register(session, month) if month else api_get_payroll_register(session)
            headers, rows = get_payroll_export_rows(records)
            title = f'UCC PAYROLL REGISTER - {month or "ALL"}'
            csv_data = export_csv_generic(headers, rows, title)
            body = csv_data.encode('utf-8')
            self.send_response(200)
            self.send_header('Content-Type', 'text/csv')
            self.send_header('Content-Disposition', f'attachment; filename="payroll_{month or "all"}.csv"')
            self.send_header('Content-Length', len(body))
            self.end_headers()
            self.wfile.write(body)
        elif path == '/api/export/actuals-full':
            pid = qs.get('project_id', [None])[0]
            rows = api_get_actuals(session, pid)
            headers = ['Code','Project','Date','Payee','Description','Currency',
                       'Amt FCY','FX Rate','Amt GHS','Has VAT','VAT','Has WHVAT','WHVAT',
                       'WHT Type','WHT Rate','WHT Amt','Has UCF','UCF Amt','FX GL Type','FX GL','Receipt']
            data_rows = [[r.get('actual_code',''),r.get('project_code',''),r.get('expense_date',''),
                         r.get('payee',''),r.get('description',''),r.get('currency',''),
                         r.get('amount_fcy',0),r.get('pay_fx_rate',0),r.get('amount_ghs',0),
                         'Y' if r.get('has_vat') else 'N',r.get('vat_amount',0),
                         'Y' if r.get('has_whvat') else 'N',r.get('whvat_amount',0),
                         r.get('wht_type','-'),r.get('wht_rate',0),r.get('wht_amount',0),
                         'Y' if r.get('has_ucf') else 'N',r.get('ucf_amount',0),
                         r.get('fx_gl_type','-'),r.get('fx_gl_ghs',0),r.get('receipt_no','')] for r in rows]
            csv_data = export_csv_generic(headers, data_rows, 'UCC ACTUAL EXPENSES')
            body = csv_data.encode('utf-8')
            self.send_response(200)
            self.send_header('Content-Type', 'text/csv')
