    def do_DELETE(self):
        parsed = urlparse(self.path)
        path = parsed.path

        session = self.get_session()
        if not session:
            self.send_json({'error': 'Not authenticated'}, 401)
            return

        # DELETE /api/actuals/<id> — admin only
        if path.startswith('/api/actuals/'):
            actual_id = path.split('/')[-1]
            self.send_json(api_delete_actual(actual_id, session))
        elif path.startswith('/api/budget-uploads/'):
            upload_id = path.split('/')[-1]
            self.send_json(api_delete_budget_upload(upload_id, session))
        # DELETE /api/budgets/<id> — admin only
