def api_get_bank_accounts(session):
    conn = get_db()
    rows = [dict(r) for r in conn.execute("""
        SELECT b.*,
            COALESCE((SELECT SUM(amount_ghs) FROM fund_receipts fr WHERE fr.bank_account_id=b.id),0) as total_receipts,
            COALESCE((SELECT SUM(amount_ghs) FROM actuals a
                JOIN budgets bg ON a.budget_id=bg.id
                JOIN projects p ON bg.project_id=p.id
                WHERE p.id=b.project_id),0) as total_payments,
            p.project_code, p.title as project_title
        FROM bank_accounts b
        LEFT JOIN projects p ON b.project_id=p.id
        WHERE b.is_active=1
        ORDER BY b.bank_name, b.account_name
    """)]
    conn.close()
    return rows

def api_save_bank_account(data, session):
    conn = get_db()
    bid = data.get('id') or str(uuid.uuid4())
    if data.get('id'):
        conn.execute("""UPDATE bank_accounts SET account_name=?,bank_name=?,branch=?,
            account_number=?,account_type=?,currency=?,project_id=?,description=?,is_active=?
            WHERE id=?""",
            (data['account_name'],data['bank_name'],data.get('branch',''),
             data['account_number'],data.get('account_type','Current'),data.get('currency','GHS'),
             data.get('project_id') or None,data.get('description',''),int(data.get('is_active',1)),bid))
    else:
        conn.execute("""INSERT INTO bank_accounts(id,account_name,bank_name,branch,account_number,
            account_type,currency,project_id,description,opening_balance,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,?,?)""",
            (bid,data['account_name'],data['bank_name'],data.get('branch',''),data['account_number'],
             data.get('account_type','Current'),data.get('currency','GHS'),
             data.get('project_id') or None,data.get('description',''),
             float(data.get('opening_balance',0)),session['username']))
    _audit(conn, session, 'SAVE_BANK_ACCOUNT', 'bank_accounts', bid, data.get('account_name',''))
    conn.commit(); conn.close()
    return {'ok': True, 'id': bid}

def api_get_fund_receipts(session, project_id=None):
    conn = get_db()
    q = """SELECT fr.*, p.project_code, p.title as project_title,
        b.account_name as bank_account_name, b.bank_name, b.account_number
        FROM fund_receipts fr
        JOIN projects p ON fr.project_id=p.id
        LEFT JOIN bank_accounts b ON fr.bank_account_id=b.id"""
    args = []
    if project_id:
        q += " WHERE fr.project_id=?"
        args.append(project_id)
    q += " ORDER BY fr.receipt_date DESC"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows

def api_save_fund_receipt(data, session):
    conn = get_db()
    rid = data.get('id') or str(uuid.uuid4())
    rcode = data.get('receipt_code') or f"RCP-{datetime.now().strftime('%Y')}-{str(uuid.uuid4())[:6].upper()}"
    amount_ghs = float(data['amount_fcy']) * float(data.get('fx_rate',1))
    if data.get('id'):
        conn.execute("""UPDATE fund_receipts SET project_id=?,bank_account_id=?,receipt_date=?,
            donor=?,description=?,currency=?,amount_fcy=?,fx_rate=?,amount_ghs=?,
            reference_no=?,receipt_type=?,notes=? WHERE id=?""",
            (data['project_id'],data.get('bank_account_id'),data['receipt_date'],
             data['donor'],data['description'],data['currency'],float(data['amount_fcy']),
             float(data.get('fx_rate',1)),amount_ghs,data.get('reference_no',''),
             data.get('receipt_type','Grant Receipt'),data.get('notes',''),rid))
    else:
        conn.execute("""INSERT INTO fund_receipts(id,receipt_code,project_id,bank_account_id,
            receipt_date,donor,description,currency,amount_fcy,fx_rate,amount_ghs,
            reference_no,receipt_type,notes,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (rid,rcode,data['project_id'],data.get('bank_account_id'),data['receipt_date'],
             data['donor'],data['description'],data['currency'],float(data['amount_fcy']),
             float(data.get('fx_rate',1)),amount_ghs,data.get('reference_no',''),
             data.get('receipt_type','Grant Receipt'),data.get('notes',''),session['username']))
    _audit(conn, session, 'SAVE_FUND_RECEIPT', 'fund_receipts', rid,
           f"{data.get('donor','')} {amount_ghs:.2f} GHS")
    conn.commit(); conn.close()
    return {'ok': True, 'id': rid}

def api_get_bank_statement(session, account_id, date_from=None, date_to=None):
    """Returns a running bank statement with receipts & payments for an account."""
    conn = get_db()
    acct = conn.execute("SELECT * FROM bank_accounts WHERE id=?", (account_id,)).fetchone()
    if not acct:
        conn.close()
        return {'error': 'Account not found'}
    acct = dict(acct)

    date_filter = ""
    args_r, args_p = [], []
    if date_from:
        date_filter += " AND receipt_date >= ?" if 'receipt' not in date_filter else " AND receipt_date >= ?"
        args_r.append(date_from)
    if date_to:
        args_r.append(date_to)
    if date_from: args_p.append(date_from)
    if date_to: args_p.append(date_to)

    df_clause_r = (" AND receipt_date >= ?" if date_from else "") + (" AND receipt_date <= ?" if date_to else "")
    df_clause_a = (" AND expense_date >= ?" if date_from else "") + (" AND expense_date <= ?" if date_to else "")

    receipts = [dict(r) for r in conn.execute(
        f"SELECT *, amount_ghs as amount, 'Receipt' as txn_type FROM fund_receipts WHERE bank_account_id=?{df_clause_r} ORDER BY receipt_date",
        [account_id]+args_r)]
    payments = [dict(r) for r in conn.execute(
        f"""SELECT a.*, a.amount_ghs as amount, 'Payment' as txn_type,
            p.project_code, b.account_name as budget_line
            FROM actuals a
            JOIN projects p ON a.project_id=p.id
            LEFT JOIN budgets b ON a.budget_id=b.id
            WHERE a.bank_account_id=?{df_clause_a} ORDER BY expense_date""",
        [account_id]+args_p)] if date_from or date_to else         [dict(r) for r in conn.execute(
            """SELECT a.*, a.amount_ghs as amount, 'Payment' as txn_type,
                p.project_code, b.account_name as budget_line
                FROM actuals a JOIN projects p ON a.project_id=p.id
                LEFT JOIN budgets b ON a.budget_id=b.id
                WHERE a.bank_account_id=?""", [account_id])]

    total_receipts = sum(r['amount_ghs'] for r in receipts)
    total_payments = sum(r['amount_ghs'] for r in payments)
    balance = acct['opening_balance'] + total_receipts - total_payments

    conn.close()
    return {
        'account': acct,
        'receipts': receipts,
        'payments': payments,
        'total_receipts': total_receipts,
        'total_payments': total_payments,
        'opening_balance': acct['opening_balance'],
        'closing_balance': balance,
    }

def api_save_bank_reconciliation(data, session):
    conn = get_db()
    rid = str(uuid.uuid4())
    stmt_bal = float(data['statement_balance'])
    book_bal = float(data['book_balance'])
    conn.execute("""INSERT INTO bank_reconciliations
        (id,bank_account_id,recon_date,statement_balance,book_balance,difference,status,notes,reconciled_by)
        VALUES(?,?,?,?,?,?,?,?,?)""",
        (rid, data['bank_account_id'], data['recon_date'], stmt_bal, book_bal,
         round(stmt_bal - book_bal, 2), data.get('status','Draft'),
         data.get('notes',''), session['username']))
    _audit(conn, session, 'BANK_RECONCILIATION', 'bank_reconciliations', rid,
           f"Account {data['bank_account_id']} reconciled at {data['recon_date']}")
    conn.commit(); conn.close()
    return {'ok': True, 'id': rid}

def api_get_bank_reconciliations(session, account_id=None):
    conn = get_db()
    q = """SELECT r.*, b.account_name, b.bank_name, b.account_number
        FROM bank_reconciliations r JOIN bank_accounts b ON r.bank_account_id=b.id"""
    args = []
    if account_id:
        q += " WHERE r.bank_account_id=?"
        args.append(account_id)
    q += " ORDER BY r.recon_date DESC"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows


# ═══════════════════════════════════════════════════════════════════════════
# JOURNAL VOUCHER (JV) MODULE — UCC-FMS v2.0
# Full double-entry bookkeeping with approval workflow and role-based access
# ═══════════════════════════════════════════════════════════════════════════
#
# JV TYPES:
#   JV  - General Journal Voucher         (Finance Officer + Admin)
#   PV  - Payment Voucher                 (Finance Officer + Admin)
#   RV  - Receipt Voucher                 (Finance Officer + Admin)
#   BV  - Bank Transfer Voucher           (Finance Officer + Admin)
#   AJV - Adjustment Journal Voucher      (Admin only)
#   RJV - Reversing Journal Voucher       (Admin only)
#
# APPROVAL WORKFLOW:
#   Project Leader  → can DRAFT PV/RV for their project only
#   Finance Officer → can DRAFT + SUBMIT all types; can APPROVE JV/PV/RV/BV
#   Admin           → can DRAFT + SUBMIT + APPROVE + POST all types; 
#                     only Admin can approve AJV/RJV; only Admin can void/delete
#
# STATUS FLOW:
#   Draft → Submitted → Approved → Posted → (Reversed if needed)
#   Any status → Void  (Admin only, with reason)
# ═══════════════════════════════════════════════════════════════════════════

def init_jv_db():
    """Create JV tables and extend COA with balance-sheet accounts."""
    conn = get_db()
    c = conn.cursor()
    try:
        if c.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='journal_vouchers'").fetchone():
            jv_cols = [r[1] for r in c.execute("PRAGMA table_info(journal_vouchers)")]
            if 'jv_number' not in jv_cols:
                c.execute("DROP TABLE IF EXISTS jv_lines")
                c.execute("DROP TABLE IF EXISTS journal_vouchers")
                print("  JV repair: dropped legacy jv_code schema; rebuilding canonical jv_number schema")
    except Exception as _jv_repair_exc:
        print("  JV repair warning:", _jv_repair_exc)
    c.executescript("""
    -- ── JOURNAL VOUCHER HEADER ─────────────────────────────────────────────
    CREATE TABLE IF NOT EXISTS journal_vouchers (
        id          TEXT PRIMARY KEY,
        jv_number   TEXT UNIQUE NOT NULL,
        jv_type     TEXT NOT NULL CHECK(jv_type IN ('JV','PV','RV','BV','AJV','RJV')),
        jv_date     TEXT NOT NULL,
        period      TEXT NOT NULL,          -- YYYY-MM accounting period
        description TEXT NOT NULL,
        narration   TEXT,
        reference   TEXT,
        project_id  TEXT REFERENCES projects(id),
        bank_account_id TEXT REFERENCES bank_accounts(id),
        currency    TEXT DEFAULT 'GHS',
        fx_rate     REAL DEFAULT 1.0,
        total_debit  REAL DEFAULT 0,
        total_credit REAL DEFAULT 0,
        status      TEXT DEFAULT 'Draft'    -- Draft|Submitted|Approved|Posted|Reversed|Void
            CHECK(status IN ('Draft','Submitted','Approved','Posted','Reversed','Void')),
        is_reversal  INTEGER DEFAULT 0,
        reversal_of  TEXT REFERENCES journal_vouchers(id),
        reversed_by  TEXT REFERENCES journal_vouchers(id),
        prepared_by  TEXT NOT NULL,
        prepared_at  TEXT DEFAULT (datetime('now')),
        submitted_by TEXT,
        submitted_at TEXT,
        approved_by  TEXT,
        approved_at  TEXT,
        posted_by    TEXT,
        posted_at    TEXT,
        voided_by    TEXT,
        voided_at    TEXT,
        void_reason  TEXT,
        auto_generated INTEGER DEFAULT 0,   -- 1 = system-created from actuals/payroll
        source_module  TEXT,                -- 'actuals'|'payroll'|'receipts'|'manual'
        source_id      TEXT,
        notes          TEXT,
        created_at  TEXT DEFAULT (datetime('now'))
    );

    -- ── JOURNAL VOUCHER LINE ITEMS (DOUBLE-ENTRY) ─────────────────────────
    CREATE TABLE IF NOT EXISTS jv_lines (
        id          TEXT PRIMARY KEY,
        jv_id       TEXT NOT NULL REFERENCES journal_vouchers(id) ON DELETE CASCADE,
        line_number INTEGER NOT NULL,
        coa_id      TEXT NOT NULL REFERENCES chart_of_accounts(id),
        description TEXT NOT NULL,
        debit_amount  REAL DEFAULT 0,
        credit_amount REAL DEFAULT 0,
        project_id    TEXT REFERENCES projects(id),
        cost_centre   TEXT,
        bank_account_id TEXT REFERENCES bank_accounts(id),
        tax_code      TEXT,
        created_at    TEXT DEFAULT (datetime('now'))
    );

    -- ── LEDGER (POSTED ENTRIES — immutable once posted) ───────────────────
    CREATE TABLE IF NOT EXISTS general_ledger (
        id          TEXT PRIMARY KEY,
        jv_id       TEXT NOT NULL REFERENCES journal_vouchers(id),
        jv_number   TEXT NOT NULL,
        jv_line_id  TEXT REFERENCES jv_lines(id),
        ledger_date TEXT NOT NULL,
        period      TEXT NOT NULL,
        coa_id      TEXT NOT NULL REFERENCES chart_of_accounts(id),
        coa_code    TEXT NOT NULL,
        account_name TEXT NOT NULL,
        description TEXT NOT NULL,
        debit_amount  REAL DEFAULT 0,
        credit_amount REAL DEFAULT 0,
        running_balance REAL DEFAULT 0,
        project_id    TEXT,
        project_code  TEXT,
        posted_by   TEXT NOT NULL,
        posted_at   TEXT DEFAULT (datetime('now'))
    );

    -- ── ACCOUNTING PERIODS ────────────────────────────────────────────────
    CREATE TABLE IF NOT EXISTS accounting_periods (
        id          TEXT PRIMARY KEY,
        period      TEXT UNIQUE NOT NULL,   -- YYYY-MM
        period_name TEXT NOT NULL,
        status      TEXT DEFAULT 'Open'
            CHECK(status IN ('Open','Closed','Locked')),
        opened_by   TEXT,
        closed_by   TEXT,
        closed_at   TEXT,
        created_at  TEXT DEFAULT (datetime('now'))
    );

    -- ── JV AUDIT TRAIL ────────────────────────────────────────────────────
    CREATE TABLE IF NOT EXISTS jv_audit (
        id          TEXT PRIMARY KEY,
        jv_id       TEXT NOT NULL REFERENCES journal_vouchers(id),
        jv_number   TEXT NOT NULL,
        timestamp   TEXT DEFAULT (datetime('now')),
        username    TEXT NOT NULL,
        user_role   TEXT,
        action      TEXT NOT NULL,
        old_status  TEXT,
        new_status  TEXT,
        details     TEXT
    );
    """)

    # ── SEED ADDITIONAL COA accounts (all conforming to 1-6xxx scheme) ───
    # These supplement _reseed_coa with accounts needed by JV auto-generation.
    # All codes strictly conform: Assets 1xxx, Liabilities 2xxx,
    # Funds & Reserves 3xxx, Revenue 4xxx, Expenses 6xxx.
    extra_accounts = [
        # Assets — additional sub-accounts
        ('1150','Assets','Non-Current Assets','Accumulated Depreciation (Contra)','Asset',0),
        ('1160','Assets','Non-Current Assets','Net Book Value — PPE','Asset',0),
        # Liabilities — tax & payroll payables (supplement 2xxx)
        ('2034','Liabilities','Tax Payables','WHVAT Payable — GRA','Liability',0),
        ('2035','Liabilities','Tax Payables','UCC Common Fund Payable','Liability',0),
        ('2036','Liabilities','Payroll Liabilities','Net Salary Payable','Liability',0),
        ('2037','Liabilities','Payroll Liabilities','Tier 2 Payable — Trustee','Liability',0),
        # Funds & Reserves — additional
        ('3016','Funds & Reserves','Restricted Funds','USAID Project Fund','Equity',0),
        ('3017','Funds & Reserves','Restricted Funds','GIZ Project Fund','Equity',0),
        ('3018','Funds & Reserves','Restricted Funds','Other Restricted Donor Fund','Equity',0),
    ]
    for row in extra_accounts:
        coa_id = str(uuid.uuid4())
        c.execute("""INSERT OR IGNORE INTO chart_of_accounts
            (id,code,category,sub_category,account_name,account_type,vat_applicable)
            VALUES(?,?,?,?,?,?,?)""", (coa_id, *row))

    # ── SEED OPEN ACCOUNTING PERIODS (current + prior 3 months) ─────────
    from datetime import datetime as _dt, date as _date, timedelta as _td
    today = _date.today()
    for i in range(-3, 3):
        month = (today.replace(day=1) + _td(days=32*i)).replace(day=1)
        period = month.strftime('%Y-%m')
        period_name = month.strftime('%B %Y')
        status = 'Open' if i >= 0 else 'Open'  # keep all open for demo
        c.execute("""INSERT OR IGNORE INTO accounting_periods(id,period,period_name,status)
            VALUES(?,?,?,?)""", (str(uuid.uuid4()), period, period_name, status))

    conn.commit()
    conn.close()


# ── JV NUMBER GENERATOR ───────────────────────────────────────────────────
def _seq_code(conn, table, column, prefix, width):
    """Collision-proof sequential code generator.

    Finds the MAX numeric suffix among existing '<prefix>NNN' values, then bumps
    until the candidate is unused. Replaces fragile COUNT(*)+1 schemes, which
    produce duplicate / UNIQUE-violating codes once rows are deleted, imported
    or manually numbered (e.g. vendors.vendor_code, journal_vouchers.jv_number)."""
    n = 0
    try:
        for _r in conn.execute("SELECT %s FROM %s WHERE %s LIKE ?" % (column, table, column), (prefix + '%',)).fetchall():
            _s = str(_r[0] or '')[len(prefix):]
            if _s.isdigit() and int(_s) > n:
                n = int(_s)
    except Exception:
        pass
    n += 1
    code = prefix + str(n).zfill(width)
    try:
        while conn.execute("SELECT 1 FROM %s WHERE %s=? LIMIT 1" % (table, column), (code,)).fetchone():
            n += 1
            code = prefix + str(n).zfill(width)
    except Exception:
        pass
    return code


def _next_jv_number(conn, jv_type):
    """Generate sequential JV number: JV-2024-0001, PV-2024-0001, etc."""
    from datetime import date as _d
    yr = _d.today().year
    return _seq_code(conn, 'journal_vouchers', 'jv_number', f'{jv_type}-{yr}-', 4)


# ── ROLE PERMISSIONS ──────────────────────────────────────────────────────
def _jv_can_create(session, jv_type):
    role = session.get('role','')
    if role == 'Admin': return True
    if role == 'Finance Officer': return jv_type in ('JV','PV','RV','BV')
    if role == 'Project Leader': return jv_type in ('PV','RV')
    return False

def _jv_can_submit(session, jv): return session.get('role') in ('Admin','Finance Officer')
def _jv_can_approve(session, jv_type):
    role = session.get('role','')
    if role == 'Admin': return True
    if role == 'Finance Officer': return jv_type in ('JV','PV','RV','BV')
    return False
def _jv_can_post(session): return session.get('role') == 'Admin'
def _jv_can_void(session): return session.get('role') == 'Admin'


# ── JV VALIDATION ─────────────────────────────────────────────────────────
def _validate_jv_lines(lines):
    """Check lines are non-empty, balanced, and each line has exactly one of debit/credit."""
    if not lines or len(lines) < 2:
        return False, "A journal entry must have at least 2 lines."
    import math
    total_dr = 0.0; total_cr = 0.0
    for i, l in enumerate(lines):
        dr = float(l.get('debit_amount',0) or 0)
        cr = float(l.get('credit_amount',0) or 0)
        if not (math.isfinite(dr) and math.isfinite(cr)):
            return False, f"Line {i+1}: amount is not a finite number (NaN/Infinity rejected)."
        if dr < 0 or cr < 0:
            return False, f"Line {i+1}: amounts cannot be negative."
        if dr > 0 and cr > 0:
            return False, f"Line {i+1}: cannot have both a debit and credit amount on the same line."
        if dr == 0 and cr == 0:
            return False, f"Line {i+1}: must have either a debit or credit amount."
        if not l.get('coa_id'):
            return False, f"Line {i+1}: no account selected."
        total_dr += dr; total_cr += cr
    if abs(total_dr - total_cr) > 0.005:
        return False, f"Journal is NOT balanced: Debits GHS {total_dr:,.2f} ≠ Credits GHS {total_cr:,.2f}"
    return True, "OK"


# ── API: GET JOURNAL VOUCHERS ──────────────────────────────────────────────
def api_get_jvs(session, filters=None):
    conn = get_db()
    q = """SELECT jv.*, p.project_code, p.title as project_title
        FROM journal_vouchers jv
        LEFT JOIN projects p ON jv.project_id=p.id"""
    args = []
    wheres = []

    # Project Leaders only see their own projects' vouchers
    if session.get('role') == 'Project Leader':
        # get their projects via project_code stored in employees or just by created_by
        wheres.append("(jv.prepared_by=? OR jv.status IN ('Approved','Posted'))")
        args.append(session.get('username',''))

    if filters:
        if filters.get('jv_type'):
            wheres.append("jv.jv_type=?"); args.append(filters['jv_type'])
        if filters.get('status'):
            wheres.append("jv.status=?"); args.append(filters['status'])
        if filters.get('period'):
            wheres.append("jv.period=?"); args.append(filters['period'])
        if filters.get('project_id'):
            wheres.append("jv.project_id=?"); args.append(filters['project_id'])
        if filters.get('date_from'):
            wheres.append("jv.jv_date>=?"); args.append(filters['date_from'])
        if filters.get('date_to'):
            wheres.append("jv.jv_date<=?"); args.append(filters['date_to'])

    # [C2] Enforce the viewer's org-unit read scope on the JV list (mirrors the
    # GL listing). Unrestricted for Admin/university; scoped users see only JVs
    # stamped to a unit they may read.
    if '_ucc_gl_scope_clause' in globals():
        _uf, _up = _ucc_gl_scope_clause(conn, session, alias='jv')
        if _uf:
            wheres.append(_uf.replace(' AND ', '', 1).strip()); args += _up

    if wheres:
        q += " WHERE " + " AND ".join(wheres)
    q += " ORDER BY jv.jv_date DESC, jv.jv_number DESC LIMIT 300"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows


def api_get_jv_detail(session, jv_id):
    conn = get_db()
    jv = conn.execute("""SELECT jv.*, p.project_code, p.title as project_title,
        b.account_name as bank_account_name, b.bank_name, b.account_number
        FROM journal_vouchers jv
        LEFT JOIN projects p ON jv.project_id=p.id
        LEFT JOIN bank_accounts b ON jv.bank_account_id=b.id
        WHERE jv.id=?""", (jv_id,)).fetchone()
    if not jv:
        conn.close(); return None
    jv = dict(jv)
    # [C1 IDOR] Enforce the viewer's org-unit read scope: a scoped (non-Admin,
    # non-university) user may only open a JV belonging to a unit they may read.
    if '_ucc_resolve_read_scope' in globals():
        try:
            enforced = _ucc_resolve_read_scope(conn, session)
            if enforced is not None and jv.get('unit_id') not in enforced:
                conn.close(); return None
        except Exception:
            conn.close(); return None  # fail closed on scope-resolution error
    lines = [dict(r) for r in conn.execute("""
        SELECT l.*, c.code as coa_code, c.account_name, c.category, c.account_type,
            p.project_code, b.account_name as bank_name
        FROM jv_lines l
        JOIN chart_of_accounts c ON l.coa_id=c.id
        LEFT JOIN projects p ON l.project_id=p.id
        LEFT JOIN bank_accounts b ON l.bank_account_id=b.id
        WHERE l.jv_id=? ORDER BY l.line_number""", (jv_id,))]
    audit = [dict(r) for r in conn.execute(
        "SELECT * FROM jv_audit WHERE jv_id=? ORDER BY timestamp DESC", (jv_id,))]
    jv['lines'] = lines
    jv['audit_trail'] = audit
    conn.close()
    return jv


def api_save_jv(data, session):
    """Create or update a JV (Draft only). Lines replaced wholesale."""
    role = session.get('role','')
    jv_type = data.get('jv_type','JV')

    if not _jv_can_create(session, jv_type):
        return {'ok': False, 'error': f'Your role ({role}) cannot create {jv_type} vouchers.'}

    lines_data = data.get('lines', [])
    ok_bal, msg = _validate_jv_lines(lines_data)
    if not ok_bal:
        return {'ok': False, 'error': msg}

    conn = get_db()

    # Check period is open
    period = data.get('period') or data.get('jv_date','')[:7]
    per_row = conn.execute("SELECT status FROM accounting_periods WHERE period=?", (period,)).fetchone()
    if per_row and per_row['status'] in ('Closed','Locked'):
        conn.close()
        return {'ok': False, 'error': f'Period {period} is not open. Cannot save or post to a closed/locked period.'}

    # Hard-require an org unit: every JV must attribute to a unit (explicit pick or the
    # poster's home unit). No silent default — reject so the unit is chosen at entry.
    if '_ucc_resolve_write_unit' in globals():
        if not _ucc_resolve_write_unit(conn, data, session):
            conn.close()
            return {'ok': False, 'error': 'A unit / cost centre must be selected for this journal voucher.'}

    jv_id = data.get('id') or str(uuid.uuid4())
    is_new = not data.get('id')

    # Defensive defaults: these were hard dict accesses (_jv_desc,
    # _jv_date) that raised a 500 KeyError for any caller — API client, bulk
    # import or auto-generated JV — that supplied a narration/date under another key.
    _jv_desc = data.get('description') or data.get('narration') or 'Journal Voucher'
    _jv_date = data.get('jv_date') or data.get('date') or date.today().isoformat()

    total_dr = sum(float(l.get('debit_amount',0)) for l in lines_data)
    total_cr = sum(float(l.get('credit_amount',0)) for l in lines_data)

    if is_new:
        jv_num = _next_jv_number(conn, jv_type)
        _wunit = _ucc_resolve_write_unit(conn, data, session) if '_ucc_resolve_write_unit' in globals() else None
        conn.execute("""INSERT INTO journal_vouchers
            (id,jv_number,jv_type,jv_date,period,description,narration,reference,
             project_id,bank_account_id,currency,fx_rate,total_debit,total_credit,
             status,prepared_by,source_module,source_id,notes,unit_id)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (jv_id, jv_num, jv_type, _jv_date, period,
             _jv_desc, data.get('narration',''), data.get('reference',''),
             data.get('project_id') or None, data.get('bank_account_id') or None,
             data.get('currency','GHS'), float(data.get('fx_rate',1)),
             total_dr, total_cr, 'Draft', session['username'],
             data.get('source_module','manual'), data.get('source_id'),
             data.get('notes',''), _wunit))
    else:
        # Only Drafts can be edited
        existing = conn.execute("SELECT status,jv_number,jv_type FROM journal_vouchers WHERE id=?", (jv_id,)).fetchone()
        if not existing:
            conn.close(); return {'ok': False, 'error': 'JV not found'}
        if existing['status'] != 'Draft':
            conn.close(); return {'ok': False, 'error': f'Only Draft JVs can be edited. This JV is {existing["status"]}.'}
        jv_num = existing['jv_number']
        _wunit_u = _ucc_resolve_write_unit(conn, data, session) if '_ucc_resolve_write_unit' in globals() else None
        conn.execute("""UPDATE journal_vouchers SET jv_date=?,period=?,description=?,narration=?,
            reference=?,project_id=?,bank_account_id=?,currency=?,fx_rate=?,
            total_debit=?,total_credit=?,notes=?,unit_id=? WHERE id=?""",
            (_jv_date, period, _jv_desc, data.get('narration',''),
             data.get('reference',''), data.get('project_id') or None,
             data.get('bank_account_id') or None,
             data.get('currency','GHS'), float(data.get('fx_rate',1)),
             total_dr, total_cr, data.get('notes',''), _wunit_u, jv_id))
        conn.execute("DELETE FROM jv_lines WHERE jv_id=?", (jv_id,))

    # Insert lines
    for i, line in enumerate(lines_data):
        conn.execute("""INSERT INTO jv_lines
            (id,jv_id,line_number,coa_id,description,debit_amount,credit_amount,
             project_id,cost_centre,bank_account_id,tax_code)
            VALUES(?,?,?,?,?,?,?,?,?,?,?)""",
            (str(uuid.uuid4()), jv_id, i+1,
             line['coa_id'], line.get('description', _jv_desc),
             float(line.get('debit_amount',0)), float(line.get('credit_amount',0)),
             line.get('project_id') or None, line.get('cost_centre',''),
             line.get('bank_account_id') or None, line.get('tax_code','')))

    action = 'CREATE_JV' if is_new else 'UPDATE_JV'
    _jv_audit(conn, session, jv_id, jv_num, action, None, 'Draft',
              f'{jv_type} | {_jv_desc} | DR:{total_dr:.2f} CR:{total_cr:.2f}')
    _audit(conn, session, action, 'journal_vouchers', jv_id, f'{jv_num}: {_jv_desc}')
    conn.commit(); conn.close()
    return {'ok': True, 'id': jv_id, 'jv_number': jv_num}


def api_jv_workflow(data, session):
    """Handle JV status transitions: submit / approve / post / void / reverse."""
    jv_id = data.get('jv_id')
    action = data.get('action')  # submit | approve | post | void | reverse

    conn = get_db()
    jv = conn.execute("SELECT * FROM journal_vouchers WHERE id=?", (jv_id,)).fetchone()
    if not jv:
        conn.close(); return {'ok': False, 'error': 'JV not found'}
    jv = dict(jv)
    role = session.get('role','')

    # [H2] Org-unit authorisation: a scoped (non-Admin) actor may only act on a
    # JV belonging to a unit within their enforced scope. This sits alongside the
    # existing SoD/dual-control checks below (it does not replace them). Admins
    # (enforced is None) are exempt and may act institution-wide.
    if '_ucc_resolve_read_scope' in globals():
        try:
            _enf = _ucc_resolve_read_scope(conn, session)
        except Exception:
            _enf = set()  # fail closed
        if _enf is not None and jv.get('unit_id') not in _enf:
            conn.close()
            return {'ok': False, 'error': 'You are not authorised to act on a journal voucher outside your unit.'}

    old_status = jv['status']
    new_status = None
    extra_fields = {}

    if action == 'submit':
        if not _jv_can_submit(session, jv):
            conn.close(); return {'ok': False, 'error': 'Insufficient permissions to submit JVs'}
        if old_status != 'Draft':
            conn.close(); return {'ok': False, 'error': f'Only Draft JVs can be submitted (current: {old_status})'}
        new_status = 'Submitted'
        extra_fields = {'submitted_by': session['username'], 'submitted_at': datetime.now().isoformat()}

    elif action == 'approve':
        if not _jv_can_approve(session, jv['jv_type']):
            conn.close(); return {'ok': False, 'error': f'Your role cannot approve {jv["jv_type"]} vouchers'}
        if old_status not in ('Submitted',):
            conn.close(); return {'ok': False, 'error': f'Only Submitted JVs can be approved (current: {old_status})'}
        if jv['prepared_by'] == session['username'] and role != 'Admin':
            conn.close(); return {'ok': False, 'error': 'You cannot approve a JV you prepared (segregation of duties)'}
        new_status = 'Approved'
        extra_fields = {'approved_by': session['username'], 'approved_at': datetime.now().isoformat()}

    elif action == 'post':
        if not _jv_can_post(session):
            conn.close(); return {'ok': False, 'error': 'Only Admins can post JVs to the general ledger'}
        if old_status != 'Approved':
            conn.close(); return {'ok': False, 'error': f'Only Approved JVs can be posted (current: {old_status})'}
        # Dual control on high-value reversals: the admin who CREATED a reversing entry
        # cannot also post it to the ledger -- a SECOND admin must post it. Mirrors the
        # maker-checker on high-value payments (opt-in via dual_control_threshold_ghs; 0=off).
        try:
            if jv.get('is_reversal'):
                _rr = conn.execute("SELECT value FROM settings WHERE key='dual_control_threshold_ghs'").fetchone()
                _rthr = float((_rr['value'] if _rr else 0) or 0)
                _ramt = max(float(jv.get('total_debit') or 0), float(jv.get('total_credit') or 0))
                if _rthr > 0 and _ramt >= _rthr and (jv.get('prepared_by') or '') == session.get('username'):
                    conn.close(); return {'ok': False, 'error': 'Dual control: a reversal of GHS {:,.0f} or more must be posted by a DIFFERENT admin than the one who created it. A second approver must post this reversing entry.'.format(_rthr)}
        except Exception:
            pass
        # Check period is not locked
        per_row = conn.execute("SELECT status FROM accounting_periods WHERE period=?", (jv['period'],)).fetchone()
        if per_row and per_row['status'] in ('Closed','Locked'):
            conn.close(); return {'ok': False, 'error': f'Period {jv["period"]} is not open'}
        new_status = 'Posted'
        extra_fields = {'posted_by': session['username'], 'posted_at': datetime.now().isoformat()}
        # Write to general ledger
        lines = conn.execute("""SELECT l.*, c.code as coa_code, c.account_name, p.project_code
            FROM jv_lines l JOIN chart_of_accounts c ON l.coa_id=c.id
            LEFT JOIN projects p ON l.project_id=p.id
            WHERE l.jv_id=? ORDER BY l.line_number""", (jv_id,)).fetchall()
        _jv_unit = jv.get('unit_id') if hasattr(jv, 'get') else None
        for line in lines:
            conn.execute("""INSERT INTO general_ledger
                (id,jv_id,jv_number,jv_line_id,ledger_date,period,coa_id,coa_code,
                 account_name,description,debit_amount,credit_amount,project_id,
                 project_code,posted_by,unit_id)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (str(uuid.uuid4()), jv_id, jv['jv_number'], line['id'],
                 jv['jv_date'], jv['period'], line['coa_id'], line['coa_code'],
                 line['account_name'], line['description'],
                 line['debit_amount'], line['credit_amount'],
                 line['project_id'], (line['project_code'] if 'project_code' in line.keys() and line['project_code'] is not None else ''),
                 session['username'], _jv_unit))
        # If this is a staged reversal (dual control), posting it now flips the original
        # voucher to Reversed -- the offsetting GL lines have just landed.
        if jv.get('is_reversal') and jv.get('reversal_of'):
            conn.execute("UPDATE journal_vouchers SET status='Reversed', reversed_by=? WHERE id=?",
                         (jv_id, jv['reversal_of']))

    elif action == 'void':
        if not _jv_can_void(session):
            conn.close(); return {'ok': False, 'error': 'Only Admins can void JVs'}
        if old_status == 'Void':
            conn.close(); return {'ok': False, 'error': 'JV is already voided'}
        if old_status == 'Posted':
            conn.close(); return {'ok': False, 'error': 'A Posted entry cannot be voided -- its ledger amounts would be orphaned. Use Reverse to create a balanced reversing entry that preserves the audit trail.'}
        reason = data.get('reason','')
        if not reason:
            conn.close(); return {'ok': False, 'error': 'A void reason is required'}
        new_status = 'Void'
        extra_fields = {'voided_by': session['username'], 'voided_at': datetime.now().isoformat(),
                        'void_reason': reason}

    elif action == 'reverse':
        if not _jv_can_post(session):
            conn.close(); return {'ok': False, 'error': 'Only Admins can create reversing JVs'}
        if old_status != 'Posted':
            conn.close(); return {'ok': False, 'error': 'Only Posted JVs can be reversed'}
        if jv.get('reversed_by'):
            conn.close(); return {'ok': False, 'error': 'This JV has already been reversed'}
        _rev_reason = (data.get('reason') or '').strip()
        if len(_rev_reason) < 5:
            conn.close(); return {'ok': False, 'error': 'A reversal reason (at least 5 characters) is required for the audit trail.'}
        # Create the reversing JV automatically
        rev_id = str(uuid.uuid4())
        rev_num = _next_jv_number(conn, 'RJV')
        rev_date = data.get('reversal_date', datetime.now().strftime('%Y-%m-%d'))
        rev_period = rev_date[:7]
        conn.execute("""INSERT INTO journal_vouchers
            (id,jv_number,jv_type,jv_date,period,description,narration,project_id,
             currency,fx_rate,total_debit,total_credit,status,is_reversal,reversal_of,
             prepared_by,source_module,notes,unit_id)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (rev_id, rev_num, 'RJV', rev_date, rev_period,
             f'REVERSAL of {jv["jv_number"]}: {jv["description"]}',
             f'Reversal of {jv["jv_number"]} -- {_rev_reason}',
             jv['project_id'], jv['currency'], jv['fx_rate'],
             jv['total_credit'], jv['total_debit'],  # swap totals
             'Draft', 1, jv_id, session['username'], 'reversal', jv_id,
             (jv.get('unit_id') if hasattr(jv, 'get') else None)))
        # Create reversed lines (swap debit/credit)
        orig_lines = conn.execute(
            "SELECT * FROM jv_lines WHERE jv_id=? ORDER BY line_number", (jv_id,)).fetchall()
        for line in orig_lines:
            conn.execute("""INSERT INTO jv_lines
                (id,jv_id,line_number,coa_id,description,debit_amount,credit_amount,
                 project_id,cost_centre,bank_account_id,tax_code)
                VALUES(?,?,?,?,?,?,?,?,?,?,?)""",
                (str(uuid.uuid4()), rev_id, line['line_number'], line['coa_id'],
                 f'Reversal: {line["description"]}',
                 line['credit_amount'], line['debit_amount'],  # swap
                 line['project_id'], line['cost_centre'],
                 line['bank_account_id'], line['tax_code']))
        # Mark original as Reversed
        conn.execute("UPDATE journal_vouchers SET status='Reversed', reversed_by=? WHERE id=?",
                     (rev_id, jv_id))
        _jv_audit(conn, session, jv_id, jv['jv_number'], 'REVERSED', 'Posted', 'Reversed',
                  f'Reversed by {rev_num}')
        _jv_audit(conn, session, rev_id, rev_num, 'CREATE_REVERSAL', None, 'Draft',
                  f'Reversal of {jv["jv_number"]}')
        _audit(conn, session, 'REVERSE_JV', 'journal_vouchers', rev_id,
               f'{rev_num} reverses {jv["jv_number"]} | reason: {_rev_reason}')
        conn.commit(); conn.close()
        return {'ok': True, 'message': f'Reversing JV {rev_num} created in Draft status', 'reversal_id': rev_id}
    else:
        conn.close(); return {'ok': False, 'error': f'Unknown action: {action}'}

    # Update status and extra fields
    set_clause = "status=?"
    set_vals = [new_status]
    for k, v in extra_fields.items():
        set_clause += f",{k}=?"
        set_vals.append(v)
    set_vals.append(jv_id)
    conn.execute(f"UPDATE journal_vouchers SET {set_clause} WHERE id=?", set_vals)

    _jv_audit(conn, session, jv_id, jv['jv_number'], action.upper()+'_JV',
              old_status, new_status, data.get('reason',''))
    _audit(conn, session, f'JV_{action.upper()}', 'journal_vouchers', jv_id,
           f'{jv["jv_number"]} → {new_status}')
    conn.commit(); conn.close()
    return {'ok': True, 'new_status': new_status, 'jv_number': jv['jv_number']}


def api_get_general_ledger(session, filters=None):
    """Query the general ledger with running balance calculation."""
    conn = get_db()
    q = """SELECT gl.*, c.category, c.account_type, p.project_code
        FROM general_ledger gl
        JOIN chart_of_accounts c ON gl.coa_id=c.id
        LEFT JOIN projects p ON gl.project_id=p.id"""
    args = []
    wheres = []
    if filters:
        if filters.get('coa_id'):
            wheres.append("gl.coa_id=?"); args.append(filters['coa_id'])
        if filters.get('coa_code'):
            wheres.append("gl.coa_code=?"); args.append(filters['coa_code'])
        if filters.get('period'):
            wheres.append("gl.period=?"); args.append(filters['period'])
        if filters.get('project_id'):
            wheres.append("gl.project_id=?"); args.append(filters['project_id'])
        if filters.get('date_from'):
            wheres.append("gl.ledger_date>=?"); args.append(filters['date_from'])
        if filters.get('date_to'):
            wheres.append("gl.ledger_date<=?"); args.append(filters['date_to'])
    # UCC (Phase 1c): enforce the viewer's org-unit scope on the ledger listing.
    if '_ucc_gl_scope_clause' in globals():
        _uf, _up = _ucc_gl_scope_clause(conn, session)
        if _uf:
            wheres.append(_uf.replace(' AND ', '', 1).strip()); args += _up
    if wheres:
        q += " WHERE " + " AND ".join(wheres)
    q += " ORDER BY gl.ledger_date, gl.jv_number, gl.id"
    rows = [dict(r) for r in conn.execute(q, args)]

    # Compute running balance per account
    bal = {}
    for r in rows:
        k = r['coa_id']
        if k not in bal: bal[k] = 0
        # Assets/Expenses: Dr increases, Cr decreases
        # Liabilities/Income/Equity: Cr increases, Dr decreases
        acct_type = r.get('account_type','')
        if acct_type in ('Asset','Expense','Capital','Overhead','Contra'):
            bal[k] += r['debit_amount'] - r['credit_amount']
        else:
            bal[k] += r['credit_amount'] - r['debit_amount']
        r['running_balance'] = round(bal[k], 2)

    conn.close()
    return rows


def api_get_ledger_accounts_summary(session, period=None):
    """Account balances summary for a period (for trial balance)."""
    conn = get_db()
    q = """SELECT gl.coa_id, gl.coa_code, gl.account_name, c.category, c.account_type,
        COALESCE(SUM(gl.debit_amount),0) as total_debit,
        COALESCE(SUM(gl.credit_amount),0) as total_credit,
        COUNT(*) as entry_count
        FROM general_ledger gl
        JOIN chart_of_accounts c ON gl.coa_id=c.id"""
    args = []
    if period:
        q += " WHERE gl.period=?"; args.append(period)
    q += " GROUP BY gl.coa_id, gl.coa_code, gl.account_name, c.category, c.account_type"
    q += " ORDER BY gl.coa_code"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows


def api_get_accounting_periods(session):
    conn = get_db()
    rows = [dict(r) for r in conn.execute(
        "SELECT * FROM accounting_periods ORDER BY period DESC")]
    conn.close()
    return rows


def api_manage_period(data, session):
    """Open, close, or lock an accounting period (Admin only)."""
    if session.get('role') != 'Admin':
        return {'ok': False, 'error': 'Only Admins can manage accounting periods'}
    conn = get_db()
    action = data.get('action')
    period = data.get('period')
    status_map = {'open':'Open','close':'Closed','lock':'Locked'}
    new_status = status_map.get(action)
    if not new_status:
        conn.close(); return {'ok': False, 'error': 'Invalid action'}
    extra = {}
    if action in ('close','lock'):
        extra = {'closed_by': session['username'], 'closed_at': datetime.now().isoformat()}
    set_parts = ["status=?"]
    vals = [new_status]
    for k,v in extra.items():
        set_parts.append(f"{k}=?"); vals.append(v)
    vals.append(period)
    conn.execute(f"UPDATE accounting_periods SET {','.join(set_parts)} WHERE period=?", vals)
    _audit(conn, session, f'PERIOD_{action.upper()}', 'accounting_periods',
           period, f'Period {period} → {new_status}')
    conn.commit(); conn.close()
    return {'ok': True}


def api_auto_generate_jv(data, session):
    """Auto-generate a JV from an existing transaction (actual/receipt/payroll)."""
    if not _jv_can_create(session, 'JV'):
        return {'ok': False, 'error': 'Insufficient permissions'}
    source = data.get('source_module')
    source_id = data.get('source_id')
    conn = get_db()

    lines = []
    desc = ''
    proj_id = None

    if source == 'actuals':
        # Build double-entry for a payment
        txn = conn.execute("""SELECT a.*, p.project_code, b.budget_code,
            c.code as coa_code, c.account_name, c.id as coa_db_id
            FROM actuals a JOIN projects p ON a.project_id=p.id
            LEFT JOIN budgets b ON a.budget_id=b.id
            LEFT JOIN chart_of_accounts c ON b.coa_id=c.id
            WHERE a.id=?""", (source_id,)).fetchone()
        if not txn:
            conn.close(); return {'ok': False, 'error': 'Transaction not found'}
        txn = dict(txn)
        desc = f"Payment: {txn['payee']} — {txn['description']}"
        proj_id = txn['project_id']
        gross = txn['amount_ghs']
        ex_vat = gross / 1.2 if txn.get('has_whvat') else gross
        wht = txn.get('wht_amount', 0)
        whvat = txn.get('whvat_amount', 0)
        ucf = txn.get('ucf_amount', 0)
        net_pay = gross - wht - whvat - ucf
        coa_db_id = txn.get('coa_db_id')

        if coa_db_id:
            lines.append({'coa_id': coa_db_id, 'debit_amount': gross,
                          'credit_amount': 0, 'description': f'Expense: {txn["description"]}'})
        # WHT payable
        if wht > 0:
            wht_coa = conn.execute(
                "SELECT id FROM chart_of_accounts WHERE code='2030'").fetchone()
            if wht_coa:
                lines.append({'coa_id': wht_coa['id'], 'debit_amount': 0,
                              'credit_amount': wht, 'description': f'WHT Payable ({txn["wht_type"]})'})
        # WHVAT payable
        if whvat > 0:
            whvat_coa = conn.execute(
                "SELECT id FROM chart_of_accounts WHERE code='2034'").fetchone()
            if whvat_coa:
                lines.append({'coa_id': whvat_coa['id'], 'debit_amount': 0,
                              'credit_amount': whvat, 'description': 'WHVAT Payable'})
        # UCF payable
        if ucf > 0:
            ucf_coa = conn.execute(
                "SELECT id FROM chart_of_accounts WHERE code='2035'").fetchone()
            if ucf_coa:
                lines.append({'coa_id': ucf_coa['id'], 'debit_amount': 0,
                              'credit_amount': ucf, 'description': 'UCC Common Fund Payable'})
        # Bank/Cash credit (net payment)
        bank_coa = conn.execute(
            "SELECT id FROM chart_of_accounts WHERE code='1020'").fetchone()
        if bank_coa:
            lines.append({'coa_id': bank_coa['id'], 'debit_amount': 0,
                          'credit_amount': net_pay, 'description': f'Bank payment to {txn["payee"]}'})

    elif source == 'receipts':
        rcpt = conn.execute("""SELECT fr.*, p.project_code
            FROM fund_receipts fr JOIN projects p ON fr.project_id=p.id
            WHERE fr.id=?""", (source_id,)).fetchone()
        if not rcpt:
            conn.close(); return {'ok': False, 'error': 'Receipt not found'}
        rcpt = dict(rcpt)
        desc = f"Fund Receipt: {rcpt['donor']} — {rcpt['description']}"
        proj_id = rcpt['project_id']
        amount = rcpt['amount_ghs']
        # Dr Bank, Cr Grant Income
        bank_coa = conn.execute("SELECT id FROM chart_of_accounts WHERE code='1020'").fetchone()
        income_coa = conn.execute("SELECT id FROM chart_of_accounts WHERE code='4006'").fetchone()
        if bank_coa:
            lines.append({'coa_id': bank_coa['id'], 'debit_amount': amount,
                          'credit_amount': 0, 'description': f'Bank receipt from {rcpt["donor"]}'})
        if income_coa:
            lines.append({'coa_id': income_coa['id'], 'debit_amount': 0,
                          'credit_amount': amount, 'description': f'Grant income: {rcpt["description"]}'})

    conn.close()
    if not lines:
        return {'ok': False, 'error': 'Could not generate lines for this transaction'}

    jv_data = {
        'jv_type': 'PV' if source == 'actuals' else 'RV',
        'jv_date': data.get('jv_date', datetime.now().strftime('%Y-%m-%d')),
        'description': desc,
        'project_id': proj_id,
        'source_module': source,
        'source_id': source_id,
        'lines': lines,
        'narration': f'Auto-generated from {source} record {source_id[:8]}',
        'notes': 'System-generated JV — verify before posting'
    }
    result = api_save_jv(jv_data, session)
    result['auto_generated'] = True
    return result


def _jv_audit(conn, session, jv_id, jv_number, action, old_status, new_status, details=''):
    conn.execute("""INSERT INTO jv_audit(id,jv_id,jv_number,username,user_role,action,old_status,new_status,details)
        VALUES(?,?,?,?,?,?,?,?,?)""",
        (str(uuid.uuid4()), jv_id, jv_number, session.get('username','system'),
         session.get('role',''), action, old_status, new_status, details))


