# FUEL COUPON MANAGEMENT  (matches UCC FMS implementation exactly)
# All data stored locally — no external network calls
# ══════════════════════════════════════════════════════════════════════════════

def _nxt_fc(conn):
    """Generate sequential batch number: FC-2026-0001"""
    from datetime import datetime as _dt
    yr = _dt.now().year
    n = conn.execute(
        f"SELECT COUNT(*) FROM fuel_coupon_batches WHERE procurement_date LIKE '{yr}%'"
    ).fetchone()[0] + 1
    return f"FC-{yr}-{n:04d}"

def api_fuel(session):
    """GET /api/fuel-coupons — return all batches, movements, and summary"""
    conn = get_db()
    batches = [dict(r) for r in conn.execute("""
        SELECT * FROM fuel_coupon_batches ORDER BY procurement_date DESC
    """)]
    movements = [dict(r) for r in conn.execute("""
        SELECT fm.*, fb.batch_number
        FROM fuel_coupon_movements fm
        LEFT JOIN fuel_coupon_batches fb ON fm.batch_id = fb.id
        ORDER BY fm.movement_date DESC, fm.created_at DESC LIMIT 300
    """)]

    # Summary totals
    fc_in    = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_batches").fetchone()[0]
    borrow_in= conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Borrow'").fetchone()[0]
    issued   = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Issue'").fetchone()[0]
    lent     = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Lend'").fetchone()[0]
    returned = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type IN ('Return','Return-Issued','Return-Lent','Return-Borrowed')").fetchone()[0]
    out_lent = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Lend' AND returned_date IS NULL").fetchone()[0]
    balance  = fc_in + borrow_in - issued - lent + returned

    # Per-project balances for SBS research grants and school activities
    proj_bal = [dict(r) for r in conn.execute("""
        SELECT p.id, p.title as name, p.project_code,
               COALESCE(SUM(CASE WHEN fm.movement_type='Issue' THEN fm.face_value ELSE 0 END),0) as issued,
               COALESCE(SUM(CASE WHEN fm.movement_type IN ('Return','Return-Issued') THEN fm.face_value ELSE 0 END),0) as returned
        FROM projects p
        LEFT JOIN fuel_coupon_movements fm ON p.id = fm.project_id
        GROUP BY p.id
        HAVING issued > 0
        ORDER BY p.title
    """)]

    conn.close()
    return {
        'batches':  batches,
        'movements': movements,
        'project_balances': proj_bal,
        'summary': {
            'procured':        fc_in,
            'borrowed_in':     borrow_in,
            'issued':          issued,
            'lent':            lent,
            'returned':        returned,
            'balance':         balance,
            'outstanding_lent': out_lent,
        }
    }

def api_save_fc_batch(data, session):
    """POST /api/fuel-coupons/batch — record new procurement"""
    if not session: return {'ok': False, 'error': 'Not logged in'}
    if not data.get('supplier') or not data.get('denomination') or not data.get('quantity'):
        return {'ok': False, 'error': 'supplier, denomination and quantity are required'}
    conn = get_db()
    bid   = str(uuid.uuid4())
    bno   = _nxt_fc(conn)
    qty   = int(data['quantity'])
    denom = float(data['denomination'])
    face  = round(qty * denom, 2)
    cost  = float(data['cost_value']) if data.get('cost_value') else face
    conn.execute("""INSERT INTO fuel_coupon_batches
        (id,batch_number,procurement_date,supplier,invoice_number,denomination,
         quantity,face_value,cost_value,received_by,project_id,notes,created_by)
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (bid, bno, data['procurement_date'], data['supplier'],
         data.get('invoice_number',''), denom, qty, face, cost,
         data.get('received_by',''), data.get('project_id'),
         data.get('notes',''), session['username']))
    _audit(conn, session, 'FC_PROCURE', 'fuel_coupon_batches', bid, f'{qty}x GHS{denom} = GHS{face:.2f}')
    conn.commit(); conn.close()
    return {'ok': True, 'id': bid, 'batch_number': bno, 'face_value': face}

def api_save_fc_movement(data, session):
    """POST /api/fuel-coupons/movement — record Issue/Lend/Return/Borrow"""
    if not session: return {'ok': False, 'error': 'Not logged in'}
    if not data.get('denomination') or not data.get('quantity'):
        return {'ok': False, 'error': 'denomination and quantity are required'}
    mv_type = data.get('movement_type','Issue')
    qty   = int(data['quantity'])
    denom = float(data['denomination'])
    face  = round(qty * denom, 2)
    conn  = get_db()

    # Normalise sub-type returns — they all add to central balance (same as 'Return')
    is_return_variant = mv_type in ('Return-Issued', 'Return-Lent', 'Return-Borrowed')

    # Balance check for outgoing movements
    if mv_type in ('Issue', 'Lend') or (mv_type == 'Return-Borrowed'):
        # Return-Borrowed reduces central balance (we're giving coupons back to external)
        if mv_type == 'Return-Borrowed':
            pass  # no balance check needed — it reduces what we borrowed (treated same as outgoing)
    if mv_type in ('Issue', 'Lend'):
        fc_in    = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_batches").fetchone()[0]
        borrow_in= conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Borrow'").fetchone()[0]
        issued   = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type IN ('Issue')").fetchone()[0]
        lent     = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Lend'").fetchone()[0]
        returned = conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type IN ('Return','Return-Issued','Return-Lent','Return-Borrowed')").fetchone()[0]
        balance  = fc_in + borrow_in - issued - lent + returned
        if face > balance + 0.01:
            conn.close()
            return {'ok': False, 'error': f'INSUFFICIENT STOCK: Requested GHS {face:,.2f} but only GHS {balance:,.2f} available. Central balance cannot go negative.'}

    mid = str(uuid.uuid4())
    conn.execute("""INSERT INTO fuel_coupon_movements
        (id,movement_date,movement_type,batch_id,project_id,from_entity,to_entity,
         denomination,quantity,face_value,officer,purpose,reference,
         return_due_date,receipt_submitted,receipt_date,notes,created_by)
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (mid, data['movement_date'], mv_type,
         data.get('batch_id'), data.get('project_id'),
         data.get('from_entity','UCC'), data.get('to_entity',''),
         denom, qty, face, data.get('officer',''), data.get('purpose',''),
         data.get('reference',''), data.get('return_due_date'),
         int(data.get('receipt_submitted',0)), data.get('receipt_date'),
         data.get('notes',''), session['username']))
    _audit(conn, session, f'FC_{mv_type.upper()}', 'fuel_coupon_movements', mid, f'{qty}x GHS{denom} = GHS{face:.2f}')
    conn.commit(); conn.close()
    return {'ok': True, 'id': mid}

def api_update_fc_receipt(data, session):
    """POST /api/fuel-coupons/receipt — mark receipt submitted"""
    if not session: return {'ok': False, 'error': 'Not logged in'}
    conn = get_db()
    conn.execute("UPDATE fuel_coupon_movements SET receipt_submitted=?,receipt_date=? WHERE id=?",
                 (1, data.get('receipt_date'), data['id']))
    _audit(conn, session, 'FC_RECEIPT', 'fuel_coupon_movements', data['id'], f"Receipt {data.get('receipt_date','')}")
    conn.commit(); conn.close()
    return {'ok': True}

def api_update_fc_movement(data, session):
    """POST /api/fuel-coupons/movement/update — edit an existing movement (all users); admin can also change type"""
    if not session: return {'ok': False, 'error': 'Not logged in'}
    mid = data.get('id')
    if not mid: return {'ok': False, 'error': 'Movement ID required'}
    conn = get_db()
    row = conn.execute("SELECT * FROM fuel_coupon_movements WHERE id=?", (mid,)).fetchone()
    if not row:
        conn.close(); return {'ok': False, 'error': 'Movement not found'}
    # All users may update officer, purpose, reference, notes, receipt fields
    # Only admin may change date, type, qty, denom, entities
    is_admin = session.get('role') == 'Admin'
    if is_admin:
        qty   = int(data.get('quantity', row['quantity']))
        denom = float(data.get('denomination', row['denomination']))
        face  = round(qty * denom, 2)
        conn.execute("""UPDATE fuel_coupon_movements
            SET movement_date=?, movement_type=?, batch_id=?, project_id=?,
                from_entity=?, to_entity=?, denomination=?, quantity=?,
                face_value=?, officer=?, purpose=?, reference=?,
                return_due_date=?, notes=?, serial_from=?, serial_to=?
            WHERE id=?""",
            (data.get('movement_date', row['movement_date']),
             data.get('movement_type', row['movement_type']),
             data.get('batch_id', row['batch_id']),
             data.get('project_id', row['project_id']),
             data.get('from_entity', row['from_entity']),
             data.get('to_entity', row['to_entity']),
             denom, qty, face,
             data.get('officer', row['officer']),
             data.get('purpose', row['purpose']),
             data.get('reference', row['reference']),
             data.get('return_due_date', row['return_due_date']),
             data.get('notes', row['notes']),
             data.get('serial_from', row['serial_from'] if 'serial_from' in row.keys() else ''),
             data.get('serial_to', row['serial_to'] if 'serial_to' in row.keys() else ''), mid))
    else:
        conn.execute("""UPDATE fuel_coupon_movements
            SET officer=?, purpose=?, reference=?, notes=?, serial_from=?, serial_to=?
            WHERE id=?""",
            (data.get('officer', row['officer']),
             data.get('purpose', row['purpose']),
             data.get('reference', row['reference']),
             data.get('notes', row['notes']),
             data.get('serial_from', row['serial_from'] if 'serial_from' in row.keys() else ''),
             data.get('serial_to', row['serial_to'] if 'serial_to' in row.keys() else ''), mid))
    _audit(conn, session, 'FC_EDIT', 'fuel_coupon_movements', mid,
           f"Edited by {session['username']} ({'Admin full-edit' if is_admin else 'user fields'})")
    conn.commit(); conn.close()
    return {'ok': True}

def api_delete_fc_movement(mov_id, session):
    """DELETE /api/fuel-coupons/movement/<id> — admin only"""
    if session.get('role') != 'Admin':
        return {'ok': False, 'error': 'Admin access required to delete fuel coupon movements'}
    if not mov_id: return {'ok': False, 'error': 'No movement ID provided'}
    conn = get_db()
    row = conn.execute("SELECT movement_type, face_value, movement_date FROM fuel_coupon_movements WHERE id=?", (mov_id,)).fetchone()
    if not row:
        conn.close(); return {'ok': False, 'error': 'Movement not found'}
    desc = f"{row['movement_type']} GHS {row['face_value']:.2f} on {row['movement_date']}"
    conn.execute("DELETE FROM fuel_coupon_movements WHERE id=?", (mov_id,))
    _audit(conn, session, 'FC_DELETE', 'fuel_coupon_movements', mov_id, desc)
    conn.commit(); conn.close()
    return {'ok': True}

def api_fuel_report(session, date_from=None, date_to=None, project_id=None):
    """GET /api/report/fuel-coupons — fuel consumption report with date range & optional project filter"""
    if not session: return {'ok': False, 'error': 'Not logged in'}
    conn = get_db()

    # Build date filter clause
    filters, args = [], []
    if date_from:
        filters.append("fm.movement_date >= ?"); args.append(date_from)
    if date_to:
        filters.append("fm.movement_date <= ?"); args.append(date_to)
    if project_id:
        filters.append("fm.project_id = ?"); args.append(project_id)
    where = ("WHERE " + " AND ".join(filters)) if filters else ""

    # All movements in range
    movements = [dict(r) for r in conn.execute(f"""
        SELECT fm.*, fb.batch_number, p.project_code, p.title as project_title
        FROM fuel_coupon_movements fm
        LEFT JOIN fuel_coupon_batches fb ON fm.batch_id = fb.id
        LEFT JOIN projects p ON fm.project_id = p.id
        {where}
        ORDER BY fm.movement_date ASC, fm.created_at ASC
    """, args)]

    # Opening balance = all stock movements BEFORE the period start
    # Formula: all procured + all borrowed - all issued - all lent + all returns (before period)
    ob_filters, ob_args = [], []
    if date_from:
        ob_filters.append("movement_date < ?"); ob_args.append(date_from)
    ob_where = ("WHERE " + " AND ".join(ob_filters)) if ob_filters else ""

    if date_from:
        ob_proc = conn.execute(
            "SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_batches WHERE procurement_date < ?",
            (date_from,)).fetchone()[0]
    else:
        ob_proc = 0  # All-time report: opening balance is 0 (start from scratch)

    ob_rows = conn.execute(
        f"SELECT movement_type, COALESCE(SUM(face_value),0) as tot FROM fuel_coupon_movements {ob_where} GROUP BY movement_type",
        ob_args).fetchall()
    ob_map = {r['movement_type']: r['tot'] for r in ob_rows}
    # Opening = procured before + borrowed before - issued before - lent before + returns before
    ob_returns_before = (ob_map.get('Return',0) + ob_map.get('Return-Issued',0) +
                         ob_map.get('Return-Lent',0) + ob_map.get('Return-Borrowed',0))
    ob_bal = ob_proc + ob_map.get('Borrow',0) - ob_map.get('Issue',0) - ob_map.get('Lend',0) + ob_returns_before

    # Period totals (filtered)
    p_args_base = args[:] if not project_id else args[:-1]  # exclude project filter for institute totals
    p_where_inst = ("WHERE " + " AND ".join(filters[:-1])) if (filters and project_id) else where

    def period_sum(mv_type, w, a):
        return conn.execute(f"SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements fm {w} {'AND' if w else 'WHERE'} movement_type=?",
                            a + [mv_type]).fetchone()[0]

    period_procured = conn.execute(
        "SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_batches" +
        (f" WHERE procurement_date BETWEEN ? AND ?" if (date_from and date_to) else
         f" WHERE procurement_date >= ?" if date_from else
         f" WHERE procurement_date <= ?" if date_to else ""),
        ([date_from, date_to] if (date_from and date_to) else
         [date_from] if date_from else [date_to] if date_to else [])
    ).fetchone()[0]

    p_issued   = period_sum('Issue',   where, args)
    p_returned = period_sum('Return',  where, args)
    p_lent     = period_sum('Lend',    where, args)
    p_borrowed = period_sum('Borrow',  where, args)
    # closing_bal computed properly below after all return subtypes are known

    # Per-project breakdown
    proj_args = []
    proj_filters = []
    if date_from: proj_filters.append("fm.movement_date >= ?"); proj_args.append(date_from)
    if date_to:   proj_filters.append("fm.movement_date <= ?"); proj_args.append(date_to)
    proj_where = ("WHERE " + " AND ".join(proj_filters)) if proj_filters else ""

    proj_breakdown = [dict(r) for r in conn.execute(f"""
        SELECT p.project_code, p.title,
            COALESCE(SUM(CASE WHEN fm.movement_type='Issue'  THEN fm.face_value ELSE 0 END),0) as issued,
            COALESCE(SUM(CASE WHEN fm.movement_type='Return' THEN fm.face_value ELSE 0 END),0) as returned,
            COALESCE(SUM(CASE WHEN fm.movement_type='Lend'   THEN fm.face_value ELSE 0 END),0) as lent_out,
            COUNT(CASE WHEN fm.movement_type='Issue' THEN 1 END) as issue_count
        FROM projects p
        JOIN fuel_coupon_movements fm ON fm.project_id = p.id
        {proj_where}
        GROUP BY p.id
        ORDER BY issued DESC
    """, proj_args)]

    # Split Returns by movement_type sub-type stored in DB
    def period_sum_type(mv_type, w, a):
        return conn.execute(
            f"SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements fm {w} "
            f"{'AND' if w else 'WHERE'} movement_type=?",
            a + [mv_type]).fetchone()[0]

    # Return sub-types are stored as 'Return', 'Return-Issued', 'Return-Lent', 'Return-Borrowed'
    p_returned_issued   = period_sum_type('Return-Issued',   where, args) + period_sum_type('Return', where, args)
    p_returned_lent     = period_sum_type('Return-Lent',     where, args)
    p_returned_borrowed = period_sum_type('Return-Borrowed', where, args)
    # Legacy: 'Return' type counts as Return-Issued; total_returned includes all types
    p_all_returned = p_returned_issued + p_returned_lent + p_returned_borrowed

    # Closing balance: procured + borrowed_in - issued - lent + all_returns
    closing_bal = ob_bal + period_procured + p_borrowed - p_issued - p_lent + p_all_returned  # correct formula

    conn.close()
    return {
        'movements': movements,
        'opening_balance': ob_bal,
        'closing_balance': closing_bal,
        'period': {
            'procured':         period_procured,
            'issued':           p_issued,
            'returned':         p_returned_issued,
            'returned_lent':    p_returned_lent,
            'returned_borrowed':p_returned_borrowed,
            'all_returned':     p_all_returned,
            'lent':             p_lent,
            'borrowed':         p_borrowed,
            'lent_returned':    p_returned_lent,
            'borrow_returned':  p_returned_borrowed,
            'net_consumption':  p_issued - p_returned_issued,
        },
        'project_breakdown': proj_breakdown,
        'date_from': date_from,
        'date_to':   date_to,
    }


