# BANK OF GHANA INTERBANK FX RATES INTEGRATION
# Fetches daily mid rates from bog.gov.gh and caches in local DB
# ══════════════════════════════════════════════════════════════════════════════
import urllib.request, urllib.error
from html.parser import HTMLParser

BOG_FX_URL = "https://www.bog.gov.gh/treasury-and-the-markets/interbank-forex/"

class _BOGParser(HTMLParser):
    """Extract data rows from the first table on the BOG interbank forex page."""
    def __init__(self):
        super().__init__()
        self.rows = []
        self._cur_row = []
        self._cur_cell = ""
        self._in_table = False
        self._in_cell  = False
        self._table_done = False

    def handle_starttag(self, tag, attrs):
        if self._table_done: return
        if tag == "table" and not self._in_table:
            self._in_table = True
        if self._in_table:
            if tag == "tr":
                self._cur_row = []
            if tag in ("td", "th"):
                self._in_cell = True
                self._cur_cell = ""

    def handle_endtag(self, tag):
        if self._table_done: return
        if tag == "table" and self._in_table:
            self._in_table = False
            self._table_done = True
        if self._in_table:
            if tag in ("td", "th"):
                self._in_cell = False
                self._cur_row.append(self._cur_cell.strip())
            if tag == "tr" and self._cur_row:
                self.rows.append(self._cur_row[:])
                self._cur_row = []

    def handle_data(self, data):
        if self._in_cell:
            self._cur_cell += data

def _parse_bog_date(s):
    """Parse BOG date string -> YYYY-MM-DD or None."""
    import re as _re
    s = s.strip().replace('\xa0', ' ')
    # DD/MM/YYYY
    m = _re.match(r'(\d{1,2})/(\d{1,2})/(\d{4})', s)
    if m:
        d, mo, y = m.groups()
        return f'{y}-{int(mo):02d}-{int(d):02d}'
    # YYYY-MM-DD
    m = _re.match(r'(\d{4})-(\d{2})-(\d{2})', s)
    if m:
        return s[:10]
    # DD Mon YYYY  or  Mon DD, YYYY
    months = {'jan':1,'feb':2,'mar':3,'apr':4,'may':5,'jun':6,
              'jul':7,'aug':8,'sep':9,'oct':10,'nov':11,'dec':12}
    m = _re.match(r'(\d{1,2})\s+([A-Za-z]{3})[A-Za-z]*[,\s]+(\d{4})', s)
    if m:
        d, mon, y = m.groups()
        mo = months.get(mon.lower()[:3])
        if mo:
            return f'{y}-{mo:02d}-{int(d):02d}'
    m = _re.match(r'([A-Za-z]{3})[A-Za-z]*\.?\s+(\d{1,2}),?\s+(\d{4})', s)
    if m:
        mon, d, y = m.groups()
        mo = months.get(mon.lower()[:3])
        if mo:
            return f'{y}-{mo:02d}-{int(d):02d}'
    return None

# Alternative BOG data sources (tried in order)
BOG_FX_URLS = [
    "https://www.bog.gov.gh/treasury-and-the-markets/interbank-forex/",
    "https://bog.gov.gh/treasury-and-the-markets/interbank-forex/",
    "https://www.bog.gov.gh/monetary-policy/interbank-forex/",
]

def _fetch_url(url, timeout=15):
    """Fetch a URL with browser-like headers. Returns HTML string or raises."""
    import gzip as _gzip
    hdrs = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0 Safari/537.36',
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
        'Accept-Language': 'en-US,en;q=0.9',
        'Accept-Encoding': 'gzip, deflate',
        'Connection': 'keep-alive',
        'Cache-Control': 'no-cache',
    }
    req = urllib.request.Request(url, headers=hdrs)
    _ctx = None
    try:
        import certifi as _cf, ssl as _ssl
        _ctx = _ssl.create_default_context(cafile=_cf.where())
    except Exception:
        _ctx = None
    with urllib.request.urlopen(req, timeout=timeout, context=_ctx) as resp:
        raw = resp.read()
        enc = resp.info().get('Content-Encoding', '')
        if enc == 'gzip':
            raw = _gzip.decompress(raw)
        return raw.decode('utf-8', errors='replace')


def _scrape_bog_page():
    """Download and parse the BOG interbank FX page.
    Returns list of dicts: {date, USD, EUR, GBP, ...} mid rates.
    Raises RuntimeError on fetch/parse failure."""
    last_err = None
    html = None
    for url in BOG_FX_URLS:
        try:
            html = _fetch_url(url, timeout=20)
            if html and len(html) > 500:
                break
        except Exception as e:
            last_err = e
            continue
    if not html:
        raise RuntimeError(f'Cannot reach BOG website: {last_err}')

    parser = _BOGParser()
    parser.feed(html)

    if len(parser.rows) < 2:
        raise RuntimeError('BOG table not found or structure has changed')

    # Detect column layout from header row
    header = [h.strip().upper().replace('\xa0', ' ') for h in parser.rows[0]]
    # Identify mid-rate columns for each currency
    # Typical BOG layout: Date | USD Buy | USD Mid | USD Sell | EUR Buy | EUR Mid | EUR Sell | GBP Buy | GBP Mid | GBP Sell | ...
    currencies = ['USD', 'EUR', 'GBP', 'JPY', 'CHF', 'NOK', 'SEK', 'DKK', 'CAD', 'AUD',
                  'ZAR', 'CNY', 'INR', 'AED', 'NGN']
    mid_cols = {}
    for i, h in enumerate(header):
        for curr in currencies:
            if curr in h and 'MID' in h:
                mid_cols[curr] = i
    # Fallback: standard BOG layout (0-indexed)
    if not mid_cols:
        mid_cols = {'USD': 2, 'EUR': 5, 'GBP': 8}

    results = []
    for row in parser.rows[1:]:
        if not row or not row[0] or not row[0].strip():
            continue
        parsed_date = _parse_bog_date(row[0])
        if not parsed_date:
            continue
        entry = {'date': parsed_date}
        for curr, col in mid_cols.items():
            if col < len(row):
                try:
                    val = row[col].replace(',', '').strip()
                    if val:
                        entry[curr] = float(val)
                except (ValueError, TypeError):
                    pass
        if len(entry) > 1:  # has at least one rate
            results.append(entry)
    if not results:
        raise RuntimeError('No valid rate rows found in BOG table')
    return results

def api_fuel_tracker(session):
    """GET /api/fuel-coupons/tracker — outstanding lent and borrowed coupons"""
    if not session: return {'ok': False, 'error': 'Not logged in'}
    conn = get_db()

    # All Lend movements with their returns
    lent = [dict(r) for r in conn.execute("""
        SELECT fm.id, fm.movement_date, fm.to_entity, fm.face_value, fm.quantity,
               fm.denomination, fm.officer, fm.return_due_date, fm.notes, fm.purpose,
               fb.batch_number, p.project_code,
               COALESCE((SELECT SUM(face_value) FROM fuel_coupon_movements
                WHERE movement_type IN ('Return-Lent','Return')
                AND from_entity=fm.to_entity AND face_value<=fm.face_value),0) as returned_amount
        FROM fuel_coupon_movements fm
        LEFT JOIN fuel_coupon_batches fb ON fm.batch_id=fb.id
        LEFT JOIN projects p ON fm.project_id=p.id
        WHERE fm.movement_type='Lend'
        ORDER BY fm.movement_date DESC
    """)]

    # All Borrow movements with their returns
    borrowed = [dict(r) for r in conn.execute("""
        SELECT fm.id, fm.movement_date, fm.from_entity, fm.face_value, fm.quantity,
               fm.denomination, fm.officer, fm.return_due_date, fm.notes, fm.purpose,
               fb.batch_number,
               COALESCE((SELECT SUM(face_value) FROM fuel_coupon_movements
                WHERE movement_type='Return-Borrowed'
                AND to_entity=fm.from_entity AND face_value<=fm.face_value),0) as returned_amount
        FROM fuel_coupon_movements fm
        LEFT JOIN fuel_coupon_batches fb ON fm.batch_id=fb.id
        WHERE fm.movement_type='Borrow'
        ORDER BY fm.movement_date DESC
    """)]

    today = str(__import__('datetime').date.today())
    for m in lent:
        m['outstanding'] = max(0, m['face_value'] - m['returned_amount'])
        m['is_overdue'] = bool(m['return_due_date'] and m['return_due_date'] < today and m['outstanding'] > 0)
    for m in borrowed:
        m['outstanding'] = max(0, m['face_value'] - m['returned_amount'])
        m['is_overdue'] = bool(m['return_due_date'] and m['return_due_date'] < today and m['outstanding'] > 0)

    conn.close()
    return {
        'lent': lent,
        'borrowed': borrowed,
        'total_lent_outstanding': sum(m['outstanding'] for m in lent),
        'total_borrowed_outstanding': sum(m['outstanding'] for m in borrowed),
        'overdue_lent': sum(1 for m in lent if m['is_overdue']),
        'overdue_borrowed': sum(1 for m in borrowed if m['is_overdue']),
    }

def api_bog_fetch_rates(session, date_from=None, date_to=None):
    """Fetch BOG rates for a date range, store in DB, return result."""
    if not session:
        return err('Not logged in', 401)
    from datetime import date as _date, timedelta as _td
    today_str = str(_date.today())
    if not date_from:
        date_from = today_str
    if not date_to:
        date_to = date_from
    try:
        rows = _scrape_bog_page()
    except RuntimeError as e:
        return err(f'BOG fetch failed: {e}. The BOG website may be temporarily unavailable or the page structure may have changed. Try again later or add rates manually.')

    conn = get_db()
    stored = []
    # Store all rows returned by BOG page (it usually returns recent history)
    for entry in rows:
        d = entry['date']
        # Only store rows within the requested date range
        if d < date_from or d > date_to:
            continue
        for curr, rate in entry.items():
            if curr == 'date': continue
            rid = str(uuid.uuid4())
            try:
                conn.execute("""INSERT OR REPLACE INTO exchange_rates
                    (id, rate_date, currency, rate_to_ghs, source, entered_by)
                    VALUES (?,?,?,?,'Bank of Ghana (Interbank Mid Rate)',?)""",
                    (rid, d, curr, rate, session['username']))
                stored.append({'date': d, 'currency': curr, 'rate': rate})
            except Exception:
                pass
    # If nothing matched the filter, store all rows (BOG page may only show a few days)
    if not stored:
        for entry in rows:
            d = entry['date']
            for curr, rate in entry.items():
                if curr == 'date': continue
                rid = str(uuid.uuid4())
                try:
                    conn.execute("""INSERT OR REPLACE INTO exchange_rates
                        (id, rate_date, currency, rate_to_ghs, source, entered_by)
                        VALUES (?,?,?,?,'Bank of Ghana (Interbank Mid Rate)',?)""",
                        (rid, d, curr, rate, session['username']))
                    stored.append({'date': d, 'currency': curr, 'rate': rate})
                except Exception:
                    pass
    conn.commit()
    # Find best rate for the requested end date (nearest previous)
    best = {}
    for curr in ['USD', 'EUR', 'GBP']:
        row = conn.execute("""SELECT rate_to_ghs, rate_date FROM exchange_rates
            WHERE currency=? AND rate_date<=? ORDER BY rate_date DESC LIMIT 1""",
            (curr, date_to)).fetchone()
        if row:
            best[curr] = {'rate': row[0], 'date': row[1]}
    conn.close()
    db2 = get_db()
    _audit(db2, session, 'BOG_FX_FETCH', 'exchange_rates',
           date_to, f'{len(stored)} rates stored ({date_from} to {date_to})')
    db2.close()
    return ok({
        'stored': len(stored),
        'rows_fetched': len(rows),
        'best_for_date': best,
        'date_from': date_from,
        'date_to': date_to,
        'source': 'Bank of Ghana Interbank (Mid Rate)',
    })

def api_bog_rate_for_date(currency, target_date, session):
    """Return the best available BOG mid rate for a currency on/before a date.
    First tries the DB cache; if not found fetches live from BOG."""
    if currency == 'GHS':
        return ok({'rate': 1.0, 'date': target_date, 'source': 'GHS base currency'})
    conn = get_db()
    row = conn.execute("""SELECT rate_to_ghs, rate_date, source FROM exchange_rates
        WHERE currency=? AND rate_date<=? ORDER BY rate_date DESC LIMIT 1""",
        (currency, target_date)).fetchone()
    conn.close()
    if row:
        return ok({'rate': row[0], 'date': row[1], 'source': row[2] or 'cached',
                   'from_cache': True})
    # Not in DB — try live fetch
    try:
        rows = _scrape_bog_page()
    except RuntimeError as e:
        return ok({'rate': 1.0, 'date': target_date,
                   'source': f'Unavailable ({e})', 'error': str(e)})
    conn = get_db()
    for entry in rows:
        for curr, rate in entry.items():
            if curr == 'date': continue
            rid = str(uuid.uuid4())
            try:
                conn.execute("""INSERT OR IGNORE INTO exchange_rates
                    (id,rate_date,currency,rate_to_ghs,source,entered_by)
                    VALUES(?,?,?,?,'Bank of Ghana (Interbank Mid Rate)','auto')""",
                    (rid, entry['date'], curr, rate))
            except Exception:
                pass
    conn.commit()
    row = conn.execute("""SELECT rate_to_ghs, rate_date, source FROM exchange_rates
        WHERE currency=? AND rate_date<=? ORDER BY rate_date DESC LIMIT 1""",
        (currency, target_date)).fetchone()
    conn.close()
    if row:
        return ok({'rate': row[0], 'date': row[1], 'source': row[2] or 'BOG',
                   'from_cache': False})
    return ok({'rate': 1.0, 'date': target_date, 'source': 'Not available', 'error': 'No rate found'})

# ── PAYROLL CALCULATION ENGINE ────────────────────────────────────────────

def _get_paye_bands_for_year(year=None):
    """Return the PAYE bands effective for the given year (defaults to current year)."""
    import datetime as _dt
    if year is None:
        year = _dt.date.today().year
    year_start = f"{year}-01-01"
    conn = get_db()
    # Get bands whose effective_date <= year-01-01, picking the latest available year
    bands = [dict(r) for r in conn.execute(
        """SELECT * FROM paye_bands
        WHERE active=1 AND effective_date <= ?
        ORDER BY effective_date DESC, band_order ASC""", (year_start,))]
    conn.close()
    # Deduplicate: keep only the most-recent effective_date set
    if bands:
        latest_date = bands[0]['effective_date']
        bands = [b for b in bands if b['effective_date'] == latest_date]
    return bands

def calc_ghana_paye(annual_taxable_income, is_resident=True, settings=None, bands=None, year=None):
    """Calculate Ghana PAYE for given annual taxable income using current-year bands."""
    if not is_resident:
        rate = float((settings or {}).get('nonresident_tax_rate', 0.20))
        return annual_taxable_income * rate

    if not bands:
        bands = _get_paye_bands_for_year(year)

    tax = 0.0
    remaining = annual_taxable_income
    prev_min = 0
    for band in bands:
        band_width = (band['annual_max'] if band['annual_max'] else float('inf'))
        if remaining <= 0:
            break
        taxable_in_band = min(remaining, band_width)
        tax += taxable_in_band * band['rate']
        remaining -= taxable_in_band
    return tax

def calc_employee_payroll(emp, month_str, overrides=None, settings_dict=None):
    """
    Calculate full payroll for one employee for one month.
    Returns a dict with all computed fields.
    """
    import datetime as _dt
    current_year = _dt.date.today().year
    if not settings_dict:
        conn = get_db()
        settings_dict = {r['key']: r['value'] for r in conn.execute("SELECT key,value FROM payroll_settings")}
        conn.close()
    bands = _get_paye_bands_for_year(current_year)

    ov = overrides or {}
    is_resident = emp['tax_residency'] == 'Resident'

    # ── Gross components ──
    basic          = float(ov.get('basic_salary',       emp['basic_salary'] or 0))
    market_prem    = float(ov.get('market_premium',     emp['market_premium'] or 0))
    housing        = float(ov.get('housing_allowance',  emp['housing_allowance'] or 0))
    transport      = float(ov.get('transport_allowance',emp['transport_allowance'] or 0))
    utility        = float(ov.get('utility_allowance',  emp['utility_allowance'] or 0))
    research       = float(ov.get('research_allowance', emp['research_allowance'] or 0))
    other_allow    = float(ov.get('other_allowance',    emp['other_allowance'] or 0))
    overtime       = float(ov.get('overtime_amount',    0))
    bonus          = float(ov.get('bonus',              0))
    arrears        = float(ov.get('arrears',            0))
    arrears_desc   = str(ov.get('arrears_description', ''))
    arrears_period = str(ov.get('arrears_period', ''))

    gross = basic + market_prem + housing + transport + utility + research + other_allow + overtime + bonus + arrears

    # ── Pensionable emoluments (basic + market premium only per Ghana practice) ──
    pensionable = basic + market_prem

    # ── Pension contributions ──
    # Ghana 3-Tier Pension (Act 766 as amended) - 18.5% total of pensionable emoluments
    # Employee: 5.5% -> SSNIT Tier 1 only
    # Employer: 13% split as 8% -> SSNIT Tier 1 + 5% -> Tier 2 trustee
    # Total Tier 1 remittance to SSNIT = 5.5% + 8% = 13.5%
    # Total Tier 2 to trustee = 5% (employer only)
    emp_tier1_rate  = float(settings_dict.get('ssnit_employee_rate',  0.055))  # 5.5% employee -> Tier1
    empr_tier1_rate = float(settings_dict.get('tier1_employer_rate',  0.08))   # 8% employer -> Tier1
    empr_tier2_rate = float(settings_dict.get('tier2_employer_rate',  0.05))   # 5% employer -> Tier2
    tier3_rate      = float(settings_dict.get('tier3_employee_rate',  0.00))   # voluntary Tier3

    # tier1_member=1 means enrolled in SSNIT Tier 1 (default true; can be unchecked for exemptions)
    has_tier1 = bool(emp.get('tier1_member', 1))
    # SSNIT (Tier 1) is mandatory for formal-sector members and is computed regardless
    # of whether the SSNIT NUMBER has been captured — the number is a remittance/
    # reporting detail (flagged MISSING on the schedule), not a precondition for the
    # contribution (this mirrors PAYE, which is computed even when the TIN is blank).
    has_ssnit = has_tier1 and emp['employment_type'] not in ('Casual','Visiting','Contract')
    has_tier2 = bool(emp.get('tier2_member')) and has_ssnit
    has_tier3 = bool(emp.get('tier3_member'))

    emp_tier1    = pensionable * emp_tier1_rate  if has_ssnit else 0  # 5.5% employee
    emp_tier2    = 0  # Employee does NOT contribute to Tier 2 separately in Ghana
    emp_tier3    = pensionable * tier3_rate       if has_tier3 else 0  # voluntary
    empr_tier1   = pensionable * empr_tier1_rate  if has_ssnit else 0  # 8% employer to SSNIT
    empr_tier2   = pensionable * empr_tier2_rate  if has_tier2 else 0  # 5% employer to trustee
    total_tier1_to_ssnit = emp_tier1 + empr_tier1   # 13.5% total to SSNIT
    total_emp_pension = emp_tier1 + emp_tier2 + emp_tier3
    total_empr_cost_pension = empr_tier1 + empr_tier2

    # ── Tax reliefs (GRA 2026 schedule) ──────────────────────────────────────
    monthly_relief = 0
    if is_resident:
        # Marriage / Responsibility Relief (GHS 1,200 / year)
        marriage_r   = float(emp.get('tax_relief_marriage', 0)) / 12
        # Child Education Relief (GHS 600 / child, max 3)
        children_n   = int(emp.get('tax_relief_children', 0))
        child_r_each = float(settings_dict.get('child_relief_per', 600))
        child_r_max  = int(settings_dict.get('child_relief_max', 3))
        child_r      = min(children_n, child_r_max) * child_r_each / 12
        # Aged Dependent Relative Relief (GHS 1,000 / relative, max 2)
        aged_dep_n   = int(emp.get('tax_relief_aged_dependent', 0))
        aged_dep_max = int(settings_dict.get('aged_dependent_max', 2))
        aged_dep_r   = min(aged_dep_n, aged_dep_max) * float(settings_dict.get('aged_dependent_relief', 1000)) / 12
        # Individual Aged Relief — employee 60+ years (GHS 1,500 / year)
        aged_self_r  = int(emp.get('tax_relief_aged_self', 0)) * float(settings_dict.get('aged_self_relief', 1500)) / 12
        # Training / Vocational Skills Development Relief (GHS 2,000 / year max)
        training_r   = min(float(emp.get('tax_relief_training', 0)), float(settings_dict.get('training_relief', 2000))) / 12
        # Life Insurance / Private Pension Relief (lower of GHS 2,000 or 16.5% of annual income)
        li_annual    = float(emp.get('tax_relief_life_insurance', 0))
        li_cap_flat  = float(settings_dict.get('life_insurance_cap', 2000))
        li_cap_pct   = gross * 12 * float(settings_dict.get('pension_relief_cap', 0.165))
        li_r         = min(li_annual, li_cap_flat, li_cap_pct) / 12
        # Disability Relief (25% of gross monthly income)
        disability_r = 0
        if emp.get('tax_relief_disabled'):
            disability_r = gross * float(settings_dict.get('disability_relief_pct', 0.25))
        monthly_relief = marriage_r + child_r + aged_dep_r + aged_self_r + training_r + li_r + disability_r

    # ── PAYE ──
    # Taxable = Gross - Employee pension - Reliefs
    taxable_monthly = max(0, gross - emp_tier1 - monthly_relief)
    annual_taxable  = taxable_monthly * 12
    annual_paye     = calc_ghana_paye(annual_taxable, is_resident, settings_dict, bands)
    monthly_paye    = annual_paye / 12

    # ── Other deductions ──
    loan_ded   = float(emp.get('monthly_loan_repayment', 0))
    union_ded  = float(emp.get('union_deduction', 0))
    other_ded  = float(emp.get('other_deduction', 0))

    total_deductions = emp_tier1 + monthly_paye + loan_ded + union_ded + other_ded
    net_pay = gross - total_deductions
    total_employer_cost = gross + total_empr_cost_pension

    return {
        'payroll_month':        month_str,
        'employee_id':          emp['id'],
        'basic_salary':         round(basic, 2),
        'market_premium':       round(market_prem, 2),
        'housing_allowance':    round(housing, 2),
        'transport_allowance':  round(transport, 2),
        'utility_allowance':    round(utility, 2),
        'research_allowance':   round(research, 2),
        'other_allowance':      round(other_allow, 2),
        'overtime_amount':      round(overtime, 2),
        'bonus':                round(bonus, 2),
        'arrears':              round(arrears, 2),
        'gross_pay':            round(gross, 2),
        'pensionable_emoluments': round(pensionable, 2),
        'employee_tier1':       round(emp_tier1, 2),
        'employee_tier2':       round(emp_tier2, 2),
        'employee_tier3':       round(emp_tier3, 2),
        'total_employee_pension': round(total_emp_pension, 2),
        'taxable_income':       round(taxable_monthly, 2),
        'total_relief':         round(monthly_relief, 2),
        'paye':                 round(monthly_paye, 2),
        'loan_deduction':       round(loan_ded, 2),
        'union_deduction':      round(union_ded, 2),
        'other_deduction':      round(other_ded, 2),
        'total_deductions':     round(total_deductions, 2),
        'net_pay':              round(net_pay, 2),
        'employer_tier1':       round(empr_tier1, 2),
        'employer_tier2':       round(empr_tier2, 2),
        'total_tier1_ssnit':    round(total_tier1_to_ssnit, 2),
        'total_employer_cost':  round(total_employer_cost, 2),
        'tax_residency':        emp['tax_residency'],
        'division':             emp.get('division',''),
        'funding_source':       emp.get('funding_source',''),
        'project_code':         emp.get('project_code',''),
        'status':               'Draft',
        'created_by':           'system',
    }

# ── PAYROLL API HANDLERS ──────────────────────────────────────────────────

def api_get_employees(session):
    conn = get_db()
    rows = [dict(r) for r in conn.execute("SELECT * FROM employees ORDER BY full_name")]
    conn.close()
    return rows

def api_save_employee(data, session):
    conn = get_db()
    eid = data.get('id') or str(uuid.uuid4())
    emp_code = data.get('employee_id') or f"EMP-{str(uuid.uuid4())[:6].upper()}"
    if data.get('id'):
        fields = ['full_name','division','employment_type','tax_residency','nationality',
                  'gra_tin','ssnit_number','tier1_member','tier2_member','tier3_member','date_of_birth',
                  'date_appointed','contract_end_date','job_title','grade',
                  'basic_salary','market_premium','housing_allowance','transport_allowance',
                  'utility_allowance','research_allowance','other_allowance',
                  'funding_source','project_code','cost_centre','bank_name','bank_branch',
                  'account_number','union_deduction','monthly_loan_repayment',
                  'tax_relief_marriage','tax_relief_children','tax_relief_disabled',
                  'tax_relief_aged_dependent','status','notes']
        sets = ', '.join(f"{f}=?" for f in fields)
        vals = [data.get(f, '') for f in fields] + [eid]
        conn.execute(f"UPDATE employees SET {sets} WHERE id=?", vals)
    else:
        conn.execute("""INSERT INTO employees(id,employee_id,staff_number,full_name,division,
            employment_type,tax_residency,nationality,gra_tin,ssnit_number,tier1_member,tier2_member,
            tier3_member,date_of_birth,date_appointed,contract_end_date,job_title,grade,
            basic_salary,market_premium,housing_allowance,transport_allowance,
            utility_allowance,research_allowance,other_allowance,funding_source,
            project_code,cost_centre,bank_name,bank_branch,account_number,
            union_deduction,monthly_loan_repayment,tax_relief_marriage,
            tax_relief_children,tax_relief_disabled,tax_relief_aged_dependent,
            status,notes,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (eid, emp_code, data.get('staff_number',''), data.get('full_name'),
             data.get('division'), data.get('employment_type'), data.get('tax_residency','Resident'),
             data.get('nationality','Ghanaian'), data.get('gra_tin',''), data.get('ssnit_number',''),
             int(data.get('tier1_member',1)), int(data.get('tier2_member',1)), int(data.get('tier3_member',0)),
             data.get('date_of_birth',''), data.get('date_appointed',''), data.get('contract_end_date',''),
             data.get('job_title',''), data.get('grade',''),
             float(data.get('basic_salary',0)), float(data.get('market_premium',0)),
             float(data.get('housing_allowance',0)), float(data.get('transport_allowance',0)),
             float(data.get('utility_allowance',0)), float(data.get('research_allowance',0)),
             float(data.get('other_allowance',0)), data.get('funding_source','UCC'),
             data.get('project_code',''), data.get('cost_centre',''),
             data.get('bank_name',''), data.get('bank_branch',''), data.get('account_number',''),
             float(data.get('union_deduction',0)), float(data.get('monthly_loan_repayment',0)),
             float(data.get('tax_relief_marriage',0)), int(data.get('tax_relief_children',0)),
             int(data.get('tax_relief_disabled',0)), int(data.get('tax_relief_aged_dependent',0)),
             data.get('status','Active'), data.get('notes',''), session['username']))
    # UCC unit attribution: stamp employees.unit_id (explicit pick → home unit) so the
    # payroll run carries each employee's org unit into the register and the GL.
    try:
        _eu = (_ucc_resolve_write_unit(conn, data, session) if '_ucc_resolve_write_unit' in globals() else data.get('unit_id'))
        if _eu and 'unit_id' in {r[1] for r in conn.execute("PRAGMA table_info(employees)").fetchall()}:
            conn.execute("UPDATE employees SET unit_id=? WHERE id=?", (_eu, eid))
    except Exception:
        pass
    _pay_audit(conn, session, 'SAVE_EMPLOYEE', None, eid, data.get('full_name',''))
    conn.commit(); conn.close()
    return {'ok': True, 'id': eid}

def _ensure_payroll_register_runtime_schema(conn):
    """Keep payroll_register compatible across old/new persistent databases."""
    try:
        cols = {r[1] for r in conn.execute("PRAGMA table_info(payroll_register)").fetchall()}
        for col, decl in [("arrears_description", "TEXT"), ("arrears_period", "TEXT")]:
            if col not in cols:
                conn.execute(f"ALTER TABLE payroll_register ADD COLUMN {col} {decl}")
    except Exception as exc:
        print("payroll schema compatibility warning:", exc)

def api_run_payroll(data, session):
    """Run payroll for all active employees for a given month"""
    month = data.get('month')
    if not month:
        return {'ok': False, 'error': 'Month is required (YYYY-MM)'}
    conn = get_db()
    _ensure_payroll_register_runtime_schema(conn)
    # Check if payroll already approved for this month
    existing = conn.execute(
        "SELECT COUNT(*) FROM payroll_register WHERE payroll_month=? AND status='Approved'",
        (month,)).fetchone()[0]
    if existing > 0:
        conn.close()
        return {'ok': False, 'error': f'Payroll for {month} is already approved and locked.'}
    # Safety: don't recompute while a reversal is still staged (GL not yet unwound). The
    # original payroll journal stays 'Posted' until a second admin posts the reversing entry,
    # so re-approving now would be skipped by idempotency and leave a half-state.
    _pend_rev = conn.execute("""SELECT jv_number FROM journal_vouchers
        WHERE source_module='payroll' AND source_id=? AND status='Posted' AND reversed_by IS NOT NULL
        LIMIT 1""", (month,)).fetchone()
    if _pend_rev:
        conn.close()
        return {'ok': False, 'error': f'Payroll {month} has a reversal awaiting a second admin to post. Post the reversing entry from the Reversals Register before re-running this month.'}
    # Recompute support: clear any prior Draft, and any Reversed rows (the month is being
    # re-run after a reversal) so the month list shows a single clean entry. The reversal
    # itself stays in the GL + Reversals Register. Commit so the clear persists.
    _rev_cleared = conn.execute("SELECT COUNT(*) FROM payroll_register WHERE payroll_month=? AND status='Reversed'", (month,)).fetchone()[0]
    conn.execute("DELETE FROM payroll_register WHERE payroll_month=? AND status IN ('Draft','Reversed')", (month,))
    if _rev_cleared:
        try: _pay_audit(conn, session, 'RECOMPUTE_PAYROLL', month, None, f'Re-running reversed payroll {month}: cleared {_rev_cleared} prior reversed line(s)')
        except Exception: pass
    conn.commit()
    settings_dict = {r['key']: r['value'] for r in conn.execute("SELECT key,value FROM payroll_settings")}
    employees = [dict(r) for r in conn.execute("SELECT * FROM employees WHERE status='Active'")]
    conn.close()
    # Per-employee overrides from request (e.g. arrears, bonuses)
    req_overrides = data.get('overrides') or {}
    results = []
    for emp in employees:
        emp_override = req_overrides.get(emp['id'], {}) if isinstance(req_overrides, dict) else {}
        rec = calc_employee_payroll(emp, month, emp_override, settings_dict)
        rec['id'] = str(uuid.uuid4())
        rec['created_by'] = session['username']
        conn = get_db()
        conn.execute("""INSERT INTO payroll_register(id,payroll_month,employee_id,basic_salary,
            market_premium,housing_allowance,transport_allowance,utility_allowance,
            research_allowance,other_allowance,overtime_amount,bonus,arrears,arrears_description,arrears_period,gross_pay,
            pensionable_emoluments,employee_tier1,employee_tier2,employee_tier3,
            total_employee_pension,taxable_income,total_relief,paye,loan_deduction,
            union_deduction,other_deduction,total_deductions,net_pay,employer_tier1,
            employer_tier2,total_employer_cost,tax_residency,division,funding_source,
            project_code,status,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (rec['id'],rec['payroll_month'],rec['employee_id'],rec['basic_salary'],
             rec['market_premium'],rec['housing_allowance'],rec['transport_allowance'],
             rec['utility_allowance'],rec['research_allowance'],rec['other_allowance'],
             rec['overtime_amount'],rec['bonus'],rec['arrears'],rec.get('arrears_description',''),rec.get('arrears_period',''),rec['gross_pay'],
             rec['pensionable_emoluments'],rec['employee_tier1'],rec['employee_tier2'],
             rec['employee_tier3'],rec['total_employee_pension'],rec['taxable_income'],
             rec['total_relief'],rec['paye'],rec['loan_deduction'],rec['union_deduction'],
             rec['other_deduction'],rec['total_deductions'],rec['net_pay'],
             rec['employer_tier1'],rec['employer_tier2'],rec['total_employer_cost'],
             rec['tax_residency'],rec['division'],rec['funding_source'],
             rec['project_code'],'Draft',session['username']))
        # UCC unit attribution: carry the employee's org unit onto the payroll line.
        try:
            _pru = emp.get('unit_id') if hasattr(emp, 'get') else None
            if _pru and 'unit_id' in {r[1] for r in conn.execute("PRAGMA table_info(payroll_register)").fetchall()}:
                conn.execute("UPDATE payroll_register SET unit_id=? WHERE id=?", (_pru, rec['id']))
        except Exception:
            pass
        conn.commit(); conn.close()
        results.append(rec)
    conn = get_db()
    _pay_audit(conn, session, 'RUN_PAYROLL', month, None, f'{len(results)} employees processed')
    conn.commit(); conn.close()
    return {'ok': True, 'month': month, 'count': len(results), 'records': results}

def api_get_payroll_register(session, month=None):
    conn = get_db()
    q = """SELECT r.*, e.full_name, e.employee_id AS emp_code, e.staff_number, e.job_title,
        e.employment_type, e.bank_name, e.account_number, e.gra_tin, e.ssnit_number
        FROM payroll_register r JOIN employees e ON r.employee_id=e.id"""
    args = []
    if month:
        q += " WHERE r.payroll_month=?"
        args.append(month)
    q += " ORDER BY r.payroll_month DESC, e.full_name"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows

def api_approve_payroll(data, session):
    if session['role'] not in ('Admin', 'Finance Officer'):
        return {'ok': False, 'error': 'Insufficient permissions to approve payroll'}
    month = data.get('month')
    conn = get_db()
    conn.execute("""UPDATE payroll_register SET status='Approved', approved_by=?, approved_at=datetime('now')
        WHERE payroll_month=? AND status='Draft'""", (session['username'], month))
    _pay_audit(conn, session, 'APPROVE_PAYROLL', month, None, f'Payroll {month} approved')

    # ── GL Auto-posting (IPSAS 25 / IAS 19) ──────────────────────────────────
    # Create a balanced payroll journal so the Trial Balance & Financial
    # Statements reflect ALL payroll cost (not just net cash disbursement).
    #   Dr  6000  Salary Expense            = Total Employer Cost
    #   Cr  2010  PAYE Tax Payable (GRA)    = Total PAYE withheld
    #   Cr  2011  SSNIT Tier 1 Payable      = Ee 5.5% + Er 8% = 13.5%
    #   Cr  2012  Tier 2 Pension Payable    = Ee 5% + Er 5% = 10% (if > 0)
    #   Cr  2038  Staff Deductions Payable  = Loans + Union + Other
    #   Cr  2036  Net Salary Payable        = Take-home (balancing figure)
    _gl_ok = True; _gl_msg = None
    # Idempotency: never post the payroll journal twice for the same month.
    if conn.execute("SELECT 1 FROM journal_vouchers WHERE source_module='payroll' AND source_id=? AND status='Posted'", (month,)).fetchone():
        conn.commit(); conn.close()
        return {'ok': True, 'gl_posted': True, 'message': f'Payroll {month} already posted to the ledger.'}
    try:
        # UCC unit attribution: build the payroll journal PER ORG UNIT so each unit's
        # salary cost and statutory payables land on its own GL lines (the journal stays
        # balanced overall because every unit's Dr = Cr). Rows with no unit_id fall into a
        # single NULL-unit group, preserving single-entity behaviour. _create_posted_journal
        # honours each line's unit_id.
        _has_unit_col = 'unit_id' in {r[1] for r in conn.execute("PRAGMA table_info(payroll_register)").fetchall()}
        _grp_expr = 'unit_id' if _has_unit_col else "NULL AS unit_id"
        unit_totals = conn.execute(("""
            SELECT %s,
                COALESCE(SUM(gross_pay),0)          as t_gross,
                COALESCE(SUM(paye),0)                as t_paye,
                COALESCE(SUM(employee_tier1),0)      as t_emp1,
                COALESCE(SUM(employer_tier1),0)      as t_er1,
                COALESCE(SUM(employee_tier2),0)      as t_emp2,
                COALESCE(SUM(employer_tier2),0)      as t_er2,
                COALESCE(SUM(loan_deduction),0)      as t_loan,
                COALESCE(SUM(union_deduction),0)     as t_union,
                COALESCE(SUM(other_deduction),0)     as t_other,
                COALESCE(SUM(net_pay),0)             as t_net,
                COALESCE(SUM(total_employer_cost),0) as t_cost
            FROM payroll_register WHERE payroll_month=? AND status='Approved'
        """ % _grp_expr) + (" GROUP BY unit_id" if _has_unit_col else ""), (month,)).fetchall()

        jv_date  = (month + '-01') if len(month) == 7 else month[:7] + '-01'
        # Resolve to real chart-of-accounts IDs (8-digit IPSAS codes). The legacy
        # 4-digit codes are kept as fallbacks. _create_posted_journal looks up the
        # account by id, so passing a bare code never matched and the payroll
        # journal silently failed to reach the ledger.
        def _pcoa(*codes):
            for _c in codes:
                _r = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (str(_c),)).fetchone()
                if _r: return _r['id']
            return None
        id_salary = _pcoa('61101001', '6000')                    # Basic Salary / wages (expense)
        id_ssnit_exp = _pcoa('61101003', '61101001')             # Employer SSNIT = social-security cost (expense)
        id_paye   = _pcoa('21100017', '2010')                    # PAYE payable
        id_ssnit  = _pcoa('21100015', '2011')                    # SSNIT / Social Security Fund payable
        id_tier2  = _pcoa('21100021', '2012')                    # Tier 2 → Sundry Creditors Control
        id_ded    = _pcoa('21100021', '2038')                    # Staff deductions → Sundry Creditors
        id_net    = _pcoa('21200005', '21100021', '2036')        # Net Salary Payable → Accrued Expenses

        jv_lines = []
        for totals in unit_totals:
            if not totals or float(totals['t_cost'] or 0) <= 0:
                continue
            _u = (totals['unit_id'] if 'unit_id' in totals.keys() else None)
            t_cost  = round(float(totals['t_cost']),  2)
            t_paye  = round(float(totals['t_paye']),  2)
            t_ssnit = round(float(totals['t_emp1']) + float(totals['t_er1']), 2)
            t_tier2 = round(float(totals['t_emp2']) + float(totals['t_er2']), 2)
            t_ded   = round(float(totals['t_loan']) + float(totals['t_union']) + float(totals['t_other']), 2)
            t_net   = round(float(totals['t_net']), 2)
            # Balancing: net-salary absorbs any sub-cent rounding difference (per unit).
            t_cr_check = t_paye + t_ssnit + t_tier2 + t_ded + t_net
            if abs(t_cost - t_cr_check) > 0.005:
                t_net = round(t_net + (t_cost - t_cr_check), 2)
            # Split the salary cost: employees' gross wages vs the EMPLOYER SSNIT
            # contribution, so each is shown under its proper expense account.
            t_employer_ssnit = round(float(totals['t_er1'] or 0) + float(totals['t_er2'] or 0), 2)
            t_gross_basic = round(t_cost - t_employer_ssnit, 2)
            jv_lines.append({'coa_id': id_salary, 'debit_amount': t_gross_basic, 'credit_amount': 0,
                             'description': f'Payroll {month} — Gross Salaries & Wages', 'unit_id': _u})
            if t_employer_ssnit > 0:
                jv_lines.append({'coa_id': id_ssnit_exp or id_salary, 'debit_amount': t_employer_ssnit, 'credit_amount': 0,
                                 'description': f'Payroll {month} — Employer SSNIT Contribution (Tier 1 8% + Tier 2 5%)', 'unit_id': _u})
            jv_lines += [
                {'coa_id': id_paye, 'debit_amount': 0, 'credit_amount': t_paye,
                 'description': f'PAYE Tax Withheld — {month}', 'unit_id': _u},
                {'coa_id': id_ssnit, 'debit_amount': 0, 'credit_amount': t_ssnit,
                 'description': f'SSNIT Tier 1 Payable (Ee 5.5% + Er 8%) — {month}', 'unit_id': _u},
            ]
            if t_tier2 > 0:
                jv_lines.append({'coa_id': id_tier2, 'debit_amount': 0, 'credit_amount': t_tier2,
                                  'description': f'Tier 2 Pension Payable (Employer 5%) — {month}', 'unit_id': _u})
            if t_ded > 0:
                jv_lines.append({'coa_id': id_ded, 'debit_amount': 0, 'credit_amount': t_ded,
                                  'description': f'Staff Deductions Payable (Loans/Union) — {month}', 'unit_id': _u})
            jv_lines.append({'coa_id': id_net, 'debit_amount': 0, 'credit_amount': t_net,
                              'description': f'Net Salary Payable — {month}', 'unit_id': _u})

        if jv_lines:
            if all(l['coa_id'] for l in jv_lines):
                _create_posted_journal(
                    conn, session, 'JV', jv_date,
                    f'Payroll {month} — Statutory GL Posting',
                    f'PAY-{month}', None, None, 'payroll', month, jv_lines
                )
            else:
                raise ValueError('one or more payroll COA accounts could not be resolved')
    except Exception as _pay_gl_ex:
        _gl_ok = False
        _gl_msg = (f'Payroll {month} was approved, but GL posting FAILED ({_pay_gl_ex}). '
                   'The ledger does NOT reflect this payroll — resolve the issue and re-approve.')
        print('[WARN] ' + _gl_msg, flush=True)
    # ─────────────────────────────────────────────────────────────────────────

    conn.commit(); conn.close()
    if not _gl_ok:
        return {'ok': True, 'gl_posted': False, 'warning': _gl_msg}
    return {'ok': True, 'gl_posted': True}

def api_reverse_payroll(data, session):
    """Reverse a posted payroll month. Reverses its GL journal through the standard
    reversal workflow -- so high-value payroll reversals inherit dual control (a second
    admin must post) and show up in the Reversals Register -- then marks the payroll
    month Reversed so it can be recomputed."""
    if not session: return {'ok': False, 'error': 'Not authenticated'}
    if session.get('role') != 'Admin':
        return {'ok': False, 'error': 'Only Admins can reverse a posted payroll'}
    month = (data.get('month') or '').strip()
    reason = (data.get('reason') or '').strip()
    if not month: return {'ok': False, 'error': 'Payroll month is required'}
    if len(reason) < 5: return {'ok': False, 'error': 'A reversal reason (at least 5 characters) is required'}
    conn = get_db()
    try:
        jv = conn.execute("""SELECT id, jv_number, status, reversed_by FROM journal_vouchers
            WHERE source_module='payroll' AND source_id=? AND status='Posted'
            ORDER BY rowid DESC LIMIT 1""", (month,)).fetchone()
        jv = dict(jv) if jv else None
    finally:
        conn.close()
    if not jv:
        return {'ok': False, 'error': f'No posted payroll journal found for {month}. Nothing to reverse.'}
    if jv.get('reversed_by'):
        return {'ok': False, 'error': f'Payroll {month} has already been reversed.'}
    # Reuse the standard reversal workflow: dual control on high-value + audit + register entry.
    res = api_jv_workflow({'jv_id': jv['id'], 'action': 'reverse',
                           'reason': f'Payroll {month} reversal: {reason}'}, session)
    if not (isinstance(res, dict) and res.get('ok')):
        return res
    conn = get_db()
    try:
        conn.execute("UPDATE payroll_register SET status='Reversed' WHERE payroll_month=? AND status IN ('Approved','Draft')", (month,))
        _pay_audit(conn, session, 'REVERSE_PAYROLL', month, None,
                   f'Payroll {month} reversed via {res.get("jv_number","reversing JV")}: {reason}')
        conn.commit()
    finally:
        conn.close()
    out = dict(res); out['month'] = month
    return out

def api_get_payroll_settings(session):
    conn = get_db()
    rows = [dict(r) for r in conn.execute("SELECT * FROM payroll_settings ORDER BY key")]
    bands = _get_paye_bands_for_year()  # always use current-year bands
    conn.close()
    return {'settings': rows, 'bands': bands}

def api_save_payroll_setting(data, session):
    if session['role'] != 'Admin':
        return {'ok': False, 'error': 'Admin only'}
    conn = get_db()
    conn.execute("INSERT OR REPLACE INTO payroll_settings(key,value,description,updated_by,updated_at) VALUES(?,?,?,?,datetime('now'))",
        (data['key'], data['value'], data.get('description',''), session['username']))
    _pay_audit(conn, session, 'UPDATE_SETTING', None, data['key'], f"Set to {data['value']}")
    conn.commit(); conn.close()
    return {'ok': True}

def api_get_payroll_months(session):
    conn = get_db()
    rows = [dict(r) for r in conn.execute("""
        SELECT payroll_month, status, COUNT(*) as emp_count,
        SUM(gross_pay) as total_gross, SUM(net_pay) as total_net,
        SUM(paye) as total_paye, SUM(employee_tier1) as total_ssnit,
        SUM(total_employer_cost) as total_cost
        FROM payroll_register GROUP BY payroll_month, status ORDER BY payroll_month DESC""")]
    conn.close()
    return rows

def api_get_payslip(session, reg_id):
    conn = get_db()
    row = conn.execute("""SELECT r.*, e.full_name, e.employee_id AS emp_code, e.staff_number, e.job_title,
        e.division, e.bank_name, e.account_number, e.gra_tin, e.ssnit_number,
        e.employment_type, e.tax_residency, e.funding_source
        FROM payroll_register r JOIN employees e ON r.employee_id=e.id WHERE r.id=?""",
        (reg_id,)).fetchone()
    conn.close()
    return dict(row) if row else None

def api_get_statutory_schedules(session, month):
    conn = get_db()
    q = """SELECT r.*, e.full_name, e.employee_id, e.gra_tin, e.ssnit_number, e.bank_name, e.account_number
        FROM payroll_register r JOIN employees e ON r.employee_id=e.id
        WHERE r.payroll_month=? ORDER BY e.full_name"""
    rows = [dict(r) for r in conn.execute(q, (month,))]
    conn.close()
    return {
        'month': month,
        'paye_schedule': rows,
        'ssnit_schedule': [r for r in rows if r['employee_tier1'] > 0],
        'net_pay_schedule': rows,
        'summary': {
            'total_gross': sum(r['gross_pay'] for r in rows),
            'total_paye': sum(r['paye'] for r in rows),
            'total_ssnit_employee': sum(r['employee_tier1'] for r in rows),
            'total_ssnit_employer': sum(r['employer_tier1'] for r in rows),
            'total_tier2_employer': sum(r['employer_tier2'] for r in rows),
            'total_net': sum(r['net_pay'] for r in rows),
            'total_employer_cost': sum(r['total_employer_cost'] for r in rows),
        }
    }

def _pay_audit(conn, session, action, month, emp_id, details):
    conn.execute("INSERT INTO payroll_audit(id,username,action,payroll_month,employee_id,details) VALUES(?,?,?,?,?,?)",
        (str(uuid.uuid4()), session.get('username','system'), action, month, emp_id, details))

