def export_csv_generic(headers, rows_data, title="UCC Export"):
    out = io.StringIO()
    w = csv.writer(out)
    w.writerow([title])
    w.writerow(['University of Cape Coast, University of Cape Coast, Ghana'])
    w.writerow([])
    w.writerow(headers)
    for row in rows_data:
        w.writerow(row)
    return out.getvalue()

def get_payroll_export_rows(records):
    headers = ['EmpID','Name','Division','Type','Tax','Basic','Gross',
               'SSNIT_Emp(5.5%)','PAYE','Loan','Union','Total_Ded','Net_Pay',
               'Empr_Tier1(8%)','Empr_Tier2(5%)','Total_Tier1_SSNIT','Employer_Cost',
               'GRA_TIN','SSNIT_No','Bank','Account','Fund_Source','Status']
    rows = []
    for r in records:
        t1 = round((r.get('employee_tier1',0) or 0)+(r.get('employer_tier1',0) or 0),2)
        rows.append([
            r.get('employee_id',''), r.get('full_name',''), r.get('division',''),
            r.get('employment_type',''), r.get('tax_residency',''),
            r.get('basic_salary',0), r.get('gross_pay',0),
            r.get('employee_tier1',0), r.get('paye',0),
            r.get('loan_deduction',0), r.get('union_deduction',0),
            r.get('total_deductions',0), r.get('net_pay',0),
            r.get('employer_tier1',0), r.get('employer_tier2',0), t1,
            r.get('total_employer_cost',0),
            r.get('gra_tin',''), r.get('ssnit_number',''),
            r.get('bank_name',''), r.get('account_number',''),
            r.get('funding_source',''), r.get('status','')
        ])
    return headers, rows


