def api_get_users(session):
    if session.get('role') != 'Admin':
        return err('Admin access required')
    conn = get_db()
    rows = [dict(r) for r in conn.execute(
        "SELECT id,username,full_name,role,email,active,created_at,home_unit_id,scope "
        "FROM users ORDER BY full_name")]
    conn.close()
    return rows

def api_save_user(data, session):
    import hashlib as _hl
    if session.get('role') != 'Admin':
        return err('Admin access required')
    conn = get_db()
    uid = data.get('id') or str(uuid.uuid4())

    # Delete user
    if data.get('_delete'):
        protected = conn.execute("SELECT username FROM users WHERE id=?", (uid,)).fetchone()
        if not protected:
            conn.close(); return err('User not found')
        if protected[0] in ('admin', 'demo'):
            conn.close(); return err('Cannot delete system accounts (admin/demo)')
        conn.execute("DELETE FROM users WHERE id=?", (uid,))
        _audit(conn, session, 'DELETE_USER', 'users', uid, data.get('username',''))
        conn.commit(); conn.close()
        return ok({'deleted': uid})

    if data.get('id'):
        fields = ['full_name','role','email','active']
        set_parts = [f"{f}=?" for f in fields]
        vals = [data.get(f) for f in fields]
        # Optional unit assignment — only touched when explicitly provided, so a
        # plain profile edit never wipes a user's home unit / scope.
        for opt in ('home_unit_id', 'scope'):
            if opt in data:
                set_parts.append(f"{opt}=?"); vals.append(data.get(opt))
        if data.get('new_password'):
            set_parts.append('password_hash=?')
            vals.append(_hl.sha256(data['new_password'].encode()).hexdigest())
        conn.execute(f"UPDATE users SET {','.join(set_parts)} WHERE id=?", vals + [uid])
        _audit(conn, session, 'UPDATE_USER', 'users', uid, data.get('username',''))
    else:
        if not data.get('password'):
            conn.close(); return err('Password required for new user')
        _pw_new = data['password']
        if len(_pw_new) < 10 or not any(c.isupper() for c in _pw_new) \
                or not any(c.islower() for c in _pw_new) or not any(c.isdigit() for c in _pw_new):
            conn.close(); return err('Password must be at least 10 characters including uppercase, lowercase and a digit')
        pw = _hl.sha256(data['password'].encode()).hexdigest()
        _scope = data.get('scope') or ('university' if data.get('role') == 'Admin' else 'own_unit')
        conn.execute("""INSERT INTO users(id,username,password_hash,full_name,role,email,active,home_unit_id,scope)
            VALUES(?,?,?,?,?,?,1,?,?)""",
            (uid, data['username'], pw, data['full_name'], data['role'],
             data.get('email',''), data.get('home_unit_id'), _scope))
        _audit(conn, session, 'CREATE_USER', 'users', uid, data.get('username',''))
    conn.commit(); conn.close()
    return ok({'id': uid})

def api_get_notifications(session):
    """Return system notifications / alerts."""
    conn = get_db()
    notes = []
    # Overdue commitments
    overdue = conn.execute("""SELECT COUNT(*) FROM commitments
        WHERE status='Open' AND commit_date < date('now','-90 days')""").fetchone()[0]
    if overdue:
        notes.append({'type':'warning','title':f'{overdue} commitment(s) older than 90 days','module':'commitments'})
    # Pending JVs (submitted but not approved)
    pending_jv = conn.execute(
        "SELECT COUNT(*) FROM journal_vouchers WHERE status='Submitted'").fetchone()[0]
    if pending_jv:
        notes.append({'type':'info','title':f'{pending_jv} JV(s) awaiting approval','module':'jvs'})
    # Projects ending soon (within 60 days)
    ending = conn.execute("""SELECT COUNT(*) FROM projects
        WHERE status='Active' AND end_date BETWEEN date('now') AND date('now','+60 days')""").fetchone()[0]
    if ending:
        notes.append({'type':'warning','title':f'{ending} project(s) ending within 60 days','module':'projects'})
    # Budget overruns
    overrun = conn.execute("""SELECT COUNT(DISTINCT b.id) FROM budgets b
        WHERE (SELECT COALESCE(SUM(a.amount_ghs),0) FROM actuals a WHERE a.budget_id=b.id) > b.budget_ghs""").fetchone()[0]
    if overrun:
        notes.append({'type':'danger','title':f'{overrun} budget line(s) exceeded','module':'budgets'})
    conn.close()
    return notes

def api_get_search(session, query):
    """Global search across projects, actuals, commitments."""
    if not query or len(query) < 2:
        return []
    q = f"%{query}%"
    conn = get_db()
    results = []
    for r in conn.execute("SELECT id,project_code,title,'project' as type FROM projects WHERE project_code LIKE ? OR title LIKE ? OR donor LIKE ? LIMIT 5", (q,q,q)):
        results.append({'id':r['id'],'label':f"{r['project_code']} – {r['title']}","type":"project"})
    for r in conn.execute("SELECT id,actual_code,payee,description,'actual' as type FROM actuals WHERE actual_code LIKE ? OR payee LIKE ? OR description LIKE ? LIMIT 5", (q,q,q)):
        results.append({'id':r['id'],'label':f"{r['actual_code']} – {r['payee']} – {r['description'][:40]}","type":"actual"})
    for r in conn.execute("SELECT id,commit_code,vendor,description,'commitment' as type FROM commitments WHERE commit_code LIKE ? OR vendor LIKE ? LIMIT 5", (q,q)):
        results.append({'id':r['id'],'label':f"{r['commit_code']} – {r['vendor']}","type":"commitment"})
    conn.close()
    return results

def api_get_dashboard_charts(session):
    """Return chart data for the enhanced dashboard."""
    conn = get_db()
    # Monthly actuals trend (last 12 months)
    monthly = [dict(r) for r in conn.execute("""
        SELECT strftime('%Y-%m', expense_date) as month,
               ROUND(SUM(amount_ghs),2) as total
        FROM actuals
        WHERE expense_date >= date('now','-12 months')
        GROUP BY month ORDER BY month
    """)]
    # Budget utilisation by project
    utilisation = [dict(r) for r in conn.execute("""
        SELECT p.project_code, p.title,
               ROUND(p.budget_ghs,2) as budget,
               ROUND(COALESCE((SELECT SUM(amount_ghs) FROM actuals a WHERE a.project_id=p.id),0),2) as spent,
               ROUND(COALESCE((SELECT SUM(amount_ghs) FROM commitments c WHERE c.project_id=p.id AND c.status='Open'),0),2) as committed
        FROM projects p WHERE p.status='Active'
        ORDER BY budget DESC LIMIT 8
    """)]
    # Expenditure by COA category
    by_category = [dict(r) for r in conn.execute("""
        SELECT c.category,
               ROUND(SUM(a.amount_ghs),2) as total
        FROM actuals a
        JOIN budgets b ON a.budget_id=b.id
        JOIN chart_of_accounts c ON b.coa_id=c.id
        GROUP BY c.category ORDER BY total DESC LIMIT 6
    """)]
    # Fund receipts by month
    receipts_trend = [dict(r) for r in conn.execute("""
        SELECT strftime('%Y-%m', receipt_date) as month,
               ROUND(SUM(amount_ghs),2) as total
        FROM fund_receipts
        WHERE receipt_date >= date('now','-12 months')
        GROUP BY month ORDER BY month
    """)]
    conn.close()
    return {
        'monthly_actuals': monthly,
        'utilisation': utilisation,
        'by_category': by_category,
        'receipts_trend': receipts_trend,
    }


# ═══════════════════════════════════════════════════════════════════════════
# UCC-FMS v3.1 WORLDCLASS HARDENING PATCH
# Persistent Render disk, IPSAS double-entry flow, safer periods and audit trail
# ═══════════════════════════════════════════════════════════════════════════
from calendar import monthrange as _monthrange

# Prefer the mounted Render disk whenever present. This is intentionally repeated
# at the end of the module so DB_PATH is corrected even if RENDER_DATA_DIR was not
# set before import.
def _resolve_db_path():
    candidates = []
    data_dir_env = os.environ.get('RENDER_DATA_DIR', '').strip()
    if data_dir_env:
        candidates.append(Path(data_dir_env))
    # Render persistent disk convention used by render.yaml
    candidates.append(Path('/var/data'))
    for data_dir in candidates:
        try:
            data_dir.mkdir(parents=True, exist_ok=True)
            test = data_dir / '.sbs_write_test'
            test.write_text('ok')
            test.unlink(missing_ok=True)
            dbp = data_dir / 'ucc_fms.db'
            print(f"  DB location: {dbp} (persistent disk)")
            return dbp
        except Exception:
            continue
    fallback = Path(__file__).parent / 'ucc_fms.db'
    print(f"  DB location: {fallback} (local fallback)")
    return fallback

DB_PATH = _resolve_db_path()
# Reapply training-mode path after second _resolve_db_path() (UCC-FMS pattern)
if '_TRAINING_MODE' in dir() and _TRAINING_MODE:
    DB_PATH = DB_PATH.parent / (DB_PATH.stem + '_training' + DB_PATH.suffix)


def _col_exists(conn, table, col):
    try:
        return any(r[1] == col for r in conn.execute(f"PRAGMA table_info({table})").fetchall())
    except Exception:
        return False


def _add_col(conn, table, ddl):
    col = ddl.split()[0]
    if not _col_exists(conn, table, col):
        conn.execute(f"ALTER TABLE {table} ADD COLUMN {ddl}")


def _month_bounds(period):
    y, m = [int(x) for x in period[:7].split('-')]
    return f"{y:04d}-{m:02d}-01", f"{y:04d}-{m:02d}-{_monthrange(y,m)[1]:02d}"


def _ensure_accounting_period(conn, txn_date):
    """Return an accounting period row for a date, creating an Open monthly period if absent."""
    if not txn_date:
        txn_date = datetime.now().strftime('%Y-%m-%d')
    # Prefer range-based periods, falling back to YYYY-MM period field.
    try:
        row = conn.execute("""SELECT * FROM accounting_periods
            WHERE start_date IS NOT NULL AND end_date IS NOT NULL
              AND date(?) BETWEEN date(start_date) AND date(end_date)
            ORDER BY start_date DESC LIMIT 1""", (txn_date,)).fetchone()
        if row:
            return row
    except Exception:
        pass
    period = txn_date[:7]
    row = conn.execute("SELECT * FROM accounting_periods WHERE period=?", (period,)).fetchone()
    if row:
        return row
    start, end = _month_bounds(period)
    name = datetime.strptime(start, '%Y-%m-%d').strftime('%B %Y')
    conn.execute("""INSERT OR IGNORE INTO accounting_periods
        (id,period,period_name,status,opened_by,start_date,end_date)
        VALUES(?,?,?,?,?,?,?)""", (str(uuid.uuid4()), period, name, 'Open', 'system', start, end))
    return conn.execute("SELECT * FROM accounting_periods WHERE period=?", (period,)).fetchone()


def _assert_period_open(conn, txn_date):
    row = _ensure_accounting_period(conn, txn_date)
    if row and row['status'] != 'Open':
        return False, f"Accounting period {row['period']} is {row['status']}. Re-open the period before posting."
    return True, row['period'] if row else (txn_date or '')[:7]


def _get_coa(conn, codes):
    if isinstance(codes, str):
        codes = [codes]
    expanded = []
    try:
        from ucc_chart_of_accounts import coa_alias_candidates
        for code in codes:
            expanded.extend(coa_alias_candidates(str(code), org='SBS'))
    except Exception:
        expanded.extend([str(c) for c in codes])
    seen = set()
    for code in expanded:
        code = str(code)
        if code in seen:
            continue
        seen.add(code)
        row = conn.execute("SELECT id, code, account_name FROM chart_of_accounts WHERE code=?", (code,)).fetchone()
        if row:
            return row
    return None

def _coa_id(conn, code):
    row = _get_coa(conn, code)
    return row['id'] if row else None


def _bank_coa_for(conn, bank_account_id=None, currency='GHS'):
    if bank_account_id:
        try:
            acct = conn.execute("SELECT * FROM bank_accounts WHERE id=?", (bank_account_id,)).fetchone()
            if acct:
                if 'coa_id' in acct.keys() and acct['coa_id']:
                    row = conn.execute("SELECT id, code, account_name FROM chart_of_accounts WHERE id=?", (acct['coa_id'],)).fetchone()
                    if row: return row
                # Good default for donor/research bank accounts in SBS COA
                if acct['currency'] and acct['currency'] != 'GHS':
                    row = _get_coa(conn, ['1004','1003','1001'])
                else:
                    row = _get_coa(conn, ['1001','1003','1004'])
                if row: return row
        except Exception:
            pass
    return _get_coa(conn, ['1001','1003','1004','1005'])


def _insert_voucher_posted(conn, session, *, jv_type, jv_date, description, project_id=None,
                           bank_account_id=None, source_module='manual', source_id=None,
                           reference='', lines=None, notes='System posted from source transaction',
                           unit_id=None):
    lines = lines or []
    ok_bal, msg = _validate_jv_lines(lines)
    if not ok_bal:
        raise ValueError(msg)
    okp, period = _assert_period_open(conn, jv_date)
    if not okp:
        raise ValueError(period)
    jv_id = str(uuid.uuid4())
    jv_num = _next_jv_number(conn, jv_type)
    total_dr = round(sum(float(l.get('debit_amount', 0) or 0) for l in lines), 2)
    total_cr = round(sum(float(l.get('credit_amount', 0) or 0) for l in lines), 2)
    now = datetime.now().isoformat()
    user = session.get('username','system') if session else 'system'
    # UCC unit attribution (Phase 1b): explicit unit → posting user's home unit.
    _wunit = unit_id or (_ucc_resolve_write_unit(conn, None, session)
                         if '_ucc_resolve_write_unit' in globals() else None)
    conn.execute("""INSERT INTO journal_vouchers
        (id,jv_number,jv_type,jv_date,period,description,narration,reference,
         project_id,bank_account_id,currency,fx_rate,total_debit,total_credit,
         status,prepared_by,prepared_at,submitted_by,submitted_at,approved_by,approved_at,
         posted_by,posted_at,auto_generated,source_module,source_id,notes,unit_id)
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (jv_id,jv_num,jv_type,jv_date,period,description,notes,reference,
         project_id,bank_account_id,'GHS',1.0,total_dr,total_cr,'Posted',user,now,
         user,now,user,now,user,now,1,source_module,source_id,notes,_wunit))
    for i, line in enumerate(lines, 1):
        line_id = str(uuid.uuid4())
        coa = conn.execute("SELECT code, account_name FROM chart_of_accounts WHERE id=?", (line['coa_id'],)).fetchone()
        if not coa:
            raise ValueError('Invalid chart of accounts line in voucher')
        line_project = line.get('project_id') or project_id
        conn.execute("""INSERT INTO jv_lines
            (id,jv_id,line_number,coa_id,description,debit_amount,credit_amount,
             project_id,cost_centre,bank_account_id,tax_code)
            VALUES(?,?,?,?,?,?,?,?,?,?,?)""",
            (line_id,jv_id,i,line['coa_id'],line.get('description',description),
             float(line.get('debit_amount',0) or 0),float(line.get('credit_amount',0) or 0),
             line_project,line.get('cost_centre',''),line.get('bank_account_id') or bank_account_id,
             line.get('tax_code','')))
        project_code = ''
        if line_project:
            pr = conn.execute("SELECT project_code FROM projects WHERE id=?", (line_project,)).fetchone()
            project_code = pr['project_code'] if pr else ''
        conn.execute("""INSERT INTO general_ledger
            (id,jv_id,jv_number,jv_line_id,ledger_date,period,coa_id,coa_code,
             account_name,description,debit_amount,credit_amount,project_id,project_code,posted_by,unit_id)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (str(uuid.uuid4()),jv_id,jv_num,line_id,jv_date,period,line['coa_id'],coa['code'],
             coa['account_name'],line.get('description',description),
             float(line.get('debit_amount',0) or 0),float(line.get('credit_amount',0) or 0),
             line_project,project_code,user,(line.get('unit_id') or _wunit)))
    _jv_audit(conn, session or {}, jv_id, jv_num, 'AUTO_POST', None, 'Posted', notes)
    _audit(conn, session or {}, f'AUTO_POST_{jv_type}', 'journal_vouchers', jv_id, description)
    return jv_id, jv_num


def _reverse_voucher(conn, session, jv_id, reason='Correction'):
    orig = conn.execute("SELECT * FROM journal_vouchers WHERE id=?", (jv_id,)).fetchone()
    if not orig or orig['status'] not in ('Posted','Reversed'):
        return None
    if orig['status'] == 'Reversed':
        return orig['reversed_by']
    rev_date = datetime.now().strftime('%Y-%m-%d')
    # Correction-of-error best practice (IPSAS 3): when the ORIGINAL period is
    # still open, date the reversal INTO that period so it cancels the wrong
    # entry in-month and the cash book / monthly reports show the true picture.
    # Only a closed/locked original period forces the reversal into today.
    try:
        _od = (orig['jv_date'] or '')[:10]
        if _od:
            _ok0, _p0 = _assert_period_open(conn, _od)
            if _ok0:
                rev_date = _od
    except Exception:
        pass
    okp, period = _assert_period_open(conn, rev_date)
    if not okp:
        raise ValueError(period)
    orig_lines = [dict(r) for r in conn.execute("SELECT * FROM jv_lines WHERE jv_id=? ORDER BY line_number", (jv_id,)).fetchall()]
    lines = []
    for line in orig_lines:
        lines.append({
            'coa_id': line['coa_id'],
            'description': 'REVERSAL: ' + (line['description'] or orig['description']),
            'debit_amount': float(line['credit_amount'] or 0),
            'credit_amount': float(line['debit_amount'] or 0),
            'project_id': line['project_id'],
            'bank_account_id': line['bank_account_id'],
            'tax_code': line['tax_code'] or ''
        })
    rev_id, rev_num = _insert_voucher_posted(conn, session, jv_type='RJV', jv_date=rev_date,
        description=f"Reversal of {orig['jv_number']} — {reason}", project_id=orig['project_id'],
        bank_account_id=orig['bank_account_id'], source_module='reversal', source_id=jv_id,
        reference=orig['jv_number'], lines=lines, notes=reason)
    conn.execute("UPDATE journal_vouchers SET status='Reversed', reversed_by=? WHERE id=?", (rev_id, jv_id))
    try:
        conn.execute("UPDATE journal_vouchers SET is_reversal=1, reversal_of=? WHERE id=?", (jv_id, rev_id))
    except Exception:
        pass
    _audit(conn, session or {}, 'REVERSE_POSTED_VOUCHER', 'journal_vouchers', jv_id,
           f"{orig['jv_number']} reversed by {rev_num}: {reason}")
    return rev_id


def _worldclass_migrations():
    conn = get_db()
    try:
        for ddl in [
            "bank_account_id TEXT", "payment_method TEXT DEFAULT 'Bank Transfer'", "payment_reference TEXT",
            "jv_id TEXT", "edit_reason TEXT", "last_amended_by TEXT", "last_amended_at TEXT"
        ]:
            try: _add_col(conn, 'actuals', ddl)
            except Exception: pass
        for ddl in [
            "coa_id TEXT", "last_amended_by TEXT", "last_amended_at TEXT"
        ]:
            try: _add_col(conn, 'bank_accounts', ddl)
            except Exception: pass
        for ddl in [
            "budget_id TEXT", "receipt_no TEXT", "transfer_ref TEXT", "is_posted INTEGER DEFAULT 0",
            "posted_by TEXT", "posted_at TEXT", "jv_id TEXT", "last_amended_by TEXT", "last_amended_at TEXT"
        ]:
            try: _add_col(conn, 'fund_receipts', ddl)
            except Exception: pass
        # Ensure the table exists before we touch it. On a fresh persistent disk,
        # init_db() (which calls this migration) runs before init_jv_db() creates
        # accounting_periods, so we create it here idempotently to avoid a startup crash.
        conn.execute("""CREATE TABLE IF NOT EXISTS accounting_periods (
            id          TEXT PRIMARY KEY,
            period      TEXT UNIQUE NOT NULL,
            period_name TEXT NOT NULL,
            status      TEXT DEFAULT 'Open'
                CHECK(status IN ('Open','Closed','Locked')),
            opened_by   TEXT,
            closed_by   TEXT,
            closed_at   TEXT,
            created_at  TEXT DEFAULT (datetime('now'))
        )""")
        for ddl in ["start_date TEXT", "end_date TEXT", "opened_by TEXT"]:
            try: _add_col(conn, 'accounting_periods', ddl)
            except Exception: pass
        # Backfill period ranges.
        for r in conn.execute("SELECT id, period, start_date, end_date FROM accounting_periods").fetchall():
            if not r['start_date'] or not r['end_date']:
                st, en = _month_bounds(r['period'])
                conn.execute("UPDATE accounting_periods SET start_date=?, end_date=? WHERE id=?", (st,en,r['id']))
        # Seed current/prior/next periods with ranges.
        today = date.today().replace(day=1)
        for offset in range(-6, 13):
            y = today.year + ((today.month-1 + offset)//12)
            m = ((today.month-1 + offset) % 12) + 1
            period = f"{y:04d}-{m:02d}"
            st, en = _month_bounds(period)
            name = datetime.strptime(st, '%Y-%m-%d').strftime('%B %Y')
            conn.execute("""INSERT OR IGNORE INTO accounting_periods
                (id,period,period_name,status,opened_by,start_date,end_date)
                VALUES(?,?,?,?,?,?,?)""", (str(uuid.uuid4()), period, name, 'Open', 'system', st, en))
        # Link existing bank accounts to a sensible COA code.
        main_bank = _get_coa(conn, ['1001','1003','1004'])
        if main_bank:
            conn.execute("UPDATE bank_accounts SET coa_id=COALESCE(coa_id, ?) WHERE coa_id IS NULL", (main_bank['id'],))
        # Backfill payment reference from old receipt_no when relevant.
        try:
            conn.execute("UPDATE actuals SET payment_reference=COALESCE(payment_reference, receipt_no) WHERE payment_reference IS NULL AND receipt_no IS NOT NULL")
        except Exception: pass
        conn.commit()
    finally:
        conn.close()
    print('  Migration: SBS v3.1 worldclass finance controls applied')


_original_init_db = init_db
def init_db():
    _original_init_db()
    _worldclass_migrations()

_original_init_jv_db = init_jv_db
def init_jv_db():
    _original_init_jv_db()
    _worldclass_migrations()


def _create_bank_coa(conn, code, name):
    """Insert a new bank/cash asset account into the chart of accounts."""
    import uuid as _u
    cid = str(_u.uuid4())
    conn.execute("INSERT INTO chart_of_accounts(id,code,category,sub_category,account_name,account_type,vat_applicable) "
                 "VALUES(?,?,?,?,?,?,0)",
                 (cid, str(code), 'Assets', 'Bank Accounts', (name or 'Bank Account')[:120], 'Asset'))
    return cid


def _ensure_bank_coa(conn, data):
    """Return a valid BANK-ASSET chart-of-accounts id for a bank account, creating
    one if needed so EVERY bank has its own GL account. Preference:
      1) a supplied coa_id that is already a 12x asset;
      2) the typed account_number when it is a free 8-digit 12x code -> create it;
      3) the next available 127xxxxx code -> create it (auto-extends the chart)."""
    cid = (data or {}).get('coa_id')
    if cid:
        r = conn.execute("SELECT id, code FROM chart_of_accounts WHERE id=?", (cid,)).fetchone()
        if r and str(r['code']).startswith('12'):
            return r['id']
    name = ((data or {}).get('account_name') or (data or {}).get('bank_name') or 'Bank Account').strip()
    acctno = str((data or {}).get('account_number') or '').strip()
    if acctno.isdigit() and len(acctno) == 8 and acctno.startswith('12'):
        r = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (acctno,)).fetchone()
        return r['id'] if r else _create_bank_coa(conn, acctno, name)
    row = conn.execute("SELECT code FROM chart_of_accounts WHERE code LIKE '127%' AND LENGTH(code)=8 ORDER BY code DESC LIMIT 1").fetchone()
    nxt = (int(row['code']) + 1) if (row and str(row['code']).isdigit()) else 12703001
    while conn.execute("SELECT 1 FROM chart_of_accounts WHERE code=?", (str(nxt),)).fetchone():
        nxt += 1
    return _create_bank_coa(conn, str(nxt), name)


def _bank_opening_sync(conn, session, bank_id):
    """Post (or re-post) a bank account's opening balance into the GENERAL LEDGER
    as a balanced AJV (Dr bank COA / Cr Accumulated Fund) so it appears in the
    Trial Balance and SFP. Idempotent: any prior opening JV for this bank is
    removed first, so editing the figure (including to 0) updates the ledger."""
    try:
        row = conn.execute("SELECT account_name, opening_balance, coa_id FROM bank_accounts WHERE id=?", (bank_id,)).fetchone()
        if not row:
            return None
        amt = round(float(row['opening_balance'] or 0), 2)
        coa_id = row['coa_id']
        # remove any prior bank-opening journal for this bank (so re-saves don't stack)
        for p in conn.execute("SELECT id FROM journal_vouchers WHERE source_module='bank_opening_balance' AND source_id=? AND status='Posted'", (bank_id,)).fetchall():
            conn.execute("DELETE FROM general_ledger WHERE jv_id=?", (p['id'],))
            conn.execute("UPDATE journal_vouchers SET status='Reversed', total_debit=0, total_credit=0 WHERE id=?", (p['id'],))
        if amt == 0 or not coa_id:
            return None
        acc = (conn.execute("SELECT id FROM chart_of_accounts WHERE code='31100001'").fetchone()
               or conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '311%' ORDER BY code LIMIT 1").fetchone()
               or conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '3%' ORDER BY code LIMIT 1").fetchone())
        if not acc:
            return None
        import datetime as _dt
        ob_date = '%d-01-01' % _dt.date.today().year
        desc = 'Opening balance: %s' % (row['account_name'] or 'Bank account')
        jv_id, jv_num = _create_posted_journal(
            conn, session, 'AJV', ob_date, desc, 'BANK-OB', None, None,
            'bank_opening_balance', bank_id,
            [{'coa_id': coa_id, 'debit_amount': amt, 'credit_amount': 0, 'description': desc},
             {'coa_id': acc['id'], 'debit_amount': 0, 'credit_amount': amt, 'description': desc}])
        return jv_num
    except Exception as _boe:
        print('bank opening-balance sync warning:', _boe)
        return None


def api_save_bank_account(data, session):
    conn = get_db()
    try:
        bid = data.get('id') or str(uuid.uuid4())
        # Validate required fields with clear messages (previously these were hard
        # dict accesses, so a missing field raised a cryptic KeyError instead of a
        # readable validation error).
        account_name = (data.get('account_name') or '').strip()
        bank_name = (data.get('bank_name') or data.get('bank') or '').strip()
        account_number = (data.get('account_number') or '').strip()
        _missing = [lbl for val, lbl in ((account_name, 'Account name'),
                                         (bank_name, 'Bank name'),
                                         (account_number, 'Account number')) if not val]
        if _missing:
            conn.close()
            return err(', '.join(_missing) + (' is' if len(_missing) == 1 else ' are') + ' required')
        # Ensure the bank has its own BANK-ASSET chart account (auto-create the next
        # available 127xxxxx code if none exists), so opening balances and payments
        # always post to a real bank asset — never a fallback expense account.
        coa_id = _ensure_bank_coa(conn, data)
        if data.get('id'):
            # include opening_balance so admins can correct it (it was previously omitted,
            # which is why editing the figure appeared to do nothing).
            conn.execute("""UPDATE bank_accounts SET account_name=?,bank_name=?,branch=?,
                account_number=?,account_type=?,currency=?,project_id=?,description=?,is_active=?,opening_balance=?,coa_id=?,last_amended_by=?,last_amended_at=datetime('now')
                WHERE id=?""",
                (account_name,bank_name,data.get('branch',''),
                 account_number,data.get('account_type','Current'),data.get('currency','GHS'),
                 data.get('project_id') or None,data.get('description',''),int(data.get('is_active',1)),
                 float(data.get('opening_balance',0) or 0),coa_id,session['username'],bid))
        else:
            conn.execute("""INSERT INTO bank_accounts(id,account_name,bank_name,branch,account_number,
                account_type,currency,project_id,description,opening_balance,created_by,coa_id)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?)""",
                (bid,account_name,bank_name,data.get('branch',''),account_number,
                 data.get('account_type','Current'),data.get('currency','GHS'),
                 data.get('project_id') or None,data.get('description',''),
                 float(data.get('opening_balance',0)),session['username'],coa_id))
        # Post/refresh the opening balance into the GL so it shows in the Trial Balance & SFP.
        _bank_opening_sync(conn, session, bid)
        _audit(conn, session, 'SAVE_BANK_ACCOUNT', 'bank_accounts', bid, data.get('account_name',''))
        conn.commit()
        return {'ok': True, 'id': bid}
    except Exception as _bse:
        try: conn.rollback()
        except Exception: pass
        msg = str(_bse)
        if 'UNIQUE' in msg and 'account_number' in msg:
            return err('A bank account with that account number already exists.')
        return err('Bank account save failed: ' + msg)
    finally:
        try: conn.close()
        except Exception: pass


def _expense_lines_for_actual(conn, txn):
    gross = float(txn['amount_ghs'] or 0)
    has_vat = int(txn.get('has_vat') or 0)
    has_whvat = int(txn.get('has_whvat') or 0)
    ex_vat = round(gross / 1.2, 2) if has_whvat else gross
    vat_amount = float(txn.get('vat_amount') or 0)
    wht = float(txn.get('wht_amount') or 0)
    whvat = float(txn.get('whvat_amount') or 0)
    ucf = float(txn.get('ucf_amount') or 0)
    expense_coa = None
    if txn.get('budget_id'):
        expense_coa = conn.execute("""SELECT c.id, c.code, c.account_name FROM budgets b
            JOIN chart_of_accounts c ON b.coa_id=c.id WHERE b.id=?""", (txn['budget_id'],)).fetchone()
    if not expense_coa:
        expense_coa = _get_coa(conn, ['6103','6111','6300','6000'])
    bank_coa = _bank_coa_for(conn, txn.get('bank_account_id'), txn.get('currency','GHS'))
    if not expense_coa or not bank_coa:
        raise ValueError('Could not determine expense or bank account for posting')
    debit_expense = ex_vat if has_vat else gross
    debit_vat = vat_amount if has_vat else 0
    gross_invoice = round(debit_expense + debit_vat, 2)
    net_bank = round(gross_invoice - wht - whvat - ucf, 2)
    if net_bank < -0.01:
        raise ValueError('Deductions exceed gross invoice amount')
    lines = [{
        'coa_id': expense_coa['id'], 'debit_amount': debit_expense, 'credit_amount': 0,
        'description': f"Expense: {txn.get('description','')}", 'project_id': txn.get('project_id')
    }]
    if debit_vat > 0:
        vat_rec = _get_coa(conn, ['1012'])
        if vat_rec:
            lines.append({'coa_id':vat_rec['id'],'debit_amount':debit_vat,'credit_amount':0,
                          'description':'Input VAT receivable / VAT component','project_id':txn.get('project_id')})
    for amount, codes, label in [
        (wht, ['2030'], f"WHT Payable ({txn.get('wht_type','')})"),
        (whvat, ['2031','2034'], 'WHVAT Payable'),
        (ucf, ['2033','2035'], 'UCC Common Fund Payable')
    ]:
        if amount > 0:
            coa = _get_coa(conn, codes)
            if coa:
                lines.append({'coa_id':coa['id'],'debit_amount':0,'credit_amount':amount,
                              'description':label,'project_id':txn.get('project_id')})
    lines.append({'coa_id': bank_coa['id'], 'debit_amount':0, 'credit_amount':net_bank,
                  'description': f"{txn.get('payment_method','Bank Transfer')} payment to {txn.get('payee','')}",
                  'project_id': txn.get('project_id'), 'bank_account_id': txn.get('bank_account_id')})
    return lines


def api_save_actual(data, session):
    conn = get_db()
    try:
        is_update = bool(data.get('id'))
        existing = conn.execute("SELECT * FROM actuals WHERE id=?", (data.get('id'),)).fetchone() if is_update else None
        if existing and existing['is_posted'] and session.get('role') != 'Admin':
            return err('Posted transactions are locked. Only Admin can amend them through audit-controlled correction.')
        if existing and existing['is_posted'] and not data.get('edit_reason'):
            return err('Admin edit reason is required for posted transaction amendment')
        okp, period_or_msg = _assert_period_open(conn, data.get('expense_date'))
        if not okp:
            return err(period_or_msg)

        aid = data.get('id') or str(uuid.uuid4())
        acode = data.get('actual_code') or (existing['actual_code'] if existing else f"ACT-{str(uuid.uuid4())[:6].upper()}")
        pay_fx = float(data.get('pay_fx_rate', 1) or 1)
        commit_fx = float(data.get('commit_fx_rate', pay_fx) or pay_fx)
        amount_fcy = float(data['amount_fcy'])
        amount_ghs = amount_fcy * pay_fx
        currency = data.get('currency', 'GHS')
        fx_gl = 0; fx_type = 'None'
        if currency != 'GHS':
            fx_gl = abs(amount_fcy * pay_fx - amount_fcy * commit_fx)
            fx_type = 'Loss' if pay_fx > commit_fx else ('Gain' if pay_fx < commit_fx else 'None')
        has_vat = int(data.get('has_vat', 0) or 0)
        has_whvat = int(data.get('has_whvat', 0) or 0)
        ex_vat = round(amount_ghs / 1.2, 4) if has_whvat else amount_ghs
        vat_amount = round(amount_ghs - ex_vat, 2) if has_whvat else (round(amount_ghs * 0.20, 2) if has_vat else 0)
        whvat_amount = round(ex_vat * 0.07, 2) if has_whvat else 0
        wht_type = data.get('wht_type', 'None')
        wht_rate_map = {'None':0,'WHT-Goods':0.03,'WHT-Service':0.075,'WHT-Income':0.10,
                        'WHT-Sitting':0.20,'WHT-Works':0.05}
        wht_rate = wht_rate_map.get(wht_type, 0)
        wht_amount = round(ex_vat * wht_rate, 2)
        has_ucf = int(data.get('has_ucf', 0) or 0)
        ucf_base = ex_vat - wht_amount - whvat_amount
        ucf_amount = round(max(0, ucf_base) * 0.05, 2) if has_ucf else 0
        payment_method = data.get('payment_method') or ('Cheque' if data.get('cheque_no') else 'Bank Transfer')
        payment_reference = data.get('payment_reference') or data.get('cheque_no') or data.get('transfer_ref') or data.get('receipt_no','')
        if existing and existing['is_posted'] and existing['jv_id']:
            try:
                __wp_paid = float((conn.execute("SELECT COALESCE(SUM(amount_ghs),0) FROM withholding_payables WHERE actual_id=? AND status='Paid'", (existing['id'],)).fetchone() or [0])[0] or 0)
            except Exception:
                __wp_paid = 0
            if __wp_paid > 0.005:
                try: conn.rollback()
                except Exception: pass
                return err('Cannot amend this posted voucher \u2014 GHS %.2f of withholding tax on it has already been remitted to the authority. Reverse that remittance under Withholding Payables first (or post a separate adjustment journal), then amend.' % __wp_paid)
            _reverse_voucher(conn, session, existing['jv_id'], data.get('edit_reason','Admin correction'))
        params = (aid,acode,data['project_id'],data.get('budget_id'),data.get('commitment_id'),
            data['expense_date'],data['payee'],data['description'],currency,amount_fcy,
            commit_fx,pay_fx,amount_ghs,fx_gl,fx_type,has_vat,vat_amount,has_whvat,whvat_amount,
            has_ucf,ucf_amount,wht_type,wht_rate,wht_amount,payment_reference,
            data.get('bank_account_id') or None,payment_method,payment_reference,data.get('edit_reason',''),session['username'])
        if existing:
            conn.execute("""UPDATE actuals SET project_id=?,budget_id=?,commitment_id=?,expense_date=?,payee=?,
                description=?,currency=?,amount_fcy=?,commit_fx_rate=?,pay_fx_rate=?,amount_ghs=?,fx_gl_ghs=?,fx_gl_type=?,
                has_vat=?,vat_amount=?,has_whvat=?,whvat_amount=?,has_ucf=?,ucf_amount=?,wht_type=?,wht_rate=?,wht_amount=?,
                receipt_no=?,bank_account_id=?,payment_method=?,payment_reference=?,edit_reason=?,last_amended_by=?,last_amended_at=datetime('now')
                WHERE id=?""", params[2:] + (aid,))
        else:
            conn.execute("""INSERT INTO actuals(id,actual_code,project_id,budget_id,commitment_id,
                expense_date,payee,description,currency,amount_fcy,commit_fx_rate,pay_fx_rate,amount_ghs,
                fx_gl_ghs,fx_gl_type,has_vat,vat_amount,has_whvat,whvat_amount,has_ucf,ucf_amount,
                wht_type,wht_rate,wht_amount,receipt_no,bank_account_id,payment_method,payment_reference,edit_reason,created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""", params)
        if data.get('commitment_id'):
            _settle_commitment(conn, data['commitment_id'])
        # If an admin amended a posted transaction, immediately post a corrected PV.
        if existing and existing['is_posted']:
            txn = dict(conn.execute("SELECT * FROM actuals WHERE id=?", (aid,)).fetchone())
            lines = _expense_lines_for_actual(conn, txn)
            jv_id, jv_num = _insert_voucher_posted(conn, session, jv_type='PV', jv_date=txn['expense_date'],
                description=f"Corrected payment: {txn['payee']} — {txn['description']} [voucher {txn['actual_code']} — replaces reversed entry]", project_id=txn['project_id'],
                bank_account_id=txn.get('bank_account_id'), source_module='actuals', source_id=aid,
                reference=txn.get('payment_reference') or txn.get('receipt_no') or '', lines=lines,
                notes='Admin correction reposted after reversal')
            conn.execute("UPDATE actuals SET is_posted=1, posted_by=?, posted_at=datetime('now'), jv_id=? WHERE id=?",
                         (session['username'], jv_id, aid))
            _audit(conn, session, 'AMEND_POSTED_ACTUAL', 'actuals', aid,
                   f"{acode} corrected. New voucher {jv_num}. Reason: {data.get('edit_reason','')}")
        else:
            _audit(conn, session, 'SAVE_ACTUAL', 'actuals', aid, f"{data.get('payee','')} {amount_ghs:.2f} GHS")
        conn.commit()
        return {'ok': True, 'id': aid}
    except Exception as e:
        conn.rollback(); return err(str(e))
    finally:
        conn.close()


def api_post_actual(data, session):
    if not session:
        return err('Not logged in', 401)
    actual_id = data.get('id')
    if not actual_id:
        return err('No record ID provided')
    conn = get_db()
    try:
        row = conn.execute("SELECT * FROM actuals WHERE id=?", (actual_id,)).fetchone()
        if not row:
            return err('Transaction not found')
        if row['is_posted']:
            return err('Transaction is already posted')
        okp, period_or_msg = _assert_period_open(conn, row['expense_date'])
        if not okp:
            return err(period_or_msg)
        txn = dict(row)
        lines = _expense_lines_for_actual(conn, txn)
        jv_id, jv_num = _insert_voucher_posted(conn, session, jv_type='PV', jv_date=txn['expense_date'],
            description=f"Payment: {txn['payee']} — {txn['description']}", project_id=txn['project_id'],
            bank_account_id=txn.get('bank_account_id'), source_module='actuals', source_id=actual_id,
            reference=txn.get('payment_reference') or txn.get('receipt_no') or '', lines=lines,
            unit_id=(txn.get('unit_id') if hasattr(txn, 'get') else None),
            notes='Auto-posted from Actual Expense module')
        conn.execute("UPDATE actuals SET is_posted=1, posted_by=?, posted_at=datetime('now'), jv_id=? WHERE id=?",
                     (session['username'], jv_id, actual_id))
        _audit(conn, session, 'POST_ACTUAL_DOUBLE_ENTRY', 'actuals', actual_id, f"{txn['actual_code']} posted as {jv_num}")
        conn.commit()
        return ok({'message': f"{txn['actual_code']} posted as {jv_num}", 'jv_id': jv_id, 'jv_number': jv_num})
    except Exception as e:
        conn.rollback(); return err(str(e))
    finally:
        conn.close()


def api_save_fund_receipt(data, session):
    conn = get_db()
    try:
        is_update = bool(data.get('id'))
        existing = conn.execute("SELECT * FROM fund_receipts WHERE id=?", (data.get('id'),)).fetchone() if is_update else None
        if existing and existing['is_posted'] and session.get('role') != 'Admin':
            return err('Posted receipts are locked. Only Admin can amend them through audit-controlled correction.')
        if existing and existing['is_posted'] and not data.get('edit_reason'):
            return err('Admin edit reason is required for posted receipt amendment')
        okp, period_or_msg = _assert_period_open(conn, data.get('receipt_date'))
        if not okp:
            return err(period_or_msg)
        rid = data.get('id') or str(uuid.uuid4())
        rcode = data.get('receipt_code') or (existing['receipt_code'] if existing else f"RCP-{datetime.now().strftime('%Y')}-{str(uuid.uuid4())[:6].upper()}")
        amount_ghs = float(data['amount_fcy']) * float(data.get('fx_rate',1) or 1)
        donor_source = data.get('donor') or data.get('source') or data.get('payer') or 'Unspecified source'
        receipt_no = data.get('receipt_no') or data.get('reference_no') or ''
        transfer_ref = data.get('transfer_ref') or data.get('reference_no') or ''
        if existing and existing['is_posted'] and existing['jv_id']:
            try:
                __wp_paid = float((conn.execute("SELECT COALESCE(SUM(amount_ghs),0) FROM withholding_payables WHERE actual_id=? AND status='Paid'", (existing['id'],)).fetchone() or [0])[0] or 0)
            except Exception:
                __wp_paid = 0
            if __wp_paid > 0.005:
                try: conn.rollback()
                except Exception: pass
                return err('Cannot amend this posted voucher \u2014 GHS %.2f of withholding tax on it has already been remitted to the authority. Reverse that remittance under Withholding Payables first (or post a separate adjustment journal), then amend.' % __wp_paid)
            _reverse_voucher(conn, session, existing['jv_id'], data.get('edit_reason','Admin correction'))
        if existing:
            conn.execute("""UPDATE fund_receipts SET project_id=?,bank_account_id=?,budget_id=?,receipt_date=?,
                donor=?,description=?,currency=?,amount_fcy=?,fx_rate=?,amount_ghs=?,reference_no=?,receipt_no=?,transfer_ref=?,
                receipt_type=?,notes=?,last_amended_by=?,last_amended_at=datetime('now') WHERE id=?""",
                (data['project_id'],data.get('bank_account_id'),data.get('budget_id'),data['receipt_date'],
                 donor_source,data['description'],data['currency'],float(data['amount_fcy']),
                 float(data.get('fx_rate',1)),amount_ghs,data.get('reference_no',''),receipt_no,transfer_ref,
                 data.get('receipt_type','Grant Receipt'),data.get('notes',''),session['username'],rid))
        else:
            conn.execute("""INSERT INTO fund_receipts(id,receipt_code,project_id,bank_account_id,budget_id,
                receipt_date,donor,description,currency,amount_fcy,fx_rate,amount_ghs,
                reference_no,receipt_no,transfer_ref,receipt_type,notes,created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (rid,rcode,data['project_id'],data.get('bank_account_id'),data.get('budget_id'),data['receipt_date'],
                 donor_source,data['description'],data['currency'],float(data['amount_fcy']),
                 float(data.get('fx_rate',1)),amount_ghs,data.get('reference_no',''),receipt_no,transfer_ref,
                 data.get('receipt_type','Grant Receipt'),data.get('notes',''),session['username']))
        # Auto-post RV to ensure receipts are reflected in IPSAS statements.
        bank_coa = _bank_coa_for(conn, data.get('bank_account_id'), data.get('currency','GHS'))
        income_codes = ['4000'] if str(data.get('receipt_type','')).lower().startswith(('ucc','subvention')) else ['4020','4000']
        income_coa = _get_coa(conn, income_codes)
        if not bank_coa or not income_coa:
            raise ValueError('Could not determine bank or income account for receipt posting')
        lines = [
            {'coa_id':bank_coa['id'],'debit_amount':amount_ghs,'credit_amount':0,
             'description':f"Bank receipt from {donor_source}",'project_id':data['project_id'],
             'bank_account_id':data.get('bank_account_id')},
            {'coa_id':income_coa['id'],'debit_amount':0,'credit_amount':amount_ghs,
             'description':f"Fund income: {data.get('description','')}",'project_id':data['project_id']}
        ]
        jv_id, jv_num = _insert_voucher_posted(conn, session, jv_type='RV', jv_date=data['receipt_date'],
            description=f"Receipt: {donor_source} — {data.get('description','')}",
            project_id=data['project_id'], bank_account_id=data.get('bank_account_id'), source_module='receipts',
            source_id=rid, reference=transfer_ref or receipt_no or data.get('reference_no',''), lines=lines,
            unit_id=(data.get('unit_id') if hasattr(data, 'get') else None),
            notes='Auto-posted from Fund Receipts module')
        conn.execute("UPDATE fund_receipts SET is_posted=1, posted_by=?, posted_at=datetime('now'), jv_id=? WHERE id=?",
                     (session['username'], jv_id, rid))
        _audit(conn, session, 'SAVE_FUND_RECEIPT_DOUBLE_ENTRY', 'fund_receipts', rid,
               f"{donor_source} {amount_ghs:.2f} GHS posted as {jv_num}")
        conn.commit()
        return {'ok': True, 'id': rid, 'jv_number': jv_num}
    except Exception as e:
        conn.rollback(); return err(str(e))
    finally:
        conn.close()


def api_get_bank_accounts(session):
    conn = get_db()
    rows = [dict(r) for r in conn.execute("""
        SELECT b.*, c.code as coa_code, c.account_name as coa_account_name,
            COALESCE((SELECT SUM(gl.debit_amount - gl.credit_amount) FROM general_ledger gl WHERE gl.coa_id=b.coa_id),0) as ledger_balance,
            p.project_code, p.title as project_title
        FROM bank_accounts b
        LEFT JOIN chart_of_accounts c ON b.coa_id=c.id
        LEFT JOIN projects p ON b.project_id=p.id
        WHERE b.is_active=1
        ORDER BY b.bank_name, b.account_name
    """)]
    conn.close()
    return rows


def api_get_ledger_accounts_summary(session, period=None):
    conn = get_db()
    q = """SELECT gl.coa_id, gl.coa_code, gl.account_name, c.category, c.account_type,
        COALESCE(SUM(gl.debit_amount),0) as total_debit,
        COALESCE(SUM(gl.credit_amount),0) as total_credit,
        COUNT(*) as entry_count
        FROM general_ledger gl
        JOIN chart_of_accounts c ON gl.coa_id=c.id"""
    args=[]
    if period:
        q += " WHERE gl.period=?"; args.append(period)
    q += " GROUP BY gl.coa_id, gl.coa_code, gl.account_name, c.category, c.account_type ORDER BY gl.coa_code"
    rows=[]
    for r in conn.execute(q,args).fetchall():
        d=dict(r)
        acct_type=(d.get('account_type') or '').lower()
        natural = d['total_debit'] - d['total_credit'] if acct_type in ('asset','expense','capital','overhead','contra') else d['total_credit'] - d['total_debit']
        d['balance']=round(natural,2)
        d['debit_balance']=round(max(natural,0),2) if acct_type in ('asset','expense','capital','overhead','contra') else round(max(-natural,0),2)
        d['credit_balance']=round(max(-natural,0),2) if acct_type in ('asset','expense','capital','overhead','contra') else round(max(natural,0),2)
        rows.append(d)
    conn.close(); return rows


def api_manage_period(data, session):
    if session.get('role') != 'Admin':
        return {'ok': False, 'error': 'Only Admins can manage accounting periods'}
    conn = get_db()
    try:
        action = data.get('action') or 'open'
        period = data.get('period') or data.get('period_code')
        if not period:
            return {'ok': False, 'error': 'Period code is required'}
        name = data.get('period_name') or period
        start_date = data.get('start_date')
        end_date = data.get('end_date')
        if not start_date or not end_date:
            start_date, end_date = _month_bounds(period)
        if action in ('create','open'):
            row = conn.execute("SELECT id FROM accounting_periods WHERE period=?", (period,)).fetchone()
            if row:
                conn.execute("""UPDATE accounting_periods SET period_name=?,start_date=?,end_date=?,status='Open',opened_by=?,closed_by=NULL,closed_at=NULL WHERE period=?""",
                             (name,start_date,end_date,session['username'],period))
            else:
                conn.execute("""INSERT INTO accounting_periods(id,period,period_name,status,opened_by,start_date,end_date)
                    VALUES(?,?,?,?,?,?,?)""", (str(uuid.uuid4()),period,name,'Open',session['username'],start_date,end_date))
            new_status='Open'
        else:
            status_map={'close':'Closed','lock':'Locked'}
            new_status=status_map.get(action)
            if not new_status:
                return {'ok': False, 'error': 'Invalid action'}
            extra = ', closed_by=?, closed_at=datetime(\'now\')' if action in ('close','lock') else ''
            vals = [new_status]
            if extra:
                vals.append(session['username'])
            vals.append(period)
            conn.execute(f"UPDATE accounting_periods SET status=?{extra} WHERE period=?", vals)
        _audit(conn, session, f'PERIOD_{action.upper()}', 'accounting_periods', period,
               f'Period {period} → {new_status} ({start_date} to {end_date})')
        conn.commit(); return {'ok': True}
    except Exception as e:
        conn.rollback(); return {'ok': False, 'error': str(e)}
    finally:
        conn.close()



# ---------------------------------------------------------------------------
# UCC-FMS v3.1 LEDGER GOVERNANCE PATCH
# Prevent destructive edits of posted records and ensure reversals affect GL.
# ---------------------------------------------------------------------------

_original_api_delete_actual_worldclass = api_delete_actual

def api_delete_actual(actual_id, session):
    """Delete only draft/unposted expenses. Posted expenses must be amended/reversed for audit integrity."""
    if session.get('role') != 'Admin':
        return {'ok': False, 'error': 'Admin access required to delete transactions'}
    if not actual_id:
        return {'ok': False, 'error': 'No record ID provided'}
    conn = get_db()
    try:
        row = conn.execute("SELECT actual_code, payee, amount_ghs, is_posted, jv_id FROM actuals WHERE id=?", (actual_id,)).fetchone()
        if not row:
            return {'ok': False, 'error': 'Transaction not found'}
        if row['is_posted']:
            return {'ok': False, 'error': 'Posted transactions cannot be deleted. Use Admin amendment or reversing JV so the audit trail and reports remain intact.'}
        desc = f"{row['actual_code']} | {row['payee']} | GHS {float(row['amount_ghs'] or 0):,.2f}"
        conn.execute("DELETE FROM actuals WHERE id=?", (actual_id,))
        _audit(conn, session, 'DELETE_DRAFT_ACTUAL', 'actuals', actual_id, desc)
        conn.commit(); return {'ok': True}
    except Exception as e:
        conn.rollback(); return {'ok': False, 'error': str(e)}
    finally:
        conn.close()

_original_api_jv_workflow_worldclass = api_jv_workflow

def api_jv_workflow(data, session):
    """World-class JV workflow guardrails.

    - Posted JVs cannot be voided because their GL lines would remain in statutory reports.
    - Admin reversal of a Posted JV creates and posts the reversing voucher immediately.
    """
    action = data.get('action')
    jv_id = data.get('jv_id')
    if action not in ('void', 'reverse'):
        return _original_api_jv_workflow_worldclass(data, session)

    conn = get_db()
    try:
        jv = conn.execute("SELECT * FROM journal_vouchers WHERE id=?", (jv_id,)).fetchone()
        if not jv:
            return {'ok': False, 'error': 'JV not found'}
        jv = dict(jv)
        if action == 'void':
            if jv.get('status') == 'Posted':
                return {'ok': False, 'error': 'Posted vouchers cannot be voided. Use Reverse so the General Ledger remains balanced and auditable.'}
            conn.close()
            return _original_api_jv_workflow_worldclass(data, session)

        # action == reverse
        if not _jv_can_post(session):
            return {'ok': False, 'error': 'Only Admins can create and post reversing JVs'}
        if jv.get('status') not in ('Posted','Reversed'):
            return {'ok': False, 'error': 'Only Posted JVs can be reversed'}
        if jv.get('status') == 'Reversed' or jv.get('reversed_by'):
            return {'ok': False, 'error': 'This JV has already been reversed'}
        reason = (data.get('reason') or data.get('notes') or '').strip()
        if not reason:
            return {'ok': False, 'error': 'A reversal reason is required'}
        rev_date = data.get('reversal_date') or datetime.now().strftime('%Y-%m-%d')
        _assert_period_open(conn, rev_date)
        rev_period = rev_date[:7]
        orig_lines = conn.execute("""SELECT l.*, c.code as coa_code, c.account_name, p.project_code
            FROM jv_lines l JOIN chart_of_accounts c ON l.coa_id=c.id
            LEFT JOIN projects p ON l.project_id=p.id
            WHERE l.jv_id=? ORDER BY l.line_number""", (jv_id,)).fetchall()
        if not orig_lines:
            return {'ok': False, 'error': 'JV has no lines to reverse'}
        # Dual control: a reversal at/above the threshold cannot be created-and-posted by a
        # single admin. We stage it as an Approved (un-posted) RJV; a SECOND admin must post it
        # (the base 'post' branch enforces poster != creator). Below threshold / disabled -> the
        # original instant create-and-post behaviour is preserved.
        _dc = conn.execute("SELECT value FROM settings WHERE key='dual_control_threshold_ghs'").fetchone()
        _dcthr = float((_dc['value'] if _dc else 0) or 0)
        _amt = max(float(jv.get('total_debit') or 0), float(jv.get('total_credit') or 0))
        _hv = (_dcthr > 0 and _amt >= _dcthr)
        rev_id = str(uuid.uuid4())
        rev_num = _next_jv_number(conn, 'RJV')
        _rstatus = 'Approved' if _hv else 'Posted'
        _posted_by = None if _hv else session['username']
        _posted_at = None if _hv else datetime.now().isoformat()
        conn.execute("""INSERT INTO journal_vouchers
            (id,jv_number,jv_type,jv_date,period,description,narration,project_id,
             currency,fx_rate,total_debit,total_credit,status,is_reversal,reversal_of,
             prepared_by,approved_by,approved_at,posted_by,posted_at,source_module,notes)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (rev_id, rev_num, 'RJV', rev_date, rev_period,
             f'REVERSAL of {jv["jv_number"]}: {jv["description"]}',
             (f'Reversal of {jv["jv_number"]} pending second-admin posting. Reason: {reason}' if _hv
              else f'Auto-posted reversal of {jv["jv_number"]}. Reason: {reason}'),
             jv.get('project_id'), jv.get('currency','GHS'), jv.get('fx_rate',1),
             float(jv.get('total_credit') or 0), float(jv.get('total_debit') or 0),
             _rstatus, 1, jv_id, session['username'], session['username'], datetime.now().isoformat(),
             _posted_by, _posted_at, 'reversal', reason))
        for line in orig_lines:
            line_id = str(uuid.uuid4())
            debit = float(line['credit_amount'] or 0)
            credit = float(line['debit_amount'] or 0)
            desc = f'Reversal: {line["description"]}'
            conn.execute("""INSERT INTO jv_lines
                (id,jv_id,line_number,coa_id,description,debit_amount,credit_amount,
                 project_id,cost_centre,bank_account_id,tax_code)
                VALUES(?,?,?,?,?,?,?,?,?,?,?)""",
                (line_id, rev_id, line['line_number'], line['coa_id'], desc,
                 debit, credit, line['project_id'], line['cost_centre'], line['bank_account_id'], line['tax_code']))
            if not _hv:
                conn.execute("""INSERT INTO general_ledger
                    (id,jv_id,jv_number,jv_line_id,ledger_date,period,coa_id,coa_code,
                     account_name,description,debit_amount,credit_amount,project_id,project_code,posted_by)
                    VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                    (str(uuid.uuid4()), rev_id, rev_num, line_id, rev_date, rev_period,
                     line['coa_id'], line['coa_code'], line['account_name'], desc,
                     debit, credit, line['project_id'], line['project_code'] or '', session['username']))
        if _hv:
            # Block a duplicate reversal, but leave the original Posted (and its GL intact) until
            # the second admin actually posts this RJV — that posting flips it to Reversed.
            conn.execute("UPDATE journal_vouchers SET reversed_by=? WHERE id=?", (rev_id, jv_id))
            _jv_audit(conn, session, jv_id, jv['jv_number'], 'REVERSAL_PENDING', 'Posted', 'Posted', f'Reversal {rev_num} awaiting second-admin posting: {reason}')
            _jv_audit(conn, session, rev_id, rev_num, 'CREATE_REVERSAL_PENDING', None, 'Approved', f'Reversal of {jv["jv_number"]}: {reason}')
            _audit(conn, session, 'REVERSAL_PENDING_DUAL_CONTROL', 'journal_vouchers', rev_id, f'{rev_num} reverses {jv["jv_number"]}: {reason}')
            conn.commit()
            return {'ok': True, 'message': f'Reversing JV {rev_num} created and approved. Dual control: a SECOND admin must post it from the JV register before it hits the ledger.', 'reversal_id': rev_id, 'jv_number': rev_num, 'pending_second_post': True}
        conn.execute("UPDATE journal_vouchers SET status='Reversed', reversed_by=? WHERE id=?", (rev_id, jv_id))
        _jv_audit(conn, session, jv_id, jv['jv_number'], 'REVERSED_AND_POSTED', 'Posted', 'Reversed', f'Reversed by {rev_num}: {reason}')
        _jv_audit(conn, session, rev_id, rev_num, 'CREATE_POSTED_REVERSAL', None, 'Posted', f'Reversal of {jv["jv_number"]}: {reason}')
        _audit(conn, session, 'POSTED_REVERSAL_JV', 'journal_vouchers', rev_id, f'{rev_num} reverses {jv["jv_number"]}: {reason}')
        conn.commit()
        return {'ok': True, 'message': f'Reversing JV {rev_num} created and posted', 'reversal_id': rev_id, 'jv_number': rev_num}
    except Exception as e:
        conn.rollback(); return {'ok': False, 'error': str(e)}
    finally:
        try: conn.close()
        except Exception: pass


# ---------------------------------------------------------------------------
# UCC-FMS v3.1 POSTED-ONLY BUDGET AND MANAGEMENT SUMMARIES
# Operational dashboards may show draft records in the transaction register, but
# financial utilisation/reporting must use posted GL-backed expenditure only.
# ---------------------------------------------------------------------------

def api_get_projects(session, params=None):
    conn = get_db()
    rows = [dict(r) for r in conn.execute("""
        SELECT p.*,
            COALESCE(SUM(CASE WHEN c.status='Open' THEN c.amount_ghs ELSE 0 END),0) as committed_ghs,
            COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.project_id=p.id AND COALESCE(a.is_posted,0)=1),0) as actual_ghs,
            COALESCE((SELECT SUM(budget_ghs) FROM budgets b WHERE b.project_id=p.id),0) as budgeted_ghs,
            COALESCE((SELECT SUM(fr.amount_ghs) FROM fund_receipts fr WHERE fr.project_id=p.id AND COALESCE(fr.is_posted,0)=1),0) as receipts_ghs
        FROM projects p
        LEFT JOIN commitments c ON c.project_id=p.id
        GROUP BY p.id ORDER BY p.created_at DESC
    """)]
    conn.close()
    return rows


def api_get_budgets(session, project_id=None):
    conn = get_db()
    q = """SELECT b.*, p.project_code, p.title as project_title, p.currency as proj_currency,
        c.code as coa_code, c.account_name, c.category,
        COALESCE((SELECT SUM(MAX(0, cm.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=cm.id AND COALESCE(_ax.is_posted,0)=1),0))) FROM commitments cm WHERE cm.budget_id=b.id AND COALESCE(cm.status,'') NOT IN ('Cancelled','Fully Paid')),0) as committed_ghs,
        COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id AND COALESCE(a.is_posted,0)=1),0) as actual_ghs,
        COALESCE((SELECT SUM(fr.amount_ghs) FROM fund_receipts fr WHERE fr.budget_id=b.id AND COALESCE(fr.is_posted,0)=1),0) as receipts_ghs
        FROM budgets b
        JOIN projects p ON b.project_id=p.id
        JOIN chart_of_accounts c ON b.coa_id=c.id"""
    args = []
    if project_id:
        q += " WHERE b.project_id=?"
        args.append(project_id)
    q += " ORDER BY b.created_at"
    rows = [dict(r) for r in conn.execute(q, args)]
    conn.close()
    return rows


def api_get_departments(session):
    conn = get_db()
    rows = conn.execute("""
        SELECT d.*,
          COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a
            INNER JOIN projects p ON a.project_id=p.id WHERE p.division=d.dept_code AND COALESCE(a.is_posted,0)=1),0) as spent,
          COALESCE((SELECT SUM(cm.amount_ghs) FROM commitments cm
            INNER JOIN projects p2 ON cm.project_id=p2.id WHERE p2.division=d.dept_code AND cm.status='Open'),0) as committed,
          COALESCE((SELECT COUNT(*) FROM projects p WHERE p.division=d.dept_code AND p.status='Active'),0) as active_grants,
          COALESCE((SELECT SUM(p.budget_ghs) FROM projects p WHERE p.division=d.dept_code),0) as grant_budget,
          COALESCE((SELECT SUM(fr.amount_ghs) FROM fund_receipts fr
            INNER JOIN projects p3 ON fr.project_id=p3.id WHERE p3.division=d.dept_code AND COALESCE(fr.is_posted,0)=1),0) as receipts
        FROM departments d WHERE d.status='Active' ORDER BY d.dept_code
    """).fetchall()
    conn.close()
    return [dict(r) for r in rows]


def api_get_report(session, report_type, project_id=None):
    conn = get_db()
    try:
        if report_type == 'project' and project_id:
            proj_row = conn.execute("SELECT * FROM projects WHERE id=?", (project_id,)).fetchone()
            if not proj_row:
                return {'error': 'Project not found'}
            proj = dict(proj_row)
            budgets = [dict(r) for r in conn.execute("""
                SELECT b.*, c.account_name, c.code as coa_code, c.category,
                    COALESCE((SELECT SUM(MAX(0, cm.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=cm.id AND COALESCE(_ax.is_posted,0)=1),0))) FROM commitments cm WHERE cm.budget_id=b.id AND COALESCE(cm.status,'') NOT IN ('Cancelled','Fully Paid')),0) as committed_ghs,
                    COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id AND COALESCE(a.is_posted,0)=1),0) as actual_ghs,
                    COALESCE((SELECT SUM(fr.amount_ghs) FROM fund_receipts fr WHERE fr.budget_id=b.id AND COALESCE(fr.is_posted,0)=1),0) as receipts_ghs
                FROM budgets b
                JOIN chart_of_accounts c ON b.coa_id=c.id
                WHERE b.project_id=? GROUP BY b.id""", (project_id,))]
            actuals = [dict(r) for r in conn.execute(
                "SELECT * FROM actuals WHERE project_id=? ORDER BY expense_date", (project_id,))]
            commitments = [dict(r) for r in conn.execute(
                "SELECT * FROM commitments WHERE project_id=? ORDER BY commit_date", (project_id,))]
            fx_gain = conn.execute("SELECT COALESCE(SUM(fx_gl_ghs),0) FROM actuals WHERE project_id=? AND COALESCE(is_posted,0)=1 AND fx_gl_type='Gain'",(project_id,)).fetchone()[0]
            fx_loss = conn.execute("SELECT COALESCE(SUM(fx_gl_ghs),0) FROM actuals WHERE project_id=? AND COALESCE(is_posted,0)=1 AND fx_gl_type='Loss'",(project_id,)).fetchone()[0]
            return {'project': proj, 'budgets': budgets, 'actuals': actuals,
                    'commitments': commitments, 'fx_gain': fx_gain, 'fx_loss': fx_loss}
        if report_type == 'centre':
            projects = api_get_projects(session)
            divisions = [dict(r) for r in conn.execute("""
                SELECT division, COUNT(*) as proj_count,
                    COALESCE(SUM(budget_ghs),0) as total_budget,
                    COALESCE(SUM(CASE WHEN status='Active' THEN budget_ghs ELSE 0 END),0) as active_budget
                FROM projects GROUP BY division""")]
            fx_summary = conn.execute("""SELECT
                COALESCE(SUM(CASE WHEN fx_gl_type='Gain' THEN fx_gl_ghs ELSE 0 END),0) as total_gain,
                COALESCE(SUM(CASE WHEN fx_gl_type='Loss' THEN fx_gl_ghs ELSE 0 END),0) as total_loss
                FROM actuals WHERE COALESCE(is_posted,0)=1""").fetchone()
            return {'projects': projects, 'divisions': divisions,
                    'fx_gain': fx_summary[0], 'fx_loss': fx_summary[1]}
        return {'error': 'Unknown report'}
    finally:
        conn.close()



# ---------------------------------------------------------------------------
# UCC-FMS v3.2 FINAL: Financial integrity cockpit
# Verifies that the ERP is reporting from posted double-entry records only.
# ---------------------------------------------------------------------------
def _safe_scalar(conn, sql, args=(), default=0):
    try:
        row = conn.execute(sql, args).fetchone()
        if row is None:
            return default
        return row[0] if not isinstance(row, dict) else list(row)[0]
    except Exception:
        return default


def api_financial_integrity(session):
    """Real-time finance-control health check for Admin/Finance dashboards."""
    conn = get_db()
    try:
        debit = float(_safe_scalar(conn, "SELECT COALESCE(SUM(debit_amount),0) FROM general_ledger", default=0) or 0)
        credit = float(_safe_scalar(conn, "SELECT COALESCE(SUM(credit_amount),0) FROM general_ledger", default=0) or 0)
        ledger_diff = round(abs(debit - credit), 2)

        posted_jvs = int(_safe_scalar(conn, "SELECT COUNT(*) FROM journal_vouchers WHERE status='Posted'", default=0) or 0)
        unposted_jvs = int(_safe_scalar(conn, "SELECT COUNT(*) FROM journal_vouchers WHERE status IN ('Draft','Submitted','Approved')", default=0) or 0)
        reversed_jvs = int(_safe_scalar(conn, "SELECT COUNT(*) FROM journal_vouchers WHERE status='Reversed'", default=0) or 0)
        unbalanced_posted_jvs = int(_safe_scalar(conn, """
            SELECT COUNT(*) FROM journal_vouchers
            WHERE status='Posted' AND ABS(COALESCE(total_debit,0)-COALESCE(total_credit,0)) > 0.01
        """, default=0) or 0)
        posted_jv_without_gl = int(_safe_scalar(conn, """
            SELECT COUNT(*) FROM journal_vouchers j
            WHERE j.status='Posted' AND NOT EXISTS (SELECT 1 FROM general_ledger gl WHERE gl.jv_id=j.id)
        """, default=0) or 0)
        orphan_gl = int(_safe_scalar(conn, """
            SELECT COUNT(*) FROM general_ledger gl
            WHERE NOT EXISTS (SELECT 1 FROM journal_vouchers j WHERE j.id=gl.jv_id)
        """, default=0) or 0)

        unposted_expenses = int(_safe_scalar(conn, "SELECT COUNT(*) FROM actuals WHERE COALESCE(is_posted,0)=0", default=0) or 0)
        unposted_expense_value = float(_safe_scalar(conn, "SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE COALESCE(is_posted,0)=0", default=0) or 0)
        posted_expenses_without_jv = int(_safe_scalar(conn, """
            SELECT COUNT(*) FROM actuals WHERE COALESCE(is_posted,0)=1 AND (jv_id IS NULL OR jv_id='')
        """, default=0) or 0)

        unposted_receipts = int(_safe_scalar(conn, "SELECT COUNT(*) FROM fund_receipts WHERE COALESCE(is_posted,0)=0", default=0) or 0)
        unposted_receipt_value = float(_safe_scalar(conn, "SELECT COALESCE(SUM(amount_ghs),0) FROM fund_receipts WHERE COALESCE(is_posted,0)=0", default=0) or 0)
        posted_receipts_without_jv = int(_safe_scalar(conn, """
            SELECT COUNT(*) FROM fund_receipts WHERE COALESCE(is_posted,0)=1 AND (jv_id IS NULL OR jv_id='')
        """, default=0) or 0)

        overrun_lines = int(_safe_scalar(conn, """
            SELECT COUNT(*) FROM budgets b
            WHERE COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id AND COALESCE(a.is_posted,0)=1),0)
                + COALESCE((SELECT SUM(MAX(0, c.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=c.id AND COALESCE(_ax.is_posted,0)=1),0))) FROM commitments c WHERE c.budget_id=b.id AND COALESCE(c.status,'') NOT IN ('Cancelled','Fully Paid')),0)
                > COALESCE(b.budget_ghs,0)
        """, default=0) or 0)

        open_periods = int(_safe_scalar(conn, "SELECT COUNT(*) FROM accounting_periods WHERE status='Open'", default=0) or 0)
        closed_periods = int(_safe_scalar(conn, "SELECT COUNT(*) FROM accounting_periods WHERE status='Closed'", default=0) or 0)
        locked_periods = int(_safe_scalar(conn, "SELECT COUNT(*) FROM accounting_periods WHERE status='Locked'", default=0) or 0)
        audit_entries = int(_safe_scalar(conn, "SELECT COUNT(*) FROM audit_log", default=0) or 0)

        checks = []
        def add(key, label, ok_condition, warn_condition=False, detail=''):
            status = 'pass' if ok_condition else ('warn' if warn_condition else 'fail')
            checks.append({'key': key, 'label': label, 'status': status, 'detail': detail})

        add('ledger_balance', 'General Ledger debits equal credits', ledger_diff < 0.01,
            detail=f'Debits {debit:,.2f}; Credits {credit:,.2f}; Difference {ledger_diff:,.2f}')
        add('posted_jv_balance', 'Posted vouchers are individually balanced', unbalanced_posted_jvs == 0,
            detail=f'{unbalanced_posted_jvs} posted voucher(s) have debit/credit differences')
        add('posted_jv_gl', 'Posted vouchers have ledger lines', posted_jv_without_gl == 0,
            detail=f'{posted_jv_without_gl} posted voucher(s) have no GL lines')
        add('orphan_gl', 'No orphan ledger lines', orphan_gl == 0,
            detail=f'{orphan_gl} GL line(s) lack a source voucher')
        add('expense_control', 'Posted expenses are linked to vouchers', posted_expenses_without_jv == 0,
            detail=f'{posted_expenses_without_jv} posted expense(s) have no voucher reference')
        add('receipt_control', 'Posted receipts are linked to vouchers', posted_receipts_without_jv == 0,
            detail=f'{posted_receipts_without_jv} posted receipt(s) have no voucher reference')
        add('budget_control', 'Budget lines within control threshold', overrun_lines == 0, overrun_lines <= 3,
            detail=f'{overrun_lines} budget line(s) are over-controlled budget')
        add('period_control', 'Accounting periods are configured', (open_periods + closed_periods + locked_periods) > 0,
            detail=f'{open_periods} open; {closed_periods} closed; {locked_periods} locked')
        add('audit_trail', 'Audit trail is active', audit_entries > 0, audit_entries == 0,
            detail=f'{audit_entries} recorded audit event(s)')

        fail = sum(1 for c in checks if c['status'] == 'fail')
        warn = sum(1 for c in checks if c['status'] == 'warn')
        score = max(0, 100 - fail*18 - warn*7 - (10 if unposted_jvs > 25 else 0))
        rating = 'Excellent' if score >= 90 else 'Good' if score >= 75 else 'Needs attention' if score >= 55 else 'High risk'

        return {
            'ok': True,
            'score': score,
            'rating': rating,
            'generated_at': datetime.now().isoformat(),
            'metrics': {
                'ledger_debit': debit, 'ledger_credit': credit, 'ledger_difference': ledger_diff,
                'posted_jvs': posted_jvs, 'unposted_jvs': unposted_jvs, 'reversed_jvs': reversed_jvs,
                'unposted_expenses': unposted_expenses, 'unposted_expense_value': unposted_expense_value,
                'unposted_receipts': unposted_receipts, 'unposted_receipt_value': unposted_receipt_value,
                'overrun_budget_lines': overrun_lines,
                'open_periods': open_periods, 'closed_periods': closed_periods, 'locked_periods': locked_periods,
                'audit_entries': audit_entries
            },
            'checks': checks
        }
    finally:
        conn.close()


