def _sbs_v33_commitment_payment_migrations():
    """Idempotent schema fixes for commitment/account coding and payment channels."""
    conn = get_db()
    try:
        for ddl in [
            "dept TEXT", "coa_id TEXT", "procurement_method TEXT DEFAULT 'Purchase Order'",
            "due_date TEXT", "delivery_status TEXT DEFAULT 'Pending'", "last_amended_by TEXT",
            "last_amended_at TEXT"
        ]:
            try: _add_col(conn, 'commitments', ddl)
            except Exception: pass
        for ddl in [
            "dept TEXT", "cheque_no TEXT", "transfer_ref TEXT", "mobile_money_provider TEXT",
            "mobile_money_number TEXT"
        ]:
            try: _add_col(conn, 'actuals', ddl)
            except Exception: pass
        conn.commit()
    finally:
        conn.close()
    print('  Migration: SBS v3.3 commitment/payment reference controls applied')

# Wrap the latest init functions without losing earlier worldclass migrations.
_prev_init_db_v33 = init_db
def init_db():
    _prev_init_db_v33()
    _sbs_v33_commitment_payment_migrations()

_prev_init_jv_db_v33 = init_jv_db
def init_jv_db():
    _prev_init_jv_db_v33()
    _sbs_v33_commitment_payment_migrations()


def _normalise_department_code(value):
    raw = (value or '').strip()
    if not raw:
        return ''
    aliases = {
        'Dean\'s Office & Administration': 'DEAN',
        'Dean\'s Office &amp; Administration': 'DEAN',
        'Dean Office': 'DEAN',
        'School-Wide': 'SCHOOL',
        'School Wide': 'SCHOOL',
        'University-Wide': 'SCHOOL',
        'University Wide': 'SCHOOL'
    }
    return aliases.get(raw, raw)


def _ensure_general_project_for_dept(conn, dept, session):
    """Create/reuse a non-donor General Fund project for direct departmental transactions."""
    dept = _normalise_department_code(dept)
    if not dept:
        raise ValueError('Department is required when no research grant/project is selected')
    existing = conn.execute("""
        SELECT id FROM projects
        WHERE division=? AND (project_code LIKE 'GF-%' OR donor IN ('UCC/GETFund','UCC General Fund'))
        ORDER BY created_at DESC LIMIT 1
    """, (dept,)).fetchone()
    if existing:
        return existing['id']
    gf_id = str(uuid.uuid4())
    safe = ''.join(ch for ch in dept.upper() if ch.isalnum())[:8] or 'DEPT'
    gf_code = f"GF-{safe}"
    # Avoid code collision by suffixing a short token.
    if conn.execute("SELECT 1 FROM projects WHERE project_code=?", (gf_code,)).fetchone():
        gf_code = f"GF-{safe}-{str(uuid.uuid4())[:4].upper()}"
    conn.execute("""INSERT INTO projects
        (id, project_code, title, division, donor, currency, budget_fcy, fx_rate, budget_ghs,
         start_date, end_date, status, pi_name, notes, created_by)
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (gf_id, gf_code, f"General Fund — {dept}", dept, 'UCC General Fund', 'GHS', 0, 1.0, 0,
         '2024-01-01', '2035-12-31', 'Active', '',
         'System-created project for direct departmental commitments and payments.',
         (session or {}).get('username','system')))
    return gf_id


def _materialize_quarterly_budget(conn, qb_id, session):
    """When a quarterly budget line is approved, mirror it into the budgets ledger
    as a real budget line under the department's General Fund project. This makes
    it selectable as a Budget Line on commitments/actuals and gives it proper
    committed/actual/available exposure tracking. Idempotent via a deterministic
    budget_code derived from the quarterly-budget id."""
    try:
        row = conn.execute(
            "SELECT id, dept_code, coa_id, annual_total, currency, description "
            "FROM quarterly_budgets WHERE id=?", (qb_id,)).fetchone()
        if not row:
            return None
        row = dict(row)
        coa_id = row.get('coa_id')
        if not coa_id:
            return None  # budgets.coa_id is NOT NULL — cannot mirror without an account
        proj_id = _ensure_general_project_for_dept(conn, row.get('dept_code'), session)
        # Idempotency is keyed on (project_id, coa_id) — one budget line per department
        # General-Fund project + account — so the display code can be a friendly
        # sequential QB-YYYY-NNN instead of a hex fragment, without risking duplicates.
        existing = conn.execute("SELECT id FROM budgets WHERE project_id=? AND coa_id=?",
                                (proj_id, coa_id)).fetchone()
        if existing:
            return existing['id']  # already materialised
        bcode = _next_budget_code(conn)
        amt = float(row.get('annual_total') or 0)
        bid = str(uuid.uuid4())
        conn.execute(
            "INSERT INTO budgets(id,budget_code,project_id,coa_id,budget_fcy,currency,fx_rate,budget_ghs,notes) "
            "VALUES(?,?,?,?,?,?,?,?,?)",
            (bid, bcode, proj_id, coa_id, amt, row.get('currency') or 'GHS', 1.0, amt,
             'Approved quarterly budget: ' + str(row.get('description') or '')))
        return bid
    except Exception as _mqb_exc:
        print('  Quarterly budget materialise warning:', _mqb_exc)
        return None


def _backfill_quarterly_budget_materialisation():
    """Idempotently mirror every already-approved quarterly budget into the budgets
    ledger. Needed for budgets approved before materialisation existed — runs once on
    startup; lines already mirrored are skipped via the deterministic budget_code."""
    conn = get_db()
    try:
        try:
            rows = conn.execute(
                "SELECT id FROM quarterly_budgets "
                "WHERE approval_status='Approved' AND COALESCE(is_deleted,0)=0 AND COALESCE(coa_id,'')<>''"
            ).fetchall()
        except Exception:
            return
        made = 0
        for r in rows:
            try:
                if _materialize_quarterly_budget(conn, r['id'], None):
                    made += 1
            except Exception:
                pass
        conn.commit()
        if made:
            print('  QB backfill: mirrored %d approved quarterly budget line(s) into the budgets ledger' % made)
    finally:
        conn.close()


def api_get_commitments(session, project_id=None):
    conn = get_db()
    try:
        q = """SELECT c.*, p.project_code, p.title as project_title,
            COALESCE(c.dept, p.division) as dept,
            b.budget_code,
            COALESCE(coab.account_name, coac.account_name) as account_name,
            COALESCE(coab.code, coac.code) as coa_code,
            COALESCE(coab.id, coac.id) as effective_coa_id
            FROM commitments c
            JOIN projects p ON c.project_id=p.id
            LEFT JOIN budgets b ON c.budget_id=b.id
            LEFT JOIN chart_of_accounts coab ON b.coa_id=coab.id
            LEFT JOIN chart_of_accounts coac ON c.coa_id=coac.id"""
        args = []
        if project_id:
            q += " WHERE c.project_id=?"
            args.append(project_id)
        q += " ORDER BY c.created_at DESC"
        return [dict(r) for r in conn.execute(q, args)]
    finally:
        conn.close()


def api_save_commitment(data, session):
    """Robust commitment save.

    Fixes the previous broken UI/API mismatch where the frontend passed a COA id as
    budget_id and never sent the department value. Commitments may now be tied to a
    project budget line or, for direct departmental spend, to a department + COA.
    Commitments still do not post to GL; they reserve budget/procurement exposure only.
    """
    conn = get_db()
    try:
        cid = data.get('id') or str(uuid.uuid4())
        existing = conn.execute("SELECT * FROM commitments WHERE id=?", (cid,)).fetchone() if data.get('id') else None
        ccode = data.get('commit_code') or (existing['commit_code'] if existing else f"CMT-{str(uuid.uuid4())[:6].upper()}")
        dept = _normalise_department_code(data.get('dept') or data.get('department') or data.get('division') or (existing['dept'] if existing and 'dept' in existing.keys() else ''))
        project_id = data.get('project_id') or (existing['project_id'] if existing else None)
        budget_id = data.get('budget_id') or None
        coa_id = data.get('coa_id') or None
        vendor = (data.get('vendor') or '').strip()
        description = (data.get('description') or '').strip()
        if not vendor or not description:
            return err('Vendor and description are required')
        amount_fcy = float(data.get('amount_fcy') or 0)
        fx_rate = float(data.get('fx_rate') or 1)
        if amount_fcy <= 0:
            return err('Commitment amount must be greater than zero')
        if not project_id:
            project_id = _ensure_general_project_for_dept(conn, dept, session)
        if not dept:
            pr = conn.execute("SELECT division FROM projects WHERE id=?", (project_id,)).fetchone()
            dept = _normalise_department_code(pr['division'] if pr else '')
        # If user accidentally sends a COA id in budget_id, move it safely to coa_id.
        if budget_id and not conn.execute("SELECT 1 FROM budgets WHERE id=?", (budget_id,)).fetchone():
            if conn.execute("SELECT 1 FROM chart_of_accounts WHERE id=?", (budget_id,)).fetchone():
                coa_id, budget_id = budget_id, None
            else:
                return err('Selected budget line is invalid')
        # A selected budget line must belong to the selected project. Also derive COA.
        if budget_id:
            budg = conn.execute("SELECT project_id, coa_id FROM budgets WHERE id=?", (budget_id,)).fetchone()
            if not budg:
                return err('Selected budget line could not be found')
            if budg['project_id'] != project_id:
                return err('Selected budget line does not belong to the selected project')
            coa_id = budg['coa_id']
        if coa_id and not conn.execute("SELECT 1 FROM chart_of_accounts WHERE id=?", (coa_id,)).fetchone():
            return err('Selected chart-of-account line is invalid')
        amount_ghs = round(amount_fcy * fx_rate, 2)
        # Budget availability check, excluding this commitment during edits.
        if budget_id:
            budg = conn.execute("""SELECT b.budget_ghs,
                COALESCE((SELECT SUM(MAX(0, c.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=c.id AND COALESCE(_ax.is_posted,0)=1),0))) FROM commitments c
                          WHERE c.budget_id=b.id AND COALESCE(c.status,'') NOT IN ('Cancelled','Fully Paid') AND c.id<>?),0) as committed,
                COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a
                          WHERE a.budget_id=b.id AND COALESCE(a.is_posted,0)=1),0) as actual
                FROM budgets b WHERE b.id=?""", (cid, budget_id)).fetchone()
            if budg:
                available = float(budg['budget_ghs'] or 0) - float(budg['committed'] or 0) - float(budg['actual'] or 0)
                if amount_ghs > available and session.get('role') != 'Admin':
                    return err(f'Insufficient budget. Available: GHS {available:,.2f}. Ask Admin to approve an override or vire funds.')
        commit_date = data.get('commit_date') or date.today().isoformat()
        status = data.get('status') or (existing['status'] if existing else 'Open')
        procurement_method = data.get('procurement_method') or (existing['procurement_method'] if existing and 'procurement_method' in existing.keys() else 'Purchase Order')
        due_date = data.get('due_date') or (existing['due_date'] if existing and 'due_date' in existing.keys() else '')
        delivery_status = data.get('delivery_status') or (existing['delivery_status'] if existing and 'delivery_status' in existing.keys() else 'Pending')
        reference = data.get('reference') or ''
        if existing:
            conn.execute("""UPDATE commitments SET project_id=?, budget_id=?, coa_id=?, dept=?, commit_date=?, vendor=?,
                description=?, currency=?, amount_fcy=?, fx_rate=?, amount_ghs=?, reference=?, status=?,
                procurement_method=?, due_date=?, delivery_status=?, last_amended_by=?, last_amended_at=datetime('now')
                WHERE id=?""",
                (project_id, budget_id, coa_id, dept, commit_date, vendor, description, data.get('currency','GHS'),
                 amount_fcy, fx_rate, amount_ghs, reference, status, procurement_method, due_date, delivery_status,
                 session.get('username','system'), cid))
            action = 'UPDATE_COMMITMENT'
        else:
            conn.execute("""INSERT INTO commitments(id, commit_code, project_id, budget_id, coa_id, dept, commit_date,
                vendor, description, currency, amount_fcy, fx_rate, amount_ghs, reference, status,
                procurement_method, due_date, delivery_status, created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (cid, ccode, project_id, budget_id, coa_id, dept, commit_date, vendor, description,
                 data.get('currency','GHS'), amount_fcy, fx_rate, amount_ghs, reference, status,
                 procurement_method, due_date, delivery_status, session.get('username','system')))
            action = 'SAVE_COMMITMENT'
        _audit(conn, session, action, 'commitments', cid,
               f"{ccode} | {dept or '-'} | {vendor} | GHS {amount_ghs:,.2f} | {status}")
        conn.commit()
        return ok({'id': cid, 'commit_code': ccode, 'project_id': project_id})
    except Exception as e:
        conn.rollback()
        return err(str(e))
    finally:
        conn.close()


def _expense_lines_for_actual(conn, txn):
    """PV double-entry lines with correct payment channel and reference text."""
    gross = float(txn.get('amount_ghs') or 0)
    has_vat = int(txn.get('has_vat') or 0)
    has_whvat = int(txn.get('has_whvat') or 0)
    ex_vat = round(gross / 1.2, 2) if has_whvat else gross
    vat_amount = float(txn.get('vat_amount') or 0)
    wht = float(txn.get('wht_amount') or 0)
    whvat = float(txn.get('whvat_amount') or 0)
    ucf = float(txn.get('ucf_amount') or 0)
    expense_coa = None
    if txn.get('budget_id'):
        expense_coa = conn.execute("""SELECT c.id, c.code, c.account_name FROM budgets b
            JOIN chart_of_accounts c ON b.coa_id=c.id WHERE b.id=?""", (txn['budget_id'],)).fetchone()
    # Honour the expense account the user actually selected. The actuals row stores
    # it as expense_coa_id (some callers pass coa_id) — previously only coa_id was read,
    # so selections fell through to the Printing & Stationery fallback.
    _sel_coa = txn.get('coa_id') or txn.get('expense_coa_id')
    if not expense_coa and _sel_coa:
        expense_coa = conn.execute("SELECT id, code, account_name FROM chart_of_accounts WHERE id=?", (_sel_coa,)).fetchone()
    if not expense_coa:
        expense_coa = _get_coa(conn, ['6103','6111','6300','6000'])
    bank_coa = _bank_coa_for(conn, txn.get('bank_account_id'), txn.get('currency','GHS'))
    if not expense_coa or not bank_coa:
        raise ValueError('Could not determine expense or bank/cash account for posting')
    debit_expense = ex_vat if has_vat else gross
    debit_vat = vat_amount if has_vat else 0
    gross_invoice = round(debit_expense + debit_vat, 2)
    net_bank = round(gross_invoice - wht - whvat - ucf, 2)
    if net_bank < -0.01:
        raise ValueError('Deductions exceed gross invoice amount')
    ref = txn.get('payment_reference') or txn.get('cheque_no') or txn.get('transfer_ref') or txn.get('receipt_no') or ''
    method = txn.get('payment_method') or 'Bank Transfer'
    lines = [{
        'coa_id': expense_coa['id'], 'debit_amount': debit_expense, 'credit_amount': 0,
        'description': f"Expense: {txn.get('description','')}", 'project_id': txn.get('project_id')
    }]
    if debit_vat > 0:
        vat_rec = _get_coa(conn, ['1012'])
        if vat_rec:
            lines.append({'coa_id':vat_rec['id'],'debit_amount':debit_vat,'credit_amount':0,
                          'description':'Input VAT receivable / VAT component','project_id':txn.get('project_id')})
    for amount, codes, label in [
        (wht, ['2030'], f"WHT Payable ({txn.get('wht_type','')})"),
        (whvat, ['2031','2034'], 'WHVAT Payable'),
        (ucf, ['2033','2035'], 'UCC Common Fund Payable')
    ]:
        if amount > 0:
            coa = _get_coa(conn, codes)
            if coa:
                lines.append({'coa_id':coa['id'],'debit_amount':0,'credit_amount':amount,
                              'description':label,'project_id':txn.get('project_id')})
    lines.append({'coa_id': bank_coa['id'], 'debit_amount':0, 'credit_amount':net_bank,
                  'description': f"{method} payment to {txn.get('payee','')}" + (f" | Ref: {ref}" if ref else ''),
                  'project_id': txn.get('project_id'), 'bank_account_id': txn.get('bank_account_id')})
    return lines


# Preserve richer payment-channel metadata after the core actual save routine.
_prev_api_save_actual_v33 = api_save_actual
def api_save_actual(data, session):
    result = _prev_api_save_actual_v33(data, session)
    if not result or not result.get('ok') or not result.get('id'):
        return result
    conn = get_db()
    try:
        method = data.get('payment_method') or 'Bank Transfer'
        ref = data.get('payment_reference') or data.get('cheque_no') or data.get('transfer_ref') or data.get('receipt_no') or ''
        cheque_no = data.get('cheque_no') or (ref if method == 'Cheque' else '')
        transfer_ref = data.get('transfer_ref') or (ref if method != 'Cheque' else '')
        conn.execute("""UPDATE actuals SET dept=?, cheque_no=?, transfer_ref=?, mobile_money_provider=?, mobile_money_number=?,
            payment_method=?, payment_reference=? WHERE id=?""",
            (data.get('dept') or data.get('department') or '', cheque_no, transfer_ref,
             data.get('mobile_money_provider') or ('Mobile Money' if method == 'Mobile Money' else ''),
             data.get('mobile_money_number') or '', method, ref, result['id']))
        conn.commit()
    finally:
        conn.close()
    return result



# User-requested gross contract-sum expense posting for withholding transactions.
def _expense_lines_for_actual(conn, txn):
    '''PV double-entry lines: Dr full contract sum to expense, Cr statutory payables, Cr bank with net payment.'''
    # MULTI-LINE PV: when this voucher carries itemised lines (one payee, several COA
    # items / departments, each line independently taxable), post Dr per line / Cr the
    # aggregated statutory payables / single Cr bank for the net total. Single-line
    # vouchers (no child lines) fall through to the original logic below — unchanged.
    try:
        if txn.get('id') and _ml_has_lines(conn, txn['id']):
            return _multiline_expense_lines(conn, txn)
    except Exception as _ml_exc:
        if 'Withholdings exceed' in str(_ml_exc) or 'account for posting' in str(_ml_exc):
            raise
    gross = round(float(txn.get('amount_ghs') or 0), 2)
    wht = round(float(txn.get('wht_amount') or 0), 2)
    whvat = round(float(txn.get('whvat_amount') or 0), 2)
    ucf = round(float(txn.get('ucf_amount') or 0), 2)
    # VAT add-on policy (mirrors AOI _build_actual_posting and the multi-line builder):
    #   * VAT + WHVAT  -> amount_ghs is VAT-INCLUSIVE; VAT already embedded, no add-on.
    #   * VAT only     -> amount_ghs is VAT-EXCLUSIVE; the 20% VAT add-on is charged to the
    #                     selected expense COA and added to the bank settlement.
    _has_vat = int(txn.get('has_vat') or 0)
    _has_whvat = int(txn.get('has_whvat') or 0)
    _vat_amount = round(float(txn.get('vat_amount') or 0), 2)
    vat_addon = _vat_amount if (_has_vat and not _has_whvat) else 0
    expense_debit = round(gross + vat_addon, 2)
    # The account the user SELECTED for the payment (expense_coa_id; some callers pass
    # coa_id) is authoritative for the debit. The budget link is for budget-vs-actual
    # CONTROL only and must NOT override the chosen account — otherwise a payment tagged
    # to a budget line on a different account (e.g. a 'Practical Fees' income budget)
    # would be debited to that income account instead of the expense the user picked.
    expense_coa = None
    _sel_coa = txn.get('coa_id') or txn.get('expense_coa_id')
    if _sel_coa:
        expense_coa = conn.execute("SELECT id, code, account_name FROM chart_of_accounts WHERE id=?", (_sel_coa,)).fetchone()
    # Fallback only for legacy rows with no selected account: use the budget line's account.
    if not expense_coa and txn.get('budget_id'):
        expense_coa = conn.execute('''SELECT c.id, c.code, c.account_name FROM budgets b
            JOIN chart_of_accounts c ON b.coa_id=c.id WHERE b.id=?''', (txn['budget_id'],)).fetchone()
    if not expense_coa:
        # Last-resort default — make it payment-type-aware so an Asset Purchase / Liability
        # Settlement with no selected account is not silently booked to an expense head
        # (mirrors AOI _build_actual_posting). Normal PVs always carry a selected COA.
        _pt = (txn.get('payment_type') or 'Expense Payment')
        if _pt in ('Liability Settlement', 'Withholding Remittance'):
            expense_coa = _get_coa(conn, ['21100001', '21100014', '2030'])
        elif _pt == 'Asset Purchase':
            expense_coa = _get_coa(conn, ['11103004', '111'])
        if not expense_coa:
            expense_coa = _get_coa(conn, ['6103', '6111', '6300', '6000'])
    bank_coa = _bank_coa_for(conn, txn.get('bank_account_id'), txn.get('currency','GHS'))
    if not expense_coa or not bank_coa:
        raise ValueError('Could not determine expense or bank/cash account for posting')
    net_bank = round(expense_debit - wht - whvat - ucf, 2)
    if net_bank < -0.01:
        raise ValueError('Withholdings exceed the gross contract sum')
    ref = txn.get('payment_reference') or txn.get('cheque_no') or txn.get('transfer_ref') or txn.get('receipt_no') or ''
    method = txn.get('payment_method') or 'Bank Transfer'
    lines = [{
        'coa_id': expense_coa['id'], 'debit_amount': expense_debit, 'credit_amount': 0,
        'description': f"Expense recognised at full contract sum: {txn.get('description','')}",
        'project_id': txn.get('project_id')
    }]
    for amount, codes, label in [
        (wht, ['2030'], f"WHT Payable ({txn.get('wht_type','')})"),
        (whvat, ['2031','2034'], 'WHVAT Payable'),
        (ucf, ['2033','2035'], 'UCC Common Fund Payable')
    ]:
        if amount > 0:
            coa = _get_coa(conn, codes)
            if coa:
                lines.append({'coa_id':coa['id'],'debit_amount':0,'credit_amount':amount,
                              'description':label,'project_id':txn.get('project_id')})
    if net_bank > 0:
        lines.append({'coa_id': bank_coa['id'], 'debit_amount':0, 'credit_amount':net_bank,
                      'description': f"{method} net payment to {txn.get('payee','')}" + (f" | Ref: {ref}" if ref else ''),
                      'project_id': txn.get('project_id'), 'bank_account_id': txn.get('bank_account_id')})
    return lines


# ═══════════════════════════════════════════════════════════════════════════
# WITHHOLDING PAYABLES CONTROL MODULE — v3.7
# ═══════════════════════════════════════════════════════════════════════════
# Purpose: prevent oversight of WHT, WHVAT and UCF deductions. When an expense
# is posted, the vendor PV credits bank with the net amount and credits the
# relevant withholding liability accounts. This module creates a pending
# payable register for each deduction and allows Finance/Admin to complete the
# statutory remittance PV by selecting the paying bank and payment reference.

def _withholding_migration():
    conn = get_db()
    try:
        conn.executescript('''
        CREATE TABLE IF NOT EXISTS withholding_payables (
            id TEXT PRIMARY KEY,
            actual_id TEXT NOT NULL,
            source_jv_id TEXT,
            source_pv_number TEXT,
            payable_type TEXT NOT NULL CHECK(payable_type IN ('WHT','WHVAT','UCF')),
            payable_label TEXT NOT NULL,
            beneficiary TEXT NOT NULL,
            coa_id TEXT NOT NULL,
            project_id TEXT,
            amount_ghs REAL NOT NULL,
            status TEXT DEFAULT 'Pending' CHECK(status IN ('Pending','Paid','Cancelled')),
            due_date TEXT,
            created_by TEXT,
            created_at TEXT DEFAULT (datetime('now')),
            bank_account_id TEXT,
            payment_method TEXT,
            payment_reference TEXT,
            settlement_date TEXT,
            settlement_jv_id TEXT,
            settlement_pv_number TEXT,
            paid_by TEXT,
            paid_at TEXT,
            notes TEXT,
            UNIQUE(actual_id, payable_type)
        );
        CREATE INDEX IF NOT EXISTS idx_withholding_status ON withholding_payables(status, due_date);
        CREATE INDEX IF NOT EXISTS idx_withholding_actual ON withholding_payables(actual_id);
        ''')
        conn.commit()
    finally:
        conn.close()


def _wh_scalar(conn, sql, params=(), default=None):
    try:
        row = conn.execute(sql, params).fetchone()
        if row is None:
            return default
        return row[0]
    except Exception:
        return default


def _wh_table_has_col(conn, table, col):
    try:
        return any(r[1] == col for r in conn.execute(f"PRAGMA table_info({table})").fetchall())
    except Exception:
        return False


def _wh_coa_id(conn, codes):
    if isinstance(codes, str):
        codes = [codes]
    if '_get_coa' in globals():
        row = _get_coa(conn, codes)
        if row:
            return row['id']
    for code in codes:
        if '_coa_id' in globals():
            cid = _coa_id(conn, code)
            if cid:
                return cid
        row = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (str(code),)).fetchone()
        if row:
            return row['id']
    return None


def _wh_bank_coa_id(conn, bank_account_id=None, currency='GHS'):
    if '_bank_coa_for' in globals():
        row = _bank_coa_for(conn, bank_account_id, currency)
        if row:
            return row['id']
    if bank_account_id and _wh_table_has_col(conn, 'bank_accounts', 'coa_id'):
        row = conn.execute("SELECT coa_id FROM bank_accounts WHERE id=?", (bank_account_id,)).fetchone()
        if row and row['coa_id']:
            return row['coa_id']
    return _wh_coa_id(conn, ['1001','1020','1000'])


def _wh_assert_period_open(conn, date_str):
    if '_assert_period_open' in globals():
        okp, msg = _assert_period_open(conn, date_str)
        if not okp:
            raise ValueError(msg)
        return msg
    if '_ensure_period_accepts' in globals():
        return _ensure_period_accepts(conn, date_str, by_date=True, purpose='withholding payment')
    return (date_str or '')[:7]


def _wh_due_date(expense_date):
    try:
        from datetime import datetime as _dt, timedelta as _td
        return (_dt.strptime(expense_date[:10], '%Y-%m-%d') + _td(days=14)).strftime('%Y-%m-%d')
    except Exception:
        return None


_WH_STATUS_FIXED = [False]
def _wh_status_migration(conn):
    """Allow the 'Awaiting Posting' stage in withholding_payables.status — the
    CHECK constraint is extended in place via writable_schema (no rebuild)."""
    if _WH_STATUS_FIXED[0]:
        return
    import sys as _sys
    try:
        row = conn.execute("SELECT sql FROM sqlite_master WHERE type='table' AND name='withholding_payables'").fetchone()
        sql = (row[0] or '') if row else ''
        if not sql or 'Awaiting Posting' in sql or "'Pending','Paid','Cancelled'" not in sql:
            _WH_STATUS_FIXED[0] = True
            return
        sv = conn.execute('PRAGMA schema_version').fetchone()[0]
        conn.execute('PRAGMA writable_schema=ON')
        conn.execute("UPDATE sqlite_master SET sql=replace(sql, \"'Pending','Paid','Cancelled'\", \"'Pending','Awaiting Posting','Paid','Cancelled'\") WHERE type='table' AND name='withholding_payables'")
        conn.execute('PRAGMA writable_schema=OFF')
        conn.execute('PRAGMA schema_version=%d' % (int(sv) + 1))
        conn.commit()
        chk = conn.execute('PRAGMA integrity_check').fetchone()[0]
        print('withholding status CHECK extended (Awaiting Posting): %s' % chk, file=_sys.stderr); _sys.stderr.flush()
        _WH_STATUS_FIXED[0] = True
    except Exception as exc:
        try: conn.rollback()
        except Exception: pass
        print('withholding status migration warning:', exc, file=_sys.stderr); _sys.stderr.flush()


def _sync_withholding_payables_for_actual(conn, session, actual_id, allow_unposted=False):
    """Create/refresh the tracked withholding payables for a PV. By policy
    (2026-06-11) the rows are created at PV APPROVAL with status
    'Awaiting Posting' (early remittance visibility), then flip to 'Pending'
    when the voucher posts and the liability actually exists in the ledger.
    Settlement is blocked until 'Pending'."""
    _wh_status_migration(conn)
    row = conn.execute('''SELECT a.*, p.project_code, p.title AS project_title,
                jv.jv_number AS source_pv_number
         FROM actuals a
         LEFT JOIN projects p ON p.id=a.project_id
         LEFT JOIN journal_vouchers jv ON jv.id=a.jv_id
         WHERE a.id=?''', (actual_id,)).fetchone()
    if not row or (not int(row['is_posted'] or 0) and not allow_unposted):
        return []
    _wh_target_status = 'Pending' if int(row['is_posted'] or 0) else 'Awaiting Posting'
    actual = dict(row)
    payables = [
        ('WHT',   float(actual.get('wht_amount') or 0),   ['2030'],        'WHT Payable',   'Ghana Revenue Authority'),
        ('WHVAT', float(actual.get('whvat_amount') or 0), ['2031','2034'], 'WHVAT Payable', 'Ghana Revenue Authority'),
        ('UCF',   float(actual.get('ucf_amount') or 0),   ['2033','2035'], 'UCC Common Fund Payable', 'University of Cape Coast'),
    ]
    created=[]
    due = _wh_due_date(actual.get('expense_date') or '')
    for ptype, amount, codes, label, beneficiary in payables:
        amount = round(amount, 2)
        existing = conn.execute("SELECT * FROM withholding_payables WHERE actual_id=? AND payable_type=?", (actual_id, ptype)).fetchone()
        if amount <= 0:
            if existing and existing['status'] in ('Pending', 'Awaiting Posting'):
                conn.execute("UPDATE withholding_payables SET status='Cancelled', notes=COALESCE(notes,'') || ' | Cancelled because corrected amount is zero.' WHERE id=?", (existing['id'],))
            continue
        coa_id = _wh_coa_id(conn, codes)
        if not coa_id:
            continue
        if existing:
            if existing['status'] in ('Pending', 'Awaiting Posting'):
                conn.execute('''UPDATE withholding_payables SET source_jv_id=?,source_pv_number=?,coa_id=?,project_id=?,
                        amount_ghs=?,due_date=?,payable_label=?,beneficiary=?,status=? WHERE id=?''',
                    (actual.get('jv_id'), actual.get('source_pv_number') or '', coa_id, actual.get('project_id'),
                     amount, due, label, beneficiary, _wh_target_status, existing['id']))
        else:
            wid = str(uuid.uuid4())
            conn.execute('''INSERT INTO withholding_payables
                (id,actual_id,source_jv_id,source_pv_number,payable_type,payable_label,beneficiary,coa_id,
                 project_id,amount_ghs,status,due_date,created_by,notes)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)''',
                (wid, actual_id, actual.get('jv_id'), actual.get('source_pv_number') or '', ptype, label, beneficiary,
                 coa_id, actual.get('project_id'), amount, _wh_target_status, due, (session or {}).get('username','system'),
                 f"Auto-created from {'posted' if _wh_target_status == 'Pending' else 'APPROVED'} expense {actual.get('actual_code')}"))
            created.append((ptype, amount))
    if created:
        detail = ', '.join([f"{t} GHS {a:,.2f}" for t,a in created])
        _audit(conn, session or {}, 'CREATE_WITHHOLDING_PAYABLES', 'withholding_payables', actual_id, detail)
    return created


def api_get_withholding_payables(session, status=None):
    _withholding_migration()
    conn = get_db()
    try:
        wheres=[]; args=[]
        if status:
            wheres.append('wp.status=?'); args.append(status)
        where = ('WHERE ' + ' AND '.join(wheres)) if wheres else ''
        rows = [dict(r) for r in conn.execute(f'''
            SELECT wp.*, a.actual_code, a.expense_date, a.payee, a.description AS expense_description,
                   p.project_code, p.title AS project_title,
                   ba.account_name AS paying_bank_name, ba.bank_name AS paying_bank,
                   sjv.jv_number AS settlement_jv_number,
                   CAST(julianday('now') - julianday(COALESCE(wp.due_date, date('now'))) AS INTEGER) AS days_overdue
            FROM withholding_payables wp
            LEFT JOIN actuals a ON a.id=wp.actual_id
            LEFT JOIN projects p ON p.id=wp.project_id
            LEFT JOIN bank_accounts ba ON ba.id=wp.bank_account_id
            LEFT JOIN journal_vouchers sjv ON sjv.id=wp.settlement_jv_id
            {where}
            ORDER BY CASE wp.status WHEN 'Pending' THEN 1 WHEN 'Paid' THEN 2 ELSE 3 END,
                     COALESCE(wp.due_date, wp.created_at), wp.payable_type
        ''', args).fetchall()]
        summary = {'pending_count':0,'paid_count':0,'overdue_count':0,'pending_amount':0.0,'paid_amount':0.0,
                   'wht_pending':0.0,'whvat_pending':0.0,'ucf_pending':0.0}
        for r in rows:
            amt = float(r.get('amount_ghs') or 0)
            if r.get('status') == 'Pending':
                summary['pending_count'] += 1; summary['pending_amount'] += amt
                if (r.get('days_overdue') or 0) > 0: summary['overdue_count'] += 1
                if r.get('payable_type') == 'WHT': summary['wht_pending'] += amt
                elif r.get('payable_type') == 'WHVAT': summary['whvat_pending'] += amt
                elif r.get('payable_type') == 'UCF': summary['ucf_pending'] += amt
            elif r.get('status') == 'Paid':
                summary['paid_count'] += 1; summary['paid_amount'] += amt
        for k in ('pending_amount','paid_amount','wht_pending','whvat_pending','ucf_pending'):
            summary[k] = round(summary[k], 2)
        return {'rows': rows, 'summary': summary}
    finally:
        conn.close()


def api_settle_withholding_payable(data, session):
    if not session:
        return err('Not logged in', 401)
    wid = data.get('id') or data.get('withholding_id')
    if not wid:
        return err('Withholding payable ID is required')
    bank_account_id = data.get('bank_account_id')
    if not bank_account_id:
        return err('Select the bank account paying the withholding')
    payment_method = data.get('payment_method') or 'Bank Transfer'
    payment_reference = (data.get('payment_reference') or data.get('cheque_no') or data.get('transfer_ref') or '').strip()
    if not payment_reference:
        return err('Payment reference / cheque number / transfer reference is required')
    payment_date = data.get('payment_date') or datetime.now().strftime('%Y-%m-%d')
    notes = data.get('notes') or ''
    _withholding_migration()
    conn = get_db()
    try:
        wp = conn.execute('''SELECT wp.*, a.actual_code, a.payee, a.description AS expense_description, a.currency, a.wht_rate,
                                    p.project_code
                             FROM withholding_payables wp
                             LEFT JOIN actuals a ON a.id=wp.actual_id
                             LEFT JOIN projects p ON p.id=wp.project_id
                             WHERE wp.id=?''', (wid,)).fetchone()
        if not wp:
            conn.close(); return err('Withholding payable not found')
        wp = dict(wp)
        if wp.get('status') == 'Paid':
            conn.close(); return err('This withholding payable has already been paid')
        if wp.get('status') == 'Awaiting Posting':
            conn.close(); return err('This withholding was created when the payment voucher was APPROVED, but the voucher has not been POSTED yet — post the PV first (the liability must exist in the ledger), then remit.')
        if wp.get('actual_id'):
            _src = conn.execute("SELECT COALESCE(is_posted,0) FROM actuals WHERE id=?", (wp.get('actual_id'),)).fetchone()
            if _src is not None and not int(_src[0] or 0):
                conn.close(); return err('The source payment voucher has not been posted yet — post it first, then remit this withholding.')
        _wh_assert_period_open(conn, payment_date)
        bank_coa_id = _wh_bank_coa_id(conn, bank_account_id, 'GHS')
        liability_coa_id = wp.get('coa_id')
        if not bank_coa_id or not liability_coa_id:
            raise ValueError('Required liability or bank COA is missing')
        amount = round(float(wp.get('amount_ghs') or 0), 2)
        if amount <= 0:
            raise ValueError('Payable amount must be greater than zero')
        # Narration policy (2026-06-12): the remittance PV self-describes —
        # "<rate>% <type> - <payee> - <what the original payment was for>" so
        # nobody re-types (or alters) the story of the withholding.
        _wp_rate_txt = ''
        if wp.get('payable_type') == 'WHT':
            try:
                _wr = float(wp.get('wht_rate') or 0)
                _wp_rate_txt = ('%g%%' % round(_wr * 100, 2)) if _wr else ''
            except Exception:
                _wp_rate_txt = ''
        elif wp.get('payable_type') == 'WHVAT':
            _wp_rate_txt = '7%'
        elif wp.get('payable_type') == 'UCF':
            _wp_rate_txt = '5%'
        _wp_short = {'WHT': 'WHT', 'WHVAT': 'WHVAT', 'UCF': 'UCC Common Fund'}.get(wp.get('payable_type'), wp.get('payable_type') or 'Withholding')
        _wp_bits = [(' '.join([_wp_rate_txt, _wp_short])).strip(),
                    (wp.get('payee') or '').strip(),
                    (wp.get('expense_description') or '').strip()]
        desc = ' - '.join([b for b in _wp_bits if b])
        if wp.get('actual_code'):
            desc += f" (source {wp['actual_code']})"
        line_note = (f"{payment_method} | Ref: {payment_reference}" if payment_reference else payment_method)
        lines = [
            {'coa_id': liability_coa_id, 'debit_amount': amount, 'credit_amount': 0,
             'description': desc, 'project_id': wp.get('project_id')},
            {'coa_id': bank_coa_id, 'debit_amount': 0, 'credit_amount': amount,
             'description': f"{desc} | {line_note}",
             'project_id': wp.get('project_id'), 'bank_account_id': bank_account_id},
        ]
        if '_insert_voucher_posted' in globals():
            jv_id, jv_num = _insert_voucher_posted(conn, session, jv_type='PV', jv_date=payment_date,
                description=desc, project_id=wp.get('project_id'), bank_account_id=bank_account_id,
                source_module='withholding_payables', source_id=wid, reference=payment_reference,
                lines=lines, notes=f"Statutory withholding settlement. {notes}")
        else:
            jv_id, jv_num = _create_posted_journal(conn, session, 'PV', payment_date, desc, payment_reference,
                wp.get('project_id'), bank_account_id, 'withholding_payables', wid, lines)
        conn.execute('''UPDATE withholding_payables SET status='Paid', bank_account_id=?, payment_method=?,
                payment_reference=?, settlement_date=?, settlement_jv_id=?, settlement_pv_number=?,
                paid_by=?, paid_at=datetime('now'), notes=? WHERE id=?''',
            (bank_account_id, payment_method, payment_reference, payment_date, jv_id, jv_num,
             session.get('username','system'), notes, wid))
        _audit(conn, session, 'SETTLE_WITHHOLDING_PAYABLE', 'withholding_payables', wid,
               f"{wp['payable_type']} GHS {amount:,.2f} settled as {jv_num}")
        conn.commit(); conn.close()
        return ok({'id': wid, 'jv_id': jv_id, 'jv_number': jv_num,
                   'message': f"{wp['payable_type']} payable settled and posted as {jv_num}"})
    except Exception as exc:
        conn.rollback(); conn.close()
        return err(f'Withholding settlement failed: {exc}')


_prev_api_post_actual_withholding = api_post_actual
def api_post_actual(data, session):
    result = _prev_api_post_actual_withholding(data, session)
    try:
        if result and result.get('ok'):
            actual_id = data.get('id') or result.get('id')
            if actual_id:
                conn = get_db()
                try:
                    _sync_withholding_payables_for_actual(conn, session, actual_id)
                    conn.commit()
                finally:
                    conn.close()
    except Exception as exc:
        try:
            conn = get_db(); _audit(conn, session or {}, 'WITHHOLDING_SYNC_WARNING', 'actuals', data.get('id',''), str(exc)); conn.commit(); conn.close()
        except Exception:
            pass
    return result


_prev_api_save_actual_withholding = api_save_actual
def api_save_actual(data, session):
    result = _prev_api_save_actual_withholding(data, session)
    try:
        if result and result.get('ok') and result.get('id'):
            conn = get_db()
            try:
                posted = _wh_scalar(conn, "SELECT is_posted FROM actuals WHERE id=?", (result['id'],), 0)
                if posted:
                    _sync_withholding_payables_for_actual(conn, session, result['id'])
                    conn.commit()
            finally:
                conn.close()
    except Exception as exc:
        try:
            conn = get_db(); _audit(conn, session or {}, 'WITHHOLDING_SYNC_WARNING', 'actuals', result.get('id',''), str(exc)); conn.commit(); conn.close()
        except Exception:
            pass
    return result


_prev_api_get_notifications_withholding = api_get_notifications
def api_get_notifications(session):
    notes = _prev_api_get_notifications_withholding(session) or []
    try:
        _withholding_migration()
        conn = get_db()
        pending = conn.execute("SELECT COUNT(*), COALESCE(SUM(amount_ghs),0) FROM withholding_payables WHERE status='Pending'").fetchone()
        overdue = conn.execute("SELECT COUNT(*), COALESCE(SUM(amount_ghs),0) FROM withholding_payables WHERE status='Pending' AND due_date IS NOT NULL AND due_date < date('now')").fetchone()
        conn.close()
        if pending and pending[0]:
            notes.append({'type':'warning','title':f"{pending[0]} withholding payable(s) pending — GHS {float(pending[1] or 0):,.2f}", 'module':'withholding-payables'})
        if overdue and overdue[0]:
            notes.append({'type':'danger','title':f"{overdue[0]} overdue withholding remittance(s) — GHS {float(overdue[1] or 0):,.2f}", 'module':'withholding-payables'})
    except Exception:
        pass
    return notes


