def api_submit_approval(data, session):
    if not session: return err('Not authenticated')
    _ent_migration()
    module = (data.get('module') or '').strip()
    record_id = (data.get('record_id') or '').strip()
    if not module or not record_id: return err('Module and record ID are required')
    conn = get_db()
    try:
        meta = _ent_record_meta(conn, module, record_id)
        if not meta: return err('Record not found')
        existing = conn.execute("SELECT * FROM approvals WHERE module=? AND record_id=?", (module, record_id)).fetchone()
        if existing:
            _examt = _ent_money(existing['amount_ghs']); _curamt = _ent_money(meta.get('amount_ghs'))
            if abs(_curamt - _examt) > 0.01:
                # The record was edited since this approval was raised — the prior sign-off is
                # stale (maker changed the amount). Invalidate it so the payment must be
                # re-approved afresh at its new amount instead of soft-locking.
                conn.execute("DELETE FROM approval_steps WHERE approval_id=?", (existing['id'],))
                conn.execute("DELETE FROM approvals WHERE id=?", (existing['id'],))
            else:
                return ok({'id': existing['id'], 'status': existing['status'], 'message': f"Already {existing['status']}"})
        aid = str(uuid.uuid4())
        amount = _ent_money(meta.get('amount_ghs'))
        unit = meta.get('unit_code') or ''
        project_id = meta.get('project_id') or ''
        # Dual control: a high-value payment cannot be auto-cleared by its submitter (even an
        # Admin) — it must go through a pending approval so a SECOND person signs off.
        _dc_thr = 0.0
        try:
            _dcr = conn.execute("SELECT value FROM settings WHERE key='dual_control_threshold_ghs'").fetchone()
            _dc_thr = float((_dcr['value'] if _dcr else 0) or 0)
        except Exception:
            _dc_thr = 0.0
        _force_dual = (module == 'actuals' and _dc_thr > 0 and amount >= _dc_thr)
        if _ent_admin(session) and not _force_dual:
            conn.execute("""INSERT INTO approvals(id,module,record_id,record_code,amount_ghs,unit_code,project_id,status,submitted_by,decided_by,decided_at,comments)
                           VALUES(?,?,?,?,?,?,?,?,?,?,datetime('now'),?)""",
                        (aid,module,record_id,meta.get('code'),amount,unit,project_id,'Approved',session.get('username'),session.get('username'),data.get('comments','Admin approval bypass')))
            conn.execute("""INSERT INTO approval_steps(id,approval_id,step_order,approver_role,status,action_by,action_at,comments)
                           VALUES(?,?,?,?,?,?,datetime('now'),?)""", (str(uuid.uuid4()), aid, 1, 'Admin', 'Approved', session.get('username'), 'Admin unlimited approval authority'))
        else:
            if _force_dual:
                # Dual control: exactly ONE second approver (anyone other than the creator)
                # clears a high-value payment — override any multi-step config so the chain
                # can't deadlock on a step the creator themselves would have to sign.
                rules = [{'step_order':1,'approver_role':'','approver_user':''}]
            else:
                rules = _ent_matching_rules(conn, module, amount, unit, project_id)
                if not rules:
                    rules = [{'step_order':1,'approver_role':'Finance Officer','approver_user':''},{'step_order':2,'approver_role':'Admin','approver_user':''}]
            conn.execute("""INSERT INTO approvals(id,module,record_id,record_code,amount_ghs,unit_code,project_id,status,submitted_by,comments)
                           VALUES(?,?,?,?,?,?,?,?,?,?)""",
                        (aid,module,record_id,meta.get('code'),amount,unit,project_id,'Pending',session.get('username'),data.get('comments','')))
            for r in rules:
                conn.execute("""INSERT INTO approval_steps(id,approval_id,step_order,approver_role,approver_user,status)
                               VALUES(?,?,?,?,?, 'Pending')""", (str(uuid.uuid4()), aid, int(r.get('step_order') or 1), r.get('approver_role') or '', r.get('approver_user') or ''))
        _audit(conn, session, 'SUBMIT_APPROVAL', 'approvals', aid, f"{module}:{record_id} | {meta.get('code')} | GHS {amount:,.2f}")
        conn.commit(); return ok({'id': aid, 'status': ('Approved' if (_ent_admin(session) and not _force_dual) else 'Pending')})
    except Exception as exc:
        conn.rollback(); return err(f'Approval submission failed: {exc}')
    finally:
        conn.close()

def api_approval_action(data, session):
    if not session: return err('Not authenticated')
    _ent_migration()
    aid = data.get('approval_id') or data.get('id')
    action = (data.get('action') or '').lower()
    if action not in ('approve','reject','cancel'): return err('Action must be approve, reject or cancel')
    conn=get_db()
    try:
        appr = conn.execute("SELECT * FROM approvals WHERE id=?", (aid,)).fetchone()
        if not appr: return err('Approval not found')
        if appr['status'] != 'Pending' and not _ent_admin(session): return err(f"Approval is already {appr['status']}")
        if action == 'cancel':
            if not _ent_admin(session) and appr['submitted_by'] != session.get('username'):
                return err('Only the requester or Admin can cancel')
            conn.execute("UPDATE approvals SET status='Cancelled',decided_by=?,decided_at=datetime('now'),comments=? WHERE id=?", (session.get('username'),data.get('comments','Cancelled'),aid))
        elif action == 'reject':
            conn.execute("UPDATE approvals SET status='Rejected',decided_by=?,decided_at=datetime('now'),comments=? WHERE id=?", (session.get('username'),data.get('comments','Rejected'),aid))
            conn.execute("UPDATE approval_steps SET status='Rejected', action_by=?, action_at=datetime('now'), comments=? WHERE approval_id=? AND status='Pending'", (session.get('username'),data.get('comments','Rejected'),aid))
        elif _ent_admin(session):
            # Admin has no amount limit and can final-approve any transaction immediately.
            conn.execute("UPDATE approval_steps SET status='Skipped', action_by=?, action_at=datetime('now'), comments='Admin final approval override' WHERE approval_id=? AND status='Pending'", (session.get('username'),aid))
            conn.execute("UPDATE approvals SET status='Approved',decided_by=?,decided_at=datetime('now'),comments=? WHERE id=?", (session.get('username'),data.get('comments','Approved by Admin'),aid))
        else:
            step = conn.execute("""SELECT * FROM approval_steps WHERE approval_id=? AND status='Pending'
                                   AND (approver_user=? OR approver_user='' OR approver_user IS NULL)
                                   AND (approver_role=? OR approver_role='' OR approver_role IS NULL)
                                   ORDER BY step_order LIMIT 1""", (aid, session.get('username'), session.get('role'))).fetchone()
            if not step: return err('You are not the current approver for this request')
            conn.execute("UPDATE approval_steps SET status='Approved',action_by=?,action_at=datetime('now'),comments=? WHERE id=?", (session.get('username'),data.get('comments','Approved'),step['id']))
            remaining = _ent_scalar(conn, "SELECT COUNT(*) FROM approval_steps WHERE approval_id=? AND status='Pending'", (aid,), 0)
            if not remaining:
                conn.execute("UPDATE approvals SET status='Approved',decided_by=?,decided_at=datetime('now'),comments=? WHERE id=?", (session.get('username'),data.get('comments','Approved'),aid))
        _audit(conn, session, f"APPROVAL_{action.upper()}", 'approvals', aid, data.get('comments',''))
        conn.commit(); return ok({'id': aid})
    except Exception as exc:
        conn.rollback(); return err(f'Approval action failed: {exc}')
    finally:
        conn.close()

def api_get_approvals(session, status=None):
    if not session: return err('Not authenticated')
    _ent_migration(); conn=get_db()
    try:
        q="""SELECT a.*, p.project_code, p.title as project_title,
              (SELECT COUNT(*) FROM approval_steps s WHERE s.approval_id=a.id) AS step_count,
              (SELECT COUNT(*) FROM approval_steps s WHERE s.approval_id=a.id AND s.status='Approved') AS approved_steps
              FROM approvals a LEFT JOIN projects p ON p.id=a.project_id WHERE 1=1"""
        args=[]
        if status: q += " AND a.status=?"; args.append(status)
        q += " ORDER BY a.submitted_at DESC LIMIT 500"
        rows=[dict(r) for r in conn.execute(q,args).fetchall()]
        for r in rows:
            r['steps']=[dict(s) for s in conn.execute("SELECT * FROM approval_steps WHERE approval_id=? ORDER BY step_order", (r['id'],)).fetchall()]
        return rows
    finally: conn.close()

