def api_get_procure_to_pay(session):
    if not session: return err('Not authenticated')
    _ent_migration(); conn=get_db()
    try:
        rows=[dict(r) for r in conn.execute("""
            SELECT c.id, c.commit_code, c.commit_date, c.vendor, c.description, c.amount_ghs, c.status,
                   p.project_code, p.title AS project_title, p.division,
                   COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.commitment_id=c.id),0) AS paid_ghs,
                   COALESCE((SELECT COUNT(*) FROM actuals a WHERE a.commitment_id=c.id AND COALESCE(a.is_posted,0)=1),0) AS posted_payments,
                   COALESCE((SELECT COUNT(*) FROM withholding_payables w JOIN actuals a ON a.id=w.actual_id WHERE a.commitment_id=c.id AND w.status='Pending'),0) AS pending_withholdings,
                   COALESCE((SELECT COUNT(*) FROM document_attachments d WHERE d.module='commitments' AND d.record_id=c.id),0) AS docs,
                   COALESCE((SELECT status FROM approvals ap WHERE ap.module='commitments' AND ap.record_id=c.id),'Not Submitted') AS approval_status
            FROM commitments c JOIN projects p ON p.id=c.project_id
            ORDER BY c.created_at DESC LIMIT 500
        """).fetchall()]
        for r in rows:
            paid = _ent_money(r.get('paid_ghs')); amt = _ent_money(r.get('amount_ghs'))
            if r.get('pending_withholdings'):
                r['flow_stage']='Withholding Pending'
            elif paid >= amt and amt > 0:
                r['flow_stage']='Paid / Closed'
            elif paid > 0:
                r['flow_stage']='Part-paid'
            elif r.get('approval_status') == 'Approved':
                r['flow_stage']='Approved / Awaiting Payment'
            else:
                r['flow_stage']='Committed / Awaiting Approval'
        return rows
    finally: conn.close()

def api_project_closeout(session, project_id=None):
    if not session: return err('Not authenticated')
    _ent_migration(); conn=get_db()
    try:
        if not project_id:
            projects=[dict(r) for r in conn.execute("SELECT id,project_code,title,donor,division,status,start_date,end_date,budget_ghs FROM projects ORDER BY end_date DESC").fetchall()]
            return {'projects': projects}
        p = conn.execute("SELECT * FROM projects WHERE id=?", (project_id,)).fetchone()
        if not p: return err('Project not found')
        budget = _ent_money(p['budget_ghs'])
        receipts = _ent_money(_ent_scalar(conn, "SELECT SUM(amount_ghs) FROM fund_receipts WHERE project_id=? AND COALESCE(is_posted,0)=1", (project_id,), 0))
        expenses = _ent_money(_ent_scalar(conn, "SELECT SUM(amount_ghs) FROM actuals WHERE project_id=? AND COALESCE(is_posted,0)=1", (project_id,), 0))
        commitments = _ent_money(_ent_scalar(conn, "SELECT SUM(MAX(0, cmt.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=cmt.id AND COALESCE(_ax.is_posted,0)=1),0))) FROM commitments cmt WHERE cmt.project_id=? AND COALESCE(cmt.status,'') NOT IN ('Cancelled','Fully Paid')", (project_id,), 0))
        wh_pending = _ent_money(_ent_scalar(conn, "SELECT SUM(amount_ghs) FROM withholding_payables WHERE project_id=? AND status='Pending'", (project_id,), 0)) if _ent_table_exists(conn,'withholding_payables') else 0
        docs = int(_ent_scalar(conn, "SELECT COUNT(*) FROM document_attachments WHERE module='projects' AND record_id=?", (project_id,), 0))
        budget_lines=[dict(r) for r in conn.execute("""
            SELECT b.budget_code, c.code AS coa_code, c.account_name, b.budget_ghs,
              COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id AND COALESCE(a.is_posted,0)=1),0) AS actual_ghs,
              COALESCE((SELECT SUM(MAX(0, cm.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=cm.id AND COALESCE(_ax.is_posted,0)=1),0))) FROM commitments cm WHERE cm.budget_id=b.id AND COALESCE(cm.status,'') NOT IN ('Cancelled','Fully Paid')),0) AS committed_ghs
            FROM budgets b LEFT JOIN chart_of_accounts c ON c.id=b.coa_id WHERE b.project_id=? ORDER BY c.code
        """, (project_id,)).fetchall()]
        return {'project': dict(p), 'summary': {
            'budget_ghs': budget, 'posted_receipts_ghs': receipts, 'posted_expenses_ghs': expenses,
            'open_commitments_ghs': commitments, 'pending_withholdings_ghs': wh_pending,
            'unspent_cash_ghs': round(receipts - expenses - wh_pending, 2),
            'available_budget_ghs': round(budget - expenses - commitments, 2),
            'document_count': docs,
            'closeout_ready': commitments == 0 and wh_pending == 0
        }, 'budget_lines': budget_lines}
    finally: conn.close()

