def _ent_backup_dir():
    root = Path(os.environ.get('RENDER_DATA_DIR','') or ('/var/data' if Path('/var/data').exists() else str(Path(__file__).parent)))
    b = root / 'backups'
    b.mkdir(parents=True, exist_ok=True)
    return b

def _ent_prune_backups(conn, keep_days=None, keep_min=7):
    """Delete backups older than the retention window so the persistent disk never
    fills up. Always keeps at least the newest `keep_min` regardless of age (so a
    burst of same-day backups can never wipe history). Configure via the
    BACKUP_RETENTION_DAYS env var (default 30; set 0 to disable pruning).
    Returns the number of backup files removed."""
    import time as _t
    try:
        keep_days = keep_days if keep_days is not None else int(os.environ.get('BACKUP_RETENTION_DAYS', '30') or 30)
    except Exception:
        keep_days = 30
    if keep_days <= 0:
        return 0
    try:
        bdir = _ent_backup_dir()
        files = sorted([p for p in bdir.glob('*-backup-*.db') if p.is_file()],
                       key=lambda p: p.stat().st_mtime, reverse=True)
    except Exception:
        return 0
    cutoff = _t.time() - keep_days * 86400
    removed = 0
    for p in files[keep_min:]:           # never delete the newest keep_min backups
        try:
            if p.stat().st_mtime < cutoff:
                p.unlink()
                removed += 1
                try:
                    conn.execute("DELETE FROM backup_log WHERE backup_path=?", (str(p),))
                except Exception:
                    pass
        except Exception:
            pass
    return removed

def _sigv4_sign(key, msg):
    import hmac as _hm, hashlib as _h
    return _hm.new(key, msg.encode('utf-8'), _h.sha256).digest()

def _offsite_backup_push(file_path, file_name):
    """Best-effort upload of a backup file to S3-compatible object storage so backups live
    OFF the Render disk and survive a disk loss. Configured via BACKUP_S3_* env vars; a no-op
    (does not affect the on-disk backup) if unset. Pure-stdlib AWS Signature V4 PUT — works
    with AWS S3, Cloudflare R2, Backblaze B2 (S3 API), Wasabi, DigitalOcean Spaces, MinIO."""
    import os as _os, hashlib as _h, urllib.request as _u, datetime as _dt
    bucket=_os.environ.get('BACKUP_S3_BUCKET','').strip()
    ak=_os.environ.get('BACKUP_S3_ACCESS_KEY','').strip()
    sk=_os.environ.get('BACKUP_S3_SECRET_KEY','').strip()
    if not (bucket and ak and sk):
        return {'enabled': False, 'reason': 'off-site storage not configured (set BACKUP_S3_BUCKET / BACKUP_S3_ACCESS_KEY / BACKUP_S3_SECRET_KEY)'}
    endpoint=(_os.environ.get('BACKUP_S3_ENDPOINT','').strip() or 's3.amazonaws.com')
    region=(_os.environ.get('BACKUP_S3_REGION','').strip() or 'us-east-1')
    prefix=(_os.environ.get('BACKUP_S3_PREFIX','').strip() or 'backups/')
    if prefix and not prefix.endswith('/'): prefix += '/'
    insecure=endpoint.startswith('http://')
    host=endpoint.replace('https://','').replace('http://','').rstrip('/')
    okey=prefix+file_name
    canonical_uri='/'+bucket+'/'+okey   # path-style (broadest S3-compatible support)
    try:
        with open(file_path,'rb') as _f: payload=_f.read()
        ph=_h.sha256(payload).hexdigest()
        now=_dt.datetime.now(_dt.timezone.utc)
        amzdate=now.strftime('%Y%m%dT%H%M%SZ'); ds=now.strftime('%Y%m%d')
        ch='host:'+host+'\nx-amz-content-sha256:'+ph+'\nx-amz-date:'+amzdate+'\n'
        sh='host;x-amz-content-sha256;x-amz-date'
        creq='PUT\n'+canonical_uri+'\n\n'+ch+'\n'+sh+'\n'+ph
        scope=ds+'/'+region+'/s3/aws4_request'
        sts='AWS4-HMAC-SHA256\n'+amzdate+'\n'+scope+'\n'+_h.sha256(creq.encode()).hexdigest()
        kd=_sigv4_sign(('AWS4'+sk).encode('utf-8'),ds); kr=_sigv4_sign(kd,region)
        ksv=_sigv4_sign(kr,'s3'); ksig=_sigv4_sign(ksv,'aws4_request')
        import hmac as _hm
        signature=_hm.new(ksig,sts.encode('utf-8'),_h.sha256).hexdigest()
        auth='AWS4-HMAC-SHA256 Credential='+ak+'/'+scope+', SignedHeaders='+sh+', Signature='+signature
        url=('http://' if insecure else 'https://')+host+canonical_uri
        req=_u.Request(url,data=payload,method='PUT',headers={
            'x-amz-date':amzdate,'x-amz-content-sha256':ph,'Authorization':auth,
            'Content-Type':'application/octet-stream'})
        with _u.urlopen(req,timeout=90) as r:
            return {'enabled': True, 'pushed': True, 'status': getattr(r,'status',200), 'bucket': bucket, 'object': okey, 'bytes': len(payload)}
    except Exception as exc:
        return {'enabled': True, 'pushed': False, 'error': str(exc)[:200], 'bucket': bucket, 'object': okey}

def api_offsite_backup_test(session):
    """Admin: verify off-site storage credentials/connectivity by uploading a tiny probe object."""
    if not session: return err('Not authenticated')
    if not _ent_admin(session): return err('Admin access required')
    import tempfile as _tmp
    probe=Path(_tmp.gettempdir()) / ('ucc-offsite-test-'+datetime.now().strftime('%Y%m%d%H%M%S')+'.txt')
    try:
        probe.write_text('UCC ERP off-site backup connectivity test @ '+datetime.now().isoformat())
        res=_offsite_backup_push(str(probe), probe.name)
    finally:
        try: probe.unlink()
        except Exception: pass
    if not res.get('enabled'): return err(res.get('reason','Off-site storage not configured'))
    if res.get('pushed'): return ok({'message': 'Off-site upload OK → '+str(res.get('bucket'))+'/'+str(res.get('object')), 'detail': res})
    return err('Off-site upload failed: '+str(res.get('error','unknown')))

def api_create_backup(session, notes='Manual backup'):
    if not session: return err('Not authenticated')
    if not _ent_admin(session): return err('Admin access required')
    _ent_migration()
    bdir = _ent_backup_dir()
    stamp = datetime.now().strftime('%Y%m%d-%H%M%S')
    org = _ent_org_terms()['org_short'].lower()
    name = f"{org}-backup-{stamp}.db"
    dest = bdir / name
    _pruned = 0
    try:
        # Use SQLite's online backup API for a CONSISTENT snapshot that includes
        # committed transactions still sitting in the -wal file. The DB runs in WAL
        # mode, where a raw shutil.copy2 of just the .db can omit recently-committed
        # data (the WAL isn't copied) -> a silently incomplete backup. Fall back to a
        # file copy only if the backup API is unavailable.
        try:
            _src = sqlite3.connect(str(DB_PATH))
            _dst = sqlite3.connect(str(dest))
            try:
                with _dst:
                    _src.backup(_dst)
            finally:
                _dst.close(); _src.close()
        except Exception:
            shutil.copy2(DB_PATH, dest)
        conn=get_db()
        try:
            bid=str(uuid.uuid4())
            conn.execute("INSERT INTO backup_log(id,backup_name,backup_path,backup_size,created_by,notes) VALUES(?,?,?,?,?,?)",
                         (bid,name,str(dest),dest.stat().st_size,session.get('username','system'),notes))
            _audit(conn, session, 'CREATE_BACKUP', 'backup_log', bid, name)
            try:
                _pruned = _ent_prune_backups(conn)
            except Exception:
                _pruned = 0
            conn.commit()
        finally: conn.close()
        # Best-effort off-site copy (S3-compatible) so backups survive a Render disk loss.
        # Never fails the on-disk backup; reports status in the response.
        _offsite = {}
        try: _offsite = _offsite_backup_push(str(dest), name)
        except Exception as _oe: _offsite = {'enabled': True, 'pushed': False, 'error': str(_oe)[:120]}
        return ok({'backup_name': name, 'backup_path': str(dest), 'backup_size': dest.stat().st_size, 'pruned': _pruned, 'offsite': _offsite})
    except Exception as exc:
        return err(f'Backup failed: {exc}')

def api_download_backup(session):
    if not session or not _ent_admin(session):
        return None, None, 'Admin access required'
    r = api_create_backup(session, 'Downloaded backup')
    if not r.get('ok'):
        return None, None, r.get('error','Backup failed')
    path = Path(r['backup_path'])
    return r['backup_name'], path.read_bytes(), None

def api_restore_backup(data, session):
    if not session: return err('Not authenticated')
    if not _ent_admin(session): return err('Admin access required')
    file_data = data.get('file_data') or ''
    if ',' in file_data: file_data = file_data.split(',',1)[1]
    if not file_data: return err('No backup file supplied')
    try:
        raw = __import__('base64').b64decode(file_data)
        if len(raw) < 1000: return err('Backup file is too small or invalid')
        # Safety backup before overwrite.
        api_create_backup(session, 'Automatic backup before restore')
        tmp = DB_PATH.with_suffix('.restore.tmp')
        tmp.write_bytes(raw)
        shutil.copy2(tmp, DB_PATH)
        try: tmp.unlink()
        except Exception: pass
        conn=get_db()
        try:
            _ent_migration()
            _audit(conn, session, 'RESTORE_BACKUP', 'database', 'DB_PATH', data.get('filename','uploaded backup'))
            conn.commit()
        finally: conn.close()
        return ok({'message': 'Database restored. Restart the service to ensure all open connections use the restored file.'})
    except Exception as exc:
        return err(f'Restore failed: {exc}')

def api_export_audit_csv(session, date_from=None, date_to=None, user=None, action=None):
    if not session: return ''
    # [C3] The audit trail aggregates activity across every org unit (it is a
    # cross-unit dataset that cannot be cleanly unit-scoped at the row level), so
    # restrict its export to Admin and Auditor roles. Other roles get an empty CSV.
    if (session.get('role') or '') not in ('Admin', 'Auditor'):
        out = io.StringIO(); w = csv.writer(out)
        w.writerow(['Timestamp','Username','Role','Action','Module','Record ID','Details'])
        return out.getvalue()
    conn=get_db()
    try:
        where, args = _audit_filter_clause(action, user, date_from, date_to)
        q = "SELECT * FROM (" + _audit_union_sql(conn) + ") WHERE " + where + " ORDER BY timestamp DESC"
        try:
            rows = conn.execute(q, args).fetchall()
        except Exception as _se:
            import sys as _sx; print('export_audit_csv warning: %s'%_se,file=_sx.stderr)
            rows = []
        out=io.StringIO(); w=csv.writer(out)
        w.writerow(['Timestamp','Username','Role','Action','Module','Record ID','Details'])
        for r in rows:
            w.writerow([r['timestamp'], r['username'], r['user_role'], r['action'], r['module'], r['record_id'], r['details']])
        return out.getvalue()
    finally: conn.close()

