def _v42_admin(session):
    return bool(session and str(session.get('role','')).lower() == 'admin')

def _v42_finance_or_admin(session):
    return bool(session and str(session.get('role','')).lower() in ('admin','finance officer','finance','accountant'))

def _v42_now():
    return datetime.now().strftime('%Y-%m-%d %H:%M:%S')

def _v42_date():
    return datetime.now().strftime('%Y-%m-%d')

def _v42_hash(v):
    return hashlib.sha256(str(v).encode()).hexdigest()

def _v42_table_exists(conn, t):
    try: return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (t,)).fetchone() is not None
    except Exception: return False

def _v42_col_exists(conn, table, col):
    try: return any(r[1] == col for r in conn.execute(f"PRAGMA table_info({table})").fetchall())
    except Exception: return False

def _v42_add_col(conn, table, col, ddl):
    try:
        if _v42_table_exists(conn, table) and not _v42_col_exists(conn, table, col):
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {col} {ddl}")
    except Exception:
        pass

def _v42_scalar(conn, sql, args=(), default=None):
    try:
        row = conn.execute(sql, args).fetchone()
        return row[0] if row is not None else default
    except Exception:
        return default

def _v42_audit(conn, session, action, module, record_id, details):
    try:
        _audit(conn, session or {'username':'system','role':'System'}, action, module, record_id, details)
    except Exception:
        try:
            conn.execute("INSERT INTO audit_log(id,timestamp,username,user_role,action,module,record_id,details) VALUES(?,?,?,?,?,?,?,?)",
                         (str(uuid.uuid4()), _v42_now(), (session or {}).get('username','system'), (session or {}).get('role','System'), action, module, str(record_id or ''), str(details or '')))
        except Exception:
            pass

