def api_save_mfa_settings(data, session):
    if not session: return err('Not authenticated')
    target_user = data.get('user_id') or session.get('id')
    if target_user != session.get('id') and not _v42_admin(session): return err('Admin access required')
    _v42_migration(); conn=get_db()
    try:
        enabled = 1 if data.get('enabled') in (1,True,'1','true','Yes','yes') else 0
        delivery = data.get('delivery') or 'email'
        email = data.get('email') or _v42_scalar(conn, 'SELECT email FROM users WHERE id=?', (target_user,), '')
        phone = data.get('phone') or ''
        conn.execute("""INSERT INTO mfa_settings(user_id,enabled,delivery,email,phone,updated_by,updated_at)
            VALUES(?,?,?,?,?,?,datetime('now')) ON CONFLICT(user_id) DO UPDATE SET enabled=excluded.enabled,delivery=excluded.delivery,email=excluded.email,phone=excluded.phone,updated_by=excluded.updated_by,updated_at=datetime('now')""",
            (target_user, enabled, delivery, email, phone, session.get('username','system')))
        _v42_audit(conn, session, 'UPDATE_MFA_SETTINGS', 'mfa_settings', target_user, f'enabled={enabled}, delivery={delivery}')
        conn.commit(); return ok({'enabled': enabled})
    finally: conn.close()

def _v42_queue_email(conn, to_email, subject, body):
    eid = str(uuid.uuid4())
    conn.execute("INSERT INTO email_outbox(id,to_email,subject,body,status) VALUES(?,?,?,?,?)", (eid, to_email, subject, body, 'Queued'))
    return eid

def _v42_send_email_now(conn, eid):
    row=conn.execute("SELECT * FROM email_outbox WHERE id=?", (eid,)).fetchone()
    if not row: return False, 'Email record not found'
    host=os.environ.get('SMTP_HOST','').strip(); port=int(os.environ.get('SMTP_PORT','587') or 587)
    user=os.environ.get('SMTP_USER','').strip(); pwd=os.environ.get('SMTP_PASSWORD','').strip()
    sender=os.environ.get('SMTP_FROM','').strip() or user or f'noreply@{V42_ORG_SHORT.lower()}.local'
    if not host:
        conn.execute("UPDATE email_outbox SET status='Queued - SMTP not configured', error=? WHERE id=?", ('Set SMTP_HOST, SMTP_PORT, SMTP_USER, SMTP_PASSWORD and SMTP_FROM in Render.', eid))
        return False, 'SMTP not configured'
    try:
        msg=_V42EmailMessage(); msg['From']=sender; msg['To']=row['to_email']; msg['Subject']=row['subject']; msg.set_content(row['body'])
        with _v42_smtplib.SMTP(host, port, timeout=20) as smtp:
            smtp.starttls()
            if user: smtp.login(user, pwd)
            smtp.send_message(msg)
        conn.execute("UPDATE email_outbox SET status='Sent', sent_at=datetime('now'), error=NULL WHERE id=?", (eid,))
        return True, 'Sent'
    except Exception as exc:
        conn.execute("UPDATE email_outbox SET status='Failed', error=? WHERE id=?", (str(exc)[:500], eid))
        return False, str(exc)

