def _v42_create_mfa_challenge(username, email=None):
    code = str(uuid.uuid4().int)[0:6]
    challenge_id = str(uuid.uuid4())
    conn=get_db()
    try:
        conn.execute("INSERT INTO mfa_challenges(id,username,code_hash,expires_at) VALUES(?,?,?,datetime('now','+10 minutes'))", (challenge_id, username, _v42_hash(code)))
        if email:
            eid=_v42_queue_email(conn, email, f'{V42_APP_NAME} verification code', f'Your {V42_APP_NAME} verification code is: {code}\n\nThis code expires in 10 minutes.')
            _v42_send_email_now(conn, eid)
        conn.commit()
        # Development/SMTP-unconfigured fallback: return masked message and dev code only when explicitly allowed.
        return challenge_id, (code if os.environ.get('ALLOW_DEV_MFA_CODE','1') == '1' and not os.environ.get('SMTP_HOST') else None)
    finally: conn.close()

def api_verify_mfa(data):
    _v42_migration(); username=(data.get('username') or '').strip(); cid=data.get('challenge_id') or ''; code=data.get('code') or ''
    if not username or not cid or not code: return err('Username, challenge and code required')
    conn=get_db()
    try:
        row=conn.execute("SELECT * FROM mfa_challenges WHERE id=? AND username=? AND verified=0 AND expires_at > datetime('now')", (cid, username)).fetchone()
        if not row: return err('Invalid or expired verification code')
        if row['code_hash'] == 'TOTP':
            _vts = ''
            try:
                _vu = conn.execute("SELECT id FROM users WHERE username=?", (username,)).fetchone()
                if _vu:
                    _vr = conn.execute("SELECT COALESCE(totp_secret,'') FROM mfa_settings WHERE user_id=?", (_vu['id'],)).fetchone()
                    _vts = _vr[0] if _vr else ''
            except Exception:
                _vts = ''
            if not (_vts and _totp_check(_vts, code)): return err('Invalid authenticator code')
        elif row['code_hash'] != _v42_hash(code): return err('Invalid or expired verification code')
        conn.execute("UPDATE mfa_challenges SET verified=1 WHERE id=?", (cid,))
        user=conn.execute("SELECT * FROM users WHERE username=? AND active=1", (username,)).fetchone()
        if not user: return err('User not found')
        sid=str(uuid.uuid4()); sessions[sid]={'id':user['id'],'username':user['username'],'full_name':user['full_name'],'role':user['role'],'email':user['email']}
        _v42_audit(conn, sessions[sid], 'MFA_LOGIN_VERIFIED', 'security', user['id'], 'MFA verification successful')
        conn.commit(); return ok({'sid': sid, 'user': sessions[sid]})
    finally: conn.close()

# MFA-aware login wrapper. MFA is optional and disabled until Admin enables it for a user.
try:
    _v42_prev_api_login = api_login
    def api_login(data):
        res = _v42_prev_api_login(data)
        try:
            if res and res.get('ok'):
                _v42_migration(); conn=get_db()
                try:
                    user = res.get('user') or {}
                    enabled = int(_v42_scalar(conn, "SELECT COALESCE(enabled,0) FROM mfa_settings WHERE user_id=?", (user.get('id'),), 0) or 0)
                    # Admin/Finance are MFA-capable; MFA is enforced only if enabled.
                    if enabled and str(user.get('role','')).lower() in ('admin','finance officer','auditor'):
                        sid = res.get('sid')
                        if sid in sessions: del sessions[sid]
                        _mfa_delivery = _v42_scalar(conn, "SELECT COALESCE(delivery,'email') FROM mfa_settings WHERE user_id=?", (user.get('id'),), 'email')
                        if str(_mfa_delivery) == 'totp':
                            _mfa_tsec = _v42_scalar(conn, "SELECT COALESCE(totp_secret,'') FROM mfa_settings WHERE user_id=?", (user.get('id'),), '')
                            if _mfa_tsec:
                                _mfa_cid = str(uuid.uuid4())
                                conn.execute("INSERT INTO mfa_challenges(id,username,code_hash,expires_at) VALUES(?,?,?,datetime('now','+10 minutes'))", (_mfa_cid, user.get('username'), 'TOTP'))
                                conn.commit()
                                return {'ok': False, 'mfa_required': True, 'username': user.get('username'), 'challenge_id': _mfa_cid,
                                        'message': 'Enter the 6-digit code from your authenticator app.'}
                        email = _v42_scalar(conn, "SELECT COALESCE(email,'') FROM mfa_settings WHERE user_id=?", (user.get('id'),), '') or user.get('email')
                        challenge_id, dev_code = _v42_create_mfa_challenge(user.get('username'), email)
                        return {'ok': False, 'mfa_required': True, 'username': user.get('username'), 'challenge_id': challenge_id,
                                'message': 'Verification code required. Check email or ask Admin.', 'dev_code': dev_code}
                finally: conn.close()
        except Exception as exc:
            print('MFA login wrapper warning:', exc)
        return res
except Exception:
    pass

