def _v42_auto_backup_if_due(session=None, silent=False):
    try:
        _v42_migration(); conn=get_db()
        try:
            cfg=conn.execute("SELECT * FROM scheduled_backup_config WHERE id='default'").fetchone()
            if not cfg or not int(cfg['enabled'] or 0): return False
            due=cfg['next_due'] or ''
            if due and due > _v42_now(): return False
        finally: conn.close()
        # api_create_backup already performs admin checks; use system session here for scheduled housekeeping.
        sys_sess={'username':'system-backup','role':'Admin','full_name':'System Backup','email':''}
        r=api_create_backup(sys_sess, 'Automatic scheduled backup') if 'api_create_backup' in globals() else err('Backup function unavailable')
        conn=get_db()
        try:
            freq=max(1, int(_v42_scalar(conn, "SELECT frequency_hours FROM scheduled_backup_config WHERE id='default'", default=24) or 24))
            status='Success' if r.get('ok') else 'Failed: '+str(r.get('error','unknown'))[:160]
            conn.execute("UPDATE scheduled_backup_config SET last_run=datetime('now'), next_due=datetime('now','+'||?||' hours'), last_status=?, updated_at=datetime('now') WHERE id='default'", (freq, status))
            conn.commit()
        finally: conn.close()
        return bool(r.get('ok'))
    except Exception as exc:
        if not silent: print('Scheduled backup warning:', exc)
        return False

