def _v42_csv_rows(text):
    text = text or ''
    if ',' in text[:50] or '\n' in text:
        f=io.StringIO(text)
    else:
        try: f=io.StringIO(_v42_base64.b64decode(text).decode('utf-8-sig'))
        except Exception: f=io.StringIO(text)
    return list(csv.DictReader(f))

def api_import_csv(data, session):
    pe=_v42_require(session, 'import-wizard', 'create')
    if pe: return err(pe)
    _v42_migration(); module=(data.get('module') or '').strip().lower(); filename=data.get('filename') or f'{module}.csv'; rows=_v42_csv_rows(data.get('csv_text') or data.get('file_data') or '')
    if not rows: return err('No CSV rows found. Upload/paste a valid CSV with headers.')
    conn=get_db(); success=0; errors=[]; ob_lines=[]
    try:
        for i,r in enumerate(rows, start=2):
            try:
                if module in ('vendors','vendor','beneficiaries'):
                    api_save_vendor({
                        'vendor_name': r.get('vendor_name') or r.get('name') or r.get('Vendor Name'),
                        'vendor_type': r.get('vendor_type') or r.get('type') or 'Supplier',
                        'tin': r.get('tin') or r.get('TIN'), 'email': r.get('email'), 'phone': r.get('phone'),
                        'bank_name': r.get('bank_name'), 'account_name': r.get('account_name'), 'account_number': r.get('account_number'),
                        'momo_number': r.get('momo_number'), 'compliance_status': r.get('status') or 'Active'
                    }, session); success += 1
                elif module in ('assets','asset-register','asset'):
                    rr={k.lower():v for k,v in r.items()}
                    res=api_save_asset({
                        'asset_code': rr.get('asset_code'), 'asset_name': rr.get('asset_name') or rr.get('name'), 'asset_category': rr.get('asset_category') or rr.get('category'),
                        'owner_code': rr.get('owner_code') or rr.get('unit_code') or rr.get('dept_code'), 'project_id': rr.get('project_id'), 'funding_source': rr.get('funding_source'),
                        'acquisition_date': rr.get('acquisition_date'), 'acquisition_cost': rr.get('acquisition_cost') or 0, 'useful_life_years': rr.get('useful_life_years') or 0,
                        'accumulated_depreciation': rr.get('accumulated_depreciation') or 0, 'location': rr.get('location'), 'custodian': rr.get('custodian'), 'serial_no': rr.get('serial_no'), 'status': rr.get('status') or 'Active', 'notes': rr.get('notes')
                    }, session)
                    if not res.get('ok'): raise Exception(res.get('error'))
                    success += 1
                elif module in ('projects','project'):
                    rr={k.lower():v for k,v in r.items()}
                    res=api_save_project({
                        'project_code': rr.get('project_code') or rr.get('code'), 'title': rr.get('title') or rr.get('project_title'), 'donor': rr.get('donor') or 'Internal', 'division': rr.get('division') or rr.get('unit_code') or rr.get('dept_code') or 'ADMIN',
                        'currency': rr.get('currency') or 'GHS', 'budget_fcy': rr.get('budget_fcy') or rr.get('budget_ghs') or 0, 'fx_rate': rr.get('fx_rate') or 1, 'budget_ghs': rr.get('budget_ghs') or rr.get('budget_fcy') or 0,
                        'start_date': rr.get('start_date') or _v42_date(), 'end_date': rr.get('end_date') or _v42_date(), 'status': rr.get('status') or 'Active', 'pi_name': rr.get('pi_name')
                    }, session)
                    if not res.get('ok'): raise Exception(res.get('error'))
                    success += 1
                elif module in ('opening-balances','opening balances'):
                    # Accumulate one BALANCED opening-balance AJV, posted to the GL after
                    # the loop so the figures appear in the Trial Balance / SFP even before
                    # any transactions. COA codes are resolved STRICTLY (unknown -> reject).
                    rr={k.lower():v for k,v in r.items()}
                    code=(rr.get('coa_code') or rr.get('code') or rr.get('account_code') or '').strip()
                    dr=round(float(rr.get('debit') or 0),2); cr=round(float(rr.get('credit') or 0),2)
                    if dr == 0 and cr == 0: continue
                    if dr and cr: raise Exception('use either debit or credit, not both (%s)' % code)
                    cid=_ih2_coa_id(conn, code)
                    if not cid: raise Exception('chart of account not found (%s)' % (code or '(blank)'))
                    ob_lines.append({'coa_id': cid, 'debit_amount': dr, 'credit_amount': cr,
                                     'description': (rr.get('narration') or 'Opening Balance')})
                    success += 1
                else:
                    raise Exception('Supported modules: vendors, assets, projects, opening-balances')
            except Exception as exc:
                errors.append(f'Line {i}: {exc}')
        # ── Opening balances: post ONE balanced AJV to the GL so the figures show
        #    in the Trial Balance / SFP immediately (idempotent — a re-import
        #    reverses the prior import journal first). Rejected if it doesn't balance.
        ob_jv = None
        if module in ('opening-balances','opening balances') and ob_lines:
            tot_dr = round(sum(l['debit_amount'] for l in ob_lines), 2)
            tot_cr = round(sum(l['credit_amount'] for l in ob_lines), 2)
            if abs(tot_dr - tot_cr) > 0.01:
                errors.append('Opening balances NOT posted: debits (%.2f) must equal credits (%.2f); difference %.2f. Fix the CSV so total debits = total credits.' % (tot_dr, tot_cr, round(tot_dr - tot_cr, 2)))
                success = 0
            else:
                import datetime as _obdt
                _p = (data.get('period') or '').strip()
                ob_date = ((_p + '-01') if len(_p) == 7 else (data.get('opening_date') or data.get('date') or ('%d-01-01' % _obdt.date.today().year)))[:10]
                try:
                    # Post the NEW import first; only then reverse PRIOR imports, so a
                    # failed re-import never deletes existing opening balances.
                    _obid, ob_jv = _create_posted_journal(
                        conn, session, 'AJV', ob_date, 'Opening balances (bulk import)',
                        'OPENING-BAL', None, None, 'opening_balance_import', None, ob_lines)
                    for p in conn.execute("SELECT id FROM journal_vouchers WHERE source_module='opening_balance_import' AND status='Posted' AND id<>?", (_obid,)).fetchall():
                        conn.execute("DELETE FROM general_ledger WHERE jv_id=?", (p['id'],))
                        conn.execute("UPDATE journal_vouchers SET status='Reversed', total_debit=0, total_credit=0 WHERE id=?", (p['id'],))
                except Exception as _obe:
                    conn.rollback()
                    errors.append('Opening balance posting failed: %s' % _obe)
                    success = 0
        jid=str(uuid.uuid4())
        conn.execute("INSERT INTO import_jobs(id,module,filename,total_rows,success_rows,error_rows,created_by,notes) VALUES(?,?,?,?,?,?,?,?)",
                     (jid,module,filename,len(rows),success,len(errors),session.get('username','system'),'\n'.join(errors[:50])))
        _v42_audit(conn, session, 'IMPORT_CSV', 'import_jobs', jid, f'{module}: {success}/{len(rows)} imported')
        conn.commit(); return ok({'job_id':jid,'total_rows':len(rows),'success_rows':success,'error_rows':len(errors),'errors':errors[:20],'opening_balance_jv':ob_jv})
    finally: conn.close()

def api_import_template(session, module):
    module=(module or '').lower()
    templates={
        'vendors':'vendor_name,vendor_type,tin,email,phone,bank_name,account_name,account_number,momo_number,status\nABC Supplies,Supplier,TIN123,abc@example.com,0240000000,GCB,ABC Supplies,123456789,,Active\n',
        'assets':'asset_code,asset_name,asset_category,owner_code,project_id,funding_source,acquisition_date,acquisition_cost,useful_life_years,accumulated_depreciation,location,custodian,serial_no,status,notes\nAST-001,Laptop,ICT,ADMIN,,Internal,2026-01-01,10000,4,0,Main Office,Finance Officer,SN123,Active,\n',
        'projects':'project_code,title,donor,division,currency,budget_fcy,fx_rate,budget_ghs,start_date,end_date,status,pi_name\nPRJ-001,Sample Project,Donor,ADMIN,GHS,100000,1,100000,2026-01-01,2026-12-31,Active,Project Lead\n',
        'opening-balances':'coa_code,account_name,debit,credit,narration\n1010,Bank,10000,0,Opening balance\n3000,Accumulated Fund,0,10000,Opening balance\n'
    }
