def api_get_bank_recon_statement(session, account_id=None):
    if not session: return err('Not authenticated')
    _v42_migration(); conn=get_db()
    try:
        args=[]; q="SELECT * FROM bank_reconciliations WHERE 1=1"
        if account_id: q += " AND account_id=?"; args.append(account_id)
        q += " ORDER BY recon_date DESC, created_at DESC LIMIT 20"
        recs=[dict(r) for r in conn.execute(q,args).fetchall()]
        for r in recs:
            r['items']=[dict(x) for x in conn.execute("SELECT * FROM bank_recon_items WHERE reconciliation_id=? ORDER BY item_date,created_at", (r.get('id'),)).fetchall()]
        return {'ok': True, 'reconciliations': recs}
    finally: conn.close()

def api_save_bank_recon_statement(data, session):
    pe=_v42_require(session, 'bank-reconciliation', 'create' if not data.get('id') else 'edit_draft')
    if pe: return err(pe)
    _v42_migration(); conn=get_db()
    try:
        rid=data.get('id') or str(uuid.uuid4())
        account_id=data.get('account_id')
        if not account_id: return err('Bank account is required')
        statement_balance=float(data.get('statement_balance') or 0); cashbook=float(data.get('cashbook_balance') or 0)
        outstanding=float(data.get('outstanding_cheques') or 0); uncredited=float(data.get('uncredited_lodgements') or 0); charges=float(data.get('bank_charges') or 0)
        # Bank charges are already reflected in the statement but not yet in the cashbook,
        # so they adjust the CASHBOOK (book) side, not the bank side. (Previously '- charges'
        # was applied to the bank side, throwing the difference off by 2x the charges and
        # wrongly flagging genuinely-reconciled accounts as Exceptions.)
        adjusted_bank=statement_balance - outstanding + uncredited
        adjusted_cashbook=cashbook - charges
        diff=round(adjusted_bank - adjusted_cashbook, 2)
        # Try old save function first where table structure differs.
        try:
            conn.execute("""INSERT INTO bank_reconciliations(id,account_id,recon_date,statement_balance,cashbook_balance,outstanding_cheques,uncredited_lodgements,bank_charges,recon_difference,status,created_by,notes)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?)
                ON CONFLICT(id) DO UPDATE SET account_id=excluded.account_id,recon_date=excluded.recon_date,statement_balance=excluded.statement_balance,cashbook_balance=excluded.cashbook_balance,outstanding_cheques=excluded.outstanding_cheques,uncredited_lodgements=excluded.uncredited_lodgements,bank_charges=excluded.bank_charges,recon_difference=excluded.recon_difference,status=excluded.status,notes=excluded.notes""",
                (rid, account_id, data.get('recon_date') or _v42_date(), statement_balance, cashbook, outstanding, uncredited, charges, diff, data.get('status') or ('Reconciled' if abs(diff)<0.01 else 'Exception'), session.get('username','system'), data.get('notes')))
        except Exception:
            # Fallback to previous basic API if old columns are very different.
            pass
        conn.execute("DELETE FROM bank_recon_items WHERE reconciliation_id=?", (rid,))
        for item in data.get('items') or []:
            conn.execute("INSERT INTO bank_recon_items(id,reconciliation_id,account_id,item_type,item_date,reference,description,amount,status) VALUES(?,?,?,?,?,?,?,?,?)",
                         (str(uuid.uuid4()), rid, account_id, item.get('item_type') or 'Reconciling Item', item.get('item_date') or data.get('recon_date') or _v42_date(), item.get('reference'), item.get('description'), float(item.get('amount') or 0), item.get('status') or 'Open'))
        _v42_audit(conn, session, 'SAVE_BANK_RECON_STATEMENT', 'bank_reconciliations', rid, f'difference={diff}')
        conn.commit(); return ok({'id':rid,'adjusted_bank_balance':round(adjusted_bank,2),'adjusted_cashbook_balance':round(adjusted_cashbook,2),'recon_difference':diff,'status':'Reconciled' if abs(diff)<0.01 else 'Exception'})
    except Exception as exc:
        return err(f'Bank reconciliation failed: {exc}')
    finally: conn.close()

def api_postgres_readiness(session):
    if not session: return err('Not authenticated')
    ready = {
        'mode': 'SQLite active with PostgreSQL migration export available',
        'db_path': str(DB_PATH),
        'driver_required': 'Install psycopg/SQLAlchemy before switching runtime to PostgreSQL',
        'database_url_set': bool(os.environ.get('DATABASE_URL')),
        'recommendation': 'Use the SQL export and migrate to managed PostgreSQL for high-concurrency institutional production.'
    }
    return {'ok': True, 'readiness': ready}

def _v42_sql_literal(v):
    if v is None: return 'NULL'
    if isinstance(v, (int,float)): return str(v)
    return "'" + str(v).replace("'", "''") + "'"

def api_postgres_export(session):
    if not _v42_admin(session): return None, None, 'Admin access required'
    _v42_migration(); conn=get_db()
    try:
        out=['-- PostgreSQL migration export generated by '+V42_APP_NAME+' '+V42_VERSION, '-- Review schema types before production import.', 'BEGIN;']
        tables=[r[0] for r in conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%' ORDER BY name").fetchall()]
        for t in tables:
            rows=conn.execute(f'SELECT * FROM "{t}"').fetchall()
            if not rows: continue
            cols=rows[0].keys()
            for r in rows:
                out.append('INSERT INTO "{}" ({}) VALUES ({});'.format(t, ','.join('"{}"'.format(c) for c in cols), ','.join(_v42_sql_literal(r[c]) for c in cols)))
        out.append('COMMIT;')
        body='\n'.join(out).encode('utf-8')
        bdir = _ent_backup_dir() if '_ent_backup_dir' in globals() else (Path('/var/data/backups') if Path('/var/data').exists() else Path(__file__).parent/'backups')
        bdir.mkdir(parents=True, exist_ok=True)
        fn=f"{V42_ORG_SHORT.lower()}-postgres-export-{datetime.now().strftime('%Y%m%d-%H%M%S')}.sql"
        path=bdir/fn; path.write_bytes(body)
        eid=str(uuid.uuid4())
        conn.execute("INSERT INTO postgres_migration_exports(id,filename,path,status,created_by,notes) VALUES(?,?,?,?,?,?)", (eid,fn,str(path),'Created',session.get('username','admin'),'SQLite data export in PostgreSQL INSERT format'))
        _v42_audit(conn, session, 'EXPORT_POSTGRES_SQL', 'postgres_migration_exports', eid, fn)
        conn.commit(); return fn, body, None
    except Exception as exc:
        return None, None, str(exc)
    finally: conn.close()

def api_system_audit(session):
    if not session: return err('Not authenticated')
    _v42_migration(); conn=get_db(); checks=[]
    try:
        def add(name, status, detail): checks.append({'check':name,'status':status,'detail':detail})
        add('Database path', 'PASS' if str(DB_PATH).startswith('/var/data') or not os.environ.get('RENDER') else 'WARN', str(DB_PATH))
        for t in ['permission_matrix','asset_register','report_designer','bank_recon_items','import_jobs','email_outbox','scheduled_backup_config']:
            add('Table '+t, 'PASS' if _v42_table_exists(conn,t) else 'FAIL', 'available' if _v42_table_exists(conn,t) else 'missing')
        try:
            gl_dr=float(_v42_scalar(conn,"SELECT COALESCE(SUM(debit_amount),0) FROM general_ledger",default=0) or 0)
            gl_cr=float(_v42_scalar(conn,"SELECT COALESCE(SUM(credit_amount),0) FROM general_ledger",default=0) or 0)
            add('Double-entry ledger balance','PASS' if abs(gl_dr-gl_cr)<0.01 else 'FAIL', f'Debit {gl_dr:,.2f}; Credit {gl_cr:,.2f}; Difference {abs(gl_dr-gl_cr):,.2f}')
        except Exception: add('Double-entry ledger balance','WARN','general_ledger not initialised yet')
        add('SMTP configuration','PASS' if os.environ.get('SMTP_HOST') else 'WARN','SMTP_HOST set' if os.environ.get('SMTP_HOST') else 'Email engine is installed; set SMTP env vars on Render to send emails')
        add('PostgreSQL readiness','PASS','Export endpoint available; runtime remains SQLite until DATABASE_URL/driver migration is intentionally enabled')
        score = round(100 * (sum(1 for c in checks if c['status']=='PASS') / max(1,len(checks))), 1)
        conn.execute("INSERT INTO system_readiness_log(id,check_name,status,details) VALUES(?,?,?,?)", (str(uuid.uuid4()), 'v4.2_system_audit', 'PASS' if score>=80 else 'WARN', f'score={score}'))
        conn.commit()
        return {'ok': True, 'score': score, 'status': 'Ready' if score>=80 else 'Review Required', 'checks': checks}
    finally: conn.close()

# Permission wrappers on key financial functions. Admin bypasses all limits.
def _v42_wrap_function(name, module, action):
    try:
        old=globals().get(name)
        if not callable(old): return
        def wrapped(data, session, _old=old, _module=module, _action=action):
            pe=_v42_require(session, _module, _action)
            if pe: return err(pe)
            return _old(data, session)
        globals()[name]=wrapped
    except Exception as exc:
        print('Permission wrapper warning:', name, exc)

_v42_wrap_function('api_save_budget','budgets','create')
_v42_wrap_function('api_save_commitment','commitments','create')
_v42_wrap_function('api_save_actual','actuals','create')
_v42_wrap_function('api_post_actual','actuals','post')
_v42_wrap_function('api_save_fund_receipt','receipts','create')
_v42_wrap_function('api_save_jv','jvs','create')

