def _v44_org_prefix():
    return 'AOI' if 'AOI_UNITS' in globals() else 'UCC'

def _v44_app_name():
    return 'AOI-FMS' if _v44_org_prefix() == 'AOI' else 'UCC-FMS'

def _v44_default_password_hash():
    p = 'AOI@2024' if _v44_org_prefix() == 'AOI' else 'UCC@2024'
    return hashlib.sha256(p.encode()).hexdigest()

def _v44_is_admin(session):
    return bool(session and str(session.get('role','')).lower() == 'admin')

def _v44_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False

def _v44_col_exists(conn, table, col):
    try:
        return any(r[1] == col for r in conn.execute(f"PRAGMA table_info({table})").fetchall())
    except Exception:
        return False

def _v44_scalar(conn, sql, args=(), default=0):
    try:
        row = conn.execute(sql, args).fetchone()
        return row[0] if row and row[0] is not None else default
    except Exception:
        return default

def _v44_audit(conn, session, action, table_name, record_id, details):
    try:
        if 'audit_log' in globals():
            _audit(conn, session or {'username':'system','role':'System'}, action, table_name, record_id, details)
        elif _v44_table_exists(conn, 'audit_log'):
            conn.execute("INSERT INTO audit_log(id,username,role,action,table_name,record_id,details) VALUES(?,?,?,?,?,?,?)",
                         (str(uuid.uuid4()), (session or {}).get('username','system'), (session or {}).get('role','System'), action, table_name, record_id, details))
    except Exception:
        pass

def _v44_migration():
    conn = get_db()
    try:
        c = conn.cursor()
        c.execute("""CREATE TABLE IF NOT EXISTS transaction_reference_counters(
            id TEXT PRIMARY KEY, prefix TEXT NOT NULL, reference_type TEXT NOT NULL, year INTEGER NOT NULL,
            last_no INTEGER DEFAULT 0, updated_at TEXT DEFAULT (datetime('now')), UNIQUE(prefix, reference_type, year)
        )""")
        c.execute("""CREATE TABLE IF NOT EXISTS go_live_status_log(
            id TEXT PRIMARY KEY, score REAL, status TEXT, checked_by TEXT, checked_at TEXT DEFAULT (datetime('now')), details TEXT
        )""")
        c.execute("""CREATE TABLE IF NOT EXISTS system_health_snapshots(
            id TEXT PRIMARY KEY, status TEXT, db_path TEXT, db_size_mb REAL, disk_free_mb REAL,
            users_count INTEGER, pending_approvals INTEGER, pending_withholdings INTEGER,
            created_by TEXT, created_at TEXT DEFAULT (datetime('now'))
        )""")
        c.execute("""CREATE TABLE IF NOT EXISTS demo_data_events(
            id TEXT PRIMARY KEY, action TEXT, notes TEXT, performed_by TEXT, performed_at TEXT DEFAULT (datetime('now'))
        )""")
        c.execute("""CREATE TABLE IF NOT EXISTS user_onboarding_state(
            id TEXT PRIMARY KEY, user_id TEXT, step_key TEXT, completed INTEGER DEFAULT 0,
            updated_at TEXT DEFAULT (datetime('now')), UNIQUE(user_id, step_key)
        )""")
        conn.commit()
    finally:
        conn.close()

def _v44_next_reference(conn, ref_type, ref_date=None):
    prefix = _v44_org_prefix()
    try:
        year = int(str(ref_date or date.today())[:4])
    except Exception:
        year = date.today().year
    ref_type = str(ref_type or 'REF').upper().replace(' ', '-')[:12]
    row = conn.execute("SELECT id,last_no FROM transaction_reference_counters WHERE prefix=? AND reference_type=? AND year=?",
                       (prefix, ref_type, year)).fetchone()
    if row:
        n = int(row['last_no'] or 0) + 1
        conn.execute("UPDATE transaction_reference_counters SET last_no=?,updated_at=datetime('now') WHERE id=?", (n, row['id']))
    else:
        n = 1
        conn.execute("INSERT INTO transaction_reference_counters(id,prefix,reference_type,year,last_no) VALUES(?,?,?,?,?)",
                     (str(uuid.uuid4()), prefix, ref_type, year, n))
    return f"{prefix}/{ref_type}/{year}/{n:04d}"

def _v44_peek_reference(conn, ref_type, year=None):
    prefix = _v44_org_prefix()
    year = int(year or date.today().year)
    row = conn.execute("SELECT last_no FROM transaction_reference_counters WHERE prefix=? AND reference_type=? AND year=?",
                       (prefix, ref_type, year)).fetchone()
    n = int(row['last_no'] or 0) + 1 if row else 1
    return f"{prefix}/{ref_type}/{year}/{n:04d}"

def api_reference_preview(session):
    if not session: return err('Not authenticated')
    _v44_migration(); conn = get_db()
    try:
        kinds = ['PV','RV','JV','CMT','WHT','WHVAT','UCF','AST','REC','IMP']
        return {'ok': True, 'prefix': _v44_org_prefix(), 'references': [{'type': k, 'next': _v44_peek_reference(conn, k)} for k in kinds]}
    finally:
        conn.close()

def _v44_validate_payment_ref(data, context='payment'):
    method = str(data.get('payment_method') or data.get('method') or '').strip()
    ref = str(data.get('payment_reference') or data.get('receipt_no') or data.get('reference_no') or data.get('transfer_ref') or '').strip()
    m = method.lower()
    if not method:
        return None
    required = None
    if 'cheque' in m: required = 'Cheque No.'
    elif 'mobile' in m or 'momo' in m: required = 'Mobile Money reference'
    elif 'transfer' in m: required = 'Bank transfer reference'
    elif 'direct debit' in m or 'interbank' in m: required = 'payment reference'
    if required and len(ref) < 3:
        return f'{required} is required for {method} {context}.'
    return None

def _v44_validate_actual_payload(data, session):
    e = _v44_validate_payment_ref(data, 'expenses')
    if e: return e
    try:
        amt = float(data.get('amount_ghs') or data.get('amount_fcy') or 0)
        if amt <= 0: return 'Expense amount must be greater than zero.'
    except Exception:
        return 'Expense amount must be numeric.'
    for flag, amount, label in [('has_whvat','whvat_amount','WHVAT'),('has_ucf','ucf_amount','UCF')]:
        if str(data.get(flag,0)) in ('1','true','True','yes','Yes') and float(data.get(amount) or 0) <= 0:
            return f'{label} amount is required when {label} is selected.'
    if str(data.get('wht_type') or 'None').lower() not in ('none','','n/a') and float(data.get('wht_amount') or 0) <= 0:
        return 'WHT amount is required when a WHT type is selected.'
    return None

def _v44_validate_receipt_payload(data, session):
    # Receipts can be official receipt numbers or transfer references.
    ref = str(data.get('reference_no') or data.get('receipt_no') or data.get('transfer_ref') or '').strip()
    if len(ref) < 2:
        return 'Receipt No. or Transfer Reference is required for fund receipts.'
    try:
        amt = float(data.get('amount_ghs') or data.get('amount_fcy') or 0)
        if amt <= 0: return 'Receipt amount must be greater than zero.'
    except Exception:
        return 'Receipt amount must be numeric.'
    return None

def api_go_live_readiness(session):
    if not session: return err('Not authenticated')
    _v44_migration(); conn = get_db(); checks = []
    try:
        def add(key, label, status, detail, action=None):
            checks.append({'key':key,'label':label,'status':status,'detail':detail,'action':action})
        db_path = str(DB_PATH)
        on_render = bool(os.environ.get('RENDER'))
        add('persistent_disk','Persistent database storage', 'PASS' if (db_path.startswith('/var/data') or not on_render) else 'FAIL', db_path, 'backup-restore')
        admin = conn.execute("SELECT password_hash FROM users WHERE username='admin' LIMIT 1").fetchone() if _v44_table_exists(conn,'users') else None
        default_hash = _v44_default_password_hash()
        add('admin_password','Default admin password changed', 'PASS' if admin and admin['password_hash'] != default_hash else 'WARN', 'Change the default admin password before live institutional use.', 'users')
        backup_enabled = False
        if _v44_table_exists(conn, 'scheduled_backup_config'):
            backup_enabled = bool(_v44_scalar(conn, "SELECT enabled FROM scheduled_backup_config WHERE id='default'", default=0))
        add('backup_schedule','Automatic backup schedule active', 'PASS' if backup_enabled else 'WARN', 'Scheduled backup is active.' if backup_enabled else 'Enable scheduled backup and test backup restore.', 'backup-restore')
        period_count = int(_v44_scalar(conn, "SELECT COUNT(*) FROM accounting_periods", default=0)) if _v44_table_exists(conn,'accounting_periods') else 0
        add('periods','Accounting periods configured', 'PASS' if period_count else 'FAIL', f'{period_count} accounting period(s) found.', 'accounting-periods')
        bank_count = int(_v44_scalar(conn, "SELECT COUNT(*) FROM bank_accounts", default=0)) if _v44_table_exists(conn,'bank_accounts') else 0
        add('banks','Bank accounts configured', 'PASS' if bank_count else 'WARN', f'{bank_count} bank account(s) configured.', 'bank-accounts')
        coa_count = int(_v44_scalar(conn, "SELECT COUNT(*) FROM chart_of_accounts", default=0)) if _v44_table_exists(conn,'chart_of_accounts') else 0
        add('coa','Chart of accounts seeded', 'PASS' if coa_count >= 20 else 'WARN', f'{coa_count} COA line(s) available.', 'coa')
        perm_count = int(_v44_scalar(conn, "SELECT COUNT(*) FROM permission_matrix", default=0)) if _v44_table_exists(conn,'permission_matrix') else 0
        add('permissions','Permission matrix configured', 'PASS' if perm_count else 'WARN', f'{perm_count} permission rule(s) available.', 'permissions')
        approval_count = int(_v44_scalar(conn, "SELECT COUNT(*) FROM approval_rules", default=0)) if _v44_table_exists(conn,'approval_rules') else 0
        add('approvals','Approval rules configured', 'PASS' if approval_count else 'WARN', f'{approval_count} approval rule(s) configured. Admin remains unlimited.', 'approvals')
        add('email','Email notification settings', 'PASS' if os.environ.get('SMTP_HOST') else 'WARN', 'SMTP configured.' if os.environ.get('SMTP_HOST') else 'Set SMTP_HOST and related variables on Render to enable outgoing email alerts.', 'email-notifications')
        backup_count = int(_v44_scalar(conn, "SELECT COUNT(*) FROM backup_log", default=0)) if _v44_table_exists(conn,'backup_log') else 0
        add('latest_backup','Latest backup exists', 'PASS' if backup_count else 'WARN', f'{backup_count} backup log record(s).', 'backup-restore')
        # readiness hardening items (pre-takeoff audit): off-site backup, Auditor login, MFA
        try:
            _off = bool(os.environ.get('BACKUP_S3_BUCKET'))
            add('offsite_backup_cfg','Off-site (S3) backup configured', 'PASS' if _off else 'WARN',
                'Off-site backup target set.' if _off else 'Set BACKUP_S3_BUCKET and keys on the host so backups copy off-server (disaster recovery).', 'backup-schedule')
        except Exception: pass
        try:
            _auditor = int(_v44_scalar(conn, "SELECT COUNT(*) FROM users WHERE role='Auditor'", default=0)) if _v44_table_exists(conn,'users') else 0
            add('auditor_login','Read-only Auditor login created', 'PASS' if _auditor else 'WARN',
                (str(_auditor)+' Auditor login(s) exist.') if _auditor else 'Create a read-only Auditor user for external auditors (Users, role Auditor).', 'users')
        except Exception: pass
        try:
            _mfa = int(_v44_scalar(conn, "SELECT COUNT(*) FROM mfa_settings WHERE COALESCE(enabled,0)=1", default=0)) if _v44_table_exists(conn,'mfa_settings') else 0
            add('mfa_enabled','Multi-factor authentication enabled', 'PASS' if _mfa else 'WARN',
                (str(_mfa)+' account(s) have MFA on.') if _mfa else 'Enable TOTP MFA for Admin/Finance accounts (Security, MFA) before go-live.', 'security-mfa')
        except Exception: pass
        # Pull the quality seal if available.
        try:
            q = api_quality_seal(session)
            qscore = float((q.get('quality') or {}).get('score') or 0)
            add('quality_seal','Quality seal score', 'PASS' if qscore >= 95 else 'WARN', f'Quality score: {qscore:.1f}%.', 'quality-seal')
        except Exception:
            add('quality_seal','Quality seal score', 'WARN', 'Quality endpoint unavailable during check.', 'quality-seal')
        penalty = sum(20 if c['status']=='FAIL' else 5 if c['status']=='WARN' else 0 for c in checks)
        score = max(0, min(100, 100-penalty))
        status = 'Go-Live Ready' if score >= 90 and not any(c['status']=='FAIL' for c in checks) else 'Action Required'
        conn.execute("INSERT INTO go_live_status_log(id,score,status,checked_by,details) VALUES(?,?,?,?,?)",
                     (str(uuid.uuid4()), score, status, session.get('username','system'), json.dumps(checks)))
        conn.commit()
        return {'ok': True, 'score': score, 'status': status, 'checks': checks, 'checked_at': datetime.now().isoformat(timespec='seconds')}
    finally:
        conn.close()

def api_system_health(session):
    if not session: return err('Not authenticated')
    _v44_migration(); conn = get_db()
    try:
        db_path = Path(DB_PATH)
        try:
            usage_path = db_path.parent if db_path.parent.exists() else Path('/')
            du = shutil.disk_usage(str(usage_path))
            disk_free_mb = round(du.free/1024/1024, 1)
            disk_total_mb = round(du.total/1024/1024, 1)
        except Exception:
            disk_free_mb = disk_total_mb = 0
        def count(t, where='1=1'):
            return int(_v44_scalar(conn, f"SELECT COUNT(*) FROM {t} WHERE {where}", default=0)) if _v44_table_exists(conn,t) else 0
        pending_approvals = count('approvals', "status='Pending'")
        pending_withholdings = count('withholding_payables', "status IN ('Pending','Overdue')")
        unposted_expenses = count('actuals', "COALESCE(is_posted,0)=0")
        unposted_receipts = count('fund_receipts', "COALESCE(is_posted,0)=0")
        users = count('users', "COALESCE(active,1)=1")
        last_backup = None
        if _v44_table_exists(conn,'backup_log'):
            try:
                cols = [r[1] for r in conn.execute("PRAGMA table_info(backup_log)").fetchall()]
                name_col = 'filename' if 'filename' in cols else ('backup_name' if 'backup_name' in cols else 'id')
                status_col = 'status' if 'status' in cols else "'Created'"
                rb = conn.execute(f"SELECT {name_col} AS filename, created_at, {status_col} AS status FROM backup_log ORDER BY created_at DESC LIMIT 1").fetchone()
                last_backup = dict(rb) if rb else None
            except Exception:
                last_backup = None
        status = 'Healthy' if pending_approvals + pending_withholdings + unposted_expenses + unposted_receipts == 0 else 'Needs Attention'
        snap = {'status':status,'db_path':str(db_path),'db_size_mb':round(db_path.stat().st_size/1024/1024, 2) if db_path.exists() else 0,
                'disk_free_mb':disk_free_mb,'disk_total_mb':disk_total_mb,'users_count':users,'pending_approvals':pending_approvals,
                'pending_withholdings':pending_withholdings,'unposted_expenses':unposted_expenses,'unposted_receipts':unposted_receipts,'last_backup':last_backup,
                'environment':'Render' if os.environ.get('RENDER') else 'Local/Development'}
        conn.execute("INSERT INTO system_health_snapshots(id,status,db_path,db_size_mb,disk_free_mb,users_count,pending_approvals,pending_withholdings,created_by) VALUES(?,?,?,?,?,?,?,?,?)",
                     (str(uuid.uuid4()), status, str(db_path), snap['db_size_mb'], disk_free_mb, users, pending_approvals, pending_withholdings, session.get('username','system')))
        conn.commit(); return {'ok': True, 'health': snap}
    finally:
        conn.close()

