def api_set_launch_lock(data, session):
    if not _v50_is_admin(session): return err('Admin access required')
    reason=(data or {}).get('reason') or (data or {}).get('change_reason') or ''
    if not reason.strip(): return err('Enter a launch-lock reason or change note.')
    _v50_migration(); conn=get_db()
    try:
        locked = 1 if str((data or {}).get('is_locked', (data or {}).get('locked','0'))).lower() in ('1','true','yes','on') else 0
        conn.execute("""INSERT INTO launch_lock(id,is_locked,locked_at,locked_by,reason,updated_at)
                      VALUES('default',?,?,?,?,?)
                      ON CONFLICT(id) DO UPDATE SET is_locked=excluded.is_locked, locked_at=excluded.locked_at, locked_by=excluded.locked_by, reason=excluded.reason, updated_at=excluded.updated_at""",
                     (locked, _v50_now() if locked else None, session.get('username','admin'), reason, _v50_now()))
        _v50_set_setting(conn, 'LAUNCH_MODE', 'Live Locked' if locked else 'Preparation', session)
        _v50_audit(conn, session, 'SET_LAUNCH_LOCK' if locked else 'REMOVE_LAUNCH_LOCK', 'launch_lock', 'default', reason)
        conn.commit(); return ok({'message':'Launch Lock activated.' if locked else 'Launch Lock removed.', 'is_locked': bool(locked)})
    finally: conn.close()

