def api_migration_template_csv(template_name, session):
    if not session: return 'error\nNot authenticated\n'
    templates=_v50_templates(); name=str(template_name or '').replace('.csv','')
    if name not in templates: return 'error\nUnknown template\n'
    out=io.StringIO(); w=csv.writer(out); cols=templates[name]; w.writerow(cols)
    sample=[]
    for c in cols:
        if 'date' in c: sample.append(date.today().isoformat())
        elif 'amount' in c or 'budget' in c or c in ('debit','credit'): sample.append('0.00')
        elif 'currency' in c: sample.append('GHS')
        elif 'status' in c: sample.append('Active')
        elif 'unit' in c: sample.append('ACECoR' if _v50_org_prefix()=='AOI' else 'MBB')
        elif 'department' in c or c=='dept_code': sample.append('MBB')
        else: sample.append('Sample')
    w.writerow(sample); return out.getvalue()

