# Launch-lock wrappers for live data protection. Admins remain unrestricted but must give reasons after lock.
def _v50_wrap_critical(name, area):
    try:
        old=globals().get(name)
        if not callable(old): return
        def wrapped(data, session, _old=old, _area=area):
            msg=_v50_launch_guard(data or {}, session, _area)
            if msg: return err(msg)
            return _old(data, session)
        globals()[name]=wrapped
    except Exception as exc:
        print('v5.0 critical wrapper warning:', name, exc)

