        add('Mobile responsiveness', 'PASS' if '@media (max-width: 900px)' in idx or 'v502-mobile' in idx else 'WARN', 'Small-screen CSS installed for sidebar, forms, cards and tables.', 'dashboard')
        add('Print/report polish', 'PASS' if 'print-color-adjust' in idx and '@media print' in idx else 'WARN', 'Reports print on clean white surfaces with stable contrast.', 'reports')
        add('Dark-mode form legibility', 'PASS' if '--field-bg' in idx or 'v502-dark-legibility' in idx else 'WARN', 'Dark-mode field and select contrast rules detected.', 'settings')
        add('API secrets excluded from frontend', 'PASS' if 'OPENAI_API_KEY=' not in idx and 'ANTHROPIC_API_KEY=' not in idx else 'FAIL', 'No API key values are embedded in index.html.', 'ai-governance')
        for t in ['users','general_ledger','audit_log']:
            add('Core table: '+t, 'PASS' if _v50_table_exists(conn, t) else 'FAIL', 'Available' if _v50_table_exists(conn, t) else 'Missing', 'system-health')
        try:
            db = str(DB_PATH)
            add('Database storage path', 'PASS' if db.startswith('/var/data') or not os.environ.get('RENDER') else 'WARN', db, 'system-health')
        except Exception as exc:
            add('Database storage path', 'WARN', str(exc), 'system-health')
        open_feedback = 0
        try:
            open_feedback = int(_v50_scalar(conn, "SELECT COUNT(*) FROM pilot_feedback WHERE COALESCE(status,'Open')='Open'", default=0) or 0)
        except Exception: pass
