def api_log_client_error(data, session):
    # Public, anonymous-safe browser error logger. It must not trigger 401 loops
    # before login, and it de-duplicates repeated identical client errors.
    if not session:
        session = {'username': 'anonymous', 'role': 'Guest'}
    data = data or {}
    _v502_migration(); conn = get_db()
    try:
        page = str(data.get('page') or data.get('source') or '')[:120]
        message = str(data.get('message') or '')[:1000]
        stack = str(data.get('stack') or '')[:3000]
        browser = str(data.get('browser') or data.get('user_agent') or '')[:300]
        key = (page, message[:250], stack[:250])
        now_ts = time.time()
        cache = globals().setdefault('_CLIENT_ERROR_DEDUP_CACHE', {})
        # prune old entries and suppress rapid repeats from browser event loops
        for k, t in list(cache.items()):
            if now_ts - t > 30:
                cache.pop(k, None)
        if cache.get(key) and now_ts - cache[key] < 10:
            return {'ok': True, 'deduped': True}
        cache[key] = now_ts
        eid = str(uuid.uuid4())
        conn.execute("""INSERT INTO client_error_log(id,page,message,stack,browser,created_by,created_at)
                      VALUES(?,?,?,?,?,?,?)""", (eid, page, message, stack, browser, session.get('username','anonymous'), _v50_now()))
        conn.commit(); return {'ok': True, 'id': eid}
    finally:
        conn.close()


