# v5.0.22 SBS compatibility: AOI uses unit-normalisation; SBS already uses departments.
def _normalise_unit_payload(data):
    return data or {}
# ─────────────────────────────────────────────────────────────────────────────
# v5.0.22 Official UCC Chart of Accounts as Primary Ledger
# ─────────────────────────────────────────────────────────────────────────────
# This layer removes legacy/default compact COA accounts from the active ledger,
# makes the uploaded UCC IPSAS chart the authoritative account master, populates
# selectable bank accounts from UCC bank COA lines, and links expense/receipt
# posting directly to selected UCC expense/revenue accounts.

_V505_ORG = "SBS"
_V505_OTHER_EXPENSE = "61800005" if _V505_ORG == "AOI" else "61800003"
_V505_DEFAULT_BANK = "12708044" if _V505_ORG == "AOI" else "12703001"
_V505_DEFAULT_REVENUE = "42300029"
_V505_DEFAULT_PAYABLE = "21100021"
_V505_DEFAULT_FUND = "31100001"


def _v505_cols(conn, table):
    try:
        return {r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()}
    except Exception:
        return set()


def _v505_add_column(conn, table, col, decl):
    try:
        if col not in _v505_cols(conn, table):
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {col} {decl}")
    except Exception as exc:
        print(f"v5.0.22 migration note: could not add {table}.{col}: {exc}")


def _v505_is_official_code(code):
    code = str(code or '').strip()
    return code.isdigit() and len(code) == 8


def _v505_coa_by_code(conn, code):
    return conn.execute("SELECT id, code, account_name, category, sub_category, account_type FROM chart_of_accounts WHERE code=?", (str(code),)).fetchone()


def _v505_fallback_for_legacy(row):
    """Return a safe official UCC fallback account code for legacy/default ERP rows."""
    if not row:
        return _V505_OTHER_EXPENSE
    d = dict(row)
    cat = (d.get('category') or '').lower()
    at  = (d.get('account_type') or '').lower()
    name = (d.get('account_name') or '').lower()
    if 'income' in at or 'revenue' in cat:
        return _V505_DEFAULT_REVENUE
    if 'expense' in at or 'expense' in cat:
        return _V505_OTHER_EXPENSE
    if 'liabil' in at or 'payable' in cat or 'creditor' in name:
        return _V505_DEFAULT_PAYABLE
    if 'fund' in cat or 'equity' in at or 'reserve' in name:
        return _V505_DEFAULT_FUND
    if 'bank' in name or 'cash' in name or 'asset' in at or 'asset' in cat:
        return _V505_DEFAULT_BANK
    return _V505_OTHER_EXPENSE


def _v505_official_target_code(conn, legacy_code, row=None):
    legacy_code = str(legacy_code or '').strip()
    if _v505_is_official_code(legacy_code) and _v505_coa_by_code(conn, legacy_code):
        return legacy_code
    try:
        from ucc_chart_of_accounts import coa_alias_candidates
        for candidate in coa_alias_candidates(legacy_code, org=_V505_ORG):
            if _v505_is_official_code(candidate) and _v505_coa_by_code(conn, candidate):
                return candidate
    except Exception:
        pass
    return _v505_fallback_for_legacy(row)


def _v505_relink_coa_id(conn, old_id, new_id, new_code, new_name):
    for tbl, col in [('budgets','coa_id'), ('actuals','expense_coa_id'), ('fund_receipts','income_coa_id'),
                     ('jv_lines','coa_id'), ('general_ledger','coa_id')]:
        try:
            if col in _v505_cols(conn, tbl):
                conn.execute(f"UPDATE {tbl} SET {col}=? WHERE {col}=?", (new_id, old_id))
        except Exception:
            pass
    try:
        conn.execute("UPDATE general_ledger SET coa_code=?, account_name=? WHERE coa_id=?", (new_code, new_name, new_id))
    except Exception:
        pass


def _v505_parse_bank_name(account_name):
    name = str(account_name or '').strip()
    upper = name.upper()
    for b, label in [
        ('ABSA','ABSA Bank'), ('ADB','ADB Bank'), ('GCB','GCB Bank'),
        ('PRUDENTIAL','Prudential Bank'), ('ZENITH','Zenith Bank'),
        ('NIB','NIB Bank'), ('CONSOLIDATED','CBG'), ('CBG','CBG'),
        ('ECOBANK','Ecobank'), ('GHANA INTERNATIONAL','Ghana International Bank'),
        ('STANBIC','Stanbic Bank'), ('FIDELITY','Fidelity Bank'),
        ('CALBANK','CalBank'), ('CAL BANK','CalBank'), ('ACCESS','Access Bank'),
        ('REPUBLIC','Republic Bank'), ('UMB','UMB Bank'), ('BANK OF GHANA','Bank of Ghana'),
    ]:
        if b in upper:
            return label
    if 'FOREIGN ACCOUNT' in upper or 'FOREX ACCOUNT' in upper:
        return 'Foreign Currency Bank'
    if 'BANK' in upper:
        return name.split('-')[0].strip()[:80] or 'Bank'
    # Fallback: leading segment of the account name (before a separator) rather
    # than a generic placeholder, so the real account stays identifiable.
    for sep in (' - ', ' \u2013 ', '-', '\u2013', ':'):
        if sep in name:
            lead = name.split(sep)[0].strip()
            if lead:
                return lead[:80]
    return name[:80] if name else 'Bank Account'


def _v505_account_type_from_name(account_name):
    n = str(account_name or '').upper()
    if 'FOREX' in n:
        return 'Forex'
    if 'FOREIGN' in n:
        return 'Foreign'
    if 'CALL' in n:
        return 'Call'
    return 'Current'


def _v505_currency_from_code_name(code, account_name):
    n = str(account_name or '').upper()
    if 'DOLLAR' in n or 'USD' in n:
        return 'USD'
    if 'POUND' in n:
        return 'GBP'
    if 'EURO' in n:
        return 'EUR'
    return 'GHS'


def _v505_seed_bank_accounts_from_coa(conn):
    _v505_add_column(conn, 'bank_accounts', 'coa_id', 'TEXT')
    rows = conn.execute("""SELECT id, code, account_name FROM chart_of_accounts
                           WHERE code LIKE '127%' AND LENGTH(code)=8
                           ORDER BY code""").fetchall()
    for r in rows:
        code = str(r['code'])
        name = r['account_name']
        existing = conn.execute("SELECT id FROM bank_accounts WHERE account_number=? OR coa_id=?", (code, r['id'])).fetchone()
        bank_name = _v505_parse_bank_name(name)
        acct_type = _v505_account_type_from_name(name)
        curr = _v505_currency_from_code_name(code, name)
        if existing:
            conn.execute("""UPDATE bank_accounts SET coa_id=?, account_name=?, bank_name=?, account_type=?, currency=?, is_active=1
                            WHERE id=?""", (r['id'], name, bank_name, acct_type, curr, existing['id']))
        else:
            conn.execute("""INSERT INTO bank_accounts(id, account_name, bank_name, branch, account_number,
                         account_type, currency, project_id, description, is_active, opening_balance, created_by)
                         VALUES(?,?,?,?,?,?,?,?,?,?,?,?)""",
                         (str(uuid.uuid4()), name, bank_name, '', code, acct_type, curr, None,
                          'Seeded from official UCC Chart of Accounts', 1, 0, 'system'))


def _v505_enforce_ucc_primary_coa(conn=None):
    own_conn = conn is None
    conn = conn or get_db()
    try:
        from ucc_chart_of_accounts import seed_ucc_chart_of_accounts
        _v505_add_column(conn, 'actuals', 'expense_coa_id', 'TEXT')
        _v505_add_column(conn, 'fund_receipts', 'income_coa_id', 'TEXT')
        _v505_add_column(conn, 'bank_accounts', 'coa_id', 'TEXT')
        seed_ucc_chart_of_accounts(conn.cursor(), org=_V505_ORG)

        # Re-link and remove old/default compact accounts so the UCC chart is the active master.
        rows = conn.execute("SELECT * FROM chart_of_accounts ORDER BY code").fetchall()
        for old in rows:
            old_code = str(old['code'])
            if _v505_is_official_code(old_code):
                continue
            target_code = _v505_official_target_code(conn, old_code, old)
            target = _v505_coa_by_code(conn, target_code)
            if not target:
                continue
            _v505_relink_coa_id(conn, old['id'], target['id'], target['code'], target['account_name'])
            try:
                conn.execute("DELETE FROM chart_of_accounts WHERE id=?", (old['id'],))
            except Exception:
                # If an FK prevents deletion, keep it hidden from API by filtering in api_get_coa.
                pass

        _v505_seed_bank_accounts_from_coa(conn)
        conn.execute("INSERT OR REPLACE INTO settings(key,value,description) VALUES(?,?,?)",
                     ('ucc_coa_mode','official_ucc_primary','Official UCC IPSAS Chart of Accounts is the active account master; legacy/default ERP codes are migrated or hidden'))
        conn.commit()
        return True
    finally:
        if own_conn:
            conn.close()


def _v505_filter_coa_rows(conn, kind=None, q=None):
    _v505_enforce_ucc_primary_coa(conn)
    wh = ["LENGTH(code)=8"]
    args = []
    if kind == 'expense':
        wh.append("(account_type='Expense' OR category='Expenses' OR code LIKE '6%')")
    elif kind in ('revenue','income'):
        wh.append("(account_type IN ('Income','Revenue') OR category='Revenue' OR code LIKE '4%')")
    elif kind == 'bank':
        wh.append("code LIKE '127%'")
    if q:
        wh.append("(LOWER(code) LIKE ? OR LOWER(account_name) LIKE ? OR LOWER(category) LIKE ? OR LOWER(sub_category) LIKE ?)")
        needle = '%' + str(q).lower() + '%'
        args += [needle, needle, needle, needle]
    return [dict(r) for r in conn.execute("SELECT * FROM chart_of_accounts WHERE " + " AND ".join(wh) + " ORDER BY code", args).fetchall()]


def api_get_coa(session):
    conn = get_db()
    try:
        return _v505_filter_coa_rows(conn)
    finally:
        conn.close()


