def api_reset_coa(session):
    if session.get('role') != 'Admin':
        return err('Admin access required')
    conn = get_db()
    try:
        _v505_enforce_ucc_primary_coa(conn)
        status = api_coa_ucc_status(session) if 'api_coa_ucc_status' in globals() else {'ok': True}
        try: _audit(conn, session, 'RESET_UCC_COA_PRIMARY', 'chart_of_accounts', 'UCC', 'Official UCC COA enforced as active master')
        except Exception: pass
        conn.commit()
        return {'ok': True, 'message': 'Official UCC Chart of Accounts is now the active account master.', 'status': status}
    finally:
        conn.close()


def _coa_id(conn, code):
    code_str = str(code or '').strip()
    target_code = _v505_official_target_code(conn, code_str, None)
    row = _v505_coa_by_code(conn, target_code)
    if row:
        return row['id']
    row = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (code_str,)).fetchone()
    return row['id'] if row else None


def _v505_bank_coa_id(conn, bank_account_id):
    if bank_account_id:
        b = conn.execute("SELECT * FROM bank_accounts WHERE id=?", (bank_account_id,)).fetchone()
        if b:
            cols = _v505_cols(conn, 'bank_accounts')
            if 'coa_id' in cols and b['coa_id']:
                row = conn.execute("SELECT id FROM chart_of_accounts WHERE id=?", (b['coa_id'],)).fetchone()
                if row: return row['id']
            # account_number is the UCC bank COA code for accounts seeded from the chart
            row = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (str(b['account_number']),)).fetchone()
            if row: return row['id']
    return _coa_id(conn, '1001') or _coa_id(conn, _V505_DEFAULT_BANK)


def _v505_revenue_coa_id(conn, explicit_id=None, budget_id=None, receipt_type=None, donor=None):
    if explicit_id:
        row = conn.execute("SELECT id FROM chart_of_accounts WHERE id=? AND LENGTH(code)=8", (explicit_id,)).fetchone()
        if row: return row['id']
    if budget_id:
        row = conn.execute("""SELECT c.id, c.account_type, c.category, c.code FROM budgets b
                              JOIN chart_of_accounts c ON b.coa_id=c.id WHERE b.id=?""", (budget_id,)).fetchone()
        if row and (str(row['code']).startswith('4') or row['account_type'] in ('Income','Revenue') or row['category']=='Revenue'):
            return row['id']
    try:
        return _receipt_income_account(conn, receipt_type, donor)
    except Exception:
        return _coa_id(conn, _V505_DEFAULT_REVENUE)


def _build_actual_posting(conn, actual_id):
    """Build double-entry lines for an actual expense using the selected official UCC expense COA and bank COA."""
    row = conn.execute("""SELECT a.*, p.project_code, b.coa_id AS budget_coa_id, c.account_name, c.code as coa_code
        FROM actuals a
        JOIN projects p ON a.project_id=p.id
        LEFT JOIN budgets b ON a.budget_id=b.id
        LEFT JOIN chart_of_accounts c ON COALESCE(a.expense_coa_id, b.coa_id)=c.id
        WHERE a.id=?""", (actual_id,)).fetchone()
    if not row:
        raise ValueError('Transaction not found')
    a = dict(row)
    _ensure_period_accepts(conn, a['expense_date'], by_date=True, purpose='expense posting')
    expense_coa = a.get('expense_coa_id') or a.get('budget_coa_id') or _coa_id(conn, _V505_OTHER_EXPENSE)
    bank_coa    = _v505_bank_coa_id(conn, a.get('bank_account_id'))
    wht_coa     = _coa_id(conn, '2030')
    whvat_coa   = _coa_id(conn, '2031') or _coa_id(conn, '21100024')
    ucf_coa     = _coa_id(conn, '2033') or _coa_id(conn, '21100027')
    if not expense_coa or not bank_coa:
        raise ValueError('Required selected expense/bank COA account is missing')

    gross = round(float(a.get('amount_ghs') or 0), 2)
    wht = round(float(a.get('wht_amount') or 0), 2)
    whvat = round(float(a.get('whvat_amount') or 0), 2)
    ucf = round(float(a.get('ucf_amount') or 0), 2)
    net_bank = round(gross - wht - whvat - ucf, 2)
    if net_bank < -0.01:
        raise ValueError('Deductions exceed gross payment')

    ref = a.get('receipt_no') or ''
    pm = a.get('payment_method') or 'Bank Transfer'
    desc = f"{pm}: {a['payee']} — {a['description']}"
    lines = [
        {'coa_id': expense_coa, 'debit_amount': gross, 'credit_amount': 0,
         'description': f"Expense recognised: {a['description']}", 'project_id': a['project_id'], 'bank_account_id': a.get('bank_account_id')},
    ]
    if wht > 0 and wht_coa:
        lines.append({'coa_id': wht_coa, 'debit_amount': 0, 'credit_amount': wht,
                      'description': f"WHT payable — {a.get('wht_type','')}", 'project_id': a['project_id']})
    if whvat > 0 and whvat_coa:
        lines.append({'coa_id': whvat_coa, 'debit_amount': 0, 'credit_amount': whvat,
                      'description': 'WHVAT payable', 'project_id': a['project_id']})
    if ucf > 0 and ucf_coa:
        lines.append({'coa_id': ucf_coa, 'debit_amount': 0, 'credit_amount': ucf,
                      'description': 'UCC Common Fund payable', 'project_id': a['project_id']})
    if net_bank > 0:
        lines.append({'coa_id': bank_coa, 'debit_amount': 0, 'credit_amount': net_bank,
                      'description': f"Payment from bank — {ref or a['actual_code']}",
                      'project_id': a['project_id'], 'bank_account_id': a.get('bank_account_id')})
    return a, desc, ref, lines


# Wrap the existing save functions so selected COA fields are persisted before
# posted-admin reversals/reposts and after new draft creation.
try:
    _v505_prev_api_save_actual = api_save_actual
    def api_save_actual(data, session):
        _v505_enforce_ucc_primary_coa()
        exp = (data or {}).get('expense_coa_id') or (data or {}).get('coa_id') or None
        aid_in = (data or {}).get('id')
        if aid_in and exp:
            conn = get_db()
            try:
                _v505_add_column(conn, 'actuals', 'expense_coa_id', 'TEXT')
                conn.execute("UPDATE actuals SET expense_coa_id=? WHERE id=?", (exp, aid_in))
                conn.commit()
            finally:
                conn.close()
        res = _v505_prev_api_save_actual(data, session)
        if isinstance(res, dict) and res.get('ok') and exp and res.get('id'):
            conn = get_db()
            try:
                _v505_add_column(conn, 'actuals', 'expense_coa_id', 'TEXT')
                conn.execute("UPDATE actuals SET expense_coa_id=? WHERE id=?", (exp, res['id']))
                conn.commit()
            finally:
                conn.close()
        return res
except Exception as _v505_exc:
    print('v5.0.22 actual save wrapper warning:', _v505_exc)

try:
    _v505_prev_api_get_actuals = api_get_actuals
    def api_get_actuals(session, project_id=None):
        _v505_enforce_ucc_primary_coa()
        conn = get_db(); args=[]
        try:
            try: _v505_add_column(conn, 'actuals', 'expense_coa_id', 'TEXT')
            except Exception: pass
            q = """SELECT a.*, p.project_code, p.title as project_title,
                b.budget_code,
                COALESCE(exp.account_name, coa.account_name) as account_name,
                COALESCE(exp.code, coa.code) as coa_code,
                exp.id as expense_coa_id,
                exp.code as expense_coa_code,
                exp.account_name as expense_coa_name,
                cm.commit_code
                FROM actuals a
                JOIN projects p ON a.project_id=p.id
                LEFT JOIN budgets b ON a.budget_id=b.id
                LEFT JOIN chart_of_accounts coa ON b.coa_id=coa.id
                LEFT JOIN chart_of_accounts exp ON a.expense_coa_id=exp.id
                LEFT JOIN commitments cm ON a.commitment_id=cm.id"""
            if project_id:
                q += " WHERE a.project_id=?"; args.append(project_id)
            q += " ORDER BY a.created_at DESC"
            return [dict(r) for r in conn.execute(q, args)]
        finally:
            conn.close()
except Exception as _v505_exc:
    print('v5.0.22 actual get wrapper warning:', _v505_exc)


def _post_receipt_to_gl(conn, session, receipt_id, force=False):
    r = conn.execute("""SELECT fr.*, p.project_code, p.donor as project_donor
        FROM fund_receipts fr JOIN projects p ON fr.project_id=p.id WHERE fr.id=?""", (receipt_id,)).fetchone()
    if not r:
        raise ValueError('Receipt not found')
    r = dict(r)
    if r.get('is_posted') and not force:
        return r.get('jv_id'), None
    _ensure_period_accepts(conn, r['receipt_date'], by_date=True, purpose='fund receipt')
    bank_coa = _v505_bank_coa_id(conn, r.get('bank_account_id'))
    income_coa = _v505_revenue_coa_id(conn, r.get('income_coa_id'), r.get('budget_id'), r.get('receipt_type'), r.get('donor') or r.get('project_donor'))
    if not bank_coa or not income_coa:
        raise ValueError('Required selected bank/revenue COA account is missing')
    amount = round(float(r.get('amount_ghs') or 0), 2)
    desc = f"Fund receipt: {r['donor']} — {r['description']}"
    ref = r.get('reference_no') or r.get('receipt_code') or ''
    _r_unit = r.get('unit_id')
    lines = [
        {'coa_id': bank_coa, 'debit_amount': amount, 'credit_amount': 0, 'description': f"Bank receipt — {ref}", 'project_id': r['project_id'], 'bank_account_id': r.get('bank_account_id'), 'unit_id': _r_unit},
        {'coa_id': income_coa, 'debit_amount': 0, 'credit_amount': amount, 'description': f"Income recognised — {r['description']}", 'project_id': r['project_id'], 'unit_id': _r_unit},
    ]
    jv_id, jv_num = _create_posted_journal(conn, session, 'RV', r['receipt_date'], desc, ref, r['project_id'], r.get('bank_account_id'), 'receipts', receipt_id, lines)
    conn.execute("UPDATE fund_receipts SET is_posted=1, posted_by=?, posted_at=datetime('now'), jv_id=? WHERE id=?", (session['username'], jv_id, receipt_id))
    return jv_id, jv_num

