try:
    _v505_prev_api_get_bank_accounts = api_get_bank_accounts
    def api_get_bank_accounts(session):
        _v505_enforce_ucc_primary_coa()
        conn = get_db()
        try:
            _OBM = "('opening_balance','opening_balance_import','bank_opening_balance')"
            rows = [dict(r) for r in conn.execute("""
                SELECT b.*, c.code as coa_code, c.account_name as coa_account_name,
                    COALESCE((SELECT SUM(amount_ghs) FROM fund_receipts fr WHERE fr.bank_account_id=b.id),0) as legacy_receipts,
                    COALESCE((SELECT SUM(amount_ghs) FROM actuals a WHERE a.bank_account_id=b.id),0) as legacy_payments,
                    COALESCE((SELECT SUM(COALESCE(gl.debit_amount,0)-COALESCE(gl.credit_amount,0)) FROM general_ledger gl LEFT JOIN journal_vouchers jv ON jv.id=gl.jv_id WHERE gl.coa_id=b.coa_id AND COALESCE(jv.source_module,'') IN """+_OBM+"""),0) as gl_opening,
                    COALESCE((SELECT SUM(COALESCE(gl.debit_amount,0)) FROM general_ledger gl LEFT JOIN journal_vouchers jv ON jv.id=gl.jv_id WHERE gl.coa_id=b.coa_id AND COALESCE(jv.source_module,'') NOT IN """+_OBM+"""),0) as gl_receipts,
                    COALESCE((SELECT SUM(COALESCE(gl.credit_amount,0)) FROM general_ledger gl LEFT JOIN journal_vouchers jv ON jv.id=gl.jv_id WHERE gl.coa_id=b.coa_id AND COALESCE(jv.source_module,'') NOT IN """+_OBM+"""),0) as gl_payments,
                    COALESCE((SELECT COUNT(*) FROM general_ledger gl WHERE gl.coa_id=b.coa_id),0) as gl_count,
                    p.project_code, p.title as project_title
                FROM bank_accounts b
                LEFT JOIN chart_of_accounts c ON b.coa_id=c.id
                LEFT JOIN projects p ON b.project_id=p.id
                WHERE b.is_active=1
                ORDER BY c.code, b.bank_name, b.account_name
            """).fetchall()]
            for r in rows:
                # The GENERAL LEDGER is the single source of truth: when the bank's COA
                # has ledger activity, derive opening/receipts/payments from the GL so
                # the balance reflects opening balances posted via import/journal and
                # ties to the Trial Balance / SFP. Otherwise fall back to legacy fields.
                if r.get('coa_id') and (r.get('gl_count') or 0) > 0:
                    r['opening_balance'] = round(float(r.get('gl_opening') or 0), 2)
                    r['total_receipts']  = round(float(r.get('gl_receipts') or 0), 2)
                    r['total_payments']  = round(float(r.get('gl_payments') or 0), 2)
                else:
                    r['total_receipts']  = round(float(r.get('legacy_receipts') or 0), 2)
                    r['total_payments']  = round(float(r.get('legacy_payments') or 0), 2)
                # Display name: never show the generic seed placeholder. Re-derive a
                # meaningful bank label from the account's real name so the list shows
                # e.g. "Zenith Bank" instead of "UCC Bank Account".
                bn = str(r.get('bank_name') or '').strip()
                if (not bn) or bn.lower() in ('ucc bank account', 'bank', 'bank account', 'ucc'):
                    r['bank_name'] = _v505_parse_bank_name(r.get('account_name'))
            return rows
        finally:
            conn.close()
except Exception as _v505_exc:
    print('v5.0.22 bank get wrapper warning:', _v505_exc)

