# ─────────────────────────────────────────────────────────────────────────────
# v5.0.22b UCC COA Bank Master Fix
# ─────────────────────────────────────────────────────────────────────────────
# Ensures every bank account seeded from the official UCC bank COA carries the
# correct chart_of_accounts.id in bank_accounts.coa_id. This lets payment and
# receipt postings credit/debit the selected official bank ledger account.

def _v505_seed_bank_accounts_from_coa(conn):
    _v505_add_column(conn, 'bank_accounts', 'coa_id', 'TEXT')
    rows = conn.execute("""SELECT id, code, account_name FROM chart_of_accounts
                           WHERE code LIKE '127%' AND LENGTH(code)=8
                           ORDER BY code""").fetchall()
    for r in rows:
        code = str(r['code'])
        name = r['account_name']
        existing = conn.execute("SELECT id FROM bank_accounts WHERE account_number=? OR coa_id=?", (code, r['id'])).fetchone()
        bank_name = _v505_parse_bank_name(name)
        acct_type = _v505_account_type_from_name(name)
        curr = _v505_currency_from_code_name(code, name)
        if existing:
            conn.execute("""UPDATE bank_accounts
                            SET coa_id=?, account_name=?, bank_name=?, account_type=?, currency=?, is_active=1
                            WHERE id=?""", (r['id'], name, bank_name, acct_type, curr, existing['id']))
        else:
            conn.execute("""INSERT INTO bank_accounts(id, account_name, bank_name, branch, account_number,
                         account_type, currency, project_id, description, is_active, opening_balance, created_by, coa_id)
                         VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                         (str(uuid.uuid4()), name, bank_name, '', code, acct_type, curr, None,
                          'Seeded from official UCC Chart of Accounts', 1, 0, 'system', r['id']))
    # Backfill any previously-seeded bank rows that carried the UCC account code
    # as account_number but did not have coa_id populated.
    conn.execute("""UPDATE bank_accounts
                    SET coa_id=(SELECT c.id FROM chart_of_accounts c WHERE c.code=bank_accounts.account_number LIMIT 1)
                    WHERE (coa_id IS NULL OR coa_id='')
                      AND account_number IN (SELECT code FROM chart_of_accounts WHERE code LIKE '127%' AND LENGTH(code)=8)""")

try:
    _v505b_prev_init_db = init_db
    def init_db():
        _v505b_prev_init_db()
        try:
            conn = get_db()
            try:
                _v505_seed_bank_accounts_from_coa(conn)
                conn.commit()
                print('  v5.0.22b UCC bank accounts linked to official COA ids')
            finally:
                conn.close()
        except Exception as exc:
            print('v5.0.22b bank COA link warning:', exc)
except Exception:
    pass


# ─────────────────────────────────────────────────────────────────────────────
# v5.0.22c Tax Deduction Validation Alignment
# ─────────────────────────────────────────────────────────────────────────────
# The PV form lets users select WHT/WHVAT/UCF while the backend computes the
# amounts from the gross contract sum. Guardrails therefore validate negative or
# malformed amounts without blocking legitimate computed deductions.

def _v44_validate_actual_payload(data, session):
    e = _v44_validate_payment_ref(data, 'expenses') if '_v44_validate_payment_ref' in globals() else None
    if e: return e
    try:
        amt = float(data.get('amount_ghs') or data.get('amount_fcy') or 0)
        if amt <= 0: return 'Expense amount must be greater than zero.'
    except Exception:
        return 'Expense amount must be numeric.'
    for amount, label in [('whvat_amount','WHVAT'),('ucf_amount','UCF'),('wht_amount','WHT')]:
        if data.get(amount) not in (None, ''):
            try:
                if float(data.get(amount) or 0) < 0:
                    return f'{label} amount cannot be negative.'
            except Exception:
                return f'{label} amount must be numeric.'
    return None


# ─────────────────────────────────────────────────────────────────────────────
# v5.0.22d Selected Revenue COA Receipt Posting
# ─────────────────────────────────────────────────────────────────────────────
# Fund receipts must post to the user-selected official UCC revenue/income COA
# before the RV is created, not after. This final override preserves the earlier
# admin-amendment and audit behaviour while adding income_coa_id to inserts and
# updates before _post_receipt_to_gl() runs.

def api_save_fund_receipt(data, session):
    if not session:
        return err('Not logged in', 401)
    if '_v44_validate_receipt_payload' in globals():
        ve = _v44_validate_receipt_payload(data, session)
        if ve: return err(ve)
    _v505_enforce_ucc_primary_coa()
    data = _normalise_unit_payload(data)
    conn = get_db()
    try:
        rid = data.get('id') or str(uuid.uuid4())
        if data.get('receipt_code'):
            rcode = data.get('receipt_code')
        elif '_v44_next_reference' in globals():
            rcode = _v44_next_reference(conn, 'RV', data.get('receipt_date') or data.get('date'))
        else:
            rcode = f"RCP-{datetime.now().strftime('%Y')}-{str(uuid.uuid4())[:6].upper()}"
        existing = None
        posted_admin_edit = False
        edit_reason = (data.get('edit_reason') or data.get('reason') or '').strip()
        before_snapshot = {}
        if data.get('id'):
            existing = conn.execute("SELECT * FROM fund_receipts WHERE id=?", (rid,)).fetchone()
            if existing and existing['is_posted']:
                if session.get('role') != 'Admin':
                    conn.close(); return err('Posted receipts are locked. Only Admin can edit posted receipts.')
                if len(edit_reason) < 5:
                    conn.close(); return err('Admin edit reason is required for posted receipts')
                posted_admin_edit = True
                before_snapshot = _compact_snapshot(existing, ['receipt_code','project_id','bank_account_id','budget_id','income_coa_id','receipt_date','donor','description','currency','amount_fcy','fx_rate','amount_ghs','reference_no','receipt_type','jv_id'])

        project_id = data.get('project_id') or None
        if not project_id:
            unit = canonical_unit_code(data.get('unit') or data.get('unit_code') or data.get('dept_code') or data.get('division'))
            try:
                project_id = _get_or_create_general_project(conn, unit, session)
            except Exception as exc:
                conn.close(); return err(str(exc))
        else:
            pr = conn.execute("SELECT id FROM projects WHERE id=?", (project_id,)).fetchone()
            if not pr:
                conn.close(); return err('Selected donor project was not found')

        receipt_date = data.get('receipt_date') or data.get('date') or datetime.now().strftime('%Y-%m-%d')
        donor = (data.get('donor') or data.get('source') or '').strip()
        description = (data.get('description') or '').strip()
        if not donor or not description:
            conn.close(); return err('Donor/source and description are required')
        currency = data.get('currency') or 'GHS'
        try:
            amount_fcy = float(data.get('amount_fcy') or 0)
            fx_rate = float(data.get('fx_rate') or 1)
        except (TypeError, ValueError):
            conn.close(); return err('Amount and FX rate must be numeric')
        if amount_fcy <= 0 or fx_rate <= 0:
            conn.close(); return err('Amount and FX rate must be greater than zero')
        amount_ghs = round(amount_fcy * fx_rate, 2)
        reference_no = data.get('reference_no') or data.get('receipt_no') or data.get('transfer_ref') or ''
        receipt_type = data.get('receipt_type','Grant Receipt')
        budget_id = data.get('budget_id') or None
        income_coa_id = data.get('income_coa_id') or data.get('revenue_coa_id') or None
        if income_coa_id:
            ok_income = conn.execute("""SELECT id FROM chart_of_accounts
                                      WHERE id=? AND LENGTH(code)=8
                                        AND (code LIKE '4%' OR account_type IN ('Income','Revenue') OR category='Revenue')""", (income_coa_id,)).fetchone()
            if not ok_income:
                conn.close(); return err('Select a valid official UCC revenue/income COA account')

        if existing:
            conn.execute("""UPDATE fund_receipts SET project_id=?,bank_account_id=?,budget_id=?,income_coa_id=?,receipt_date=?,
                donor=?,description=?,currency=?,amount_fcy=?,fx_rate=?,amount_ghs=?,
                reference_no=?,receipt_type=?,notes=? WHERE id=?""",
                (project_id,data.get('bank_account_id') or None,budget_id,income_coa_id,receipt_date,donor,description,currency,amount_fcy,
                 fx_rate,amount_ghs,reference_no,receipt_type,data.get('notes',''),rid))
        else:
            conn.execute("""INSERT INTO fund_receipts(id,receipt_code,project_id,bank_account_id,budget_id,income_coa_id,
                receipt_date,donor,description,currency,amount_fcy,fx_rate,amount_ghs,
                reference_no,receipt_type,notes,created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (rid,rcode,project_id,data.get('bank_account_id') or None,budget_id,income_coa_id,receipt_date,donor,description,currency,amount_fcy,
                 fx_rate,amount_ghs,reference_no,receipt_type,data.get('notes',''),session['username']))

        if posted_admin_edit:
            old_jv_id = before_snapshot.get('jv_id')
            rev_id, rev_num = _auto_reverse_posted_journal(conn, session, old_jv_id, 'fund_receipts', rid, edit_reason)
            jv_id, jv_num = _post_receipt_to_gl(conn, session, rid, force=True)
            conn.execute("""UPDATE fund_receipts SET amended_by=?, amended_at=datetime('now'),
                amendment_reason=?, amendment_count=COALESCE(amendment_count,0)+1,
                last_reversal_jv_id=? WHERE id=?""",
                (session['username'], edit_reason, rev_id, rid))
            after_row = conn.execute("SELECT * FROM fund_receipts WHERE id=?", (rid,)).fetchone()
            after_snapshot = _compact_snapshot(after_row, ['receipt_code','project_id','bank_account_id','budget_id','income_coa_id','receipt_date','donor','description','currency','amount_fcy','fx_rate','amount_ghs','reference_no','receipt_type','jv_id'])
            detail = json.dumps({'reason': edit_reason, 'reversed_jv': rev_num, 'new_jv': jv_num,
                                 'before': before_snapshot, 'after': after_snapshot}, default=str)[:3500]
            _audit(conn, session, 'ADMIN_EDIT_POSTED_RECEIPT', 'fund_receipts', rid, detail)
            conn.commit(); conn.close()
            return {'ok': True, 'id': rid, 'jv_id': jv_id, 'jv_number': jv_num,
                    'message': f'Posted receipt amended. {rev_num or "Old JV"} reversed and {jv_num} posted.'}

        jv_id, jv_num = _post_receipt_to_gl(conn, session, rid)
        _audit(conn, session, 'SAVE_FUND_RECEIPT', 'fund_receipts', rid, f"{donor} {amount_ghs:.2f} GHS | {jv_num or 'posted'}")
        conn.commit(); conn.close()
        return {'ok': True, 'id': rid, 'jv_id': jv_id, 'jv_number': jv_num}
    except Exception as exc:
        conn.rollback(); conn.close()
        return {'ok': False, 'error': f'Receipt save failed: {exc}'}


# v5.0.22e SBS accounting-period compatibility helpers for UCC receipt posting.
# AOI already defines these; SBS receives safe equivalents here.
try:
    _ensure_period_accepts
except NameError:
    def _parse_iso_date(value):
        if not value:
            return None
        try:
            return datetime.strptime(str(value)[:10], '%Y-%m-%d').date().isoformat()
        except Exception:
            return None
    def _period_row_for_date(conn, value):
        d = _parse_iso_date(value)
        if not d:
            return None
        try:
            row = conn.execute("""SELECT * FROM accounting_periods
                   WHERE start_date IS NOT NULL AND end_date IS NOT NULL
                     AND date(start_date) <= date(?) AND date(end_date) >= date(?)
                   ORDER BY date(start_date) DESC LIMIT 1""", (d, d)).fetchone()
            if row: return row
        except Exception:
            pass
        try:
            return conn.execute("SELECT * FROM accounting_periods WHERE period=?", (d[:7],)).fetchone()
        except Exception:
            return None
    def _ensure_period_accepts(conn, period_or_date, *, by_date=True, purpose='transaction'):
        row = _period_row_for_date(conn, period_or_date) if by_date else conn.execute("SELECT * FROM accounting_periods WHERE period=?", (period_or_date,)).fetchone()
        code = (row['period'] if row and 'period' in row.keys() else (str(period_or_date)[:7] if by_date else period_or_date))
        if row and row['status'] in ('Closed','Locked'):
            raise ValueError(f'Accounting period {code} is {row["status"]}. Re-open it before recording or posting this {purpose}.')
        return code


# v5.0.22f SBS posted-journal helper for selected UCC receipt COA flow.
try:
    _create_posted_journal
except NameError:
    def _create_posted_journal(conn, session, jv_type, jv_date, description, reference, project_id, bank_account_id, source_module, source_id, lines):
        clean = []
        total_dr = total_cr = 0.0
        for line in lines:
            dr = round(float(line.get('debit_amount') or 0), 2)
            cr = round(float(line.get('credit_amount') or 0), 2)
            if dr <= 0 and cr <= 0:
                continue
            if dr > 0 and cr > 0:
                raise ValueError('A journal line cannot have both debit and credit')
            coa_id = line.get('coa_id')
            coa = conn.execute("SELECT code, account_name FROM chart_of_accounts WHERE id=?", (coa_id,)).fetchone()
            if not coa:
                raise ValueError('Invalid chart of accounts line')
            item = dict(line); item['debit_amount']=dr; item['credit_amount']=cr; item['coa_code']=coa['code']; item['account_name']=coa['account_name']
            clean.append(item); total_dr += dr; total_cr += cr
        total_dr = round(total_dr, 2); total_cr = round(total_cr, 2)
        if not clean or abs(total_dr-total_cr) > 0.01:
            raise ValueError(f'Journal is not balanced: DR {total_dr:.2f} CR {total_cr:.2f}')
        jv_id = str(uuid.uuid4())
        jv_num = _next_jv_number(conn, jv_type)
        period = _ensure_period_accepts(conn, jv_date or datetime.now().strftime('%Y-%m-%d'), by_date=True, purpose=f'{jv_type} posting')
        _wunit = _ucc_resolve_write_unit(conn, None, session) if '_ucc_resolve_write_unit' in globals() else None
        conn.execute("""INSERT INTO journal_vouchers
            (id,jv_number,jv_type,jv_date,period,description,narration,reference,project_id,
             bank_account_id,currency,fx_rate,total_debit,total_credit,status,prepared_by,
             submitted_by,submitted_at,approved_by,approved_at,posted_by,posted_at,
             auto_generated,source_module,source_id,notes,unit_id)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,datetime('now'),?,datetime('now'),?,datetime('now'),?,?,?,?,?)""",
            (jv_id,jv_num,jv_type,jv_date,period,description,description,reference or '',project_id,
             bank_account_id,'GHS',1,total_dr,total_cr,'Posted',session['username'],session['username'],
             session['username'],session['username'],1,source_module,source_id,'System auto-posted from operational transaction',_wunit))
        for i, line in enumerate(clean, start=1):
            line_id = str(uuid.uuid4())
            conn.execute("""INSERT INTO jv_lines
                (id,jv_id,line_number,coa_id,description,debit_amount,credit_amount,project_id,cost_centre,bank_account_id,tax_code)
                VALUES(?,?,?,?,?,?,?,?,?,?,?)""",
                (line_id,jv_id,i,line['coa_id'],line.get('description',description),line['debit_amount'],line['credit_amount'],
                 line.get('project_id') or project_id,line.get('cost_centre',''),line.get('bank_account_id') or bank_account_id,line.get('tax_code','')))
            proj_code = ''
            if line.get('project_id') or project_id:
                pr = conn.execute("SELECT project_code FROM projects WHERE id=?", (line.get('project_id') or project_id,)).fetchone()
                proj_code = pr['project_code'] if pr else ''
            conn.execute("""INSERT INTO general_ledger
                (id,jv_id,jv_number,jv_line_id,ledger_date,period,coa_id,coa_code,account_name,description,
                 debit_amount,credit_amount,project_id,project_code,posted_by,unit_id)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (str(uuid.uuid4()),jv_id,jv_num,line_id,jv_date,period,line['coa_id'],line['coa_code'],line['account_name'],
                 line.get('description',description),line['debit_amount'],line['credit_amount'],line.get('project_id') or project_id,proj_code,session['username'],(line.get('unit_id') or _wunit)))
        try: _jv_audit(conn, session, jv_id, jv_num, 'AUTO_POST', None, 'Posted', f'{source_module}:{source_id}')
        except Exception: pass
        try: _audit(conn, session, 'AUTO_POST_JV', 'journal_vouchers', jv_id, f'{jv_num}: {description}')
        except Exception: pass
        return jv_id, jv_num


# ─────────────────────────────────────────────────────────────────────────────
# v5.0.22g Dynamic COA Relink Sanitiser
# ─────────────────────────────────────────────────────────────────────────────
# Any table that carries a coa_id field is now relinked from old/default accounts
# to the official UCC account before legacy rows are removed. This prevents
# hidden conflicts in future modules such as assets, bank accounts or imports.

def _v505_relink_coa_id(conn, old_id, new_id, new_code, new_name):
    try:
        tables = [r[0] for r in conn.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()]
    except Exception:
        tables = []
    for tbl in tables:
        try:
            cols = _v505_cols(conn, tbl)
            if 'coa_id' in cols:
                conn.execute(f'UPDATE "{tbl}" SET coa_id=? WHERE coa_id=?', (new_id, old_id))
            if tbl == 'actuals' and 'expense_coa_id' in cols:
                conn.execute('UPDATE actuals SET expense_coa_id=? WHERE expense_coa_id=?', (new_id, old_id))
            if tbl == 'fund_receipts' and 'income_coa_id' in cols:
                conn.execute('UPDATE fund_receipts SET income_coa_id=? WHERE income_coa_id=?', (new_id, old_id))
        except Exception:
            pass
    try:
        conn.execute("UPDATE general_ledger SET coa_code=?, account_name=? WHERE coa_id=?", (new_code, new_name, new_id))
    except Exception:
        pass


# ─────────────────────────────────────────────────────────────────────────────
# v5.0.22 Default Period, Final Audit & Transaction Flow Hardening
# ─────────────────────────────────────────────────────────────────────────────
# This production hardening layer removes old/closed/locked seed periods and
# installs one official open reporting window for the 2026 financial year.  It
# also exposes a final audit endpoint and tightens period acceptance so all
# PV/RV/JV posting flows resolve to the official FY2026 range.

_V506_PERIOD_CODE = '2026'
_V506_PERIOD_NAME = 'Financial Year 2026'
_V506_PERIOD_START = '2026-01-01'
_V506_PERIOD_END = '2026-12-31'
_V506_APP_NAME = 'UCC-FMS'
_V506_ACADEMIC_YEAR = '2025/2026'
_V506_SEMESTER = 'Second Semester'

def _v506_cols(conn, table):
    try:
        return {r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()}
    except Exception:
        return set()

def _v506_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False

def _v506_add_col(conn, table, ddl):
    col = ddl.split()[0]
    try:
        if col not in _v506_cols(conn, table):
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {ddl}")
    except Exception:
        pass

def _v506_audit(conn, action, module, record_id, details):
    try:
        if _v506_table_exists(conn, 'audit_log'):
            conn.execute("""INSERT INTO audit_log(id, username, user_role, action, module, record_id, details, ip_address)
                         VALUES(?,?,?,?,?,?,?,?)""",
                         (str(uuid.uuid4()), 'system', 'System', action, module, record_id, details, 'startup'))
    except Exception:
        pass

def _v506_install_default_period(conn):
    """Replace old accounting periods with one official open FY2026 period."""
    if not _v506_table_exists(conn, 'accounting_periods'):
        conn.execute("""CREATE TABLE IF NOT EXISTS accounting_periods(
            id TEXT PRIMARY KEY, period TEXT UNIQUE NOT NULL, period_name TEXT NOT NULL,
            start_date TEXT, end_date TEXT, status TEXT DEFAULT 'Open', opened_by TEXT,
            opened_at TEXT, closed_by TEXT, closed_at TEXT, created_at TEXT DEFAULT (datetime('now'))
        )""")
    for ddl in ['start_date TEXT','end_date TEXT','opened_by TEXT','opened_at TEXT','closed_by TEXT','closed_at TEXT']:
        _v506_add_col(conn, 'accounting_periods', ddl)
    try:
        before = conn.execute("SELECT COUNT(*) FROM accounting_periods").fetchone()[0]
    except Exception:
        before = 0
    # IDEMPOTENT: ensure the official FY period EXISTS without disturbing any
    # period an admin has Closed/Locked. Deleting all periods on every startup
    # silently reopened closed years on each redeploy (data-integrity bug).
    cols = _v506_cols(conn, 'accounting_periods')
    _fy_exists = conn.execute("SELECT COUNT(*) FROM accounting_periods WHERE period=?", (_V506_PERIOD_CODE,)).fetchone()[0]
    if not _fy_exists:
        if 'opened_at' in cols:
            conn.execute("""INSERT INTO accounting_periods
                (id,period,period_name,start_date,end_date,status,opened_by,opened_at,created_at)
                VALUES(?,?,?,?,?,?,?,datetime('now'),datetime('now'))""",
                (str(uuid.uuid4()), _V506_PERIOD_CODE, _V506_PERIOD_NAME,
                 _V506_PERIOD_START, _V506_PERIOD_END, 'Open', 'system-v5.0.22'))
        else:
            conn.execute("""INSERT INTO accounting_periods
                (id,period,period_name,start_date,end_date,status,opened_by)
                VALUES(?,?,?,?,?,?,?)""",
                (str(uuid.uuid4()), _V506_PERIOD_CODE, _V506_PERIOD_NAME,
                 _V506_PERIOD_START, _V506_PERIOD_END, 'Open', 'system-v5.0.22'))
    # Record settings so readiness panels and the chatbot can explain the live context.
    try:
        if _v506_table_exists(conn, 'settings'):
            for k,v,d in [
                ('default_accounting_period', _V506_PERIOD_CODE, 'Default live reporting period'),
                ('default_period_start', _V506_PERIOD_START, 'Default accounting period start date'),
                ('default_period_end', _V506_PERIOD_END, 'Default accounting period end date'),
                ('period_policy', 'Single open FY2026 period; old closed/locked periods removed at take-off', 'Accounting-period policy')
            ]:
                conn.execute("INSERT OR REPLACE INTO settings(key,value,description) VALUES(?,?,?)", (k,v,d))
        if _v506_table_exists(conn, 'app_settings'):
            for k,v in [
                ('DEFAULT_ACCOUNTING_PERIOD', _V506_PERIOD_CODE),
                ('DEFAULT_PERIOD_START', _V506_PERIOD_START),
                ('DEFAULT_PERIOD_END', _V506_PERIOD_END),
                ('APP_VERSION', 'v5.0.22 Final Audit Build')
            ]:
                conn.execute("""INSERT INTO app_settings(setting_key,setting_value,updated_by,updated_at)
                              VALUES(?,?,?,datetime('now'))
                              ON CONFLICT(setting_key) DO UPDATE SET setting_value=excluded.setting_value, updated_by='system-v5.0.22', updated_at=datetime('now')""",
                             (k,v,'system-v5.0.22'))
    except Exception:
        pass
    if _V506_APP_NAME == 'UCC-FMS':
        _v506_set_sbs_academic_context(conn)
    _v506_audit(conn, 'V506_DEFAULT_PERIOD_INSTALLED', 'accounting_periods', _V506_PERIOD_CODE,
                f'Replaced {before} accounting period row(s) with 01-Jan-2026 to 31-Dec-2026 Open period')

def _v506_set_sbs_academic_context(conn):
    """Install SBS current academic context across settings stores."""
    try:
        if _v506_table_exists(conn, 'settings'):
            for k,v,d in [
                ('academic_year', _V506_ACADEMIC_YEAR, 'Current academic year'),
                ('semester', _V506_SEMESTER, 'Current academic semester'),
                ('academic_context', f'{_V506_ACADEMIC_YEAR} Academic Year, {_V506_SEMESTER}', 'Current SBS teaching/reporting context')
            ]:
                conn.execute("INSERT OR REPLACE INTO settings(key,value,description) VALUES(?,?,?)", (k,v,d))
        if _v506_table_exists(conn, 'app_settings'):
            for k,v in [('ACADEMIC_YEAR',_V506_ACADEMIC_YEAR),('SEMESTER',_V506_SEMESTER),('ACADEMIC_CONTEXT',f'{_V506_ACADEMIC_YEAR} Academic Year, {_V506_SEMESTER}')]:
                conn.execute("""INSERT INTO app_settings(setting_key,setting_value,updated_by,updated_at)
                              VALUES(?,?,?,datetime('now'))
                              ON CONFLICT(setting_key) DO UPDATE SET setting_value=excluded.setting_value, updated_by='system-v5.0.22', updated_at=datetime('now')""",
                             (k,v,'system-v5.0.22'))
    except Exception:
        pass

# Override period resolvers so transactional modules cannot fall back to legacy monthly periods.
def _period_row_for_date(conn, value):
    try:
        d = str(value or '')[:10]
        return conn.execute("""SELECT * FROM accounting_periods
                   WHERE start_date IS NOT NULL AND end_date IS NOT NULL
                     AND date(start_date) <= date(?) AND date(end_date) >= date(?)
                   ORDER BY date(start_date) DESC LIMIT 1""", (d, d)).fetchone()
    except Exception:
        return None

def _period_code_for_date(conn, value):
    row = _period_row_for_date(conn, value)
    return row['period'] if row else _V506_PERIOD_CODE

def _ensure_period_accepts(conn, period_or_date, *, by_date=True, purpose='transaction'):
    if by_date:
        row = _period_row_for_date(conn, period_or_date)
    else:
        row = conn.execute("SELECT * FROM accounting_periods WHERE period=?", (period_or_date,)).fetchone()
    if not row:
        raise ValueError(f'The date {str(period_or_date)[:10]} is outside the active accounting period 01-Jan-2026 to 31-Dec-2026. Use a 2026 transaction date or open a valid period.')
    if row['status'] in ('Closed','Locked'):
        raise ValueError(f'Accounting period {row["period"]} is {row["status"]}. Re-open it before recording or posting this {purpose}.')
    return row['period']

# SBS uses _ensure_accounting_period/_assert_period_open in some earlier flows;
# override them too when present so they never auto-create legacy monthly periods.
def _ensure_accounting_period(conn, txn_date):
    row = _period_row_for_date(conn, txn_date or _V506_PERIOD_START)
    if row:
        return row
    raise ValueError(f'Transaction date {str(txn_date or "")[:10]} is outside the default open FY2026 period.')

def _assert_period_open(conn, txn_date):
    row = _ensure_accounting_period(conn, txn_date)
    if row and row['status'] == 'Open':
        return True, row['period']
    return False, f"Accounting period {row['period'] if row else _V506_PERIOD_CODE} is not Open."

def api_get_accounting_periods(session):
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        _v506_install_default_period(conn)
        conn.commit()
        return [dict(r) for r in conn.execute("SELECT * FROM accounting_periods ORDER BY start_date DESC").fetchall()]
    finally:
        conn.close()

def _v506_final_checks(conn):
    checks = []
    def add(name, ok_flag, detail):
        checks.append({'check': name, 'status': 'PASS' if ok_flag else 'WARN', 'detail': detail})
    try:
        periods = [dict(r) for r in conn.execute("SELECT period,period_name,start_date,end_date,status FROM accounting_periods").fetchall()]
    except Exception:
        periods = []
    add('Default accounting period', len(periods)==1 and periods[0].get('period')=='2026' and periods[0].get('status')=='Open', f'{len(periods)} period row(s) configured')
    add('FY2026 date range', bool(periods and periods[0].get('start_date')==_V506_PERIOD_START and periods[0].get('end_date')==_V506_PERIOD_END), 'Expected 2026-01-01 to 2026-12-31')
    try:
        dr = float(conn.execute("SELECT COALESCE(SUM(debit_amount),0) FROM general_ledger").fetchone()[0] or 0)
        cr = float(conn.execute("SELECT COALESCE(SUM(credit_amount),0) FROM general_ledger").fetchone()[0] or 0)
        add('Double-entry ledger balance', abs(dr-cr) < 0.01, f'DR {dr:,.2f} / CR {cr:,.2f}')
    except Exception as exc:
        add('Double-entry ledger balance', False, f'Unable to verify ledger: {exc}')
    try:
        legacy = conn.execute("SELECT COUNT(*) FROM chart_of_accounts WHERE LENGTH(code)<8").fetchone()[0]
        add('Official UCC COA primary', legacy == 0, f'{legacy} short legacy account code(s) remain active')
    except Exception:
        add('Official UCC COA primary', False, 'COA table check unavailable')
    try:
        banks = conn.execute("SELECT COUNT(*) FROM bank_accounts WHERE is_active=1 AND coa_id IS NOT NULL").fetchone()[0]
        add('UCC bank selector population', banks > 0, f'{banks} bank account(s) linked to COA')
    except Exception:
        add('UCC bank selector population', False, 'Bank selector check unavailable')
    if _V506_APP_NAME == 'UCC-FMS':
        try:
            row = conn.execute("SELECT value FROM settings WHERE key='academic_context'").fetchone()
            add('SBS academic context', bool(row and _V506_ACADEMIC_YEAR in row[0] and _V506_SEMESTER in row[0]), row[0] if row else 'Not configured')
        except Exception:
            add('SBS academic context', False, 'Academic context unavailable')
    score = round((sum(1 for c in checks if c['status']=='PASS') / max(1,len(checks))) * 100)
    return {'ok': True, 'score': score, 'rating': 'World-Class Ready' if score == 100 else 'Ready with Review Items', 'checks': checks,
            'default_period': {'period': _V506_PERIOD_CODE, 'period_name': _V506_PERIOD_NAME, 'start_date': _V506_PERIOD_START, 'end_date': _V506_PERIOD_END, 'status': 'Open'},
            'academic_context': f'{_V506_ACADEMIC_YEAR} Academic Year, {_V506_SEMESTER}' if _V506_APP_NAME == 'UCC-FMS' else None}

def api_final_system_audit(session):
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        _v506_install_default_period(conn)
        conn.commit()
        return _v506_final_checks(conn)
    finally:
        conn.close()

