# ---------------------------------------------------------------------------
# v5.0.22 Payment Classification + COA Integrity Patch
# ---------------------------------------------------------------------------
def _v507_cols(conn, table):
    try:
        return {r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()}
    except Exception:
        return set()

def _v507_add_column(conn, table, col, typ):
    try:
        # Only patch existing tables. During a fresh Render boot this helper may
        # be imported before init_db() has created the actuals table; silently
        # deferring the column patch keeps startup logs clean and avoids false alarms.
        exists = conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone()
        if not exists:
            return
        if col not in _v507_cols(conn, table):
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {col} {typ}")
    except Exception as exc:
        print(f"v5.0.22 column patch warning {table}.{col}: {exc}")

def _v507_ensure_payment_columns(conn=None):
    own = conn is None
    conn = conn or get_db()
    try:
        _v507_add_column(conn, 'actuals', 'payment_type', 'TEXT')
        _v507_add_column(conn, 'actuals', 'payment_purpose', 'TEXT')
        _v507_add_column(conn, 'actuals', 'payment_reference_required', 'INTEGER DEFAULT 0')
        try:
            conn.execute("UPDATE actuals SET payment_type='Expense Payment' WHERE payment_type IS NULL OR TRIM(payment_type)=''")
        except Exception:
            pass
        conn.commit()
    finally:
        if own:
            conn.close()

_V507_PAYMENT_TYPES = {
    'Expense Payment',
    'Asset Purchase',
    'Liability Settlement',
    'Advance / Prepayment',
    'Project Payment',
    'Withholding Remittance',
}

def _v507_payment_type(value):
    raw = str(value or '').strip()
    aliases = {
        'expense':'Expense Payment', 'expenses':'Expense Payment', 'actual expense':'Expense Payment', 'expense payment':'Expense Payment',
        'asset':'Asset Purchase', 'asset purchase':'Asset Purchase', 'capital purchase':'Asset Purchase', 'ppe':'Asset Purchase',
        'liability':'Liability Settlement', 'liability settlement':'Liability Settlement', 'payable settlement':'Liability Settlement',
        'advance':'Advance / Prepayment', 'prepayment':'Advance / Prepayment', 'advance / prepayment':'Advance / Prepayment',
        'project':'Project Payment', 'project payment':'Project Payment', 'donor project payment':'Project Payment',
        'withholding':'Withholding Remittance', 'withholding remittance':'Withholding Remittance', 'wht remittance':'Withholding Remittance', 'tax remittance':'Withholding Remittance',
    }
    return aliases.get(raw.lower(), raw if raw in _V507_PAYMENT_TYPES else 'Expense Payment')

def _v507_coa_row(conn, coa_id):
    if not coa_id:
        return None
    try:
        return conn.execute("SELECT * FROM chart_of_accounts WHERE id=?", (coa_id,)).fetchone()
    except Exception:
        return None

def _v507_coa_ok_for_payment(ptype, row):
    if not row:
        return True, ''
    code = str(row['code'] or '')
    name = str(row['account_name'] or '')
    up = name.upper()
    if len(code) != 8:
        return False, 'Select an official 8-digit UCC Chart of Accounts code.'
    if ptype == 'Expense Payment':
        return (code.startswith('6'), 'Expense Payment must debit an expense account from the UCC 6xxxxxxx expense range.')
    if ptype == 'Asset Purchase':
        return (code.startswith('1') and not code.startswith(('127','128')), 'Asset Purchase must debit an asset account from the UCC 1xxxxxxx range, excluding paying bank/cash accounts.')
    if ptype == 'Liability Settlement':
        return (code.startswith('2'), 'Liability Settlement must debit a liability/payable account from the UCC 2xxxxxxx range.')
    if ptype == 'Advance / Prepayment':
        ok = code.startswith(('122','123','124','129','114')) or any(w in up for w in ['ADVANCE','PREPAID','PREPAYMENT','IMPREST'])
        return (ok, 'Advance / Prepayment must debit a receivable, advance, imprest or prepaid asset account.')
    if ptype == 'Project Payment':
        ok = code.startswith('6') or (code.startswith('1') and not code.startswith(('127','128')))
        return (ok, 'Project Payment should debit a project expense or project asset account.')
    if ptype == 'Withholding Remittance':
        ok = code in {'21100014','21100024','21100027'} or any(w in up for w in ['GHANA REVENUE AUTHORITY','VAT WITHHOLDING','UCC COMMON FUND','WHT','WITHHOLDING'])
        return (ok, 'Withholding Remittance must debit GRA/WHT, WHVAT or UCC Common Fund payable.')
    return True, ''

def _v507_derive_payment_type_from_code(code):
    code = str(code or '')
    if code.startswith('6'):
        return 'Expense Payment'
    if code.startswith(('122','123','124','129','114')):
        return 'Advance / Prepayment'
    if code.startswith('2'):
        return 'Liability Settlement'
    if code.startswith('1') and not code.startswith(('127','128')):
        return 'Asset Purchase'
    return 'Expense Payment'

try:
    _v507_prev_api_save_actual = api_save_actual
    def api_save_actual(data, session):
        _v507_ensure_payment_columns()
        data = dict(data or {})
        ptype = _v507_payment_type(data.get('payment_type') or data.get('payment_category') or data.get('payment_purpose'))
        data['payment_type'] = ptype
        # The legacy column name expense_coa_id is retained as the debit/COA-affected field for compatibility.
        if data.get('payment_coa_id') and not data.get('expense_coa_id'):
            data['expense_coa_id'] = data.get('payment_coa_id')
        if data.get('coa_affected_id') and not data.get('expense_coa_id'):
            data['expense_coa_id'] = data.get('coa_affected_id')
        if ptype == 'Withholding Remittance':
            # A remittance clears existing liabilities; it must not create a fresh WHT/WHVAT/UCF payable.
            data['has_vat'] = 0
            data['has_whvat'] = 0
            data['has_ucf'] = 0
            data['wht_type'] = 'None'
        aid = data.get('id')
        coa_id = data.get('expense_coa_id') or data.get('coa_id')
        conn = get_db()
        try:
            _v507_ensure_payment_columns(conn)
            if not coa_id and aid:
                row0 = conn.execute("SELECT expense_coa_id FROM actuals WHERE id=?", (aid,)).fetchone()
                coa_id = row0['expense_coa_id'] if row0 and 'expense_coa_id' in row0.keys() else None
            # If no explicit COA is supplied, an existing budget COA may still drive the posting.
            if not coa_id and not data.get('budget_id'):
                return err('Select the UCC Chart of Accounts item affected by this payment.')
            if coa_id:
                row = _v507_coa_row(conn, coa_id)
                ok, msg = _v507_coa_ok_for_payment(ptype, row)
                if not ok:
                    return err(msg)
            method = str(data.get('payment_method') or data.get('payment_mode') or 'Bank Transfer')
            ref = str(data.get('receipt_no') or data.get('payment_reference') or data.get('cheque_no') or data.get('transfer_ref') or '').strip()
            if method.lower() not in ('cash','') and not ref:
                return err(f'{method} requires a cheque number, transfer reference or MoMo reference.')
            if ptype == 'Project Payment' and not data.get('project_id') and not data.get('commitment_id'):
                return err('Project Payment requires a selected project/grant or linked commitment.')
            conn.commit()
        finally:
            conn.close()
        res = _v507_prev_api_save_actual(data, session)
        if isinstance(res, dict) and res.get('ok') and res.get('id'):
            conn = get_db()
            try:
                _v507_ensure_payment_columns(conn)
                conn.execute("UPDATE actuals SET payment_type=?, payment_purpose=?, payment_reference_required=? WHERE id=?",
                             (ptype, ptype, 0 if str(data.get('payment_method','')).lower()=='cash' else 1, res['id']))
                if data.get('expense_coa_id'):
                    try:
                        conn.execute("UPDATE actuals SET expense_coa_id=? WHERE id=?", (data.get('expense_coa_id'), res['id']))
                    except Exception:
                        pass
                _audit(conn, session, 'SAVE_PAYMENT_TYPE', 'actuals', res['id'], f'{ptype} using official UCC COA')
                conn.commit()
            finally:
                conn.close()
        elif isinstance(res, dict) and res.get('error'):
            res['error'] = str(res['error']).replace('Expense save failed', 'Payment voucher save failed').replace('expense', 'payment')
        return res
except Exception as _v507_exc:
    print('v5.0.22 api_save_actual wrapper warning:', _v507_exc)

try:
    _v507_prev_api_get_actuals = api_get_actuals
    def api_get_actuals(session, project_id=None):
        _v507_ensure_payment_columns()
        rows = _v507_prev_api_get_actuals(session, project_id)
        if isinstance(rows, list):
            for r in rows:
                r['payment_type'] = r.get('payment_type') or _v507_derive_payment_type_from_code(r.get('expense_coa_code') or r.get('coa_code'))
                r['payment_purpose'] = r.get('payment_purpose') or r['payment_type']
        return rows
except Exception as _v507_exc:
    print('v5.0.22 api_get_actuals wrapper warning:', _v507_exc)

try:
    _v507_prev_build_actual_posting = _build_actual_posting
    def _build_actual_posting(conn, actual_id):
        """Build PV lines using payment type + selected official UCC COA.

        VAT posting policy used by the PV workflow:
        * VAT + WHVAT: amount_ghs is VAT inclusive. VAT is embedded in the gross payment
          amount and is not posted a second time.
        * VAT only: amount_ghs is VAT exclusive. The 20 percent VAT add on is included in
          the debit to the selected COA and in the bank settlement amount.
        """
        _v507_ensure_payment_columns(conn)
        row = conn.execute("""SELECT a.*, p.project_code, b.coa_id AS budget_coa_id,
                c.account_name, c.code as coa_code
            FROM actuals a
            JOIN projects p ON a.project_id=p.id
            LEFT JOIN budgets b ON a.budget_id=b.id
            LEFT JOIN chart_of_accounts c ON COALESCE(a.expense_coa_id, b.coa_id)=c.id
            WHERE a.id=?""", (actual_id,)).fetchone()
        if not row:
            raise ValueError('Transaction not found')
        a = dict(row)
        _ensure_period_accepts(conn, a['expense_date'], by_date=True, purpose='payment voucher posting')
        ptype = _v507_payment_type(a.get('payment_type'))
        debit_coa = a.get('expense_coa_id') or a.get('budget_coa_id')
        if not debit_coa:
            # Conservative fallback keeps old records postable but should rarely be used in v5.0.22.
            fallback_code = '61300001' if ptype == 'Expense Payment' else '21100001' if ptype in ('Liability Settlement','Withholding Remittance') else '11103004'
            debit_coa = _coa_id(conn, fallback_code)
        debit_row = _v507_coa_row(conn, debit_coa)
        ok, msg = _v507_coa_ok_for_payment(ptype, debit_row)
        if not ok:
            raise ValueError(msg)
        bank_coa = _v505_bank_coa_id(conn, a.get('bank_account_id')) if '_v505_bank_coa_id' in globals() else _coa_id(conn, '12703001')
        if not debit_coa or not bank_coa:
            raise ValueError('Required selected debit/bank COA account is missing')

        gross = round(float(a.get('amount_ghs') or 0), 2)
        has_vat = int(a.get('has_vat') or 0)
        has_whvat = int(a.get('has_whvat') or 0)
        vat_amount = round(float(a.get('vat_amount') or 0), 2)

        # Only expense, asset and project payments may create fresh withholding liabilities.
        allow_new_withholding = ptype in ('Expense Payment','Asset Purchase','Project Payment','Liability Settlement')
        wht = round(float(a.get('wht_amount') or 0), 2) if allow_new_withholding else 0
        whvat = round(float(a.get('whvat_amount') or 0), 2) if allow_new_withholding else 0
        ucf = round(float(a.get('ucf_amount') or 0), 2) if allow_new_withholding else 0

        # If VAT is checked without WHVAT, the amount entered is VAT exclusive and the VAT
        # amount is an add on. In this workflow, it is charged to the selected COA rather
        # than posted to a separate input VAT receivable account.
        vat_addon = vat_amount if (allow_new_withholding and has_vat and not has_whvat) else 0
        debit_total = round(gross + vat_addon, 2)

        wht_coa = _coa_id(conn, '21100014') or _coa_id(conn, '2030')
        whvat_coa = _coa_id(conn, '21100024') or _coa_id(conn, '2031')
        ucf_coa = _coa_id(conn, '21100027') or _coa_id(conn, '2033')
        if wht > 0 and not wht_coa:
            raise ValueError('WHT payable COA 21100014 is missing')
        if whvat > 0 and not whvat_coa:
            raise ValueError('WHVAT payable COA 21100024 is missing')
        if ucf > 0 and not ucf_coa:
            raise ValueError('UCC Common Fund payable COA 21100027 is missing')

        net_bank = round(debit_total - wht - whvat - ucf, 2)
        if net_bank < -0.01:
            raise ValueError('Deductions exceed gross payment')
        ref = a.get('receipt_no') or ''
        pm = a.get('payment_method') or 'Bank Transfer'
        desc = f"{ptype}: {pm}: {a['payee']} — {a['description']}"
        debit_label = {
            'Expense Payment':'Expense recognised',
            'Asset Purchase':'Asset capitalised',
            'Liability Settlement':'Liability settled',
            'Advance / Prepayment':'Advance/prepayment recognised',
            'Project Payment':'Project cost recognised',
            'Withholding Remittance':'Withholding payable remitted',
        }.get(ptype, 'Payment recognised')
        lines = [
            {'coa_id': debit_coa, 'debit_amount': debit_total, 'credit_amount': 0,
             'description': f"{debit_label}: {a['description']}", 'project_id': a['project_id'], 'bank_account_id': a.get('bank_account_id')},
        ]
        if wht > 0:
            lines.append({'coa_id': wht_coa, 'debit_amount': 0, 'credit_amount': wht,
                          'description': f"WHT payable — {a.get('wht_type','')}", 'project_id': a['project_id']})
        if whvat > 0:
            lines.append({'coa_id': whvat_coa, 'debit_amount': 0, 'credit_amount': whvat,
                          'description': 'WHVAT payable', 'project_id': a['project_id']})
        if ucf > 0:
            lines.append({'coa_id': ucf_coa, 'debit_amount': 0, 'credit_amount': ucf,
                          'description': 'UCC Common Fund payable', 'project_id': a['project_id']})
        if net_bank > 0:
            lines.append({'coa_id': bank_coa, 'debit_amount': 0, 'credit_amount': net_bank,
                          'description': f"Payment from bank — {ref or a['actual_code']}",
                          'project_id': a['project_id'], 'bank_account_id': a.get('bank_account_id')})
        return a, desc, ref, lines
except Exception as _v507_exc:
    print('v5.0.22 _build_actual_posting override warning:', _v507_exc)

# Ensure migrations run during import/startup.
try:
    _v507_ensure_payment_columns()
except Exception as _v507_exc:
    print('v5.0.22 startup payment column warning:', _v507_exc)


# v5.0.22b Direct Unit/Department Payment Fallback
try:
    _v507b_prev_api_save_actual = api_save_actual
    def api_save_actual(data, session):
        data = dict(data or {})
        # Direct payments for expenses/assets/liabilities/advances may be made without a donor/project.
        # Create/reuse the internal General Fund project so NOT NULL project_id constraints and reports remain intact.
        if not data.get('project_id') and not data.get('commitment_id'):
            unit = data.get('unit') or data.get('unit_code') or data.get('dept_code') or data.get('dept') or data.get('division')
            if unit:
                conn = get_db()
                try:
                    if '_get_or_create_general_project' in globals():
                        data['project_id'] = _get_or_create_general_project(conn, unit, session)
                    elif '_ensure_general_project_for_dept' in globals():
                        data['project_id'] = _ensure_general_project_for_dept(conn, unit, session)
                    else:
                        existing = conn.execute("SELECT id FROM projects WHERE division=? AND status='Active' ORDER BY created_at DESC LIMIT 1", (unit,)).fetchone()
                        if existing:
                            data['project_id'] = existing['id']
                    conn.commit()
                finally:
                    conn.close()
        return _v507b_prev_api_save_actual(data, session)
except Exception as _v507b_exc:
    print('v5.0.22b direct payment fallback warning:', _v507b_exc)

# ─────────────────────────────────────────────────────────────────────────────
# v5.0.22 Grant / Donor Project Funding Receipt Treatment
# ─────────────────────────────────────────────────────────────────────────────
# Grant receipts are not automatically recognised as revenue.  Conditional or
# restricted donor receipts now post Dr Bank and Cr Restricted Fund / Deferred
# Grant / Project Liability.  Revenue recognition is stored separately and can be
# applied by policy when grant conditions are satisfied.

V508_GRANT_CLASSIFICATION = 'Grant / Donor Project Funding'
V508_REVENUE_CLASSIFICATION = 'Revenue / Income Receipt'


def _v508_cols(conn, table):
    try:
        return [r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()]
    except Exception:
        return []


def _v508_add_column(conn, table, ddl):
    col = ddl.split()[0].strip()
    if col not in _v508_cols(conn, table):
        try:
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {ddl}")
        except Exception:
            pass


def _v508_org_code():
    try:
        if 'AOI_UNITS' in globals():
            return 'AOI'
    except Exception:
        pass
    return 'SBS'


def _v508_default_restricted_codes():
    return ['22500043', '22500029', '22500026', '22500040', '22500004'] if _v508_org_code() == 'AOI' else ['22500004', '22500043', '22500029', '22500026', '22500040']


def _v508_default_revenue_codes():
    return ['42300016', '41100005', '42300017', '41100002']


def _v508_ensure_receipt_columns(conn):
    if 'fund_receipts' not in [r[0] for r in conn.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()]:
        return
    for ddl in [
        'income_coa_id TEXT',
        'income_type TEXT',
        "receipt_classification TEXT DEFAULT 'Grant / Donor Project Funding'",
        "grant_condition_status TEXT DEFAULT 'Restricted / Conditional'",
        "recognition_treatment TEXT DEFAULT 'Defer recognition until grant conditions are satisfied'",
        'restricted_fund_coa_id TEXT',
        'revenue_recognition_coa_id TEXT'
    ]:
        _v508_add_column(conn, 'fund_receipts', ddl)
    try:
        conn.execute("""
            UPDATE fund_receipts
               SET receipt_classification = COALESCE(NULLIF(receipt_classification,''), NULLIF(income_type,''), NULLIF(receipt_type,''), 'Grant / Donor Project Funding'),
                   income_type = COALESCE(NULLIF(income_type,''), NULLIF(receipt_classification,''), NULLIF(receipt_type,''), 'Grant / Donor Project Funding'),
                   grant_condition_status = COALESCE(NULLIF(grant_condition_status,''), 'Restricted / Conditional'),
                   recognition_treatment = COALESCE(NULLIF(recognition_treatment,''), 'Defer recognition until grant conditions are satisfied')
        """)
    except Exception:
        pass


def _v508_coa_by_id(conn, coa_id):
    if not coa_id:
        return None
    try:
        r = conn.execute("SELECT * FROM chart_of_accounts WHERE id=?", (coa_id,)).fetchone()
        return dict(r) if r else None
    except Exception:
        return None


def _v508_coa_by_code(conn, code):
    try:
        r = conn.execute("SELECT * FROM chart_of_accounts WHERE code=?", (str(code),)).fetchone()
        return dict(r) if r else None
    except Exception:
        return None


def _v508_first_existing_coa_id(conn, codes):
    for code in codes:
        row = _v508_coa_by_code(conn, code)
        if row:
            return row.get('id')
    return None


def _v508_is_restricted_or_deferred_account(row):
    if not row:
        return False
    code = str(row.get('code') or '')
    words = ' '.join(str(row.get(k) or '') for k in ('account_name', 'category', 'sub_category', 'account_type')).upper()
    return code.startswith(('2', '3')) or any(w in words for w in ('RESTRICTED', 'DEFERRED', 'DONOR', 'PROJECT', 'LIABILITY', 'FUND'))


def _v508_is_revenue_account(row):
    if not row:
        return False
    code = str(row.get('code') or '')
    words = ' '.join(str(row.get(k) or '') for k in ('account_name', 'category', 'sub_category', 'account_type')).upper()
    return code.startswith('4') or any(w in words for w in ('REVENUE', 'INCOME'))


def _v508_receipt_classification(row_or_data):
    raw = ''
    for key in ('receipt_classification', 'income_type', 'receipt_type'):
        try:
            val = row_or_data.get(key)
        except Exception:
            val = None
        if val:
            raw = str(val).strip()
            break
    return raw or V508_GRANT_CLASSIFICATION


def _v508_is_grant_receipt(row_or_data):
    c = _v508_receipt_classification(row_or_data).lower()
    if 'revenue / income' in c or c in ('revenue', 'income receipt'):
        return False
    return any(x in c for x in ('grant', 'donor', 'project / donor', 'project funding', 'restricted', 'conditional'))


def _v508_bank_coa_id(conn, bank_account_id):
    if '_v505_bank_coa_id' in globals():
        try:
            return _v505_bank_coa_id(conn, bank_account_id)
        except Exception:
            pass
    if '_bank_coa_for' in globals():
        try:
            row = _bank_coa_for(conn, bank_account_id)
            if isinstance(row, dict):
                return row.get('id')
            if hasattr(row, 'keys'):
                return row['id']
        except Exception:
            pass
    if '_coa_id' in globals():
        for code in ('12701154', '12703001', '1001'):
            try:
                cid = _coa_id(conn, code)
                if cid:
                    return cid
            except Exception:
                pass
    return _v508_first_existing_coa_id(conn, ['12701154', '12703001'])


def _v508_credit_account_id(conn, receipt_row):
    receipt = dict(receipt_row or {})
    if _v508_is_grant_receipt(receipt):
        selected = receipt.get('restricted_fund_coa_id') or receipt.get('deferred_grant_coa_id') or receipt.get('project_fund_coa_id')
        row = _v508_coa_by_id(conn, selected)
        if row and _v508_is_restricted_or_deferred_account(row):
            return row['id']
        default_id = _v508_first_existing_coa_id(conn, _v508_default_restricted_codes())
        if default_id:
            return default_id
        return selected
    selected = receipt.get('income_coa_id') or receipt.get('revenue_coa_id') or receipt.get('revenue_recognition_coa_id')
    row = _v508_coa_by_id(conn, selected)
    if row and _v508_is_revenue_account(row):
        return row['id']
    default_id = _v508_first_existing_coa_id(conn, _v508_default_revenue_codes())
    if default_id:
        return default_id
    if '_v505_revenue_coa_id' in globals():
        return _v505_revenue_coa_id(conn, selected, receipt.get('budget_id'), receipt.get('receipt_type'), receipt.get('donor') or receipt.get('project_donor'))
    return selected


def _v508_posted_journal(conn, session, jv_type, jv_date, description, reference, project_id, bank_account_id, source_module, source_id, lines):
    if '_create_posted_journal' in globals():
        return _create_posted_journal(conn, session, jv_type, jv_date, description, reference, project_id, bank_account_id, source_module, source_id, lines)
    if '_insert_voucher_posted' in globals():
        return _insert_voucher_posted(conn, session, jv_type=jv_type, jv_date=jv_date, description=description,
                                      project_id=project_id, bank_account_id=bank_account_id, source_module=source_module,
                                      source_id=source_id, reference=reference, lines=lines, notes='Auto-posted from Fund Receipts module')
    raise ValueError('Posted journal helper is not available')


def _v508_reverse_existing_receipt_voucher(conn, session, jv_id, reason, rid):
    if not jv_id:
        return None, None
    if '_auto_reverse_posted_journal' in globals():
        try:
            return _auto_reverse_posted_journal(conn, session, jv_id, 'fund_receipts', rid, reason)
        except Exception:
            pass
    if '_reverse_voucher' in globals():
        try:
            rev_id = _reverse_voucher(conn, session, jv_id, reason)
            return rev_id, None
        except Exception:
            pass
    return None, None


def _post_receipt_to_gl(conn, session, receipt_id, force=False):
    _v508_ensure_receipt_columns(conn)
    row = conn.execute("""SELECT fr.*, p.project_code, p.donor as project_donor
        FROM fund_receipts fr JOIN projects p ON fr.project_id=p.id WHERE fr.id=?""", (receipt_id,)).fetchone()
    if not row:
        raise ValueError('Receipt not found')
    r = dict(row)
    if r.get('is_posted') and not force:
        return r.get('jv_id'), None
    if '_ensure_period_accepts' in globals():
        _ensure_period_accepts(conn, r['receipt_date'], by_date=True, purpose='fund receipt')
    elif '_assert_period_open' in globals():
        okp, period_or_msg = _assert_period_open(conn, r['receipt_date'])
        if not okp:
            raise ValueError(period_or_msg)
    bank_coa = _v508_bank_coa_id(conn, r.get('bank_account_id'))
    credit_coa = _v508_credit_account_id(conn, r)
    if not bank_coa or not credit_coa:
        raise ValueError('Required receiving bank or receipt credit COA account is missing')
    amount = round(float(r.get('amount_ghs') or 0), 2)
    ref = r.get('reference_no') or r.get('receipt_code') or ''
    is_grant = _v508_is_grant_receipt(r)
    desc = f"Receipt: {r.get('donor','')} — {r.get('description','')}"
    credit_desc = ("Restricted/deferred grant funding — " if is_grant else "Revenue/income receipt — ") + str(r.get('description') or '')
    _r_unit = r.get('unit_id')
    lines = [
        {'coa_id': bank_coa, 'debit_amount': amount, 'credit_amount': 0,
         'description': f"Bank receipt — {ref}", 'project_id': r['project_id'], 'bank_account_id': r.get('bank_account_id'), 'unit_id': _r_unit},
        {'coa_id': credit_coa, 'debit_amount': 0, 'credit_amount': amount,
         'description': credit_desc, 'project_id': r['project_id'], 'unit_id': _r_unit},
    ]
    jv_id, jv_num = _v508_posted_journal(conn, session, 'RV', r['receipt_date'], desc, ref, r['project_id'], r.get('bank_account_id'), 'receipts', receipt_id, lines)
    conn.execute("UPDATE fund_receipts SET is_posted=1, posted_by=?, posted_at=datetime('now'), jv_id=? WHERE id=?", ((session or {}).get('username','system'), jv_id, receipt_id))
    return jv_id, jv_num


def _v508_resolve_project_id(conn, data, session):
    project_id = data.get('project_id') or None
    if project_id:
        pr = conn.execute("SELECT id FROM projects WHERE id=?", (project_id,)).fetchone()
        if not pr:
            raise ValueError('Selected project/grant was not found')
        return project_id
    if _v508_is_grant_receipt(data):
        raise ValueError('Grant / Donor Project Funding requires a selected Project / Grant')
    unit = data.get('unit') or data.get('unit_code') or data.get('dept_code') or data.get('department') or data.get('division')
    if 'canonical_unit_code' in globals():
        try:
            unit = canonical_unit_code(unit)
        except Exception:
            pass
    if '_get_or_create_general_project' in globals():
        return _get_or_create_general_project(conn, unit, session)
    if '_ensure_general_project_for_dept' in globals():
        return _ensure_general_project_for_dept(conn, unit, session)
    existing = conn.execute("SELECT id FROM projects WHERE division=? AND status='Active' ORDER BY created_at DESC LIMIT 1", (unit,)).fetchone()
    if existing:
        return existing['id']
    raise ValueError('Select a project/grant or a valid unit/department')


def _v508_validate_receipt_accounts(conn, data):
    classification = _v508_receipt_classification(data)
    is_grant = _v508_is_grant_receipt(data)
    if not data.get('bank_account_id'):
        return 'Receiving bank account is required'
    if is_grant:
        selected = data.get('restricted_fund_coa_id') or data.get('deferred_grant_coa_id') or data.get('project_fund_coa_id')
        if not selected:
            selected = _v508_first_existing_coa_id(conn, _v508_default_restricted_codes())
            data['restricted_fund_coa_id'] = selected
        row = _v508_coa_by_id(conn, selected)
        if not row or not _v508_is_restricted_or_deferred_account(row):
            return 'Select a valid Restricted Fund / Deferred Grant / Project Liability account'
    else:
        selected = data.get('income_coa_id') or data.get('revenue_coa_id') or data.get('revenue_recognition_coa_id')
        row = _v508_coa_by_id(conn, selected)
        if not row or not _v508_is_revenue_account(row):
            return 'Select a valid Revenue / Income COA account'
    data['receipt_classification'] = classification
    data['income_type'] = classification
    return None


def api_save_fund_receipt(data, session):
    if not session:
        return err('Not logged in', 401)
    data = dict(data or {})
    if '_v44_validate_receipt_payload' in globals():
        ve = _v44_validate_receipt_payload(data, session)
        if ve:
            return err(ve)
    if '_v505_enforce_ucc_primary_coa' in globals():
        try:
            _v505_enforce_ucc_primary_coa()
        except Exception:
            pass
    if '_normalise_unit_payload' in globals():
        try:
            data = _normalise_unit_payload(data)
        except Exception:
            pass
    conn = get_db()
    try:
        _v508_ensure_receipt_columns(conn)
        rid = data.get('id') or str(uuid.uuid4())
        if data.get('receipt_code'):
            rcode = data.get('receipt_code')
        elif '_v44_next_reference' in globals():
            rcode = _v44_next_reference(conn, 'RV', data.get('receipt_date') or data.get('date'))
        else:
            rcode = f"RCP-{datetime.now().strftime('%Y')}-{str(uuid.uuid4())[:6].upper()}"
        existing = conn.execute("SELECT * FROM fund_receipts WHERE id=?", (rid,)).fetchone() if data.get('id') else None
        posted_admin_edit = False
        edit_reason = (data.get('edit_reason') or data.get('reason') or '').strip()
        before_snapshot = {}
        if existing and existing['is_posted']:
            if (session or {}).get('role') != 'Admin':
                conn.close(); return err('Posted receipts are locked. Only Admin can edit posted receipts.')
            if len(edit_reason) < 5:
                conn.close(); return err('Admin edit reason is required for posted receipts')
            posted_admin_edit = True
            try:
                before_snapshot = _compact_snapshot(existing, ['receipt_code','project_id','bank_account_id','budget_id','income_coa_id','restricted_fund_coa_id','revenue_recognition_coa_id','receipt_classification','grant_condition_status','recognition_treatment','receipt_date','donor','description','currency','amount_fcy','fx_rate','amount_ghs','reference_no','receipt_type','jv_id'])
            except Exception:
                before_snapshot = dict(existing)
        receipt_date = data.get('receipt_date') or data.get('date') or datetime.now().strftime('%Y-%m-%d')
        donor = (data.get('donor') or data.get('source') or data.get('payer') or '').strip()
        description = (data.get('description') or '').strip()
        if not donor or not description:
            conn.close(); return err('Donor/source and description are required')
        currency = data.get('currency') or 'GHS'
        try:
            amount_fcy = float(data.get('amount_fcy') or 0)
            fx_rate = float(data.get('fx_rate') or 1)
        except (TypeError, ValueError):
            conn.close(); return err('Amount and FX rate must be numeric')
        if amount_fcy <= 0 or fx_rate <= 0:
            conn.close(); return err('Amount and FX rate must be greater than zero')
        amount_ghs = round(amount_fcy * fx_rate, 2)
        project_id = _v508_resolve_project_id(conn, data, session)
        account_error = _v508_validate_receipt_accounts(conn, data)
        if account_error:
            conn.close(); return err(account_error)
        is_grant = _v508_is_grant_receipt(data)
        reference_no = data.get('reference_no') or data.get('receipt_no') or data.get('transfer_ref') or ''
        classification = _v508_receipt_classification(data)
        grant_condition_status = data.get('grant_condition_status') or ('Restricted / Conditional' if is_grant else 'Not Applicable')
        recognition_treatment = data.get('recognition_treatment') or ('Defer recognition until grant conditions are satisfied' if is_grant else 'Recognise on receipt')
        restricted_fund_coa_id = data.get('restricted_fund_coa_id') if is_grant else None
        revenue_recognition_coa_id = data.get('revenue_recognition_coa_id') or data.get('recognition_coa_id') or None
        income_coa_id = None if is_grant else (data.get('income_coa_id') or data.get('revenue_coa_id') or revenue_recognition_coa_id)
        budget_id = data.get('budget_id') or None
        notes = data.get('notes','')
        if posted_admin_edit:
            old_jv_id = before_snapshot.get('jv_id') if isinstance(before_snapshot, dict) else None
            rev_id, rev_num = _v508_reverse_existing_receipt_voucher(conn, session, old_jv_id, edit_reason, rid)
        if existing:
            conn.execute("""UPDATE fund_receipts SET project_id=?,bank_account_id=?,budget_id=?,income_coa_id=?,income_type=?,
                receipt_classification=?,grant_condition_status=?,recognition_treatment=?,restricted_fund_coa_id=?,revenue_recognition_coa_id=?,
                receipt_date=?,donor=?,description=?,currency=?,amount_fcy=?,fx_rate=?,amount_ghs=?,reference_no=?,receipt_type=?,notes=?,is_posted=0,jv_id=NULL
                WHERE id=?""",
                (project_id,data.get('bank_account_id') or None,budget_id,income_coa_id,classification,
                 classification,grant_condition_status,recognition_treatment,restricted_fund_coa_id,revenue_recognition_coa_id,
                 receipt_date,donor,description,currency,amount_fcy,fx_rate,amount_ghs,reference_no,classification,notes,rid))
        else:
            conn.execute("""INSERT INTO fund_receipts(id,receipt_code,project_id,bank_account_id,budget_id,income_coa_id,income_type,
                receipt_classification,grant_condition_status,recognition_treatment,restricted_fund_coa_id,revenue_recognition_coa_id,
                receipt_date,donor,description,currency,amount_fcy,fx_rate,amount_ghs,reference_no,receipt_type,notes,created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (rid,rcode,project_id,data.get('bank_account_id') or None,budget_id,income_coa_id,classification,
                 classification,grant_condition_status,recognition_treatment,restricted_fund_coa_id,revenue_recognition_coa_id,
                 receipt_date,donor,description,currency,amount_fcy,fx_rate,amount_ghs,reference_no,classification,notes,(session or {}).get('username','system')))
        # UCC unit attribution: stamp the receipt's unit_id (explicit pick → home unit)
        # BEFORE posting so _post_receipt_to_gl propagates it onto every GL line.
        try:
            _ru = (_ucc_resolve_write_unit(conn, data, session)
                   if '_ucc_resolve_write_unit' in globals() else (data or {}).get('unit_id'))
            if _ru:
                conn.execute("UPDATE fund_receipts SET unit_id=? WHERE id=?", (_ru, rid))
        except Exception:
            pass
        jv_id, jv_num = _post_receipt_to_gl(conn, session, rid, force=True)
        if posted_admin_edit:
            try:
                conn.execute("""UPDATE fund_receipts SET amended_by=?, amended_at=datetime('now'),
                    amendment_reason=?, amendment_count=COALESCE(amendment_count,0)+1,
                    last_reversal_jv_id=? WHERE id=?""", ((session or {}).get('username','system'), edit_reason, rev_id, rid))
                after_row = conn.execute("SELECT * FROM fund_receipts WHERE id=?", (rid,)).fetchone()
                after_snapshot = _compact_snapshot(after_row, ['receipt_code','project_id','bank_account_id','budget_id','income_coa_id','restricted_fund_coa_id','revenue_recognition_coa_id','receipt_classification','grant_condition_status','recognition_treatment','receipt_date','donor','description','currency','amount_fcy','fx_rate','amount_ghs','reference_no','receipt_type','jv_id'])
                detail = json.dumps({'reason': edit_reason, 'reversed_jv': rev_num, 'new_jv': jv_num, 'before': before_snapshot, 'after': after_snapshot}, default=str)[:3500]
                _audit(conn, session, 'ADMIN_EDIT_POSTED_RECEIPT', 'fund_receipts', rid, detail)
            except Exception:
                pass
        else:
            try:
                _audit(conn, session, 'SAVE_FUND_RECEIPT_GRANT_CLASSIFICATION', 'fund_receipts', rid, f"{classification} | {donor} {amount_ghs:.2f} GHS | {jv_num or 'posted'}")
            except Exception:
                pass
        conn.commit(); conn.close()
        msg = 'Grant receipt posted to restricted/deferred project funding account' if is_grant else 'Receipt posted to revenue/income account'
        return {'ok': True, 'id': rid, 'jv_id': jv_id, 'jv_number': jv_num, 'message': msg}
    except Exception as exc:
        try:
            conn.rollback(); conn.close()
        except Exception:
            pass
        return {'ok': False, 'error': f'Receipt save failed: {exc}'}


