# v5.0.22 server startup relocated to ensure all enterprise patches load before serving
def _run_server_main():
    print("Initialising SBS ERP database...")
    init_db()
    init_payroll_db()
    init_jv_db()
    HOST = os.environ.get('HOST', '0.0.0.0')
    preferred = PORT
    # Always try the preferred/specified port first
    _all_ports = [8000, 8080, 8888, 9000, 9090, 7000, 5050]
    fallbacks = [preferred] + [p for p in _all_ports if p != preferred]
    server = None
    actual_port = None
    for p in fallbacks:
        try:
            server = ReuseAddrHTTPServer((HOST, p), Handler)
            actual_port = p
            break
        except OSError:
            print(f"  Port {p} in use, trying next...")
    if not server:
        print("ERROR: Could not find an available port. Please close other servers and try again.")
        import sys; sys.exit(1)
    url = os.environ.get("RENDER_EXTERNAL_URL", f"http://localhost:{actual_port}")
    print(f"\n✓ SBS ERP / Financial Management System")
    print(f"  URL: {url}")
    print(f"  Database: {DB_PATH}")
    print("  Press Ctrl+C to stop\n")
    print("Default login credentials:")
    print("  admin      / UCC@2024  (Admin)")
    print("  finance01  / Fin@2024  (Finance Officer)")
    print("  project01  / HOD@2024  (Project Leader)")
    print("  demo       / Demo@2024 (Admin demo)\n")
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\n✓ Server stopped.")


