def api_deleted_items(session, module=None):
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    _v511_migration(); conn = get_db()
    try:
        args=[]; where="WHERE status='Deleted'"
        if module:
            where += " AND module=?"; args.append(module)
        rows = [dict(r) for r in conn.execute(f"SELECT * FROM soft_deleted_items {where} ORDER BY deleted_at DESC LIMIT 300", args).fetchall()]
        return {'ok': True, 'items': rows}
    finally:
        conn.close()


def api_restore_deleted_item(data, session):
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    if (session or {}).get('role') != 'Admin':
        return {'ok': False, 'error': 'Only Admin can restore deleted records'}
    soft_id = data.get('id') or data.get('soft_delete_id')
    if not soft_id:
        return {'ok': False, 'error': 'Deleted item ID is required'}
    _v511_migration(); conn=get_db()
    try:
        item = conn.execute("SELECT * FROM soft_deleted_items WHERE id=? AND status='Deleted'", (soft_id,)).fetchone()
        if not item:
            return {'ok': False, 'error': 'Deleted item not found or already restored'}
        item = dict(item)
        table = item['module']; rid = item['record_id']
        if not _v511_table_exists(conn, table) or 'is_deleted' not in _v511_cols(conn, table):
            return {'ok': False, 'error': 'This record type cannot be restored automatically'}
        conn.execute(f"UPDATE {table} SET is_deleted=0, deleted_at=NULL, deleted_by=NULL, delete_reason=NULL WHERE id=?", (rid,))
        if table == 'budget_uploads':
            snap = json.loads(item.get('snapshot_json') or '{}')
            batch_id = snap.get('batch_id') or snap.get('upload_batch')
            if batch_id and _v511_table_exists(conn, 'quarterly_budgets') and 'is_deleted' in _v511_cols(conn, 'quarterly_budgets'):
                conn.execute("UPDATE quarterly_budgets SET is_deleted=0, deleted_at=NULL, deleted_by=NULL, delete_reason=NULL WHERE upload_batch=?", (batch_id,))
        conn.execute("UPDATE soft_deleted_items SET status='Restored', restored_by=?, restored_at=datetime('now') WHERE id=?", ((session or {}).get('username','system'), soft_id))
        _v511_log_change(conn, session, 'RESTORE_DELETED_ITEM', table, rid, {'is_deleted':1}, {'is_deleted':0}, data.get('reason','Restored by Admin'))
        conn.commit(); return {'ok': True, 'message': f"{item.get('record_code') or rid} restored"}
    except Exception as exc:
        conn.rollback(); return {'ok': False, 'error': f'Restore failed: {exc}'}
    finally:
        conn.close()


def _v511_parse_amount(v):
    try:
        if v is None or v == '': return 0.0, None
        return float(str(v).replace(',', '').strip()), None
    except Exception:
        return 0.0, 'Amount is not numeric'


def _v511_validate_budget_rows(conn, rows, dept_code, academic_year):
    dept_codes = set()
    try:
        dept_codes = {str(r[0]) for r in conn.execute('SELECT dept_code FROM departments').fetchall()}
    except Exception:
        pass
    coa_codes = set()
    try:
        coa_codes = {str(r[0]) for r in conn.execute('SELECT code FROM chart_of_accounts').fetchall()}
    except Exception:
        pass
    accepted=[]; report=[]; seen=set()
    for idx, row in enumerate(rows or [], start=2):
        r = dict(row or {})
        errors=[]; warnings=[]
        d = str(r.get('dept_code') or dept_code or '').strip()
        ay = str(r.get('academic_year') or academic_year or '').strip()
        desc = str(r.get('description') or '').strip()
        acct = str(r.get('account_code') or '').strip()
        if not d: errors.append('Missing department/unit code')
        elif dept_codes and d not in dept_codes: warnings.append(f'Department/unit code {d} is not in the department master')
        if not ay: errors.append('Missing academic year')
        elif '/' not in ay and len(ay) < 4: warnings.append('Academic year format looks unusual')
        if not desc: errors.append('Missing budget description')
        if acct and coa_codes and acct not in coa_codes: errors.append(f'COA code {acct} was not found')
        if not acct: warnings.append('No COA code supplied; system will attempt auto-assignment from description/category')
        total=0
        for q in ['q1_amount','q2_amount','q3_amount','q4_amount']:
            amt, e = _v511_parse_amount(r.get(q, 0))
            if e: errors.append(f'{q}: {e}')
            if amt < 0: errors.append(f'{q}: negative amount is not allowed')
            total += amt
        if total <= 0: errors.append('Annual budget total is zero')
        key=(d, ay, acct, desc.lower())
        if key in seen: errors.append('Duplicate line in this upload')
        seen.add(key)
        item={'row': idx, 'dept_code': d, 'academic_year': ay, 'account_code': acct, 'description': desc, 'total': round(total,2), 'errors': errors, 'warnings': warnings}
        report.append(item)
        if not errors:
            accepted.append(r)
    return accepted, report

# Preserve the previous importer and wrap it with a validation/report layer.
_v511_prev_api_upload_budget = globals().get('api_upload_budget')
def api_upload_budget(data, session):
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    _v511_migration(); conn=get_db()
    try:
        rows = data.get('rows') or []
        dept_code = data.get('dept_code') or ''
        ay = data.get('academic_year') or '2025/2026'
        filename = data.get('filename') or 'budget_upload.xlsx'
        accepted, report = _v511_validate_budget_rows(conn, rows, dept_code, ay)
        rejected = [r for r in report if r['errors']]
        warnings = [r for r in report if r['warnings']]
        report_id = str(uuid.uuid4())
        result = {'ok': False, 'imported': 0, 'failed': len(rejected), 'errors': [f"Row {r['row']}: "+'; '.join(r['errors']) for r in rejected[:8]]}
        upload_id = None
        if accepted and callable(_v511_prev_api_upload_budget):
            d2 = dict(data); d2['rows'] = accepted
            result = _v511_prev_api_upload_budget(d2, session)
            if result and result.get('batch_id'):
                row = conn.execute("SELECT id FROM budget_uploads WHERE batch_id=? ORDER BY created_at DESC LIMIT 1", (result.get('batch_id'),)).fetchone()
                if row:
                    upload_id = row[0]
                    conn.execute("UPDATE budget_uploads SET validation_report_id=? WHERE id=?", (report_id, upload_id))
        else:
            upload_id = str(uuid.uuid4())
            try:
                conn.execute("""INSERT INTO budget_uploads(id,filename,dept_code,academic_year,rows_imported,rows_failed,status,error_log,validation_report_id,uploaded_by)
                              VALUES(?,?,?,?,?,?,?,?,?,?)""",
                           (upload_id, filename, dept_code, ay, 0, len(rejected), 'Rejected', '\n'.join(result['errors'][:20]), report_id, (session or {}).get('username','system')))
            except Exception:
                pass
        conn.execute("""INSERT INTO budget_upload_validation_reports(id,upload_id,filename,dept_code,academic_year,row_count,accepted_rows,rejected_rows,warning_count,error_count,report_json,created_by)
                    VALUES(?,?,?,?,?,?,?,?,?,?,?,?)""",
                    (report_id, upload_id, filename, dept_code, ay, len(rows), len(accepted), len(rejected), len(warnings), sum(len(r['errors']) for r in report), _v511_json(report), (session or {}).get('username','system')))
        _v511_log_change(conn, session, 'BUDGET_UPLOAD_VALIDATION', 'budget_uploads', upload_id or report_id, None, {'accepted':len(accepted),'rejected':len(rejected),'warnings':len(warnings)}, 'Pre-import validation report generated')
        conn.commit()
        result = result or {'ok': False, 'error': 'Budget upload failed'}
        result['validation_report_id'] = report_id
        result['accepted_rows'] = len(accepted)
        result['rejected_rows'] = len(rejected)
        result['warnings'] = [f"Row {r['row']}: "+'; '.join(r['warnings']) for r in warnings[:8]]
        return result
    except Exception as exc:
        conn.rollback()
        return {'ok': False, 'error': f'Budget validation/upload failed: {exc}'}
    finally:
        conn.close()


