def _v511_wrap_save_function(fn_name, table, code_field, amount_field='amount_ghs'):
    old = globals().get(fn_name)
    if not callable(old) or getattr(old, '_v511_wrapped', False):
        return
    def wrapped(data, session, _old=old, _table=table, _code=code_field, _amount=amount_field):
        _v511_migration()
        rid = (data or {}).get('id')
        before = None
        if rid:
            conn0=get_db(); before=_v511_row(conn0, _table, rid); conn0.close()
        res = _old(data, session)
        try:
            if isinstance(res, dict) and res.get('ok'):
                rid2 = res.get('id') or rid
                conn=get_db()
                after=_v511_row(conn, _table, rid2)
                if after:
                    code=after.get(_code) if _code else rid2
                    amount=after.get(_amount) if _amount in after else after.get('budget_ghs') or 0
                    stage='Posted' if int(after.get('is_posted') or 0)==1 or after.get('status')=='Posted' else 'Draft'
                    approval='Approved' if after.get('approved_by') or stage=='Posted' else 'Draft'
                    _v511_touch_workflow(conn, session, _table, rid2, code, amount, stage, approval)
                    _v511_log_change(conn, session, 'SAVE_WITH_CHANGE_AUDIT', _table, rid2, before, after, (data or {}).get('edit_reason',''))
                    conn.commit()
                conn.close()
        except Exception:
            pass
        return res
    wrapped._v511_wrapped = True
    globals()[fn_name]=wrapped

_v511_wrap_save_function('api_save_budget', 'budgets', 'budget_code', 'budget_ghs')
_v511_wrap_save_function('api_save_commitment', 'commitments', 'commit_code', 'amount_ghs')
_v511_wrap_save_function('api_save_actual', 'actuals', 'actual_code', 'amount_ghs')
_v511_wrap_save_function('api_save_fund_receipt', 'fund_receipts', 'receipt_code', 'amount_ghs')

