def api_management_alerts(session):
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    _v511_migration(); conn=get_db(); alerts=[]
    try:
        def add(sev, title, detail, module='dashboard', count=0):
            alerts.append({'severity':sev, 'title':title, 'detail':detail, 'module':module, 'count':int(count or 0)})
        # Pending approvals / workflow queues.
        pending = _v511_scalar(conn, "SELECT COUNT(*) FROM transaction_workflows WHERE approval_status IN ('Draft','Pending','Submitted')", default=0)
        if pending: add('warning', 'Transactions awaiting workflow review', f'{pending} transaction(s) are still draft/submitted and should be reviewed before posting.', 'approvals', pending)
        # Old draft PVs.
        if _v511_table_exists(conn,'actuals'):
            where = "WHERE COALESCE(is_deleted,0)=0 AND COALESCE(is_posted,0)=0 AND date(created_at) <= date('now','-7 day')"
            old_pv = _v511_scalar(conn, f"SELECT COUNT(*) FROM actuals {where}", default=0)
            if old_pv: add('warning','Old draft payment vouchers', f'{old_pv} PV(s) have remained unposted for 7+ days.', 'actuals', old_pv)
        # Budget upload validation failures.
        bad_uploads = _v511_scalar(conn, "SELECT COUNT(*) FROM budget_upload_validation_reports WHERE rejected_rows>0", default=0)
        if bad_uploads: add('danger','Budget upload validation exceptions', f'{bad_uploads} upload report(s) contain rejected rows that should be corrected.', 'budget-validation', bad_uploads)
        # Deleted records pending restore/final review.
        deleted = _v511_scalar(conn, "SELECT COUNT(*) FROM soft_deleted_items WHERE status='Deleted'", default=0)
        if deleted: add('info','Deleted/Reversed items retained', f'{deleted} item(s) are held in the Deleted/Reversed Items register.', 'deleted-items', deleted)
        # Unbalanced GL.
        dr = float(_v511_scalar(conn, "SELECT COALESCE(SUM(debit_amount),0) FROM general_ledger", default=0) or 0)
        cr = float(_v511_scalar(conn, "SELECT COALESCE(SUM(credit_amount),0) FROM general_ledger", default=0) or 0)
        if abs(dr-cr) > 0.01: add('danger','General Ledger imbalance', f'Debits and credits differ by GHS {abs(dr-cr):,.2f}.', 'general-ledger', 1)
        # Bank reconciliation exceptions.
        if _v511_table_exists(conn,'bank_reconciliations'):
            recon_ex = _v511_scalar(conn, "SELECT COUNT(*) FROM bank_reconciliations WHERE status NOT IN ('Reconciled','Closed')", default=0)
            if recon_ex: add('warning','Bank reconciliation exceptions', f'{recon_ex} reconciliation(s) are not yet reconciled/closed.', 'reconciliation', recon_ex)
        # Missing persistent disk warning on Render.
        if os.environ.get('RENDER') and not str(DB_PATH).startswith('/var/data'):
            add('danger','Persistent disk not detected', 'RENDER_DATA_DIR is not pointing to /var/data; database may not survive redeploys.', 'production-control', 1)
        return {'ok': True, 'alerts': alerts, 'generated_at': _v511_now()}
    finally:
        conn.close()


def api_production_control(session):
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    _v511_migration(); conn=get_db(); checks=[]
    try:
        def add(name, status, detail):
            checks.append({'check':name,'status':status,'detail':detail})
        add('Database persistent disk', 'PASS' if (not os.environ.get('RENDER') or str(DB_PATH).startswith('/var/data')) else 'FAIL', str(DB_PATH))
        add('Soft delete register', 'PASS' if _v511_table_exists(conn,'soft_deleted_items') else 'FAIL', 'Deleted records are retained and restorable by Admin')
        add('Budget upload validation', 'PASS' if _v511_table_exists(conn,'budget_upload_validation_reports') else 'FAIL', 'Pre-import validation reports are stored')
        add('Workflow register', 'PASS' if _v511_table_exists(conn,'transaction_workflows') else 'FAIL', 'PV/budget/receipt workflow status is tracked')
        add('Audit change log', 'PASS' if _v511_table_exists(conn,'audit_change_log') else 'FAIL', 'Old/new snapshots are captured for controlled saves')
        users = int(_v511_scalar(conn, "SELECT COUNT(*) FROM users WHERE active=1", default=0) or 0) if _v511_table_exists(conn,'users') else 0
        add('Active user accounts', 'PASS' if users>0 else 'FAIL', f'{users} active user(s)')
        backups = int(_v511_scalar(conn, "SELECT COUNT(*) FROM backup_log", default=0) or 0) if _v511_table_exists(conn,'backup_log') else 0
        add('Backup log', 'PASS' if backups>0 else 'WARN', f'{backups} backup record(s); create a backup before go-live')
        gl_ok = abs(float(_v511_scalar(conn,"SELECT COALESCE(SUM(debit_amount),0) FROM general_ledger", default=0) or 0) - float(_v511_scalar(conn,"SELECT COALESCE(SUM(credit_amount),0) FROM general_ledger", default=0) or 0)) < 0.01
        add('Double-entry ledger', 'PASS' if gl_ok else 'FAIL', 'Debit and credit totals balance' if gl_ok else 'General ledger is out of balance')
        score = round(100 * sum(1 for c in checks if c['status']=='PASS') / max(1, len(checks)), 1)
        status = 'Ready' if score >= 85 and all(c['status']!='FAIL' for c in checks) else 'Review Required'
        conn.execute("INSERT INTO production_control_log(id,check_name,status,details,created_by) VALUES(?,?,?,?,?)", (str(uuid.uuid4()), 'v5.0.22_production_control', status, f'score={score}', (session or {}).get('username','system')))
        conn.commit()
        return {'ok': True, 'score': score, 'status': status, 'checks': checks, 'version': '5.0.28-deployment-stability'}
    finally:
        conn.close()

