def _v512_app_name():
    try:
        return 'AOI-FMS' if 'AOI_UNITS' in globals() else 'UCC-FMS'
    except Exception:
        return 'FMS'

def _v512_now():
    try:
        return datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    except Exception:
        return str(time.time())

def _v512_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False

def _v512_scalar(conn, sql, args=(), default=0):
    try:
        row = conn.execute(sql, args).fetchone()
        return row[0] if row is not None else default
    except Exception:
        return default

def _v512_csv(headers, rows):
    out = io.StringIO()
    w = csv.writer(out)
    w.writerow(headers)
    for row in rows:
        if isinstance(row, dict):
            w.writerow([row.get(h, '') for h in headers])
        else:
            w.writerow(row)
    return out.getvalue()

