def _v514_status(checks):
    fail=sum(1 for c in checks if c.get('status')=='FAIL'); warn=sum(1 for c in checks if c.get('status')=='WARN')
    score=round(100*sum(1 for c in checks if c.get('status')=='PASS')/max(1,len(checks)),1)
    status='Ready for Controlled Deployment' if fail==0 and score>=88 else ('Ready With Warnings' if fail==0 else 'Review Required')
    return score,status,fail,warn

def _v514_core_checks(session=None):
    _v514_migration(); checks=[]; base=Path(__file__).parent
    for fn in ['app.py','server.py','index.html','requirements.txt','Procfile','render.yaml','runtime.txt']:
        _v514_add(checks,'files','Required deployment file: '+fn,'PASS' if (base/fn).exists() else 'FAIL','available' if (base/fn).exists() else 'missing')
    try: app_txt=(base/'app.py').read_text(encoding='utf-8',errors='ignore')
    except Exception: app_txt=''
    for r in ['/api/dashboard','/api/budgets','/api/actuals','/api/fund-receipts','/api/withholding-payables','/api/coa','/api/system-assurance','/api/database-migration-check','/api/backup-restore-centre']:
        _v514_add(checks,'routes','Route registered: '+r,'PASS' if r in app_txt else 'FAIL','route marker found' if r in app_txt else 'route marker missing',r)
    try: idx=(base/'index.html').read_text(encoding='utf-8',errors='ignore')
    except Exception: idx=''
    for marker,label in [('v514-option','COA dropdown display repair'),('v507RenderCombo','COA type/select engine'),('vWithholdingPayables','Withholding payable UI'),('v514SystemAssurance','System assurance UI'),('Enterprise Controls','Enterprise Controls navigation')]:
        _v514_add(checks,'frontend','Frontend marker: '+label,'PASS' if marker in idx else 'FAIL','installed' if marker in idx else 'not detected')
    conn=get_db()
    try:
        try: conn.execute('SELECT 1'); _v514_add(checks,'database','Database connection','PASS',str(DB_PATH))
        except Exception as exc: _v514_add(checks,'database','Database connection','FAIL',exc)
        parent=Path(DB_PATH).parent; _v514_add(checks,'database','Database directory writable','PASS' if os.access(str(parent), os.W_OK) else 'FAIL',str(parent))
        for t in ['users','chart_of_accounts','audit_log','projects','budgets','actuals','fund_receipts','general_ledger','accounting_periods','soft_deleted_items','transaction_workflows','budget_upload_validation_reports','system_assurance_runs']:
            _v514_add(checks,'database','Table available: '+t,'PASS' if _v514_table_exists(conn,t) else 'WARN','available' if _v514_table_exists(conn,t) else 'not yet created')
        if _v514_table_exists(conn,'general_ledger'):
            dr=float(_v514_scalar(conn,"SELECT COALESCE(SUM(debit_amount),0) FROM general_ledger",default=0) or 0); cr=float(_v514_scalar(conn,"SELECT COALESCE(SUM(credit_amount),0) FROM general_ledger",default=0) or 0)
            _v514_add(checks,'integrity','General ledger balance','PASS' if abs(dr-cr)<=0.01 else 'FAIL',f'Dr={dr:,.2f}; Cr={cr:,.2f}; Difference={abs(dr-cr):,.2f}','general-ledger')
        active=int(_v514_scalar(conn,"SELECT COUNT(*) FROM users WHERE COALESCE(active,1)=1",default=0) or 0) if _v514_table_exists(conn,'users') else 0
        _v514_add(checks,'security','Active users configured','PASS' if active else 'FAIL',f'{active} active user(s)','users')
        errors=int(_v514_scalar(conn,"SELECT COUNT(*) FROM client_error_log WHERE datetime(created_at)>=datetime('now','-1 day')",default=0) or 0) if _v514_table_exists(conn,'client_error_log') else 0
        _v514_add(checks,'frontend','Client errors in last 24 hours','PASS' if errors==0 else 'WARN',f'{errors} captured browser error(s)','client-errors')
        backups=int(_v514_scalar(conn,"SELECT COUNT(*) FROM backup_log",default=0) or 0) if _v514_table_exists(conn,'backup_log') else 0
        _v514_add(checks,'backup','Backup evidence','PASS' if backups>0 else 'WARN',f'{backups} backup record(s); create a backup before go-live','backup')
        _v514_add(checks,'deployment','Persistent disk path','PASS' if (not os.environ.get('RENDER') or str(DB_PATH).startswith('/var/data')) else 'FAIL',str(DB_PATH))
    finally: conn.close()
    return checks

