        req={'actuals':['is_deleted','workflow_stage','approval_status','payment_status','approved_by','approved_at'],'fund_receipts':['is_deleted','workflow_stage','approval_status','approved_by','approved_at'],'budget_uploads':['is_deleted','validation_report_id','deleted_at','delete_reason'],'quarterly_budgets':['is_deleted','upload_batch','deleted_at','delete_reason'],'audit_log':['old_snapshot','new_snapshot','reason'],'soft_deleted_items':['snapshot_json','deleted_by','restored_by','status']}
        for table,cols in req.items():
            have=set(_v514_cols(conn,table)) if _v514_table_exists(conn,table) else set()
