# ── v5.0.22 Public Readiness Cleanup: reviewed browser-error reset ─────────
def api_clear_client_errors(data=None, session=None):
    """Clear captured browser errors after they have been reviewed/resolved."""
    try:
        conn = get_db()
        cur = conn.cursor()
        cur.execute("CREATE TABLE IF NOT EXISTS client_error_log (id TEXT PRIMARY KEY, page TEXT, message TEXT, stack TEXT, browser TEXT, created_by TEXT, created_at TEXT)")
        before = cur.execute("SELECT COUNT(*) FROM client_error_log").fetchone()[0]
        cur.execute("DELETE FROM client_error_log")
        try:
            conn.execute("""INSERT INTO audit_log(id,action,entity_type,entity_id,details,created_by,created_at)
                            VALUES(?,?,?,?,?,?,?)""", (str(uuid.uuid4()), 'CLEAR_CLIENT_ERRORS', 'client_error_log', 'all', f'Cleared {before} reviewed browser error(s)', (session or {}).get('username','system'), datetime.now().isoformat()))
        except Exception:
            pass
        conn.commit(); conn.close()
        return {"ok": True, "cleared": int(before), "message": f"Cleared {before} reviewed browser error(s)."}
    except Exception as exc:
        return {"ok": False, "error": str(exc)}


