GO_LIVE_RELEASE = "Go-Live Stability Build"


def _glv_app_name():
    return "UCC-FMS"


def _glv_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False


def _glv_cols(conn, table):
    try:
        return [r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()]
    except Exception:
        return []


def _glv_scalar(conn, sql, args=(), default=0):
    try:
        row = conn.execute(sql, args).fetchone()
        return row[0] if row is not None else default
    except Exception:
        return default


def _glv_add(checks, domain, control, status, evidence='', route='', owner=''):
    checks.append({
        'domain': domain,
        'control': control,
        'status': status,
        'evidence': str(evidence or ''),
        'route': route,
        'owner': owner or 'Finance / System Admin'
    })


def _glv_status(checks):
    total = max(1, len(checks))
    fail = sum(1 for c in checks if str(c.get('status')).upper() == 'FAIL')
    warn = sum(1 for c in checks if str(c.get('status')).upper() == 'WARN')
    passed = sum(1 for c in checks if str(c.get('status')).upper() == 'PASS')
    score = round((passed / total) * 100, 1)
    status = 'Go-Live Ready' if fail == 0 and score >= 90 else ('Ready With Management Actions' if fail == 0 else 'Hold for Correction')
    return score, status, fail, warn


