def api_workflow_compliance(session):
    """Enterprise compliance matrix for IPSAS reporting, double-entry, projects, inventory and payroll."""
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    _glv_migration()
    conn = get_db()
    checks, metrics = [], {}
    try:
        # IPSAS / reporting evidence
        report_tables = ['chart_of_accounts', 'general_ledger', 'journal_vouchers', 'accounting_periods']
        for table in report_tables:
            _glv_add(checks, 'IPSAS reporting', f'Required reporting table: {table}',
                     'PASS' if _glv_table_exists(conn, table) else 'FAIL',
                     'available' if _glv_table_exists(conn, table) else 'missing', 'reports')
        periods = int(_glv_scalar(conn, "SELECT COUNT(*) FROM accounting_periods", default=0) or 0) if _glv_table_exists(conn, 'accounting_periods') else 0
        _glv_add(checks, 'IPSAS reporting', 'Accounting period configured', 'PASS' if periods else 'WARN', f'{periods} period row(s)', 'accounting-periods')

        # Double-entry integrity
        if _glv_table_exists(conn, 'general_ledger'):
            dr = float(_glv_scalar(conn, "SELECT COALESCE(SUM(debit_amount),0) FROM general_ledger", default=0) or 0)
            cr = float(_glv_scalar(conn, "SELECT COALESCE(SUM(credit_amount),0) FROM general_ledger", default=0) or 0)
            diff = round(abs(dr - cr), 2)
            metrics['total_debits'] = dr; metrics['total_credits'] = cr; metrics['ledger_difference'] = diff
            _glv_add(checks, 'Double entry', 'General ledger balances', 'PASS' if diff <= 0.01 else 'FAIL',
                     f'Debits {dr:,.2f}; Credits {cr:,.2f}; Difference {diff:,.2f}', 'general-ledger')
        if _glv_table_exists(conn, 'journal_vouchers'):
            unbalanced = int(_glv_scalar(conn, """SELECT COUNT(*) FROM journal_vouchers
                WHERE status='Posted' AND ABS(COALESCE(total_debit,0)-COALESCE(total_credit,0)) > 0.01""", default=0) or 0)
            _glv_add(checks, 'Double entry', 'Posted vouchers are balanced', 'PASS' if unbalanced == 0 else 'FAIL',
                     f'{unbalanced} unbalanced posted voucher(s)', 'journal-vouchers')
            posted_without_gl = int(_glv_scalar(conn, """SELECT COUNT(*) FROM journal_vouchers j
                WHERE j.status='Posted' AND NOT EXISTS (SELECT 1 FROM general_ledger gl WHERE gl.jv_id=j.id)""", default=0) or 0) if _glv_table_exists(conn, 'general_ledger') else 0
            _glv_add(checks, 'Double entry', 'Posted vouchers have ledger lines', 'PASS' if posted_without_gl == 0 else 'FAIL',
                     f'{posted_without_gl} posted voucher(s) without GL lines', 'journal-vouchers')

        # Project management workflow
        for table in ['projects', 'budgets', 'commitments', 'actuals', 'fund_receipts']:
            _glv_add(checks, 'Project management', f'Workflow table: {table}', 'PASS' if _glv_table_exists(conn, table) else 'FAIL',
                     'available' if _glv_table_exists(conn, table) else 'missing', table.replace('_','-'))
        if _glv_table_exists(conn, 'actuals') and _glv_table_exists(conn, 'projects'):
            orphan_actuals = int(_glv_scalar(conn, """SELECT COUNT(*) FROM actuals a
                WHERE a.project_id IS NOT NULL AND a.project_id<>''
                AND NOT EXISTS (SELECT 1 FROM projects p WHERE p.id=a.project_id)""", default=0) or 0)
            _glv_add(checks, 'Project management', 'Payments remain linked to valid projects', 'PASS' if orphan_actuals == 0 else 'FAIL',
                     f'{orphan_actuals} orphan payment record(s)', 'actuals')
        if _glv_table_exists(conn, 'budgets') and _glv_table_exists(conn, 'actuals'):
            over_budget = int(_glv_scalar(conn, """SELECT COUNT(*) FROM budgets b
                WHERE COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id AND COALESCE(a.is_posted,0)=1),0) > COALESCE(b.budget_ghs,0) + 0.01""", default=0) or 0)
            _glv_add(checks, 'Project management', 'Posted actuals do not exceed budget lines', 'PASS' if over_budget == 0 else 'WARN',
                     f'{over_budget} over-budget budget line(s)', 'budget-control')

        # Inventory / stores evidence through fuel coupon inventory tables
        has_batches = _glv_table_exists(conn, 'fuel_coupon_batches')
        has_moves = _glv_table_exists(conn, 'fuel_coupon_movements')
        _glv_add(checks, 'Inventory and stores', 'Fuel / coupon inventory master exists', 'PASS' if has_batches else 'WARN', 'available' if has_batches else 'not configured yet', 'fuel')
        _glv_add(checks, 'Inventory and stores', 'Fuel / coupon movement ledger exists', 'PASS' if has_moves else 'WARN', 'available' if has_moves else 'not configured yet', 'fuel')
        if has_batches and has_moves:
            procured = float(_glv_scalar(conn, "SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_batches", default=0) or 0)
            borrowed = float(_glv_scalar(conn, "SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Borrow'", default=0) or 0)
            issued = float(_glv_scalar(conn, "SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type IN ('Issue','Lend')", default=0) or 0)
            returned = float(_glv_scalar(conn, "SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type LIKE 'Return%'", default=0) or 0)
            balance = round(procured + borrowed - issued + returned, 2)
            metrics['inventory_balance_ghs'] = balance
            _glv_add(checks, 'Inventory and stores', 'Inventory balance is not negative', 'PASS' if balance >= -0.01 else 'FAIL',
                     f'Calculated fuel/coupon balance {balance:,.2f}', 'fuel')

        # Payroll compliance workflow
        for table in ['employees', 'payroll_settings', 'payroll_register', 'payroll_audit']:
            _glv_add(checks, 'Payroll', f'Payroll table: {table}', 'PASS' if _glv_table_exists(conn, table) else 'FAIL',
                     'available' if _glv_table_exists(conn, table) else 'missing', 'payroll')
        if _glv_table_exists(conn, 'payroll_register'):
            negative_net = int(_glv_scalar(conn, "SELECT COUNT(*) FROM payroll_register WHERE COALESCE(net_pay,0) < 0", default=0) or 0)
            _glv_add(checks, 'Payroll', 'Net pay values are non-negative', 'PASS' if negative_net == 0 else 'FAIL',
                     f'{negative_net} negative net pay record(s)', 'payroll')
            months = int(_glv_scalar(conn, "SELECT COUNT(DISTINCT payroll_month) FROM payroll_register", default=0) or 0)
            _glv_add(checks, 'Payroll', 'Payroll schedules can be generated safely', 'PASS',
                     f'{months} posted/draft payroll month(s); empty systems default to the current month without error', 'payroll')

        # Security / go-live management actions that should remain visible, not hidden.
        if _glv_table_exists(conn, 'users'):
            active_users = int(_glv_scalar(conn, "SELECT COUNT(*) FROM users WHERE COALESCE(active,1)=1", default=0) or 0)
            _glv_add(checks, 'Security and governance', 'Active users exist', 'PASS' if active_users else 'FAIL', f'{active_users} active user(s)', 'users')
        backups = int(_glv_scalar(conn, "SELECT COUNT(*) FROM backup_log", default=0) or 0) if _glv_table_exists(conn, 'backup_log') else 0
        _glv_add(checks, 'Security and governance', 'Pre-go-live backup evidence', 'PASS' if backups else 'WARN',
                 f'{backups} backup record(s). Create a manual backup before live cut-over.', 'backup-restore')
    finally:
        conn.close()

    score, status, fail, warn = _glv_status(checks)
    grouped = {}
    for c in checks:
        grouped.setdefault(c['domain'], {'total':0, 'pass':0, 'warn':0, 'fail':0})
        grouped[c['domain']]['total'] += 1
        grouped[c['domain']][str(c['status']).lower()] += 1
    try:
        conn = get_db()
        conn.execute("INSERT INTO go_live_evidence_log(id,app_name,version,score,status,checks_json,created_by) VALUES(?,?,?,?,?,?,?)",
                     (str(uuid.uuid4()), _glv_app_name(), GO_LIVE_VERSION, score, status, json.dumps(checks, ensure_ascii=False), (session or {}).get('username','system')))
        conn.commit(); conn.close()
    except Exception:
        pass
    return ok({
        'app': _glv_app_name(),
        'version': GO_LIVE_VERSION,
        'release': GO_LIVE_RELEASE,
        'score': score,
        'status': status,
        'failed': fail,
        'warnings': warn,
        'metrics': metrics,
        'domains': grouped,
        'checks': checks,
        'generated_at': datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    })


def api_export_workflow_compliance_csv(session):
    res = api_workflow_compliance(session)
    rows = []
    for c in res.get('checks', []):
        rows.append([res.get('app'), res.get('version'), res.get('generated_at'), res.get('score'), res.get('status'), c.get('domain'), c.get('control'), c.get('status'), c.get('evidence'), c.get('route'), c.get('owner')])
    out = io.StringIO(); w = csv.writer(out)
    w.writerow(['App','Version','Generated At','Score','Overall Status','Domain','Control','Status','Evidence','Route','Owner'])
    w.writerows(rows)
    return out.getvalue()


