def api_system_assurance(session):
    base = _glv_previous_api_system_assurance(session) if callable(_glv_previous_api_system_assurance) else ok({'checks': []})
    comp = api_workflow_compliance(session) if session else {'ok': False, 'score': 0, 'failed': 1, 'warnings': 0}
    if isinstance(base, dict):
        base['app'] = _glv_app_name()
        base['version'] = GO_LIVE_VERSION
        base['release'] = GO_LIVE_RELEASE
        checks = list(base.get('checks') or [])
        checks.append({'category': 'workflow', 'test': 'Workflow compliance matrix', 'status': 'PASS' if comp.get('failed', 0) == 0 else 'FAIL', 'detail': f"{comp.get('status')} — score {comp.get('score')}% with {comp.get('warnings')} warning(s)", 'route': 'workflow-compliance'})
        base['checks'] = checks
        score, status, fail, warn = _glv_status([
            {'status': x.get('status','PASS')} for x in checks
        ])
        base['score'] = score
        base['status'] = 'Go-Live Ready' if fail == 0 and comp.get('failed',0) == 0 and score >= 90 else ('Ready With Management Actions' if fail == 0 and comp.get('failed',0) == 0 else 'Hold for Correction')
        base['failed'] = fail + int(comp.get('failed', 0) or 0)
        base['warnings'] = warn + int(comp.get('warnings', 0) or 0)
    return base


