def api_fuel_control_report(session):
    if not session: return err('Not authenticated')
    _ice_migration(); conn=get_db()
    try:
        stock = api_fuel_stock_health(session)
        pending = int(_ice_scalar(conn, "SELECT COUNT(*) FROM approvals WHERE module IN ('fuel_coupon_batches','fuel_coupon_movements') AND status='Pending'", default=0)) if _ice_table_exists(conn,'approvals') else 0
        missing_docs = 0
        if _ice_table_exists(conn, 'document_attachments'):
            missing_docs += int(_ice_scalar(conn, """SELECT COUNT(*) FROM fuel_coupon_batches b WHERE COALESCE(b.ledger_posted,0)=1 AND NOT EXISTS(SELECT 1 FROM document_attachments d WHERE d.module='fuel_coupon_batches' AND d.record_id=b.id)""", default=0))
            missing_docs += int(_ice_scalar(conn, """SELECT COUNT(*) FROM fuel_coupon_movements m WHERE COALESCE(m.ledger_posted,0)=1 AND NOT EXISTS(SELECT 1 FROM document_attachments d WHERE d.module='fuel_coupon_movements' AND d.record_id=m.id)""", default=0))
        low_threshold = _ice_money(_ice_setting(conn, 'fuel_low_stock_threshold_ghs', '500'))
        balance = _ice_money((stock or {}).get('calculated_stock_value') if isinstance(stock, dict) else 0)
        issue_exp = _ice_money(_ice_scalar(conn, "SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Issue' AND COALESCE(ledger_posted,0)=1 AND COALESCE(ledger_reversed,0)=0", default=0))
        by_vehicle = [dict(r) for r in conn.execute("""SELECT COALESCE(vehicle_number,'Unspecified') vehicle_number, COUNT(*) movements, COALESCE(SUM(face_value),0) value
                                                     FROM fuel_coupon_movements WHERE movement_type='Issue' GROUP BY COALESCE(vehicle_number,'Unspecified') ORDER BY value DESC LIMIT 20""").fetchall()] if _ice_table_exists(conn,'fuel_coupon_movements') else []
        by_project = [dict(r) for r in conn.execute("""SELECT COALESCE(p.project_code,'Unassigned') project_code, COALESCE(p.title,'Unassigned') project_title, COUNT(m.id) movements, COALESCE(SUM(m.face_value),0) value
                                                     FROM fuel_coupon_movements m LEFT JOIN projects p ON p.id=m.project_id WHERE m.movement_type='Issue' GROUP BY m.project_id ORDER BY value DESC LIMIT 20""").fetchall()] if _ice_table_exists(conn,'fuel_coupon_movements') else []
        warnings = list((stock or {}).get('warnings', []) if isinstance(stock, dict) else [])
        if balance <= low_threshold:
            warnings.append(f'Fuel coupon stock is at or below the configured threshold of GHS {low_threshold:,.2f}.')
        if pending:
            warnings.append(f'{pending} fuel approval request(s) are pending.')
        if missing_docs:
            warnings.append(f'{missing_docs} posted fuel transaction(s) do not yet have supporting attachments.')
        return ok({'version': ICE_VERSION, 'stock': stock, 'pending_approvals': pending, 'missing_documents': missing_docs, 'posted_issue_expense': issue_exp, 'by_vehicle': by_vehicle, 'by_project': by_project, 'warnings': warnings, 'generated_at': _ice_now()})
    finally: conn.close()


def api_export_fuel_control_csv(session):
    d = api_fuel_control_report(session)
    out = io.StringIO(); w = csv.writer(out)
    w.writerow(['Fuel Control Report', _ice_now()])
    if not d.get('ok'):
        w.writerow(['Error', d.get('error')]); return out.getvalue()
    w.writerow([]); w.writerow(['Metric','Value'])
    w.writerow(['Calculated Stock', ((d.get('stock') or {}).get('calculated_stock_value') if isinstance(d.get('stock'), dict) else '')])
    w.writerow(['Posted Issue Expense', d.get('posted_issue_expense')])
    w.writerow(['Pending Approvals', d.get('pending_approvals')])
    w.writerow(['Missing Documents', d.get('missing_documents')])
    w.writerow([]); w.writerow(['Warnings'])
    for x in d.get('warnings', []): w.writerow([x])
    w.writerow([]); w.writerow(['Vehicle','Movements','Value'])
    for r in d.get('by_vehicle', []): w.writerow([r.get('vehicle_number'), r.get('movements'), r.get('value')])
    w.writerow([]); w.writerow(['Project','Title','Movements','Value'])
    for r in d.get('by_project', []): w.writerow([r.get('project_code'), r.get('project_title'), r.get('movements'), r.get('value')])
    return out.getvalue()


def api_management_reports(session):
    if not session: return err('Not authenticated')
    _ice_migration(); conn=get_db()
    try:
        summary = {
            'projects': int(_ice_scalar(conn, "SELECT COUNT(*) FROM projects", default=0)) if _ice_table_exists(conn,'projects') else 0,
            'posted_pvs': int(_ice_scalar(conn, "SELECT COUNT(*) FROM actuals WHERE COALESCE(is_posted,0)=1", default=0)) if _ice_table_exists(conn,'actuals') else 0,
            'unposted_pvs': int(_ice_scalar(conn, "SELECT COUNT(*) FROM actuals WHERE COALESCE(is_posted,0)=0 AND COALESCE(is_deleted,0)=0", default=0)) if _ice_table_exists(conn,'actuals') else 0,
            'pending_approvals': int(_ice_scalar(conn, "SELECT COUNT(*) FROM approvals WHERE status='Pending'", default=0)) if _ice_table_exists(conn,'approvals') else 0,
            'attachments': int(_ice_scalar(conn, "SELECT COUNT(*) FROM document_attachments", default=0)) if _ice_table_exists(conn,'document_attachments') else 0,
            'posted_fuel_issues': _ice_money(_ice_scalar(conn, "SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Issue' AND COALESCE(ledger_posted,0)=1 AND COALESCE(ledger_reversed,0)=0", default=0)) if _ice_table_exists(conn,'fuel_coupon_movements') else 0,
        }
        exceptions = []
        if _ice_table_exists(conn, 'general_ledger'):
            diff = _ice_money(_ice_scalar(conn, "SELECT COALESCE(SUM(debit_amount),0)-COALESCE(SUM(credit_amount),0) FROM general_ledger", default=0))
            if abs(diff) > 0.01: exceptions.append({'severity':'High','message':f'General ledger is out of balance by GHS {diff:,.2f}.'})
        if _ice_table_exists(conn, 'actuals'):
            unapproved_posted = int(_ice_scalar(conn, """SELECT COUNT(*) FROM actuals a WHERE COALESCE(a.is_posted,0)=1 AND NOT EXISTS(SELECT 1 FROM approvals ap WHERE ap.module='actuals' AND ap.record_id=a.id AND ap.status='Approved')""", default=0)) if _ice_table_exists(conn,'approvals') else 0
            if unapproved_posted: exceptions.append({'severity':'Medium','message':f'{unapproved_posted} posted PV(s) have no approval record. Admin legacy bypass may apply.'})
        fuel = api_fuel_control_report(session)
        return ok({'version': ICE_VERSION, 'summary': summary, 'exceptions': exceptions, 'fuel': fuel, 'generated_at': _ice_now()})
    finally: conn.close()


def api_institutional_readiness(session):
    if not session: return err('Not authenticated')
    _ice_migration(); conn=get_db()
    try:
        checks=[]
        def add(area, item, status, detail=''):
            checks.append({'area':area,'item':item,'status':status,'detail':detail})
        add('Accounting', 'Fuel procurement posts to stock', 'PASS' if _ice_coa_id(conn, None, _ice_setting(conn, 'fuel_procurement_default_stock_coa_code','12107003')) else 'FAIL', 'Dr Fuel Coupon Stock; Cr Bank')
        add('Accounting', 'Fuel issue posts stock to expense', 'PASS' if _ice_coa_id(conn, None, _ice_setting(conn, 'fuel_issue_default_expense_coa_code','61300005')) else 'FAIL', 'Dr Fuel Expense; Cr Fuel Coupon Stock')
        add('Control', 'Approval tables', 'PASS' if _ice_table_exists(conn,'approvals') and _ice_table_exists(conn,'approval_steps') else 'FAIL', 'Generic approval workflow')
        add('Control', 'Document vault', 'PASS' if _ice_table_exists(conn,'document_attachments') else 'FAIL', 'Attachments table')
        add('Control', 'Audit log', 'PASS' if _ice_table_exists(conn,'audit_log') else 'FAIL', 'Audit trail table')
        add('Security', 'Permission matrix', 'PASS' if _ice_table_exists(conn,'permission_matrix') else 'WARN', 'Role-based access control')
        add('Budget', 'Budget overrun blocking', 'PASS' if _ice_bool(_ice_setting(conn,'budget_control_block_overrun','1')) else 'WARN', 'Setting can be changed by Admin')
        add('Deployment', 'No bundled database required', 'PASS', 'Fresh database is created on first launch; no transactional records are seeded')
        fail=sum(1 for c in checks if c['status']=='FAIL'); warn=sum(1 for c in checks if c['status']=='WARN')
        return ok({'version': ICE_VERSION, 'status': 'Ready' if fail==0 else 'Needs Attention', 'warnings': warn, 'failures': fail, 'checks': checks, 'generated_at': _ice_now()})
    finally: conn.close()


