def api_reset_for_deployment(data, session):
    if not session: return err('Not authenticated')
    if not _ice_admin(session): return err('Admin access required to reset deployment data')
    confirm = str((data or {}).get('confirm') or '').strip().upper()
    if confirm not in ('RESET', 'CLEAN DEPLOYMENT', 'YES RESET'):
        return err('Type confirm="RESET" to clear transactional data.')
    _ice_migration(); conn=get_db()
    tables = [
        'general_ledger','jv_lines','jv_audit','journal_vouchers','actuals','commitments','fund_receipts','withholding_payables',
        'invoice_lines','invoices','fuel_coupon_movements','fuel_coupon_batches','fuel_vehicles','approvals','approval_steps','document_attachments',
        'budget_uploads','budgets','quarterly_budgets','dept_allocations','projects','vendors','asset_register','employees','payroll_register','payroll_loans','payroll_audit',
        'bank_reconciliations','bank_recon_items','backup_log','audit_log','soft_deleted_items','transaction_workflows',
        'institutional_exceptions','pilot_feedback','client_errors','pv_batch_import_log','pv_preview_audit'
    ]
    cleaned=[]
    try:
        conn.execute('PRAGMA foreign_keys=OFF')
        for t in tables:
            if _ice_table_exists(conn,t):
                conn.execute(f"DELETE FROM {t}"); cleaned.append(t)
        rid=str(uuid.uuid4())
        conn.execute("INSERT INTO deployment_reset_log(id,reset_scope,tables_cleaned,created_by,notes) VALUES(?,?,?,?,?)", (rid, 'transactional', ','.join(cleaned), session.get('username','system'), (data or {}).get('notes','Clean institutional deployment reset')))
        conn.execute('PRAGMA foreign_keys=ON')
        conn.commit()
        return ok({'id': rid, 'tables_cleaned': cleaned, 'message': 'Operational data cleared. Master setup such as users, COA, settings, bank accounts and institutional units/departments is preserved; projects, budgets, vendors, payroll employees, fuel vehicles and transaction history are reset for first deployment.'})
    except Exception as exc:
        conn.rollback(); return err(f'Deployment reset failed: {exc}')
    finally:
        try: conn.execute('PRAGMA foreign_keys=ON')
        except Exception: pass
        conn.close()


# Production-safe wrappers.
try:
    _ice_prev_api_save_fc_batch = api_save_fc_batch
    def api_save_fc_batch(data, session):
        _ice_migration()
        data = dict(data or {})
        wants_post = _ice_bool(data.get('post_to_ledger'))
        non_admin_deferred = wants_post and not _ice_admin(session)
        if non_admin_deferred:
            data['post_to_ledger'] = 0
        res = _ice_prev_api_save_fc_batch(data, session)
        if isinstance(res, dict) and res.get('ok'):
            conn = get_db()
            try:
                ids = res.get('ids') or ([res.get('id')] if res.get('id') else [])
                for bid in ids:
                    row = conn.execute("SELECT * FROM fuel_coupon_batches WHERE id=?", (bid,)).fetchone()
                    if not row: continue
                    amount = _ice_money(row['cost_value'] if 'cost_value' in row.keys() else row['face_value'])
                    aid, status = _ice_submit_approval(conn, session, 'fuel_coupon_batches', bid, row['batch_number'], amount, row['project_id'] if 'project_id' in row.keys() else None, 'Fuel procurement submitted')
                    if status == 'Approved':
                        conn.execute("UPDATE fuel_coupon_batches SET approval_status='Approved', approved_by=?, approved_at=datetime('now'), submitted_by=?, submitted_at=datetime('now') WHERE id=?", (session.get('username','system'), session.get('username','system'), bid))
                    else:
                        conn.execute("UPDATE fuel_coupon_batches SET approval_status='Pending', workflow_stage='Submitted', submitted_by=?, submitted_at=datetime('now') WHERE id=?", (session.get('username','system'), bid))
                conn.commit()
                if non_admin_deferred:
                    res['ledger_posted'] = 0
                    res['approval_status'] = 'Pending'
                    res['message'] = 'Fuel procurement saved and submitted for approval. Ledger posting will occur after approval.'
            except Exception:
                conn.rollback()
            finally:
                conn.close()
        return res
except Exception as _ice_exc:
    print('Institutional batch save wrapper warning:', _ice_exc)

try:
    _ice_prev_api_save_fc_movement = api_save_fc_movement
    def api_save_fc_movement(data, session):
        _ice_migration()
        data = dict(data or {})
        mv_type = data.get('movement_type','Issue')
        conn = get_db()
        try:
            if _ice_bool(_ice_setting(conn, 'fuel_serial_validation_enabled', '1')) and mv_type in ('Issue','Lend','Return-Borrowed'):
                valid, msg = _ice_validate_serial_range(conn, data.get('batch_id'), data.get('serial_from'), data.get('serial_to'))
                if not valid:
                    return err(msg)
            if mv_type == 'Issue':
                amount = _ice_money(data.get('face_value') or (_ice_money(data.get('denomination')) * _ice_int(data.get('quantity'))))
                ok_budget, budget_msg = _ice_check_budget_for_fuel_issue(conn, session, data.get('project_id'), amount)
                if not ok_budget:
                    return err(budget_msg)
        finally:
            conn.close()
        res = _ice_prev_api_save_fc_movement(data, session)
        if isinstance(res, dict) and res.get('ok') and res.get('id'):
            mid = res.get('id')
            conn = get_db()
            try:
                row = conn.execute("SELECT * FROM fuel_coupon_movements WHERE id=?", (mid,)).fetchone()
                if row:
                    amount = _ice_money(row['face_value'])
                    aid, status = _ice_submit_approval(conn, session, 'fuel_coupon_movements', mid, f"{row['movement_type']} {mid[:8]}", amount, row['project_id'] if 'project_id' in row.keys() else None, 'Fuel movement submitted')
                    if status == 'Approved':
                        conn.execute("UPDATE fuel_coupon_movements SET approval_status='Approved', approved_by=?, approved_at=datetime('now'), submitted_by=?, submitted_at=datetime('now') WHERE id=?", (session.get('username','system'), session.get('username','system'), mid))
                    else:
                        conn.execute("UPDATE fuel_coupon_movements SET approval_status='Pending', workflow_stage='Submitted', submitted_by=?, submitted_at=datetime('now') WHERE id=?", (session.get('username','system'), mid))
                    # Admin auto-posts fuel issue and issued returns according to institutional policy.
                    if _ice_admin(session) and row['movement_type'] in ('Issue','Return-Issued','Return') and _ice_bool(_ice_setting(conn,'fuel_issue_auto_post_to_ledger','1')):
                        post_res = _ice_post_fuel_movement(conn, session, mid, False)
                        if post_res.get('ok'):
                            res.update({'ledger_posted':1, 'jv_id':post_res.get('jv_id'), 'jv_number':post_res.get('jv_number'), 'message':post_res.get('message')})
                        else:
                            res.update({'ledger_posted':0, 'ledger_warning':post_res.get('error')})
                conn.commit()
            except Exception as exc:
                conn.rollback(); res.setdefault('ledger_warning', str(exc))
            finally:
                conn.close()
        return res
except Exception as _ice_exc:
    print('Institutional movement save wrapper warning:', _ice_exc)

