# ---------------------------------------------------------------------------
# Runtime stability route bridge for local HTTPServer mode
# Keeps local `python server.py` behaviour aligned with Render/Gunicorn app.py.
# ---------------------------------------------------------------------------
try:
    _runtime_prev_do_GET = Handler.do_GET
    def _runtime_do_GET(self):
        parsed = urlparse(self.path); path = parsed.path; qs = parse_qs(parsed.query)
        session = self.get_session()
        if path.startswith('/api/') and not session and path not in ('/api/login','/api/health','/api/client-error'):
            return self.send_json({'error':'Not authenticated'}, 401)
        if session:
            if path in ('/api/dept-summary','/api/unit-summary'):
                return self.send_json(api_dept_summary(session))
            if path == '/api/final-system-audit':
                return self.send_json(api_final_system_audit(session))
            if path == '/api/go-live-readiness':
                return self.send_json(api_go_live_readiness(session))
            if path == '/api/system-health':
                return self.send_json(api_system_health(session))
            if path == '/api/takeoff-wizard':
                return self.send_json(api_takeoff_wizard(session))
            if path == '/api/acceptance-testing':
                return self.send_json(api_acceptance_testing(session))
            if path == '/api/stability-audit':
                return self.send_json(api_stability_audit(session))
            if path == '/api/quality-seal':
                return self.send_json(api_quality_seal(session))
        return _runtime_prev_do_GET(self)
    Handler.do_GET = _runtime_do_GET
except Exception as _runtime_route_exc:
    print('Runtime stability local route bridge warning:', _runtime_route_exc)



# ═════════════════════════════════════════════════════════════════════════════
# DEPLOYMENT POLISH PACK: fuel return serial controls, batch over issue guard,
# budget deletion hygiene, and clean deployment reset hardening.
# This is intentionally additive and overrides earlier wrappers safely.
# ═════════════════════════════════════════════════════════════════════════════
DEPLOYMENT_POLISH_VERSION = '2026.05.21-fuel-return-budget-ui-polish'


def _dpx_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False


def _dpx_cols(conn, table):
    try:
        return {r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()}
    except Exception:
        return set()


def _dpx_add_col(conn, table, coldef):
    try:
        name = coldef.split()[0]
        if _dpx_table_exists(conn, table) and name not in _dpx_cols(conn, table):
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {coldef}")
    except Exception:
        pass


def _dpx_migration():
    conn = get_db()
    try:
        if _dpx_table_exists(conn, 'fuel_coupon_movements'):
            for col in [
                'source_movement_id TEXT', 'serial_from TEXT', 'serial_to TEXT',
                'issuing_officer TEXT', 'receiving_officer TEXT', 'vehicle_id TEXT',
                'vehicle_number TEXT', 'ledger_reversed INTEGER DEFAULT 0',
                'is_deleted INTEGER DEFAULT 0', 'updated_by TEXT', 'updated_at TEXT'
            ]:
                _dpx_add_col(conn, 'fuel_coupon_movements', col)
        if _dpx_table_exists(conn, 'fuel_coupon_batches'):
            for col in ['serial_from TEXT', 'serial_to TEXT', 'is_deleted INTEGER DEFAULT 0', 'updated_by TEXT', 'updated_at TEXT']:
                _dpx_add_col(conn, 'fuel_coupon_batches', col)
        for tbl in ['budgets', 'quarterly_budgets', 'actuals', 'commitments']:
            if _dpx_table_exists(conn, tbl):
                _dpx_add_col(conn, tbl, 'is_deleted INTEGER DEFAULT 0')
                _dpx_add_col(conn, tbl, 'deleted_at TEXT')
                _dpx_add_col(conn, tbl, 'deleted_by TEXT')
                _dpx_add_col(conn, tbl, 'delete_reason TEXT')
        if _dpx_table_exists(conn, 'settings'):
            defaults = [
                ('fuel_batch_overissue_guard_enabled','1','Block issue quantity above the selected batch balance'),
                ('fuel_return_source_required','1','Require original issue record when returning issued coupons'),
                ('fuel_return_serial_containment_enabled','1','Returned coupon serial range must fall within the original issue serial range'),
                ('budget_report_exclude_deleted','1','Budget and performance reports exclude deleted budget lines and deleted actuals'),
                ('deployment_polish_pack_version', DEPLOYMENT_POLISH_VERSION, 'Deployment polish pack version'),
            ]
            for k, v, d in defaults:
                conn.execute("INSERT OR IGNORE INTO settings(key,value,description) VALUES(?,?,?)", (k, v, d))
        conn.commit()
    finally:
        conn.close()


def _dpx_bool(v):
    if isinstance(v, bool): return v
    if isinstance(v, (int, float)): return bool(v)
    return str(v or '').strip().lower() in ('1','true','yes','y','on','checked')


def _dpx_int(v, default=0):
    try:
        if v is None or v == '': return int(default)
        return int(float(str(v).replace(',', '').strip()))
    except Exception:
        return int(default)


def _dpx_float(v, default=0.0):
    try:
        if v is None or v == '': return float(default)
        return float(str(v).replace(',', '').strip())
    except Exception:
        return float(default)


def _dpx_setting(conn, key, default=None):
    try:
        row = conn.execute("SELECT value FROM settings WHERE key=?", (key,)).fetchone()
        return row[0] if row else default
    except Exception:
        return default


def _dpx_active_clause(alias=''):
    p = (alias + '.') if alias else ''
    return f"COALESCE({p}ledger_reversed,0)=0 AND COALESCE({p}is_deleted,0)=0"


def _dpx_serial_key(value):
    s = str(value or '').strip().upper()
    if not s:
        return ('', None, 0)
    m = re.match(r'^(.*?)(\d+)$', s)
    if m:
        return (m.group(1), int(m.group(2)), len(m.group(2)))
    return (s, None, 0)


def _dpx_serial_count(start, end):
    if not start or not end:
        return None
    p1, n1, _ = _dpx_serial_key(start)
    p2, n2, _ = _dpx_serial_key(end)
    if n1 is None or n2 is None or p1 != p2:
        return None
    return abs(n2 - n1) + 1


def _dpx_serial_contains(parent_from, parent_to, child_from, child_to):
    if not parent_from or not parent_to:
        return True
    if not child_from or not child_to:
        return False
    pp1, pn1, _ = _dpx_serial_key(parent_from)
    pp2, pn2, _ = _dpx_serial_key(parent_to)
    cp1, cn1, _ = _dpx_serial_key(child_from)
    cp2, cn2, _ = _dpx_serial_key(child_to)
    if None in (pn1, pn2, cn1, cn2):
        pf = str(parent_from).strip().upper(); pt = str(parent_to).strip().upper()
        cf = str(child_from).strip().upper(); ct = str(child_to).strip().upper()
        return pf <= cf <= pt and pf <= ct <= pt
    if pp1 != pp2 or cp1 != cp2 or pp1 != cp1:
        return False
    plo, phi = min(pn1, pn2), max(pn1, pn2)
    clo, chi = min(cn1, cn2), max(cn1, cn2)
    return plo <= clo and chi <= phi


def _dpx_serial_overlap(a1, a2, b1, b2):
    if not a1 or not a2 or not b1 or not b2:
        return False
    p1, n1, _ = _dpx_serial_key(a1); p2, n2, _ = _dpx_serial_key(a2)
    q1, m1, _ = _dpx_serial_key(b1); q2, m2, _ = _dpx_serial_key(b2)
    if None in (n1, n2, m1, m2):
        return str(a1).strip().upper() == str(b1).strip().upper() or str(a2).strip().upper() == str(b2).strip().upper()
    if p1 != p2 or q1 != q2 or p1 != q1:
        return False
    lo1, hi1 = min(n1,n2), max(n1,n2)
    lo2, hi2 = min(m1,m2), max(m1,m2)
    return max(lo1, lo2) <= min(hi1, hi2)


def _dpx_batch_available_qty(conn, batch_id, exclude_id=None):
    if not batch_id:
        return None
    b = conn.execute("SELECT * FROM fuel_coupon_batches WHERE id=?", (batch_id,)).fetchone()
    if not b:
        return None
    qty = _dpx_int(b['quantity'] if 'quantity' in b.keys() else 0)
    args = [batch_id]
    ex = ''
    if exclude_id:
        ex = ' AND id<>?'; args.append(exclude_id)
    active = _dpx_active_clause('')
    rows = conn.execute(f"""
        SELECT movement_type, COALESCE(SUM(quantity),0) qty
        FROM fuel_coupon_movements
        WHERE batch_id=? AND {active} {ex}
        GROUP BY movement_type
    """, args).fetchall()
    m = {r['movement_type']: _dpx_int(r['qty']) for r in rows}
    out_qty = m.get('Issue',0) + m.get('Lend',0) + m.get('Return-Borrowed',0)
    in_qty = m.get('Return',0) + m.get('Return-Issued',0) + m.get('Return-Lent',0)
    return {'batch': dict(b), 'procured_qty': qty, 'out_qty': out_qty, 'return_qty': in_qty, 'available_qty': qty - out_qty + in_qty}


def _dpx_source_returned_qty(conn, source_id, exclude_id=None):
    if not source_id:
        return 0
    args = [source_id]
    ex = ''
    if exclude_id:
        ex = ' AND id<>?'; args.append(exclude_id)
    row = conn.execute(f"""
        SELECT COALESCE(SUM(quantity),0) FROM fuel_coupon_movements
        WHERE source_movement_id=? AND movement_type IN ('Return','Return-Issued')
          AND {_dpx_active_clause('')} {ex}
    """, args).fetchone()
    return _dpx_int(row[0] if row else 0)


def _dpx_fill_return_from_source(conn, data):
    source_id = data.get('source_movement_id') or data.get('return_source_id')
    if not source_id:
        return None
    src = conn.execute("SELECT * FROM fuel_coupon_movements WHERE id=?", (source_id,)).fetchone()
    if not src:
        return None
    srcd = dict(src)
    for k in ('batch_id','project_id','denomination','vehicle_id','vehicle_number'):
        if not data.get(k):
            data[k] = srcd.get(k)
    if not data.get('from_entity'):
        data['from_entity'] = srcd.get('to_entity') or srcd.get('vehicle_number') or ''
    if not data.get('to_entity'):
        data['to_entity'] = 'Central Fuel Store'
    if not data.get('officer'):
        data['officer'] = srcd.get('officer') or ''
    if not data.get('issuing_officer'):
        data['issuing_officer'] = srcd.get('issuing_officer') or srcd.get('officer') or ''
    return srcd


def _dpx_validate_issue_against_batch(conn, data, exclude_id=None):
    mv_type = data.get('movement_type') or 'Issue'
    if mv_type != 'Issue':
        return True, ''
    batch_id = data.get('batch_id')
    if not batch_id:
        return False, 'Select the exact fuel coupon batch before issuing. Batch level control is required to prevent over issuing from one batch.'
    qty = _dpx_int(data.get('quantity'))
    if qty <= 0:
        return False, 'Enter a valid coupon issue quantity.'
    info = _dpx_batch_available_qty(conn, batch_id, exclude_id)
    if not info:
        return False, 'Selected fuel coupon batch was not found.'
    batch = info['batch']
    denom = _dpx_float(data.get('denomination'))
    batch_denom = _dpx_float(batch.get('denomination'))
    if abs(denom - batch_denom) > 0.001:
        return False, f'Coupon denomination mismatch. The selected batch is GHS {batch_denom:g}, but this issue uses GHS {denom:g}.'
    if qty > info['available_qty']:
        return False, f'OVER ISSUING BLOCKED: selected batch has only {info["available_qty"]} coupon(s) available, but {qty} coupon(s) were requested. Use another batch or reduce the quantity.'
    sf = str(data.get('serial_from') or '').strip(); st = str(data.get('serial_to') or '').strip()
    bsf = str(batch.get('serial_from') or '').strip(); bst = str(batch.get('serial_to') or '').strip()
    if (bsf or bst) and not _dpx_serial_contains(bsf, bst, sf, st):
        return False, f'ISSUE SERIAL BLOCKED: issued serials must fall within selected batch range {bsf} to {bst}.'
    sc = _dpx_serial_count(sf, st)
    if sc is not None and sc != qty:
        return False, f'Serial range contains {sc} coupon(s), but issue quantity is {qty}. Make the quantity and serial range agree.'
    if sf and st:
        rows = conn.execute("""
            SELECT id, serial_from, serial_to FROM fuel_coupon_movements
            WHERE batch_id=? AND movement_type='Issue' AND COALESCE(serial_from,'')<>'' AND COALESCE(serial_to,'')<>''
              AND COALESCE(ledger_reversed,0)=0 AND COALESCE(is_deleted,0)=0
              AND (? IS NULL OR id<>?)
        """, (batch_id, exclude_id, exclude_id)).fetchall()
        for r in rows:
            if _dpx_serial_overlap(sf, st, r['serial_from'], r['serial_to']):
                return False, f'ISSUE SERIAL BLOCKED: the range overlaps an earlier issue {r["serial_from"]} to {r["serial_to"]} from this batch.'
    return True, ''


def _dpx_validate_return_against_source(conn, data, exclude_id=None):
    mv_type = data.get('movement_type') or ''
    if mv_type not in ('Return', 'Return-Issued'):
        return True, ''
    source_id = data.get('source_movement_id') or data.get('return_source_id')
    if _dpx_bool(_dpx_setting(conn, 'fuel_return_source_required', '1')) and not source_id:
        return False, 'Select the original issued coupon record before saving a return. This prevents returning more coupons than were issued.'
    src = _dpx_fill_return_from_source(conn, data)
    if not src:
        return False, 'The selected original issue record could not be found.'
    if src.get('movement_type') != 'Issue':
        return False, 'Only coupons originally issued can be returned through this return form.'
    qty = _dpx_int(data.get('quantity'))
    if qty <= 0:
        return False, 'Enter a valid coupon return quantity.'
    issued_qty = _dpx_int(src.get('quantity'))
    returned_qty = _dpx_source_returned_qty(conn, source_id, exclude_id)
    available = issued_qty - returned_qty
    if qty > available:
        return False, f'OVER RETURN BLOCKED: only {available} coupon(s) remain returnable from the selected issue, but {qty} coupon(s) were entered.'
    if data.get('batch_id') and src.get('batch_id') and data.get('batch_id') != src.get('batch_id'):
        return False, 'Returned coupons must belong to the same batch as the original issue.'
    denom = _dpx_float(data.get('denomination'))
    src_denom = _dpx_float(src.get('denomination'))
    if abs(denom - src_denom) > 0.001:
        return False, f'Returned coupon denomination must match the original issue denomination of GHS {src_denom:g}.'
    sf = str(data.get('serial_from') or '').strip(); st = str(data.get('serial_to') or '').strip()
    osf = str(src.get('serial_from') or '').strip(); ost = str(src.get('serial_to') or '').strip()
    if _dpx_bool(_dpx_setting(conn, 'fuel_return_serial_containment_enabled', '1')) and (osf or ost):
        if not sf or not st:
            return False, f'Enter the returned coupon serial range. It must fall within the original issue range {osf} to {ost}.'
        if not _dpx_serial_contains(osf, ost, sf, st):
            return False, f'RETURN SERIAL BLOCKED: returned serials must fall within original issue range {osf} to {ost}.'
    sc = _dpx_serial_count(sf, st)
    if sc is not None and sc != qty:
        return False, f'Returned serial range contains {sc} coupon(s), but return quantity is {qty}. Make the quantity and serial range agree.'
    if sf and st:
        rows = conn.execute("""
            SELECT id, serial_from, serial_to FROM fuel_coupon_movements
            WHERE source_movement_id=? AND movement_type IN ('Return','Return-Issued')
              AND COALESCE(serial_from,'')<>'' AND COALESCE(serial_to,'')<>''
              AND COALESCE(ledger_reversed,0)=0 AND COALESCE(is_deleted,0)=0
              AND (? IS NULL OR id<>?)
        """, (source_id, exclude_id, exclude_id)).fetchall()
        for r in rows:
            if _dpx_serial_overlap(sf, st, r['serial_from'], r['serial_to']):
                return False, f'RETURN SERIAL BLOCKED: this returned range overlaps an earlier return {r["serial_from"]} to {r["serial_to"]} from the same issue.'
    return True, ''


def _dpx_validate_fuel_movement_payload(conn, data, exclude_id=None):
    data = dict(data or {})
    src = None
    if (data.get('movement_type') or '') in ('Return','Return-Issued') and (data.get('source_movement_id') or data.get('return_source_id')):
        src = _dpx_fill_return_from_source(conn, data)
    valid, msg = _dpx_validate_issue_against_batch(conn, data, exclude_id)
    if not valid:
        return False, msg, data
    valid, msg = _dpx_validate_return_against_source(conn, data, exclude_id)
    if not valid:
        return False, msg, data
    return True, '', data


def _dpx_enrich_fuel_payload(conn, payload):
    try:
        for b in payload.get('batches', []) or []:
            info = _dpx_batch_available_qty(conn, b.get('id'))
            if info:
                b['issued_qty'] = info['out_qty']
                b['returned_qty'] = info['return_qty']
                b['available_qty'] = max(0, info['available_qty'])
        movements = payload.get('movements', []) or []
        for m in movements:
            if m.get('movement_type') == 'Issue':
                rq = _dpx_source_returned_qty(conn, m.get('id'))
                m['returned_qty'] = rq
                m['available_return_qty'] = max(0, _dpx_int(m.get('quantity')) - rq)
                m['return_status'] = 'Fully returned' if m['available_return_qty'] <= 0 else 'Open for return'
            if m.get('batch_id'):
                bi = _dpx_batch_available_qty(conn, m.get('batch_id'))
                if bi:
                    m['batch_available_qty'] = max(0, bi['available_qty'])
    except Exception:
        pass
    return payload

