try:
    _dpx_prev_return_sources = api_fuel_return_sources
    def api_fuel_return_sources(session):
        if not session:
            return err('Not authenticated')
        _dpx_migration(); conn = get_db()
        try:
            rows = []
            for r in conn.execute("""
                SELECT fm.*, fb.batch_number, p.project_code, p.title as project_title,
                       v.registration_number as vehicle_registration, v.vehicle_name
                FROM fuel_coupon_movements fm
                LEFT JOIN fuel_coupon_batches fb ON fb.id=fm.batch_id
                LEFT JOIN projects p ON p.id=fm.project_id
                LEFT JOIN fuel_vehicles v ON v.id=fm.vehicle_id
                WHERE fm.movement_type='Issue' AND COALESCE(fm.ledger_reversed,0)=0 AND COALESCE(fm.is_deleted,0)=0
                ORDER BY fm.movement_date DESC, fm.created_at DESC
                LIMIT 300
            """).fetchall():
                d = dict(r)
                ret = _dpx_source_returned_qty(conn, d.get('id'))
                d['returned_qty'] = ret
                d['available_return_qty'] = max(0, _dpx_int(d.get('quantity')) - ret)
                d['return_status'] = 'Fully returned' if d['available_return_qty'] <= 0 else 'Open for return'
                if d['available_return_qty'] > 0:
                    rows.append(d)
            return ok({'sources': rows, 'version': DEPLOYMENT_POLISH_VERSION})
        finally:
            conn.close()
except Exception as _dpx_exc:
    print('Deployment polish return source wrapper warning:', _dpx_exc)

