try:
    _dpx_prev_get_budgets = api_get_budgets
    def api_get_budgets(session, project_id=None):
        _dpx_migration(); conn = get_db()
        try:
            bdel = "COALESCE(b.is_deleted,0)=0" if 'is_deleted' in _dpx_cols(conn,'budgets') else "1=1"
            adel = "AND COALESCE(a.is_deleted,0)=0" if 'is_deleted' in _dpx_cols(conn,'actuals') else ""
            cdel = "AND COALESCE(cm.is_deleted,0)=0" if 'is_deleted' in _dpx_cols(conn,'commitments') else ""
            q = f"""SELECT b.*, p.project_code, p.title as project_title, p.currency as proj_currency, p.division,
                c.code as coa_code, c.account_name, c.category,
                COALESCE((SELECT SUM(MAX(0, cm.amount_ghs - COALESCE((SELECT SUM(_ax.amount_ghs) FROM actuals _ax WHERE _ax.commitment_id=cm.id AND COALESCE(_ax.is_posted,0)=1),0))) FROM commitments cm WHERE cm.budget_id=b.id AND COALESCE(cm.status,'') NOT IN ('Cancelled','Fully Paid') {cdel}),0) as committed_ghs,
                COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id {adel}),0) as actual_ghs
                FROM budgets b
                JOIN projects p ON b.project_id=p.id
                JOIN chart_of_accounts c ON b.coa_id=c.id
                WHERE {bdel}"""
            args = []
            if project_id:
                q += " AND b.project_id=?"; args.append(project_id)
            q += " ORDER BY b.created_at"
            return [dict(r) for r in conn.execute(q, args).fetchall()]
        finally:
            conn.close()
except Exception as _dpx_exc:
    print('Deployment polish budget list wrapper warning:', _dpx_exc)

try:
    _dpx_prev_get_qb = api_get_quarterly_budgets
    def api_get_quarterly_budgets(session, dept_code=None, academic_year=None):
        if not session: return {'error':'Not authenticated'}
        _dpx_migration(); conn = get_db()
        try:
            dept_code = canonical_unit_code(dept_code) if dept_code else None
            deleted_filter = " AND COALESCE(qb.is_deleted,0)=0" if 'is_deleted' in _dpx_cols(conn,'quarterly_budgets') else ""
            q = """SELECT qb.*, c.account_name, c.code as account_code,
                          p.project_code, p.title as project_title, p.donor as project_donor
                   FROM quarterly_budgets qb
                   LEFT JOIN chart_of_accounts c ON qb.coa_id=c.id
                   LEFT JOIN projects p ON qb.project_id=p.id
                   WHERE 1=1""" + deleted_filter
            params = []
            if dept_code: q += " AND qb.dept_code=?"; params.append(dept_code)
            if academic_year: q += " AND qb.academic_year=?"; params.append(academic_year)
            q += " ORDER BY qb.dept_code, COALESCE(p.project_code,''), qb.category, qb.description"
            return [dict(r) for r in conn.execute(q, params).fetchall()]
        finally:
            conn.close()
except Exception as _dpx_exc:
    print('Deployment polish quarterly budget wrapper warning:', _dpx_exc)

try:
    _dpx_prev_quarterly_performance = api_quarterly_performance
    def api_quarterly_performance(session, dept_code=None, academic_year=None, quarter=None):
        if not session: return {'error':'Not authenticated'}
        _dpx_migration(); conn = get_db()
        try:
            ay = academic_year or '2025/2026'
            dept_code = canonical_unit_code(dept_code) if dept_code else None
            qb_deleted = " AND COALESCE(qb.is_deleted,0)=0" if 'is_deleted' in _dpx_cols(conn,'quarterly_budgets') else ""
            a_deleted = " AND COALESCE(a.is_deleted,0)=0" if 'is_deleted' in _dpx_cols(conn,'actuals') else ""
            b_deleted = " AND COALESCE(bud.is_deleted,0)=0" if 'is_deleted' in _dpx_cols(conn,'budgets') else ""
            budgets = conn.execute("""
                SELECT qb.dept_code, d.dept_name, qb.project_id, p.project_code, p.title as project_title,
                       qb.category, qb.description, qb.coa_id,
                       qb.q1_amount, qb.q2_amount, qb.q3_amount, qb.q4_amount, qb.annual_total,
                       c.account_name, c.code as account_code
                FROM quarterly_budgets qb
                LEFT JOIN departments d ON qb.dept_code=d.dept_code
                LEFT JOIN projects p ON qb.project_id=p.id
                LEFT JOIN chart_of_accounts c ON qb.coa_id=c.id
                WHERE qb.academic_year=?""" + qb_deleted + (" AND qb.dept_code=?" if dept_code else ""),
                [ay] + ([dept_code] if dept_code else [])).fetchall()
            # Actual spend is matched to a quarterly budget line by the EXPENDITURE ACCOUNT
            # (coa_id) + department + quarter — NOT by category string. (qb.category is the
            # broad 'Expense'/'Asset'/'Income' bucket, while the actual side previously keyed
            # on the COA's far more granular sub_category — e.g. 'General Expenses' — so the
            # two never aligned and actuals always read zero.) Only payments tagged to a
            # budget line are counted, matched on that budget line's coa_id.
            # An academic year like '2025/2026' spans TWO calendar years, so match
            # spend dated in EITHER (the old filter compared only the first year, e.g.
            # '2025', and silently dropped every 2026-dated payment).
            _yrs = [y.strip() for y in str(ay).replace('-', '/').split('/') if y.strip().isdigit() and len(y.strip()) == 4]
            if not _yrs:
                _yrs = [str(ay)[:4]]
            _yr_in = ','.join('?' for _ in _yrs)
            actuals_q = conn.execute("""
                SELECT p.division as dept_code, a.project_id, bud.coa_id as coa_id,
                       CASE
                         WHEN strftime('%m', a.expense_date) IN ('01','02','03') THEN 1
                         WHEN strftime('%m', a.expense_date) IN ('04','05','06') THEN 2
                         WHEN strftime('%m', a.expense_date) IN ('07','08','09') THEN 3
                         ELSE 4
                       END as quarter,
                       SUM(a.amount_ghs) as actual_amount
                FROM actuals a
                INNER JOIN projects p ON a.project_id=p.id
                INNER JOIN budgets bud ON a.budget_id=bud.id
                WHERE strftime('%Y', a.expense_date) IN (""" + _yr_in + ")" + a_deleted + b_deleted + (" AND p.division=?" if dept_code else "") + """
                GROUP BY p.division, a.project_id, bud.coa_id, quarter
            """, _yrs + ([dept_code] if dept_code else [])).fetchall()
            actuals_map = {}
            for row in actuals_q:
                key_unit = (row['dept_code'], row['coa_id'] or '', row['quarter'])
                key_proj = (row['dept_code'], row['project_id'] or '', row['coa_id'] or '', row['quarter'])
                actuals_map[key_unit] = actuals_map.get(key_unit, 0) + (row['actual_amount'] or 0)
                actuals_map[key_proj] = actuals_map.get(key_proj, 0) + (row['actual_amount'] or 0)
            result = []
            for b in budgets:
                row_data = dict(b)
                for qi in [1,2,3,4]:
                    budget_q = b[f'q{qi}_amount'] or 0
                    if b['project_id']:
                        actual_q = actuals_map.get((b['dept_code'], b['project_id'], b['coa_id'], qi), 0)
                    else:
                        actual_q = actuals_map.get((b['dept_code'], b['coa_id'], qi), 0)
                    variance_q = budget_q - actual_q
                    pct_q = (actual_q/budget_q*100) if budget_q > 0 else 0
                    row_data[f'actual_q{qi}'] = actual_q
                    row_data[f'variance_q{qi}'] = variance_q
                    row_data[f'pct_q{qi}'] = round(pct_q, 1)
                result.append(row_data)
            return result
        finally:
            conn.close()
except Exception as _dpx_exc:
    print('Deployment polish quarterly performance wrapper warning:', _dpx_exc)

