# ═════════════════════════════════════════════════════════════════════════════
# INSTITUTIONAL HARDENING PACK: backup/restore, period close visibility,
# opening balance wizard, mandatory document checks, approval notifications,
# exception dashboard, import/user manual centre, and clean bank selection UX.
# Additive only. Existing transaction engines are not rewritten.
# ═════════════════════════════════════════════════════════════════════════════
IH2_VERSION = '2026.05.21-institutional-hardening-bank-selector'


def _ih2_now():
    return datetime.now().strftime('%Y-%m-%d %H:%M:%S')


def _ih2_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False


def _ih2_cols(conn, table):
    try:
        return {r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()}
    except Exception:
        return set()


def _ih2_add_col(conn, table, coldef):
    try:
        name = coldef.split()[0]
        if _ih2_table_exists(conn, table) and name not in _ih2_cols(conn, table):
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {coldef}")
    except Exception:
        pass


def _ih2_scalar(conn, sql, args=(), default=0):
    try:
        row = conn.execute(sql, args or ()).fetchone()
        if row is None:
            return default
        return row[0]
    except Exception:
        return default


def _ih2_bool(v):
    return str(v).strip().lower() in ('1','true','yes','on','enabled','required')


def _ih2_setting(conn, key, default=''):
    try:
        row = conn.execute("SELECT value FROM settings WHERE key=?", (key,)).fetchone()
        return row[0] if row else default
    except Exception:
        return default


def _ih2_admin(session):
    return bool(session and session.get('role') == 'Admin')


def _ih2_finance(session):
    return bool(session and session.get('role') in ('Admin','Finance Officer'))


def _ih2_has_attachment(conn, module, record_id):
    if not module or not record_id or not _ih2_table_exists(conn, 'document_attachments'):
        return False
    return int(_ih2_scalar(conn, "SELECT COUNT(*) FROM document_attachments WHERE module=? AND record_id=?", (module, record_id), 0) or 0) > 0


def _ih2_coa_id(conn, value):
    """STRICT chart-of-accounts resolver for opening-balance imports: match an
    EXACT COA id or EXACT COA code only. Returns None for anything else so the
    import REJECTS unrecognised codes with a clear error, instead of silently
    falling back to a default expense account (the old behaviour resolved ANY
    unknown code -- e.g. a bank account number that is not a COA code -- to
    61800003 'Other Expenses', dumping money into the wrong account)."""
    if not value:
        return None
    raw = str(value).strip()
    try:
        row = conn.execute("SELECT id FROM chart_of_accounts WHERE id=?", (raw,)).fetchone()
        if row:
            return row['id'] if hasattr(row, 'keys') else row[0]
    except Exception:
        pass
    try:
        row = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (raw,)).fetchone()
        if row:
            return row['id'] if hasattr(row, 'keys') else row[0]
    except Exception:
        pass
    return None


