            ('import_templates','Data Import Templates','Installed','institutional-control','CSV templates exist for deployment master data.'),
            ('in_app_manual','In App User Manual','Installed','institutional-control','Simple operational guides are available inside the app.'),
            ('bank_selector','Clean Bank Account Selector','Installed','bank-accounts','The bank account screen now uses a selector rather than displaying all accounts.'),
            ('petty_cash_imprest','Petty Cash Imprest System','Installed','petty-cash','Per-department imprest floats, multi-line disbursements, edit/adjust/close, replenish and count - wired to the GL.'),
