def api_post_opening_balances(data, session):
    if not session: return err('Not authenticated')
    if not _ih2_finance(session): return err('Finance Officer or Admin access required')
    _ih2_migration()
    lines = data.get('lines') or []
    opening_date = (data.get('opening_date') or data.get('date') or '2026-01-01')[:10]
    description = data.get('description') or 'Opening balance migration entry'
    if len(lines) < 2: return err('Opening balance requires at least two debit/credit lines')
    conn = get_db()
    try:
        try: init_jv_db()
        except Exception: pass
        clean=[]; total_dr=0.0; total_cr=0.0
        for idx,line in enumerate(lines, start=1):
            coa_value = line.get('coa_id') or line.get('coa_code') or line.get('account_code')
            cid = _ih2_coa_id(conn, coa_value)
            if not cid: raise ValueError(f'Line {idx}: chart of account not found ({coa_value})')
            dr = round(float(line.get('debit') or line.get('debit_amount') or 0),2)
            cr = round(float(line.get('credit') or line.get('credit_amount') or 0),2)
            if dr and cr: raise ValueError(f'Line {idx}: use either debit or credit, not both')
            if dr <= 0 and cr <= 0: continue
            total_dr += dr; total_cr += cr
            clean.append({'coa_id':cid,'debit_amount':dr,'credit_amount':cr,'description':line.get('narration') or description,'unit_id':line.get('unit_id') or None})
        total_dr=round(total_dr,2); total_cr=round(total_cr,2)
        if not clean or abs(total_dr-total_cr)>0.01:
            raise ValueError(f'Opening balance is not balanced: debit {total_dr:,.2f}, credit {total_cr:,.2f}')
        # Idempotent opening balances: re-posting REPLACES the previous opening-balance
        # batch (consistent with the CSV import path) so figures are never duplicated.
        for p in conn.execute("SELECT id FROM journal_vouchers WHERE source_module='opening_balance' AND status='Posted'").fetchall():
            conn.execute("DELETE FROM general_ledger WHERE jv_id=?", (p['id'],))
            conn.execute("UPDATE journal_vouchers SET status='Reversed', total_debit=0, total_credit=0, void_reason='Superseded by a newer opening-balance posting', voided_at=datetime('now') WHERE id=?", (p['id'],))
        try:
            conn.execute("UPDATE opening_balance_batches SET status='Reversed' WHERE status='Posted'")
        except Exception:
            pass
        # Warn (non-blocking) when an account also carries an opening balance from a
        # different mechanism (bank-field sync or CSV import) — would double-count.
        ob_warnings = []
        for _ln in clean:
            _coa = conn.execute("SELECT code, account_name FROM chart_of_accounts WHERE id=?", (_ln['coa_id'],)).fetchone()
            # Skip the equity/fund contra (code 3) — it is legitimately shared as the
            # balancing account for every opening journal, so it is not a duplicate.
            if _coa and str(_coa['code'] or '').startswith('3'):
                continue
            _dup = conn.execute(
                "SELECT jv.jv_number FROM general_ledger gl JOIN journal_vouchers jv ON jv.id=gl.jv_id "
                "WHERE gl.coa_id=? AND jv.status='Posted' AND jv.source_module IN ('bank_opening_balance','opening_balance_import') LIMIT 1",
                (_ln['coa_id'],)).fetchone()
            if _dup:
                ob_warnings.append('%s already has an opening balance via %s — reverse one to avoid double-counting.' % ((_coa['account_name'] if _coa else _ln['coa_id']), _dup['jv_number']))
        _ensure_period_accepts(conn, opening_date, by_date=True, purpose='opening balance')
        jv_id, jv_num = _create_posted_journal(conn, session, 'AJV', opening_date, description, data.get('reference') or 'Opening Balance', None, None, 'opening_balance', 'opening_balance', clean)
        bid=str(uuid.uuid4()); batch_no = 'OB-' + datetime.now().strftime('%Y%m%d-%H%M%S') + '-' + bid[:4].upper()
        conn.execute("INSERT INTO opening_balance_batches(id,batch_no,opening_date,description,total_debit,total_credit,status,jv_id,created_by) VALUES(?,?,?,?,?,?,?,?,?)", (bid,batch_no,opening_date,description,total_dr,total_cr,'Posted',jv_id,session.get('username','system')))
        for line in clean:
            coa = conn.execute("SELECT code,account_name FROM chart_of_accounts WHERE id=?", (line['coa_id'],)).fetchone()
            conn.execute("INSERT INTO opening_balance_lines(id,batch_id,coa_id,coa_code,account_name,debit,credit,narration) VALUES(?,?,?,?,?,?,?,?)", (str(uuid.uuid4()),bid,line['coa_id'],coa['code'],coa['account_name'],line['debit_amount'],line['credit_amount'],line['description']))
        _audit(conn, session, 'POST_OPENING_BALANCE', 'opening_balance_batches', bid, f'{batch_no} via {jv_num}')
        conn.commit()
        return ok({'batch_id':bid,'batch_no':batch_no,'jv_id':jv_id,'jv_number':jv_num,'total_debit':total_dr,'total_credit':total_cr,'warnings':ob_warnings})
    except Exception as exc:
        conn.rollback(); return err(str(exc))
    finally:
        conn.close()


def api_approval_notification_centre(session):
    if not session: return err('Not authenticated')
    _ih2_migration(); conn=get_db()
    try:
        alerts=[]
        def add(sev,title,message,module,record_id=''):
            alerts.append({'severity':sev,'title':title,'message':message,'module':module,'record_id':record_id})
        if _ih2_table_exists(conn,'approvals'):
            n=int(_ih2_scalar(conn,"SELECT COUNT(*) FROM approvals WHERE status='Pending'", default=0) or 0)
            if n: add('warning','Pending approvals',f'{n} item(s) awaiting approval.','approvals')
        if _ih2_table_exists(conn,'actuals'):
            n=int(_ih2_scalar(conn,"SELECT COUNT(*) FROM actuals WHERE COALESCE(is_posted,0)=0 AND COALESCE(is_deleted,0)=0", default=0) or 0)
            if n: add('info','Draft payment vouchers',f'{n} PV(s) are saved but not posted.','actuals')
        if _ih2_table_exists(conn,'journal_vouchers'):
            n=int(_ih2_scalar(conn,"SELECT COUNT(*) FROM journal_vouchers WHERE status IN ('Draft','Submitted','Approved')", default=0) or 0)
            if n: add('info','JV workflow queue',f'{n} journal voucher(s) need action.','journal-vouchers')
        if _ih2_table_exists(conn,'fuel_coupon_batches'):
            threshold=int(float(_ih2_setting(conn,'low_fuel_stock_quantity','10') or 10))
            try:
                rows=conn.execute("""SELECT b.id,b.batch_number,b.quantity - COALESCE((SELECT SUM(m.quantity) FROM fuel_coupon_movements m WHERE m.batch_id=b.id AND m.movement_type='Issue' AND COALESCE(m.is_deleted,0)=0),0) + COALESCE((SELECT SUM(m.quantity) FROM fuel_coupon_movements m WHERE m.batch_id=b.id AND m.movement_type IN ('Return','Return-Issued') AND COALESCE(m.is_deleted,0)=0),0) AS available_qty FROM fuel_coupon_batches b WHERE COALESCE(b.is_deleted,0)=0""").fetchall()
            except Exception as _se:
                import sys as _sx; print('approval_centre warning: %s'%_se,file=_sx.stderr)
                rows=[]
            low=[dict(r) for r in rows if float(r['available_qty'] or 0) <= threshold]
            if low: add('warning','Low fuel coupon stock',f'{len(low)} batch(es) are at or below {threshold} coupon(s).','fuel')
        if _ih2_table_exists(conn,'client_error_log'):
            n=int(_ih2_scalar(conn,"SELECT COUNT(*) FROM client_error_log WHERE datetime(created_at)>=datetime('now','-24 hours')", default=0) or 0)
            if n: add('danger','Recent client errors',f'{n} browser error(s) were captured in the last 24 hours.','client-errors')
        return ok({'version':IH2_VERSION,'alerts':alerts,'count':len(alerts),'generated_at':_ih2_now()})
    finally:
        conn.close()


def api_exception_audit_dashboard(session):
    if not session: return err('Not authenticated')
    _ih2_migration(); conn=get_db()
    try:
        exceptions=[]
        def ex(sev,title,detail,module,count=0):
            exceptions.append({'severity':sev,'title':title,'detail':detail,'module':module,'count':count})
        if _ih2_table_exists(conn,'general_ledger'):
            diff=round(float(_ih2_scalar(conn,"SELECT COALESCE(SUM(debit_amount),0)-COALESCE(SUM(credit_amount),0) FROM general_ledger",default=0) or 0),2)
            if abs(diff)>0.01: ex('danger','Ledger imbalance',f'Debit and credit differ by GHS {diff:,.2f}.','general-ledger',1)
        if _ih2_table_exists(conn,'audit_log'):
            edits=int(_ih2_scalar(conn,"SELECT COUNT(*) FROM audit_log WHERE action LIKE '%DELETE%' OR action LIKE '%REVERSE%' OR action LIKE '%RESTORE%'", default=0) or 0)
            if edits: ex('warning','Sensitive audit actions',f'{edits} delete, reverse or restore audit event(s) exist.','audit',edits)
        if _ih2_table_exists(conn,'document_attachments') and _ih2_bool(_ih2_setting(conn,'mandatory_supporting_documents','1')):
            missing=0
            if _ih2_table_exists(conn,'actuals'):
                missing += int(_ih2_scalar(conn,"""SELECT COUNT(*) FROM actuals a WHERE COALESCE(a.is_posted,0)=1 AND NOT EXISTS(SELECT 1 FROM document_attachments d WHERE d.module='actuals' AND d.record_id=a.id)""",default=0) or 0)
            if missing: ex('danger','Missing supporting documents',f'{missing} posted PV(s) do not have attachments.','document-vault',missing)
        if _ih2_table_exists(conn,'client_error_log'):
            n=int(_ih2_scalar(conn,"SELECT COUNT(*) FROM client_error_log WHERE datetime(created_at)>=datetime('now','-7 days')", default=0) or 0)
            if n: ex('warning','Client side errors',f'{n} browser error(s) captured in the last 7 days.','client-errors',n)
        audit=[]
        if _ih2_table_exists(conn,'audit_log'):
            audit=[dict(r) for r in conn.execute("SELECT timestamp,username,user_role,action,module,record_id,details FROM audit_log ORDER BY timestamp DESC LIMIT 50").fetchall()]
        return ok({'version':IH2_VERSION,'exceptions':exceptions,'audit':audit,'generated_at':_ih2_now()})
    finally:
        conn.close()


