def _ih2_require_doc(module, record_id):
    # Retained for compatibility/readiness display: returns a message only when no
    # supporting document is attached. Callers no longer use this to BLOCK posting.
    conn=get_db()
    try:
        if _ih2_has_attachment(conn, module, record_id):
            return None
        return ('Posted. Supporting evidence is not yet attached — upload the invoice, '
                'approval memo or other document in Document Vault to complete the audit trail.')
    finally:
        conn.close()

def _ih2_doc_reminder(module, record_id):
    """Attaching evidence is strongly encouraged but NOT mandatory to post. Returns a
    non-blocking reminder when no document is attached for the record, else None."""
    if not record_id:
        return None
    try:
        return _ih2_require_doc(module, record_id)
    except Exception:
        return None

def _ih2_with_reminder(res, reminder):
    if reminder and isinstance(res, dict) and res.get('ok'):
        res.setdefault('warning', reminder)
        res['document_reminder'] = reminder
    return res

