try:
    _rmx_prev_api_fuel_stock_health = api_fuel_stock_health
    def api_fuel_stock_health(session):
        payload = _rmx_prev_api_fuel_stock_health(session)
        try:
            if isinstance(payload, dict) and payload.get('ok') is False:
                return payload
            conn = get_db()
            try:
                def mv_sum(t):
                    return _rmx_money(conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type=?", (t,)).fetchone()[0])
                procured = _rmx_money(conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_batches").fetchone()[0])
                borrowed = mv_sum('Borrow')
                issued = mv_sum('Issue')
                lent = mv_sum('Lend')
                stock_returns = mv_sum('Return') + mv_sum('Return-Issued') + mv_sum('Return-Lent')
                borrowed_returns = mv_sum('Return-Borrowed')
                corrected = round(procured + borrowed - issued - lent + stock_returns - borrowed_returns, 2)
            finally:
                conn.close()
            if isinstance(payload, dict):
                payload['calculated_stock_value'] = corrected
                payload['returned_to_stock_value'] = round(stock_returns, 2)
                payload['returned_borrowed_value'] = round(borrowed_returns, 2)
                payload['return_modes_restored_version'] = RETURN_MODES_RESTORATION_VERSION
                payload.setdefault('double_entry', {})
                payload['double_entry']['return_lent'] = 'Operational stock return: external unit returns coupons previously lent out; stock balance increases without consumption journal.'
                payload['double_entry']['return_borrowed'] = 'Operational borrowed coupon repayment: institution returns coupons previously borrowed; stock balance decreases without consumption journal.'
        except Exception as exc:
            try:
                payload.setdefault('warnings', []).append(f'Return mode stock health warning: {exc}')
            except Exception:
                pass
        return payload
except Exception as _rmx_exc:
    print('Return modes stock health wrapper warning:', _rmx_exc)


try:
    _rmx_prev_api_fuel_report = api_fuel_report
    def api_fuel_report(session, date_from=None, date_to=None, project_id=None):
        res = _rmx_prev_api_fuel_report(session, date_from, date_to, project_id)
        try:
            if not isinstance(res, dict):
                return res
            p = res.setdefault('period', {})
            rb = _rmx_money(p.get('returned_borrowed') or p.get('borrow_returned') or 0)
            returned_to_stock = _rmx_money(p.get('returned',0)) + _rmx_money(p.get('returned_lent',0))
            p['returned_to_stock'] = returned_to_stock
            p['returned_borrowed'] = rb
            p['all_returned'] = returned_to_stock + rb
            # Correct prior formula which added Return-Borrowed to stock instead of subtracting it.
            ob = _rmx_money(res.get('opening_balance'))
            conn = get_db()
            try:
                if date_from:
                    rb_before = _rmx_money(conn.execute("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type='Return-Borrowed' AND movement_date < ?", (date_from,)).fetchone()[0])
                    ob = round(ob - (2 * rb_before), 2)
            finally:
                conn.close()
            res['opening_balance'] = ob
            res['closing_balance'] = round(ob + _rmx_money(p.get('procured')) + _rmx_money(p.get('borrowed')) - _rmx_money(p.get('issued')) - _rmx_money(p.get('lent')) + returned_to_stock - rb, 2)
            res['return_modes_restored_version'] = RETURN_MODES_RESTORATION_VERSION
        except Exception:
            pass
        return res
except Exception as _rmx_exc:
    print('Return modes fuel report wrapper warning:', _rmx_exc)



