# GO-LIVE ENFORCEMENT GATE — controlled institutional deployment discipline
# ═══════════════════════════════════════════════════════════════════════════
GO_LIVE_ENFORCEMENT_VERSION = 'v5.0.31-go-live-enforcement'


def _gle_now():
    try:
        return datetime.now().isoformat(timespec='seconds')
    except Exception:
        return str(datetime.now())


def _gle_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False


def _gle_col_exists(conn, table, col):
    try:
        return any(r[1] == col for r in conn.execute(f"PRAGMA table_info({table})").fetchall())
    except Exception:
        return False


def _gle_scalar(conn, sql, args=(), default=0):
    try:
        row = conn.execute(sql, args).fetchone()
        if row is None:
            return default
        return row[0]
    except Exception:
        return default


def _gle_audit(conn, session, action, module, record_id, details):
    try:
        if callable(globals().get('_audit')):
            return globals()['_audit'](conn, session or {}, action, module, record_id, details)
    except Exception:
        pass
    try:
        if _gle_table_exists(conn, 'audit_log'):
            cols = {r[1] for r in conn.execute('PRAGMA table_info(audit_log)').fetchall()}
            if {'id','action','module','record_id','details'}.issubset(cols):
                created_col = 'timestamp' if 'timestamp' in cols else ('created_at' if 'created_at' in cols else None)
                user_col = 'username' if 'username' in cols else ('created_by' if 'created_by' in cols else None)
                cols_sql = ['id','action','module','record_id','details']
                vals = [str(uuid.uuid4()), action, module, str(record_id or ''), str(details or '')]
                if user_col:
                    cols_sql.append(user_col); vals.append((session or {}).get('username','system'))
                if created_col:
                    cols_sql.append(created_col); vals.append(_gle_now())
                ph = ','.join(['?'] * len(vals))
                conn.execute(f"INSERT INTO audit_log({','.join(cols_sql)}) VALUES({ph})", vals)
    except Exception:
        pass


def _gle_is_admin(session):
    role = str((session or {}).get('role') or '').strip().lower()
    return role in ('admin','administrator','super admin','superadmin','finance admin')


def _gle_migration():
    conn = get_db(); c = conn.cursor()
    try:
        c.execute("""CREATE TABLE IF NOT EXISTS go_live_enforcement(
            id TEXT PRIMARY KEY DEFAULT 'default',
            enabled INTEGER DEFAULT 1,
            mode TEXT DEFAULT 'SETUP',
            signed_off INTEGER DEFAULT 0,
            signed_off_by TEXT,
            signed_off_at TEXT,
            signoff_note TEXT,
            last_uat_score REAL DEFAULT 0,
            updated_by TEXT,
            updated_at TEXT DEFAULT CURRENT_TIMESTAMP
        )""")
        c.execute("INSERT OR IGNORE INTO go_live_enforcement(id,enabled,mode,signed_off,signoff_note,updated_by) VALUES('default',1,'SETUP',0,'Not yet signed off','system')")
        c.execute("""CREATE TABLE IF NOT EXISTS go_live_checklist_items(
            item_key TEXT PRIMARY KEY,
            category TEXT,
            label TEXT,
            required INTEGER DEFAULT 1,
            status TEXT DEFAULT 'Pending',
            evidence TEXT,
            updated_by TEXT,
            updated_at TEXT DEFAULT CURRENT_TIMESTAMP
        )""")
        c.execute("""CREATE TABLE IF NOT EXISTS go_live_waivers(
            id TEXT PRIMARY KEY,
            module TEXT,
            action TEXT,
            reason TEXT,
            expires_at TEXT,
            created_by TEXT,
            created_at TEXT DEFAULT CURRENT_TIMESTAMP
        )""")
        items = [
            ('clean_reset_completed','Deployment','Clean reset completed after UAT',1),
            ('opening_balances_confirmed','Accounting','Opening balances entered or formally confirmed not applicable',1),
            ('roles_confirmed','Security','Users and roles confirmed',1),
            ('uat_completed','Testing','User acceptance testing completed',1),
            ('training_completed','Training','Finance, fuel and approval users trained',1),
            ('backup_confirmed','Continuity','Backup created and downloaded before go-live',1),
            ('period_lock_confirmed','Accounting','Accounting period lock reviewed',1),
            ('management_signoff','Governance','Management or project owner sign-off obtained',1),
        ]
        for key,cat,label,req in items:
            c.execute("""INSERT OR IGNORE INTO go_live_checklist_items(item_key,category,label,required,status,evidence,updated_by)
                         VALUES(?,?,?,?,?,?,?)""", (key,cat,label,req,'Pending','', 'system'))
        conn.commit()
    finally:
        conn.close()


def _gle_operational_counts(conn):
    tables = ['actuals','fund_receipts','journal_vouchers','general_ledger','fuel_coupon_batches','fuel_coupon_movements','invoices','commitments','payroll_register','approvals','document_attachments','bank_reconciliations']
    out = {}
    for t in tables:
        if _gle_table_exists(conn, t):
            where = ''
            if _gle_col_exists(conn, t, 'is_deleted'):
                where = ' WHERE COALESCE(is_deleted,0)=0'
            out[t] = int(_gle_scalar(conn, f"SELECT COUNT(*) FROM {t}{where}", default=0) or 0)
    return out


def _gle_latest_acceptance(conn):
    if not _gle_table_exists(conn, 'acceptance_test_runs'):
        return {'score':0,'status':'Not run','created_at':None}
    try:
        r = conn.execute("SELECT score,status,created_at FROM acceptance_test_runs ORDER BY created_at DESC LIMIT 1").fetchone()
        return dict(r) if r else {'score':0,'status':'Not run','created_at':None}
    except Exception:
        return {'score':0,'status':'Not run','created_at':None}


def _gle_dynamic_checks(conn):
    checks = []
    def add(key, category, label, status, detail, required=True):
        checks.append({'key':key,'category':category,'label':label,'status':status,'detail':detail,'required':required})
    bank_count = int(_gle_scalar(conn, "SELECT COUNT(*) FROM bank_accounts", default=0) or 0) if _gle_table_exists(conn,'bank_accounts') else 0
    add('bank_accounts','Setup','Bank accounts configured','PASS' if bank_count > 0 else 'FAIL', f'{bank_count} bank account(s) found.')
    user_count = int(_gle_scalar(conn, "SELECT COUNT(*) FROM users WHERE COALESCE(active,1)=1", default=0) or 0) if _gle_table_exists(conn,'users') else 0
    add('users','Security','Active users configured','PASS' if user_count > 1 else 'WARN', f'{user_count} active user(s). Add named users before institutional use.')
    period_count = int(_gle_scalar(conn, "SELECT COUNT(*) FROM accounting_periods", default=0) or 0) if _gle_table_exists(conn,'accounting_periods') else 0
    open_periods = int(_gle_scalar(conn, "SELECT COUNT(*) FROM accounting_periods WHERE LOWER(COALESCE(status,'')) IN ('open','active')", default=0) or 0) if _gle_table_exists(conn,'accounting_periods') else 0
    add('periods','Accounting','Accounting periods configured','PASS' if period_count and open_periods else 'FAIL', f'{period_count} period(s), {open_periods} open.')
    approval_rules = int(_gle_scalar(conn, "SELECT COUNT(*) FROM approval_rules", default=0) or 0) if _gle_table_exists(conn,'approval_rules') else 0
    add('approval_rules','Control','Approval workflow configured','PASS' if approval_rules > 0 else 'WARN', f'{approval_rules} approval rule(s).')
    backup_count = int(_gle_scalar(conn, "SELECT COUNT(*) FROM backup_log", default=0) or 0) if _gle_table_exists(conn,'backup_log') else 0
    add('backup','Continuity','At least one backup exists','PASS' if backup_count > 0 else 'FAIL', f'{backup_count} backup record(s).')
    ob_count = int(_gle_scalar(conn, "SELECT COUNT(*) FROM opening_balance_batches WHERE LOWER(COALESCE(status,''))='posted'", default=0) or 0) if _gle_table_exists(conn,'opening_balance_batches') else 0
    add('opening_balances','Accounting','Opening balances posted or confirmed','PASS' if ob_count > 0 else 'WARN', f'{ob_count} posted opening balance batch(es). If not applicable, mark the checklist item Done with evidence.')
    acc = _gle_latest_acceptance(conn)
    try: score = float(acc.get('score') or 0)
    except Exception: score = 0
    add('acceptance_test','Testing','Acceptance test run','PASS' if score >= 90 else 'WARN', f"Latest score: {score:.1f}; status: {acc.get('status') or 'Not run'}.")
    doc_required = True
    try:
        if _gle_table_exists(conn,'app_settings'):
            val = _gle_scalar(conn, "SELECT setting_value FROM app_settings WHERE setting_key='mandatory_supporting_documents'", default='1')
            doc_required = str(val).lower() not in ('0','false','no','off')
    except Exception:
        doc_required = True
    add('mandatory_documents','Audit','Mandatory supporting documents active','PASS' if doc_required else 'WARN', 'Attachment requirement is active.' if doc_required else 'Turn on mandatory supporting documents before live use.')
    gl_diff = 0.0
    if _gle_table_exists(conn,'general_ledger'):
        gl_diff = round(float(_gle_scalar(conn, "SELECT COALESCE(SUM(debit_amount),0)-COALESCE(SUM(credit_amount),0) FROM general_ledger", default=0) or 0), 2)
    add('ledger_balance','Accounting','General ledger balances','PASS' if abs(gl_diff) < 0.01 else 'FAIL', f'Debit minus credit: GHS {gl_diff:,.2f}.')
    return checks


def _gle_state(conn):
    _gle_migration()
    r = conn.execute("SELECT * FROM go_live_enforcement WHERE id='default'").fetchone()
    d = dict(r) if r else {'enabled':1,'mode':'SETUP','signed_off':0}
    d['enabled'] = bool(int(d.get('enabled') or 0))
    d['signed_off'] = bool(int(d.get('signed_off') or 0))
    d['mode'] = str(d.get('mode') or 'SETUP').upper()
    return d


def _gle_readiness(conn):
    st = _gle_state(conn)
    manual = [dict(r) for r in conn.execute("SELECT * FROM go_live_checklist_items ORDER BY category,label").fetchall()]
    dynamic = _gle_dynamic_checks(conn)
    manual_blockers = []
    for m in manual:
        req = bool(int(m.get('required') or 0))
        status = str(m.get('status') or 'Pending')
        if req and status not in ('Done','Not Applicable','N/A'):
            manual_blockers.append(m.get('item_key'))
    dynamic_blockers = [d.get('key') for d in dynamic if d.get('required') and d.get('status') == 'FAIL']
    warnings = [d.get('key') for d in dynamic if d.get('status') == 'WARN']
    score = max(0, 100 - (len(manual_blockers) * 8) - (len(dynamic_blockers) * 15) - (len(warnings) * 3))
    ready_for_live = (not manual_blockers) and (not dynamic_blockers) and score >= 85
    posting_allowed = True
    posting_message = 'Posting allowed.'
    if st.get('enabled'):
        if st.get('mode') == 'SETUP':
            posting_allowed = False
            posting_message = 'Posting is locked during SETUP. Switch to UAT for test postings or complete go-live sign-off for live operations.'
        elif st.get('mode') == 'LIVE' and not st.get('signed_off'):
            posting_allowed = False
            posting_message = 'LIVE mode requires completed go-live sign-off.'
    return {'state':st,'manual_checklist':manual,'dynamic_checks':dynamic,'manual_blockers':manual_blockers,'dynamic_blockers':dynamic_blockers,'warnings':warnings,'score':round(score,1),'ready_for_live':ready_for_live,'posting_allowed':posting_allowed,'posting_message':posting_message}


def api_go_live_enforcement(session):
    if not session: return err('Not authenticated')
    _gle_migration(); conn=get_db()
    try:
        info = _gle_readiness(conn)
        counts = _gle_operational_counts(conn)
        return ok({'version':GO_LIVE_ENFORCEMENT_VERSION, **info, 'operational_counts':counts, 'generated_at':_gle_now()})
    finally:
        conn.close()


def api_update_go_live_checklist(data, session):
    if not _gle_is_admin(session): return err('Admin access required')
    _gle_migration(); conn=get_db()
    try:
        items = (data or {}).get('items')
        if not items:
            items = [{'item_key':(data or {}).get('item_key') or (data or {}).get('key'), 'status':(data or {}).get('status'), 'evidence':(data or {}).get('evidence') or (data or {}).get('notes','')}]
        allowed = {'Pending','Done','Not Applicable','N/A'}
        changed = 0
        for item in items:
            key = (item or {}).get('item_key') or (item or {}).get('key')
            if not key: continue
            status = (item or {}).get('status') or 'Pending'
            if status not in allowed: raise ValueError(f'Invalid checklist status for {key}')
            evidence = (item or {}).get('evidence') or (item or {}).get('notes') or ''
            conn.execute("""UPDATE go_live_checklist_items SET status=?, evidence=?, updated_by=?, updated_at=? WHERE item_key=?""", (status, evidence, (session or {}).get('username','admin'), _gle_now(), key))
            changed += conn.total_changes
        _gle_audit(conn, session, 'UPDATE_GO_LIVE_CHECKLIST', 'go_live_checklist_items', 'multiple', f'{changed} checklist update(s)')
        conn.commit()
        return api_go_live_enforcement(session)
    except Exception as exc:
        conn.rollback(); return err(str(exc))
    finally:
        conn.close()


def api_set_go_live_mode(data, session):
    if not _gle_is_admin(session): return err('Admin access required')
    _gle_migration(); conn=get_db()
    try:
        mode = str((data or {}).get('mode') or '').upper().strip()
        if mode not in ('SETUP','UAT','LIVE'):
            return err('Mode must be SETUP, UAT or LIVE')
        reason = ((data or {}).get('reason') or (data or {}).get('note') or '').strip()
        if len(reason) < 5:
            return err('Enter a reason or note of at least 5 characters')
        if mode == 'LIVE':
            info = _gle_readiness(conn)
            if not info.get('ready_for_live'):
                return err('Go-live sign-off is not yet allowed. Complete required checklist and clear failed readiness checks first.')
            conn.execute("""UPDATE go_live_enforcement SET mode='LIVE', signed_off=1, signed_off_by=?, signed_off_at=?, signoff_note=?, updated_by=?, updated_at=? WHERE id='default'""", (session.get('username','admin'), _gle_now(), reason, session.get('username','admin'), _gle_now()))
            # Activate the existing Launch Lock so post-live master data changes require admin reasons.
            try:
                if _gle_table_exists(conn,'launch_lock'):
                    conn.execute("""INSERT INTO launch_lock(id,is_locked,locked_at,locked_by,reason,updated_at)
                                  VALUES('default',1,?,?,?,?)
                                  ON CONFLICT(id) DO UPDATE SET is_locked=1, locked_at=excluded.locked_at, locked_by=excluded.locked_by, reason=excluded.reason, updated_at=excluded.updated_at""", (_gle_now(), session.get('username','admin'), 'Go-live sign-off: '+reason, _gle_now()))
            except Exception:
                pass
        else:
            conn.execute("""UPDATE go_live_enforcement SET mode=?, signed_off=0, signoff_note=?, updated_by=?, updated_at=? WHERE id='default'""", (mode, reason, session.get('username','admin'), _gle_now()))
        _gle_audit(conn, session, 'SET_GO_LIVE_MODE', 'go_live_enforcement', 'default', f'{mode}: {reason}')
        conn.commit()
        return api_go_live_enforcement(session)
    except Exception as exc:
        conn.rollback(); return err(str(exc))
    finally:
        conn.close()


def api_go_live_signoff(data, session):
    d = dict(data or {})
    d['mode'] = 'LIVE'
    return api_set_go_live_mode(d, session)


def _gle_posting_guard(data, session, action_label):
    try:
        _gle_migration(); conn=get_db()
        try:
            info = _gle_readiness(conn)
            st = info.get('state') or {}
            if not st.get('enabled'):
                return None
            mode = st.get('mode') or 'SETUP'
            if mode == 'SETUP':
                return f'Go-Live Gate: {action_label} is locked during SETUP. Move the system to UAT for test postings, or complete live sign-off before institutional posting.'
            if mode == 'LIVE' and not st.get('signed_off'):
                return f'Go-Live Gate: {action_label} is blocked because LIVE mode has not been signed off.'
            return None
        finally:
            conn.close()
    except Exception:
        # Never crash a production route because of the guard. A failed guard audit should not break the app.
        return None


