# Local server route bridge for the Go-Live Enforcement Gate. Render uses app.py;
# this keeps `python server.py` behaviour consistent for offline testing.
try:
    _gle_prev_handler_do_GET = Handler.do_GET
    def _gle_handler_do_GET(self):
        path = urlparse(self.path).path
        if path == '/api/go-live-enforcement':
            session = self.get_session()
            if not session: return self.send_json({'error':'Not authenticated'}, 401)
            return self.send_json(api_go_live_enforcement(session))
        return _gle_prev_handler_do_GET(self)
    Handler.do_GET = _gle_handler_do_GET
except Exception as _gle_exc:
    print('Go-live local GET route warning:', _gle_exc)

try:
    _gle_prev_handler_do_POST = Handler.do_POST
    def _gle_handler_do_POST(self):
        path = urlparse(self.path).path
        if path in ('/api/go-live-enforcement/checklist','/api/go-live-enforcement/mode','/api/go-live-enforcement/signoff'):
            data = self.read_body(); session = self.get_session()
            if not session: return self.send_json({'error':'Not authenticated'}, 401)
            if path == '/api/go-live-enforcement/checklist':
                return self.send_json(api_update_go_live_checklist(data, session))
            if path == '/api/go-live-enforcement/mode':
                return self.send_json(api_set_go_live_mode(data, session))
            return self.send_json(api_go_live_signoff(data, session))
        return _gle_prev_handler_do_POST(self)
    Handler.do_POST = _gle_handler_do_POST
except Exception as _gle_exc:
    print('Go-live local POST route warning:', _gle_exc)

