# ── Opening-balance register & reversal (admin data-cleanup) ──────────────────
def api_list_opening_journals(session):
    """List every opening-balance journal (CSV import + bank opening) so admins can
    review and reverse erroneous/duplicate entries. The GL is the source of truth."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        src = "('opening_balance','opening_balance_import','bank_opening_balance')"
        rows = conn.execute(
            "SELECT id, jv_number, jv_date, description, source_module, source_id, "
            "total_debit, total_credit, status FROM journal_vouchers "
            "WHERE source_module IN " + src + " ORDER BY jv_date, jv_number").fetchall()
        out = []
        for r in rows:
            d = dict(r)
            legs = [dict(x) for x in conn.execute(
                "SELECT coa_code, account_name, debit_amount, credit_amount "
                "FROM general_ledger WHERE jv_id=? ORDER BY debit_amount DESC", (r['id'],)).fetchall()]
            d['lines'] = legs
            dr_legs = [x for x in legs if (x.get('debit_amount') or 0) > 0]
            if dr_legs:
                top = max(dr_legs, key=lambda x: x.get('debit_amount') or 0)
                lbl = ((top.get('coa_code') or '') + ' ' + (top.get('account_name') or '')).strip()
                if len(dr_legs) > 1:
                    lbl += '  (+%d more)' % (len(dr_legs) - 1)
                d['account_label'] = lbl
            else:
                d['account_label'] = ''
            # Amount = the journal total (its credit to Accumulated Fund), so the figure
            # ties directly to the AF reconciliation. Fall back to summed debit legs.
            total = float(r['total_debit'] or 0)
            if not total and legs:
                total = sum(float(x.get('debit_amount') or 0) for x in legs)
            d['amount'] = round(total, 2)
            d['gl_active'] = len(legs) > 0
            out.append(d)
        return ok({'journals': out})
    finally:
        conn.close()


def api_reverse_opening_journal(data, session):
    """Reverse a single opening-balance journal: remove its general-ledger lines so it
    disappears from the Trial Balance / SFP / Cash Flow, mark the voucher Reversed,
    zero any linked bank opening balance, and flag its batch. Admin/Finance only."""
    if not session: return err('Not authenticated')
    if not _ih2_finance(session): return err('Finance Officer or Admin access required')
    key = (data or {}).get('jv_number') or (data or {}).get('jv_id') or (data or {}).get('id')
    if not key: return err('jv_number or jv_id is required')
    conn = get_db()
    try:
        jv = conn.execute(
            "SELECT id, jv_number, source_module, source_id, status, total_debit "
            "FROM journal_vouchers WHERE (jv_number=? OR id=?) AND source_module IN "
            "('opening_balance','opening_balance_import','bank_opening_balance')",
            (key, key)).fetchone()
        if not jv: return err('Opening-balance journal not found: %s' % key)
        if (jv['status'] or '') == 'Reversed':
            return err('That opening balance is already reversed')
        jv_id = jv['id']
        # Opening balances have no downstream transactions — removing the ledger lines
        # cleanly retracts them from every statement.
        conn.execute("DELETE FROM general_ledger WHERE jv_id=?", (jv_id,))
        # Only touch columns with no foreign-key constraints (reversed_by/voided_by
        # reference other rows) — record who/why in void_reason which is free text.
        conn.execute(
            "UPDATE journal_vouchers SET status='Reversed', total_debit=0, total_credit=0, "
            "void_reason=?, voided_at=datetime('now') WHERE id=?",
            ('Opening balance reversed by %s' % session.get('username', 'admin'), jv_id))
        if (jv['source_module'] == 'bank_opening_balance') and jv['source_id']:
            try:
                conn.execute("UPDATE bank_accounts SET opening_balance=0 WHERE id=?", (jv['source_id'],))
            except Exception:
                pass
        try:
            conn.execute("UPDATE opening_balance_batches SET status='Reversed' WHERE jv_id=?", (jv_id,))
        except Exception:
            pass
        try:
            _audit(conn, session, 'reverse', 'opening_balance', jv_id, 'Reversed %s' % jv['jv_number'])
        except Exception:
            pass
        conn.commit()
        return ok({'reversed': jv['jv_number']})
    finally:
        conn.close()
def api_reset_ledger_zero(data, session):
    """Clean FINANCIAL slate: remove every posted transaction and opening balance so
    all ledger, bank and cash balances read zero, while PRESERVING setup (chart of
    accounts, bank accounts, employees, vendors, projects, departments, periods,
    users, settings) and BUDGETS. Admin only; takes an automatic backup first."""
    if not session: return err('Not authenticated')
    if not _ice_admin(session): return err('Admin access required to reset balances')
    confirm = str((data or {}).get('confirm') or '').strip().upper()
    if confirm not in ('RESET', 'ZERO', 'YES'):
        return err('Type confirm="RESET" to zero all balances and transactions.')
    backup_note = None
    try:
        bk = api_create_backup(session, notes='Auto-backup before balance reset')
        if isinstance(bk, dict):
            backup_note = bk.get('filename') or bk.get('file') or 'backup created'
    except Exception as _bke:
        backup_note = 'backup skipped: %s' % _bke
    TX_TABLES = [
        'general_ledger','jv_lines','jv_audit','journal_vouchers',
        'actuals','fund_receipts','commitments','recurring_commitments','withholding_payables',
        'invoice_lines','invoices',
        'fuel_coupon_movements','fuel_coupon_batches',
        'payroll_register','payroll_audit',
        'opening_balance_lines','opening_balance_batches',
        'bank_reconciliations','bank_recon_items','bank_reconciliations_v55','recon_items',
        'asset_movements','asset_maintenance','asset_verifications',
        'approvals','approval_steps','transaction_workflows',
        'soft_deleted_items','pv_batch_import_log','pv_preview_audit',
    ]
    conn = get_db()
    cleared = []
    try:
        conn.execute('PRAGMA foreign_keys=OFF')
        for t in TX_TABLES:
            if _ice_table_exists(conn, t):
                n = conn.execute("SELECT COUNT(*) FROM %s" % t).fetchone()[0]
                conn.execute("DELETE FROM %s" % t)
                if n: cleared.append('%s(%d)' % (t, n))
        try:
            conn.execute("UPDATE bank_accounts SET opening_balance=0")
        except Exception:
            pass
        try:
            rid = str(uuid.uuid4())
            if _ice_table_exists(conn, 'deployment_reset_log'):
                conn.execute("INSERT INTO deployment_reset_log(id,reset_scope,tables_cleaned,created_by,notes) VALUES(?,?,?,?,?)",
                             (rid, 'financial_zero', ','.join(cleared), session.get('username','system'),
                              'Balances and transactions reset to zero; budgets and setup preserved'))
        except Exception:
            pass
        conn.execute('PRAGMA foreign_keys=ON')
        conn.commit()
    except Exception as exc:
        conn.rollback()
        return err('Reset failed: %s' % exc)
    finally:
        try: conn.execute('PRAGMA foreign_keys=ON')
        except Exception: pass
        conn.close()
    return ok({
        'cleared': cleared,
        'backup': backup_note,
        'message': 'All balances and transactions reset to zero. Budgets and setup '
                   '(chart of accounts, bank accounts, employees, vendors, projects, '
                   'periods, users, settings) preserved.'
    })


def api_tag_actual_budget(data, session):
    """POST /api/actuals/tag-budget — link a payment (actual) to a budget line for
    budget-vs-actual control, WITHOUT touching the General Ledger. The budget link is
    a reporting tag, not a financial attribute, so (unlike a full edit) it must NOT
    reverse/repost the journal — that would add pointless reversal noise. Admin /
    Finance only. Pass budget_id='' or null to clear the tag."""
    if not session:
        return err('Not logged in', 401)
    if not _ih2_finance(session):
        return err('Finance Officer or Admin access required')
    aid = data.get('id') or data.get('actual_id')
    if not aid:
        return err('No transaction ID provided')
    budget_id = data.get('budget_id') or None
    conn = get_db()
    try:
        a = conn.execute("SELECT * FROM actuals WHERE id=?", (aid,)).fetchone()
        if not a:
            conn.close(); return err('Transaction not found')
        _a_coa = a['expense_coa_id'] if 'expense_coa_id' in a.keys() else None
        if budget_id:
            b = conn.execute("SELECT id, coa_id FROM budgets WHERE id=?", (budget_id,)).fetchone()
            if not b:
                conn.close(); return err('Budget line not found')
            # Safety: only allow tagging to a budget line for the SAME expenditure item
            # (COA) as the payment, so a payment can't be charged to an unrelated budget.
            if _a_coa and b['coa_id'] and _a_coa != b['coa_id']:
                conn.close(); return err('That budget line is for a different account than this payment — choose the budget line for the same expenditure item (COA).')
        conn.execute("UPDATE actuals SET budget_id=? WHERE id=?", (budget_id, aid))
        _audit(conn, session, 'TAG_ACTUAL_BUDGET', 'actuals', aid,
               f"{a['actual_code']} budget link set to {budget_id or '(cleared)'} — reporting tag only, no GL change")
        conn.commit(); conn.close()
        return ok({'id': aid, 'budget_id': budget_id, 'message': 'Budget link updated (no ledger change)'})
    except Exception as e:
        try: conn.rollback(); conn.close()
        except Exception: pass
        return err('Tag budget failed: ' + str(e))


def _next_budget_code(conn, year='2026'):
    """Sequential human-friendly budget code QB-YYYY-NNN (continues the highest existing)."""
    try:
        last = conn.execute("SELECT budget_code FROM budgets WHERE budget_code LIKE ? ORDER BY budget_code DESC LIMIT 1",
                            ('QB-' + year + '-%',)).fetchone()
        nextn = 1
        if last and last['budget_code']:
            try: nextn = int(str(last['budget_code']).split('-')[-1]) + 1
            except Exception: nextn = 1
        while conn.execute("SELECT 1 FROM budgets WHERE budget_code=?", ('QB-%s-%03d' % (year, nextn),)).fetchone():
            nextn += 1
        return 'QB-%s-%03d' % (year, nextn)
    except Exception:
        return 'QB-%s-%03d' % (year, 1)


def api_renumber_budget_codes(data, session):
    """POST /api/budgets/renumber-codes — one-time: replace auto/hex budget codes with
    sequential QB-YYYY-NNN, ordered by department then account. Admin/Finance only.
    Cosmetic and SAFE — budget_code is not a foreign key (links use budget_id)."""
    if not session:
        return err('Not logged in', 401)
    if not _ih2_finance(session):
        return err('Finance Officer or Admin access required')
    year = str((data or {}).get('year') or '2026')
    conn = get_db()
    try:
        rows = conn.execute("""SELECT b.id FROM budgets b
            LEFT JOIN projects p ON p.id=b.project_id
            LEFT JOIN chart_of_accounts c ON c.id=b.coa_id
            WHERE COALESCE(b.is_deleted,0)=0
            ORDER BY COALESCE(p.division, p.project_code, ''), COALESCE(c.code,'')""").fetchall()
        # Two passes to avoid UNIQUE collisions with existing codes mid-update.
        for r in rows:
            conn.execute("UPDATE budgets SET budget_code=? WHERE id=?", ('TMP-' + str(r['id'])[:8], r['id']))
        n = 0
        for i, r in enumerate(rows, start=1):
            conn.execute("UPDATE budgets SET budget_code=? WHERE id=?", ('QB-%s-%03d' % (year, i), r['id']))
            n += 1
        _audit(conn, session, 'RENUMBER_BUDGET_CODES', 'budgets', 'all',
               '%d budget codes renumbered to QB-%s-NNN' % (n, year))
        conn.commit(); conn.close()
        return ok({'renumbered': n, 'message': '%d budget lines renumbered to QB-%s-001..%03d' % (n, year, n)})
    except Exception as e:
        try: conn.rollback(); conn.close()
        except Exception: pass
        return err('Renumber failed: ' + str(e))


def api_ai_context(session):
    """Lightweight live-snapshot for the in-app assistant (consumed by /api/ai/context
    in the UI). Returns headline figures so the chatbot can answer with current data."""
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        def sc(q):
            try:
                return float((conn.execute(q).fetchone() or [0])[0] or 0)
            except Exception:
                return 0.0
        import os as _os
        ctx = {
            'project_count': int(sc("SELECT COUNT(*) FROM projects")),
            'budget_total_ghs': round(sc("SELECT COALESCE(SUM(COALESCE(budget_ghs,budget_fcy,0)),0) FROM budgets"), 2),
            'actuals_posted_ghs': round(sc("SELECT COALESCE(SUM(amount_ghs),0) FROM actuals"), 2),
            'actuals_pending': int(sc("SELECT COUNT(*) FROM actuals WHERE COALESCE(approval_status,status,'') IN ('Pending','Submitted')")),
            'commitments_open': int(sc("SELECT COUNT(*) FROM commitments WHERE COALESCE(status,'') NOT IN ('Closed','Cancelled','Fully Utilised','Fully Paid')")),
            # Unpaid commitment encumbrance (value still reserved against budget)
            'open_commitment_value_ghs': round(sc("SELECT COALESCE(SUM(MAX(0, c.amount_ghs - COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.commitment_id=c.id AND COALESCE(a.is_posted,0)=1),0))),0) FROM commitments c WHERE COALESCE(c.status,'') NOT IN ('Cancelled','Fully Paid')"), 2),
            # Cash & bank position from the GL (asset codes 126x/127x/128x/1001)
            'cash_and_bank_ghs': round(sc("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '126%' OR coa_code LIKE '127%' OR coa_code LIKE '128%' OR coa_code LIKE '129%' OR coa_code='1001'"), 2),
            'spend_this_year_ghs': round(sc("SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE COALESCE(is_posted,0)=1 AND substr(COALESCE(expense_date,''),1,4)=strftime('%Y','now')"), 2),
            'pending_approvals': int(sc("SELECT COUNT(*) FROM approvals WHERE COALESCE(status,'')='Pending'")),
            'pending_withholdings_ghs': round(sc("SELECT COALESCE(SUM(amount_ghs),0) FROM withholding_payables WHERE COALESCE(status,'')='Pending'"), 2),
            'overdue_withholdings': int(sc("SELECT COUNT(*) FROM withholding_payables WHERE COALESCE(status,'')='Pending' AND due_date IS NOT NULL AND due_date < date('now')")),
            'overdue_withholdings_ghs': round(sc("SELECT COALESCE(SUM(amount_ghs),0) FROM withholding_payables WHERE COALESCE(status,'')='Pending' AND due_date IS NOT NULL AND due_date < date('now')"), 2),
            'receivables_outstanding_ghs': round(sc("SELECT COALESCE(SUM(total_ghs - amount_received - COALESCE(credited_ghs,0)),0) FROM ar_invoices WHERE status IN ('Posted','Part-Paid')"), 2),
            'receivables_overdue_ghs': round(sc("SELECT COALESCE(SUM(total_ghs - amount_received - COALESCE(credited_ghs,0)),0) FROM ar_invoices WHERE status IN ('Posted','Part-Paid') AND due_date IS NOT NULL AND due_date < date('now')"), 2),
            'inventory_value_ghs': round(sc("SELECT COALESCE(SUM(qty_on_hand*avg_cost),0) FROM inv_items"), 2),
            'fuel_coupon_stock_ghs': round(sc("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_batches") + sc("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type IN ('Borrow','Return','Return-Issued','Return-Lent')") - sc("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type IN ('Issue','Lend','Return-Borrowed')"), 2),
            'inventory_low_stock': int(sc("SELECT COUNT(*) FROM inv_items WHERE reorder_level>0 AND qty_on_hand<=reorder_level")),
            'ai_configured': bool(_os.environ.get('ANTHROPIC_API_KEY')),
        }
        return ok({'context': ctx})
    finally:
        conn.close()


def api_budget_control(session, period_from=None, period_to=None, project_id=None, unit_code=None):
    """Budget vs Actual (Budget Control) report. Wraps the budget-variance engine and
    exposes the lines under the keys the Budget Control / comparative screens expect."""
    res = api_budget_variance_v556(session, period_from, period_to, project_id, unit_code)
    if isinstance(res, dict) and res.get('ok'):
        lines = res.get('lines', [])
        res['items'] = lines
        res['budget_lines'] = lines
    return res


