def _ips_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False


def _ips_cols(conn, table):
    try:
        return {r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()}
    except Exception:
        return set()


def _ips_setting(conn, key, default=''):
    try:
        row = conn.execute("SELECT value FROM settings WHERE key=?", (key,)).fetchone()
        return row[0] if row and row[0] is not None else default
    except Exception:
        return default


def _ips_set_setting(conn, key, value, description=''):
    conn.execute("""INSERT INTO settings(key,value,description) VALUES(?,?,?)
                    ON CONFLICT(key) DO UPDATE SET value=excluded.value,
                    description=COALESCE(NULLIF(excluded.description,''), settings.description)""", (key, str(value), description or ''))


def _ips_float(v, default=0.0):
    try:
        if v is None or v == '':
            return float(default)
        return float(v)
    except Exception:
        return float(default)


def _ips_int(v, default=0):
    try:
        if v is None or v == '':
            return int(default)
        return int(float(v))
    except Exception:
        return int(default)


def _ips_session_is_demo(session):
    try:
        s = session or {}
        marker = ' '.join([str(s.get('username','')), str(s.get('full_name','')), str(s.get('email',''))]).lower()
        return any(x in marker for x in ('demo', 'trial', 'uat'))
    except Exception:
        return False


def _ips_migration():
    conn = get_db()
    try:
        if _ips_table_exists(conn, 'settings'):
            _ips_set_setting(conn, 'fuel_coupon_reorder_level', _ips_setting(conn, 'fuel_coupon_reorder_level', '0'), 'Central fuel coupon reorder level in face value GHS')
            _ips_set_setting(conn, 'fuel_coupon_reorder_quantity_level', _ips_setting(conn, 'fuel_coupon_reorder_quantity_level', '0'), 'Central fuel coupon reorder level in number of coupons')
            _ips_set_setting(conn, 'financial_reporting_basis', 'IFRS/IPSAS net balance reporting', 'Trial balance and statement reports use net account balances from posted ledger entries')
        # Guarded additive columns only. Older deployments can accept the new UI payload safely.
        if _ips_table_exists(conn, 'fuel_coupon_movements'):
            cols = _ips_cols(conn, 'fuel_coupon_movements')
            adds = {
                'source_movement_id': 'TEXT',
                'serial_from': 'TEXT',
                'serial_to': 'TEXT',
                'vehicle_id': 'TEXT',
                'vehicle_number': 'TEXT',
                'vehicle_is_external': 'INTEGER DEFAULT 0',
                'issuing_officer': 'TEXT',
                'receiving_officer': 'TEXT',
                'return_mode': 'TEXT',
                'is_reversed': 'INTEGER DEFAULT 0',
                'is_deleted': 'INTEGER DEFAULT 0'
            }
            for col, ddl in adds.items():
                if col not in cols:
                    try:
                        conn.execute(f"ALTER TABLE fuel_coupon_movements ADD COLUMN {col} {ddl}")
                    except Exception:
                        pass
        conn.commit()
    finally:
        conn.close()


