def _ips_gl_rows(conn, filters=None):
    filters = filters or {}
    where, args = [], []
    if filters.get('period'):
        where.append('gl.period=?'); args.append(filters.get('period'))
    if filters.get('project_id'):
        where.append('gl.project_id=?'); args.append(filters.get('project_id'))
    if filters.get('coa_id'):
        where.append('gl.coa_id=?'); args.append(filters.get('coa_id'))
    if filters.get('coa_code'):
        where.append('gl.coa_code=?'); args.append(filters.get('coa_code'))
    if filters.get('date_from'):
        where.append('gl.ledger_date>=?'); args.append(filters.get('date_from'))
    if filters.get('date_to'):
        where.append('gl.ledger_date<=?'); args.append(filters.get('date_to'))
    q = """
        SELECT gl.*, c.category, c.sub_category, c.account_type
        FROM general_ledger gl
        LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id
    """
    if where:
        q += ' WHERE ' + ' AND '.join(where)
    q += ' ORDER BY gl.ledger_date, gl.jv_number, gl.id'
    return [dict(r) for r in conn.execute(q, args).fetchall()]


def _ips_account_nature(row):
    code = str(row.get('coa_code') or row.get('code') or '')
    cat = str(row.get('category') or '').lower()
    typ = str(row.get('account_type') or '').lower()
    name = str(row.get('account_name') or '').lower()
    if typ in ('asset', 'assets') or 'asset' in cat or code.startswith('1'):
        return 'Asset'
    if typ in ('liability', 'liabilities') or 'liabil' in cat or code.startswith('2'):
        return 'Liability'
    if typ in ('equity','capital','fund') or 'equity' in cat or 'fund' in cat or 'net asset' in cat or code.startswith('3'):
        return 'Equity'
    if typ in ('income','revenue') or 'income' in cat or 'revenue' in cat or code.startswith('4'):
        return 'Income'
    if typ in ('expense','expenses') or 'expense' in cat or 'cost' in cat or code.startswith(('5','6','7','8','9')):
        return 'Expense'
    if 'bank' in name or 'cash' in name:
        return 'Asset'
    return 'Other'


def api_get_ledger_accounts_summary(session, period=None, unit=None):
    """IFRS/IPSAS style trial balance summary: one net debit or credit balance per account."""
    if not session:
        return []
    conn = get_db()
    try:
        filters = {'period': period} if period else {}
        rows = _ips_gl_rows(conn, filters)
        # [H2b] Enforce the viewer's org-unit read scope AND an optional ?unit=
        # consolidation node (subtree), intersected with the enforced scope —
        # mirrors the scoped trial balance. Unrestricted for Admin/university.
        if '_ucc_gl_scope_clause' in globals():
            try:
                _node = unit if (unit and '_ucc_subtree_unit_ids' in globals()
                                 and _ucc_subtree_unit_ids(conn, unit)) else None
                enforced = _ucc_resolve_read_scope(conn, session)   # None=unrestricted
                req = _ucc_subtree_unit_ids(conn, _node) if _node else None
                if enforced is None and req is None:
                    eff = None  # fully unrestricted
                elif enforced is None:
                    eff = req
                elif req is None:
                    eff = enforced
                else:
                    eff = enforced & req
                if eff is not None:
                    rows = [r for r in rows if r.get('unit_id') in eff]
            except Exception:
                rows = []  # fail closed
        acc = {}
        for r in rows:
            key = r.get('coa_id') or r.get('coa_code') or r.get('account_name')
            if not key:
                continue
            if key not in acc:
                acc[key] = {
                    'coa_id': r.get('coa_id'),
                    'code': r.get('coa_code') or '',
                    'coa_code': r.get('coa_code') or '',
                    'account_name': r.get('account_name') or '',
                    'category': r.get('category') or '',
                    'sub_category': r.get('sub_category') or '',
                    'account_type': r.get('account_type') or '',
                    'total_debit': 0.0,
                    'total_credit': 0.0,
                    'transaction_count': 0,
                }
            acc[key]['total_debit'] += _ips_float(r.get('debit_amount'))
            acc[key]['total_credit'] += _ips_float(r.get('credit_amount'))
            acc[key]['transaction_count'] += 1
        out = []
        for a in acc.values():
            dr = round(a['total_debit'], 2)
            cr = round(a['total_credit'], 2)
            net = round(dr - cr, 2)
            debit_balance = round(max(net, 0), 2)
            credit_balance = round(max(-net, 0), 2)
            nature = _ips_account_nature(a)
            statement_balance = net if nature in ('Asset','Expense') else -net if nature in ('Liability','Equity','Income') else net
            a.update({
                'total_debit': dr,
                'total_credit': cr,
                'net_balance': net,
                'debit_balance': debit_balance,
                'credit_balance': credit_balance,
                'normal_side': 'Debit' if debit_balance else ('Credit' if credit_balance else ''),
                'account_nature': nature,
                'statement_balance': round(statement_balance, 2),
                'reporting_basis': 'Net posted ledger balance. Movements are retained for audit only.',
            })
            out.append(a)
        out.sort(key=lambda x: (str(x.get('code') or ''), str(x.get('account_name') or '')))
        return out
    finally:
        conn.close()


# Fuel receiving office, batch over-issue controls, reorder settings, and corrected project return balances.
try:
    _ips_prev_api_fuel = api_fuel
except Exception:
    _ips_prev_api_fuel = None


def _ips_movement_live_where(prefix=''):
    p = (prefix + '.') if prefix else ''
    parts = []
    # The columns may be absent on older DBs, so caller must only use after migration.
    parts.append(f"COALESCE({p}is_deleted,0)=0")
    parts.append(f"COALESCE({p}is_reversed,0)=0")
    return ' AND '.join(parts)


def _ips_batch_available(conn, batch_id, exclude_id=None):
    batch = conn.execute("SELECT * FROM fuel_coupon_batches WHERE id=?", (batch_id,)).fetchone()
    if not batch:
        return 0, 0, 0
    cols = _ips_cols(conn, 'fuel_coupon_movements')
    live = []
    if 'is_deleted' in cols: live.append('COALESCE(is_deleted,0)=0')
    if 'is_reversed' in cols: live.append('COALESCE(is_reversed,0)=0')
    if exclude_id: live.append('id<>?')
    wh = ' AND '.join(['batch_id=?'] + live)
    args = [batch_id] + ([exclude_id] if exclude_id else [])
    rows = [dict(r) for r in conn.execute(f"SELECT movement_type, quantity FROM fuel_coupon_movements WHERE {wh}", args).fetchall()]
    qty = _ips_int(batch['quantity'])
    inflow_returns = sum(_ips_int(r.get('quantity')) for r in rows if r.get('movement_type') in ('Return','Return-Issued','Return-Lent'))
    outgoing = sum(_ips_int(r.get('quantity')) for r in rows if r.get('movement_type') in ('Issue','Lend','Return-Borrowed'))
    borrowed_in = sum(_ips_int(r.get('quantity')) for r in rows if r.get('movement_type') == 'Borrow')
    available = qty + borrowed_in + inflow_returns - outgoing
    return max(available, 0), qty, outgoing


def _ips_receiving_label(conn, data):
    for k in ('to_entity','receiving_office','receiving_department','unit_name','dept_name'):
        if data.get(k):
            return str(data.get(k)).strip()
    pid = data.get('project_id')
    if pid:
        try:
            p = conn.execute("SELECT project_code,title FROM projects WHERE id=?", (pid,)).fetchone()
            if p:
                return f"{p['project_code']} — {p['title']}"
        except Exception:
            pass
    code = data.get('unit_code') or data.get('dept_code') or data.get('division')
    if code:
        try:
            return f"{code} — {canonical_unit_name(code)}"
        except Exception:
            return str(code)
    return ''


try:
    _ips_prev_api_save_fc_movement = api_save_fc_movement
    def api_save_fc_movement(data, session):
        _ips_migration()
        d = dict(data or {})
        mv = str(d.get('movement_type') or '').strip()
        # Preserve source return link from either frontend naming convention.
        if mv in ('Return','Return-Issued','Return-Lent','Return-Borrowed') and not d.get('source_movement_id'):
            d['source_movement_id'] = d.get('return_source_id') or d.get('source_id')
        conn = get_db()
        try:
            if mv == 'Issue':
                if not d.get('to_entity'):
                    label = _ips_receiving_label(conn, d)
                    if label:
                        d['to_entity'] = label
                if not d.get('to_entity'):
                    return err('Select the receiving office, department, unit or project before issuing fuel coupons.')
                batch_id = d.get('batch_id')
                qty = _ips_int(d.get('quantity'))
                if batch_id and qty > 0:
                    available, batch_qty, outgoing = _ips_batch_available(conn, batch_id, d.get('id'))
                    if qty > available:
                        return err(f'Over issue blocked. This batch has only {available} coupon(s) available; requested {qty}. Central balance cannot override a batch-specific shortage.')
            elif mv in ('Return','Return-Issued','Return-Lent','Return-Borrowed'):
                d['return_mode'] = mv if mv != 'Return' else 'Return-Issued'
                if not d.get('source_movement_id'):
                    return err('Select the original issue, lending or borrowing record being returned.')
            return _ips_prev_api_save_fc_movement(d, session)
        finally:
            conn.close()
except Exception as exc:
    print('IFRS/IPSAS fuel movement wrapper warning:', exc)


def api_set_fuel_reorder_level(data, session):
    if not session:
        return err('Not authenticated')
    if str((session or {}).get('role','')).lower() not in ('admin','finance officer'):
        return err('Only Admin or Finance Officer can set fuel coupon reorder levels')
    _ips_migration()
    conn = get_db()
    try:
        amount = max(0.0, _ips_float((data or {}).get('reorder_level') or (data or {}).get('amount') or 0))
        qty = max(0, _ips_int((data or {}).get('quantity_level') or (data or {}).get('reorder_quantity') or 0))
        _ips_set_setting(conn, 'fuel_coupon_reorder_level', amount, 'Central fuel coupon reorder level in face value GHS')
        _ips_set_setting(conn, 'fuel_coupon_reorder_quantity_level', qty, 'Central fuel coupon reorder level in number of coupons')
        try:
            _audit(conn, session, 'SET_FUEL_REORDER_LEVEL', 'settings', 'fuel_coupon_reorder_level', f'Value={amount}; Qty={qty}')
        except Exception:
            pass
        conn.commit()
        return ok({'reorder_level': amount, 'quantity_level': qty})
    except Exception as exc:
        conn.rollback(); return err(str(exc))
    finally:
        conn.close()


def api_fuel(session):
    _ips_migration()
    payload = _ips_prev_api_fuel(session) if callable(_ips_prev_api_fuel) else {'batches': [], 'movements': [], 'summary': {}}
    conn = get_db()
    try:
        movements = payload.get('movements') or []
        # Correct project balance: returns linked to an issue inherit the original issue project even if the return row has no project_id.
        balances = {}
        def ensure(pid, code='', title=''):
            if not pid:
                return None
            if pid not in balances:
                balances[pid] = {'project_id': pid, 'project_code': code or '', 'name': title or '', 'issued': 0.0, 'returned': 0.0, 'net': 0.0}
            if code and not balances[pid].get('project_code'):
                balances[pid]['project_code'] = code
            if title and not balances[pid].get('name'):
                balances[pid]['name'] = title
            return balances[pid]
        proj_meta = {}
        if _ips_table_exists(conn, 'projects'):
            for p in conn.execute("SELECT id, project_code, title FROM projects").fetchall():
                proj_meta[p['id']] = (p['project_code'], p['title'])
        if _ips_table_exists(conn, 'fuel_coupon_movements'):
            cols = _ips_cols(conn, 'fuel_coupon_movements')
            live = []
            if 'is_deleted' in cols: live.append('COALESCE(r.is_deleted,0)=0')
            if 'is_reversed' in cols: live.append('COALESCE(r.is_reversed,0)=0')
            live_where = (' WHERE ' + ' AND '.join(live)) if live else ''
            for r in conn.execute(f"""
                SELECT r.id, r.movement_type, r.project_id, r.face_value, r.source_movement_id,
                       src.project_id AS source_project_id
                FROM fuel_coupon_movements r
                LEFT JOIN fuel_coupon_movements src ON src.id=r.source_movement_id
                {live_where}
            """).fetchall():
                mv = r['movement_type']
                pid = r['project_id']
                if mv in ('Return','Return-Issued') and r['source_project_id']:
                    pid = r['source_project_id']
                if not pid:
                    continue
                code, title = proj_meta.get(pid, ('', ''))
                b = ensure(pid, code, title)
                if mv == 'Issue':
                    b['issued'] += _ips_float(r['face_value'])
                elif mv in ('Return','Return-Issued'):
                    b['returned'] += _ips_float(r['face_value'])
        for b in balances.values():
            b['issued'] = round(b['issued'], 2)
            b['returned'] = round(b['returned'], 2)
            b['net'] = round(b['issued'] - b['returned'], 2)
        payload['project_balances'] = sorted(balances.values(), key=lambda x: (x.get('project_code') or '', x.get('name') or ''))
        # Reorder level and alert added to central summary.
        summary = dict(payload.get('summary') or {})
        reorder_val = _ips_float(_ips_setting(conn, 'fuel_coupon_reorder_level', '0'))
        reorder_qty = _ips_int(_ips_setting(conn, 'fuel_coupon_reorder_quantity_level', '0'))
        balance_value = _ips_float(summary.get('balance') or summary.get('stock_value') or 0)
        balance_qty = _ips_int(summary.get('balance_qty') or summary.get('stock_qty') or summary.get('available_qty') or 0)
        summary['reorder_level'] = reorder_val
        summary['reorder_quantity_level'] = reorder_qty
        # Reorder is driven by the GHS face VALUE only — denominations vary, so a coupon
        # count is not a meaningful trigger.
        summary['below_reorder_level'] = bool(reorder_val > 0 and balance_value <= reorder_val)
        summary['reorder_message'] = 'Fuel coupon stock is at or below reorder level.' if summary['below_reorder_level'] else 'Fuel coupon stock is above reorder level.'
        summary['reporting_note'] = 'Central balance observes batch-level controls; no batch can be over-issued even where total central value is sufficient.'
        payload['summary'] = summary
        payload['ifrs_ipsas_stabilisation_version'] = IFRS_IPSAS_STABILISATION_VERSION
        return payload
    finally:
        conn.close()


# Local/direct server route for reorder level. WSGI Render route is patched in app.py.
try:
    _ips_prev_handler_post = Handler.do_POST
    def _ips_do_POST(self):
        path = urlparse(self.path).path
        if path == '/api/fuel-coupons/reorder-level':
            data = self.read_body(); session = self.get_session()
            if not session: return self.send_json({'error':'Not authenticated'}, 401)
            return self.send_json(api_set_fuel_reorder_level(data, session))
        return _ips_prev_handler_post(self)
    Handler.do_POST = _ips_do_POST
except Exception as exc:
    print('IFRS/IPSAS local POST route warning:', exc)

try:
    _ips_migration()
except Exception as exc:
    print('IFRS/IPSAS stabilisation startup migration warning:', exc)


