def _cf_is_demo_session(session):
    try:
        s = session or {}
        marker = ' '.join([str(s.get('username','')), str(s.get('full_name','')), str(s.get('email','')), str(s.get('role',''))]).lower()
        return any(x in marker for x in ('demo', 'trial', 'uat'))
    except Exception:
        return False


def set_current_session(session=None):
    global _cf_current_session
    _cf_current_session = session
    return True


def _cf_demo_db_path():
    try:
        base = _cf_Path(_cf_os.environ.get('AOI_DEMO_DATA_DIR') or _cf_os.environ.get('DEMO_DATA_DIR') or '/tmp')
        base.mkdir(parents=True, exist_ok=True)
        prefix = 'sbs' if 'sbs' in str(_cf_Path(__file__).resolve()).lower() else 'aoi'
        return base / f'{prefix}_erp_demo_training.db'
    except Exception:
        return _cf_Path('/tmp/erp_demo_training.db')


def _cf_connect(path):
    conn = _cf_sqlite3.connect(str(path), timeout=30)
    conn.row_factory = _cf_sqlite3.Row
    try:
        conn.execute('PRAGMA foreign_keys=ON')
        conn.execute('PRAGMA busy_timeout=30000')
    except Exception:
        pass
    return conn


def _cf_demo_db_needs_init(path):
    if not _cf_Path(path).exists():
        return True
    try:
        conn = _cf_connect(path)
        try:
            row = conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='users'").fetchone()
            return row is None
        finally:
            conn.close()
    except Exception:
        return True


def get_db():
    global _cf_demo_initialising
    if _cf_is_demo_session(_cf_current_session):
        dbp = _cf_demo_db_path()
        if (not _cf_demo_initialising) and _cf_demo_db_needs_init(dbp):
            _cf_demo_initialising = True
            try:
                _cf_original_init_db()
            finally:
                _cf_demo_initialising = False
            try:
                # Bring the demo/training sandbox up to the same client final schema.
                _cf_migration()
            except Exception as _cf_demo_mig_exc:
                print('Demo sandbox migration warning:', _cf_demo_mig_exc)
        return _cf_connect(dbp)
    return _cf_original_get_db()


