def _cf_err(msg):
    return err(msg) if 'err' in globals() else {'ok': False, 'error': msg}


def _cf_ok(payload=None):
    return ok(payload or {}) if 'ok' in globals() else {'ok': True, **(payload or {})}


def _cf_cols(conn, table):
    try:
        return {r[1] for r in conn.execute(f"PRAGMA table_info({table})").fetchall()}
    except Exception:
        return set()


def _cf_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False


def _cf_add_col(conn, table, col, ddl):
    try:
        if _cf_table_exists(conn, table) and col not in _cf_cols(conn, table):
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {col} {ddl}")
    except Exception:
        pass


def _cf_scalar(conn, sql, params=(), default=None):
    try:
        row = conn.execute(sql, params).fetchone()
        if row is None:
            return default
        return row[0]
    except Exception:
        return default


def _cf_float(v, default=0.0):
    try:
        if v is None or v == '':
            return float(default)
        return float(str(v).replace(',', '').strip())
    except Exception:
        return float(default)


def _cf_int(v, default=0):
    try:
        return int(float(str(v).replace(',', '').strip()))
    except Exception:
        return int(default)


def _cf_date(v=None):
    v = (str(v or '').strip())[:10]
    return v or _cf_datetime.now().strftime('%Y-%m-%d')


def _cf_migration():
    conn = get_db()
    try:
        if _cf_table_exists(conn, 'actuals'):
            _cf_add_col(conn, 'actuals', 'vendor_id', 'TEXT')
            _cf_add_col(conn, 'actuals', 'beneficiary_id', 'TEXT')
        if _cf_table_exists(conn, 'vendors'):
            _cf_add_col(conn, 'vendors', 'beneficiary_type', 'TEXT')
            _cf_add_col(conn, 'vendors', 'status', "TEXT DEFAULT 'Active'")
        if not _cf_table_exists(conn, 'import_jobs'):
            conn.execute("""CREATE TABLE IF NOT EXISTS import_jobs(
                id TEXT PRIMARY KEY, module TEXT, filename TEXT, total_rows INTEGER DEFAULT 0,
                success_rows INTEGER DEFAULT 0, error_rows INTEGER DEFAULT 0, created_by TEXT,
                notes TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP)""")
        if _cf_table_exists(conn, 'asset_register'):
            for col, ddl in {
                'asset_tag':'TEXT','asset_description':'TEXT','asset_class':'TEXT','asset_sub_class':'TEXT',
                'manufacturer':'TEXT','model':'TEXT','serial_number':'TEXT','barcode':'TEXT','qr_code':'TEXT',
                'supplier_id':'TEXT','invoice_no':'TEXT','po_number':'TEXT','condition_status':"TEXT DEFAULT 'Good'",
                'asset_owner':'TEXT','department_code':'TEXT','unit_code':'TEXT','project_code':'TEXT','fund_code':'TEXT',
                'asset_coa_id':'TEXT','depreciation_coa_id':'TEXT','expense_coa_id':'TEXT','disposal_coa_id':'TEXT',
                'depreciation_method':"TEXT DEFAULT 'Straight Line'",'depreciation_start_date':'TEXT','residual_value':'REAL DEFAULT 0',
                'revaluation_amount':'REAL DEFAULT 0','impairment_amount':'REAL DEFAULT 0','last_valuation_date':'TEXT',
                'insurance_policy_no':'TEXT','insurance_expiry':'TEXT','warranty_expiry':'TEXT','maintenance_schedule':'TEXT',
                'last_maintenance_date':'TEXT','next_maintenance_date':'TEXT','last_verification_date':'TEXT','next_verification_date':'TEXT',
                'disposal_date':'TEXT','disposal_proceeds':'REAL DEFAULT 0','disposal_reason':'TEXT','risk_rating':'TEXT',
                'created_at':'TEXT DEFAULT CURRENT_TIMESTAMP'
            }.items():
                _cf_add_col(conn, 'asset_register', col, ddl)
        conn.execute("""CREATE TABLE IF NOT EXISTS asset_maintenance(
            id TEXT PRIMARY KEY, asset_id TEXT, maintenance_date TEXT, maintenance_type TEXT, provider TEXT,
            cost REAL DEFAULT 0, notes TEXT, next_due_date TEXT, created_by TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP)""")
        conn.execute("""CREATE TABLE IF NOT EXISTS asset_movements(
            id TEXT PRIMARY KEY, asset_id TEXT, movement_date TEXT, from_location TEXT, to_location TEXT,
            from_custodian TEXT, to_custodian TEXT, authorised_by TEXT, notes TEXT, created_by TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP)""")
        conn.execute("""CREATE TABLE IF NOT EXISTS asset_verifications(
            id TEXT PRIMARY KEY, asset_id TEXT, verification_date TEXT, verified_by TEXT, physical_condition TEXT,
            location_confirmed INTEGER DEFAULT 1, custodian_confirmed INTEGER DEFAULT 1, notes TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP)""")
        conn.commit()
    except Exception as exc:
        try: conn.rollback()
        except Exception: pass
        print('Client final migration warning:', exc)
    finally:
        conn.close()


