def _cf_csv_rows(text):
    text = text or ''
    if not isinstance(text, str):
        try: text = text.decode('utf-8-sig')
        except Exception: text = str(text)
    if text[:1] == '\ufeff':
        text = text[1:]                       # strip UTF-8 BOM (Excel-saved CSVs)
    delim = ','
    try:
        head = text.split('\n', 1)[0]
        if head.count('\t') > head.count(','): delim = '\t'
        elif head.count(';') > head.count(',') and ';' in head: delim = ';'
    except Exception:
        delim = ','
    return list(_cf_csv.DictReader(_cf_io.StringIO(text), delimiter=delim))


def _cf_xlsx_rows(b64):
    """Parse a base64-encoded .xlsx/.xls(m) workbook into list-of-dict rows
    (first non-empty row = headers). Requires openpyxl."""
    import base64 as _b64
    try:
        import openpyxl as _oxl
    except Exception:
        raise ValueError('Excel parsing needs the openpyxl package on the server. '
                          'Re-save the file as CSV and upload that, or ask the administrator to install openpyxl.')
    payload = b64.split(',', 1)[1] if ',' in b64 else b64
    raw = _b64.b64decode(payload)
    wb = _oxl.load_workbook(_cf_io.BytesIO(raw), read_only=True, data_only=True)
    ws = wb.active
    rows = []; headers = None
    for r in ws.iter_rows(values_only=True):
        if headers is None:
            headers = [(str(c).strip() if c is not None else '') for c in r]
            continue
        if r is None or all(c is None or str(c).strip() == '' for c in r):
            continue
        d = {}
        for i, h in enumerate(headers):
            if not h:
                continue
            v = r[i] if i < len(r) else None
            d[h] = '' if v is None else (v if isinstance(v, str) else str(v))
        rows.append(d)
    return rows


def _cf_ingest_rows(data):
    """Rows from csv_text OR a base64 .xlsx/.xls (file_b64) - one ingest point so
    every importer accepts CSV, TSV/TXT (auto delimiter) and Excel workbooks."""
    data = data or {}
    b64 = data.get('file_b64') or data.get('xlsx_b64')
    fn = (data.get('filename') or '').lower()
    if b64 and (fn.endswith('.xlsx') or fn.endswith('.xlsm') or fn.endswith('.xls')):
        return _cf_xlsx_rows(b64)
    return _cf_csv_rows(data.get('csv_text') or data.get('csv') or data.get('content') or data.get('file_data') or '')


def _cf_lc_row(row):
    return {str(k or '').replace('\ufeff', '').strip().lower().replace(' ', '_').replace('-', '_'): (v.strip() if isinstance(v, str) else v) for k,v in (row or {}).items()}

def api_parse_upload_rows(data, session):
    """Universal upload parser: returns list-of-dict rows from a CSV/TSV/TXT
    csv_text OR a base64 .xlsx/.xls(m) workbook (file_b64). Lets the client send
    Excel files to any importer that works on parsed rows."""
    if not session:
        return err('Not authenticated')
    try:
        rows = _cf_ingest_rows(data or {})
        return ok({'rows': rows, 'count': len(rows)})
    except Exception as e:
        return err(str(e))



