# ---------------------------------------------------------------------------
# LOGO STABILITY PATCH: serve bundled logo assets locally in direct server mode
# ---------------------------------------------------------------------------
try:
    LOGO_STABILITY_BRAND_ASSET_DIR = Path(__file__).parent / 'assets' / 'branding'
    _logo_stability_prev_do_GET = Handler.do_GET
    def _logo_stability_send_asset(self, request_path):
        import os as _os, mimetypes as _mimetypes
        fn = _os.path.basename(request_path)
        f = LOGO_STABILITY_BRAND_ASSET_DIR / fn
        if (not fn) or fn.startswith('.') or (not f.exists()) or (not f.is_file()):
            self.send_response(404); self.send_header('Content-Length','0'); self.end_headers(); return
        body = f.read_bytes()
        self.send_response(200)
        self.send_header('Content-Type', _mimetypes.guess_type(str(f))[0] or 'application/octet-stream')
        self.send_header('Content-Length', str(len(body)))
        self.send_header('Cache-Control','public, max-age=31536000, immutable')
        self.send_header('X-Content-Type-Options','nosniff')
        self.end_headers()
        try:
            self.wfile.write(body); self.wfile.flush()
        except (BrokenPipeError, ConnectionResetError):
            pass
    def _logo_stability_do_GET(self):
        parsed = urlparse(self.path)
        if parsed.path.startswith('/assets/branding/'):
            return _logo_stability_send_asset(self, parsed.path)
        return _logo_stability_prev_do_GET(self)
    Handler.do_GET = _logo_stability_do_GET
except Exception as _logo_stability_exc:
    print('Logo stability local asset route warning:', _logo_stability_exc)

