# v5.3 FEATURE EXPANSION PACK  (Grant Utilisation, GRA, Virements list, Staff
# Advances, SSNIT, Purchase Orders, Contracts, Depreciation, Interunit Transfers,
# Saved Reports, Period Close, Session Security). Additive only — never modifies
# existing functions. All queries adapted to the live SQLite schema.
# ═══════════════════════════════════════════════════════════════════════════════
import uuid as _f53_uuid
from datetime import datetime as _f53_dt, timedelta as _f53_td

def _f53_now():
    return _f53_dt.now().strftime('%Y-%m-%d %H:%M:%S')

def _f53_today():
    return _f53_dt.now().strftime('%Y-%m-%d')

def _f53_uid():
    return str(_f53_uuid.uuid4())

def _f53_f(v, d=0.0):
    import math as _math
    try:
        if v is None or v == '':
            return d
        r = float(v)
        # Reject NaN/Infinity: 'nan > 0.01' is False, so non-finite values would
        # slip past every abs(dr-cr) > tol balance gate and corrupt the ledger.
        return r if _math.isfinite(r) else d
    except Exception:
        return d

def _f53_is_admin(session):
    return (session or {}).get('role') == 'Admin'

def _f53_cols(conn, table):
    try:
        return {r[1] for r in conn.execute("PRAGMA table_info(%s)" % table).fetchall()}
    except Exception:
        return set()

def _f53_table_exists(conn, table):
    try:
        return conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)).fetchone() is not None
    except Exception:
        return False

