def api_retire_advance(data, session):
    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        adv_id = data.get('advance_id')
        amt = _f53_f(data.get('amount_retired'))
        if not adv_id: return err('Advance ID required')
        if amt <= 0: return err('Retirement amount must be positive')
        adv = conn.execute("SELECT amount_ghs, amount_retired FROM staff_advances WHERE id=?", (adv_id,)).fetchone()
        if not adv: return err('Advance not found')
        new_retired = _f53_f(adv['amount_retired']) + amt
        total = _f53_f(adv['amount_ghs'])
        if new_retired > total + 0.01: return err('Retirement exceeds outstanding balance')
        status = 'Fully Retired' if new_retired >= total - 0.01 else 'Partially Retired'
        conn.execute("INSERT INTO staff_advance_retirements(id,advance_id,retirement_date,amount_retired,retirement_ref,receipts_attached,notes,created_by) VALUES(?,?,?,?,?,?,?,?)",
            (_f53_uid(), adv_id, data.get('retirement_date') or _f53_today(), amt, data.get('retirement_ref'),
             1 if data.get('receipts_attached') else 0, data.get('notes'), session.get('username','system')))
        conn.execute("UPDATE staff_advances SET amount_retired=?,amount_outstanding=?,status=?,updated_at=datetime('now') WHERE id=?",
            (new_retired, round(total-new_retired,2), status, adv_id))
        _audit(conn, session, 'RETIRE_ADVANCE', 'staff_advances', adv_id, f"Retired GHS {amt:,.2f}")
        conn.commit()
        return ok({'status': status})
    except Exception as exc:
        return err('Retirement failed: %s' % exc)
    finally:
        conn.close()

def api_staff_advance_report(session):
    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        rows = [dict(r) for r in conn.execute("SELECT * FROM staff_advances").fetchall()]
        outstanding = 0.0; overdue = 0.0; retired_month = 0.0
        by_type = {}
        cutoff = (_f53_dt.now() - _f53_td(days=30)).strftime('%Y-%m-%d')
        month = _f53_dt.now().strftime('%Y-%m')
        for r in rows:
            out = _f53_f(r.get('amount_ghs')) - _f53_f(r.get('amount_retired'))
            if r.get('status') != 'Fully Retired':
                outstanding += out
                if r.get('due_date') and r.get('due_date') < cutoff:
                    overdue += out
            if r.get('status') == 'Fully Retired' and (r.get('updated_at') or '')[:7] == month:
                retired_month += _f53_f(r.get('amount_ghs'))
            t = r.get('advance_type') or 'Other'
            by_type[t] = by_type.get(t, 0) + out
        return ok({'total_outstanding': round(outstanding,2), 'overdue': round(overdue,2),
                   'retired_this_month': round(retired_month,2), 'by_type': by_type})
    finally:
        conn.close()

# ── FEATURE 5: SSNIT / Tier-2 Schedule ──────────────────────────────────────────
def api_ssnit_schedule(session, month=None, year=None):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        if not _f53_table_exists(conn, 'payroll_register'):
            return ok({'rows': [], 'month': month, 'totals': {}})
        q = """SELECT e.full_name, e.ssnit_number, pr.basic_salary, pr.payroll_month,
                      pr.employer_tier1, pr.employer_tier2, pr.employee_tier1, pr.employee_tier2,
                      pr.total_employee_pension FROM payroll_register pr
               LEFT JOIN employees e ON e.id=pr.employee_id WHERE 1=1"""
        args = []
        if month:
            q += " AND pr.payroll_month=?"; args.append(month)
        q += " ORDER BY e.full_name"
        rows = []
        t_basic = t_t1 = t_t2 = t_emp = t_total = 0.0
        for r in conn.execute(q, args).fetchall():
            r = dict(r)
            basic = _f53_f(r.get('basic_salary'))
            t1 = _f53_f(r.get('employer_tier1'))
            t2 = _f53_f(r.get('employer_tier2'))
            emp = _f53_f(r.get('employee_tier1')) or (_f53_f(r.get('total_employee_pension')) - _f53_f(r.get('employee_tier2')))
            total = t1 + t2 + emp
            rows.append({'name': r.get('full_name'), 'ssnit_no': r.get('ssnit_number') or '',
                'basic': basic, 'tier1_employer': t1, 'tier2': t2, 'employee_share': round(emp,2),
                'total': round(total,2)})
            t_basic += basic; t_t1 += t1; t_t2 += t2; t_emp += emp; t_total += total
        return ok({'rows': rows, 'month': month, 'generated_at': _f53_now(),
                   'totals': {'basic': round(t_basic,2), 'tier1_employer': round(t_t1,2),
                              'tier2': round(t_t2,2), 'employee_share': round(t_emp,2), 'total': round(t_total,2)}})
    finally:
        conn.close()

