    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        kind = data.get('kind') or 'po'
        if kind == 'pr':
            pid = data.get('id') or _f53_uid()
            num = data.get('pr_number') or _seq_code(conn, 'purchase_requisitions', 'pr_number', 'PR-', 4)
            conn.execute("""INSERT INTO purchase_requisitions(id,pr_number,project_id,department,requested_by,date_required,purpose,status,total_amount_ghs,created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET department=excluded.department,
                requested_by=excluded.requested_by,date_required=excluded.date_required,purpose=excluded.purpose,
                status=excluded.status,total_amount_ghs=excluded.total_amount_ghs""",
                (pid, num, data.get('project_id'), data.get('department'), data.get('requested_by') or session.get('username'),
                 data.get('date_required'), data.get('purpose'), data.get('status') or 'Draft', _f53_f(data.get('total_amount_ghs')), session.get('username','system')))
            _audit(conn, session, 'SAVE_PR', 'purchase_requisitions', pid, num)
            conn.commit(); return ok({'id': pid, 'pr_number': num})
        pid = data.get('id') or _f53_uid()
        num = data.get('po_number') or _seq_code(conn, 'purchase_orders', 'po_number', 'PO-', 4)
        lines = data.get('lines') or []
        total = sum(_f53_f(l.get('total_ghs')) or (_f53_f(l.get('quantity'))*_f53_f(l.get('unit_price_ghs'))) for l in lines) or _f53_f(data.get('total_amount_ghs'))
        conn.execute("""INSERT INTO purchase_orders(id,po_number,pr_id,vendor_id,vendor_name,project_id,po_date,delivery_date,total_amount_ghs,currency,status,terms,notes,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET vendor_name=excluded.vendor_name,
            project_id=excluded.project_id,po_date=excluded.po_date,delivery_date=excluded.delivery_date,
            total_amount_ghs=excluded.total_amount_ghs,currency=excluded.currency,status=excluded.status,
            terms=excluded.terms,notes=excluded.notes""",
            (pid, num, data.get('pr_id'), data.get('vendor_id'), data.get('vendor_name'), data.get('project_id'),
             data.get('po_date') or _f53_today(), data.get('delivery_date'), total, data.get('currency') or 'GHS',
             data.get('status') or 'Draft', data.get('terms'), data.get('notes'), session.get('username','system')))
        conn.execute("DELETE FROM po_line_items WHERE po_id=?", (pid,))
        for l in lines:
            lt = _f53_f(l.get('total_ghs')) or (_f53_f(l.get('quantity'))*_f53_f(l.get('unit_price_ghs')))
            conn.execute("INSERT INTO po_line_items(id,po_id,description,quantity,unit,unit_price_ghs,total_ghs,coa_code,coa_id) VALUES(?,?,?,?,?,?,?,?,?)",
                (_f53_uid(), pid, l.get('description'), _f53_f(l.get('quantity')), l.get('unit'), _f53_f(l.get('unit_price_ghs')), lt, l.get('coa_code'), l.get('coa_id')))
        _audit(conn, session, 'SAVE_PO', 'purchase_orders', pid, num)
        conn.commit(); return ok({'id': pid, 'po_number': num})
    except Exception as exc:
        return err('Save failed: %s' % exc)
    finally:
        conn.close()

