# ── FEATURE 8: Depreciation ─────────────────────────────────────────────────────
def _f53_dep_rows(conn):
    if not _f53_table_exists(conn, 'asset_register'):
        return []
    cols = _f53_cols(conn, 'asset_register')
    rows = [dict(r) for r in conn.execute("SELECT * FROM asset_register WHERE status='Active'").fetchall()]
    out = []
    for r in rows:
        cost = _f53_f(r.get('acquisition_cost'))
        residual = _f53_f(r.get('residual_value')) if 'residual_value' in cols else 0.0
        life = _f53_f(r.get('useful_life_years'))
        accum = _f53_f(r.get('accumulated_depreciation'))
        monthly = round((cost - residual) / (life * 12), 2) if life > 0 else 0.0
        # Cap at the remaining depreciable amount so an asset never depreciates past
        # (cost - residual). Once fully depreciated this becomes 0 and api_run_depreciation
        # skips it (it continues on monthly_dep <= 0), preventing negative carrying amounts.
        remaining = round(max(0.0, (cost - residual) - accum), 2)
        if monthly > remaining:
            monthly = remaining
        carrying = round(cost - accum, 2)
        out.append({'id': r.get('id'), 'asset_code': r.get('asset_code'), 'asset_name': r.get('asset_name'),
            'cost': cost, 'residual': residual, 'life': life, 'monthly_dep': monthly,
            'accumulated': accum, 'carrying': carrying})
    return out

def api_depreciation_schedule(session):
    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        rows = _f53_dep_rows(conn)
        hist = [dict(r) for r in conn.execute("SELECT * FROM depreciation_runs ORDER BY run_at DESC LIMIT 200").fetchall()]
        return ok({'schedule': rows, 'history': hist, 'total_monthly': round(sum(r['monthly_dep'] for r in rows),2)})
    finally:
        conn.close()

def api_run_depreciation(data, session):
    if not _f53_is_admin(session): return err('Admin access required to post depreciation')
    _f53_migrate(); conn = get_db()
    try:
        month = data.get('month') or _f53_dt.now().strftime('%Y-%m')
        already = conn.execute("SELECT COUNT(*) FROM depreciation_runs WHERE run_month=?", (month,)).fetchone()[0]
        if already and not data.get('force'):
            return err('Depreciation already posted for %s' % month)
        rows = _f53_dep_rows(conn); posted = 0; total = 0.0
        def _dep_coa(code, prefix):
            rr = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (code,)).fetchone()
            if rr: return rr['id']
            rr = conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE ? ORDER BY code LIMIT 1", (prefix + '%',)).fetchone()
            return rr['id'] if rr else None
        dep_exp_id = _dep_coa('61900011', '619')   # Depreciation expense
        acc_dep_id = _dep_coa('11902004', '119')   # Accumulated depreciation contra-asset
        # Validate posting accounts BEFORE mutating asset_register/depreciation_runs, so a
        # run can never be recorded without reaching the GL (which would block re-runs).
        if rows and not (dep_exp_id and acc_dep_id):
            conn.close()
            return err('Depreciation accounts (expense 619 / accumulated depreciation 119) are missing from the chart of accounts; nothing was posted.')
        for r in rows:
            if r['monthly_dep'] <= 0:
                continue
            new_accum = round(r['accumulated'] + r['monthly_dep'], 2)
            conn.execute("UPDATE asset_register SET accumulated_depreciation=?, carrying_amount=? WHERE id=?",
                (new_accum, round(r['cost']-new_accum,2), r['id']))
            conn.execute("INSERT INTO depreciation_runs(id,run_month,asset_id,asset_code,monthly_dep,accumulated_after,run_by) VALUES(?,?,?,?,?,?,?)",
                (_f53_uid(), month, r['id'], r['asset_code'], r['monthly_dep'], new_accum, session.get('username','system')))
            posted += 1; total += r['monthly_dep']
        # Post the depreciation charge to the GENERAL LEDGER so it appears in the
        # Income & Expenditure (expense), the SFP (accumulated depreciation contra-asset)
        # and the Trial Balance. Previously the run only updated asset_register and
        # logged depreciation_runs, so depreciation NEVER reached the financial statements.
        jv_number = None
        total = round(total, 2)
        if total > 0.005:
            desc = f"Monthly depreciation {month} ({posted} assets)"
            ledger_date = (month + '-28') if len(month) == 7 else _f53_dt.now().strftime('%Y-%m-%d')
            jv_id, jv_number = _create_posted_journal(
                conn, session, 'JV', ledger_date, desc, 'DEP-' + month, None, None,
                'asset_depreciation', month,
                [{'coa_id': dep_exp_id, 'debit_amount': total, 'credit_amount': 0, 'description': desc},
                 {'coa_id': acc_dep_id, 'debit_amount': 0, 'credit_amount': total, 'description': desc}])
        _audit(conn, session, 'RUN_DEPRECIATION', 'asset_register', month, f"{posted} assets GHS {total:,.2f} | JV {jv_number or 'n/a'}")
        conn.commit()
        return ok({'posted': posted, 'total': total, 'month': month, 'jv_number': jv_number})
    except Exception as exc:
        return err('Depreciation run failed: %s' % exc)
    finally:
        conn.close()

