def api_save_interunit_transfer(data, session):
    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        tid = data.get('id') or _f53_uid()
        num = data.get('transfer_number') or _seq_code(conn, 'interunit_transfers', 'transfer_number', 'IUT-', 4)
        amt = _f53_f(data.get('amount_ghs'))
        if not data.get('from_unit') or not data.get('to_unit'): return err('From and To units required')
        if amt <= 0: return err('Amount must be positive')
        conn.execute("""INSERT INTO interunit_transfers(id,transfer_number,from_unit,to_unit,transfer_type,amount_ghs,transfer_date,period_code,description,justification,from_coa_id,to_coa_id,status,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET from_unit=excluded.from_unit,
            to_unit=excluded.to_unit,transfer_type=excluded.transfer_type,amount_ghs=excluded.amount_ghs,
            transfer_date=excluded.transfer_date,description=excluded.description,justification=excluded.justification,
            from_coa_id=excluded.from_coa_id,to_coa_id=excluded.to_coa_id,status=excluded.status""",
            (tid, num, data.get('from_unit'), data.get('to_unit'), data.get('transfer_type') or 'Budget', amt,
             data.get('transfer_date') or _f53_today(), data.get('period_code'), data.get('description'),
             data.get('justification'), data.get('from_coa_id'), data.get('to_coa_id'), data.get('status') or 'Draft', session.get('username','system')))
        # UCC unit attribution: persist the sending and receiving org_units.id so the
        # clearing JV posted on approval can stamp each leg to the correct unit.
        try:
            _cols = [r[1] for r in conn.execute("PRAGMA table_info(interunit_transfers)").fetchall()]
            if 'from_unit_id' in _cols and data.get('from_unit_id'):
                conn.execute("UPDATE interunit_transfers SET from_unit_id=? WHERE id=?", (data.get('from_unit_id'), tid))
            if 'to_unit_id' in _cols and data.get('to_unit_id'):
                conn.execute("UPDATE interunit_transfers SET to_unit_id=? WHERE id=?", (data.get('to_unit_id'), tid))
        except Exception:
            pass
        _audit(conn, session, 'SAVE_INTERUNIT', 'interunit_transfers', tid, f"{data.get('from_unit')}->{data.get('to_unit')} GHS {amt:,.2f}")
        conn.commit(); return ok({'id': tid, 'transfer_number': num})
    except Exception as exc:
        return err('Save failed: %s' % exc)
    finally:
        conn.close()

def api_approve_interunit_transfer(data, session):
    if not _f53_is_admin(session): return err('Admin access required')
    _f53_migrate(); conn = get_db()
    try:
        tid = data.get('id')
        if not tid: return err('Transfer ID required')
        row = conn.execute("SELECT * FROM interunit_transfers WHERE id=?", (tid,)).fetchone()
        if not row: return err('Transfer not found')
        t = dict(row)
        if (t.get('status') or '') == 'Approved':
            return err('Transfer is already approved')
        jv_num = None
        # Post a balanced inter-unit clearing JV so the reallocation is reflected per
        # unit in the GL: Dr clearing (receiving unit) / Cr clearing (sending unit).
        # Each GL line is stamped to the respective org unit. Skipped silently when
        # the units are not mapped to org_units ids (legacy free-text rows) or the
        # clearing account is unavailable — approval still succeeds.
        try:
            amt = round(float(t.get('amount_ghs') or 0), 2)
            fu = t.get('from_unit_id'); tu = t.get('to_unit_id')
            if amt > 0 and fu and tu and '_create_posted_journal' in globals():
                clr = _get_coa(conn, ['12300004', '11401003']) if '_get_coa' in globals() else None
                if clr:
                    desc = 'Inter-unit transfer %s: %s -> %s' % (
                        t.get('transfer_number') or '', t.get('from_unit') or '', t.get('to_unit') or '')
                    lines = [
                        {'coa_id': clr['id'], 'debit_amount': amt, 'credit_amount': 0,
                         'description': desc + ' (receiving unit)', 'unit_id': tu},
                        {'coa_id': clr['id'], 'debit_amount': 0, 'credit_amount': amt,
                         'description': desc + ' (sending unit)', 'unit_id': fu},
                    ]
                    _jvid, jv_num = _create_posted_journal(
                        conn, session, 'JV', t.get('transfer_date') or _f53_today(), desc,
                        t.get('transfer_number') or '', None, None, 'interunit_transfers', tid, lines)
        except Exception as _iut_exc:
            try: _audit(conn, session, 'INTERUNIT_JV_WARNING', 'interunit_transfers', tid, str(_iut_exc))
            except Exception: pass
        conn.execute("UPDATE interunit_transfers SET status='Approved',approved_by=?,approved_at=datetime('now') WHERE id=?",
            (session.get('username','system'), tid))
        _audit(conn, session, 'APPROVE_INTERUNIT', 'interunit_transfers', tid, 'Approved' + ((' as ' + jv_num) if jv_num else ''))
        conn.commit(); return ok({'jv_number': jv_num})
    finally:
        conn.close()

