# ── FEATURE 14: Period Close Checklist ──────────────────────────────────────────
def api_period_close_checklist(session, period_code=None):
    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        checks = []
        draft_pv = conn.execute("SELECT COUNT(*) FROM actuals WHERE is_posted=0").fetchone()[0]
        checks.append({'key': 'draft_pvs', 'label': 'Draft / Unposted PVs', 'count': draft_pv,
            'status': 'pass' if draft_pv == 0 else 'warn',
            'detail': 'All payment vouchers posted' if draft_pv == 0 else f'{draft_pv} unposted PVs remain'})
        reco = 0
        if _f53_table_exists(conn, 'bank_reconciliations'):
            reco = conn.execute("SELECT COUNT(*) FROM bank_reconciliations").fetchone()[0]
        checks.append({'key': 'bank_reco', 'label': 'Bank Reconciliation', 'count': reco,
            'status': 'pass' if reco > 0 else 'warn',
            'detail': f'{reco} reconciliation records' if reco else 'No bank reconciliation recorded'})
        dep = conn.execute("SELECT COUNT(*) FROM depreciation_runs WHERE run_month=?", (period_code or _f53_dt.now().strftime('%Y-%m'),)).fetchone()[0]
        checks.append({'key': 'depreciation', 'label': 'Depreciation Posted', 'count': dep,
            'status': 'pass' if dep > 0 else 'warn',
            'detail': 'Depreciation posted for period' if dep else 'Depreciation not yet posted'})
        jv_unposted = 0
        if _f53_table_exists(conn, 'journal_vouchers'):
            try:
                jv_unposted = conn.execute("SELECT COUNT(*) FROM journal_vouchers WHERE status NOT IN ('Posted','Approved')").fetchone()[0]
            except Exception:
                jv_unposted = 0
        checks.append({'key': 'jvs', 'label': 'Journal Vouchers Posted', 'count': jv_unposted,
            'status': 'pass' if jv_unposted == 0 else 'warn',
            'detail': 'All JVs posted' if jv_unposted == 0 else f'{jv_unposted} draft JVs'})
        signoffs = [dict(r) for r in conn.execute("SELECT * FROM period_close_signoffs ORDER BY signed_at DESC LIMIT 50").fetchall()]
        all_pass = all(c['status'] == 'pass' for c in checks)
        return ok({'checks': checks, 'all_pass': all_pass, 'signoffs': signoffs,
                   'period_code': period_code or _f53_dt.now().strftime('%Y-%m')})
    finally:
        conn.close()

