def api_bulk_approve(data, session):
    if not _f53_is_admin(session): return err('Admin access required')
    items = data.get('items') or []
    if not items: return err('No items provided')
    _f53_migrate(); conn = get_db()
    approved = 0
    try:
        for item in items:
            iid = item.get('id'); itype = item.get('type') or ''
            try:
                if 'Actual' in itype or 'PV' in itype:
                    conn.execute("UPDATE actuals SET is_posted=1, approved_by=?, approved_at=datetime('now') WHERE id=?",
                        (session.get('username','system'), iid))
                elif 'Commitment' in itype:
                    conn.execute("UPDATE commitments SET status='Approved', approved_by=? WHERE id=?",
                        (session.get('username'), iid))
                elif 'Purchase Order' in itype:
                    conn.execute("UPDATE purchase_orders SET status='Approved', approved_by=? WHERE id=?",
                        (session.get('username'), iid))
                elif 'Staff Advance' in itype:
                    conn.execute("UPDATE staff_advances SET status='Approved' WHERE id=?", (iid,))
                elif 'Interunit' in itype:
                    conn.execute("UPDATE interunit_transfers SET status='Approved', approved_by=? WHERE id=?",
                        (session.get('username'), iid))
                approved += 1
            except Exception:
                pass
        conn.commit()
        _audit(conn, session, 'BULK_APPROVE', 'bulk_approve', '', f'Bulk approved {approved} items')
        return ok({'approved': approved})
    finally:
        conn.close()

# ── FEATURE 12: Advanced Query Filters ───────────────────────────────────────────
def api_advanced_query(module, session, date_from=None, date_to=None,
                        project_code=None, category=None, min_amount=None):
    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        filters, params = [], []
        def _add(cond, val):
            if val: filters.append(cond); params.append(val)
        if date_from: _add("date_col >= ?", date_from)
        if date_to:   _add("date_col <= ?", date_to)
        min_a = float(min_amount or 0)
        rows = []
        if module == 'actuals':
            q = "SELECT actual_code as ref, description, amount, payment_date as date, project_code, category, is_posted FROM actuals WHERE 1=1"
            p = []
            if date_from: q += " AND payment_date >= ?"; p.append(date_from)
            if date_to:   q += " AND payment_date <= ?"; p.append(date_to)
            if project_code: q += " AND project_code LIKE ?"; p.append('%'+project_code+'%')
            if category: q += " AND category LIKE ?"; p.append('%'+category+'%')
            if min_a: q += " AND amount >= ?"; p.append(min_a)
            q += " ORDER BY payment_date DESC LIMIT 500"
            rows = [dict(r) for r in conn.execute(q, p).fetchall()]
        elif module == 'commitments':
            q = "SELECT commitment_code as ref, description, amount, commitment_date as date, project_code, status FROM commitments WHERE 1=1"
            p = []
            if date_from: q += " AND commitment_date >= ?"; p.append(date_from)
            if date_to:   q += " AND commitment_date <= ?"; p.append(date_to)
            if project_code: q += " AND project_code LIKE ?"; p.append('%'+project_code+'%')
            if min_a: q += " AND amount >= ?"; p.append(min_a)
            q += " ORDER BY commitment_date DESC LIMIT 500"
            rows = [dict(r) for r in conn.execute(q, p).fetchall()]
        elif module == 'receipts':
            try:
                q = "SELECT receipt_number as ref, description, amount_ghs as amount, receipt_date as date, project_code, category FROM receipts WHERE 1=1"
                p = []
                if date_from: q += " AND receipt_date >= ?"; p.append(date_from)
                if date_to:   q += " AND receipt_date <= ?"; p.append(date_to)
                if project_code: q += " AND project_code LIKE ?"; p.append('%'+project_code+'%')
                if min_a: q += " AND amount_ghs >= ?"; p.append(min_a)
                q += " ORDER BY receipt_date DESC LIMIT 500"
                rows = [dict(r) for r in conn.execute(q, p).fetchall()]
            except Exception as _se:
                import sys as _sx; print('advanced_query warning: %s'%_se,file=_sx.stderr)
                rows = []
        elif module == 'purchase-orders':
            try:
                q = "SELECT po_number as ref, description, total_amount as amount, po_date as date, vendor_name, status FROM purchase_orders WHERE 1=1"
                p = []
                if date_from: q += " AND po_date >= ?"; p.append(date_from)
                if date_to:   q += " AND po_date <= ?"; p.append(date_to)
                if min_a: q += " AND total_amount >= ?"; p.append(min_a)
                q += " ORDER BY po_date DESC LIMIT 500"
                rows = [dict(r) for r in conn.execute(q, p).fetchall()]
            except Exception as _se:
                import sys as _sx; print('advanced_query warning: %s'%_se,file=_sx.stderr)
                rows = []
        elif module == 'staff-advances':
            try:
                q = "SELECT advance_number as ref, purpose as description, amount_ghs as amount, advance_date as date, employee_name, status FROM staff_advances WHERE 1=1"
                p = []
                if date_from: q += " AND advance_date >= ?"; p.append(date_from)
                if date_to:   q += " AND advance_date <= ?"; p.append(date_to)
                if min_a: q += " AND amount_ghs >= ?"; p.append(min_a)
                q += " ORDER BY advance_date DESC LIMIT 500"
                rows = [dict(r) for r in conn.execute(q, p).fetchall()]
            except Exception as _se:
                import sys as _sx; print('advanced_query warning: %s'%_se,file=_sx.stderr)
                rows = []
        total = sum(float(r.get('amount') or 0) for r in rows)
        return ok({'rows': rows, 'count': len(rows), 'total_amount': round(total, 2), 'module': module})
    finally:
        conn.close()

