def api_send_test_notification(data, session):
    if not session: return err('Not authenticated')
    email = data.get('email','').strip()
    if not email: return err('No recipient email provided')
    # Attempt SMTP send (best-effort; silently fail if not configured)
    try:
        import smtplib, ssl as _ssl
        from email.mime.text import MIMEText
        _f53_migrate(); conn = get_db()
        try:
            cfg = {r[0]: r[1] for r in conn.execute("SELECT key, value FROM notification_settings").fetchall()}
        finally:
            conn.close()
        host = cfg.get('smtp_host','')
        if not host: return err('SMTP not configured. Save SMTP settings first.')
        port = int(cfg.get('smtp_port','587') or 587)
        user = cfg.get('smtp_username','')
        pwd  = cfg.get('smtp_password','')
        msg  = MIMEText('This is a test notification from UCC-FMS. Your email notifications are configured correctly.')
        msg['Subject'] = 'UCC-FMS — Test Notification'
        msg['From'] = user or 'noreply@ucc.edu.gh'
        msg['To'] = email
        ctx = _ssl.create_default_context()
        with smtplib.SMTP(host, port) as smtp:
            smtp.ehlo(); smtp.starttls(context=ctx); smtp.ehlo()
            if user and pwd: smtp.login(user, pwd)
            smtp.sendmail(msg['From'], [email], msg.as_string())
        return ok({'message': f'Test email sent to {email}'})
    except Exception as exc:
        return err(f'SMTP error: {exc}')


