def _v54_migrate():
    """Create all v5.4 tables idempotently."""
    conn = get_db()
    try:
        conn.executescript("""
            CREATE TABLE IF NOT EXISTS petty_cash (
                id TEXT PRIMARY KEY,
                entry_date TEXT NOT NULL,
                description TEXT NOT NULL,
                amount REAL NOT NULL,
                entry_type TEXT DEFAULT 'Out',
                category TEXT DEFAULT '',
                receipt_ref TEXT DEFAULT '',
                balance_after REAL DEFAULT 0,
                created_by TEXT DEFAULT '',
                created_at TEXT DEFAULT(datetime('now'))
            );
            CREATE TABLE IF NOT EXISTS recurring_commitments (
                id TEXT PRIMARY KEY,
                description TEXT NOT NULL,
                amount REAL NOT NULL,
                project_code TEXT DEFAULT '',
                category TEXT DEFAULT '',
                budget_line_id TEXT DEFAULT '',
                frequency TEXT DEFAULT 'Monthly',
                day_of_month INTEGER DEFAULT 1,
                next_run TEXT,
                last_run TEXT,
                is_active INTEGER DEFAULT 1,
                created_by TEXT DEFAULT '',
                created_at TEXT DEFAULT(datetime('now'))
            );
            CREATE TABLE IF NOT EXISTS vote_on_account (
                id TEXT PRIMARY KEY,
                fiscal_year TEXT NOT NULL,
                monthly_allowance REAL NOT NULL,
                basis_year TEXT DEFAULT '',
                approved_by TEXT DEFAULT '',
                approved_at TEXT,
                notes TEXT DEFAULT '',
                created_at TEXT DEFAULT(datetime('now'))
            );
            CREATE TABLE IF NOT EXISTS approval_chain (
                id TEXT PRIMARY KEY,
                document_type TEXT NOT NULL,
                document_id TEXT NOT NULL,
                level INTEGER DEFAULT 1,
                required_role TEXT DEFAULT 'Admin',
                assigned_to TEXT DEFAULT '',
                status TEXT DEFAULT 'Pending',
                actioned_at TEXT,
                remarks TEXT DEFAULT '',
                created_at TEXT DEFAULT(datetime('now'))
            );
        """)
        conn.commit()
    except Exception as exc:
        print('v5.4 migrate warning:', exc)
    finally:
        conn.close()

# ── Trial Balance ────────────────────────────────────────────────────────────
def api_trial_balance(session, period_from=None, period_to=None):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        # Use period defaults
        from datetime import datetime as _dt
        if not period_from: period_from = _dt.now().strftime('%Y-01-01')
        if not period_to:   period_to   = _dt.now().strftime('%Y-%m-%d')

        # Build trial balance from COA + actuals (debits) + receipts (credits)
        accounts = []
        try:
            coa_rows = conn.execute(
                "SELECT id, code, name, account_type, normal_balance FROM chart_of_accounts ORDER BY code"
            ).fetchall()
        except Exception:
            coa_rows = []

        for coa in coa_rows:
            coa_id = coa[0]; code = coa[1]; name = coa[2]
            acc_type = coa[3] or ''; normal_bal = coa[4] or 'Debit'

            # Debits from actuals
            dr = 0.0
            try:
                row = conn.execute(
                    "SELECT COALESCE(SUM(amount),0) FROM actuals WHERE coa_id=? AND payment_date BETWEEN ? AND ? AND is_posted=1",
                    (coa_id, period_from, period_to)
                ).fetchone()
                dr = float(row[0] or 0)
            except Exception:
                try:
                    row = conn.execute(
                        "SELECT COALESCE(SUM(amount),0) FROM actuals WHERE payment_date BETWEEN ? AND ? AND category=? AND is_posted=1",
                        (period_from, period_to, name)
                    ).fetchone()
                    dr = float(row[0] or 0)
                except Exception:
                    pass

            # Credits from receipts
            cr = 0.0
            try:
                row = conn.execute(
                    "SELECT COALESCE(SUM(amount_ghs),0) FROM receipts WHERE coa_id=? AND receipt_date BETWEEN ? AND ?",
                    (coa_id, period_from, period_to)
                ).fetchone()
                cr = float(row[0] or 0)
            except Exception:
                pass

            balance = dr - cr if normal_bal == 'Debit' else cr - dr
            if dr != 0 or cr != 0 or balance != 0:
                accounts.append({
                    'code': code, 'name': name, 'account_type': acc_type,
                    'debit': round(dr, 2), 'credit': round(cr, 2), 'balance': round(balance, 2)
                })

        total_dr = round(sum(a['debit'] for a in accounts), 2)
        total_cr = round(sum(a['credit'] for a in accounts), 2)
        balanced = abs(total_dr - total_cr) < 0.02

        return ok({
            'accounts': accounts, 'total_debit': total_dr, 'total_credit': total_cr,
            'balanced': balanced, 'period_from': period_from, 'period_to': period_to
        })
    finally:
        conn.close()

# ── Budget Variance Report ───────────────────────────────────────────────────
def api_budget_variance(session, period_from=None, period_to=None, project_id=None):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        from datetime import datetime as _dt
        if not period_from: period_from = _dt.now().strftime('%Y-01-01')
        if not period_to:   period_to   = _dt.now().strftime('%Y-%m-%d')

        proj_filter = ""; proj_params = []
        if project_id: proj_filter = " AND b.project_id=?"; proj_params = [project_id]

        rows = conn.execute(
            f"""SELECT b.id, b.budget_code, b.project_id, b.budget_ghs as budget,
                COALESCE(SUM(CASE WHEN a.expense_date BETWEEN ? AND ? THEN a.amount_ghs ELSE 0 END),0) as spent,
                COALESCE(SUM(CASE WHEN c.commit_date BETWEEN ? AND ? THEN c.amount_ghs ELSE 0 END),0) as committed
               FROM budgets b
               LEFT JOIN actuals a ON a.budget_id=b.id
               LEFT JOIN commitments c ON c.budget_id=b.id AND c.status NOT IN ('Cancelled','Rejected')
               WHERE 1=1 {proj_filter}
               GROUP BY b.id ORDER BY b.project_id, b.budget_code""",
            [period_from, period_to, period_from, period_to] + proj_params
        ).fetchall()

        lines = []
        for r in rows:
            budget = float(r[3] or 0); spent = float(r[4] or 0); committed = float(r[5] or 0)
            variance = budget - spent - committed
            pct = round((spent + committed) / budget * 100, 1) if budget else 0
            lines.append({
                'description': r[1], 'project_id': r[2], 'budget_code': r[1],
                'budget': round(budget, 2), 'spent': round(spent, 2),
                'committed': round(committed, 2), 'variance': round(variance, 2),
                'pct_used': pct,
                'status': 'over' if variance < 0 else ('warn' if pct >= 80 else 'ok')
            })

        total_budget = round(sum(l['budget'] for l in lines), 2)
        total_spent  = round(sum(l['spent'] for l in lines), 2)
        total_committed = round(sum(l['committed'] for l in lines), 2)
        total_variance  = round(total_budget - total_spent - total_committed, 2)

        return ok({
            'lines': lines, 'total_budget': total_budget, 'total_spent': total_spent,
            'total_committed': total_committed, 'total_variance': total_variance,
            'period_from': period_from, 'period_to': period_to
        })
    finally:
        conn.close()

def api_ipsas24(session, fy=None):
    """GET /api/ipsas24?fy=YYYY — IPSAS 24 Statement of Comparison of Budget and
    Actual Amounts (expenditure appropriations).

    Original budget = current approved amount minus all logged changes
    (budget_revisions; virements log both legs from 2026-06 onward). Final
    budget = current approved budget_ghs. Actual = POSTED payment vouchers in
    the fiscal year charged to each budget line, on the same accrual basis as
    the I&E. Includes unbudgeted posted spend and a reconciliation to total
    general-ledger expenditure (the IPSAS 24.47 comparable-basis reconciliation:
    payroll, depreciation and manual journals post outside the appropriation
    ledger and appear in the reconciliation, not the appropriation lines)."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        from datetime import datetime as _dt
        fy = str(fy or _dt.now().year)[:4]
        d1, d2 = fy + '-01-01', fy + '-12-31'
        have_rev = bool(conn.execute(
            "SELECT 1 FROM sqlite_master WHERE type='table' AND name='budget_revisions'").fetchone())
        rev_sub = ("COALESCE((SELECT SUM(br.change_amount_ghs) FROM budget_revisions br "
                   "WHERE br.budget_id=b.id),0)") if have_rev else "0"
        rows = conn.execute(
            "SELECT b.id, b.budget_code, COALESCE(c.code,'') AS coa_code, "
            "COALESCE(c.account_name, b.budget_code) AS account_name, "
            "COALESCE(p.project_code,'') AS project_code, COALESCE(b.budget_ghs,0) AS final_budget, "
            + rev_sub + " AS revised_by, "
            "COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.budget_id=b.id "
            "AND COALESCE(a.is_posted,0)=1 AND a.expense_date BETWEEN ? AND ?),0) AS actual, "
            "COALESCE((SELECT SUM(MAX(0, cm.amount_ghs - COALESCE((SELECT SUM(ax.amount_ghs) "
            "FROM actuals ax WHERE ax.commitment_id=cm.id AND COALESCE(ax.is_posted,0)=1),0))) "
            "FROM commitments cm WHERE cm.budget_id=b.id "
            "AND COALESCE(cm.status,'') NOT IN ('Cancelled','Fully Paid')),0) AS open_commitments "
            "FROM budgets b LEFT JOIN chart_of_accounts c ON b.coa_id=c.id "
            "LEFT JOIN projects p ON b.project_id=p.id "
            "WHERE COALESCE(b.is_deleted,0)=0 "
            # Expenditure appropriations only — revenue (4xxx) budget lines are reported
            # in the dedicated revenue comparison below (IPSAS 24.14), not as spend.
            "AND NOT (COALESCE(c.code,'') LIKE '4%' OR c.category='Revenue' "
            "         OR c.account_type IN ('Income','Revenue')) "
            "ORDER BY coa_code, b.budget_code",
            (d1, d2)).fetchall()
        lines, agg = [], {}
        for r in rows:
            final = round(float(r['final_budget'] or 0), 2)
            orig = round(final - float(r['revised_by'] or 0), 2)
            act = round(float(r['actual'] or 0), 2)
            com = round(float(r['open_commitments'] or 0), 2)
            var = round(final - act, 2)
            pct = round(act / final * 100, 1) if final else 0.0
            lines.append({'budget_code': r['budget_code'], 'coa_code': r['coa_code'],
                          'account_name': r['account_name'], 'project_code': r['project_code'],
                          'original': orig, 'final': final, 'actual': act,
                          'open_commitments': com, 'variance': var, 'utilisation_pct': pct})
            k = (r['coa_code'], r['account_name'])
            a = agg.setdefault(k, {'coa_code': k[0], 'account_name': k[1],
                                   'original': 0.0, 'final': 0.0, 'actual': 0.0,
                                   'open_commitments': 0.0})
            a['original'] += orig; a['final'] += final
            a['actual'] += act; a['open_commitments'] += com
        by_account = []
        for a in agg.values():
            a = {k2: (round(v, 2) if isinstance(v, float) else v) for k2, v in a.items()}
            a['variance'] = round(a['final'] - a['actual'], 2)
            a['utilisation_pct'] = round(a['actual'] / a['final'] * 100, 1) if a['final'] else 0.0
            by_account.append(a)
        by_account.sort(key=lambda x: x['coa_code'] or 'zzz')
        unb = conn.execute(
            "SELECT COALESCE(SUM(amount_ghs),0), COUNT(*) FROM actuals "
            "WHERE (budget_id IS NULL OR budget_id='') AND COALESCE(is_posted,0)=1 "
            "AND expense_date BETWEEN ? AND ?", (d1, d2)).fetchone()
        unbudgeted = {'amount': round(float(unb[0] or 0), 2), 'count': int(unb[1] or 0)}
        glrow = conn.execute(
            "SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) "
            "FROM general_ledger WHERE coa_code LIKE '6%' AND ledger_date BETWEEN ? AND ?",
            (d1, d2)).fetchone()
        gl_exp = round(float(glrow[0] or 0), 2)
        tot = {'original': round(sum(l['original'] for l in lines), 2),
               'final': round(sum(l['final'] for l in lines), 2),
               'actual': round(sum(l['actual'] for l in lines), 2),
               'open_commitments': round(sum(l['open_commitments'] for l in lines), 2)}
        tot['variance'] = round(tot['final'] - tot['actual'], 2)
        tot['utilisation_pct'] = round(tot['actual'] / tot['final'] * 100, 1) if tot['final'] else 0.0
        recon = {'gl_expenditure': gl_exp, 'budget_linked_actual': tot['actual'],
                 'unbudgeted_actual': unbudgeted['amount'],
                 'other_journal_expenditure': round(gl_exp - tot['actual'] - unbudgeted['amount'], 2)}
        material = [l for l in by_account
                    if l['final'] > 0 and abs(l['variance']) >= max(0.10 * l['final'], 1.0)]

        # ── IPSAS 24.14 — REVENUE estimates vs actual ───────────────────────────
        # The Statement of Comparison of Budget and Actual Amounts must cover revenue
        # estimates as well as expenditure appropriations. Budgeted revenue = approved
        # budget lines whose COA is a revenue account (4xxx); original = final less
        # logged revisions. Actual revenue is taken from the GENERAL LEDGER (4xxx,
        # credits net of debits) on the SAME accrual basis as the I&E statement, so it
        # reconciles to total recognised revenue. Variance is favourable when actual
        # revenue exceeds the final estimate (revenue convention is the mirror of the
        # expenditure convention).
        rev_rows = conn.execute(
            "SELECT b.id, b.budget_code, COALESCE(c.code,'') AS coa_code, "
            "COALESCE(c.account_name, b.budget_code) AS account_name, "
            "COALESCE(p.project_code,'') AS project_code, COALESCE(b.budget_ghs,0) AS final_budget, "
            + rev_sub + " AS revised_by "
            "FROM budgets b LEFT JOIN chart_of_accounts c ON b.coa_id=c.id "
            "LEFT JOIN projects p ON b.project_id=p.id "
            "WHERE COALESCE(b.is_deleted,0)=0 "
            "AND (COALESCE(c.code,'') LIKE '4%' OR c.category='Revenue' "
            "     OR c.account_type IN ('Income','Revenue')) "
            "ORDER BY coa_code, b.budget_code",
            ()).fetchall()
        rev_actual_by_coa = {}
        for r in conn.execute(
                "SELECT COALESCE(coa_code,'') AS code, "
                "COALESCE(SUM(COALESCE(credit_amount,0)-COALESCE(debit_amount,0)),0) AS amt "
                "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                "WHERE (COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '4%' "
                "       OR c.category='Revenue' OR c.account_type IN ('Income','Revenue')) "
                "AND gl.ledger_date BETWEEN ? AND ? GROUP BY code", (d1, d2)).fetchall():
            rev_actual_by_coa[r['code'] or ''] = round(float(r['amt'] or 0), 2)
        rev_lines, rev_agg = [], {}
        for r in rev_rows:
            final = round(float(r['final_budget'] or 0), 2)
            orig = round(final - float(r['revised_by'] or 0), 2)
            act = round(float(rev_actual_by_coa.get(r['coa_code'], 0.0)), 2)
            var = round(act - final, 2)  # favourable when actual revenue > estimate
            pct = round(act / final * 100, 1) if final else 0.0
            rev_lines.append({'budget_code': r['budget_code'], 'coa_code': r['coa_code'],
                              'account_name': r['account_name'], 'project_code': r['project_code'],
                              'original': orig, 'final': final, 'actual': act,
                              'variance': var, 'realisation_pct': pct})
            k = (r['coa_code'], r['account_name'])
            a = rev_agg.setdefault(k, {'coa_code': k[0], 'account_name': k[1],
                                       'original': 0.0, 'final': 0.0, 'actual': 0.0})
            a['original'] += orig; a['final'] += final; a['actual'] += act
        rev_by_account = []
        for a in rev_agg.values():
            a = {k2: (round(v, 2) if isinstance(v, float) else v) for k2, v in a.items()}
            a['variance'] = round(a['actual'] - a['final'], 2)
            a['realisation_pct'] = round(a['actual'] / a['final'] * 100, 1) if a['final'] else 0.0
            rev_by_account.append(a)
        rev_by_account.sort(key=lambda x: x['coa_code'] or 'zzz')
        # Total actual revenue per the GL (whether or not it had a budget line) for the
        # reconciliation — mirrors the expenditure reconciliation.
        gl_rev_total = round(sum(rev_actual_by_coa.values()), 2)
        rev_budgeted_coas = {r['coa_code'] for r in rev_rows if r['coa_code']}
        rev_unbudgeted = round(sum(v for k, v in rev_actual_by_coa.items()
                                   if k not in rev_budgeted_coas), 2)
        rev_tot = {'original': round(sum(l['original'] for l in rev_lines), 2),
                   'final': round(sum(l['final'] for l in rev_lines), 2),
                   'actual': round(sum(l['actual'] for l in rev_lines), 2)}
        rev_tot['variance'] = round(rev_tot['actual'] - rev_tot['final'], 2)
        rev_tot['realisation_pct'] = round(rev_tot['actual'] / rev_tot['final'] * 100, 1) if rev_tot['final'] else 0.0
        rev_recon = {'gl_revenue': gl_rev_total,
                     'budget_linked_actual': rev_tot['actual'],
                     'unbudgeted_actual': rev_unbudgeted,
                     'other_revenue': round(gl_rev_total - rev_tot['actual'] - rev_unbudgeted, 2)}
        rev_material = [l for l in rev_by_account
                        if l['final'] > 0 and abs(l['variance']) >= max(0.10 * l['final'], 1.0)]
        revenue = {'lines': rev_lines, 'by_account': rev_by_account, 'totals': rev_tot,
                   'gl_reconciliation': rev_recon, 'material_variances': rev_material,
                   'basis': 'Accrual — revenue estimates per approved budget line vs '
                            'general-ledger revenue recognised (IPSAS 24.14)'}

        return ok({'fy': fy, 'date_from': d1, 'date_to': d2, 'lines': lines,
                   'by_account': by_account, 'totals': tot, 'unbudgeted': unbudgeted,
                   'gl_reconciliation': recon, 'material_variances': material,
                   'revisions_tracked': have_rev,
                   'revenue': revenue,
                   'expenditure': {'lines': lines, 'by_account': by_account, 'totals': tot,
                                   'gl_reconciliation': recon, 'material_variances': material},
                   'basis': 'Accrual — posted payment vouchers per approved budget line; '
                            'reconciled to general-ledger expenditure (IPSAS 24.47)'})
    finally:
        conn.close()


# ── Audit Log Viewer ────────────────────────────────────────────────────────
def _audit_union_sql(conn):
    """Unified audit trail across audit_log + jv_audit + payroll_audit, normalised to
    (timestamp, username, user_role, action, module, record_id, details). Only includes
    tables that actually exist so a missing table never blanks the whole view."""
    have = lambda t: conn.execute(
        "SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (t,)).fetchone()
    parts = []
    if have('audit_log'):
        parts.append("SELECT timestamp, username, user_role, action, module, record_id, details FROM audit_log")
    if have('jv_audit'):
        parts.append("SELECT timestamp, username, user_role, action, 'Journal Voucher' AS module, "
                     "jv_number AS record_id, COALESCE(details,'') || CASE WHEN COALESCE(old_status,'')<>'' "
                     "OR COALESCE(new_status,'')<>'' THEN ' ['||COALESCE(old_status,'?')||' -> '||"
                     "COALESCE(new_status,'?')||']' ELSE '' END AS details FROM jv_audit")
    if have('payroll_audit'):
        parts.append("SELECT timestamp, username, NULL AS user_role, action, 'Payroll' AS module, "
                     "COALESCE(payroll_month,'') AS record_id, details FROM payroll_audit")
    return " UNION ALL ".join(parts) if parts else (
        "SELECT NULL AS timestamp, NULL AS username, NULL AS user_role, NULL AS action, "
        "NULL AS module, NULL AS record_id, NULL AS details WHERE 0")

def _audit_filter_clause(filter_action=None, filter_user=None, date_from=None, date_to=None):
    wheres = ['1=1']; params = []
    if filter_action: wheres.append('action LIKE ?'); params.append('%' + filter_action + '%')
    if filter_user:   wheres.append('username LIKE ?'); params.append('%' + filter_user + '%')
    if date_from:     wheres.append('timestamp >= ?'); params.append(date_from)
    if date_to:       wheres.append('timestamp <= ?'); params.append(date_to + ' 23:59:59')
    return ' AND '.join(wheres), params

def api_audit_log_viewer(session, page=None, filter_action=None, filter_user=None, date_from=None, date_to=None):
    if not (_f53_is_admin(session) or (session and session.get('role') == 'Auditor')): return err('Admin or Auditor access required')
    conn = get_db()
    try:
        page = int(page or 1); per_page = 50
        offset = (page - 1) * per_page
        where, params = _audit_filter_clause(filter_action, filter_user, date_from, date_to)
        base = "SELECT * FROM (" + _audit_union_sql(conn) + ") WHERE " + where
        try:
            total = conn.execute("SELECT COUNT(*) FROM (" + base + ")", params).fetchone()[0]
            rows = [dict(r) for r in conn.execute(
                base + " ORDER BY timestamp DESC LIMIT ? OFFSET ?",
                params + [per_page, offset]
            ).fetchall()]
        except Exception:
            total = 0; rows = []

        return ok({'rows': rows, 'total': total, 'page': page, 'pages': max(1, -(-total // per_page))})
    finally:
        conn.close()

# ── Petty Cash ──────────────────────────────────────────────────────────────
def api_petty_cash(session):
    if not session: return err('Not authenticated')
    _v54_migrate(); conn = get_db()
    try:
        rows = [dict(r) for r in conn.execute(
            "SELECT * FROM petty_cash ORDER BY entry_date DESC, created_at DESC LIMIT 300"
        ).fetchall()]
        # Running balance
        bal = 0.0
        rows_rev = list(reversed(rows))
        for r in rows_rev:
            if r.get('entry_type') == 'In':
                bal += float(r.get('amount') or 0)
            else:
                bal -= float(r.get('amount') or 0)
            r['running_balance'] = round(bal, 2)
        rows = list(reversed(rows_rev))
        current_balance = rows[0]['running_balance'] if rows else 0.0
        return ok({'entries': rows, 'current_balance': round(current_balance, 2)})
    finally:
        conn.close()

def api_save_petty_cash(data, session):
    if not session: return err('Not authenticated')
    _v54_migrate(); conn = get_db()
    try:
        eid = data.get('id') or _f53_uid()
        entry_type = data.get('entry_type') or 'Out'
        amt = _f53_f(data.get('amount'))
        if amt <= 0: return err('Amount must be greater than zero')
        conn.execute("""INSERT INTO petty_cash(id,entry_date,description,amount,entry_type,category,receipt_ref,created_by)
            VALUES(?,?,?,?,?,?,?,?)
            ON CONFLICT(id) DO UPDATE SET description=excluded.description,
            amount=excluded.amount,entry_type=excluded.entry_type,
            category=excluded.category,receipt_ref=excluded.receipt_ref""",
            (eid, data.get('entry_date') or _f53_today(), data.get('description','').strip(),
             amt, entry_type, data.get('category',''), data.get('receipt_ref',''),
             session.get('username','system')))
        conn.commit()
        _audit(conn, session, 'PETTY_CASH_SAVE', 'petty_cash', eid, f'{entry_type} {amt}')
        return ok({'id': eid})
    finally:
        conn.close()

# ── Recurring Commitments ────────────────────────────────────────────────────
def api_recurring_commitments(session):
    if not session: return err('Not authenticated')
    _v54_migrate(); conn = get_db()
    try:
        rows = [dict(r) for r in conn.execute(
            "SELECT * FROM recurring_commitments ORDER BY description"
        ).fetchall()]
        return ok({'templates': rows})
    finally:
        conn.close()

def api_save_recurring(data, session):
    if not session: return err('Not authenticated')
    _v54_migrate(); conn = get_db()
    try:
        rid = data.get('id') or _f53_uid()
        from datetime import datetime as _dt
        next_run = data.get('next_run') or _dt.now().strftime('%Y-%m-01')
        conn.execute("""INSERT INTO recurring_commitments(id,description,amount,project_code,category,budget_line_id,frequency,day_of_month,next_run,is_active,created_by)
            VALUES(?,?,?,?,?,?,?,?,?,1,?)
            ON CONFLICT(id) DO UPDATE SET description=excluded.description,
            amount=excluded.amount,project_code=excluded.project_code,
            category=excluded.category,frequency=excluded.frequency,
            day_of_month=excluded.day_of_month,next_run=excluded.next_run,
            is_active=excluded.is_active""",
            (rid, data.get('description','').strip(), _f53_f(data.get('amount')),
             data.get('project_code',''), data.get('category',''), data.get('budget_line_id',''),
             data.get('frequency','Monthly'), int(data.get('day_of_month') or 1), next_run,
             session.get('username','system')))
        conn.commit()
        _audit(conn, session, 'RECURRING_SAVE', 'recurring_commitments', rid, data.get('description',''))
        return ok({'id': rid})
    finally:
        conn.close()

def api_trigger_recurring(session):
    """Generate commitment entries for all due recurring templates."""
    if not _f53_is_admin(session): return err('Admin access required')
    _v54_migrate(); conn = get_db()
    try:
        today = _f53_today()
        due = [dict(r) for r in conn.execute(
            "SELECT * FROM recurring_commitments WHERE is_active=1 AND next_run <= ?", (today,)
        ).fetchall()]
        created = 0
        for tmpl in due:
            cid = _f53_uid()
            try:
                conn.execute("""INSERT INTO commitments(id,description,amount,project_code,category,
                    budget_line_id,commitment_date,status,created_by,created_at)
                    VALUES(?,?,?,?,?,?,?,?,?,datetime('now'))""",
                    (cid, tmpl['description'], tmpl['amount'], tmpl.get('project_code',''),
                     tmpl.get('category',''), tmpl.get('budget_line_id',''), today, 'Draft',
                     session.get('username','system')))
                # Advance next_run by one month
                from datetime import datetime as _dt, timedelta as _td
                nr = _dt.strptime(tmpl['next_run'], '%Y-%m-%d')
                if tmpl.get('frequency') == 'Monthly':
                    month = nr.month + 1; year = nr.year
                    if month > 12: month = 1; year += 1
                    nr = nr.replace(year=year, month=month)
                elif tmpl.get('frequency') == 'Quarterly':
                    month = nr.month + 3; year = nr.year
                    if month > 12: month = month - 12; year += 1
                    nr = nr.replace(year=year, month=month)
                conn.execute("UPDATE recurring_commitments SET last_run=?, next_run=? WHERE id=?",
                    (today, nr.strftime('%Y-%m-%d'), tmpl['id']))
                created += 1
            except Exception as exc:
                print('recurring trigger warning:', exc)
        conn.commit()
        return ok({'created': created, 'processed': len(due)})
    finally:
        conn.close()

# ── WHT Certificate ──────────────────────────────────────────────────────────
def api_wht_certificate(session, actual_id=None):
    if not session: return err('Not authenticated')
    if not actual_id: return err('actual_id required')
    conn = get_db()
    try:
        row = conn.execute("SELECT * FROM actuals WHERE id=?", (actual_id,)).fetchone()
        if not row: return err('Payment voucher not found')
        a = dict(row)
        # Get WHT details
        wht_rate = _f53_f(a.get('wht_rate') or a.get('withholding_rate') or 0)
        gross = _f53_f(a.get('gross_amount') or a.get('amount') or 0)
        wht_amt = _f53_f(a.get('wht_amount') or (gross * wht_rate / 100))
        net = gross - wht_amt
        return ok({
            'actual_code': a.get('actual_code') or a.get('id','')[:8],
            'payee': a.get('payee') or a.get('vendor_name') or '',
            'payee_tin': a.get('payee_tin') or a.get('tin') or '',
            'description': a.get('description') or '',
            'payment_date': (a.get('payment_date') or '')[:10],
            'gross_amount': round(gross, 2),
            'wht_rate': wht_rate,
            'wht_amount': round(wht_amt, 2),
            'net_amount': round(net, 2),
            'certificate_no': 'WHT-' + (a.get('actual_code') or a.get('id','')[:8]),
            'period': (a.get('payment_date') or '')[:7]
        })
    finally:
        conn.close()

# ── SSNIT Remittance Advice ──────────────────────────────────────────────────
def api_ssnit_remittance_advice(session, month=None, year=None):
    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        from datetime import datetime as _dt
        month = month or _dt.now().strftime('%m')
        year  = year  or _dt.now().strftime('%Y')
        period = f"{year}-{month.zfill(2)}"

        # Derive directly from the posted payroll register (there is no separate
        # ssnit_contributions table). Tier-1 = SSNIT (employer 13% + employee 5.5%);
        # Tier-2 = approved private trustee (employer 5%).
        rows = []
        try:
            raw = [dict(r) for r in conn.execute(
                "SELECT e.full_name AS employee_name, e.ssnit_number, pr.basic_salary, "
                "pr.pensionable_emoluments, pr.employer_tier1, pr.employer_tier2, "
                "pr.employee_tier1, pr.employee_tier2, pr.total_employee_pension "
                "FROM payroll_register pr LEFT JOIN employees e ON e.id=pr.employee_id "
                "WHERE pr.payroll_month=? ORDER BY e.full_name", (period,)
            ).fetchall()]
            for r in raw:
                t1e = _f53_f(r.get('employee_tier1', 0)); t1r = _f53_f(r.get('employer_tier1', 0))
                t2  = _f53_f(r.get('employer_tier2', 0)) + _f53_f(r.get('employee_tier2', 0))
                r['tier1_employee'] = round(t1e, 2); r['tier1_employer'] = round(t1r, 2)
                r['tier2'] = round(t2, 2); r['total'] = round(t1e + t1r + t2, 2)
                rows.append(r)
        except Exception as _se:
            import sys as _sx; print('ssnit_remittance query warning: %s' % _se, file=_sx.stderr); rows = []

        total_t1 = round(sum(_f53_f(r.get('tier1_employee',0)) + _f53_f(r.get('tier1_employer',0)) for r in rows), 2)
        total_t2 = round(sum(_f53_f(r.get('tier2',0)) for r in rows), 2)
        total    = round(total_t1 + total_t2, 2)
        ref_no   = f"SSNIT-{period}-{str(len(rows)).zfill(3)}"

        return ok({
            'period': period, 'month': month, 'year': year,
            'employees': rows, 'count': len(rows),
            'total_tier1': total_t1, 'total_tier2': total_t2, 'total': total,
            'reference_no': ref_no
        })
    finally:
        conn.close()

# ── Notification Summary (bell badge) ────────────────────────────────────────
def api_notification_summary(session):
    if not session: return err('Not authenticated')
    _f53_migrate(); conn = get_db()
    try:
        from datetime import datetime as _dt, timedelta as _td
        today = _dt.now()
        alerts = []

        # Contracts expiring in 30 days
        try:
            soon = (today + _td(days=30)).strftime('%Y-%m-%d')
            n = conn.execute(
                "SELECT COUNT(*) FROM contracts WHERE end_date BETWEEN ? AND ? AND status='Active'",
                (today.strftime('%Y-%m-%d'), soon)
            ).fetchone()[0]
            if n: alerts.append({'type': 'contract_expiry', 'count': n, 'label': f'{n} contract(s) expiring in 30 days', 'icon': '📄', 'view': 'procurement'})
        except Exception: pass

        # Staff advances unretired > 30 days
        try:
            threshold = (today - _td(days=30)).strftime('%Y-%m-%d')
            n = conn.execute(
                "SELECT COUNT(*) FROM staff_advances WHERE status NOT IN ('Retired','Cancelled') AND advance_date < ?",
                (threshold,)
            ).fetchone()[0]
            if n: alerts.append({'type': 'advance_overdue', 'count': n, 'label': f'{n} advance(s) unretired > 30 days', 'icon': '💵', 'view': 'hr-payroll'})
        except Exception: pass

        # POs/Actuals pending approval
        try:
            n = conn.execute("SELECT COUNT(*) FROM actuals WHERE is_posted=0").fetchone()[0]
            if n: alerts.append({'type': 'approval_pending', 'count': n, 'label': f'{n} payment voucher(s) pending posting', 'icon': '✅', 'view': 'bulk-approve'})
        except Exception: pass

        # Budget lines at or above 80%
        try:
            over = conn.execute("""
                SELECT COUNT(*) FROM (
                    SELECT b.id,
                        COALESCE(SUM(a.amount_ghs),0) as spent,
                        COALESCE(b.budget_ghs, b.budget_fcy, 0) as budget
                    FROM budgets b
                    LEFT JOIN actuals a ON a.budget_id=b.id AND a.is_posted=1
                    GROUP BY b.id
                    HAVING COALESCE(b.budget_ghs, b.budget_fcy, 0) > 0
                       AND (COALESCE(SUM(a.amount_ghs),0) / COALESCE(b.budget_ghs, b.budget_fcy, 0)) >= 0.8
                )
            """).fetchone()[0]
            if over: alerts.append({'type': 'budget_threshold', 'count': over, 'label': f'{over} budget line(s) at 80%+', 'icon': '⚠️', 'view': 'financial-control'})
        except Exception: pass

        # SSNIT due (14th of each month)
        try:
            if today.day <= 14:
                alerts.append({'type': 'ssnit_due', 'count': 1, 'label': f'SSNIT remittance due by 14th of this month', 'icon': '🏛', 'view': 'hr-payroll'})
        except Exception: pass

        total_count = sum(a['count'] for a in alerts)
        return ok({'alerts': alerts, 'total': total_count})
    finally:
        conn.close()

