# ── PPA Threshold Check ──────────────────────────────────────────────────────
def api_ppa_check(session, amount=None):
    if not session: return err('Not authenticated')
    try:
        amt = float(amount or 0)
    except Exception:
        return err('Invalid amount')
    # Ghana PPA 2023 thresholds (Public Procurement Authority)
    if amt < 5000:
        method = 'Direct (Sole Source)'; threshold_label = 'Below GHS 5,000'
        description = 'Can be procured directly without competitive bidding.'
        risk = 'low'
    elif amt < 50000:
        method = 'Restricted Tender'; threshold_label = 'GHS 5,000 – GHS 50,000'
        description = 'Requires at least 3 quotations from invited suppliers.'
        risk = 'medium'
    elif amt < 200000:
        method = 'Request for Quotation (RFQ)'; threshold_label = 'GHS 50,000 – GHS 200,000'
        description = 'Formal RFQ with minimum 3 competent suppliers.'
        risk = 'medium'
    else:
        method = 'Open Competitive Tender'; threshold_label = 'Above GHS 200,000'
        description = 'Full open tender required. Advertise in national newspapers and PPA portal.'
        risk = 'high'
    return ok({
        'amount': amt, 'method': method, 'threshold_label': threshold_label,
        'description': description, 'risk': risk
    })

# ── Phase-2 Data Connection Hooks ────────────────────────────────────────────
def _v54_post_payroll_hook(conn, month, session):
    """After payroll run, auto-populate SSNIT contribution table."""
    try:
        _f53_migrate()
        rows = conn.execute(
            "SELECT employee_id, employee_name, basic_salary, gross_salary FROM payroll_runs WHERE period=?",
            (month,)
        ).fetchall()
        if not rows:
            # Try alternative payroll table structure
            rows = conn.execute(
                "SELECT employee_id, employee_name, basic_pay, total_gross FROM payroll_entries WHERE period=?",
                (month,)
            ).fetchall()
        for r in rows:
            eid = r[0]; ename = r[1]
            basic = float(r[2] or r[3] or 0)
            t1_emp = round(basic * 0.055, 2)   # Employee 5.5%
            t1_emplr = round(basic * 0.13, 2)  # Employer 13%
            t2 = round(basic * 0.05, 2)        # Tier-2 5%
            sid = _f53_uid()
            conn.execute("""INSERT OR IGNORE INTO ssnit_contributions
                (id,period,employee_id,employee_name,basic_salary,tier1_employee,tier1_employer,tier2,total,created_by)
                VALUES(?,?,?,?,?,?,?,?,?,?)""",
                (sid, month, eid, ename, basic, t1_emp, t1_emplr, t2,
                 round(t1_emp + t1_emplr + t2, 2), session.get('username','system')))
        conn.commit()
    except Exception as exc:
        print('v54 payroll→ssnit hook warning:', exc)

def _v54_post_po_approval_hook(conn, po_id, session):
    """After PO approval, auto-raise a draft commitment if none exists."""
    try:
        po = conn.execute("SELECT * FROM purchase_orders WHERE id=?", (po_id,)).fetchone()
        if not po: return
        po = dict(po)
        # Check if commitment already exists for this PO
        existing = conn.execute(
            "SELECT id FROM commitments WHERE description LIKE ?",
            ('%' + (po.get('po_number') or po_id[:8]) + '%',)
        ).fetchone()
        if existing: return
        cid = _f53_uid()
        conn.execute("""INSERT INTO commitments(id,description,amount,project_code,
            commitment_date,status,created_by,created_at)
            VALUES(?,?,?,?,?,?,?,datetime('now'))""",
            (cid, f"PO: {po.get('po_number','')} — {po.get('description','').strip()}",
             float(po.get('total_amount') or 0),
             po.get('project_code',''),
             po.get('po_date') or _f53_today(),
             'Approved', session.get('username','system')))
        conn.commit()
    except Exception as exc:
        print('v54 po→commitment hook warning:', exc)

# Wrapped route handlers that fire Phase-2 hooks
def api_approve_po_v54(data, session):
    """Approve PO then auto-raise commitment (Phase-2 hook)."""
    result = api_approve_po(data, session)
    if result.get('ok'):
        conn = get_db()
        try:
            _v54_post_po_approval_hook(conn, data.get('id',''), session)
        finally:
            conn.close()
    return result

