# ═══════════════════════════════════════════════════════
def _v55_migrate():
    conn = get_db()
    try:
        conn.executescript("""
        -- NOTE: journal_vouchers and jv_lines are intentionally NOT created here.
        -- They are owned by init_jv_db() using the canonical schema (jv_number,
        -- jv_type, period / line_number, debit_amount, credit_amount) that the whole
        -- JV subsystem, reports and frontend rely on. A duplicate CREATE here once
        -- shadowed that schema with a jv_code/period_code variant and broke the
        -- Journal Vouchers screen (HTTP 500: no such column jv.jv_number).
        CREATE TABLE IF NOT EXISTS fixed_assets (
            id TEXT PRIMARY KEY, asset_code TEXT UNIQUE NOT NULL,
            asset_name TEXT NOT NULL, category TEXT NOT NULL,
            location TEXT, condition TEXT DEFAULT 'Good',
            acquisition_date TEXT NOT NULL,
            acquisition_cost REAL NOT NULL,
            useful_life_years REAL NOT NULL DEFAULT 5,
            residual_value REAL DEFAULT 0,
            accumulated_depreciation REAL DEFAULT 0,
            net_book_value REAL,
            last_depreciation_date TEXT,
            disposal_date TEXT, disposal_proceeds REAL,
            project_id TEXT, coa_id TEXT,
            status TEXT DEFAULT 'Active',
            serial_number TEXT, insured INTEGER DEFAULT 0,
            insurance_expiry TEXT, notes TEXT,
            created_by TEXT, created_at TEXT DEFAULT (datetime('now'))
        );
        CREATE TABLE IF NOT EXISTS bank_reconciliations_v55 (
            id TEXT PRIMARY KEY, rec_code TEXT UNIQUE NOT NULL,
            bank_account_id TEXT NOT NULL,
            period_month TEXT NOT NULL,
            statement_balance REAL DEFAULT 0,
            gl_balance REAL DEFAULT 0,
            outstanding_deposits REAL DEFAULT 0,
            outstanding_payments REAL DEFAULT 0,
            adjusted_balance REAL DEFAULT 0,
            difference REAL DEFAULT 0,
            status TEXT DEFAULT 'Draft',
            prepared_by TEXT, approved_by TEXT,
            signed_off_at TEXT, notes TEXT,
            created_at TEXT DEFAULT (datetime('now'))
        );
        CREATE TABLE IF NOT EXISTS recon_items (
            id TEXT PRIMARY KEY, recon_id TEXT NOT NULL,
            item_type TEXT NOT NULL,
            item_date TEXT, description TEXT,
            amount REAL DEFAULT 0,
            is_cleared INTEGER DEFAULT 0,
            cleared_date TEXT,
            reference TEXT
        );
        CREATE TABLE IF NOT EXISTS budget_revisions (
            id TEXT PRIMARY KEY,
            budget_id TEXT NOT NULL,
            revision_date TEXT NOT NULL,
            revision_type TEXT NOT NULL,
            original_amount_ghs REAL NOT NULL,
            revised_amount_ghs REAL NOT NULL,
            change_amount_ghs REAL,
            reason TEXT NOT NULL,
            approved_by TEXT,
            approved_at TEXT,
            reference TEXT,
            created_at TEXT DEFAULT (datetime('now'))
        );
        CREATE TABLE IF NOT EXISTS approval_rules_v55 (
            id TEXT PRIMARY KEY,
            document_type TEXT NOT NULL,
            level INTEGER NOT NULL,
            level_label TEXT,
            required_role TEXT,
            min_amount REAL DEFAULT 0,
            max_amount REAL DEFAULT 999999999,
            is_active INTEGER DEFAULT 1,
            created_at TEXT DEFAULT (datetime('now'))
        );
        CREATE TABLE IF NOT EXISTS approval_steps (
            id TEXT PRIMARY KEY,
            document_type TEXT NOT NULL,
            document_id TEXT NOT NULL,
            level INTEGER NOT NULL,
            level_label TEXT,
            required_role TEXT,
            status TEXT DEFAULT 'Pending',
            actioned_by TEXT,
            actioned_at TEXT,
            notes TEXT,
            created_at TEXT DEFAULT (datetime('now'))
        );
        CREATE TABLE IF NOT EXISTS document_attachments_v55 (
            id TEXT PRIMARY KEY,
            document_type TEXT NOT NULL,
            document_id TEXT NOT NULL,
            filename TEXT NOT NULL,
            file_type TEXT,
            file_size INTEGER,
            file_data TEXT,
            description TEXT,
            uploaded_by TEXT,
            uploaded_at TEXT DEFAULT (datetime('now'))
        );
        CREATE TABLE IF NOT EXISTS year_end_closes (
            id TEXT PRIMARY KEY,
            financial_year TEXT UNIQUE NOT NULL,
            surplus_deficit REAL DEFAULT 0,
            retained_earnings_before REAL DEFAULT 0,
            retained_earnings_after REAL DEFAULT 0,
            status TEXT DEFAULT 'Draft',
            prepared_by TEXT,
            approved_by TEXT,
            closed_at TEXT,
            notes TEXT,
            created_at TEXT DEFAULT (datetime('now'))
        );
        """)
        conn.commit()
        # Seed default approval rules if none exist
        existing = conn.execute("SELECT COUNT(*) FROM approval_rules_v55").fetchone()[0]
        if existing == 0:
            import uuid as _uuid2
            rules = [
                ('actuals', 1, 'Finance Officer', 'User', 0, 10000),
                ('actuals', 2, 'Director', 'Admin', 10000, 999999999),
                ('purchase_orders', 1, 'Finance Officer', 'User', 0, 5000),
                ('purchase_orders', 2, 'Director', 'Admin', 5000, 200000),
                ('purchase_orders', 3, 'Entity Head', 'Admin', 200000, 999999999),
                ('journal_vouchers', 1, 'Finance Officer', 'User', 0, 999999999),
                ('journal_vouchers', 2, 'Director', 'Admin', 0, 999999999),
            ]
            for r in rules:
                conn.execute(
                    "INSERT INTO approval_rules_v55(id,document_type,level,level_label,required_role,min_amount,max_amount) VALUES(?,?,?,?,?,?,?)",
                    (str(_uuid2.uuid4()), r[0], r[1], r[0]+' Level '+str(r[1]), r[3], r[4], r[5])
                )
            conn.commit()
    except Exception as e:
        print('v5.5 migration warning:', e)
    finally:
        conn.close()


# ── Journal Voucher functions ─────────────────────────────────────────────────

def api_journal_vouchers(self_or_sess, period_from=None, period_to=None):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    import datetime as _dt
    try:
        today = _dt.date.today()
        if not period_from:
            period_from = str(today.year) + '-01-01'
        if not period_to:
            period_to = today.isoformat()
        conn = get_db()
        try:
            rows = [dict(r) for r in conn.execute(
                "SELECT * FROM journal_vouchers WHERE jv_date BETWEEN ? AND ? ORDER BY jv_date DESC, jv_code DESC",
                (period_from, period_to)
            ).fetchall()]
            for row in rows:
                td = _f53_f(row.get('total_debit') or 0)
                tc = _f53_f(row.get('total_credit') or 0)
                row['balance_ok'] = abs(td - tc) < 0.01
            return ok({'journal_vouchers': rows, 'period_from': period_from, 'period_to': period_to})
        finally:
            conn.close()
    except Exception as e:
        return err(str(e))


def api_save_journal_voucher(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not data:
        return err('No data provided')
    jv_date = (data.get('jv_date') or '').strip()
    description = (data.get('description') or '').strip()
    lines = data.get('lines') or []
    if not jv_date:
        return err('jv_date is required')
    if not description:
        return err('description is required')
    if not isinstance(lines, list) or len(lines) < 2:
        return err('At least 2 journal lines are required')
    total_debit = 0.0
    total_credit = 0.0
    validated_lines = []
    for i, line in enumerate(lines):
        debit = _f53_f(line.get('debit_ghs') or 0)
        credit = _f53_f(line.get('credit_ghs') or 0)
        coa_code = (line.get('coa_code') or '').strip()
        coa_id = (line.get('coa_id') or '').strip()
        if not coa_code and not coa_id:
            return err('Each line requires coa_code or coa_id (line %d)' % (i + 1))
        if debit > 0 and credit > 0:
            return err('Line %d cannot have both debit and credit > 0' % (i + 1))
        if debit == 0 and credit == 0:
            return err('Line %d must have debit or credit > 0' % (i + 1))
        total_debit += debit
        total_credit += credit
        validated_lines.append({
            'coa_id': coa_id,
            'coa_code': coa_code,
            'account_name': (line.get('account_name') or '').strip(),
            'description': (line.get('description') or '').strip(),
            'debit_ghs': debit,
            'credit_ghs': credit,
            'project_id': (line.get('project_id') or '').strip(),
        })
    if abs(total_debit - total_credit) > 0.01:
        return err('Journal voucher is not balanced: debit=%.2f credit=%.2f' % (total_debit, total_credit))
    import uuid as _uuid
    conn = get_db()
    try:
        jv_id = (data.get('id') or '').strip()
        if jv_id:
            conn.execute(
                "UPDATE journal_vouchers SET jv_date=?, description=?, reference=?, narration=?, period_code=?, project_id=?, total_debit=?, total_credit=? WHERE id=?",
                (jv_date, description, data.get('reference'), data.get('narration'), data.get('period_code'), data.get('project_id'), total_debit, total_credit, jv_id)
            )
            conn.execute("DELETE FROM jv_lines WHERE jv_id=?", (jv_id,))
        else:
            jv_id = str(_uuid.uuid4())
            # Generate jv_code: JV-YYYYMM-NNN
            period_prefix = jv_date[:7].replace('-', '')
            existing_count = conn.execute(
                "SELECT COUNT(*) FROM journal_vouchers WHERE jv_code LIKE ?",
                ('JV-' + period_prefix + '-%',)
            ).fetchone()[0]
            jv_code = 'JV-%s-%03d' % (period_prefix, existing_count + 1)
            _wunit = _ucc_resolve_write_unit(conn, data, session) if '_ucc_resolve_write_unit' in globals() else None
            conn.execute(
                "INSERT INTO journal_vouchers(id,jv_code,jv_date,description,reference,narration,prepared_by,period_code,project_id,total_debit,total_credit,status,unit_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,'Draft',?)",
                (jv_id, jv_code, jv_date, description, data.get('reference'), data.get('narration'), session.get('username'), data.get('period_code'), data.get('project_id'), total_debit, total_credit, _wunit)
            )
        for idx, line in enumerate(validated_lines):
            conn.execute(
                "INSERT INTO jv_lines(id,jv_id,line_no,coa_id,coa_code,account_name,description,debit_ghs,credit_ghs,project_id) VALUES(?,?,?,?,?,?,?,?,?,?)",
                (str(_uuid.uuid4()), jv_id, idx + 1, line['coa_id'], line['coa_code'], line['account_name'], line['description'], line['debit_ghs'], line['credit_ghs'], line['project_id'])
            )
        conn.commit()
        try:
            conn.execute(
                "INSERT INTO audit_log(id,action,module,performed_by,details,timestamp) VALUES(?,?,?,?,?,datetime('now'))",
                (str(_uuid.uuid4()), 'save_journal_voucher', 'journal_vouchers', session.get('username', ''), 'Saved JV id=' + jv_id)
            )
            conn.commit()
        except Exception:
            pass
        return ok({'jv_id': jv_id})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_post_journal_voucher(self_or_sess, jv_id):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not _f53_is_admin(session):
        return err('Admin only')
    if not jv_id:
        return err('jv_id is required')
    conn = get_db()
    try:
        jv = conn.execute("SELECT * FROM journal_vouchers WHERE id=?", (jv_id,)).fetchone()
        if not jv:
            return err('Journal voucher not found')
        jv = dict(jv)
        if jv.get('status') == 'Posted':
            return err('Journal voucher is already posted')
        total_debit = _f53_f(jv.get('total_debit') or 0)
        total_credit = _f53_f(jv.get('total_credit') or 0)
        if abs(total_debit - total_credit) > 0.01:
            return err('Cannot post unbalanced journal voucher')
        lines = [dict(r) for r in conn.execute("SELECT * FROM jv_lines WHERE jv_id=?", (jv_id,)).fetchall()]
        if not lines:
            return err('Journal voucher has no lines to post')
        # Reject negative amounts before they reach the GL (non-finite is already
        # neutralised by the hardened _f53_f, so the balance gate above is reliable).
        for _ln in lines:
            if _f53_f(_ln.get('debit_amount') or 0) < 0 or _f53_f(_ln.get('credit_amount') or 0) < 0:
                return err('Journal voucher has a negative line amount; cannot post')
        import uuid as _uuid
        import datetime as _dt
        # Write the posting to the GENERAL LEDGER using the canonical column set
        # (ledger_date/debit_amount/credit_amount/jv_number/period…). The previous code
        # inserted non-existent columns (debit_ghs/credit_ghs/entry_date) and read
        # debit_ghs from jv_lines (which stores debit_amount), then swallowed the error
        # with `except: pass` — so posted JVs NEVER reached the GL and were invisible to
        # the Trial Balance, SFP, Cash Flow and I&E. This restores them to the ledger.
        jv_number = jv.get('jv_number') or jv_id
        ledger_date = jv.get('jv_date') or _dt.date.today().isoformat()
        period = jv.get('period') or (ledger_date[:7] if ledger_date else '')
        # Enforce the accounting-period lock (this posting path previously skipped it).
        try:
            _ensure_period_accepts(conn, ledger_date, by_date=True, purpose='JV posting')
        except Exception as _pe:
            conn.close()
            return {'ok': False, 'error': str(_pe)}
        jv_project = jv.get('project_id')
        proj_code = None
        if jv_project:
            pr = conn.execute("SELECT project_code FROM projects WHERE id=?", (jv_project,)).fetchone()
            proj_code = pr['project_code'] if pr else None
        for line in lines:
            coa_id = line.get('coa_id')
            coa_code = line.get('coa_code'); account_name = line.get('account_name')
            if (not coa_code or not account_name) and coa_id:
                ca = conn.execute("SELECT code, account_name FROM chart_of_accounts WHERE id=?", (coa_id,)).fetchone()
                if ca:
                    coa_code = coa_code or ca['code']; account_name = account_name or ca['account_name']
            dr = round(float(line.get('debit_amount') or line.get('debit_ghs') or 0), 2)
            cr = round(float(line.get('credit_amount') or line.get('credit_ghs') or 0), 2)
            line_project = line.get('project_id') or jv_project
            line_proj_code = proj_code
            if line.get('project_id') and line.get('project_id') != jv_project:
                lpr = conn.execute("SELECT project_code FROM projects WHERE id=?", (line.get('project_id'),)).fetchone()
                line_proj_code = lpr['project_code'] if lpr else None
            conn.execute("""INSERT INTO general_ledger
                (id,jv_id,jv_number,jv_line_id,ledger_date,period,coa_id,coa_code,account_name,description,
                 debit_amount,credit_amount,project_id,project_code,unit_id,posted_by,posted_at)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,datetime('now'))""",
                (str(_uuid.uuid4()), jv_id, jv_number, line.get('id'), ledger_date, period, coa_id, coa_code, account_name,
                 line.get('description') or jv.get('description') or '', dr, cr, line_project, line_proj_code,
                 (line.get('unit_id') or jv.get('unit_id')), session.get('username', '')))
        conn.execute("UPDATE journal_vouchers SET status='Posted', posted_by=?, posted_at=datetime('now') WHERE id=?", (session.get('username', ''), jv_id))
        conn.commit()
        try:
            conn.execute(
                "INSERT INTO audit_log(id,action,module,performed_by,details,timestamp) VALUES(?,?,?,?,?,datetime('now'))",
                (str(_uuid.uuid4()), 'post_journal_voucher', 'journal_vouchers', session.get('username', ''), 'Posted JV id=' + jv_id)
            )
            conn.commit()
        except Exception:
            pass
        return ok({'jv_id': jv_id, 'status': 'Posted'})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_approve_journal_voucher(self_or_sess, jv_id):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not jv_id:
        return err('jv_id is required')
    conn = get_db()
    try:
        jv = conn.execute("SELECT * FROM journal_vouchers WHERE id=?", (jv_id,)).fetchone()
        if not jv:
            return err('Journal voucher not found')
        jv = dict(jv)
        if jv.get('status') == 'Posted':
            return err('Journal voucher is already posted')
        # Segregation of duties (maker-checker): the approver must differ from the
        # preparer/creator. Previously this endpoint applied no SoD check, so one user
        # could prepare and approve the same JV — a single-person control breach.
        _creator = (jv.get('prepared_by') or jv.get('created_by') or '').strip()
        if _creator and _creator == (session.get('username') or ''):
            return err('Segregation of duties: a journal voucher cannot be approved by the user who prepared it. A second authorised officer must approve.')
        import uuid as _uuid
        import datetime as _dt
        now = _dt.datetime.utcnow().isoformat()
        conn.execute(
            "UPDATE journal_vouchers SET status='Approved', approved_by=? WHERE id=?",
            (session.get('username'), jv_id)
        )
        conn.commit()
        try:
            conn.execute(
                "INSERT INTO audit_log(id,action,module,performed_by,details,timestamp) VALUES(?,?,?,?,?,datetime('now'))",
                (str(_uuid.uuid4()), 'approve_journal_voucher', 'journal_vouchers', session.get('username', ''), 'Approved JV id=' + jv_id)
            )
            conn.commit()
        except Exception:
            pass
        return ok({'jv_id': jv_id, 'status': 'Approved'})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


