def api_fixed_assets(self_or_sess):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        assets = [dict(r) for r in conn.execute(
            "SELECT * FROM fixed_assets ORDER BY category, asset_name"
        ).fetchall()]
        total_count = len(assets)
        total_cost = sum(_f53_f(a.get('acquisition_cost') or 0) for a in assets)
        total_nbv = sum(_f53_f(a.get('net_book_value') or 0) for a in assets)
        total_accum_dep = sum(_f53_f(a.get('accumulated_depreciation') or 0) for a in assets)
        return ok({
            'assets': assets,
            'summary': {
                'total_count': total_count,
                'total_cost': round(total_cost, 2),
                'total_net_book_value': round(total_nbv, 2),
                'total_accumulated_depreciation': round(total_accum_dep, 2),
            }
        })
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_save_fixed_asset(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not data:
        return err('No data provided')
    asset_name = (data.get('asset_name') or '').strip()
    category = (data.get('category') or '').strip()
    acquisition_date = (data.get('acquisition_date') or '').strip()
    acquisition_cost = _f53_f(data.get('acquisition_cost') or 0)
    useful_life_years = _f53_f(data.get('useful_life_years') or 0)
    if not asset_name:
        return err('asset_name is required')
    if not category:
        return err('category is required')
    if not acquisition_date:
        return err('acquisition_date is required')
    if acquisition_cost <= 0:
        return err('acquisition_cost must be > 0')
    if useful_life_years <= 0:
        return err('useful_life_years must be > 0')
    residual_value = _f53_f(data.get('residual_value') or 0)
    net_book_value = acquisition_cost - residual_value
    import uuid as _uuid
    conn = get_db()
    try:
        asset_id = (data.get('id') or '').strip()
        if asset_id:
            conn.execute(
                "UPDATE fixed_assets SET asset_name=?, category=?, location=?, condition=?, acquisition_date=?, acquisition_cost=?, useful_life_years=?, residual_value=?, net_book_value=?, project_id=?, coa_id=?, serial_number=?, insured=?, insurance_expiry=?, notes=? WHERE id=?",
                (asset_name, category, data.get('location'), data.get('condition', 'Good'), acquisition_date, acquisition_cost, useful_life_years, residual_value, net_book_value, data.get('project_id'), data.get('coa_id'), data.get('serial_number'), 1 if data.get('insured') else 0, data.get('insurance_expiry'), data.get('notes'), asset_id)
            )
        else:
            asset_id = str(_uuid.uuid4())
            # Generate asset_code: FA-[category_prefix]-NNN
            cat_prefix = ''.join(w[0].upper() for w in category.split()[:3]) if category else 'GEN'
            existing_count = conn.execute(
                "SELECT COUNT(*) FROM fixed_assets WHERE asset_code LIKE ?",
                ('FA-' + cat_prefix + '-%',)
            ).fetchone()[0]
            asset_code = 'FA-%s-%03d' % (cat_prefix, existing_count + 1)
            conn.execute(
                "INSERT INTO fixed_assets(id,asset_code,asset_name,category,location,condition,acquisition_date,acquisition_cost,useful_life_years,residual_value,net_book_value,project_id,coa_id,serial_number,insured,insurance_expiry,notes,created_by,status) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,'Active')",
                (asset_id, asset_code, asset_name, category, data.get('location'), data.get('condition', 'Good'), acquisition_date, acquisition_cost, useful_life_years, residual_value, net_book_value, data.get('project_id'), data.get('coa_id'), data.get('serial_number'), 1 if data.get('insured') else 0, data.get('insurance_expiry'), data.get('notes'), session.get('username'))
            )
        conn.commit()
        return ok({'asset_id': asset_id})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_run_asset_depreciation(self_or_sess):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not _f53_is_admin(session):
        return err('Admin only')
    import datetime as _dt
    conn = get_db()
    try:
        today = _dt.date.today()
        today_str = today.isoformat()
        assets = [dict(r) for r in conn.execute(
            "SELECT * FROM fixed_assets WHERE status='Active'"
        ).fetchall()]
        processed = 0
        total_depreciation = 0.0
        for asset in assets:
            acquisition_cost = _f53_f(asset.get('acquisition_cost') or 0)
            residual_value = _f53_f(asset.get('residual_value') or 0)
            useful_life_years = _f53_f(asset.get('useful_life_years') or 5)
            accumulated_dep = _f53_f(asset.get('accumulated_depreciation') or 0)
            net_book_value = _f53_f(asset.get('net_book_value') or (acquisition_cost - residual_value))
            last_dep_date_str = asset.get('last_depreciation_date') or asset.get('acquisition_date') or today_str
            try:
                last_dep_date = _dt.date.fromisoformat(last_dep_date_str[:10])
            except Exception:
                last_dep_date = today
            # Compute months since last depreciation
            months_diff = (today.year - last_dep_date.year) * 12 + (today.month - last_dep_date.month)
            if months_diff < 1:
                continue
            depreciable_amount = acquisition_cost - residual_value
            if depreciable_amount <= 0 or useful_life_years <= 0:
                continue
            annual_dep = depreciable_amount / useful_life_years
            monthly_dep = annual_dep / 12.0
            dep_charge = monthly_dep * months_diff
            # Cap at remaining depreciable amount
            remaining = depreciable_amount - accumulated_dep
            if remaining <= 0:
                # Already fully depreciated
                new_status = 'Fully Depreciated'
                conn.execute(
                    "UPDATE fixed_assets SET status=?, last_depreciation_date=? WHERE id=?",
                    (new_status, today_str, asset['id'])
                )
                conn.commit()
                continue
            dep_charge = min(dep_charge, remaining)
            new_accumulated = accumulated_dep + dep_charge
            new_nbv = acquisition_cost - new_accumulated
            new_status = 'Active'
            if new_nbv <= residual_value + 0.01:
                new_status = 'Fully Depreciated'
                new_nbv = residual_value
            conn.execute(
                "UPDATE fixed_assets SET accumulated_depreciation=?, net_book_value=?, last_depreciation_date=?, status=? WHERE id=?",
                (round(new_accumulated, 2), round(new_nbv, 2), today_str, new_status, asset['id'])
            )
            total_depreciation += dep_charge
            processed += 1
        # Post the period's depreciation charge to the GENERAL LEDGER (Dr depreciation
        # expense / Cr accumulated depreciation) so it reaches the I&E, the SFP and the
        # depreciation schedule. Previously this endpoint updated the asset rows only,
        # leaving depreciation entirely off-ledger (understating expense, overstating net assets).
        _dep_amt = round(total_depreciation, 2)
        if _dep_amt > 0:
            def _dep_coa(code, prefix):
                rr = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (code,)).fetchone()
                if rr:
                    return rr['id']
                rr = conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE ? ORDER BY code LIMIT 1", (prefix + '%',)).fetchone()
                return rr['id'] if rr else None
            dep_exp_id = _dep_coa('61900011', '619')
            acc_dep_id = _dep_coa('11902004', '119')
            if dep_exp_id and acc_dep_id:
                _desc = 'Monthly depreciation charge — ' + today_str
                _create_posted_journal(conn, session, 'AJV', today_str, _desc, 'DEP-' + today_str,
                    None, None, 'depreciation', None,
                    [{'coa_id': dep_exp_id, 'debit_amount': _dep_amt, 'credit_amount': 0, 'description': _desc},
                     {'coa_id': acc_dep_id, 'debit_amount': 0, 'credit_amount': _dep_amt, 'description': _desc}])
        conn.commit()
        return ok({'assets_processed': processed, 'total_depreciation_charged': round(total_depreciation, 2), 'gl_posted': _dep_amt > 0})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_dispose_asset(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not _f53_is_admin(session):
        return err('Admin only')
    if not data:
        return err('No data provided')
    asset_id = (data.get('asset_id') or '').strip()
    disposal_date = (data.get('disposal_date') or '').strip()
    disposal_proceeds = _f53_f(data.get('disposal_proceeds') or 0)
    if not asset_id:
        return err('asset_id is required')
    if not disposal_date:
        return err('disposal_date is required')
    conn = get_db()
    try:
        asset = conn.execute("SELECT * FROM fixed_assets WHERE id=?", (asset_id,)).fetchone()
        if not asset:
            return err('Asset not found')
        asset = dict(asset)
        net_book_value = _f53_f(asset.get('net_book_value') or 0)
        gain_loss = disposal_proceeds - net_book_value
        conn.execute(
            "UPDATE fixed_assets SET status='Disposed', disposal_date=?, disposal_proceeds=? WHERE id=?",
            (disposal_date, disposal_proceeds, asset_id)
        )
        conn.commit()
        return ok({'asset_id': asset_id, 'gain_loss': round(gain_loss, 2), 'disposal_proceeds': disposal_proceeds, 'net_book_value': net_book_value})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


# ── Bank Reconciliation functions ─────────────────────────────────────────────

def api_bank_reconciliation(self_or_sess, account_id=None, period_month=None):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    import datetime as _dt
    if not period_month:
        period_month = _dt.date.today().strftime('%Y-%m')
    conn = get_db()
    try:
        account = None
        if account_id:
            row = conn.execute("SELECT * FROM bank_accounts WHERE id=?", (account_id,)).fetchone()
            if row:
                account = dict(row)
        # Find or auto-create reconciliation
        rec = None
        if account_id:
            row = conn.execute(
                "SELECT * FROM bank_reconciliations_v55 WHERE bank_account_id=? AND period_month=?",
                (account_id, period_month)
            ).fetchone()
            if row:
                rec = dict(row)
            else:
                import uuid as _uuid
                rec_id = str(_uuid.uuid4())
                acct_num = (account or {}).get('account_number', account_id)[:10] if account else account_id[:10]
                rec_code = 'REC-%s-%s' % (acct_num, period_month)
                conn.execute(
                    "INSERT INTO bank_reconciliations_v55(id,rec_code,bank_account_id,period_month,status,prepared_by) VALUES(?,?,?,?,'Draft',?)",
                    (rec_id, rec_code, account_id, period_month, session.get('username'))
                )
                conn.commit()
                rec = dict(conn.execute("SELECT * FROM bank_reconciliations_v55 WHERE id=?", (rec_id,)).fetchone())
        items = []
        if rec:
            items = [dict(r) for r in conn.execute(
                "SELECT * FROM recon_items WHERE recon_id=? ORDER BY item_date",
                (rec['id'],)
            ).fetchall()]
            outstanding_deposits = sum(_f53_f(i.get('amount') or 0) for i in items if i.get('item_type') == 'Outstanding Deposit' and not i.get('is_cleared'))
            outstanding_payments = sum(_f53_f(i.get('amount') or 0) for i in items if i.get('item_type') == 'Outstanding Payment' and not i.get('is_cleared'))
            statement_balance = _f53_f(rec.get('statement_balance') or 0)
            gl_balance = _f53_f(rec.get('gl_balance') or 0)
            adjusted_balance = statement_balance + outstanding_deposits - outstanding_payments
            difference = adjusted_balance - gl_balance
            rec['outstanding_deposits'] = round(outstanding_deposits, 2)
            rec['outstanding_payments'] = round(outstanding_payments, 2)
            rec['adjusted_balance'] = round(adjusted_balance, 2)
            rec['difference'] = round(difference, 2)
        return ok({'reconciliation': rec, 'items': items, 'account': account, 'period_month': period_month})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_save_recon_item(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not data:
        return err('No data provided')
    recon_id = (data.get('recon_id') or '').strip()
    item_type = (data.get('item_type') or '').strip()
    amount = _f53_f(data.get('amount') or 0)
    if not recon_id:
        return err('recon_id is required')
    valid_types = ('Outstanding Deposit', 'Outstanding Payment', 'Bank Error', 'GL Error')
    if item_type not in valid_types:
        return err('item_type must be one of: ' + ', '.join(valid_types))
    import uuid as _uuid
    conn = get_db()
    try:
        item_id = (data.get('id') or '').strip()
        if item_id:
            conn.execute(
                "UPDATE recon_items SET item_type=?, item_date=?, description=?, amount=?, is_cleared=?, cleared_date=?, reference=? WHERE id=?",
                (item_type, data.get('item_date'), data.get('description'), amount, 1 if data.get('is_cleared') else 0, data.get('cleared_date'), data.get('reference'), item_id)
            )
        else:
            item_id = str(_uuid.uuid4())
            conn.execute(
                "INSERT INTO recon_items(id,recon_id,item_type,item_date,description,amount,is_cleared,cleared_date,reference) VALUES(?,?,?,?,?,?,?,?,?)",
                (item_id, recon_id, item_type, data.get('item_date'), data.get('description'), amount, 1 if data.get('is_cleared') else 0, data.get('cleared_date'), data.get('reference'))
            )
        conn.commit()
        # Recompute reconciliation totals
        items = [dict(r) for r in conn.execute("SELECT * FROM recon_items WHERE recon_id=?", (recon_id,)).fetchall()]
        outstanding_deposits = sum(_f53_f(i.get('amount') or 0) for i in items if i.get('item_type') == 'Outstanding Deposit' and not i.get('is_cleared'))
        outstanding_payments = sum(_f53_f(i.get('amount') or 0) for i in items if i.get('item_type') == 'Outstanding Payment' and not i.get('is_cleared'))
        rec = conn.execute("SELECT * FROM bank_reconciliations_v55 WHERE id=?", (recon_id,)).fetchone()
        if rec:
            rec = dict(rec)
            statement_balance = _f53_f(rec.get('statement_balance') or 0)
            gl_balance = _f53_f(rec.get('gl_balance') or 0)
            adjusted_balance = statement_balance + outstanding_deposits - outstanding_payments
            difference = adjusted_balance - gl_balance
            conn.execute(
                "UPDATE bank_reconciliations_v55 SET outstanding_deposits=?, outstanding_payments=?, adjusted_balance=?, difference=? WHERE id=?",
                (round(outstanding_deposits, 2), round(outstanding_payments, 2), round(adjusted_balance, 2), round(difference, 2), recon_id)
            )
            conn.commit()
        return ok({'item_id': item_id})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


