def api_budget_revisions(self_or_sess, budget_id=None):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        if budget_id:
            revisions = [dict(r) for r in conn.execute(
                "SELECT br.*, b.budget_code, b.budget_ghs AS current_budget_ghs, b.project_id FROM budget_revisions br LEFT JOIN budgets b ON br.budget_id=b.id WHERE br.budget_id=? ORDER BY br.revision_date DESC",
                (budget_id,)
            ).fetchall()]
            budget = conn.execute("SELECT * FROM budgets WHERE id=?", (budget_id,)).fetchone()
            budget = dict(budget) if budget else {}
        else:
            revisions = [dict(r) for r in conn.execute(
                "SELECT br.*, b.budget_code, b.budget_ghs AS current_budget_ghs, p.project_code, p.title AS project_title FROM budget_revisions br LEFT JOIN budgets b ON br.budget_id=b.id LEFT JOIN projects p ON b.project_id=p.id ORDER BY br.revision_date DESC"
            ).fetchall()]
            budget = {}
        return ok({'revisions': revisions, 'budget': budget})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_save_budget_revision(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not _f53_is_admin(session):
        return err('Admin only')
    if not data:
        return err('No data provided')
    budget_id = (data.get('budget_id') or '').strip()
    revision_type = (data.get('revision_type') or '').strip()
    revised_amount_ghs = _f53_f(data.get('revised_amount_ghs') or 0)
    reason = (data.get('reason') or '').strip()
    valid_types = ('Supplementary', 'Virement', 'Donor Amendment', 'Board Resolution')
    if not budget_id:
        return err('budget_id is required')
    if revision_type not in valid_types:
        return err('revision_type must be one of: ' + ', '.join(valid_types))
    if not reason:
        return err('reason is required')
    import uuid as _uuid
    import datetime as _dt
    conn = get_db()
    try:
        budget = conn.execute("SELECT * FROM budgets WHERE id=?", (budget_id,)).fetchone()
        if not budget:
            return err('Budget not found')
        budget = dict(budget)
        original_amount_ghs = _f53_f(budget.get('budget_ghs') or 0)
        change_amount_ghs = revised_amount_ghs - original_amount_ghs
        revision_id = str(_uuid.uuid4())
        revision_date = _dt.date.today().isoformat()
        conn.execute(
            "INSERT INTO budget_revisions(id,budget_id,revision_date,revision_type,original_amount_ghs,revised_amount_ghs,change_amount_ghs,reason,approved_by,reference) VALUES(?,?,?,?,?,?,?,?,?,?)",
            (revision_id, budget_id, revision_date, revision_type, original_amount_ghs, revised_amount_ghs, change_amount_ghs, reason, session.get('username'), data.get('reference'))
        )
        # Update budget
        current_fcy = _f53_f(budget.get('budget_fcy') or 0)
        fx_rate = _f53_f(budget.get('fx_rate') or 1)
        if original_amount_ghs and original_amount_ghs != 0:
            new_fcy = revised_amount_ghs / fx_rate if fx_rate else current_fcy
        else:
            new_fcy = current_fcy
        conn.execute(
            "UPDATE budgets SET budget_ghs=?, budget_fcy=? WHERE id=?",
            (revised_amount_ghs, round(new_fcy, 4), budget_id)
        )
        conn.commit()
        try:
            conn.execute(
                "INSERT INTO audit_log(id,action,module,performed_by,details,timestamp) VALUES(?,?,?,?,?,datetime('now'))",
                (str(_uuid.uuid4()), 'budget_revision', 'budgets', session.get('username', ''), 'Revised budget_id=%s type=%s change=%.2f' % (budget_id, revision_type, change_amount_ghs))
            )
            conn.commit()
        except Exception:
            pass
        return ok({'revision_id': revision_id, 'original_amount_ghs': original_amount_ghs, 'revised_amount_ghs': revised_amount_ghs, 'change_amount_ghs': round(change_amount_ghs, 2)})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


