def api_save_approval_rule(self_or_sess, data=None):
    # Accept (session, data) OR (data, session): dispatched both ways across app.py.
    def _is_sess(x): return isinstance(x, dict) and any(k in x for k in ('username', 'role', 'sid'))
    a, b = self_or_sess, data
    if _is_sess(a) and not _is_sess(b):
        session, data = a, b
    elif _is_sess(b):
        session, data = b, a
    else:
        session, data = a, b
    if not session:
        return err('Not authenticated')
    if not _f53_is_admin(session):
        return err('Admin only')
    if not data:
        return err('No data provided')
    document_type = (data.get('document_type') or '').strip()
    level = data.get('level')
    level_label = (data.get('level_label') or '').strip()
    min_amount = _f53_f(data.get('min_amount') or 0)
    max_amount = _f53_f(data.get('max_amount') or 999999999)
    if not document_type:
        return err('document_type is required')
    if level is None:
        return err('level is required')
    if not level_label:
        return err('level_label is required')
    import uuid as _uuid
    conn = get_db()
    try:
        rule_id = (data.get('id') or '').strip()
        if rule_id:
            conn.execute(
                "UPDATE approval_rules_v55 SET document_type=?, level=?, level_label=?, required_role=?, min_amount=?, max_amount=?, is_active=? WHERE id=?",
                (document_type, int(level), level_label, data.get('required_role'), min_amount, max_amount, 1 if data.get('is_active', True) else 0, rule_id)
            )
        else:
            rule_id = str(_uuid.uuid4())
            conn.execute(
                "INSERT INTO approval_rules_v55(id,document_type,level,level_label,required_role,min_amount,max_amount,is_active) VALUES(?,?,?,?,?,?,?,?)",
                (rule_id, document_type, int(level), level_label, data.get('required_role'), min_amount, max_amount, 1 if data.get('is_active', True) else 0)
            )
        conn.commit()
        return ok({'rule_id': rule_id})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_pending_approvals(self_or_sess):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        steps = [dict(r) for r in conn.execute(
            "SELECT * FROM approval_steps WHERE status='Pending' ORDER BY document_type, created_at"
        ).fetchall()]
        # Enrich with document details
        enriched = []
        for step in steps:
            doc_type = step.get('document_type', '')
            doc_id = step.get('document_id', '')
            doc_ref = ''
            amount = 0.0
            created_by = ''
            if doc_type == 'actuals':
                try:
                    row = conn.execute("SELECT actual_code, amount_ghs, payee FROM actuals WHERE id=?", (doc_id,)).fetchone()
                    if row:
                        doc_ref = row[0]
                        amount = _f53_f(row[1] or 0)
                        created_by = row[2] or ''
                except Exception:
                    pass
            elif doc_type == 'purchase_orders':
                try:
                    row = conn.execute("SELECT po_number, total_amount_ghs, vendor_name FROM purchase_orders WHERE id=?", (doc_id,)).fetchone()
                    if row:
                        doc_ref = row[0]
                        amount = _f53_f(row[1] or 0)
                        created_by = row[2] or ''
                except Exception:
                    pass
            elif doc_type == 'journal_vouchers':
                try:
                    row = conn.execute("SELECT jv_code, total_debit, prepared_by FROM journal_vouchers WHERE id=?", (doc_id,)).fetchone()
                    if row:
                        doc_ref = row[0]
                        amount = _f53_f(row[1] or 0)
                        created_by = row[2] or ''
                except Exception:
                    pass
            step['document_ref'] = doc_ref
            step['amount'] = amount
            step['created_by_entity'] = created_by
            enriched.append(step)
        # Group by document_type
        grouped = {}
        for step in enriched:
            dt = step.get('document_type', 'other')
            if dt not in grouped:
                grouped[dt] = []
            grouped[dt].append(step)
        return ok({'pending_approvals': enriched, 'grouped': grouped})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_process_approval(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not data:
        return err('No data provided')
    step_id = (data.get('step_id') or '').strip()
    action = (data.get('action') or '').strip()
    notes = (data.get('notes') or '').strip()
    if not step_id:
        return err('step_id is required')
    if action not in ('Approve', 'Reject'):
        return err('action must be Approve or Reject')
    conn = get_db()
    try:
        step = conn.execute("SELECT * FROM approval_steps WHERE id=?", (step_id,)).fetchone()
        if not step:
            return err('Approval step not found')
        step = dict(step)
        is_admin = _f53_is_admin(session)
        required_role = step.get('required_role', '')
        user_role = session.get('role', 'User')
        if not is_admin and required_role and user_role != required_role:
            return err('You do not have the required role (%s) for this approval step' % required_role)
        import datetime as _dt
        import uuid as _uuid
        now = _dt.datetime.utcnow().isoformat()
        _ascols = [r[1] for r in conn.execute("PRAGMA table_info(approval_steps)").fetchall()]
        if 'actioned_by' in _ascols:
            conn.execute(
                "UPDATE approval_steps SET status=?, actioned_by=?, actioned_at=?, notes=? WHERE id=?",
                (action + 'd', session.get('username'), now, notes, step_id)
            )
        else:
            conn.execute(
                "UPDATE approval_steps SET status=?, action_by=?, action_at=?, comments=? WHERE id=?",
                (action + 'd', session.get('username'), now, notes, step_id)
            )
        doc_type = step.get('document_type', '') or ''
        doc_id = step.get('document_id', '') or ''
        _legacy_steps = 'document_type' in _ascols
        _appr = None
        if not _legacy_steps and step.get('approval_id'):
            _ar = conn.execute("SELECT * FROM approvals WHERE id=?", (step.get('approval_id'),)).fetchone()
            if _ar:
                _appr = dict(_ar)
                doc_type = doc_type or (_appr.get('module') or '')
                doc_id = doc_id or (_appr.get('record_id') or '')
        if action == 'Reject':
            # Update parent document status to Rejected
            if doc_type == 'actuals':
                try:
                    conn.execute("UPDATE actuals SET status='Rejected' WHERE id=?", (doc_id,))
                except Exception:
                    pass
            elif doc_type == 'purchase_orders':
                try:
                    conn.execute("UPDATE purchase_orders SET status='Rejected' WHERE id=?", (doc_id,))
                except Exception:
                    pass
            elif doc_type == 'journal_vouchers':
                try:
                    conn.execute("UPDATE journal_vouchers SET status='Rejected' WHERE id=?", (doc_id,))
                except Exception:
                    pass
        elif action == 'Approve':
            # Check if this is the final pending step for this document
            if _legacy_steps:
                remaining_pending = conn.execute(
                    "SELECT COUNT(*) FROM approval_steps WHERE document_type=? AND document_id=? AND status='Pending' AND id!=?",
                    (doc_type, doc_id, step_id)
                ).fetchone()[0]
            else:
                remaining_pending = conn.execute(
                    "SELECT COUNT(*) FROM approval_steps WHERE approval_id=? AND status='Pending' AND id!=?",
                    (step.get('approval_id'), step_id)
                ).fetchone()[0]
            if remaining_pending == 0:
                if doc_type == 'actuals':
                    try:
                        conn.execute("UPDATE actuals SET status='Approved' WHERE id=?", (doc_id,))
                    except Exception:
                        pass
                elif doc_type == 'purchase_orders':
                    try:
                        conn.execute("UPDATE purchase_orders SET status='Approved' WHERE id=?", (doc_id,))
                    except Exception:
                        pass
                elif doc_type == 'journal_vouchers':
                    try:
                        conn.execute("UPDATE journal_vouchers SET status='Approved' WHERE id=?", (doc_id,))
                    except Exception:
                        pass
                if _appr:
                    try:
                        conn.execute("UPDATE approvals SET status='Approved', decided_by=?, decided_at=datetime('now'), comments=? WHERE id=?",
                                     (session.get('username'), notes, _appr['id']))
                    except Exception:
                        pass
        if action == 'Reject' and _appr:
            try:
                conn.execute("UPDATE approvals SET status='Rejected', decided_by=?, decided_at=datetime('now'), comments=? WHERE id=?",
                             (session.get('username'), notes, _appr['id']))
            except Exception:
                pass
        conn.commit()
        return ok({'step_id': step_id, 'action': action, 'approval_id': (_appr or {}).get('id'), 'module': doc_type, 'record_id': doc_id})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_initiate_approval(session, document_type, document_id, amount):
    """Internal helper: create approval_steps for a document based on rules."""
    import uuid as _uuid
    conn = get_db()
    steps_created = []
    try:
        amount = _f53_f(amount or 0)
        rules = [dict(r) for r in conn.execute(
            "SELECT * FROM approval_rules_v55 WHERE document_type=? AND is_active=1 AND min_amount<=? AND max_amount>=? ORDER BY level",
            (document_type, amount, amount)
        ).fetchall()]
        import datetime as _dt
        for rule in rules:
            step_id = str(_uuid.uuid4())
            conn.execute(
                "INSERT INTO approval_steps(id,document_type,document_id,level,level_label,required_role,status) VALUES(?,?,?,?,?,?,'Pending')",
                (step_id, document_type, document_id, rule.get('level', 1), rule.get('level_label', ''), rule.get('required_role', ''))
            )
            steps_created.append(step_id)
        conn.commit()
    except Exception as e:
        print('api_initiate_approval error:', e)
    finally:
        conn.close()
    return steps_created


