def api_delete_attachment(self_or_sess, attachment_id=None):
    # Accept either (session, attachment_id) or (data_dict, session): this endpoint
    # is dispatched with BOTH arg orders across app.py's route tables, and the
    # id may arrive as a bare string or inside a {id|attachment_id} payload.
    def _is_sess(x): return isinstance(x, dict) and any(k in x for k in ('username', 'role', 'sid'))
    a, b = self_or_sess, attachment_id
    if _is_sess(a) and not _is_sess(b):
        session, ident = a, b
    elif _is_sess(b):
        session, ident = b, a
    else:
        session, ident = a, b
    if isinstance(ident, dict):
        ident = ident.get('attachment_id') or ident.get('id')
    if not session:
        return err('Not authenticated')
    if not ident:
        return err('attachment_id is required')
    conn = get_db()
    try:
        # Vault uploads live in document_attachments; the v5.5 doc model uses
        # document_attachments_v55. Look in both so either kind can be removed.
        row = conn.execute("SELECT uploaded_by FROM document_attachments_v55 WHERE id=?", (ident,)).fetchone()
        tbl = 'document_attachments_v55'
        if not row:
            row = conn.execute("SELECT uploaded_by FROM document_attachments WHERE id=?", (ident,)).fetchone()
            tbl = 'document_attachments'
        if not row:
            return err('Attachment not found')
        row = dict(row)
        is_admin = _f53_is_admin(session)
        is_uploader = row.get('uploaded_by') == session.get('username')
        if not is_admin and not is_uploader:
            return err('Permission denied: only Admin or the uploader can delete this attachment')
        conn.execute("DELETE FROM " + tbl + " WHERE id=?", (ident,))
        conn.commit()
        return ok({'attachment_id': ident, 'deleted': True})
    except Exception as e:
        try: conn.rollback()
        except Exception: pass
        return err(str(e))
    finally:
        conn.close()


def api_get_attachment(self_or_sess, attachment_id):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
