# ── Vendor Register ──────────────────────────────────────────────────────────

def api_vendor_register(self_or_sess, vendor_type=None, search=None):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        q = "SELECT * FROM vendor_register_v55 WHERE is_active=1"
        params = []
        if vendor_type:
            q += " AND vendor_type=?"
            params.append(vendor_type)
        if search:
            q += " AND (vendor_name LIKE ? OR vendor_code LIKE ? OR tin LIKE ? OR email LIKE ?)"
            s = '%' + search + '%'
            params.extend([s, s, s, s])
        q += " ORDER BY vendor_name"
        vendors = [dict(r) for r in conn.execute(q, params).fetchall()]
        return ok({'vendors': vendors, 'total': len(vendors)})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_save_vendor(self_or_sess, data=None):
    # Accept either (session, data) or (data, session) — this endpoint has historically
    # been called both ways; normalise so a vendor always saves to the canonical table.
    def _is_data(x): return isinstance(x, dict) and any(k in x for k in ('vendor_name','beneficiary_name','name','vendor_type','tin'))
    a, b = self_or_sess, data
    if _is_data(a) and not _is_data(b):
        data, session = a, b
    elif _is_data(b):
        session, data = a, b
    else:
        session, data = a, b
    if not session:
        return err('Not authenticated')
    if not data:
        return err('No data provided')
    vendor_name = (data.get('vendor_name') or data.get('beneficiary_name') or data.get('name') or '').strip()
    if not vendor_name:
        return err('vendor_name is required')
    import uuid as _uuid
    conn = get_db()
    try:
        vendor_id = (data.get('id') or '').strip() or str(_uuid.uuid4())
        vendor_code = data.get('vendor_code') or _seq_code(conn, 'vendors', 'vendor_code', 'VEND-', 4)
        vtype = data.get('vendor_type') or 'Supplier'
        # PRIMARY: canonical vendors table (used by the vendor list and PV payee validation).
        conn.execute("""INSERT INTO vendors(id,vendor_code,vendor_name,vendor_type,contact_person,email,phone,tin,
                        tax_status,bank_name,account_name,account_number,momo_number,address,compliance_status,notes,created_by)
                        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                        ON CONFLICT(id) DO UPDATE SET vendor_name=excluded.vendor_name, vendor_type=excluded.vendor_type,
                        contact_person=excluded.contact_person, email=excluded.email, phone=excluded.phone, tin=excluded.tin,
                        bank_name=excluded.bank_name, account_name=excluded.account_name, account_number=excluded.account_number,
                        momo_number=excluded.momo_number, address=excluded.address,
                        compliance_status=excluded.compliance_status, notes=excluded.notes""",
            (vendor_id, vendor_code, vendor_name, vtype, data.get('contact_person') or '',
             data.get('email') or '', data.get('phone') or '', data.get('tin') or '',
             data.get('tax_status') or 'Withhold Tax where applicable', data.get('bank_name') or '',
             data.get('account_name') or '', data.get('account_number') or '', data.get('momo_number') or '',
             data.get('address') or '', data.get('compliance_status') or data.get('status') or 'Active',
             data.get('notes') or '', (session or {}).get('username','system')))
        # SECONDARY (best effort): keep the v5.5 vendor register in sync if present.
        try:
            if conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='vendor_register_v55'").fetchone():
                if not conn.execute("SELECT 1 FROM vendor_register_v55 WHERE id=?", (vendor_id,)).fetchone():
                    conn.execute("""INSERT INTO vendor_register_v55(id,vendor_name,vendor_code,tin,contact_person,phone,email,
                                    address,bank_name,account_number,account_name,vendor_type,is_active,created_by)
                                    VALUES(?,?,?,?,?,?,?,?,?,?,?,?,1,?)""",
                        (vendor_id, vendor_name, vendor_code, data.get('tin') or None, data.get('contact_person') or None,
                         data.get('phone') or None, data.get('email') or None, data.get('address') or None,
                         data.get('bank_name') or None, data.get('account_number') or None, data.get('account_name') or None,
                         vtype, (session or {}).get('username','system')))
        except Exception:
            pass
        try: _audit(conn, session, 'SAVE_VENDOR', 'vendors', vendor_id, vendor_name)
        except Exception: pass
        conn.commit()
        return ok({'id': vendor_id, 'vendor_id': vendor_id, 'vendor_code': vendor_code, 'vendor_name': vendor_name})
    except Exception as e:
        try: conn.rollback()
        except Exception: pass
        return err(str(e))
    finally:
        conn.close()


