# ── VAT / Tax Computation ────────────────────────────────────────────────────

def api_compute_vat(self_or_sess, data):
    """Compute Ghana VAT breakdown: VAT 15%, NHIL 2.5%, GETFund 2.5%."""
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not data:
        return err('No data provided')
    gross_amount = _f53_f(data.get('gross_amount') or data.get('amount') or 0)
    vat_inclusive = bool(data.get('vat_inclusive', True))
    VAT_RATE = 0.15
    NHIL_RATE = 0.025
    GETFUND_RATE = 0.025
    TOTAL_TAX_RATE = VAT_RATE + NHIL_RATE + GETFUND_RATE  # 20%
    if vat_inclusive:
        base_amount = round(gross_amount / (1 + TOTAL_TAX_RATE), 2)
    else:
        base_amount = gross_amount
    vat_amount = round(base_amount * VAT_RATE, 2)
    nhil_amount = round(base_amount * NHIL_RATE, 2)
    getfund_amount = round(base_amount * GETFUND_RATE, 2)
    total_tax = vat_amount + nhil_amount + getfund_amount
    total_amount = base_amount + total_tax
    return ok({
        'base_amount': base_amount,
        'vat_amount': vat_amount,
        'nhil_amount': nhil_amount,
        'getfund_amount': getfund_amount,
        'total_tax': round(total_tax, 2),
        'total_amount': round(total_amount, 2),
        'vat_rate_pct': 15.0,
        'nhil_rate_pct': 2.5,
        'getfund_rate_pct': 2.5
    })


