def api_save_leave_request(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not data:
        return err('No data provided')
    employee_name = (data.get('employee_name') or '').strip()
    leave_type = (data.get('leave_type') or '').strip()
    start_date = (data.get('start_date') or '').strip()
    end_date = (data.get('end_date') or '').strip()
    if not employee_name or not leave_type or not start_date or not end_date:
        return err('employee_name, leave_type, start_date, end_date are required')
    import uuid as _uuid, datetime as _dt
    try:
        sd = _dt.date.fromisoformat(start_date)
        ed = _dt.date.fromisoformat(end_date)
        days = (ed - sd).days + 1
        if days <= 0:
            return err('End date must be after start date')
    except Exception:
        return err('Invalid dates')
    conn = get_db()
    try:
        req_id = str(_uuid.uuid4())
        conn.execute(
            """INSERT INTO leave_requests(id,employee_id,employee_name,leave_type,start_date,end_date,
               days_requested,reason,status,created_by)
               VALUES(?,?,?,?,?,?,?,?,'Pending',?)""",
            (req_id, data.get('employee_id') or None, employee_name, leave_type,
             start_date, end_date, days, data.get('reason') or None, session.get('username'))
        )
        conn.commit()
        return ok({'request_id': req_id, 'days_requested': days})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_action_leave_request(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not _f53_is_admin(session):
        return err('Admin only')
    req_id = (data.get('request_id') or '').strip()
    action = (data.get('action') or '').strip()
    if not req_id or action not in ('Approved', 'Rejected'):
        return err('request_id and action (Approved/Rejected) are required')
    import datetime as _dt
    conn = get_db()
    try:
        conn.execute(
            "UPDATE leave_requests SET status=?,approved_by=?,approved_at=?,notes=? WHERE id=?",
            (action, session.get('username'), _dt.datetime.utcnow().isoformat(), data.get('notes') or None, req_id)
        )
        conn.commit()
        return ok({'request_id': req_id, 'status': action})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


