def api_save_cagd_mapping(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not _f53_is_admin(session):
        return err('Admin only')
    if not data:
        return err('No data provided')
    internal_code = (data.get('internal_code') or '').strip()
    cagd_vote_code = (data.get('cagd_vote_code') or '').strip()
    if not internal_code or not cagd_vote_code:
        return err('internal_code and cagd_vote_code are required')
    import uuid as _uuid
