# ── Comparative Reports ──────────────────────────────────────────────────────

def api_comparative_report(self_or_sess, year1=None, year2=None, project_id=None):
    """Compare expenditure across two financial years."""
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    import datetime as _dt
    conn = get_db()
    try:
        cy = _dt.date.today().year
        year1 = year1 or str(cy - 1)
        year2 = year2 or str(cy)

        def get_year_data(yr):
            params = []
            q = """SELECT
                COALESCE(SUM(a.amount_ghs),0) as total_expenditure,
                COALESCE((SELECT SUM(fr.amount_ghs) FROM fund_receipts fr WHERE strftime('%Y',fr.receipt_date)=?),0) as total_income
                FROM actuals a WHERE is_posted=1 AND strftime('%Y',a.expense_date)=?"""
            params = [yr, yr]
            if project_id:
                q = """SELECT
                    COALESCE(SUM(a.amount_ghs),0) as total_expenditure,
                    COALESCE((SELECT SUM(fr.amount_ghs) FROM fund_receipts fr WHERE strftime('%Y',fr.receipt_date)=? AND fr.project_id=?),0) as total_income
                    FROM actuals a WHERE is_posted=1 AND strftime('%Y',a.expense_date)=? AND a.project_id=?"""
                params = [yr, project_id, yr, project_id]
            row = conn.execute(q, params).fetchone()
            return dict(row) if row else {'total_expenditure': 0, 'total_income': 0}

        d1 = get_year_data(year1)
        d2 = get_year_data(year2)

        # Budget comparison
        def get_budget(yr):
            _bcols = {c[1] for c in conn.execute("PRAGMA table_info(budgets)").fetchall()}
            _yx = ("strftime('%Y',start_date)" if 'start_date' in _bcols else
                   "substr(academic_year,1,4)" if 'academic_year' in _bcols else
                   "strftime('%Y',created_at)")
            q = "SELECT COALESCE(SUM(budget_ghs),0) FROM budgets WHERE " + _yx + "=?"
            p = [yr]
            if project_id:
                q = "SELECT COALESCE(SUM(budget_ghs),0) FROM budgets WHERE " + _yx + "=? AND project_id=?"
                p = [yr, project_id]
            row = conn.execute(q, p).fetchone()
            return _f53_f(row[0] if row else 0)

        b1 = get_budget(year1)
        b2 = get_budget(year2)

        exp1 = _f53_f(d1.get('total_expenditure', 0))
        exp2 = _f53_f(d2.get('total_expenditure', 0))
        inc1 = _f53_f(d1.get('total_income', 0))
        inc2 = _f53_f(d2.get('total_income', 0))

        exp_change = exp2 - exp1
        inc_change = inc2 - inc1
        exp_pct = round((exp_change / exp1 * 100) if exp1 else 0, 1)
        inc_pct = round((inc_change / inc1 * 100) if inc1 else 0, 1)

        return ok({
            'year1': year1, 'year2': year2,
            'year1_income': round(inc1, 2), 'year2_income': round(inc2, 2),
            'year1_expenditure': round(exp1, 2), 'year2_expenditure': round(exp2, 2),
            'year1_budget': round(b1, 2), 'year2_budget': round(b2, 2),
            'year1_surplus': round(inc1 - exp1, 2), 'year2_surplus': round(inc2 - exp2, 2),
            'expenditure_change': round(exp_change, 2), 'expenditure_change_pct': exp_pct,
            'income_change': round(inc_change, 2), 'income_change_pct': inc_pct,
        })
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


