def api_initiate_project_closeout(self_or_sess, data):
    session = self_or_sess
    if not session:
        return err('Not authenticated')
    if not _f53_is_admin(session):
        return err('Admin only')
    if not data:
        return err('No data provided')
    project_id = (data.get('project_id') or '').strip()
    closeout_date = (data.get('closeout_date') or '').strip()
    if not project_id or not closeout_date:
        return err('project_id and closeout_date are required')
    import uuid as _uuid
    conn = get_db()
    try:
        # Check no existing open closeout
        existing = conn.execute(
            "SELECT id FROM project_closeouts WHERE project_id=? AND status NOT IN ('Completed','Cancelled')",
            (project_id,)
        ).fetchone()
        if existing:
            return err('An active closeout already exists for this project')

        # Compute final figures
        total_exp = _f53_f((conn.execute(
            "SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE project_id=?", (project_id,)
        ).fetchone() or [0])[0])
        total_inc = _f53_f((conn.execute(
            "SELECT COALESCE(SUM(amount_ghs),0) FROM fund_receipts WHERE project_id=?", (project_id,)
        ).fetchone() or [0])[0])
        surplus = total_inc - total_exp
        surplus_refunded = _f53_f(data.get('surplus_refunded_ghs') or 0)

        closeout_id = str(_uuid.uuid4())
        conn.execute(
            """INSERT INTO project_closeouts(id,project_id,closeout_date,final_expenditure_ghs,final_income_ghs,
               surplus_refunded_ghs,status,prepared_by,notes)
               VALUES(?,?,?,?,?,?,'Initiated',?,?)""",
            (closeout_id, project_id, closeout_date, round(total_exp, 2), round(total_inc, 2),
             surplus_refunded, session.get('username'), data.get('notes') or None)
        )
        # Mark project as Closed
        conn.execute("UPDATE projects SET status='Closed' WHERE id=?", (project_id,))
        conn.commit()
        return ok({
            'closeout_id': closeout_id,
            'final_expenditure_ghs': round(total_exp, 2),
            'final_income_ghs': round(total_inc, 2),
            'surplus': round(surplus, 2)
        })
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


