def api_sfp_v556(session, date_from=None, date_to=None, unit_code=None, project_id=None):
    if not session: return err('Not authenticated')
    import datetime as _dtm
    as_at = date_to or _dtm.date.today().isoformat()
    conn = get_db()
    try:
        # Statement of Financial Position derived ENTIRELY from the GENERAL LEDGER so it
        # reconciles to the Trial Balance (Assets = Liabilities + Net Assets). Previously
        # this read bank_accounts / fund_receipts / commitments and did NOT tie to the GL
        # (open commitments were wrongly shown as payables and cash ignored GL postings).
        gl_f = ''; gl_p = []
        if project_id:
            gl_f += " AND gl.project_id=?"; gl_p.append(project_id)
        # UCC scope/node (Phase 1c/3e) — see api_income_expenditure_v556 for rationale.
        _node = unit_code if (unit_code and '_ucc_subtree_unit_ids' in globals() and _ucc_subtree_unit_ids(conn, unit_code)) else None
        _uf, _up = (_ucc_gl_scope_clause(conn, session, _node) if '_ucc_gl_scope_clause' in globals() else ('', []))
        gl_f += _uf; gl_p += _up
        if unit_code and not _node:
            gl_f += " AND gl.project_id IN (SELECT id FROM projects WHERE division=?)"; gl_p.append(unit_code)

        def _nature(code, cat, typ):
            c0 = (code or '')[:1]
            if cat == 'Assets' or typ == 'Asset' or c0 == '1': return 'A'
            if cat == 'Liabilities' or typ == 'Liability' or c0 == '2': return 'L'
            if cat in ('Equity', 'Net Assets', 'Reserves') or typ == 'Equity' or c0 == '3': return 'Q'
            if cat == 'Revenue' or typ in ('Income', 'Revenue') or c0 == '4': return 'R'
            if cat == 'Expenses' or typ == 'Expense' or c0 in ('5', '6'): return 'E'
            return '?'

        def _compute_sfp(asof):
            rows = conn.execute(
                "SELECT COALESCE(NULLIF(gl.coa_code,''), c.code, '') AS code, "
                "       COALESCE(c.category,'') AS cat, COALESCE(c.account_type,'') AS typ, "
                "       COALESCE(gl.account_name, c.account_name, '') AS nm, "
                "       SUM(COALESCE(gl.debit_amount,0))  AS dr, "
                "       SUM(COALESCE(gl.credit_amount,0)) AS cr "
                "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                "WHERE gl.ledger_date<=? " + gl_f +
                " GROUP BY code, nm", [asof] + gl_p).fetchall()

            cash = 0.0; receivables = 0.0; inventory = 0.0
            fixed_cost = 0.0; intangibles = 0.0; accum_dep = 0.0
            # Liability buckets (IPSAS 1.70/1.88 current vs non-current + face lines).
            payables = 0.0; wht_held = 0.0
            provisions = 0.0; deferred_grant = 0.0; employee_benefits = 0.0
            nc_payables = 0.0  # explicitly long-term/non-current other liabilities
            equity_contrib = 0.0; income = 0.0; expense = 0.0
            for code, cat, typ, nm, dr, cr in rows:
                dr = float(dr or 0); cr = float(cr or 0); n = _nature(code, cat, typ)
                nml = (nm or '').lower(); code = code or ''
                if n == 'A':
                    bal = dr - cr  # asset accounts are debit-normal
                    # Cash & cash equivalents — MUST match the Cash Flow definition
                    # (api_cashflow_v556 CASH): bank/cash/MoMo + fixed deposits (126) +
                    # accountable imprest (1290xxx) + Special Advance (12300002).
                    if (code[:3] in ('126', '127') or code[:4] == '1001'
                            or code[:4] == '1290' or code == '12300002'
                            or any(k in nml for k in ('bank', 'cash', 'momo', 'mobile money', 'imprest'))):
                        cash += bal
                    elif 'depreciation' in nml or 'amortis' in nml or 'amortiz' in nml or code[:3] == '119':
                        accum_dep += -bal  # contra-asset / accumulated depreciation carries a credit balance
                    elif code[:3] == '111':
                        fixed_cost += bal          # property, plant & equipment at cost
                    elif code[:3] == '112':
                        intangibles += bal         # intangible assets (e.g. computer software)
                    elif code[:3] == '121':
                        inventory += bal           # inventories / stocks
                    else:
                        receivables += bal
                elif n == 'L':
                    bal = cr - dr  # liabilities are credit-normal
                    # Provisions (IPSAS 19) — e.g. 21501004 Provision for Audit Fees.
                    if (code[:3] == '215' or 'provision' in nml):
                        provisions += bal
                    # Deferred / conditional grant income (IPSAS 23) — restricted donor
                    # and project balances held as a liability until conditions are met.
                    elif (code[:3] == '225' or 'deferred' in nml or 'fund held' in nml
                          or 'restricted' in nml or ('grant' in nml and 'income' in nml)
                          or ('conditional' in nml and 'grant' in nml)):
                        deferred_grant += bal
                    # Employee-benefit obligations (IPSAS 25) — PAYE / SSNIT / pension /
                    # gratuity / end-of-service payable to or on behalf of staff.
                    elif (code in ('21100015', '21100017')
                          or 'paye' in nml or 'ssnit' in nml or 'social security' in nml
                          or 'pension' in nml or 'gratuity' in nml or 'end of service' in nml
                          or 'employee benefit' in nml or 'staff benefit' in nml):
                        employee_benefits += bal
                    # Statutory amounts withheld pending remittance: WHT (GRA / 21100014),
                    # VAT Withholding (21100024) and the UCC Common Fund (21100027).
                    elif ('withhold' in nml or nml.startswith('wht') or ' wht' in nml
                          or 'common fund' in nml
                          or code in ('21100014', '21100024', '21100027')):
                        wht_held += bal
                    # Long-term borrowings / loans → non-current other liabilities.
                    elif ('loan' in nml or 'borrow' in nml or 'long-term' in nml
                          or 'long term' in nml or 'lease liabilit' in nml):
                        nc_payables += bal
                    else:
                        payables += bal
                elif n == 'Q':
                    equity_contrib += (cr - dr)
                elif n == 'R':
                    income += (cr - dr)
                elif n == 'E':
                    expense += (dr - cr)

            fixed_nbv = round(fixed_cost - accum_dep, 2)
            non_current_assets = round(fixed_nbv + intangibles, 2)
            current_assets = round(cash + receivables + inventory, 2)
            total_assets = round(non_current_assets + current_assets, 2)
            # IPSAS 1.70/1.88 maturity split. Provisions, deferred grant income and
            # employee benefits are presented as non-current unless they are expected to
            # be settled within twelve months; here grant income & employee/long-term
            # obligations are taken as non-current and audit-fee provisions, WHT and
            # trade payables as current — the most conservative public-sector default.
            current_liabilities = round(payables + wht_held + provisions, 2)
            non_current_liabilities = round(deferred_grant + employee_benefits + nc_payables, 2)
            total_liabilities = round(current_liabilities + non_current_liabilities, 2)
            surplus = round(income - expense, 2)
            net_assets = round(equity_contrib + surplus, 2)
            presentation_diff = round(total_assets - (total_liabilities + net_assets), 2)

            return {
                'as_at': asof,
                'assets': {
                    'cash_and_bank': round(cash, 2),
                    'receivables': round(receivables, 2),
                    'inventory': round(inventory, 2),
                    'fixed_assets_cost': round(fixed_cost, 2),
                    'accumulated_depreciation': round(accum_dep, 2),
                    'fixed_assets_nbv': fixed_nbv,
                    'intangibles': round(intangibles, 2),
                    'non_current_total': non_current_assets,
                    'current_total': current_assets,
                    'total': total_assets
                },
                'liabilities': {
                    # Existing fields retained for the frontend (do not remove).
                    'payables': round(payables, 2),
                    'wht_held': round(wht_held, 2),
                    # New IPSAS 1.70/1.88 face lines.
                    'provisions': round(provisions, 2),
                    'deferred_grant_income': round(deferred_grant, 2),
                    'employee_benefits': round(employee_benefits, 2),
                    'other_non_current': round(nc_payables, 2),
                    'current_total': current_liabilities,
                    'non_current_total': non_current_liabilities,
                    'current': {
                        'payables': round(payables, 2),
                        'wht_held': round(wht_held, 2),
                        'provisions': round(provisions, 2),
                        'total': current_liabilities,
                    },
                    'non_current': {
                        'deferred_grant_income': round(deferred_grant, 2),
                        'employee_benefits': round(employee_benefits, 2),
                        'other': round(nc_payables, 2),
                        'total': non_current_liabilities,
                    },
                    'total': total_liabilities
                },
                'net_assets': net_assets,
                'equity': {
                    'contributed_funds': round(equity_contrib, 2),
                    'accumulated_surplus': surplus,
                    'total': net_assets
                },
                'presentation_difference': presentation_diff,
            }

        cur = _compute_sfp(as_at)
        # IPSAS 1.53 — prior year-end comparative, as-at one year earlier, same GL basis.
        prior_as_at = _prior_year_end(as_at)
        prior = _compute_sfp(prior_as_at)

        out = dict(cur)
        out['basis'] = 'general_ledger'
        out['unit_code'] = unit_code
        out['project_id'] = project_id
        out['comparative'] = prior
        out['prior_year'] = prior
        return ok(out)
    except Exception as e:
        return err('SFP report error: ' + str(e))
    finally:
        conn.close()


def api_changes_in_net_assets_v1(session, date_from=None, date_to=None, project_id=None, unit_code=None):
    """Statement of Changes in Net Assets / Equity (IPSAS 1). Derived entirely from the
    GENERAL LEDGER so it reconciles to the SFP: opening net assets + surplus for the
    period + contributed-capital movements = closing net assets."""
    if not session:
        return err('Not authenticated')
    import datetime as _dtm
    if not date_from:
        date_from = _dtm.date.today().strftime('%Y-01-01')
    if not date_to:
        date_to = _dtm.date.today().isoformat()
    conn = get_db()
    try:
        gl_f = ''; gl_p = []
        if project_id:
            gl_f += ' AND gl.project_id=?'; gl_p.append(project_id)
        if unit_code:
            gl_f += ' AND gl.project_id IN (SELECT id FROM projects WHERE division=?)'; gl_p.append(unit_code)

        def components(cond, params):
            q = ("SELECT COALESCE(NULLIF(gl.coa_code,''),c.code,'') AS code, "
                 "COALESCE(c.category,'') AS cat, COALESCE(c.account_type,'') AS typ, "
                 "SUM(COALESCE(gl.debit_amount,0)) AS dr, SUM(COALESCE(gl.credit_amount,0)) AS cr "
                 "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                 "WHERE " + cond + gl_f + " GROUP BY code")
            contrib = 0.0; income = 0.0; expense = 0.0
            for code, cat, typ, dr, cr in conn.execute(q, params + gl_p).fetchall():
                dr = float(dr or 0); cr = float(cr or 0); c0 = (code or '')[:1]
                if cat in ('Equity', 'Net Assets', 'Reserves', 'Funds & Reserves') or typ == 'Equity' or c0 == '3':
                    contrib += (cr - dr)
                elif cat == 'Revenue' or typ in ('Income', 'Revenue') or c0 == '4':
                    income += (cr - dr)
                elif cat == 'Expenses' or typ == 'Expense' or c0 in ('5', '6'):
                    expense += (dr - cr)
            return round(contrib, 2), round(income - expense, 2)

        def _movement(d_from, d_to):
            c_open, s_open = components('gl.ledger_date < ?', [d_from])
            c_close, s_close = components('gl.ledger_date <= ?', [d_to])
            return {
                'date_from': d_from, 'date_to': d_to,
                'opening': {'contributed': c_open, 'accumulated_surplus': s_open,
                            'total': round(c_open + s_open, 2)},
                'surplus_for_period': round(s_close - s_open, 2),
                'contributions': round(c_close - c_open, 2),
                'closing': {'contributed': c_close, 'accumulated_surplus': s_close,
                            'total': round(c_close + s_close, 2)},
            }

        cur = _movement(date_from, date_to)
        # IPSAS 1.53 — prior financial-year comparative on the same GL basis. The prior
        # closing equals the current opening, so the two statements articulate.
        p_from, p_to = _prior_fy_window(date_from, date_to)
        prior = _movement(p_from, p_to)
        out = dict(cur)
        out['basis'] = 'general_ledger'
        out['project_id'] = project_id
        out['unit_code'] = unit_code
        out['comparative'] = prior
        out['prior_year'] = prior
        return ok(out)
    except Exception as e:
        return err('Changes in net assets error: ' + str(e))
    finally:
        conn.close()


# ── Notes to the Financial Statements (IPSAS 1 / IFRS) ────────────────────────
def api_notes_to_accounts(session, as_at=None, date_from=None, date_to=None, unit_code=None, project_id=None):
    """Notes to the Financial Statements: accounting policies + a GL-derived,
    account-level breakdown of every balance-sheet and performance line, tying to the
    SFP and the Income & Expenditure statement. Prepared on the IPSAS accrual basis."""
    if not session:
        return err('Not authenticated')
    import datetime as _dt
    as_at = (as_at or _dt.date.today().isoformat())[:10]
    yr = as_at[:4]
    date_from = (date_from or (yr + '-01-01'))[:10]
    date_to = (date_to or as_at)[:10]
    conn = get_db()
    try:
        gl_f = ''; gl_p = []
        if project_id:
            gl_f += " AND gl.project_id=?"; gl_p.append(project_id)
        if unit_code:
            gl_f += " AND gl.project_id IN (SELECT id FROM projects WHERE division=?)"; gl_p.append(unit_code)
        _sel = ("SELECT COALESCE(NULLIF(gl.coa_code,''),c.code,'') code, c.category cat, c.account_type typ, "
                "c.sub_category subcat, COALESCE(gl.account_name,c.account_name,'') nm, "
                "SUM(COALESCE(gl.debit_amount,0)) dr, SUM(COALESCE(gl.credit_amount,0)) cr "
                "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id ")
        bs = conn.execute(_sel + "WHERE gl.ledger_date<=? " + gl_f + " GROUP BY code, nm",
                          [as_at] + gl_p).fetchall()
        pl = conn.execute(_sel + "WHERE gl.ledger_date BETWEEN ? AND ? " + gl_f + " GROUP BY code, nm",
                          [date_from, date_to] + gl_p).fetchall()

        def _nat(code, cat, typ):
            c0 = (code or '')[:1]
            if cat == 'Assets' or typ == 'Asset' or c0 == '1': return 'A'
            if cat == 'Liabilities' or typ == 'Liability' or c0 == '2': return 'L'
            if cat in ('Equity', 'Net Assets', 'Reserves') or typ == 'Equity' or c0 == '3': return 'Q'
            if cat == 'Revenue' or typ in ('Income', 'Revenue') or c0 == '4': return 'R'
            if cat == 'Expenses' or typ == 'Expense' or c0 in ('5', '6'): return 'E'
            return '?'

        cash = []; recv = []; inv = []; ppe_cost = []; ppe_dep = []; intang = []
        pay_trade = []; pay_stat = []; deferred = []; equity = []

        def _add(lst, code, nm, amt):
            if abs(amt) > 0.005:
                lst.append({'code': code, 'label': nm or code, 'amount': round(amt, 2)})

        for code, cat, typ, subcat, nm, dr, cr in bs:
            code = code or ''; nml = (nm or '').lower(); dr = float(dr or 0); cr = float(cr or 0)
            n = _nat(code, cat, typ)
            if n == 'A':
                bal = dr - cr
                if (code[:3] in ('126', '127') or code[:4] == '1001' or code[:4] == '1290' or code == '12300002'
                        or any(k in nml for k in ('bank', 'cash', 'momo', 'mobile money', 'imprest'))):
                    _add(cash, code, nm, bal)
                elif 'depreciation' in nml or 'amortis' in nml or 'amortiz' in nml or code[:3] == '119':
                    _add(ppe_dep, code, nm, -bal)
                elif code[:3] == '111':
                    _add(ppe_cost, code, nm, bal)
                elif code[:3] == '112':
                    _add(intang, code, nm, bal)
                elif code[:3] == '121':
                    _add(inv, code, nm, bal)
                else:
                    _add(recv, code, nm, bal)
            elif n == 'L':
                bal = cr - dr
                if code[:3] == '225' or 'deferred' in nml or 'fund held' in nml or 'restricted' in nml or 'grant' in nml:
                    _add(deferred, code, nm, bal)
                elif (code in ('21100017', '21100015', '21100014', '21100024', '21100027')
                      or 'paye' in nml or 'ssnit' in nml or 'withhold' in nml or 'vat' in nml
                      or nml.startswith('wht') or 'common fund' in nml or 'social security' in nml):
                    _add(pay_stat, code, nm, bal)
                else:
                    _add(pay_trade, code, nm, bal)
            elif n == 'Q':
                _add(equity, code, nm, cr - dr)

        rev = []; exp_groups = {}
        for code, cat, typ, subcat, nm, dr, cr in pl:
            code = code or ''; dr = float(dr or 0); cr = float(cr or 0); n = _nat(code, cat, typ)
            if n == 'R':
                _add(rev, code, nm, cr - dr)
            elif n == 'E':
                _add(exp_groups.setdefault(subcat or 'Other expenditure', []), code, nm, dr - cr)

        def _tot(lst):
            return round(sum(x['amount'] for x in lst), 2)

        income_total = _tot(rev)
        expense_total = round(sum(_tot(v) for v in exp_groups.values()), 2)
        surplus = round(income_total - expense_total, 2)
        ppe_cost_t = _tot(ppe_cost); ppe_dep_t = _tot(ppe_dep)
        equity_lines = list(equity) + [{'code': '', 'label': 'Accumulated surplus / (deficit) for the period and prior years', 'amount': surplus}]

        def _note(num, title, basis, lines, total=None, note=None, extra=None):
            d = {'number': num, 'title': title, 'basis': basis, 'lines': lines,
                 'total': total if total is not None else _tot(lines)}
            if note: d['narrative'] = note
            if extra: d['extra'] = extra
            return d

        notes = []
        notes.append(_note(1, 'Cash and cash equivalents', 'As at ' + as_at, cash,
                           note='Cash and cash equivalents comprise balances with banks, cash on hand, '
                                'mobile-money floats, accountable imprest and special advances that are '
                                'readily convertible to known amounts of cash (IPSAS 2).'))
        notes.append(_note(2, 'Receivables, prepayments and advances', 'As at ' + as_at, recv,
                           note='Receivables are stated at amortised cost less any impairment. Includes staff '
                                'and student debtors, prepayments and recoverable advances (IPSAS 29 / IFRS 9).'))
        if inv:
            notes.append(_note(len(notes) + 1, 'Inventories', 'As at ' + as_at, inv,
                               note='Inventories (including fuel-coupon stock) are measured at the lower of cost '
                                    'and net realisable value, cost determined on a weighted-average basis (IPSAS 12).'))
        notes.append(_note(len(notes) + 1, 'Property, plant and equipment', 'As at ' + as_at,
                           ppe_cost + [{'code': '', 'label': 'Less: accumulated depreciation', 'amount': -ppe_dep_t}],
                           total=round(ppe_cost_t - ppe_dep_t, 2),
                           note='PP&E is carried at cost less accumulated depreciation and impairment. '
                                'Depreciation is on a straight-line basis over useful lives (IPSAS 17).',
                           extra={'cost': ppe_cost_t, 'accumulated_depreciation': ppe_dep_t,
                                  'net_book_value': round(ppe_cost_t - ppe_dep_t, 2)}))
        if intang:
            notes.append(_note(len(notes) + 1, 'Intangible assets', 'As at ' + as_at, intang,
                               note='Intangible assets are carried at cost less amortisation (IPSAS 31).'))
        notes.append(_note(len(notes) + 1, 'Payables and accruals', 'As at ' + as_at, pay_trade,
                           note='Trade and other payables and accrued expenses are stated at amortised cost and '
                                'represent obligations for goods and services received before period-end.'))
        if pay_stat:
            notes.append(_note(len(notes) + 1, 'Statutory and tax liabilities', 'As at ' + as_at, pay_stat,
                               note='Amounts withheld and due to statutory bodies — PAYE and SSNIT (employees), '
                                    'and withholding tax, withholding VAT and the UCC Common Fund deducted from '
                                    'payments to suppliers — pending remittance to GRA / SSNIT.'))
        if deferred:
            notes.append(_note(len(notes) + 1, 'Deferred income and funds held on behalf', 'As at ' + as_at, deferred,
                               note='Restricted donor/grant funds and project balances are recognised as deferred '
                                    'income (a liability) and released to revenue as the related conditions are met '
                                    '(IPSAS 23).'))
        notes.append(_note(len(notes) + 1, 'Accumulated fund and reserves', 'As at ' + as_at, equity_lines,
                           note='The accumulated fund represents the residual interest in the assets after deducting '
                                'liabilities, comprising contributed/opening funds and accumulated surpluses.'))
        notes.append(_note(len(notes) + 1, 'Revenue', 'For the period ' + date_from + ' to ' + date_to, rev,
                           note='Revenue is recognised on the accrual basis to the extent that the entity controls '
                                'the resources, it is probable that economic benefits will flow, and the amount can be '
                                'measured reliably (IPSAS 9 / IPSAS 23).'))
        exp_lines = []
        for grp in sorted(exp_groups.keys()):
            exp_lines.append({'code': '', 'label': grp, 'amount': _tot(exp_groups[grp]), 'group': True,
                              'children': exp_groups[grp]})
        notes.append(_note(len(notes) + 1, 'Expenditure', 'For the period ' + date_from + ' to ' + date_to, exp_lines,
                           total=expense_total,
                           note='Expenditure is recognised on the accrual basis when goods/services are received. '
                                'Grouped by expenditure class.'))

        # ── PP&E movement schedule (IPSAS 17.88) ────────────────────────────────
        # Cost: opening (pre-period), additions (period debits), disposals (period
        # credits), closing. Accumulated depreciation: opening, charge for the period,
        # closing. NBV = closing cost − closing accumulated depreciation. Derived from
        # the GL so it ties to the SFP PP&E line.
        def _ppe_movement():
            def _scl(q, params):
                try:
                    return round(float((conn.execute(q, params).fetchone() or [0])[0] or 0), 2)
                except Exception:
                    return 0.0
            cost_clause = ("(COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '111%' "
                           "OR COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '112%')")
            dep_clause = ("(COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '119%' "
                          "OR LOWER(COALESCE(gl.account_name,c.account_name,'')) LIKE '%depreciation%' "
                          "OR LOWER(COALESCE(gl.account_name,c.account_name,'')) LIKE '%amortis%' "
                          "OR LOWER(COALESCE(gl.account_name,c.account_name,'')) LIKE '%amortiz%')")
            base = ("FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id WHERE ")
            # Cost (debit-normal asset)
            cost_open = _scl("SELECT COALESCE(SUM(COALESCE(gl.debit_amount,0)-COALESCE(gl.credit_amount,0)),0) "
                             + base + cost_clause + " AND gl.ledger_date < ? " + gl_f, [date_from] + gl_p)
            additions = _scl("SELECT COALESCE(SUM(COALESCE(gl.debit_amount,0)),0) " + base + cost_clause
                             + " AND gl.ledger_date BETWEEN ? AND ? " + gl_f, [date_from, date_to] + gl_p)
            disposals = _scl("SELECT COALESCE(SUM(COALESCE(gl.credit_amount,0)),0) " + base + cost_clause
                             + " AND gl.ledger_date BETWEEN ? AND ? " + gl_f, [date_from, date_to] + gl_p)
            cost_close = round(cost_open + additions - disposals, 2)
            # Accumulated depreciation (credit-normal contra-asset, shown positive)
            dep_open = _scl("SELECT COALESCE(SUM(COALESCE(gl.credit_amount,0)-COALESCE(gl.debit_amount,0)),0) "
                            + base + dep_clause + " AND gl.ledger_date < ? " + gl_f, [date_from] + gl_p)
            dep_charge = _scl("SELECT COALESCE(SUM(COALESCE(gl.credit_amount,0)),0) " + base + dep_clause
                              + " AND gl.ledger_date BETWEEN ? AND ? " + gl_f, [date_from, date_to] + gl_p)
            dep_disp = _scl("SELECT COALESCE(SUM(COALESCE(gl.debit_amount,0)),0) " + base + dep_clause
                            + " AND gl.ledger_date BETWEEN ? AND ? " + gl_f, [date_from, date_to] + gl_p)
            dep_close = round(dep_open + dep_charge - dep_disp, 2)
            return {
                'cost': {'opening': cost_open, 'additions': additions, 'disposals': disposals,
                         'closing': cost_close},
                'accumulated_depreciation': {'opening': dep_open, 'charge_for_period': dep_charge,
                                             'disposals': dep_disp, 'closing': dep_close},
                'net_book_value': {'opening': round(cost_open - dep_open, 2),
                                   'closing': round(cost_close - dep_close, 2)},
            }
        ppe_movement = _ppe_movement()

        # ── Segment note BY UNIT (IPSAS 18) ─────────────────────────────────────
        # The org_units tree is the segmentation basis. Each posted GL line carries a
        # unit_id (→ org_units.id); revenue/expenditure for the period are reported per
        # unit so the segment surpluses sum to the entity surplus.
        segments = []
        try:
            seg_rows = conn.execute(
                "SELECT COALESCE(ou.code,'UNASSIGNED') AS ucode, "
                "COALESCE(ou.name,'Unassigned / shared') AS uname, "
                "COALESCE(SUM(CASE WHEN (COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '4%' "
                "    OR c.category='Revenue' OR c.account_type IN ('Income','Revenue')) "
                "    THEN COALESCE(gl.credit_amount,0)-COALESCE(gl.debit_amount,0) ELSE 0 END),0) AS rev, "
                "COALESCE(SUM(CASE WHEN (COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '5%' "
                "    OR COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '6%' "
                "    OR c.category='Expenses' OR c.account_type='Expense') "
                "    THEN COALESCE(gl.debit_amount,0)-COALESCE(gl.credit_amount,0) ELSE 0 END),0) AS exp "
                "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                "LEFT JOIN org_units ou ON ou.id=gl.unit_id "
                "WHERE gl.ledger_date BETWEEN ? AND ? " + gl_f +
                " GROUP BY ucode, uname ORDER BY ucode",
                [date_from, date_to] + gl_p).fetchall()
            for r in seg_rows:
                rv = round(float(r['rev'] or 0), 2); ex = round(float(r['exp'] or 0), 2)
                if abs(rv) > 0.005 or abs(ex) > 0.005:
                    segments.append({'unit_code': r['ucode'], 'unit_name': r['uname'],
                                     'revenue': rv, 'expenditure': ex,
                                     'surplus_deficit': round(rv - ex, 2)})
        except Exception:
            segments = []
        segment_note = {
            'number': len(notes) + 1,
            'title': 'Segment information (by organisational unit)',
            'basis': 'For the period ' + date_from + ' to ' + date_to,
            'segments': segments,
            'total_revenue': round(sum(s['revenue'] for s in segments), 2),
            'total_expenditure': round(sum(s['expenditure'] for s in segments), 2),
            'total_surplus_deficit': round(sum(s['surplus_deficit'] for s in segments), 2),
            'narrative': 'Segments are the self-accounting organisational units of the University '
                         '(faculties, schools, directorates and centres) per the approved org-unit '
                         'structure. Amounts not yet assigned to a unit are shown as a single '
                         'unallocated segment (IPSAS 18).',
        }

        # Commitments (open) as a disclosure
        commit_lines = []
        try:
            for r in conn.execute(
                    "SELECT p.project_code pc, COALESCE(SUM(cm.amount_ghs),0) amt FROM commitments cm "
                    "LEFT JOIN projects p ON p.id=cm.project_id WHERE cm.status='Open' "
                    "GROUP BY p.project_code HAVING amt>0").fetchall():
                commit_lines.append({'code': '', 'label': 'Open commitments — ' + (r['pc'] or 'General'), 'amount': round(float(r['amt'] or 0), 2)})
        except Exception:
            pass
        total_commitments = round(sum(c['amount'] for c in commit_lines), 2)

        # ── Provisions recognised (IPSAS 19), feeding the contingencies note ────
        provisions_lines = []
        try:
            for code, cat, typ, subcat, nm, dr, cr in bs:
                code = code or ''; nml = (nm or '').lower()
                if (code[:3] == '215' or 'provision' in nml):
                    _add(provisions_lines, code, nm, float(cr or 0) - float(dr or 0))
        except Exception:
            provisions_lines = []
        provisions_total = _tot(provisions_lines)

        # ── Related-party disclosures (IPSAS 20) ────────────────────────────────
        related_parties = {
            'number': 0, 'title': 'Related-party disclosures',
            'narrative': 'The reporting unit is controlled by the University of Cape Coast, whose '
                         'ultimate controlling party is the Government of Ghana. Related parties '
                         'comprise the Government of Ghana and its ministries and agencies (GETFund, '
                         'NCTE/GTEC, Ministry of Education and the Ghana Revenue Authority), the '
                         'University Council and the University management as the key management '
                         'personnel, and other self-accounting units of the University. Transactions '
                         'with related parties — Government subventions and GETFund grants, statutory '
                         'remittances to the Ghana Revenue Authority and SSNIT, and inter-unit '
                         'allocations — are conducted on normal public-sector terms (IPSAS 20).',
            'parties': [
                {'party': 'Government of Ghana', 'relationship': 'Ultimate controlling party / principal funder',
                 'nature': 'Recurrent subvention, GETFund recurrent and development grants'},
                {'party': 'University Council', 'relationship': 'Governing body / oversight',
                 'nature': 'Approval of budgets, financial statements and key policies'},
                {'party': 'University management (key management personnel)',
                 'relationship': 'Key management personnel',
                 'nature': 'Remuneration recognised within employee costs; no other material transactions'},
                {'party': 'Ghana Revenue Authority / SSNIT', 'relationship': 'Statutory bodies',
                 'nature': 'Remittance of PAYE, withholding taxes and social-security contributions'},
            ],
        }

        # ── Contingent liabilities and commitments (IPSAS 19.100) ───────────────
        contingencies = {
            'number': 0, 'title': 'Contingent liabilities and capital/other commitments',
            'narrative': 'Capital and operating commitments comprise approved but unpaid purchase '
                         'commitments (open commitments on the appropriation ledger). Provisions '
                         'recognised on the face of the statement of financial position (e.g. the '
                         'provision for audit fees) are remeasured at each reporting date. Save for '
                         'the matters disclosed below, the unit is not aware of any material '
                         'contingent liabilities or pending litigation at the reporting date (IPSAS 19).',
            'commitments': commit_lines,
            'commitments_total': total_commitments,
            'provisions': provisions_lines,
            'provisions_total': provisions_total,
            'pending_litigation': [],
        }

        # ── Unreserved statement of compliance with IPSAS (IPSAS 1.28) ──────────
        compliance_statement = {
            'title': 'Statement of compliance with IPSAS',
            'body': 'These financial statements have been prepared in accordance with, and comply '
                    'with, International Public Sector Accounting Standards (IPSAS) on the accrual '
                    'basis of accounting. As required by IPSAS 1.28, the unit makes an explicit and '
                    'unreserved statement of compliance: these financial statements comply with all '
                    'the requirements of the applicable IPSAS in all material respects.',
        }

        policies = [
            {'title': 'Reporting entity',
             'body': 'These financial statements are for ' + str(_org_full_name() if '_org_full_name' in globals() else 'the reporting unit')
                     + ', a self-accounting unit of the University of Cape Coast, Ghana.'},
            {'title': 'Basis of preparation',
             'body': 'The financial statements are prepared on the accrual basis of accounting and in accordance with '
                     'International Public Sector Accounting Standards (IPSAS), supplemented by IFRS where IPSAS is silent, '
                     'and the going-concern assumption. They are presented in Ghana Cedis (GHS), the functional currency.'},
            {'title': 'Property, plant and equipment',
             'body': 'PP&E is stated at historical cost less accumulated depreciation and impairment losses. Depreciation '
                     'is charged on a straight-line basis to write off the cost over the estimated useful life of each asset '
                     '(IPSAS 17).'},
            {'title': 'Inventories',
             'body': 'Inventories, including fuel-coupon stock held for issue, are measured at the lower of cost and net '
                     'realisable value (IPSAS 12).'},
            {'title': 'Revenue recognition',
             'body': 'Exchange revenue is recognised when control of services/goods passes. Non-exchange revenue (grants, '
                     'subventions, donations) is recognised when the entity gains control of the resources and conditions, '
                     'if any, are satisfied; conditional grants are deferred until conditions are met (IPSAS 9 / 23).'},
            {'title': 'Employee benefits and taxes',
             'body': 'Salaries, PAYE and SSNIT contributions are recognised in the period the related service is rendered. '
                     'Withholding tax, withholding VAT and the UCC Common Fund are deducted at source on qualifying payments '
                     'and held as liabilities until remitted to the Ghana Revenue Authority.'},
            {'title': 'Financial instruments',
             'body': 'Financial assets (receivables, cash) and financial liabilities (payables) are recognised at amortised '
                     'cost. Receivables are assessed for impairment at each reporting date (IPSAS 41 / IFRS 9).'},
        ]

        # Attach the PP&E movement schedule to the PP&E note's `extra` (IPSAS 17.88).
        for _n in notes:
            if _n.get('title') == 'Property, plant and equipment':
                _n.setdefault('extra', {})['movement'] = ppe_movement
                break

        # Append the new disclosure notes with running numbers.
        related_parties['number'] = len(notes) + 1; notes.append(related_parties)
        segment_note['number'] = len(notes) + 1;    notes.append(segment_note)
        contingencies['number'] = len(notes) + 1;   notes.append(contingencies)

        return ok({
            'entity': {'name': (_org_full_name() if '_org_full_name' in globals() else 'Reporting unit'),
                       'parent': 'University of Cape Coast, Ghana'},
            'as_at': as_at, 'period_from': date_from, 'period_to': date_to,
            'compliance_statement': compliance_statement,
            'policies': policies,
            'notes': notes,
            'ppe_movement': ppe_movement,
            'related_parties': related_parties,
            'segments': segment_note,
            'contingencies': contingencies,
            'commitments': commit_lines,
            'reconciliation': {
                'total_assets': round(_tot(cash) + _tot(recv) + _tot(inv) + (ppe_cost_t - ppe_dep_t) + _tot(intang), 2),
                'total_liabilities': round(_tot(pay_trade) + _tot(pay_stat) + _tot(deferred), 2),
                'net_assets': round(_tot(equity) + surplus, 2),
                'income': income_total, 'expenditure': expense_total, 'surplus': surplus,
            },
            'basis': 'general_ledger',
        })
    except Exception as e:
        return err('Notes to the accounts error: ' + str(e))
    finally:
        conn.close()


# ── Statement of Cash Flows ───────────────────────────────────────────────────
def api_cashflow_v556(session, date_from=None, date_to=None, project_id=None, unit=None):
    if not session: return err('Not authenticated')
    import datetime as _dtm
    if not date_from: date_from = _dtm.date.today().strftime('%Y-01-01')
    if not date_to:   date_to   = _dtm.date.today().isoformat()
    conn = get_db()
    try:
        # Cash Flow derived from the GENERAL LEDGER: the actual movement on cash/bank
        # accounts, classified by the contra (non-cash) legs of each journal. This ties
        # to the GL cash balance and reflects EVERY posted entry (PVs, payroll, receipts,
        # manual JVs) — previously it read only fund_receipts/actuals and missed JVs.
        gl_f = ''; gl_p = []
        if project_id: gl_f += " AND gl.project_id=?"; gl_p.append(project_id)
        # UCC scope/node (Phase 1c/3e) — enforce viewer scope; treat `unit` as an org
        # node when it resolves to one, else keep the legacy division filter.
        _node = unit if (unit and '_ucc_subtree_unit_ids' in globals() and _ucc_subtree_unit_ids(conn, unit)) else None
        _uf, _up = (_ucc_gl_scope_clause(conn, session, _node) if '_ucc_gl_scope_clause' in globals() else ('', []))
        gl_f += _uf; gl_p += _up
        if unit and not _node:
            gl_f += " AND gl.project_id IN (SELECT id FROM projects WHERE division=?)"; gl_p.append(unit)

        CASH = ("(COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '126%' "
                "OR COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '127%' "
                "OR COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '1001%' "
                "OR LOWER(COALESCE(gl.account_name,c.account_name,'')) LIKE '%bank%' "
                "OR LOWER(COALESCE(gl.account_name,c.account_name,'')) LIKE '%cash%' "
                "OR LOWER(COALESCE(gl.account_name,c.account_name,'')) LIKE '%momo%' "
                # Accountable imprest & special advance are cash & cash equivalents (IPSAS):
                "OR COALESCE(NULLIF(gl.coa_code,''),c.code,'') = '12300002' "
                "OR COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '1290%' "
                "OR (LOWER(COALESCE(gl.account_name,c.account_name,'')) LIKE '%imprest%' "
                "    AND COALESCE(NULLIF(gl.coa_code,''),c.code,'') LIKE '12%'))")

        # Opening-balance journals are the OPENING cash position, not a period cash
        # flow — exclude them from the period and fold their cash into opening cash.
        OB_SRC = "('opening_balance','opening_balance_import','bank_opening_balance')"
        def _cash_legs(d1, d2):
            q = ("SELECT gl.jv_number, "
                 "SUM(COALESCE(gl.debit_amount,0)-COALESCE(gl.credit_amount,0)) AS net "
                 "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                 "LEFT JOIN journal_vouchers jv2 ON jv2.id=gl.jv_id "
                 "WHERE " + CASH + " AND gl.ledger_date BETWEEN ? AND ? "
                 "AND COALESCE(jv2.source_module,'') NOT IN " + OB_SRC + " " + gl_f +
                 " GROUP BY gl.jv_number")
            return conn.execute(q, [d1, d2] + gl_p).fetchall()

        # Contra (non-cash) legs of every journal touching cash in a period.
        def _contra_map(d1, d2):
            cmap = {}
            cq = ("SELECT gl.jv_number, COALESCE(NULLIF(gl.coa_code,''),c.code,'') AS code, "
                  "LOWER(COALESCE(gl.account_name,c.account_name,'')) AS nm "
                  "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                  "WHERE NOT " + CASH + " AND gl.ledger_date BETWEEN ? AND ? " + gl_f)
            for jv, code, nm in conn.execute(cq, [d1, d2] + gl_p).fetchall():
                cmap.setdefault(jv, []).append((code or '', nm or ''))
            return cmap

        # Only UNAMBIGUOUS payroll accounts: Basic Salary (61101001), PAYE (21100017),
        # SSNIT (21100015). The generic liabilities previously listed — Sundry Creditors
        # (21100021) and Accrued Expenses (21200005) — hold all kinds of payables (refunds,
        # supplier accruals, etc.), so settling them was wrongly shown as 'Staff Emoluments'.
        PAYROLL_CODES = {'61101001', '21100017', '21100015'}
        def _classify(jv, contra):
            legs = contra.get(jv, [])
            codes = [c for c, _ in legs]; names = [n for _, n in legs]
            # Investing = acquisition/disposal of PP&E (code 111x) or intangibles (112x),
            # keyed on the COA CODE ONLY. Matching account NAMES (e.g. 'equipment') wrongly
            # swept expense accounts such as 'Maintenance of Equipment' (615xxxx) into PP&E
            # acquisitions — no asset was bought. Real PP&E purchases post to 111x; a
            # disposal credits 111x; both are correctly caught by the code prefix.
            if any(c[:3] in ('111', '112') for c in codes):
                return 'investing'
            if any(c[:1] == '3' for c in codes) or any(('loan' in n) or ('borrow' in n) or ('deferred' in n and 'grant' in n) for n in names):
                return 'financing'
            if any(c in PAYROLL_CODES for c in codes) or any(('salary' in n) or ('payroll' in n) or ('paye' in n) or ('ssnit' in n) or ('wages' in n) for n in names):
                return 'payroll'
            # Expense-backed operating cash = supplier/operating PAYMENTS (and their
            # reversals/refunds). The EXPENSE leg (5xxx/6xxx) is the PURPOSE of the cash
            # movement; incidental tax-liability legs (GRA/VAT/UCF withholding, all
            # 21xxxxx) are ignored. Checked BEFORE the income test so a withholding
            # agency literally named "Ghana REVENUE Authority" is never mistaken for
            # revenue. A cash INFLOW here (a payment reversal) NETS AGAINST payments
            # rather than appearing as phantom "Receipts from Donors".
            if any(c[:1] in ('5', '6') for c in codes) or any(('expense' in n) or ('stationery' in n) or ('maintenance' in n) or ('supplier' in n) for n in names):
                return 'operating_payment'
            # Genuine RECEIPTS are income/revenue-backed only (4xxx, or clearly named
            # grant/donation/tuition/subvention) — never a tax liability.
            if any(c[:1] == '4' for c in codes) or any(('grant' in n) or ('donat' in n) or ('tuition' in n) or ('subvention' in n) for n in names):
                return 'operating_receipt'
            return 'operating_payment'

        def _compute_cf(d1, d2):
            contra = _contra_map(d1, d2)
            op_in = 0.0; op_out = 0.0; payroll = 0.0
            inv_acq = 0.0; inv_disp = 0.0; fin_in = 0.0; fin_out = 0.0
            for jv, net in _cash_legs(d1, d2):
                net = float(net or 0); kind = _classify(jv, contra)
                if kind == 'investing':
                    if net >= 0: inv_disp += net
                    else: inv_acq += -net
                elif kind == 'financing':
                    if net >= 0: fin_in += net
                    else: fin_out += -net
                elif kind == 'payroll':
                    # payroll cash outflow; a reversal/refund (inflow) reduces it
                    payroll += -net
                elif kind == 'operating_receipt':
                    # income-backed receipt; a donor refund (outflow) reduces it
                    op_in += net
                else:  # operating_payment — supplier/operating cash, net of refunds & reversals
                    op_out += -net

            net_operating = round(op_in - op_out - payroll, 2)
            net_investing = round(inv_disp - inv_acq, 2)
            net_financing = round(fin_in - fin_out, 2)
            net_change = round(net_operating + net_investing + net_financing, 2)

            opening_cash = float((conn.execute(
                "SELECT COALESCE(SUM(COALESCE(gl.debit_amount,0)-COALESCE(gl.credit_amount,0)),0) "
                "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                "LEFT JOIN journal_vouchers jv2 ON jv2.id=gl.jv_id "
                "WHERE " + CASH + " AND (gl.ledger_date < ? "
                "OR COALESCE(jv2.source_module,'') IN " + OB_SRC + ") " + gl_f,
                [d1] + gl_p).fetchone() or [0])[0] or 0)
            opening_cash = round(opening_cash, 2)
            closing_cash = round(opening_cash + net_change, 2)
            return {
                'period_from': d1, 'period_to': d2,
                'operating': {
                    'receipts_from_donors': round(op_in, 2),
                    'payments_to_suppliers': round(op_out, 2),
                    'payroll_payments': round(payroll, 2),
                    'net': net_operating
                },
                'investing': {
                    'asset_acquisitions': round(inv_acq, 2),
                    'asset_disposals': round(inv_disp, 2),
                    'net': net_investing
                },
                'financing': {
                    'inflows': round(fin_in, 2),
                    'outflows': round(fin_out, 2),
                    'net': net_financing
                },
                'opening_cash': opening_cash,
                'net_change': net_change,
                'closing_cash': closing_cash,
            }

        cur = _compute_cf(date_from, date_to)
        # IPSAS 1.53 / IPSAS 2.61 — prior financial-year comparative, same GL basis.
        # The prior closing cash equals the current opening cash, so they articulate.
        p_from, p_to = _prior_fy_window(date_from, date_to)
        prior = _compute_cf(p_from, p_to)

        out = dict(cur)
        out['basis'] = 'general_ledger'
        out['project_id'] = project_id
        out['comparative'] = prior
        out['prior_year'] = prior
        return ok(out)
    except Exception as e:
        return err('Cashflow report error: ' + str(e))
    finally:
        conn.close()


# ── Grant Utilisation with date filter ────────────────────────────────────────
def api_grant_utilisation_v556(session, date_from=None, date_to=None, project_id=None, donor=None):
    if not session: return err('Not authenticated')
    import datetime as _dtm
    if not date_from: date_from = None  # no period filter = lifetime
    if not date_to:   date_to   = _dtm.date.today().isoformat()
    conn = get_db()
    try:
        _f53_migrate()
        where = '1=1'; params = []
        if project_id: where += ' AND p.id=?'; params.append(project_id)
        if donor:      where += ' AND p.donor=?'; params.append(donor)

        rows = conn.execute("""
            SELECT p.id, p.project_code, p.title, p.donor, p.division,
                   p.budget_ghs, p.currency, p.status
            FROM projects p WHERE %s ORDER BY p.donor, p.project_code
        """ % where, params).fetchall()

        donors_map = {}
        for r in rows:
            r = dict(r)
            pid = r['id']
            # Budget = sum of the project's budget LINES. The projects.budget_ghs field is
            # 0 on the auto-created General-Fund projects, so reading it alone showed every
            # line as Budget 0.00 (and Available negative). Fall back to the project field
            # only when there are no budget lines.
            try:
                budget = _f53_f((conn.execute(
                    "SELECT COALESCE(SUM(budget_ghs),0) FROM budgets WHERE project_id=?",
                    (pid,)).fetchone() or [0])[0])
            except Exception:
                budget = 0.0
            if not budget:
                budget = _f53_f(r.get('budget_ghs'))

            # Committed: filtered by date if provided
            try:
                if date_from:
                    committed = _f53_f((conn.execute(
                        "SELECT COALESCE(SUM(amount_ghs),0) FROM commitments WHERE project_id=? AND status!='Cancelled' AND commit_date BETWEEN ? AND ?",
                        (pid, date_from, date_to)).fetchone() or [0])[0])
                else:
                    committed = _f53_f((conn.execute(
                        "SELECT COALESCE(SUM(amount_ghs),0) FROM commitments WHERE project_id=? AND status!='Cancelled'",
                        (pid,)).fetchone() or [0])[0])
            except Exception:
                committed = 0.0

            # Spent: filtered by period
            try:
                if date_from:
                    spent = _f53_f((conn.execute(
                        "SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE project_id=? AND expense_date BETWEEN ? AND ? AND is_posted=1",
                        (pid, date_from, date_to)).fetchone() or [0])[0])
                else:
                    spent = _f53_f((conn.execute(
                        "SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE project_id=? AND is_posted=1",
                        (pid,)).fetchone() or [0])[0])
            except Exception:
                spent = 0.0

            # Received: filtered by period
            try:
                if date_from:
                    received = _f53_f((conn.execute(
                        "SELECT COALESCE(SUM(amount_ghs),0) FROM fund_receipts WHERE project_id=? AND receipt_date BETWEEN ? AND ?",
                        (pid, date_from, date_to)).fetchone() or [0])[0])
                else:
                    received = _f53_f((conn.execute(
                        "SELECT COALESCE(SUM(amount_ghs),0) FROM fund_receipts WHERE project_id=?",
                        (pid,)).fetchone() or [0])[0])
            except Exception:
                received = 0.0

            available = budget - committed - spent
            util = round((committed + spent) / budget * 100, 1) if budget > 0 else 0
            donor_key = r.get('donor') or 'Unspecified'
            d = donors_map.setdefault(donor_key, {
                'donor': donor_key, 'projects': [], 'total_budget': 0,
                'total_committed': 0, 'total_spent': 0, 'total_received': 0
            })
            d['projects'].append({
                **r, 'budget': budget, 'committed': committed,
                'spent': spent, 'received': received,
                'available': round(available, 2), 'utilisation': util
            })
            d['total_budget'] += budget; d['total_committed'] += committed
            d['total_spent'] += spent; d['total_received'] += received

        return ok({
            'donors': list(donors_map.values()),
            'period_from': date_from, 'period_to': date_to,
            'generated_at': _f53_now()
        })
    except Exception as e:
        return err('Grant utilisation error: ' + str(e))
    finally:
        conn.close()


# ── Trial Balance with unit_code filter ──────────────────────────────────────
def api_trial_balance_v556(session, period_from=None, period_to=None, unit_code=None, project_id=None):
    if not session: return err('Not authenticated')
    import datetime as _dtm
    if not period_from: period_from = _dtm.date.today().strftime('%Y-01-01')
    if not period_to:   period_to   = _dtm.date.today().isoformat()
    conn = get_db()
    try:
        gl_proj_f = ''; gl_proj_p = []
        if project_id: gl_proj_f = ' AND gl.project_id=?'; gl_proj_p = [project_id]
        # UCC unit scope / node roll-up (Phase 1c / 3e): enforce the viewer's scope
        # and/or a requested node (unit_code). Unrestricted for Admin/university.
        unit_f, unit_p = (_ucc_gl_scope_clause(conn, session, unit_code)
                          if '_ucc_gl_scope_clause' in globals() else ('', []))

        def _nb_of(t):
            t = (t or '').lower()
            return 'Credit' if any(k in t for k in ('liab', 'equity', 'income', 'revenue', 'fund', 'capital')) else 'Debit'

        # ── Aggregate straight from general_ledger ──────────────────────────────
        # The GL stores coa_code + account_name directly; we LEFT JOIN
        # chart_of_accounts only for account_type. This is schema-robust (the old
        # query referenced name/normal_balance columns that do not exist on this
        # table, so it threw and silently returned an EMPTY trial balance) and it
        # surfaces EVERY account with ledger activity — including opening balances
        # posted with no other transactions. Captures PV/RV/JV/AJV/Payroll/Depr/OB.
        accounts = []
        try:
            rows = conn.execute(
                "SELECT gl.coa_id, gl.coa_code, MAX(gl.account_name) AS nm, "
                "COALESCE(MAX(c.account_type),'') AS at, "
                "COALESCE(SUM(gl.debit_amount),0) AS dr, COALESCE(SUM(gl.credit_amount),0) AS cr "
                "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                # A trial balance is an AS-AT statement: aggregate every posting up to
                # the reporting date so balances carry forward (and it reconciles with
                # the Statement of Financial Position). Period-bounding would drop prior
                # balances across year-ends.
                "WHERE gl.ledger_date <= ?" + gl_proj_f + unit_f + " "
                "GROUP BY gl.coa_id, gl.coa_code ORDER BY gl.coa_code",
                [period_to] + gl_proj_p + unit_p
            ).fetchall()
        except Exception as _se:
            import sys as _sx; print('trial_balance query warning: %s' % _se, file=_sx.stderr); rows = []
        for r in rows:
            code = r[1]; name = r[2]; acc_type = r[3] or ''
            dr = float(r[4] or 0); cr = float(r[5] or 0)
            balance = dr - cr if _nb_of(acc_type) == 'Debit' else cr - dr
            if dr or cr or balance:
                accounts.append({
                    'code': code, 'name': name, 'account_type': acc_type,
                    'debit': round(dr, 2), 'credit': round(cr, 2), 'balance': round(balance, 2)
                })

        total_dr = round(sum(a['debit'] for a in accounts), 2)
        total_cr = round(sum(a['credit'] for a in accounts), 2)
        balanced = abs(total_dr - total_cr) < 0.02
        return ok({
            'accounts': accounts, 'total_debit': total_dr, 'total_credit': total_cr,
            'balanced': balanced, 'period_from': period_from, 'period_to': period_to
        })
    except Exception as e:
        return err('Trial balance error: ' + str(e))
    finally:
        conn.close()


# ── Budget Variance with unit_code filter ─────────────────────────────────────
def api_budget_variance_v556(session, period_from=None, period_to=None, project_id=None, unit_code=None):
    if not session: return err('Not authenticated')
    import datetime as _dtm
    if not period_from: period_from = _dtm.date.today().strftime('%Y-01-01')
    if not period_to:   period_to   = _dtm.date.today().isoformat()
    conn = get_db()
    try:
        proj_f = ''; proj_p = []
        if project_id: proj_f = ' AND b.project_id=?'; proj_p = [project_id]
        unit_af = ''; unit_ap = []
        if unit_code: unit_af = ' AND dept=?'; unit_ap = [unit_code]

        rows = conn.execute(
            "SELECT b.id, COALESCE(b.budget_code, b.id) as bcode, b.project_id, "
            "COALESCE(b.budget_ghs, b.budget_fcy, 0) as budget, "
            "COALESCE(p.project_code, p.title, '') as project_code, "
            "COALESCE(c.account_name, '') as account_name, COALESCE(c.code,'') as coa_code "
            "FROM budgets b "
            "LEFT JOIN projects p ON p.id=b.project_id "
            "LEFT JOIN chart_of_accounts c ON c.id=b.coa_id "
            "WHERE 1=1" + proj_f + " ORDER BY b.project_id, bcode",
            proj_p
        ).fetchall()

        lines = []
        for r in rows:
            bid = r['id']; bcode = r['bcode']; proj = r['project_id']; budget = _f53_f(r['budget'])
            project_code = r['project_code'] or ''; account_name = r['account_name'] or ''; coa_code = r['coa_code'] or ''
            # Spent in period
            spent = 0.0
            try:
                spent = _f53_f((conn.execute(
                    "SELECT COALESCE(SUM(amount_ghs),0) FROM actuals "
                    "WHERE budget_id=? AND expense_date BETWEEN ? AND ? AND is_posted=1" + unit_af,
                    [bid, period_from, period_to] + unit_ap
                ).fetchone() or [0])[0])
            except Exception:
                pass
            # Committed in period
            committed = 0.0
            try:
                committed = _f53_f((conn.execute(
                    "SELECT COALESCE(SUM(amount_ghs),0) FROM commitments "
                    "WHERE budget_id=? AND commit_date BETWEEN ? AND ? AND status NOT IN ('Cancelled','Rejected')",
                    [bid, period_from, period_to]
                ).fetchone() or [0])[0])
            except Exception:
                pass
            if budget == 0 and spent == 0 and committed == 0: continue
            variance = budget - spent - committed
            pct = round((spent + committed) / budget * 100, 1) if budget else 0
            lines.append({
                'description': bcode, 'project_id': proj,
                'project_code': project_code, 'account_name': account_name, 'coa_code': coa_code,
                'budget': round(budget, 2), 'spent': round(spent, 2),
                'committed': round(committed, 2), 'variance': round(variance, 2),
                'pct_used': pct,
                'status': 'over' if variance < 0 else ('warn' if pct >= 80 else 'ok')
            })

        return ok({
            'lines': lines,
            'total_budget': round(sum(l['budget'] for l in lines), 2),
            'total_spent': round(sum(l['spent'] for l in lines), 2),
            'total_committed': round(sum(l['committed'] for l in lines), 2),
            'total_variance': round(sum(l['variance'] for l in lines), 2),
            'period_from': period_from, 'period_to': period_to
        })
    except Exception as e:
        return err('Budget variance error: ' + str(e))
    finally:
        conn.close()


# ── System Audit lightweight ───────────────────────────────────────────────────
def api_system_audit_v556(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        def count(q, p=None):
            try: return int((conn.execute(q, p or []).fetchone() or [0])[0])
            except Exception: return 0
        def scalar(q, p=None):
            try: return float((conn.execute(q, p or []).fetchone() or [0])[0] or 0)
            except Exception: return 0.0

        summary = {
            'total_users': count("SELECT COUNT(*) FROM users"),
            'total_projects': count("SELECT COUNT(*) FROM projects"),
            'total_actuals': count("SELECT COUNT(*) FROM actuals"),
            'unposted_actuals': count("SELECT COUNT(*) FROM actuals WHERE is_posted=0"),
            'total_receipts': count("SELECT COUNT(*) FROM fund_receipts"),
            'total_commitments': count("SELECT COUNT(*) FROM commitments"),
            'total_budget_lines': count("SELECT COUNT(*) FROM budgets"),
            'total_coa': count("SELECT COUNT(*) FROM chart_of_accounts"),
            'total_bank_accounts': count("SELECT COUNT(*) FROM bank_accounts"),
            'total_assets': count("SELECT COUNT(*) FROM fixed_assets WHERE status='Active'"),
            'total_jvs': count("SELECT COUNT(*) FROM journal_vouchers"),
            'total_audit_entries': count("SELECT COUNT(*) FROM audit_log"),
        }
        # Recent audit log
        recent = []
        try:
            recent = [dict(r) for r in conn.execute(
                "SELECT timestamp, action, username AS performed_by, module, details FROM audit_log "
                "ORDER BY timestamp DESC LIMIT 50"
            ).fetchall()]
        except Exception:
            pass
        return ok({'summary': summary, 'recent_activity': recent, 'generated_at': _f53_now()})
    except Exception as e:
        return err('System audit error: ' + str(e))
    finally:
        conn.close()


