# 1.  Fixed Journal-Voucher functions (column-name corrections)
#     Actual DB schema:  jv_number (not jv_code)
#                        period    (not period_code)
#     jv_lines schema:   line_number  debit_amount  credit_amount
#                        (not line_no / debit_ghs / credit_ghs)
# ---------------------------------------------------------------------------
def api_journal_vouchers_v557(session, period_from=None, period_to=None, jv_type=None):
    if not session:
        return err('Not authenticated')
    import datetime as _dt
    try:
        today = _dt.date.today()
        if not period_from:
            period_from = str(today.year) + '-01-01'
        if not period_to:
            period_to = today.isoformat()
        conn = get_db()
        try:
            q = ("SELECT jv.*, "
                 "GROUP_CONCAT(jl.coa_id || ':' || jl.debit_amount || ':' || jl.credit_amount, '|') AS lines_summary "
                 "FROM journal_vouchers jv "
                 "LEFT JOIN jv_lines jl ON jl.jv_id = jv.id "
                 "WHERE jv.jv_date BETWEEN ? AND ? "
                 "AND (jv.is_deleted IS NULL OR jv.is_deleted = 0) ")
            params = [period_from, period_to]
            if jv_type:
                q += "AND jv.jv_type = ? "
                params.append(jv_type)
            q += "GROUP BY jv.id ORDER BY jv.jv_date DESC, jv.jv_number DESC LIMIT 500"
            rows = [dict(r) for r in conn.execute(q, params).fetchall()]
            for row in rows:
                td = _f53_f(row.get('total_debit') or 0)
                tc = _f53_f(row.get('total_credit') or 0)
                row['balance_ok'] = abs(td - tc) < 0.01
            return ok({'journal_vouchers': rows, 'period_from': period_from, 'period_to': period_to, 'count': len(rows)})
        finally:
            conn.close()
    except Exception as e:
        return err(str(e))


def api_get_jv_lines_v557(session, jv_id):
    if not session:
        return err('Not authenticated')
    if not jv_id:
        return err('jv_id required')
    conn = get_db()
    try:
        jv = conn.execute("SELECT * FROM journal_vouchers WHERE id = ?", (jv_id,)).fetchone()
        if not jv:
            return err('Journal voucher not found')
        jv = dict(jv)
        lines = [dict(r) for r in conn.execute(
            "SELECT jl.*, coa.code as account_code, coa.account_name "
            "FROM jv_lines jl LEFT JOIN chart_of_accounts coa ON coa.id = jl.coa_id "
            "WHERE jl.jv_id = ? ORDER BY jl.line_number",
            (jv_id,)
        ).fetchall()]
        jv['lines'] = lines
        return ok({'jv': jv})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_save_journal_voucher_v557(session, data):
    """Fixed version using correct column names: jv_number, period, line_number, debit_amount, credit_amount."""
    if not session:
        return err('Not authenticated')
    if not data:
        return err('No data provided')
    jv_date = (data.get('jv_date') or '').strip()
    description = (data.get('description') or '').strip()
    lines = data.get('lines') or []
    if not jv_date:
        return err('jv_date is required')
    if not description:
        return err('description is required')
    if not isinstance(lines, list) or len(lines) < 2:
        return err('At least 2 journal lines are required')

    total_debit = 0.0
    total_credit = 0.0
    validated_lines = []
    for i, line in enumerate(lines):
        # Accept both old field names (debit_ghs/credit_ghs) and correct names (debit_amount/credit_amount)
        debit = _f53_f(line.get('debit_amount') or line.get('debit_ghs') or 0)
        credit = _f53_f(line.get('credit_amount') or line.get('credit_ghs') or 0)
        coa_id = (line.get('coa_id') or '').strip()
        coa_code = (line.get('coa_code') or line.get('account_code') or '').strip()
        if not coa_id and not coa_code:
            return err('Each line requires coa_id or coa_code (line %d)' % (i + 1))
        if debit > 0 and credit > 0:
            return err('Line %d cannot have both debit and credit > 0' % (i + 1))
        if debit == 0 and credit == 0:
            return err('Line %d must have debit or credit > 0' % (i + 1))
        total_debit += debit
        total_credit += credit

        # Resolve coa_id from coa_code if needed
        if not coa_id and coa_code:
            pass  # will resolve in DB

        validated_lines.append({
            'coa_id': coa_id,
            'coa_code': coa_code,
            'account_name': (line.get('account_name') or '').strip(),
            'description': (line.get('description') or description).strip(),
            'debit_amount': debit,
            'credit_amount': credit,
            'project_id': (line.get('project_id') or data.get('project_id') or '').strip() or None,
            'cost_centre': (line.get('cost_centre') or '').strip() or None,
            'bank_account_id': (line.get('bank_account_id') or '').strip() or None,
        })

    if abs(total_debit - total_credit) > 0.01:
        return err('Journal voucher is not balanced: debit=%.2f credit=%.2f' % (total_debit, total_credit))

    import uuid as _uuid
    conn = get_db()
    try:
        jv_id = (data.get('id') or '').strip()
        _raw_jv_type = (data.get('jv_type') or 'JV').strip().upper()
        _jv_type_aliases = {'GJV': 'JV', 'GENERAL': 'JV', 'PAYMENT': 'PV', 'RECEIPT': 'RV',
                             'BUDGET': 'BV', 'ADJUST': 'AJV', 'ADJUSTMENT': 'AJV', 'REVERSAL': 'RJV'}
        _allowed_jv_types = ('JV', 'PV', 'RV', 'BV', 'AJV', 'RJV')
        jv_type = _jv_type_aliases.get(_raw_jv_type, _raw_jv_type)
        if jv_type not in _allowed_jv_types:
            jv_type = 'JV'
        # Accept period from either 'period' or 'period_code' field
        period = (data.get('period') or data.get('period_code') or jv_date[:7]).strip()

        if jv_id:
            # Update existing draft JV
            existing = conn.execute("SELECT status, jv_number FROM journal_vouchers WHERE id=?", (jv_id,)).fetchone()
            if not existing:
                return err('Journal voucher not found')
            if existing['status'] not in ('Draft', 'Rejected'):
                return err('Only Draft or Rejected JVs can be edited')
            conn.execute(
                "UPDATE journal_vouchers SET jv_date=?, description=?, reference=?, narration=?, "
                "period=?, project_id=?, total_debit=?, total_credit=?, jv_type=? WHERE id=?",
                (jv_date, description, data.get('reference'), data.get('narration'),
                 period, data.get('project_id'), total_debit, total_credit, jv_type, jv_id)
            )
            conn.execute("DELETE FROM jv_lines WHERE jv_id=?", (jv_id,))
        else:
            jv_id = str(_uuid.uuid4())
            # Generate jv_number using the existing helper
            try:
                jv_number = _next_jv_number(conn, jv_type)
            except Exception:
                # Fallback if helper not available
                prefix_map = {'GJV': 'JV', 'RJV': 'RJV', 'PROV': 'PJV', 'ADJ': 'AJV'}
                prefix = prefix_map.get(jv_type, 'JV')
                yr = jv_date[:4]
                jv_number = _seq_code(conn, 'journal_vouchers', 'jv_number', '%s-%s-' % (prefix, yr), 4)

            _wunit = _ucc_resolve_write_unit(conn, data, session) if '_ucc_resolve_write_unit' in globals() else None
            conn.execute(
                "INSERT INTO journal_vouchers(id,jv_number,jv_type,jv_date,period,description,"
                "narration,reference,project_id,bank_account_id,total_debit,total_credit,"
                "status,prepared_by,prepared_at,workflow_stage,approval_status,unit_id) "
                "VALUES(?,?,?,?,?,?,?,?,?,?,?,?,'Draft',?,datetime('now'),'Draft','Draft',?)",
                (jv_id, jv_number, jv_type, jv_date, period, description,
                 data.get('narration') or None, data.get('reference') or None,
                 data.get('project_id') or None,
                 data.get('bank_account_id') or None, total_debit, total_credit,
                 session.get('username'), _wunit)
            )

        # Insert lines using correct column names
        for idx, line in enumerate(validated_lines):
            line_id = str(_uuid.uuid4())
            # Resolve coa_id from coa_code if needed
            coa_id = line['coa_id']
            if not coa_id and line['coa_code']:
                row = conn.execute(
                    "SELECT id FROM chart_of_accounts WHERE code=? LIMIT 1",
                    (line['coa_code'],)
                ).fetchone()
                if row:
                    coa_id = row[0]
            if not coa_id:
                raise ValueError('Line %d: could not resolve COA account' % (idx + 1))
            conn.execute(
                "INSERT INTO jv_lines(id,jv_id,line_number,coa_id,description,"
                "debit_amount,credit_amount,project_id,cost_centre,bank_account_id) "
                "VALUES(?,?,?,?,?,?,?,?,?,?)",
                (line_id, jv_id, idx + 1, coa_id, line['description'],
                 line['debit_amount'], line['credit_amount'],
                 line['project_id'], line['cost_centre'], line['bank_account_id'])
            )

        conn.commit()
        # Audit
        try:
            conn.execute(
                "INSERT INTO audit_log(id,action,module,performed_by,details,timestamp) "
                "VALUES(?,?,?,?,?,datetime('now'))",
                (str(_uuid.uuid4()), 'SAVE_JV', 'journal_vouchers',
                 session.get('username', ''), 'Saved JV id=' + jv_id)
            )
            conn.commit()
        except Exception:
            pass
        return ok({'jv_id': jv_id})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


