def api_search_v557(session, q=None, module=None, limit=None):
    """Global search across key modules."""
    if not session:
        return err('Not authenticated')
    if not q:
        return ok({'results': [], 'query': ''})
    conn = get_db()
    try:
        lim = int(limit or 50)
        term = '%' + str(q) + '%'
        results = []

        # Search actuals (Payment Vouchers)
        if not module or module == 'actuals':
            for r in conn.execute(
                "SELECT id, actual_code as code, description, amount_ghs as amount, "
                "expense_date as date, 'Payment Voucher' as module FROM actuals "
                "WHERE (actual_code LIKE ? OR description LIKE ?) "
                "AND (is_deleted IS NULL OR is_deleted=0) LIMIT ?",
                (term, term, lim)
            ).fetchall():
                results.append(dict(r))

        # Search fund receipts
        if not module or module == 'receipts':
            for r in conn.execute(
                "SELECT id, receipt_number as code, description, amount_ghs as amount, "
                "receipt_date as date, 'Fund Receipt' as module FROM fund_receipts "
                "WHERE (receipt_number LIKE ? OR description LIKE ?) LIMIT ?",
                (term, term, lim)
            ).fetchall():
                results.append(dict(r))

        # Search journal vouchers
        if not module or module == 'jvs':
            for r in conn.execute(
                "SELECT id, jv_number as code, description, total_debit as amount, "
                "jv_date as date, 'Journal Voucher' as module FROM journal_vouchers "
                "WHERE (jv_number LIKE ? OR description LIKE ?) "
                "AND (is_deleted IS NULL OR is_deleted=0) LIMIT ?",
                (term, term, lim)
            ).fetchall():
                results.append(dict(r))

        # Search vendors
        if not module or module == 'vendors':
            for r in conn.execute(
                "SELECT id, vendor_code as code, vendor_name as description, "
                "0 as amount, created_at as date, 'Vendor' as module "
                "FROM vendor_register_v55 "
                "WHERE (vendor_code LIKE ? OR vendor_name LIKE ?) LIMIT ?",
                (term, term, lim)
            ).fetchall():
                results.append(dict(r))

        # Search purchase orders
        if not module or module == 'pos':
            for r in conn.execute(
                "SELECT id, po_number as code, description, amount_ghs as amount, "
                "po_date as date, 'Purchase Order' as module FROM purchase_orders "
                "WHERE (po_number LIKE ? OR description LIKE ?) LIMIT ?",
                (term, term, lim)
            ).fetchall():
                results.append(dict(r))

        return ok({'results': results[:lim], 'query': q, 'count': len(results)})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


