def api_notifications_v557b(session, limit=None):
    """Notifications using actual notification_centre_log schema."""
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        lim = int(limit or 100)
        username = session.get('username', '')
        role = session.get('role', '')
        # notification_centre_log: id, alert_type, severity, title, message, module, record_id, status, created_by, created_at
        rows = [dict(r) for r in conn.execute(
            "SELECT * FROM notification_centre_log "
            "WHERE status = 'Open' OR created_by = ? "
            "ORDER BY created_at DESC LIMIT ?",
            (username, lim)
        ).fetchall()]
        unread = sum(1 for r in rows if r.get('status') == 'Open')
        # Also pull from notification_log (event-type log)
        try:
            notif_log = [dict(r) for r in conn.execute(
                "SELECT id, event_type as alert_type, recipient as created_by, "
                "subject as title, '' as message, '' as module, '' as record_id, "
                "status, sent_at as created_at FROM notification_log "
                "WHERE recipient = ? OR ? = 'Admin' ORDER BY sent_at DESC LIMIT ?",
                (username, role, lim)
            ).fetchall()]
            rows = rows + notif_log
        except Exception:
            pass
        return ok({'notifications': rows, 'unread': unread, 'total': len(rows)})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


def api_pending_approvals_v557b(session):
    """Pending approvals using actual 'approvals' table schema."""
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        # approvals table: id, module, record_id, record_code, amount_ghs, unit_code, project_id, status, submitted_by, submitted_at, decided_by, decided_at, comments
        pending = [dict(r) for r in conn.execute(
            "SELECT a.*, p.project_code, p.title as project_title "
            "FROM approvals a "
            "LEFT JOIN projects p ON p.id = a.project_id "
            "WHERE a.status = 'Pending' "
            "ORDER BY a.submitted_at DESC"
        ).fetchall()]

        # Enrich with document reference details
        for item in pending:
            module = item.get('module', '')
            record_id = item.get('record_id', '')
            try:
                if module == 'actuals':
                    row = conn.execute(
                        "SELECT actual_code, description FROM actuals WHERE id=?", (record_id,)
                    ).fetchone()
                    if row:
                        item['record_code'] = item.get('record_code') or row[0]
                        item['description'] = row[1]
                elif module == 'purchase_orders':
                    row = conn.execute(
                        "SELECT po_number, description FROM purchase_orders WHERE id=?", (record_id,)
                    ).fetchone()
                    if row:
                        item['record_code'] = item.get('record_code') or row[0]
                        item['description'] = row[1]
                elif module == 'journal_vouchers':
                    row = conn.execute(
                        "SELECT jv_number, description FROM journal_vouchers WHERE id=?", (record_id,)
                    ).fetchone()
                    if row:
                        item['record_code'] = item.get('record_code') or row[0]
                        item['description'] = row[1]
                elif module == 'fund_receipts':
                    row = conn.execute(
                        "SELECT receipt_code, description FROM fund_receipts WHERE id=?", (record_id,)
                    ).fetchone()
                    if row:
                        item['record_code'] = item.get('record_code') or row[0]
                        item['description'] = row[1]
            except Exception:
                pass

        grouped = {}
        for item in pending:
            mod = item.get('module', 'other')
            grouped.setdefault(mod, []).append(item)

        return ok({'pending_approvals': pending, 'grouped': grouped, 'count': len(pending)})
    except Exception as e:
        return err(str(e))
    finally:
        conn.close()


