# 1. Fixed bulk-approve-queue (correct column names for all tables)
# ---------------------------------------------------------------------------
def api_get_bulk_approve_queue_v558(session):
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        items = []

        # Unposted actuals
        try:
            for r in conn.execute(
                "SELECT id, actual_code as ref, description, amount_ghs as amount,"
                " expense_date as date, created_by as submitted_by"
                " FROM actuals"
                " WHERE is_posted=0 AND (is_deleted IS NULL OR is_deleted=0)"
                " ORDER BY created_at DESC LIMIT 100"
            ).fetchall():
                items.append(dict(dict(r), type='Actual / PV'))
        except Exception:
            pass

        # Open commitments — correct column: commit_code (not commitment_code)
        # commitments table has no is_deleted column; status='Open'
        try:
            for r in conn.execute(
                "SELECT id, commit_code as ref, description, amount_ghs as amount,"
                " commit_date as date, created_by as submitted_by"
                " FROM commitments"
                " WHERE status='Open'"
                " ORDER BY created_at DESC LIMIT 100"
            ).fetchall():
                items.append(dict(dict(r), type='Commitment'))
        except Exception:
            pass

        # Pending/Draft purchase orders — correct column: total_amount_ghs, created_by
        try:
            for r in conn.execute(
                "SELECT id, po_number as ref, description, total_amount_ghs as amount,"
                " po_date as date, created_by as submitted_by"
                " FROM purchase_orders"
                " WHERE status IN ('Draft','Pending')"
                " ORDER BY created_at DESC LIMIT 100"
            ).fetchall():
                items.append(dict(dict(r), type='Purchase Order'))
        except Exception:
            pass

        # Staff advances pending — correct column: date_issued (not advance_date),
        # no advance_number column (use id as ref)
        try:
            for r in conn.execute(
                "SELECT id, id as ref, purpose as description, amount_ghs as amount,"
                " date_issued as date, employee_name as submitted_by"
                " FROM staff_advances"
                " WHERE status='Pending'"
                " ORDER BY created_at DESC LIMIT 50"
            ).fetchall():
                items.append(dict(dict(r), type='Staff Advance'))
        except Exception:
            pass

        # Interunit transfers pending
        try:
            for r in conn.execute(
                "SELECT id, transfer_number as ref, description, amount_ghs as amount,"
                " transfer_date as date, created_by as submitted_by"
                " FROM interunit_transfers"
                " WHERE status='Pending'"
                " ORDER BY created_at DESC LIMIT 50"
            ).fetchall():
                items.append(dict(dict(r), type='Interunit Transfer'))
        except Exception:
            pass

        # Draft journal vouchers — correct columns: jv_number, total_debit, jv_date, prepared_by
        try:
            for r in conn.execute(
                "SELECT id, jv_number as ref, description, total_debit as amount,"
                " jv_date as date, prepared_by as submitted_by"
                " FROM journal_vouchers"
                " WHERE status='Draft' AND (is_deleted IS NULL OR is_deleted=0)"
                " ORDER BY jv_date DESC LIMIT 50"
            ).fetchall():
                items.append(dict(dict(r), type='Journal Voucher'))
        except Exception:
            pass

        return ok({'items': items, 'count': len(items)})
    except Exception as e:
        return err('Bulk approve queue error: ' + str(e))
    finally:
        conn.close()


# ---------------------------------------------------------------------------
# 2. Fixed staff advances report
#    Old version used advance_date and advance_number — neither column exists.
#    Actual columns: date_issued, id (used as reference).
# ---------------------------------------------------------------------------
def api_staff_advance_report_v558(session):
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        rows = [dict(r) for r in conn.execute(
            "SELECT * FROM staff_advances ORDER BY date_issued DESC"
        ).fetchall()]
        outstanding = 0.0
        overdue = 0.0
        retired_month = 0.0
        by_type = {}
        import datetime as _dt_mod
        today = _dt_mod.datetime.now()
        cutoff = (today - _dt_mod.timedelta(days=30)).strftime('%Y-%m-%d')
        month = today.strftime('%Y-%m')
        for r in rows:
            out = _f53_f(r.get('amount_ghs')) - _f53_f(r.get('amount_retired'))
            if r.get('status') not in ('Fully Retired', 'Retired', 'Cancelled'):
                outstanding += out
                # use date_issued as the origination date for overdue check
                issued = r.get('date_issued') or r.get('due_date') or ''
                due = r.get('due_date') or ''
                overdue_date = due if due else issued
                if overdue_date and overdue_date < cutoff:
                    overdue += out
            if r.get('status') in ('Fully Retired', 'Retired') and (r.get('updated_at') or '')[:7] == month:
                retired_month += _f53_f(r.get('amount_ghs'))
            t = r.get('advance_type') or 'Other'
            by_type[t] = round(by_type.get(t, 0.0) + out, 2)
        # Build detail rows for tabular display
        detail = []
        for r in rows:
            detail.append({
                'id': r.get('id'),
                'ref': r.get('id'),
                'employee_name': r.get('employee_name'),
                'advance_type': r.get('advance_type'),
                'purpose': r.get('purpose'),
                'amount_ghs': _f53_f(r.get('amount_ghs')),
                'amount_retired': _f53_f(r.get('amount_retired')),
                'amount_outstanding': round(
                    _f53_f(r.get('amount_ghs')) - _f53_f(r.get('amount_retired')), 2),
                'date_issued': r.get('date_issued'),
                'due_date': r.get('due_date'),
                'status': r.get('status'),
                'project_id': r.get('project_id'),
            })
        return ok({
            'total_outstanding': round(outstanding, 2),
            'overdue': round(overdue, 2),
            'retired_this_month': round(retired_month, 2),
            'by_type': by_type,
            'rows': detail,
            'count': len(detail),
        })
    except Exception as e:
        return err('Staff advance report error: ' + str(e))
    finally:
        conn.close()


# ---------------------------------------------------------------------------
# 3. Fixed notification summary — replaces advance_date with date_issued
# ---------------------------------------------------------------------------
def api_notification_summary_v558(session):
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        import datetime as _dt_mod
        today = _dt_mod.datetime.now()
        alerts = []

        # Contracts expiring within 30 days
        try:
            soon = (today + _dt_mod.timedelta(days=30)).strftime('%Y-%m-%d')
            n = conn.execute(
                "SELECT COUNT(*) FROM contracts"
                " WHERE end_date BETWEEN ? AND ? AND status='Active'",
                (today.strftime('%Y-%m-%d'), soon)
            ).fetchone()[0]
            if n:
                alerts.append({
                    'type': 'contract_expiry',
                    'count': n,
                    'label': '%d contract(s) expiring in 30 days' % n,
                    'icon': 'document',
                    'view': 'procurement',
                })
        except Exception:
            pass

        # Staff advances unretired > 30 days — use date_issued (not advance_date)
        try:
            threshold = (today - _dt_mod.timedelta(days=30)).strftime('%Y-%m-%d')
            n = conn.execute(
                "SELECT COUNT(*) FROM staff_advances"
                " WHERE status NOT IN ('Retired','Fully Retired','Cancelled')"
                " AND date_issued < ?",
                (threshold,)
            ).fetchone()[0]
            if n:
                alerts.append({
                    'type': 'advance_overdue',
                    'count': n,
                    'label': '%d advance(s) unretired > 30 days' % n,
                    'icon': 'cash',
                    'view': 'hr-payroll',
                })
        except Exception:
            pass

        # Unposted payment vouchers
        try:
            n = conn.execute(
                "SELECT COUNT(*) FROM actuals WHERE is_posted=0"
            ).fetchone()[0]
            if n:
                alerts.append({
                    'type': 'approval_pending',
                    'count': n,
                    'label': '%d payment voucher(s) pending posting' % n,
                    'icon': 'check',
                    'view': 'bulk-approve',
                })
        except Exception:
            pass

        # Reversals staged under dual control, awaiting a second admin to post
        try:
            n = conn.execute(
                "SELECT COUNT(*) FROM journal_vouchers WHERE is_reversal=1 AND status='Approved'"
            ).fetchone()[0]
            if n:
                alerts.append({
                    'type': 'reversal_pending',
                    'count': n,
                    'label': '%d reversal(s) awaiting a second admin to post' % n,
                    'icon': 'refresh',
                    'view': 'approvals',
                })
        except Exception:
            pass

        # Budget lines at or above 80%
        try:
            over = conn.execute("""
                SELECT COUNT(*) FROM (
                    SELECT b.id,
                        COALESCE(SUM(a.amount_ghs),0) as spent,
                        b.amount_ghs as budget
                    FROM budgets b
                    LEFT JOIN actuals a ON a.budget_id=b.id AND a.is_posted=1
                    GROUP BY b.id
                    HAVING b.amount_ghs > 0
                        AND (COALESCE(SUM(a.amount_ghs),0)/b.amount_ghs) >= 0.8
                )
            """).fetchone()[0]
            if over:
                alerts.append({
                    'type': 'budget_threshold',
                    'count': over,
                    'label': '%d budget line(s) at 80%%+' % over,
                    'icon': 'warning',
                    'view': 'financial-control',
                })
        except Exception:
            pass

        # SSNIT remittance due by 14th of each month
        try:
            if today.day <= 14:
                alerts.append({
                    'type': 'ssnit_due',
                    'count': 1,
                    'label': 'SSNIT remittance due by 14th of this month',
                    'icon': 'institution',
                    'view': 'hr-payroll',
                })
        except Exception:
            pass

        # Open commitments awaiting approval
        try:
            n = conn.execute(
                "SELECT COUNT(*) FROM commitments WHERE status='Open'"
            ).fetchone()[0]
            if n:
                alerts.append({
                    'type': 'commitment_pending',
                    'count': n,
                    'label': '%d commitment(s) pending approval' % n,
                    'icon': 'clipboard',
                    'view': 'bulk-approve',
                })
        except Exception:
            pass

        total_count = sum(a['count'] for a in alerts)
        return ok({'alerts': alerts, 'total': total_count})
    except Exception as e:
        return err('Notification summary error: ' + str(e))
    finally:
        conn.close()


# ---------------------------------------------------------------------------
# 4. Fixed bulk-approve POST handler (correct column names)
# ---------------------------------------------------------------------------
def api_bulk_approve_v558(data, session):
    if not _f53_is_admin(session):
        return err('Admin access required')
    items = data.get('items') or []
    if not items:
        return err('No items provided')
    conn = get_db()
    approved = 0
    errors = []
    try:
        for item in items:
            iid = item.get('id')
            itype = item.get('type') or ''
            if not iid:
                continue
            try:
                if 'Actual' in itype or 'PV' in itype:
                    try:
                        conn.execute(
                            "UPDATE actuals SET is_posted=1, approved_by=?,"
                            " approved_at=datetime('now') WHERE id=?",
                            (session.get('username', 'system'), iid)
                        )
                    except Exception:
                        conn.execute(
                            "UPDATE actuals SET is_posted=1 WHERE id=?", (iid,)
                        )
                elif 'Commitment' in itype:
                    # commitments: status transitions from 'Open' -> 'Approved'
                    try:
                        conn.execute(
                            "UPDATE commitments SET status='Approved', approved_by=? WHERE id=?",
                            (session.get('username', 'system'), iid)
                        )
                    except Exception:
                        conn.execute(
                            "UPDATE commitments SET status='Approved' WHERE id=?", (iid,)
                        )
                elif 'Purchase Order' in itype:
                    # purchase_orders: correct column is created_by / approved_by
                    try:
                        conn.execute(
                            "UPDATE purchase_orders SET status='Approved', approved_by=?,"
                            " approved_at=datetime('now') WHERE id=?",
                            (session.get('username', 'system'), iid)
                        )
                    except Exception:
                        conn.execute(
                            "UPDATE purchase_orders SET status='Approved' WHERE id=?", (iid,)
                        )
                elif 'Staff Advance' in itype:
                    conn.execute(
                        "UPDATE staff_advances SET status='Approved' WHERE id=?", (iid,)
                    )
                elif 'Interunit' in itype:
                    try:
                        conn.execute(
                            "UPDATE interunit_transfers SET status='Approved', approved_by=? WHERE id=?",
                            (session.get('username', 'system'), iid)
                        )
                    except Exception:
                        conn.execute(
                            "UPDATE interunit_transfers SET status='Approved' WHERE id=?", (iid,)
                        )
                elif 'Journal Voucher' in itype:
                    try:
                        conn.execute(
                            "UPDATE journal_vouchers SET status='Approved', approved_by=?,"
                            " approved_at=datetime('now') WHERE id=?",
                            (session.get('username', 'system'), iid)
                        )
                    except Exception:
                        conn.execute(
                            "UPDATE journal_vouchers SET status='Approved' WHERE id=?", (iid,)
                        )
                approved += 1
            except Exception as e:
                errors.append(str(e)[:120])
        conn.commit()
        try:
            _audit(conn, session, 'BULK_APPROVE_V558', 'bulk_approve', '',
                   'Bulk approved %d items (v558)' % approved)
        except Exception:
            pass
        result = {'approved': approved}
        if errors:
            result['warnings'] = errors[:5]
        return ok(result)
    except Exception as e:
        conn.rollback()
        return err('Bulk approve error: ' + str(e))
    finally:
        conn.close()


