def api_report_templates_v558b(session):
    """Return saved report templates from report_designer table (if exists)."""
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        rows = [dict(r) for r in conn.execute(
            "SELECT * FROM report_designer ORDER BY created_at DESC"
        ).fetchall()]
        return ok({'templates': rows, 'count': len(rows)})
    except Exception:
        pass
    # Fallback: return empty list gracefully
    return ok({'templates': [], 'count': 0, 'note': 'Report templates not yet configured'})
    conn.close()


def api_payroll_summary_v558b(session):
    """Top-level /api/payroll — returns employees + latest month summary."""
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        employees = [dict(r) for r in conn.execute(
            "SELECT * FROM employees WHERE COALESCE(status,'Active')='Active' ORDER BY full_name"
        ).fetchall()]
    except Exception:
        employees = []
    try:
        latest = conn.execute(
            "SELECT payroll_month FROM payroll_register GROUP BY payroll_month ORDER BY payroll_month DESC LIMIT 1"
        ).fetchone()
        month = latest[0] if latest else None
        register = []
        if month:
            register = [dict(r) for r in conn.execute(
                "SELECT r.*, e.full_name, e.staff_number, e.job_title "
                "FROM payroll_register r LEFT JOIN employees e ON e.id=r.employee_id "
                "WHERE r.payroll_month=? ORDER BY e.full_name", (month,)
            ).fetchall()]
    except Exception:
        month = None
        register = []
    conn.close()
    return ok({
        'employees': employees,
        'latest_month': month,
        'register': register,
        'employee_count': len(employees),
    })


def api_audit_log_v558b(session, limit=None):
    """GET /api/audit-log — returns recent audit log entries."""
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        lim = int(limit or 200)
        rows = [dict(r) for r in conn.execute(
            "SELECT * FROM audit_log ORDER BY timestamp DESC LIMIT ?", (lim,)
        ).fetchall()]
        return ok({'entries': rows, 'count': len(rows)})
    except Exception as e:
        return err('Audit log error: ' + str(e))
    finally:
        conn.close()


