# =============================================================================
# v5.5.8c — Staff Advance save fix (no ON CONFLICT DO UPDATE)
# Compatible with Python 3.14 sqlite3 changes
# =============================================================================
def api_save_staff_advance_v558c(data, session):
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        import uuid as _u558c
        aid = (data.get('id') or '').strip() or str(_u558c.uuid4())
        amt = float(data.get('amount_ghs') or 0)
        if not data.get('employee_name'):
            return err('Employee name required')
        if amt <= 0:
            return err('Amount must be positive')

        existing = conn.execute(
            "SELECT id, amount_retired FROM staff_advances WHERE id=?", (aid,)
        ).fetchone()
        retired = float((existing['amount_retired'] if existing else None) or 0)

        if existing:
            # UPDATE existing record
            upd = (
                "UPDATE staff_advances SET"
                " employee_id=?, employee_name=?, advance_type=?,"
                " amount_ghs=?, date_issued=?, due_date=?, purpose=?,"
                " project_id=?, pv_reference=?, approved_by=?, notes=?,"
                " amount_outstanding=?, updated_at=datetime('now')"
                " WHERE id=?"
            )
            conn.execute(upd, (
                data.get('employee_id') or None,
                data.get('employee_name'),
                data.get('advance_type') or 'Salary Advance',
                amt,
                data.get('date_issued') or _f53_today(),
                data.get('due_date') or None,
                data.get('purpose') or None,
                data.get('project_id') or None,
                data.get('pv_reference') or None,
                data.get('approved_by') or None,
                data.get('notes') or None,
                round(amt - retired, 2),
                aid,
            ))
        else:
            ins = (
                "INSERT INTO staff_advances"
                " (id, employee_id, employee_name, advance_type, amount_ghs,"
                "  date_issued, due_date, purpose, project_id, status,"
                "  amount_retired, amount_outstanding, pv_reference,"
                "  approved_by, notes, created_by)"
                " VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)"
            )
            conn.execute(ins, (
                aid,
                data.get('employee_id') or None,
                data.get('employee_name'),
                data.get('advance_type') or 'Salary Advance',
                amt,
                data.get('date_issued') or _f53_today(),
                data.get('due_date') or None,
                data.get('purpose') or None,
                data.get('project_id') or None,
                data.get('status') or 'Outstanding',
                0,
                round(amt, 2),
                data.get('pv_reference') or None,
                data.get('approved_by') or None,
                data.get('notes') or None,
                session.get('username', 'system'),
            ))

        conn.commit()
        try:
            _audit(conn, session, 'SAVE_STAFF_ADVANCE', 'staff_advances', aid,
                   '%s GHS %.2f' % (data.get('employee_name', ''), amt))
            conn.commit()
        except Exception:
            pass
        return ok({'id': aid})
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        return err('Save staff advance failed: %s' % exc)
    finally:
        conn.close()


