# v5.5.8d — SBS-specific fixes:
# 1. /api/units alias → api_get_departments (SBS has no _unitize)
# 2. /api/fixed-assets fallback to asset_register table when fixed_assets missing
# =============================================================================

def api_fixed_assets_v558d(session):
    """Fallback fixed assets using asset_register if fixed_assets doesn't exist."""
    if not session:
        return err('Not authenticated')
    conn = get_db()
    try:
        # Try original fixed_assets table first
        assets = [dict(r) for r in conn.execute(
            "SELECT * FROM fixed_assets ORDER BY category, asset_name"
        ).fetchall()]
        return ok({'assets': assets, 'summary': {
            'total_count': len(assets),
            'total_cost': round(sum(float(a.get('acquisition_cost') or 0) for a in assets), 2),
        }})
    except Exception:
        pass
    try:
        # Fallback to asset_register
        assets = [dict(r) for r in conn.execute(
            "SELECT * FROM asset_register ORDER BY asset_category, asset_name"
        ).fetchall()]
        total_cost = sum(float(a.get('acquisition_cost') or 0) for a in assets)
        total_dep = sum(float(a.get('accumulated_depreciation') or 0) for a in assets)
        return ok({'assets': assets, 'summary': {
            'total_count': len(assets),
            'total_cost': round(total_cost, 2),
            'total_accumulated_depreciation': round(total_dep, 2),
            'total_net_book_value': round(total_cost - total_dep, 2),
        }})
    except Exception as e2:
        return ok({'assets': [], 'summary': {'total_count': 0}, 'note': 'Asset register empty'})
    finally:
        conn.close()


