# =============================================================================
# v5.6.0 — Bulk Approve Queue bulletproof rewrite + additional stability fixes
# Fixes:
# 1. get_db() moved inside try block so DB errors return ok=False (not 500)
# 2. Full error detail returned so client can display actual message
# 3. Each table query reports its own error separately
# 4. POST /api/bulk-approve returns 200 JSON even on partial failures
# =============================================================================

def api_get_bulk_approve_queue_v560(session):
    """Bullet-proof bulk approval queue — never raises, always returns JSON."""
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    conn = None
    try:
        conn = get_db()
    except Exception as _dbe:
        return {'ok': False, 'error': 'Database connection failed: %s' % str(_dbe)}

    items = []
    warnings = []

    def _safe_query(label, sql, type_label):
        try:
            for r in conn.execute(sql).fetchall():
                d = dict(r)
                d['type'] = type_label
                # Ensure required fields are always present
                d.setdefault('ref', str(d.get('id', '')))
                d.setdefault('description', '')
                d.setdefault('amount', 0)
                d.setdefault('date', '')
                d.setdefault('submitted_by', '')
                items.append(d)
        except Exception as _qe:
            warnings.append('%s: %s' % (label, str(_qe)))

    try:
        # Unposted payment vouchers / actuals
        _safe_query('actuals',
            "SELECT id, COALESCE(actual_code,id) as ref, description,"
            " COALESCE(amount_ghs,0) as amount,"
            " COALESCE(expense_date,'') as date,"
            " COALESCE(created_by,'') as submitted_by"
            " FROM actuals"
            " WHERE COALESCE(is_posted,0)=0"
            " AND COALESCE(is_deleted,0)=0"
            " ORDER BY created_at DESC LIMIT 100",
            'Actual / PV')

        # Open commitments
        _safe_query('commitments',
            "SELECT id, COALESCE(commit_code,id) as ref, description,"
            " COALESCE(amount_ghs,0) as amount,"
            " COALESCE(commit_date,'') as date,"
            " COALESCE(created_by,'') as submitted_by"
            " FROM commitments"
            " WHERE status='Open'"
            " ORDER BY created_at DESC LIMIT 100",
            'Commitment')

        # Draft / Pending purchase orders
        _safe_query('purchase_orders',
            "SELECT id, COALESCE(po_number,id) as ref,"
            " COALESCE(vendor_name,'Purchase Order') as description,"
            " COALESCE(total_amount_ghs,0) as amount,"
            " COALESCE(po_date,'') as date,"
            " COALESCE(created_by,'') as submitted_by"
            " FROM purchase_orders"
            " WHERE status IN ('Draft','Pending')"
            " ORDER BY created_at DESC LIMIT 100",
            'Purchase Order')

        # Pending staff advances
        _safe_query('staff_advances',
            "SELECT id, id as ref, COALESCE(purpose,'Advance') as description,"
            " COALESCE(amount_ghs,0) as amount,"
            " COALESCE(date_issued,'') as date,"
            " COALESCE(employee_name,'') as submitted_by"
            " FROM staff_advances"
            " WHERE status='Pending'"
            " ORDER BY created_at DESC LIMIT 50",
            'Staff Advance')

        # Draft journal vouchers
        _safe_query('journal_vouchers',
            "SELECT id, COALESCE(jv_number,id) as ref, description,"
            " COALESCE(total_debit,0) as amount,"
            " COALESCE(jv_date,'') as date,"
            " COALESCE(prepared_by,'') as submitted_by"
            " FROM journal_vouchers"
            " WHERE status='Draft'"
            " AND COALESCE(is_deleted,0)=0"
            " ORDER BY jv_date DESC LIMIT 50",
            'Journal Voucher')

        # Pending interunit transfers
        _safe_query('interunit_transfers',
            "SELECT id, COALESCE(transfer_number,id) as ref, description,"
            " COALESCE(amount_ghs,0) as amount,"
            " COALESCE(transfer_date,'') as date,"
            " COALESCE(created_by,'') as submitted_by"
            " FROM interunit_transfers"
            " WHERE status='Pending'"
            " ORDER BY created_at DESC LIMIT 50",
            'Interunit Transfer')

        # Uploaded departmental quarterly budgets awaiting approval
        _safe_query('quarterly_budgets',
            "SELECT id, COALESCE(description,id) as ref,"
            " (COALESCE(dept_code,'')||' · '||COALESCE(academic_year,'')||' · '||COALESCE(description,'Budget line')) as description,"
            " COALESCE(annual_total,0) as amount,"
            " COALESCE(academic_year,'') as date,"
            " COALESCE(created_by,'') as submitted_by"
            " FROM quarterly_budgets"
            " WHERE COALESCE(is_deleted,0)=0 AND COALESCE(approval_status,'Draft') IN ('Draft','Submitted','Pending')"
            " ORDER BY created_at DESC LIMIT 500",
            'Quarterly Budget')

        result = {'ok': True, 'items': items, 'count': len(items)}
        if warnings:
            result['warnings'] = warnings
        return result

    except Exception as e:
        return {'ok': True, 'items': items, 'count': len(items),
                'warnings': warnings + ['Unexpected error: %s' % str(e)]}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def api_bulk_approve_v560(data, session):
    """Approve a list of items. Returns detailed results per-item."""
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    is_admin = str(session.get('role', '')).lower() == 'admin'
    if not is_admin:
        return {'ok': False, 'error': 'Admin access required'}

    items = data.get('items') or []
    if not items:
        return {'ok': False, 'error': 'No items selected for approval'}

    conn = None
    try:
        conn = get_db()
    except Exception as _dbe:
        return {'ok': False, 'error': 'Database connection failed: %s' % str(_dbe)}

    approved = 0
    skipped = 0
    errors = []
    approver = session.get('username', 'admin')

    TYPE_MAP = {
        'Actual / PV':        ('actuals',            'is_posted', 1,         'posted_by',  'posted_at'),
        'Commitment':         ('commitments',         'status',    'Approved', 'approved_by', 'approved_at'),
        'Purchase Order':     ('purchase_orders',     'status',    'Approved', 'approved_by', 'approved_at'),
        'Staff Advance':      ('staff_advances',      'status',    'Approved', 'approved_by', 'approved_at'),
        'Interunit Transfer': ('interunit_transfers', 'status',    'Approved', 'approved_by', 'approved_at'),
        'Journal Voucher':    ('journal_vouchers',    'status',    'Approved', 'approved_by', 'approved_at'),
        'Quarterly Budget':   ('quarterly_budgets',   'approval_status', 'Approved', 'approved_by', 'approved_at'),
    }

    try:
        import uuid as _u560
        import datetime as _dt560
        now = _dt560.datetime.now().strftime('%Y-%m-%d %H:%M:%S')

        for item in items:
            iid  = str(item.get('id') or '').strip()
            itype = str(item.get('type') or '').strip()
            if not iid:
                skipped += 1; continue
            if itype not in TYPE_MAP:
                errors.append('Unknown type %s for id %s' % (itype, iid[:8]))
                skipped += 1; continue
            table, col, val, by_col, at_col = TYPE_MAP[itype]
            try:
                # Check row exists
                exists = conn.execute("SELECT id FROM %s WHERE id=?" % table, (iid,)).fetchone()
                if not exists:
                    skipped += 1; continue

                # Check if table has the approved_by column
                cols_info = [r[1] for r in conn.execute("PRAGMA table_info(%s)" % table).fetchall()]

                sql_parts = ["%s=?" % col]
                sql_vals = [val]
                if by_col in cols_info:
                    sql_parts.append("%s=?" % by_col)
                    sql_vals.append(approver)
                if at_col in cols_info:
                    sql_parts.append("%s=?" % at_col)
                    sql_vals.append(now)
                sql_vals.append(iid)

                conn.execute(
                    "UPDATE %s SET %s WHERE id=?" % (table, ', '.join(sql_parts)),
                    sql_vals
                )
                # Keep workflow_stage consistent for quarterly budgets (new flow) and
                # mirror the approved line into the budgets ledger so it becomes a
                # selectable Budget Line on commitments/actuals.
                if table == 'quarterly_budgets':
                    if 'workflow_stage' in cols_info:
                        try: conn.execute("UPDATE quarterly_budgets SET workflow_stage='Approved' WHERE id=?", (iid,))
                        except Exception: pass
                    _materialize_quarterly_budget(conn, iid, session)
                approved += 1
            except Exception as _item_exc:
                errors.append('Failed %s %s: %s' % (itype, iid[:8], str(_item_exc)))
                skipped += 1

        conn.commit()

        # Audit trail
        try:
            _audit(conn, session, 'BULK_APPROVE_V560', 'bulk_approve', '',
                   'Approved %d items' % approved)
            conn.commit()
        except Exception:
            pass

        result = {'ok': True, 'approved': approved, 'skipped': skipped}
        if errors:
            result['errors'] = errors
        return result

    except Exception as e:
        try: conn.rollback()
        except Exception: pass
        return {'ok': False, 'error': 'Bulk approve failed: %s' % str(e)}
    finally:
        try: conn.close()
        except Exception: pass


