def api_get_aged_payables_v562(session):
    """Aged payables from posted actuals grouped by vendor/payee."""
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    conn = None
    try:
        conn = get_db()
        import datetime as _dt
        today = _dt.date.today()

        rows = conn.execute(
            "SELECT COALESCE(payee,'Unknown') as vendor,"
            " COUNT(*) as invoice_count,"
            " SUM(COALESCE(amount_ghs,0)) as total_ghs,"
            " MIN(expense_date) as oldest_date,"
            " MAX(expense_date) as latest_date"
            " FROM actuals"
            " WHERE COALESCE(is_posted,0)=1"
            " AND COALESCE(is_deleted,0)=0"
            " GROUP BY payee"
            " ORDER BY total_ghs DESC LIMIT 200"
        ).fetchall()

        buckets = {'0_30': 0.0, '31_60': 0.0, '61_90': 0.0, '90_plus': 0.0}
        payables = []
        for r in rows:
            d = dict(r)
            try:
                latest = _dt.date.fromisoformat(str(d['latest_date'])[:10]) if d['latest_date'] else today
                age = (today - latest).days
            except Exception:
                age = 0
            d['days_outstanding'] = age
            if age <= 30:
                d['bucket'] = '0-30 days'
                buckets['0_30'] += float(d['total_ghs'] or 0)
            elif age <= 60:
                d['bucket'] = '31-60 days'
                buckets['31_60'] += float(d['total_ghs'] or 0)
            elif age <= 90:
                d['bucket'] = '61-90 days'
                buckets['61_90'] += float(d['total_ghs'] or 0)
            else:
                d['bucket'] = '90+ days'
                buckets['90_plus'] += float(d['total_ghs'] or 0)
            payables.append(d)

        return {
            'ok': True,
            'payables': payables,
            'summary': {
                'total_vendors': len(payables),
                'total_ghs': round(sum(float(p['total_ghs'] or 0) for p in payables), 2),
                'buckets': {
                    '0_30_days': round(buckets['0_30'], 2),
                    '31_60_days': round(buckets['31_60'], 2),
                    '61_90_days': round(buckets['61_90'], 2),
                    '90_plus_days': round(buckets['90_plus'], 2),
                }
            }
        }
    except Exception as e:
        return {'ok': True, 'payables': [], 'summary': {}, 'note': str(e)}
    finally:
        if conn:
            try:
                conn.close()
            except Exception:
                pass


def api_get_aged_receivables_v562(session):
    """Aged receivables from posted AR invoices grouped by customer.
    Outstanding = total_ghs - amount_received - credited_ghs; aged on due_date.
    (Previously /api/aged-receivables was a hard-coded empty stub.)"""
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    conn = None
    try:
        conn = get_db()
        import datetime as _dt
        today = _dt.date.today()
        rows = conn.execute(
            "SELECT COALESCE(c.customer_name, i.customer_id, 'Unknown') AS customer,"
            " COUNT(*) AS invoice_count,"
            " SUM(COALESCE(i.total_ghs,0) - COALESCE(i.amount_received,0) - COALESCE(i.credited_ghs,0)) AS total_ghs,"
            " MIN(COALESCE(i.due_date, i.invoice_date)) AS oldest_date,"
            " MAX(COALESCE(i.due_date, i.invoice_date)) AS latest_date"
            " FROM ar_invoices i LEFT JOIN ar_customers c ON c.id = i.customer_id"
            " WHERE COALESCE(i.status,'') IN ('Posted','Part-Paid','Outstanding','Overdue')"
            "   AND (COALESCE(i.total_ghs,0) - COALESCE(i.amount_received,0) - COALESCE(i.credited_ghs,0)) > 0.005"
            " GROUP BY COALESCE(c.customer_name, i.customer_id)"
            " ORDER BY total_ghs DESC LIMIT 200"
        ).fetchall()
        buckets = {'0_30': 0.0, '31_60': 0.0, '61_90': 0.0, '90_plus': 0.0}
        receivables = []
        for r in rows:
            d = dict(r)
            try:
                oldest = _dt.date.fromisoformat(str(d['oldest_date'])[:10]) if d['oldest_date'] else today
                age = (today - oldest).days
            except Exception:
                age = 0
            d['days_outstanding'] = age
            amt = float(d['total_ghs'] or 0)
            if age <= 30:
                d['bucket'] = '0-30 days'; buckets['0_30'] += amt
            elif age <= 60:
                d['bucket'] = '31-60 days'; buckets['31_60'] += amt
            elif age <= 90:
                d['bucket'] = '61-90 days'; buckets['61_90'] += amt
            else:
                d['bucket'] = '90+ days'; buckets['90_plus'] += amt
            receivables.append(d)
        return {
            'ok': True,
            'receivables': receivables,
            'summary': {
                'total_customers': len(receivables),
                'total_ghs': round(sum(float(p['total_ghs'] or 0) for p in receivables), 2),
                'buckets': {
                    '0_30_days': round(buckets['0_30'], 2),
                    '31_60_days': round(buckets['31_60'], 2),
                    '61_90_days': round(buckets['61_90'], 2),
                    '90_plus_days': round(buckets['90_plus'], 2),
                }
            }
        }
    except Exception as e:
        return {'ok': False, 'error': 'Request failed: ' + str(e)}
    finally:
        if conn:
            try:
                conn.close()
            except Exception:
                pass


