import urllib.request as _urllib_req
import urllib.error as _urllib_err


def _ai_get_live_context(conn):
    """Pull a short live-data snapshot from the DB for the AI context window."""
    ctx = {}
    def _s(sql, *args, default=0):
        try:
            row = conn.execute(sql, args).fetchone()
            return row[0] if row else default
        except Exception:
            return default

    try:
        ctx['project_count']      = _s("SELECT COUNT(*) FROM projects")
        ctx['budget_total_ghs']   = round(float(_s("SELECT COALESCE(SUM(budget_ghs),0) FROM projects", default=0)), 2)
        ctx['actuals_posted_ghs'] = round(float(_s("SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE COALESCE(is_posted,0)=1 AND COALESCE(is_deleted,0)=0", default=0)), 2)
        ctx['actuals_pending']    = _s("SELECT COUNT(*) FROM actuals WHERE COALESCE(is_posted,0)=0 AND COALESCE(is_deleted,0)=0")
        ctx['commitments_open']   = _s("SELECT COUNT(*) FROM commitments WHERE COALESCE(status,'Open')='Open'")
        ctx['vendors_count']      = _s("SELECT COUNT(*) FROM vendors")
        ctx['users_count']        = _s("SELECT COUNT(*) FROM users WHERE COALESCE(active,1)=1")
        ctx['open_commitment_value_ghs'] = round(float(_s("SELECT COALESCE(SUM(MAX(0, c.amount_ghs - COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.commitment_id=c.id AND COALESCE(a.is_posted,0)=1),0))),0) FROM commitments c WHERE COALESCE(c.status,'') NOT IN ('Cancelled','Fully Paid')", default=0)), 2)
        ctx['cash_and_bank_ghs']  = round(float(_s("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '126%' OR coa_code LIKE '127%' OR coa_code LIKE '128%' OR coa_code LIKE '129%' OR coa_code='1001'", default=0)), 2)
        ctx['spend_this_year_ghs'] = round(float(_s("SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE COALESCE(is_posted,0)=1 AND substr(COALESCE(expense_date,''),1,4)=strftime('%Y','now')", default=0)), 2)
        ctx['pending_approvals']  = _s("SELECT COUNT(*) FROM approvals WHERE COALESCE(status,'')='Pending'")
        ctx['pending_withholdings_ghs'] = round(float(_s("SELECT COALESCE(SUM(amount_ghs),0) FROM withholding_payables WHERE COALESCE(status,'')='Pending'", default=0)), 2)
        ctx['overdue_withholdings'] = _s("SELECT COUNT(*) FROM withholding_payables WHERE COALESCE(status,'')='Pending' AND due_date IS NOT NULL AND due_date < date('now')")
        ctx['overdue_withholdings_ghs'] = round(float(_s("SELECT COALESCE(SUM(amount_ghs),0) FROM withholding_payables WHERE COALESCE(status,'')='Pending' AND due_date IS NOT NULL AND due_date < date('now')", default=0)), 2)
        ctx['receivables_outstanding_ghs'] = round(float(_s("SELECT COALESCE(SUM(total_ghs - amount_received - COALESCE(credited_ghs,0)),0) FROM ar_invoices WHERE status IN ('Posted','Part-Paid')", default=0)), 2)
        ctx['receivables_overdue_ghs'] = round(float(_s("SELECT COALESCE(SUM(total_ghs - amount_received - COALESCE(credited_ghs,0)),0) FROM ar_invoices WHERE status IN ('Posted','Part-Paid') AND due_date IS NOT NULL AND due_date < date('now')", default=0)), 2)
        ctx['inventory_value_ghs'] = round(float(_s("SELECT COALESCE(SUM(qty_on_hand*avg_cost),0) FROM inv_items", default=0)), 2)
        ctx['fuel_coupon_stock_ghs'] = round(float(_s("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_batches", default=0)) + float(_s("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type IN ('Borrow','Return','Return-Issued','Return-Lent')", default=0)) - float(_s("SELECT COALESCE(SUM(face_value),0) FROM fuel_coupon_movements WHERE movement_type IN ('Issue','Lend','Return-Borrowed')", default=0)), 2)
        ctx['inventory_low_stock'] = _s("SELECT COUNT(*) FROM inv_items WHERE reorder_level>0 AND qty_on_hand<=reorder_level")
        try:
            ctx['periods'] = [r[0] for r in conn.execute(
                "SELECT period FROM accounting_periods ORDER BY period DESC LIMIT 3"
            ).fetchall()]
        except Exception:
            ctx['periods'] = []
    except Exception:
        pass
    return ctx


def api_ai_chat_v563(session, data):
    """
    Proxy POST /api/ai/chat → Anthropic Claude API.
    Enriches the system prompt with live DB data before forwarding.
    Returns the Anthropic API response JSON directly.
    """
    import json as _j, os as _os, time as _t

    if not session:
        return {'type': 'error', 'error': {'message': 'Not authenticated'}}

    api_key = _os.environ.get('ANTHROPIC_API_KEY', '').strip()
    if not api_key:
        # Friendly not-configured message — app still usable
        return {
            'content': [{
                'type': 'text',
                'text': (
                    "I'm not fully activated yet — an ANTHROPIC_API_KEY environment variable "
                    "needs to be set in the server environment. Once configured, I'll be able "
                    "to answer any question about finance, accounting standards, ERP workflows, "
                    "or anything else you need.\n\n"
                    "**In the meantime**, try asking me about specific ERP topics — I have some "
                    "built-in knowledge about this system."
                )
            }]
        }

    # Build live DB context to inject into the system prompt
    conn = None
    live_lines = []
    try:
        conn = get_db()
        ctx = _ai_get_live_context(conn)
        if ctx:
            live_lines.append('\n\n--- LIVE DATA SNAPSHOT ---')
            live_lines.append('Projects: %d  |  Total budget: GHS %s  |  Posted actuals: GHS %s' % (
                ctx.get('project_count', 0),
                '{:,.0f}'.format(ctx.get('budget_total_ghs', 0)),
                '{:,.0f}'.format(ctx.get('actuals_posted_ghs', 0))
            ))
            live_lines.append('Pending (unposted) actuals: %d  |  Open commitments: %d  |  Vendors: %d' % (
                ctx.get('actuals_pending', 0),
                ctx.get('commitments_open', 0),
                ctx.get('vendors_count', 0)
            ))
            if ctx.get('periods'):
                live_lines.append('Recent accounting periods: %s' % ', '.join(ctx['periods']))
            live_lines.append('--------------------------')
    except Exception:
        pass
    finally:
        if conn:
            try: conn.close()
            except Exception: pass

    model = data.get('model') or 'claude-haiku-4-5-20251001'
    messages = data.get('messages') or []
    max_tokens = min(int(data.get('max_tokens') or 1500), 4096)
    system_base = data.get('system') or ''
    system = system_base + '\n'.join(live_lines)

    payload = _j.dumps({
        'model': model,
        'max_tokens': max_tokens,
        'system': system,
        'messages': messages
    }).encode('utf-8')

    req = _urllib_req.Request(
        'https://api.anthropic.com/v1/messages',
        data=payload,
        headers={
            'x-api-key': api_key,
            'anthropic-version': '2023-06-01',
            'content-type': 'application/json',
        },
        method='POST'
    )

    t0 = _t.time()
    try:
        with _urllib_req.urlopen(req, timeout=45) as resp:
            result = _j.loads(resp.read())
        # Log success
        try:
            conn2 = get_db()
            q_summary = (messages[-1].get('content', '') if messages else '')[:120]
            conn2.execute(
                "INSERT OR IGNORE INTO chatbot_usage_log(id,username,provider,model,question_summary,status,tokens_estimated,created_at)"
                " VALUES(?,?,?,?,?,?,?,datetime('now'))",
                (str(uuid.uuid4()), session.get('username', ''), 'Anthropic', model,
                 q_summary, 'OK', result.get('usage', {}).get('output_tokens', 0))
            )
            conn2.commit()
            conn2.close()
        except Exception:
            pass
        return result

    except _urllib_err.HTTPError as e:
        body = e.read().decode('utf-8', errors='replace')
        try:
            return _j.loads(body)
        except Exception:
            return {'type': 'error', 'error': {'message': body[:500]}}
    except Exception as ex:
        return {'type': 'error', 'error': {'message': str(ex)}}


