# =============================================================================
# v5.6.4 — Security Hardening & Deployment Readiness
#
# 1. Session timeout — 30-min idle / 24-hr absolute; touch last_active each request
# 2. Password policy — min 10 chars, upper+lower+digit (server-side enforcement)
# 3. Login rate limiting — 5 failures in 15 min → temporary lockout
# 4. Security HTTP headers — X-Frame-Options, X-Content-Type-Options, etc.
# 5. Health check — GET /api/health → DB ping, uptime, session count
# 6. Daily auto-backup — first request after midnight → DB snapshot (7-day retention)
# 7. Deployment audit — GET /api/deployment-audit → 25-item pre-live checklist
# Guard: # v564-security-hardening-complete
# =============================================================================

import hashlib as _v564_hl
_v564_start_time = time.time()
_v564_last_backup_day = [None]  # mutable list so closure can mutate it


# ─── 1. Session timeout (redefine get_session) ───────────────────────────────
_v564_SESSION_IDLE = 1800   # 30 minutes idle → expire
_v564_SESSION_ABS  = 86400  # 24 hours absolute → expire

def get_session(sid):
    if not sid: return None
    s = sessions.get(sid)
    if not s: return None
    now = time.time()
    last = s.get('last_active', s.get('created', now))
    if now - last > _v564_SESSION_IDLE:
        sessions.pop(sid, None)
        return None
    if now - s.get('created', now) > _v564_SESSION_ABS:
        sessions.pop(sid, None)
        return None
    s['last_active'] = now
    return s

print('[v564] Session timeout active: 30-min idle / 24-hr absolute')
# Enable WAL mode at startup for better concurrent read/write performance
try:
    _v564_wal_conn = get_db()
    _v564_wal_conn.execute("PRAGMA journal_mode=WAL")
    _v564_wal_conn.execute("PRAGMA wal_autocheckpoint=1000")
    _v564_wal_conn.commit()
    _v564_wal_conn.close()
    print('[v564] SQLite WAL mode enabled')
except Exception as _v564_wale:
    print('[v564] WAL enable note: %s' % _v564_wale)



# ─── 2. Password policy (redefine api_change_password) ───────────────────────
_v564_orig_change_pw = api_change_password

def api_change_password(data, session):
    pw = data.get('new_password', '')
    if len(pw) < 10:
        return {'ok': False, 'error': 'Password must be at least 10 characters long'}
    if not any(c.isupper() for c in pw):
        return {'ok': False, 'error': 'Password must include at least one uppercase letter'}
    if not any(c.islower() for c in pw):
        return {'ok': False, 'error': 'Password must include at least one lowercase letter'}
    if not any(c.isdigit() for c in pw):
        return {'ok': False, 'error': 'Password must include at least one number'}
    return _v564_orig_change_pw(data, session)

print('[v564] Password policy: min 10 chars, upper+lower+digit')


# ─── 3. Login rate limiting (redefine api_login) ─────────────────────────────
_v564_login_attempts = {}   # {username_lower: [timestamp, ...]}
_v564_MAX_FAILS      = 5
_v564_LOCK_WINDOW    = 900  # 15 minutes

_v564_orig_api_login = api_login

def api_login(data):
    uname = (data.get('username') or '').lower().strip()
    now   = time.time()
    # Prune stale attempts
    if uname in _v564_login_attempts:
        _v564_login_attempts[uname] = [t for t in _v564_login_attempts[uname] if now - t < _v564_LOCK_WINDOW]
    attempts = _v564_login_attempts.get(uname, [])
    if len(attempts) >= _v564_MAX_FAILS:
        remaining_sec = int(_v564_LOCK_WINDOW - (now - attempts[0]))
        mins = max(1, remaining_sec // 60)
        return {'ok': False, 'error': 'Too many failed attempts — account locked for %d minute(s). Please try again later.' % mins}
    result = _v564_orig_api_login(data)
    if not (result or {}).get('ok'):
        _v564_login_attempts.setdefault(uname, []).append(now)
        try:
            _v564_ac = get_db()
            _v564_ac.execute(
                "INSERT INTO audit_log(id,username,user_role,action,module,record_id,details) VALUES(?,?,?,?,?,?,?)",
                (str(uuid.uuid4()), uname, '', 'LOGIN_FAILED', 'security', 'auth', 'Failed login attempt for: ' + uname))
            _v564_ac.commit(); _v564_ac.close()
        except Exception: pass
    else:
        _v564_login_attempts.pop(uname, None)  # clear on successful login
        try:
            _v564_usr = (result.get('user') or {}); _v564_ac = get_db()
            _v564_ac.execute(
                "INSERT INTO audit_log(id,username,user_role,action,module,record_id,details) VALUES(?,?,?,?,?,?,?)",
                (str(uuid.uuid4()), _v564_usr.get('username', uname), _v564_usr.get('role', ''), 'LOGIN_SUCCESS', 'security', 'auth', 'Successful login'))
            _v564_ac.commit(); _v564_ac.close()
        except Exception: pass
    return result

print('[v564] Login rate limiting: 5 fails → 15-min lockout')


# ─── 4. Daily auto-backup ────────────────────────────────────────────────────
def _v564_maybe_backup():
    import datetime as _v564_dt, shutil as _v564_sh, os as _v564_os
    today = _v564_dt.date.today().isoformat()
    if _v564_last_backup_day[0] == today:
        return
    _v564_last_backup_day[0] = today
    try:
        base    = _v564_os.path.dirname(_v564_os.path.abspath(__file__))
        db_path = str(DB_PATH)  # v564-backup-fix
        if not _v564_os.path.exists(db_path):
            return
        bkp_dir = _v564_os.path.join(base, 'backups')
        _v564_os.makedirs(bkp_dir, exist_ok=True)
        bkp_file = _v564_os.path.join(bkp_dir, '%s_%s.db' % (DB_PATH.stem, today))
        if not _v564_os.path.exists(bkp_file):
            _v564_sh.copy2(db_path, bkp_file)
            print('[v564] Daily backup created: %s' % bkp_file)
        # Keep only the last 7 backups
        all_bkps = sorted([f for f in _v564_os.listdir(bkp_dir)
                           if f.startswith(DB_PATH.stem + '_') and f.endswith('.db')])
        for old in all_bkps[:-7]:
            try: _v564_os.remove(_v564_os.path.join(bkp_dir, old))
            except Exception: pass
    except Exception as _v564_be:
        print('[v564] Backup warning: %s' % _v564_be)


# ─── 5. Health check ─────────────────────────────────────────────────────────
