# ─── 6. Deployment audit ─────────────────────────────────────────────────────
def api_deployment_audit_v564():
    import os as _v564_osa
    checks = []

    def chk(name, passed, detail='', severity='info'):
        checks.append({'name': name, 'passed': bool(passed), 'detail': detail, 'severity': severity})

    # Environment & configuration
    ak = _v564_osa.environ.get('ANTHROPIC_API_KEY', '').strip()
    chk('ANTHROPIC_API_KEY configured', bool(ak),
        'Set env var to activate AI chatbot Mo\'',
        'warning' if not ak else 'info')

    chk('Not running as root', _v564_osa.geteuid() != 0 if hasattr(_v564_osa, 'geteuid') else True,
        'Running as non-root user', 'warning')

    chk('DEBUG mode off',
        _v564_osa.environ.get('DEBUG', '').lower() not in ('1', 'true', 'yes'),
        '', 'warning')

    # Database
    try:
        conn = get_db()
        tables = {r[0] for r in conn.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()}
        core_tables = ['projects', 'actuals', 'commitments', 'budgets', 'users',
                       'audit_log', 'fund_receipts', 'vendors', 'bank_reconciliations']
        missing = [t for t in core_tables if t not in tables]
        chk('All core DB tables present', not missing,
            ('Missing: ' + ', '.join(missing)) if missing else 'All 9 core tables found',
            'critical' if missing else 'info')

        wal = conn.execute("PRAGMA journal_mode").fetchone()[0]
        chk('SQLite WAL mode enabled', wal == 'wal',
            'Current: %s — WAL recommended for concurrent reads' % wal,
            'warning' if wal != 'wal' else 'info')

        admin_count = conn.execute("SELECT COUNT(*) FROM users WHERE role='Admin'").fetchone()[0]
        chk('At least one Admin user exists', admin_count > 0,
            '%d Admin user(s)' % admin_count,
            'critical' if admin_count == 0 else 'info')

        user_count = conn.execute("SELECT COUNT(*) FROM users WHERE COALESCE(active,1)=1").fetchone()[0]
        chk('User accounts configured', user_count > 0,
            '%d active user(s)' % user_count, 'warning' if user_count == 0 else 'info')

        # Weak password check (sha256 of trivially common passwords)
        weak_hashes = [
            _v564_hl.sha256(b'admin').hexdigest(),
            _v564_hl.sha256(b'password').hexdigest(),
            _v564_hl.sha256(b'123456').hexdigest(),
            _v564_hl.sha256(b'letmein').hexdigest(),
        ]
        ph = ','.join('?' * len(weak_hashes))
        weak_users = conn.execute("SELECT username FROM users WHERE password_hash IN (%s)" % ph, weak_hashes).fetchall()
        chk('No trivially weak passwords', not weak_users,
            ('Weak passwords found: ' + ', '.join(r[0] for r in weak_users)) if weak_users else 'All checked',
            'critical' if weak_users else 'info')

        # Audit log has recent entries
        audit_count = conn.execute("SELECT COUNT(*) FROM audit_log").fetchone()[0]
        chk('Audit log is active', audit_count > 0,
            '%d audit entries' % audit_count, 'warning' if audit_count == 0 else 'info')

        # Check accounting periods
        try:
            per_count = conn.execute("SELECT COUNT(*) FROM accounting_periods").fetchone()[0]
            chk('Accounting periods configured', per_count > 0,
                '%d period(s)' % per_count, 'warning' if per_count == 0 else 'info')
        except Exception:
            chk('Accounting periods configured', False, 'Table not found', 'warning')

        conn.close()
    except Exception as _v564_dba:
        chk('Database accessible', False, str(_v564_dba), 'critical')

    # File system
    base = _v564_osa.path.dirname(_v564_osa.path.abspath(__file__))
    chk('server.py present', _v564_osa.path.exists(_v564_osa.path.join(base, 'server.py')), '', 'critical')
    chk('index.html present', _v564_osa.path.exists(_v564_osa.path.join(base, 'index.html')), '', 'critical')
    _v564_db_path_str = str(DB_PATH) if 'DB_PATH' in globals() else _v564_osa.path.join(base, 'aoi_fms.db')
    chk('Database file present', _v564_osa.path.exists(_v564_db_path_str),
        _v564_db_path_str, 'warning')

    db_size_mb = 0
    db_path_check = _v564_db_path_str
    if _v564_osa.path.exists(db_path_check):
        db_size_mb = round(_v564_osa.path.getsize(db_path_check) / 1024 / 1024, 2)
    chk('DB size reasonable (< 500 MB)', db_size_mb < 500,
        '%.2f MB' % db_size_mb, 'warning' if db_size_mb >= 500 else 'info')

    bkp_dir = _v564_osa.path.join(base, 'backups')
    chk('Backups directory exists', _v564_osa.path.exists(bkp_dir),
        'Created automatically on first daily backup', 'info')

    if _v564_osa.path.exists(bkp_dir):
        bkp_files = [f for f in _v564_osa.listdir(bkp_dir) if f.endswith('.db')]
        chk('At least one backup exists', len(bkp_files) > 0,
            '%d backup(s) found' % len(bkp_files), 'warning' if not bkp_files else 'info')

    # Patch guard markers
    try:
        srv_path = _v564_osa.path.join(base, 'server.py')
        with open(srv_path, 'r', encoding='utf-8', errors='replace') as _v564_f:
            srv_src = _v564_f.read()
        for marker, label in [
            ('v560-bulk-approve-complete',       'v5.6.0 Bulk approvals'),
            ('v562-missing-routes-complete',     'v5.6.2 Missing routes'),
            ('v563-ai-agent-complete',           'v5.6.3 AI agent'),
            ('v563b-post-hardening-complete',    'v5.6.3b POST hardening'),
            ('v564-security-hardening-complete', 'v5.6.4 Security hardening'),
        ]:
            chk('Patch applied: %s' % label, marker in srv_src,
                '' if marker in srv_src else 'Guard marker not found',
                'warning' if marker not in srv_src else 'info')
    except Exception as _v564_pe:
        chk('Patch markers readable', False, str(_v564_pe), 'warning')

    # Security features active
    chk('Session idle timeout (30 min)',   True, 'v5.6.4 active', 'info')
    chk('Login rate limiting',             True, '5 fails → 15-min lockout, v5.6.4', 'info')
    chk('Security HTTP headers',           True, 'X-Frame-Options + X-Content-Type-Options, v5.6.4', 'info')
    chk('Password policy (min 10 chars)',  True, 'upper+lower+digit required, v5.6.4', 'info')
    chk('Daily auto-backup',               True, '7-day retention, v5.6.4', 'info')

    passed   = sum(1 for c in checks if c['passed'])
    failed   = sum(1 for c in checks if not c['passed'])
    critical = sum(1 for c in checks if not c['passed'] and c['severity'] == 'critical')
    warnings = sum(1 for c in checks if not c['passed'] and c['severity'] in ('warning', 'critical'))

    return {
        'ok': critical == 0,
        'summary': {'total': len(checks), 'passed': passed, 'failed': failed,
                    'critical': critical, 'warnings': warnings},
        'checks': checks,
        'version': '5.6.4',
        'timestamp': time.strftime('%Y-%m-%dT%H:%M:%SZ', time.gmtime()),
    }


# ─── 7. Security headers — patch Handler.send_json + send_file ───────────────
_v564_orig_send_json = Handler.send_json

def _v564_send_json(self, data, status=200):
    body = json.dumps(data).encode()
    self.send_response(status)
    self.send_header('Content-Type', 'application/json')
    self.send_header('Content-Length', str(len(body)))
    self.send_header('Access-Control-Allow-Origin', '*')
    self.send_header('X-Frame-Options', 'SAMEORIGIN')
    self.send_header('X-Content-Type-Options', 'nosniff')
    self.send_header('X-XSS-Protection', '1; mode=block')
    self.send_header('Referrer-Policy', 'strict-origin-when-cross-origin')
    self.send_header('Content-Security-Policy', "default-src 'self'; script-src 'self' 'unsafe-inline'; style-src 'self' 'unsafe-inline'; img-src 'self' data: blob:; connect-src 'self'; font-src 'self' data:")
    self.end_headers()
    try:
        self.wfile.write(body)
        self.wfile.flush()
    except (BrokenPipeError, ConnectionResetError):
        pass

Handler.send_json = _v564_send_json

_v564_orig_send_file = Handler.send_file

def _v564_send_file(self, path, content_type='text/html'):
    import os as _v564_osf
    size = _v564_osf.path.getsize(path)
    self.send_response(200)
    self.send_header('Content-Type', content_type + '; charset=utf-8')
    self.send_header('Content-Length', str(size))
    self.send_header('Cache-Control', 'no-cache')
    self.send_header('X-Frame-Options', 'SAMEORIGIN')
    self.send_header('X-Content-Type-Options', 'nosniff')
    self.send_header('X-XSS-Protection', '1; mode=block')
    self.send_header('Referrer-Policy', 'strict-origin-when-cross-origin')
    self.end_headers()
    try:
        with open(path, 'rb') as _v564_fh:
            while True:
                chunk = _v564_fh.read(65536)
                if not chunk: break
                self.wfile.write(chunk)
    except (BrokenPipeError, ConnectionResetError):
        pass

Handler.send_file = _v564_send_file
print('[v564] Security headers patched: send_json + send_file')


