# v8.2 AUDIT FIX PATCH -- Run missing migrations + fix response shapes
try:
    # 1. Run _v55_migrate() which was never called -- creates approval_rules_v55
    #    and document_attachments_v55 tables required by approvals & attachments views
    try:
        _v55_migrate()
        print('[v8.2] _v55_migrate() completed -- approval_rules_v55, document_attachments_v55 created')
    except Exception as _v55e:
        print('[v8.2] _v55_migrate() warning:', _v55e)

    # 2. Override GET handler to fix response shape mismatches
    #    /api/notifications: v557b wraps in {ok,notifications,unread,total}
    #                        but frontend does notes.map() -- needs flat array
    #    /api/search: v557b wraps in {ok,results,query,count}
    #                 but frontend does res.map() -- needs flat array
    _v81_prev_do_GET = Handler.do_GET

    def _v81_do_GET(self):
        from urllib.parse import urlparse, parse_qs
        _path = urlparse(self.path).path
        _qs   = parse_qs(urlparse(self.path).query)
        def _p1(k): return (_qs.get(k) or [None])[0]

        if _path == '/api/notifications':
            session = self.get_session()
            if not session:
                return self.send_json({'error': 'Not authenticated'}, 401)
            try:
                raw = api_notifications_v557b(session, _p1('limit'))
                if isinstance(raw, list):
                    return self.send_json(raw)
                # unwrap {ok, notifications:[...], unread, total} -> flat list
                flat = raw.get('notifications', []) if isinstance(raw, dict) else []
                return self.send_json(flat)
            except Exception as _nf_e:
                return self.send_json([], 200)

        if _path == '/api/search':
            session = self.get_session()
            if not session:
                return self.send_json({'error': 'Not authenticated'}, 401)
            try:
                raw = api_search_v557b(session, q=_p1('q'), module=_p1('module'))
                if isinstance(raw, list):
                    return self.send_json(raw)
                # unwrap {ok, results:[...], query, count} -> flat list
                flat = raw.get('results', []) if isinstance(raw, dict) else []
                return self.send_json(flat)
            except Exception as _sf_e:
                return self.send_json([], 200)

        return _v81_prev_do_GET(self)

    Handler.do_GET = _v81_do_GET
    print('[v8.2] Response-shape fixes: /api/notifications and /api/search now return flat arrays')

except Exception as _v81_err:
    print('[v8.2] Audit fix patch warning:', _v81_err)


