# DEMO ACCOUNT = TRAINING MODE (automatic DB isolation, no separate process)
# Logging in as 'demo' routes ALL operations to an isolated demo database.
# The live database is completely untouched for demo sessions.
# ════════════════════════════════════════════════════════════════════════════════
try:
    import threading as _demo_threading

    # ── 1. Demo DB path (sibling of live DB, never the same file) ──────────────
    _DEMO_DB_PATH = DB_PATH.parent / (DB_PATH.stem + '_demo' + DB_PATH.suffix)
    _demo_tl = _demo_threading.local()   # thread-local: is_demo flag per request

    # ── 2. Override get_db() to route demo sessions to the demo DB ─────────────
    _demo_prev_get_db = get_db
    def get_db():
        if getattr(_demo_tl, 'is_demo', False):
            _c = sqlite3.connect(str(_DEMO_DB_PATH))
            _c.row_factory = sqlite3.Row
            _c.execute("PRAGMA foreign_keys = ON")
            return _c
        return _demo_prev_get_db()

    # ── 3. Patch Handler.get_session to set the thread-local automatically ──────
    #    Every HTTP request handler calls get_session() first.  We intercept
    #    that call to flip the demo DB flag before any get_db() is invoked.
    _demo_prev_handler_get_session = Handler.get_session
    def _demo_handler_get_session(self):
        sess = _demo_prev_handler_get_session(self)
        _demo_tl.is_demo = bool(sess and sess.get('demo_mode'))
        return sess
    Handler.get_session = _demo_handler_get_session

    # ── 4. Wrap api_login to detect 'demo' user and initialise demo DB ─────────
    _demo_prev_api_login = api_login
    def api_login(data):
        result = _demo_prev_api_login(data)
        try:
            if result.get('ok') and \
               (result.get('user') or {}).get('username', '').lower() == 'demo':
                sid = result.get('sid', '')
                # Mark session as demo
                if sid and sid in sessions:
                    sessions[sid]['demo_mode'] = True
                # Surface flag to the frontend via login response
                if isinstance(result.get('user'), dict):
                    result['user']['demo_mode'] = True
                # Demo DB is pre-initialised at startup — nothing to do here
                if not _DEMO_DB_PATH.exists() or _DEMO_DB_PATH.stat().st_size < 4096:
                    _demo_tl.is_demo = True
                    try:
                        init_db()
                        print('  [DEMO] Demo DB fallback seed complete.')
                    finally:
                        _demo_tl.is_demo = False
        except Exception as _de:
            print('  [DEMO] Login hook error (non-fatal):', _de)
        return result

    # ── 5. /api/demo/reset — wipe and re-seed the demo DB (demo user only) ─────
    _demo_prev_do_POST = Handler.do_POST
    def _demo_do_POST(self):
        try:
            from urllib.parse import urlparse as _up
            if _up(self.path).path == '/api/demo/reset':
                sess = self.get_session()   # sets _demo_tl.is_demo via patch above
                if not sess or sess.get('username', '').lower() != 'demo':
                    return self.send_json({'ok': False,
                        'error': 'Demo reset is only available for the demo account.'})
                try:
                    # Invalidate all existing demo sessions (forces re-login)
                    for _sid in list(sessions.keys()):
                        if sessions[_sid].get('demo_mode'):
                            del sessions[_sid]
                    # Delete and re-create the demo DB (schema-copy + seed)
                    _demo_tl.is_demo = False
                    if _DEMO_DB_PATH.exists():
                        _DEMO_DB_PATH.unlink()
                    _live_rc = _demo_prev_get_db()
                    _reset_ddl = [r[0] for r in _live_rc.execute(
                        "SELECT sql FROM sqlite_master "
                        "WHERE sql IS NOT NULL AND type IN ('table','index','trigger') "
                        "ORDER BY rootpage").fetchall()]
                    _live_rc.close()
                    _demo_rc = sqlite3.connect(str(_DEMO_DB_PATH))
                    _demo_rc.execute("PRAGMA foreign_keys = OFF")
                    for _d in _reset_ddl:
                        try: _demo_rc.execute(_d)
                        except Exception: pass
                    _demo_rc.execute("PRAGMA foreign_keys = ON")
                    _demo_rc.commit(); _demo_rc.close()
                    _demo_tl.is_demo = True
                    try:
                        init_db()
                        try:
                            init_payroll_db()
                        except Exception:
                            pass
                    finally:
                        _demo_tl.is_demo = False
                    print('  [DEMO] Training DB reset and re-initialised (full schema).')
                    return self.send_json({'ok': True,
                        'message': 'Training data cleared. Please log out and log back in as demo to continue.'})
                except Exception as _re:
                    _demo_tl.is_demo = False
                    return self.send_json({'ok': False, 'error': 'Reset error: ' + str(_re)})
        except Exception:
            pass
        return _demo_prev_do_POST(self)
    Handler.do_POST = _demo_do_POST

    # ── Eager demo DB pre-initialisation at startup ─────────────────────────
    try:
        if not _DEMO_DB_PATH.exists() or _DEMO_DB_PATH.stat().st_size < 4096:
            if _DEMO_DB_PATH.exists():
                _DEMO_DB_PATH.unlink()
            _live_sc = sqlite3.connect(str(DB_PATH))
            _schema_ddl = [r[0] for r in _live_sc.execute(
                "SELECT sql FROM sqlite_master "
                "WHERE sql IS NOT NULL AND type IN ('table','index','trigger') "
                "ORDER BY rootpage"
            ).fetchall()]
            _live_sc.close()
            _demo_sc = sqlite3.connect(str(_DEMO_DB_PATH))
            _demo_sc.execute("PRAGMA foreign_keys = OFF")
            for _ddl in _schema_ddl:
                try:
                    _demo_sc.execute(_ddl)
                except Exception:
                    pass
            _demo_sc.execute("PRAGMA foreign_keys = ON")
            _demo_sc.commit()
            _demo_sc.close()
            _demo_tl.is_demo = True
            try:
                init_db()
                try:
                    init_payroll_db()  # re-seed payroll_settings (schema-copy skips it)
                except Exception:
                    pass
            finally:
                _demo_tl.is_demo = False
            print('  [DEMO] Demo DB pre-initialised (full schema + seed):', str(_DEMO_DB_PATH))
        else:
            print('  [DEMO] Demo DB already exists — skipping pre-init:', str(_DEMO_DB_PATH))
    except Exception as _demo_preinit_exc:
        print('  [DEMO] Demo DB pre-init warning (non-fatal):', _demo_preinit_exc)

    print('  [DEMO] Demo-account training mode ready. Login as "demo" for isolated sandbox.')

except Exception as _demo_init_exc:
    print('  [DEMO] Demo mode setup warning (non-fatal):', _demo_init_exc)
