# ADMIN RECOVERY — only active when ADMIN_RECOVERY_TOKEN env var is set
# To use: set ADMIN_RECOVERY_TOKEN=<secret> in Render dashboard, redeploy,
# then call: GET /api/admin-recovery?token=<secret>
# This resets the admin password to UCC@2024 and clears any rate-limit lockout.
# Remove the env var after recovery.
try:
    import os as _rec_os
    import hashlib as _rec_hl

    _REC_TOKEN = _rec_os.environ.get('ADMIN_RECOVERY_TOKEN', '').strip()

    if _REC_TOKEN:
        def api_admin_recovery(token):
            if not _REC_TOKEN or token != _REC_TOKEN:
                return {'ok': False, 'error': 'Invalid or missing recovery token'}
            try:
                import secrets as _rec_sec
                conn = get_db()
                new_pw = _rec_sec.token_urlsafe(16)
                new_hash = _rec_hl.sha256(new_pw.encode()).hexdigest()
                conn.execute(
                    "UPDATE users SET password_hash=?, active=1 WHERE username='admin'",
                    (new_hash,)
                )
                conn.commit()
                conn.close()
                # also clear rate-limit lockout for admin
                try:
                    _v564_login_attempts.pop('admin', None)
                except Exception:
                    pass
                print('[RECOVERY] Admin password reset to a new random value.')
                print(f'[RECOVERY] One-time admin password: {new_pw}')
                return {'ok': True, 'message': 'Admin password has been reset. The new password was printed to server logs only. Remove ADMIN_RECOVERY_TOKEN env var now.'}
            except Exception as _re:
                return {'ok': False, 'error': str(_re)}

        _rec_prev_do_GET = Handler.do_GET
        def _rec_do_GET(self):
            from urllib.parse import urlparse, parse_qs
            _rpath = urlparse(self.path).path
            if _rpath == '/api/admin-recovery':
                _rqs = parse_qs(urlparse(self.path).query)
                _tok = (_rqs.get('token') or [''])[0]
                return self.send_json(api_admin_recovery(_tok))
            return _rec_prev_do_GET(self)
        Handler.do_GET = _rec_do_GET
        print('[RECOVERY] Admin recovery endpoint active: GET /api/admin-recovery?token=<ADMIN_RECOVERY_TOKEN>')
    else:
        print('[RECOVERY] Admin recovery endpoint disabled (ADMIN_RECOVERY_TOKEN not set)')

except Exception as _rec_exc:
    print('[RECOVERY] Recovery setup warning:', _rec_exc)

