# v10.0 — Bulk Upload: Employees & Annual Budgets
# ═══════════════════════════════════════════════════════════════════════════════
try:
    import csv as _v10_csv, io as _v10_io

    # ── helpers ────────────────────────────────────────────────────────────────
    def _v10_float(val, default=0.0):
        try: return float(str(val).replace(',','').strip()) if str(val).strip() else default
        except: return default

    def _v10_int(val, default=0):
        try: return int(str(val).replace(',','').strip()) if str(val).strip() else default
        except: return default

    def _v10_str(val, default=''):
        return str(val).strip() if val is not None and str(val).strip() else default

    def _v10_ensure_default_project(conn):
        """Return the id of a default institutional project, creating one if none exist."""
        row = conn.execute("SELECT id FROM projects WHERE is_deleted=0 OR is_deleted IS NULL ORDER BY created_at LIMIT 1").fetchone()
        if row:
            return row[0]
        import uuid as _uuid
        pid = str(_uuid.uuid4())
        conn.execute(
            "INSERT OR IGNORE INTO projects(id,project_code,title,donor,division,start_date,end_date,currency,budget_fcy,fx_rate,budget_ghs,status,created_by) "
            "VALUES(?,?,?,?,?,?,?,?,0,1,0,?,?)",
            (pid,'INST-GEN','General Institutional Budget','Internal','General','2024-01-01','2099-12-31','GHS','Active','system')
        )
        conn.commit()
        return pid

    # ── EMPLOYEE BULK UPLOAD ───────────────────────────────────────────────────
    def api_upload_employees(data, session):
        if not session:
            return {'ok': False, 'error': 'Not authenticated'}
        if session.get('role') not in ('Admin', 'Finance Officer', 'HR Officer'):
            return {'ok': False, 'error': 'Admin or HR Officer access required'}
        rows = data.get('rows', [])
        if not rows:
            return {'ok': False, 'error': 'No rows provided'}

        conn = get_db()
        imported = 0; failed = 0; errors = []
        try:
            for i, row in enumerate(rows):
                rnum = i + 2   # 1-indexed, header is row 1
                name = _v10_str(row.get('full_name') or row.get('name'))
                div  = _v10_str(row.get('division') or row.get('dept_code') or row.get('department'))
                etype= _v10_str(row.get('employment_type') or row.get('type'), 'Permanent')
                if not name:
                    failed += 1
                    if len(errors) < 10: errors.append('Row %d: full_name is required' % rnum)
                    continue
                if not div:
                    failed += 1
                    if len(errors) < 10: errors.append('Row %d: division is required' % rnum)
                    continue

                import uuid as _uuid2
                eid = str(_uuid2.uuid4())
                emp_id = _v10_str(row.get('employee_id') or row.get('emp_id') or row.get('staff_id'))
                if not emp_id:
                    emp_id = 'EMP-' + eid[:6].upper()

                # Check duplicate employee_id
                existing = conn.execute("SELECT id FROM employees WHERE employee_id=?", (emp_id,)).fetchone()
                if existing:
                    failed += 1
                    if len(errors) < 10: errors.append('Row %d: employee_id %s already exists — skipped' % (rnum, emp_id))
                    continue

                try:
                    conn.execute("""INSERT INTO employees(
                        id,employee_id,staff_number,full_name,division,employment_type,
                        tax_residency,nationality,gra_tin,ssnit_number,
                        tier1_member,tier2_member,tier3_member,provident_fund_member,
                        date_of_birth,date_appointed,contract_end_date,
                        job_title,grade,basic_salary,market_premium,
                        housing_allowance,transport_allowance,utility_allowance,
                        research_allowance,other_allowance,
                        funding_source,project_code,cost_centre,
                        bank_name,bank_branch,account_number,
                        union_deduction,other_deduction,loan_balance,monthly_loan_repayment,
                        tax_relief_marriage,tax_relief_children,
                        status,notes,created_by
                    ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""", (
                        eid, emp_id,
                        _v10_str(row.get('staff_number')),
                        name, div, etype,
                        _v10_str(row.get('tax_residency'), 'Resident'),
                        _v10_str(row.get('nationality'), 'Ghanaian'),
                        _v10_str(row.get('gra_tin')),
                        _v10_str(row.get('ssnit_number')),
                        _v10_int(row.get('tier1_member'), 1),
                        _v10_int(row.get('tier2_member'), 1),
                        _v10_int(row.get('tier3_member'), 0),
                        _v10_int(row.get('provident_fund_member'), 0),
                        _v10_str(row.get('date_of_birth')),
                        _v10_str(row.get('date_appointed')),
                        _v10_str(row.get('contract_end_date')),
                        _v10_str(row.get('job_title')),
                        _v10_str(row.get('grade')),
                        _v10_float(row.get('basic_salary')),
                        _v10_float(row.get('market_premium')),
                        _v10_float(row.get('housing_allowance')),
                        _v10_float(row.get('transport_allowance')),
                        _v10_float(row.get('utility_allowance')),
                        _v10_float(row.get('research_allowance')),
                        _v10_float(row.get('other_allowance')),
                        _v10_str(row.get('funding_source'), 'General'),
                        _v10_str(row.get('project_code')),
                        _v10_str(row.get('cost_centre')),
                        _v10_str(row.get('bank_name')),
                        _v10_str(row.get('bank_branch')),
                        _v10_str(row.get('account_number')),
                        _v10_float(row.get('union_deduction')),
                        _v10_float(row.get('other_deduction') or row.get('other_deductions')),
                        _v10_float(row.get('loan_balance')),
                        _v10_float(row.get('monthly_loan_repayment')),
                        _v10_float(row.get('tax_relief_marriage')),
                        _v10_int(row.get('tax_relief_children')),
                        _v10_str(row.get('status'), 'Active'),
                        _v10_str(row.get('notes')),
                        session.get('username', 'upload'),
                    ))
                    imported += 1
                except Exception as ex:
                    failed += 1
                    if len(errors) < 10:
                        errors.append('Row %d (%s): %s' % (rnum, name, str(ex)[:80]))

            conn.commit()
            try:
                _audit(conn, session, 'BULK_UPLOAD_EMPLOYEES', 'employees', '',
                       'Imported %d employees from %s (%d failed)' % (imported, data.get('filename','upload'), failed))
            except Exception: pass
            return {'ok': True, 'imported': imported, 'failed': failed,
                    'errors': errors, 'total': len(rows)}
        finally:
            conn.close()

    # ── ANNUAL BUDGET BULK UPLOAD ──────────────────────────────────────────────
    def api_upload_annual_budgets(data, session):
        if not session:
            return {'ok': False, 'error': 'Not authenticated'}
        if session.get('role') not in ('Admin', 'Finance Officer'):
            return {'ok': False, 'error': 'Admin or Finance Officer access required'}
        rows = data.get('rows', [])
        if not rows:
            return {'ok': False, 'error': 'No rows provided'}

        conn = get_db()
        imported = 0; failed = 0; errors = []
        try:
            # Cache lookups for speed
            coa_by_code = {}
            for r in conn.execute("SELECT id, code, account_name FROM chart_of_accounts ORDER BY code").fetchall() if True else []:
                coa_by_code[str(r[1]).strip()] = {'id': r[0], 'code': r[1], 'name': r[2]}

            proj_by_code = {}
            try:
                for r in conn.execute("SELECT id, project_code, title FROM projects WHERE (is_deleted=0 OR is_deleted IS NULL)").fetchall():
                    proj_by_code[str(r[1]).strip()] = {'id': r[0], 'code': r[1], 'title': r[2]}
            except Exception: pass

            import uuid as _uuid3
            for i, row in enumerate(rows):
                rnum = i + 2
                acc_code = _v10_str(row.get('account_code') or row.get('coa_code') or row.get('code'))
                proj_code = _v10_str(row.get('project_code') or row.get('project'))
                budget_fcy = _v10_float(row.get('budget_fcy') or row.get('budget_amount') or row.get('amount'))
                currency = _v10_str(row.get('currency'), 'GHS')
                fx_rate  = _v10_float(row.get('fx_rate') or row.get('exchange_rate'), 1.0)
                notes    = _v10_str(row.get('notes'))

                if not acc_code:
                    failed += 1
                    if len(errors) < 10: errors.append('Row %d: account_code is required' % rnum)
                    continue
                if budget_fcy <= 0:
                    failed += 1
                    if len(errors) < 10: errors.append('Row %d: budget amount must be > 0' % rnum)
                    continue

                # Resolve COA
                coa_row = coa_by_code.get(acc_code)
                if not coa_row:
                    # Try partial name match
                    acc_name = _v10_str(row.get('account_name') or row.get('account'))
                    if acc_name:
                        r2 = conn.execute(
                            "SELECT id, code, account_name FROM chart_of_accounts WHERE LOWER(account_name) LIKE ? LIMIT 1",
                            ('%' + acc_name.lower() + '%',)
                        ).fetchone()
                        if r2:
                            coa_row = {'id': r2[0], 'code': r2[1], 'name': r2[2]}
                if not coa_row:
                    failed += 1
                    if len(errors) < 10: errors.append('Row %d: account code "%s" not found in COA' % (rnum, acc_code))
                    continue

                # Resolve Project
                proj_row = proj_by_code.get(proj_code) if proj_code else None
                if not proj_row:
                    # Use first available project or create default
                    if proj_by_code:
                        proj_row = list(proj_by_code.values())[0]
                    else:
                        def_pid = _v10_ensure_default_project(conn)
                        proj_row = {'id': def_pid, 'code': 'INST-GEN', 'title': 'General Institutional Budget'}
                        proj_by_code['INST-GEN'] = proj_row

                budget_ghs = budget_fcy * fx_rate
                bid = str(_uuid3.uuid4())
                budget_code = 'BDG-' + bid[:6].upper()

                # Check for duplicate COA+Project line
                dup = conn.execute(
                    "SELECT id FROM budgets WHERE project_id=? AND coa_id=? AND (is_deleted=0 OR is_deleted IS NULL)",
                    (proj_row['id'], coa_row['id'])
                ).fetchone()
                if dup:
                    # Update existing line
                    conn.execute(
                        "UPDATE budgets SET budget_fcy=budget_fcy+?, budget_ghs=budget_ghs+?, notes=?, fx_rate=? WHERE id=?",
                        (budget_fcy, budget_ghs, notes, fx_rate, dup[0])
                    )
                    imported += 1
                    continue

                try:
                    conn.execute(
                        "INSERT INTO budgets(id,budget_code,project_id,coa_id,budget_fcy,currency,fx_rate,budget_ghs,notes) "
                        "VALUES(?,?,?,?,?,?,?,?,?)",
                        (bid, budget_code, proj_row['id'], coa_row['id'],
                         budget_fcy, currency, fx_rate, budget_ghs, notes)
                    )
                    imported += 1
                except Exception as ex:
                    failed += 1
                    if len(errors) < 10:
                        errors.append('Row %d (acc=%s): %s' % (rnum, acc_code, str(ex)[:80]))

            conn.commit()
            try:
                _audit(conn, session, 'BULK_UPLOAD_BUDGETS', 'budgets', '',
                       'Imported %d budget lines from %s (%d failed)' % (imported, data.get('filename','upload'), failed))
            except Exception: pass
            return {'ok': True, 'imported': imported, 'failed': failed,
                    'errors': errors, 'total': len(rows)}
        finally:
            conn.close()

    print('[v10.0] Bulk upload: Employees + Annual Budgets registered')
except Exception as _v10_err:
    print('[v10.0] Bulk upload setup warning:', _v10_err)


