try:
    # ── 2. File attachment MIME allowlist ────────────────────────────────────────
    _ALLOWED_MIME_TYPES = {
        'image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/svg+xml',
        'application/pdf',
        'text/csv', 'text/plain',
        'application/vnd.ms-excel',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/msword',
        'application/zip',
    }
    _ALLOWED_EXTENSIONS = {
        '.jpg', '.jpeg', '.png', '.gif', '.webp', '.svg',
        '.pdf', '.csv', '.txt', '.xls', '.xlsx', '.doc', '.docx', '.zip',
    }

    _af2_prev_save_attachment = api_save_attachment

    def api_save_attachment(a, b=None):
        import os as _os2, uuid as _u2
        # Normalise (data, session) — this endpoint is invoked with both arg orders.
        def _is_sess(x): return isinstance(x, dict) and any(k in x for k in ('username','role','sid'))
        if _is_sess(a) and not _is_sess(b):
            session, data = a, b
        elif _is_sess(b):
            data, session = a, b
        else:
            data, session = a, b
        if not session:
            return err('Not authenticated')
        data = dict(data or {})
        filename = (data.get('filename') or '').strip()
        mime_type = (data.get('mime_type') or 'application/octet-stream').strip().lower().split(';')[0].strip()
        ext = _os2.path.splitext(filename)[1].lower() if filename else ''
        if ext and ext not in _ALLOWED_EXTENSIONS:
            return {'ok': False, 'error': f'File type "{ext}" is not permitted. Allowed: {", ".join(sorted(_ALLOWED_EXTENSIONS))}'}
        if mime_type and mime_type not in _ALLOWED_MIME_TYPES:
            return {'ok': False, 'error': f'MIME type "{mime_type}" is not permitted.'}
        safe_name = _os2.path.basename(filename.replace('..', '').replace('/', '').replace('\\', ''))
        data['filename'] = safe_name
        # File attachment against a record (module + record_id) — the model the GET
        # endpoint and the document-required posting gate use. Save directly to
        # document_attachments so UI uploads work (a later doc-vault function had
        # shadowed the real file saver and broke posting that requires evidence).
        module = (data.get('module') or '').strip()
        record_id = (data.get('record_id') or '').strip()
        if module and record_id and safe_name:
            conn = get_db()
            try:
                aid = data.get('id') or str(_u2.uuid4())
                conn.execute("""INSERT INTO document_attachments(id,module,record_id,filename,mime_type,file_size,file_data,notes,uploaded_by)
                               VALUES(?,?,?,?,?,?,?,?,?)""",
                    (aid, module, record_id, safe_name, mime_type or 'application/octet-stream',
                     int(data.get('file_size') or 0), data.get('file_data') or '', data.get('notes',''),
                     session.get('username','system')))
                conn.commit()
                return ok({'id': aid, 'filename': safe_name, 'module': module, 'record_id': record_id})
            except Exception as _ae:
                try: conn.rollback()
                except Exception: pass
                return err(str(_ae))
            finally:
                conn.close()
        # Otherwise fall back to the document-vault model (document_type/document_id).
        return _af2_prev_save_attachment(session, data)

    print('[v11.0] Attachments: MIME type allowlist enforced')
except Exception as _af2_err:
    print('[v11.0] Attachment MIME allowlist warning:', _af2_err)

try:
    # ── 3. Backport missing POST routes to Handler.do_POST ──────────────────────
    _af3_prev_do_POST = Handler.do_POST

    def _af3_do_POST(self):
        from urllib.parse import urlparse as _up3
        _path3 = _up3(self.path).path

        _MISSING_POST_ROUTES = {
            '/api/approvals/submit':             lambda s, d: api_submit_approval(d, s),
            '/api/approvals/action':             lambda s, d: api_approval_action(d, s),
            '/api/auto-coa':                     lambda s, d: api_auto_assign_coa(d, s),
            '/api/budget-upload':                lambda s, d: api_upload_budget(d, s),
            '/api/bulk-auto-coa':                lambda s, d: api_bulk_auto_coa(d, s),
            '/api/deleted-items/restore':        lambda s, d: api_restore_deleted_item(d, s),
            '/api/demo-data/load':               lambda s, d: api_load_sample_data(s),
            '/api/demo-data/reset':              lambda s, d: api_reset_demo_data(s),
            '/api/withholding-payables/settle':  lambda s, d: api_settle_withholding_payable(d, s),
            '/api/acceptance-testing/run':       lambda s, d: api_run_acceptance_test(d, s),
            '/api/departments':                  lambda s, d: api_save_department(d, s),
            '/api/units':                        lambda s, d: api_save_department(d, s),
            '/api/org-units':                    lambda s, d: api_save_org_unit(d, s),
            '/api/dept-allocations':             lambda s, d: api_save_dept_allocation(d, s),
            '/api/unit-allocations':             lambda s, d: api_save_dept_allocation(d, s),
            '/api/vendors':                      lambda s, d: api_save_vendor(d, s),
            '/api/attachments':                  lambda s, d: api_save_attachment(d, s),
            '/api/approval-rules':               lambda s, d: api_save_approval_rule(d, s),
        }

        if _path3 in _MISSING_POST_ROUTES:
            _sess3 = self.get_session()
            if not _sess3:
                return self.send_json({'error': 'Not authenticated'}, 401)
            try:
                _data3 = self.read_body()
                _result3 = _MISSING_POST_ROUTES[_path3](_sess3, _data3)
                return self.send_json(_result3)
            except Exception as _pe3:
                return self.send_json({'ok': False, 'error': str(_pe3)}, 500)
        return _af3_prev_do_POST(self)

    Handler.do_POST = _af3_do_POST
    print('[v11.0] Missing POST routes backported: approvals/submit, approvals/action, auto-coa, '
          'budget-upload, bulk-auto-coa, deleted-items/restore, demo-data/*, '
          'withholding-payables/settle, acceptance-testing/run, departments, dept-allocations')
except Exception as _af3_err:
    print('[v11.0] Missing POST routes warning:', _af3_err)

