try:
    # ── 8. Password hashing: migrate api_change_password to PBKDF2 ─────────────
    import hashlib as _af8_hl, os as _af8_os

    def _pbkdf2_hash(password, salt=None):
        """Return 'pbkdf2$<salt_hex>$<hash_hex>' using PBKDF2-HMAC-SHA256."""
        if salt is None:
            salt = _af8_os.urandom(32)
        elif isinstance(salt, str):
            salt = bytes.fromhex(salt)
        dk = _af8_hl.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 260000)
        return f'pbkdf2${salt.hex()}${dk.hex()}'

    def _pbkdf2_verify(password, stored_hash):
        """Verify password against stored_hash (pbkdf2$salt$hash or legacy sha256 hex)."""
        if stored_hash.startswith('pbkdf2$'):
            parts = stored_hash.split('$')
            if len(parts) != 3:
                return False
            _, salt_hex, _ = parts
            return _pbkdf2_hash(password, salt_hex) == stored_hash
        # Legacy SHA-256 (no salt) — still accept for login until password is changed
        return _af8_hl.sha256(password.encode()).hexdigest() == stored_hash

    _af8_prev_change_password = api_change_password

    def api_change_password(data, session):
        conn = get_db()
        # Verify old password — support both legacy SHA-256 and new PBKDF2
        user = conn.execute("SELECT * FROM users WHERE id=?", (session['id'],)).fetchone()
        conn.close()
        if not user:
            return {'ok': False, 'error': 'User not found'}
        if not _pbkdf2_verify(data.get('old_password', ''), user['password_hash']):
            return {'ok': False, 'error': 'Current password incorrect'}
        if len(data.get('new_password', '')) < 6:
            return {'ok': False, 'error': 'Password must be at least 6 characters'}
        new_hash = _pbkdf2_hash(data['new_password'])
        conn = get_db()
        conn.execute("UPDATE users SET password_hash=? WHERE id=?", (new_hash, session['id']))
        _audit(conn, session, 'PASSWORD_CHANGE', 'users', session['id'], '')
        conn.commit(); conn.close()
        return {'ok': True}

    # Patch api_login to support PBKDF2 as well as legacy SHA-256
    _af8_prev_api_login = api_login

    def api_login(data):
        username = (data.get('username') or '').strip()
        password = (data.get('password') or '').strip()
        conn = get_db()
        user = conn.execute(
            "SELECT * FROM users WHERE username=? AND active=1", (username,)
        ).fetchone()
        conn.close()
        if not user:
            return {'ok': False, 'error': 'Invalid credentials'}
        if not _pbkdf2_verify(password, user['password_hash']):
            return {'ok': False, 'error': 'Invalid credentials'}
        sid = create_session({
            'id': user['id'], 'username': user['username'],
            'full_name': user['full_name'], 'role': user['role']
        })
        _hu = None; _scp = None
        try:
            _ks = user.keys()
            _hu = user['home_unit_id'] if 'home_unit_id' in _ks else None
            _scp = user['scope'] if 'scope' in _ks else None
        except Exception:
            pass
        return {'ok': True, 'sid': sid, 'user': {
            'username': user['username'],
            'full_name': user['full_name'],
            'role': user['role'],
            'home_unit_id': _hu,
            'scope': _scp
        }}

    # Also wrap api_save_user to upgrade newly-set passwords to PBKDF2 after the original stores SHA-256
    _af8_prev_save_user = api_save_user

    def api_save_user(data, session):
        plain_pw = data.get('password') or ''
        plain_npw = data.get('new_password') or ''
        uid_hint = data.get('id') or data.get('username') or ''
        result = _af8_prev_save_user(data, session)
        # If a password was supplied and the save succeeded, upgrade hash to PBKDF2
        if result and result.get('ok'):
            try:
                conn = get_db()
                if plain_pw and not data.get('id'):
                    # New user: find by username and upgrade hash
                    uname = (data.get('username') or '').strip()
                    if uname:
                        new_h = _pbkdf2_hash(plain_pw)
                        conn.execute("UPDATE users SET password_hash=? WHERE username=?", (new_h, uname))
                elif plain_npw and data.get('id'):
                    # Password update for existing user
                    new_h = _pbkdf2_hash(plain_npw)
                    conn.execute("UPDATE users SET password_hash=? WHERE id=?", (new_h, data['id']))
                conn.commit()
                conn.close()
            except Exception as _af8u_e:
                print('[v11.0] PBKDF2 upgrade for save_user warning:', _af8u_e)
        return result

    print('[v11.0] Passwords: api_login + api_change_password + api_save_user now use PBKDF2-HMAC-SHA256')
except Exception as _af8_err:
    print('[v11.0] PBKDF2 password patch warning:', _af8_err)

