def api_ar_post_invoice(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn)
        iid = data.get('id') or data.get('invoice_id')
        inv = conn.execute("SELECT * FROM ar_invoices WHERE id=?", (iid,)).fetchone()
        if not inv: return err('Invoice not found')
        inv = dict(inv)
        if inv['status'] != 'Draft': return err('Invoice is already posted')
        ar_coa = _ar_control_coa(conn)
        if not ar_coa: return err('No receivables control account (code 123xxxxx) found in the chart of accounts')
        amount = round(float(inv['amount_ghs'] or 0), 2); tax = round(float(inv['tax_ghs'] or 0), 2); total = round(amount + tax, 2)
        cust = conn.execute("SELECT customer_name FROM ar_customers WHERE id=?", (inv['customer_id'],)).fetchone()
        desc = 'Invoice %s - %s' % (inv['invoice_number'], (cust['customer_name'] if cust else ''))
        _i_unit = inv.get('unit_id') if hasattr(inv, 'get') else None
        lines = [{'coa_id': ar_coa, 'debit_amount': total, 'credit_amount': 0, 'description': desc, 'project_id': inv['project_id'], 'unit_id': _i_unit}]
        ilines = [dict(r) for r in conn.execute("SELECT description,income_coa_id,amount_ghs FROM ar_invoice_lines WHERE invoice_id=? ORDER BY line_number", (iid,)).fetchall()]
        if ilines:
            for il in ilines:
                lines.append({'coa_id': il['income_coa_id'], 'debit_amount': 0, 'credit_amount': round(float(il['amount_ghs'] or 0), 2), 'description': (il['description'] or desc), 'project_id': inv['project_id'], 'unit_id': _i_unit})
        else:
            lines.append({'coa_id': inv['income_coa_id'], 'debit_amount': 0, 'credit_amount': amount, 'description': desc, 'project_id': inv['project_id'], 'unit_id': _i_unit})
        if tax > 0:
            vat = conn.execute("SELECT id FROM chart_of_accounts WHERE code='21100024' OR (LOWER(account_name) LIKE '%vat%' AND code LIKE '21%') ORDER BY code LIMIT 1").fetchone()
            if not vat: return err('Invoice has tax but no VAT output liability account (21xxxxxx) was found')
            lines.append({'coa_id': vat['id'], 'debit_amount': 0, 'credit_amount': tax, 'description': 'Output VAT on ' + inv['invoice_number'], 'project_id': inv['project_id'], 'unit_id': _i_unit})
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', inv.get('invoice_date') or date.today().isoformat(), desc, inv['invoice_number'], inv['project_id'], None, 'ar_invoices', iid, lines)
        except Exception as e:
            return err('Could not post invoice: %s' % e)
        conn.execute("UPDATE ar_invoices SET status='Posted', jv_id=?, jv_number=?, posted_at=datetime('now') WHERE id=?", (jv_id, jv_num, iid))
        _audit(conn, session, 'POST_AR_INVOICE', 'ar_invoices', iid, '%s posted as %s GHS %.2f' % (inv['invoice_number'], jv_num, total))
        conn.commit()
        return ok({'id': iid, 'jv_number': jv_num, 'message': '%s posted as %s' % (inv['invoice_number'], jv_num)})
    finally:
        conn.close()

def api_ar_receipt(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn)
        iid = data.get('invoice_id') or data.get('id')
        inv = conn.execute("SELECT * FROM ar_invoices WHERE id=?", (iid,)).fetchone()
        if not inv: return err('Invoice not found')
        inv = dict(inv)
        if inv['status'] not in ('Posted', 'Part-Paid'): return err('Only a posted invoice can receive a payment')
        amount = round(float(data.get('amount_ghs') or 0), 2)
        if amount <= 0: return err('Receipt amount must be greater than zero')
        balance = round(float(inv['total_ghs'] or 0) - float(inv['amount_received'] or 0) - float(inv.get('credited_ghs') or 0), 2)
        if amount > balance + 0.01: return err('Receipt GHS %.2f exceeds the outstanding balance GHS %.2f' % (amount, balance))
        bank_id = data.get('bank_account_id')
        if not bank_id: return err('Select the bank account receiving the payment')
        bank_coa = _ar_bank_coa(conn, bank_id)
        ar_coa = _ar_control_coa(conn)
        if not bank_coa or not ar_coa: return err('Bank or receivables control account could not be resolved')
        ref = (data.get('reference') or '').strip()
        rdate = data.get('receipt_date') or date.today().isoformat()
        cust = conn.execute("SELECT customer_name FROM ar_customers WHERE id=?", (inv['customer_id'],)).fetchone()
        desc = 'Receipt for %s — %s' % (inv['invoice_number'], (cust['customer_name'] if cust else ''))
        lines = [{'coa_id': bank_coa, 'debit_amount': amount, 'credit_amount': 0, 'description': desc, 'project_id': inv['project_id'], 'bank_account_id': bank_id},
                 {'coa_id': ar_coa, 'debit_amount': 0, 'credit_amount': amount, 'description': desc, 'project_id': inv['project_id']}]
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'RV', rdate, desc, ref, inv['project_id'], bank_id, 'ar_receipts', iid, lines)
        except Exception as e:
            return err('Could not post receipt: %s' % e)
        rid = str(uuid.uuid4()); rnum = _ar_next(conn, 'ar_receipts', 'ARR')
        conn.execute("INSERT INTO ar_receipts(id,receipt_number,invoice_id,customer_id,receipt_date,amount_ghs,bank_account_id,payment_method,reference,jv_id,jv_number,notes,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
            (rid, rnum, iid, inv['customer_id'], rdate, amount, bank_id, data.get('payment_method', 'Bank Transfer'), ref, jv_id, jv_num, data.get('notes', ''), session.get('username', 'system')))
        new_recv = round(float(inv['amount_received'] or 0) + amount, 2)
        new_status = 'Paid' if new_recv >= float(inv['total_ghs'] or 0) - 0.01 else 'Part-Paid'
        conn.execute("UPDATE ar_invoices SET amount_received=?, status=? WHERE id=?", (new_recv, new_status, iid))
        _audit(conn, session, 'AR_RECEIPT', 'ar_invoices', iid, '%s received GHS %.2f (%s) -> %s' % (inv['invoice_number'], amount, jv_num, new_status))
        conn.commit()
        return ok({'id': rid, 'jv_number': jv_num, 'status': new_status, 'message': 'Receipt posted as %s' % jv_num})
    finally:
        conn.close()

def api_ar_aging(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn)
        rows = [dict(r) for r in conn.execute("""
            SELECT i.id, i.invoice_number, i.invoice_date, i.due_date, i.total_ghs, i.amount_received,
                   (i.total_ghs - i.amount_received - COALESCE(i.credited_ghs,0)) AS balance, c.customer_name, c.customer_code
            FROM ar_invoices i LEFT JOIN ar_customers c ON c.id=i.customer_id
            WHERE i.status IN ('Posted','Part-Paid') AND (i.total_ghs - i.amount_received - COALESCE(i.credited_ghs,0)) > 0.01
            ORDER BY c.customer_name, i.due_date""").fetchall()]
        import datetime as _d
        today = _d.date.today()
        buckets = {'current': 0.0, 'b1_30': 0.0, 'b31_60': 0.0, 'b61_90': 0.0, 'b90_plus': 0.0}
        per_cust = {}
        for r in rows:
            bal = round(float(r['balance'] or 0), 2)
            days = 0
            try:
                if r.get('due_date'): days = (today - _d.date.fromisoformat(str(r['due_date'])[:10])).days
            except Exception:
                days = 0
            key = 'current' if days <= 0 else ('b1_30' if days <= 30 else ('b31_60' if days <= 60 else ('b61_90' if days <= 90 else 'b90_plus')))
            buckets[key] += bal
            cust = r.get('customer_name') or '—'
            pc = per_cust.setdefault(cust, {'customer': cust, 'current': 0, 'b1_30': 0, 'b31_60': 0, 'b61_90': 0, 'b90_plus': 0, 'total': 0})
            pc[key] += bal; pc['total'] += bal
            r['days_overdue'] = max(0, days); r['bucket'] = key
        for k in buckets: buckets[k] = round(buckets[k], 2)
        for pc in per_cust.values():
            for k in pc:
                if k != 'customer': pc[k] = round(pc[k], 2)
        return ok({'buckets': buckets, 'by_customer': list(per_cust.values()), 'invoices': rows, 'total_outstanding': round(sum(buckets.values()), 2)})
    finally:
        conn.close()

def api_ar_credit_note(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn)
        iid = data.get('invoice_id') or data.get('id')
        inv = conn.execute("SELECT * FROM ar_invoices WHERE id=?", (iid,)).fetchone()
        if not inv: return err('Invoice not found')
        inv = dict(inv)
        if inv['status'] not in ('Posted', 'Part-Paid'): return err('Only a posted (unpaid/part-paid) invoice can be credited')
        amount = round(float(data.get('amount_ghs') or 0), 2)
        if amount <= 0: return err('Credit amount must be greater than zero')
        credited = round(float(inv.get('credited_ghs') or 0), 2)
        outstanding = round(float(inv['total_ghs'] or 0) - float(inv['amount_received'] or 0) - credited, 2)
        if amount > outstanding + 0.01: return err('Credit GHS %.2f exceeds the outstanding balance GHS %.2f' % (amount, outstanding))
        ar_coa = _ar_control_coa(conn)
        if not ar_coa: return err('Receivables control account not found')
        reason = (data.get('reason') or '').strip() or 'Credit note'
        cdate = data.get('credit_date') or date.today().isoformat()
        desc = 'Credit note for %s - %s' % (inv['invoice_number'], reason)
        lines = [{'coa_id': inv['income_coa_id'], 'debit_amount': amount, 'credit_amount': 0, 'description': desc, 'project_id': inv['project_id']},
                 {'coa_id': ar_coa, 'debit_amount': 0, 'credit_amount': amount, 'description': desc, 'project_id': inv['project_id']}]
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', cdate, desc, inv['invoice_number'], inv['project_id'], None, 'ar_credit_notes', iid, lines)
        except Exception as e:
            return err('Could not post credit note: %s' % e)
        cnid = str(uuid.uuid4()); cnnum = _ar_next(conn, 'ar_credit_notes', 'CN')
        conn.execute("INSERT INTO ar_credit_notes(id,credit_number,invoice_id,customer_id,credit_date,amount_ghs,reason,jv_id,jv_number,created_by) VALUES(?,?,?,?,?,?,?,?,?,?)",
            (cnid, cnnum, iid, inv['customer_id'], cdate, amount, reason, jv_id, jv_num, session.get('username', 'system')))
        new_credited = round(credited + amount, 2)
        settled = round(float(inv['amount_received'] or 0) + new_credited, 2)
        new_status = 'Paid' if settled >= float(inv['total_ghs'] or 0) - 0.01 else 'Part-Paid'
        conn.execute("UPDATE ar_invoices SET credited_ghs=?, status=? WHERE id=?", (new_credited, new_status, iid))
        _audit(conn, session, 'AR_CREDIT_NOTE', 'ar_invoices', iid, '%s credited GHS %.2f (%s)' % (inv['invoice_number'], amount, jv_num))
        conn.commit()
        return ok({'id': cnid, 'credit_number': cnnum, 'jv_number': jv_num, 'status': new_status, 'message': 'Credit note posted as %s' % jv_num})
    finally:
        conn.close()


def api_ar_statement(session, customer_id=None):
    if not session: return err('Not authenticated')
    if not customer_id: return err('customer_id is required')
    conn = get_db()
    try:
        _ar_migration(conn)
        cust = conn.execute("SELECT * FROM ar_customers WHERE id=?", (customer_id,)).fetchone()
        if not cust: return err('Customer not found')
        # [C4] Enforce the viewer's org-unit read scope: a scoped (non-Admin) user
        # may only pull a statement for a customer they have transacted with in
        # their own unit(s). Deny when the customer has no invoices in scope.
        if '_ucc_resolve_read_scope' in globals():
            try:
                enforced = _ucc_resolve_read_scope(conn, session)
                if enforced is not None:
                    if enforced:
                        ph = ','.join('?' * len(enforced))
                        seen = conn.execute(
                            "SELECT 1 FROM ar_invoices WHERE customer_id=? AND unit_id IN (%s) LIMIT 1" % ph,
                            [customer_id] + list(enforced)).fetchone()
                    else:
                        seen = None
                    if not seen:
                        return err('Customer not found')
            except Exception:
                return err('Customer not found')  # fail closed
        invs = [dict(r) for r in conn.execute("SELECT invoice_number,invoice_date,due_date,total_ghs,description,status FROM ar_invoices WHERE customer_id=? AND status!='Draft'", (customer_id,)).fetchall()]
        rcts = [dict(r) for r in conn.execute("SELECT receipt_number,receipt_date,amount_ghs,reference FROM ar_receipts WHERE customer_id=?", (customer_id,)).fetchall()]
        events = []
        for i in invs: events.append({'date': i['invoice_date'], 'ref': i['invoice_number'], 'type': 'Invoice', 'debit': round(float(i['total_ghs'] or 0), 2), 'credit': 0, 'desc': i.get('description', '')})
        for r in rcts: events.append({'date': r['receipt_date'], 'ref': r['receipt_number'], 'type': 'Receipt', 'debit': 0, 'credit': round(float(r['amount_ghs'] or 0), 2), 'desc': r.get('reference', '')})
        events.sort(key=lambda e: (str(e['date'] or ''), e['type'] != 'Invoice'))
        bal = 0.0
        for e in events:
            bal = round(bal + e['debit'] - e['credit'], 2); e['balance'] = bal
        return ok({'customer': dict(cust), 'events': events, 'balance': bal})
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# STORES / INVENTORY — items, stock receipts (goods in), issues (consumption),
# valuation and low-stock alerts. Weighted-average costing. Receipts post
# Dr Inventory (stock asset) / Cr Bank; issues post Dr Expense / Cr Inventory at
# the running average cost — through _create_posted_journal, so stock value flows
# into the SFP (inventory asset) and consumption into the I&E (expense).
# ═══════════════════════════════════════════════════════════════════════════
def _inv_migration(conn):
    conn.execute("""CREATE TABLE IF NOT EXISTS inv_items(
        id TEXT PRIMARY KEY, item_code TEXT, item_name TEXT NOT NULL, category TEXT,
        unit TEXT DEFAULT 'each', reorder_level REAL DEFAULT 0,
        inventory_coa_id TEXT, expense_coa_id TEXT,
        qty_on_hand REAL DEFAULT 0, avg_cost REAL DEFAULT 0,
        notes TEXT, created_by TEXT, created_at TEXT DEFAULT(datetime('now')))""")
    conn.execute("""CREATE TABLE IF NOT EXISTS inv_movements(
        id TEXT PRIMARY KEY, movement_number TEXT, item_id TEXT, movement_type TEXT,
        movement_date TEXT, qty REAL DEFAULT 0, unit_cost REAL DEFAULT 0, total_cost REAL DEFAULT 0,
        party TEXT, bank_account_id TEXT, project_id TEXT, reference TEXT,
        jv_id TEXT, jv_number TEXT, notes TEXT, created_by TEXT, created_at TEXT DEFAULT(datetime('now')))""")
    conn.commit()

def _inv_asset_coa(conn):
    for q in ("SELECT id FROM chart_of_accounts WHERE code='12107006'",
              "SELECT id FROM chart_of_accounts WHERE code LIKE '121%' AND LOWER(account_name) LIKE '%stock%' ORDER BY code LIMIT 1",
              "SELECT id FROM chart_of_accounts WHERE LOWER(account_name) LIKE '%stock%' OR LOWER(account_name) LIKE '%inventor%' ORDER BY code LIMIT 1"):
        try:
            r = conn.execute(q).fetchone()
            if r: return r['id']
        except Exception:
            pass
    return None

def _inv_bank_coa(conn, bank_account_id):
    if not bank_account_id:
        return None
    try:
        if '_wh_bank_coa_id' in globals():
            cid = _wh_bank_coa_id(conn, bank_account_id, 'GHS')
            if cid: return cid
    except Exception:
        pass
    try:
        r = conn.execute("SELECT coa_id FROM bank_accounts WHERE id=?", (bank_account_id,)).fetchone()
        if r and r['coa_id']: return r['coa_id']
    except Exception:
        pass
    return None

def _inv_next(conn, table, prefix):
    col = {'inv_items': 'item_code', 'inv_movements': 'movement_number'}.get(table)
    import datetime as _d
    full = '%s-%s-' % (prefix, _d.datetime.now().year)
    if col:
        return _seq_code(conn, table, col, full, 4)
    try:
        n = conn.execute("SELECT COUNT(*) FROM %s" % table).fetchone()[0] or 0
    except Exception:
        n = 0
    return full + '%04d' % (n + 1)

def api_inv_items(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _inv_migration(conn)
        rows = [dict(r) for r in conn.execute("""
            SELECT i.*, (i.qty_on_hand * i.avg_cost) AS value_ghs,
                   ec.account_name AS expense_account, ac.account_name AS inventory_account
            FROM inv_items i
            LEFT JOIN chart_of_accounts ec ON ec.id=i.expense_coa_id
            LEFT JOIN chart_of_accounts ac ON ac.id=i.inventory_coa_id
            ORDER BY i.item_name""").fetchall()]
        for r in rows:
            r['low_stock'] = bool(float(r.get('reorder_level') or 0) > 0 and float(r.get('qty_on_hand') or 0) <= float(r.get('reorder_level') or 0))
        return ok({'items': rows})
    finally:
        conn.close()

def api_inv_save_item(data, session):
    if not session: return err('Not authenticated')
    name = (data.get('item_name') or '').strip()
    if not name: return err('Item name is required')
    if not data.get('expense_coa_id'): return err('Select the expense account to charge on issue')
    conn = get_db()
    try:
        _inv_migration(conn)
        iid = data.get('id') or str(uuid.uuid4())
        code = (data.get('item_code') or '').strip() or _inv_next(conn, 'inv_items', 'ITEM')
        inv_coa = data.get('inventory_coa_id') or _inv_asset_coa(conn)
        if conn.execute("SELECT id FROM inv_items WHERE id=?", (iid,)).fetchone():
            conn.execute("UPDATE inv_items SET item_name=?,category=?,unit=?,reorder_level=?,inventory_coa_id=?,expense_coa_id=?,notes=? WHERE id=?",
                (name, data.get('category', ''), data.get('unit', 'each'), float(data.get('reorder_level') or 0), inv_coa, data['expense_coa_id'], data.get('notes', ''), iid))
        else:
            conn.execute("INSERT INTO inv_items(id,item_code,item_name,category,unit,reorder_level,inventory_coa_id,expense_coa_id,qty_on_hand,avg_cost,notes,created_by) VALUES(?,?,?,?,?,?,?,?,0,0,?,?)",
                (iid, code, name, data.get('category', ''), data.get('unit', 'each'), float(data.get('reorder_level') or 0), inv_coa, data['expense_coa_id'], data.get('notes', ''), session.get('username', 'system')))
        _audit(conn, session, 'SAVE_INV_ITEM', 'inv_items', iid, name)
        conn.commit()
        return ok({'id': iid, 'item_code': code})
    finally:
        conn.close()

def api_inv_receipt(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _inv_migration(conn)
        it = conn.execute("SELECT * FROM inv_items WHERE id=?", (data.get('item_id'),)).fetchone()
        if not it: return err('Item not found')
        it = dict(it)
        qty = round(float(data.get('qty') or 0), 3)
        unit_cost = round(float(data.get('unit_cost') or 0), 4)
        if qty <= 0: return err('Receipt quantity must be greater than zero')
        if unit_cost < 0: return err('Unit cost cannot be negative')
        total = round(qty * unit_cost, 2)
        jv_id = jv_num = None
        if total > 0:
            bank_id = data.get('bank_account_id')
            if not bank_id: return err('Select the bank account paying for the stock')
            bank_coa = _inv_bank_coa(conn, bank_id)
            inv_coa = it.get('inventory_coa_id') or _inv_asset_coa(conn)
            if not bank_coa or not inv_coa: return err('Bank or inventory control account could not be resolved')
            rdate = data.get('movement_date') or date.today().isoformat()
            desc = 'Stock receipt: %s x%s %s' % (it['item_name'], qty, it.get('unit', ''))
            lines = [{'coa_id': inv_coa, 'debit_amount': total, 'credit_amount': 0, 'description': desc, 'project_id': data.get('project_id')},
                     {'coa_id': bank_coa, 'debit_amount': 0, 'credit_amount': total, 'description': desc, 'project_id': data.get('project_id'), 'bank_account_id': bank_id}]
            try:
                jv_id, jv_num = _create_posted_journal(conn, session, 'JV', rdate, desc, data.get('reference', ''), data.get('project_id'), bank_id, 'inv_movements', data.get('item_id'), lines)
            except Exception as e:
                return err('Could not post stock receipt: %s' % e)
        old_qty = round(float(it['qty_on_hand'] or 0), 3)
        new_qty = round(old_qty + qty, 3)
        new_avg = round((old_qty * float(it['avg_cost'] or 0) + qty * unit_cost) / new_qty, 4) if new_qty > 0 else 0
        conn.execute("UPDATE inv_items SET qty_on_hand=?, avg_cost=? WHERE id=?", (new_qty, new_avg, it['id']))
        mid = str(uuid.uuid4()); mnum = _inv_next(conn, 'inv_movements', 'GRN')
        conn.execute("INSERT INTO inv_movements(id,movement_number,item_id,movement_type,movement_date,qty,unit_cost,total_cost,party,bank_account_id,project_id,reference,jv_id,jv_number,notes,created_by) VALUES(?,?,?,'Receipt',?,?,?,?,?,?,?,?,?,?,?,?)",
            (mid, mnum, it['id'], data.get('movement_date') or date.today().isoformat(), qty, unit_cost, total, data.get('party', ''), data.get('bank_account_id'), data.get('project_id'), data.get('reference', ''), jv_id, jv_num, data.get('notes', ''), session.get('username', 'system')))
        _audit(conn, session, 'INV_RECEIPT', 'inv_items', it['id'], '%s +%s @ %.4f = %.2f (%s)' % (it['item_name'], qty, unit_cost, total, jv_num or 'no GL'))
        conn.commit()
        return ok({'id': mid, 'movement_number': mnum, 'jv_number': jv_num, 'qty_on_hand': new_qty, 'avg_cost': new_avg, 'message': 'Stock received' + ((' (' + jv_num + ')') if jv_num else '')})
    finally:
        conn.close()

def api_inv_issue(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _inv_migration(conn)
        it = conn.execute("SELECT * FROM inv_items WHERE id=?", (data.get('item_id'),)).fetchone()
        if not it: return err('Item not found')
        it = dict(it)
        qty = round(float(data.get('qty') or 0), 3)
        if qty <= 0: return err('Issue quantity must be greater than zero')
        on_hand = round(float(it['qty_on_hand'] or 0), 3)
        if qty > on_hand + 0.0001: return err('Cannot issue %s — only %s %s in stock' % (qty, on_hand, it.get('unit', '')))
        avg = round(float(it['avg_cost'] or 0), 4)
        cost = round(qty * avg, 2)
        jv_id = jv_num = None
        if cost > 0:
            inv_coa = it.get('inventory_coa_id') or _inv_asset_coa(conn)
            exp_coa = it.get('expense_coa_id')
            if not inv_coa or not exp_coa: return err('Inventory or expense account could not be resolved')
            idate = data.get('movement_date') or date.today().isoformat()
            to = (data.get('party') or '').strip()
            desc = 'Stock issue: %s x%s %s%s' % (it['item_name'], qty, it.get('unit', ''), (' to ' + to) if to else '')
            _iss_unit = (_ucc_resolve_write_unit(conn, data, session) if '_ucc_resolve_write_unit' in globals() else data.get('unit_id'))
            lines = [{'coa_id': exp_coa, 'debit_amount': cost, 'credit_amount': 0, 'description': desc, 'project_id': data.get('project_id'), 'unit_id': _iss_unit},
                     {'coa_id': inv_coa, 'debit_amount': 0, 'credit_amount': cost, 'description': desc, 'project_id': data.get('project_id'), 'unit_id': _iss_unit}]
            try:
                jv_id, jv_num = _create_posted_journal(conn, session, 'JV', idate, desc, data.get('reference', ''), data.get('project_id'), None, 'inv_movements', it['id'], lines)
            except Exception as e:
                return err('Could not post stock issue: %s' % e)
        new_qty = round(on_hand - qty, 3)
        conn.execute("UPDATE inv_items SET qty_on_hand=? WHERE id=?", (new_qty, it['id']))
        mid = str(uuid.uuid4()); mnum = _inv_next(conn, 'inv_movements', 'ISS')
        conn.execute("INSERT INTO inv_movements(id,movement_number,item_id,movement_type,movement_date,qty,unit_cost,total_cost,party,bank_account_id,project_id,reference,jv_id,jv_number,notes,created_by) VALUES(?,?,?,'Issue',?,?,?,?,?,?,?,?,?,?,?,?)",
            (mid, mnum, it['id'], data.get('movement_date') or date.today().isoformat(), qty, avg, cost, data.get('party', ''), None, data.get('project_id'), data.get('reference', ''), jv_id, jv_num, data.get('notes', ''), session.get('username', 'system')))
        # UCC unit attribution: stamp the movement row's unit_id (best-effort).
        try:
            _mu = (_ucc_resolve_write_unit(conn, data, session) if '_ucc_resolve_write_unit' in globals() else data.get('unit_id'))
            if _mu and 'unit_id' in [r[1] for r in conn.execute("PRAGMA table_info(inv_movements)").fetchall()]:
                conn.execute("UPDATE inv_movements SET unit_id=? WHERE id=?", (_mu, mid))
        except Exception:
            pass
        _audit(conn, session, 'INV_ISSUE', 'inv_items', it['id'], '%s -%s @ %.4f = %.2f (%s)' % (it['item_name'], qty, avg, cost, jv_num or 'no GL'))
        conn.commit()
        return ok({'id': mid, 'movement_number': mnum, 'jv_number': jv_num, 'qty_on_hand': new_qty, 'message': 'Stock issued' + ((' (' + jv_num + ')') if jv_num else '')})
    finally:
        conn.close()

def api_inv_adjust(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _inv_migration(conn)
        it = conn.execute("SELECT * FROM inv_items WHERE id=?", (data.get('item_id'),)).fetchone()
        if not it: return err('Item not found')
        it = dict(it)
        direction = (data.get('direction') or '').lower()
        qty = round(float(data.get('qty') or 0), 3)
        if qty <= 0: return err('Adjustment quantity must be greater than zero')
        reason = (data.get('reason') or '').strip()
        if not reason: return err('A reason is required for a stock adjustment')
        adate = data.get('movement_date') or date.today().isoformat()
        on_hand = round(float(it['qty_on_hand'] or 0), 3)
        avg = round(float(it['avg_cost'] or 0), 4)
        inv_coa = it.get('inventory_coa_id') or _inv_asset_coa(conn)
        exp_coa = it.get('expense_coa_id')
        jv_id = jv_num = None; cost = 0.0
        if direction == 'decrease':
            if qty > on_hand + 0.0001: return err('Cannot write off %s - only %s %s in stock' % (qty, on_hand, it.get('unit', '')))
            cost = round(qty * avg, 2); new_qty = round(on_hand - qty, 3); new_avg = avg; ucost = avg; mtype = 'Adjustment-'
            if cost > 0:
                if not inv_coa or not exp_coa: return err('Inventory or expense account could not be resolved')
                desc = 'Stock write-off: %s x%s - %s' % (it['item_name'], qty, reason)
                lines = [{'coa_id': exp_coa, 'debit_amount': cost, 'credit_amount': 0, 'description': desc},
                         {'coa_id': inv_coa, 'debit_amount': 0, 'credit_amount': cost, 'description': desc}]
                try: jv_id, jv_num = _create_posted_journal(conn, session, 'JV', adate, desc, reason, None, None, 'inv_movements', it['id'], lines)
                except Exception as e: return err('Could not post adjustment: %s' % e)
        elif direction == 'increase':
            ucost = round(float(data.get('unit_cost') or avg or 0), 4)
            cost = round(qty * ucost, 2); new_qty = round(on_hand + qty, 3)
            new_avg = round((on_hand * avg + qty * ucost) / new_qty, 4) if new_qty > 0 else 0; mtype = 'Adjustment+'
            if cost > 0:
                if not inv_coa or not exp_coa: return err('Inventory or expense account could not be resolved')
                desc = 'Stock increase: %s x%s - %s' % (it['item_name'], qty, reason)
                lines = [{'coa_id': inv_coa, 'debit_amount': cost, 'credit_amount': 0, 'description': desc},
                         {'coa_id': exp_coa, 'debit_amount': 0, 'credit_amount': cost, 'description': desc}]
                try: jv_id, jv_num = _create_posted_journal(conn, session, 'JV', adate, desc, reason, None, None, 'inv_movements', it['id'], lines)
                except Exception as e: return err('Could not post adjustment: %s' % e)
        else:
            return err("direction must be 'increase' or 'decrease'")
        conn.execute("UPDATE inv_items SET qty_on_hand=?, avg_cost=? WHERE id=?", (new_qty, new_avg, it['id']))
        mid = str(uuid.uuid4()); mnum = _inv_next(conn, 'inv_movements', 'ADJ')
        conn.execute("INSERT INTO inv_movements(id,movement_number,item_id,movement_type,movement_date,qty,unit_cost,total_cost,party,bank_account_id,project_id,reference,jv_id,jv_number,notes,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",
            (mid, mnum, it['id'], mtype, adate, qty, ucost, cost, '', None, None, reason, jv_id, jv_num, data.get('notes', ''), session.get('username', 'system')))
        _audit(conn, session, 'INV_ADJUST', 'inv_items', it['id'], '%s %s%s -> %s (%s)' % (it['item_name'], ('-' if direction == 'decrease' else '+'), qty, new_qty, jv_num or 'no GL'))
        conn.commit()
        return ok({'id': mid, 'movement_number': mnum, 'jv_number': jv_num, 'qty_on_hand': new_qty, 'message': 'Stock adjusted' + ((' (' + jv_num + ')') if jv_num else '')})
    finally:
        conn.close()

def api_inv_report(session, item_id=None):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _inv_migration(conn)
        if item_id:
            mv = [dict(r) for r in conn.execute("SELECT * FROM inv_movements WHERE item_id=? ORDER BY movement_date ASC, created_at ASC", (item_id,)).fetchall()]
            bal = 0.0
            for m in mv:
                t = m.get('movement_type') or ''
                q = float(m.get('qty') or 0)
                sign = 1 if (t == 'Receipt' or t == 'Adjustment+') else -1
                bal = round(bal + sign * q, 3)
                m['direction'] = 'in' if sign > 0 else 'out'
                m['balance'] = bal
            mv.reverse()
            iti = conn.execute("SELECT item_code,item_name,category,unit,qty_on_hand,avg_cost FROM inv_items WHERE id=?", (item_id,)).fetchone()
            return ok({'movements': mv, 'item': dict(iti) if iti else {}})
        items = [dict(r) for r in conn.execute("SELECT id,item_code,item_name,category,unit,reorder_level,qty_on_hand,avg_cost,(qty_on_hand*avg_cost) AS value_ghs FROM inv_items ORDER BY item_name").fetchall()]
        low = []
        total_val = 0.0
        for it in items:
            total_val += float(it.get('value_ghs') or 0)
            it['low_stock'] = bool(float(it.get('reorder_level') or 0) > 0 and float(it.get('qty_on_hand') or 0) <= float(it.get('reorder_level') or 0))
            if it['low_stock']: low.append(it)
        return ok({'items': items, 'low_stock': low, 'total_value_ghs': round(total_val, 2), 'item_count': len(items)})
    finally:
        conn.close()


def api_cash_forecast(session):
    """Forward-looking cash projection: opening cash (GL) + expected inflows
    (AR receivables by due date) - expected outflows (open commitments unpaid +
    pending withholding remittances by due date), bucketed, with a running
    projected balance. Read-only."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        import datetime as _d
        today = _d.date.today()
        def sc(q):
            try: return float((conn.execute(q).fetchone() or [0])[0] or 0)
            except Exception: return 0.0
        opening = round(sc("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '126%' OR coa_code LIKE '127%' OR coa_code LIKE '128%' OR coa_code LIKE '129%' OR coa_code='1001'"), 2)
        BUCKETS = ['Overdue', '0-30 days', '31-60 days', '61-90 days', '90+ days / undated']
        def bof(due):
            if not due: return 4
            try: d = _d.date.fromisoformat(str(due)[:10])
            except Exception: return 4
            days = (d - today).days
            if days < 0: return 0
            if days <= 30: return 1
            if days <= 60: return 2
            if days <= 90: return 3
            return 4
        inflow = [0.0] * 5; outflow = [0.0] * 5
        try:
            for r in conn.execute("SELECT due_date, (total_ghs - amount_received - COALESCE(credited_ghs,0)) AS bal FROM ar_invoices WHERE status IN ('Posted','Part-Paid')").fetchall():
                b = float(r['bal'] or 0)
                if b > 0.01: inflow[bof(r['due_date'])] += b
        except Exception: pass
        try:
            for r in conn.execute("SELECT due_date, amount_ghs FROM withholding_payables WHERE COALESCE(status,'')='Pending'").fetchall():
                outflow[bof(r['due_date'])] += float(r['amount_ghs'] or 0)
        except Exception: pass
        try:
            for r in conn.execute("SELECT due_date, (amount_ghs - COALESCE((SELECT SUM(a.amount_ghs) FROM actuals a WHERE a.commitment_id=commitments.id AND COALESCE(a.is_posted,0)=1),0)) AS unpaid FROM commitments WHERE COALESCE(status,'') NOT IN ('Cancelled','Fully Paid')").fetchall():
                u = float(r['unpaid'] or 0)
                if u > 0.01: outflow[bof(r['due_date'])] += u
        except Exception: pass
        rows = []; running = opening
        for i in range(5):
            net = round(inflow[i] - outflow[i], 2); running = round(running + net, 2)
            rows.append({'bucket': BUCKETS[i], 'inflows': round(inflow[i], 2), 'outflows': round(outflow[i], 2), 'net': net, 'projected_balance': running})
        return ok({'opening_cash': opening, 'rows': rows, 'projected_closing': running,
                   'total_inflows': round(sum(inflow), 2), 'total_outflows': round(sum(outflow), 2),
                   'generated_at': today.isoformat()})
    finally:
        conn.close()


def api_asset_dispose(data, session):
    """Dispose/sell/scrap a fixed asset. Posts Dr Accum.Depreciation + Dr Bank
    (proceeds) / Cr Asset cost, with the balancing gain (42300012) or loss
    (61700017). Marks the asset Disposed (carrying 0)."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        aid = data.get('asset_id') or data.get('id')
        a = conn.execute("SELECT * FROM asset_register WHERE id=?", (aid,)).fetchone()
        if not a: return err('Asset not found')
        a = dict(a)
        if (a.get('status') or '') == 'Disposed': return err('Asset is already disposed')
        cost = round(float(a.get('acquisition_cost') or 0), 2)
        accum = round(float(a.get('accumulated_depreciation') or 0), 2)
        nbv = round(cost - accum, 2)
        proceeds = round(float(data.get('proceeds') or 0), 2)
        if proceeds < 0: return err('Proceeds cannot be negative')
        cost_coa = data.get('cost_coa_id'); accumdep_coa = data.get('accumdep_coa_id')
        if cost > 0 and not cost_coa: return err('Select the asset cost account (PPE 111xxxxx) to credit')
        if accum > 0 and not accumdep_coa: return err('Select the accumulated depreciation account (119xxxxx)')
        ddate = data.get('disposal_date') or date.today().isoformat()
        reason = (data.get('reason') or '').strip() or 'Asset disposal'
        def coa1(*qs):
            for q in qs:
                try:
                    r = conn.execute(q).fetchone()
                    if r: return r['id']
                except Exception: pass
            return None
        gain_coa = coa1("SELECT id FROM chart_of_accounts WHERE code='42300012'",
                        "SELECT id FROM chart_of_accounts WHERE LOWER(account_name) LIKE '%disposal%' AND code LIKE '4%' ORDER BY code LIMIT 1",
                        "SELECT id FROM chart_of_accounts WHERE (LOWER(account_name) LIKE '%other income%' OR LOWER(account_name) LIKE '%sundry income%') AND code LIKE '4%' ORDER BY code LIMIT 1")
        loss_coa = coa1("SELECT id FROM chart_of_accounts WHERE code='61700017'",
                        "SELECT id FROM chart_of_accounts WHERE LOWER(account_name) LIKE '%loss on disposal%' ORDER BY code LIMIT 1")
        bank_coa = None
        if proceeds > 0:
            bank_id = data.get('bank_account_id')
            if not bank_id: return err('Select the bank account receiving the proceeds')
            bank_coa = _ar_bank_coa(conn, bank_id) if '_ar_bank_coa' in globals() else None
            if not bank_coa: return err('Bank account could not be resolved')
        gain = round(proceeds + accum - cost, 2)
        desc = 'Disposal of %s (%s)' % (a.get('asset_name'), a.get('asset_code'))
        lines = []
        if accum > 0: lines.append({'coa_id': accumdep_coa, 'debit_amount': accum, 'credit_amount': 0, 'description': desc})
        if proceeds > 0: lines.append({'coa_id': bank_coa, 'debit_amount': proceeds, 'credit_amount': 0, 'description': desc, 'bank_account_id': data.get('bank_account_id')})
        if cost > 0: lines.append({'coa_id': cost_coa, 'debit_amount': 0, 'credit_amount': cost, 'description': desc})
        if gain > 0.005:
            if not gain_coa: return err('Gain/disposal income account (42300012) not found in the chart of accounts')
            lines.append({'coa_id': gain_coa, 'debit_amount': 0, 'credit_amount': gain, 'description': 'Gain on disposal of ' + (a.get('asset_code') or '')})
        elif gain < -0.005:
            if not loss_coa: return err('Loss on disposal account (61700017) not found in the chart of accounts')
            lines.append({'coa_id': loss_coa, 'debit_amount': round(-gain, 2), 'credit_amount': 0, 'description': 'Loss on disposal of ' + (a.get('asset_code') or '')})
        if not lines: return err('Nothing to post for this asset')
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', ddate, desc, a.get('asset_code') or '', a.get('project_id'), data.get('bank_account_id'), 'asset_disposal', aid, lines)
        except Exception as e:
            return err('Could not post disposal: %s' % e)
        conn.execute("UPDATE asset_register SET status='Disposed', carrying_amount=0, updated_at=datetime('now'), notes=COALESCE(notes,'') || ? WHERE id=?",
            (' | Disposed %s: proceeds %.2f, NBV %.2f, %s %.2f (%s) - %s' % (ddate, proceeds, nbv, ('gain' if gain >= 0 else 'loss'), abs(gain), jv_num, reason), aid))
        _audit(conn, session, 'DISPOSE_ASSET', 'asset_register', aid, '%s disposed proceeds %.2f NBV %.2f %s %.2f (%s)' % (a.get('asset_code'), proceeds, nbv, ('gain' if gain >= 0 else 'loss'), abs(gain), jv_num))
        conn.commit()
        return ok({'id': aid, 'jv_number': jv_num, 'nbv': nbv, 'proceeds': proceeds, 'gain_loss': gain, 'message': 'Asset disposed as %s (%s GHS %.2f)' % (jv_num, ('gain' if gain >= 0 else 'loss'), abs(gain))})
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# ACCOUNTS PAYABLE — supplier bills (invoices), payments, debit notes, aging,
# vendor statements. Mirror of the AR module. Bills post Dr Expense / Cr Trade
# Payables control; payments post Dr Payables / Cr Bank; debit notes Dr Payables
# / Cr Expense. All through _create_posted_journal so payables land on the SFP
# (liability) and expense flows into the I&E. Reuses the existing vendors master.
# ═══════════════════════════════════════════════════════════════════════════
def _ap_migration(conn):
    conn.execute("""CREATE TABLE IF NOT EXISTS ap_bill_lines(
        id TEXT PRIMARY KEY, bill_id TEXT, line_number INTEGER,
        description TEXT, expense_coa_id TEXT, amount_ghs REAL DEFAULT 0)""")
    conn.execute("""CREATE TABLE IF NOT EXISTS ap_bills(
        id TEXT PRIMARY KEY, bill_number TEXT, vendor_invoice_no TEXT, vendor_id TEXT, bill_date TEXT,
        due_date TEXT, project_id TEXT, expense_coa_id TEXT, description TEXT,
        amount_ghs REAL DEFAULT 0, tax_ghs REAL DEFAULT 0, total_ghs REAL DEFAULT 0,
        amount_paid REAL DEFAULT 0, debited_ghs REAL DEFAULT 0, status TEXT DEFAULT 'Draft',
        jv_id TEXT, jv_number TEXT, created_by TEXT, created_at TEXT DEFAULT(datetime('now')), posted_at TEXT)""")
    conn.execute("""CREATE TABLE IF NOT EXISTS ap_payments(
        id TEXT PRIMARY KEY, payment_number TEXT, bill_id TEXT, vendor_id TEXT,
        payment_date TEXT, amount_ghs REAL DEFAULT 0, bank_account_id TEXT, payment_method TEXT,
        reference TEXT, jv_id TEXT, jv_number TEXT, notes TEXT, created_by TEXT, created_at TEXT DEFAULT(datetime('now')))""")
    conn.execute("""CREATE TABLE IF NOT EXISTS ap_debit_notes(
        id TEXT PRIMARY KEY, debit_number TEXT, bill_id TEXT, vendor_id TEXT,
        debit_date TEXT, amount_ghs REAL DEFAULT 0, reason TEXT, jv_id TEXT, jv_number TEXT,
        created_by TEXT, created_at TEXT DEFAULT(datetime('now')))""")
    conn.commit()

def _ap_control_coa(conn):
    for q in ("SELECT id FROM chart_of_accounts WHERE code='21100021'",
              "SELECT id FROM chart_of_accounts WHERE code='21100001'",
              "SELECT id FROM chart_of_accounts WHERE (LOWER(account_name) LIKE '%creditor%' OR LOWER(account_name) LIKE '%payable%') AND code LIKE '21%' ORDER BY code LIMIT 1",
              "SELECT id FROM chart_of_accounts WHERE code LIKE '211%' ORDER BY code LIMIT 1"):
        try:
            r = conn.execute(q).fetchone()
            if r: return r['id']
        except Exception:
            pass
    return None

def _ap_bank_coa(conn, bank_account_id):
    return _ar_bank_coa(conn, bank_account_id) if '_ar_bank_coa' in globals() else None

def _ap_next(conn, table, prefix):
    col = {'ap_bills': 'bill_number', 'ap_payments': 'payment_number', 'ap_debit_notes': 'debit_number'}.get(table)
    import datetime as _d
    full = '%s-%s-' % (prefix, _d.datetime.now().year)
    if col:
        return _seq_code(conn, table, col, full, 4)
    try:
        n = conn.execute("SELECT COUNT(*) FROM %s" % table).fetchone()[0] or 0
    except Exception:
        n = 0
    return full + '%04d' % (n + 1)

def api_ap_vendors(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn)
        rows = [dict(r) for r in conn.execute("""
            SELECT v.id, v.vendor_code, v.vendor_name, v.vendor_type, v.contact_person, v.email, v.phone, v.tin,
              COALESCE((SELECT SUM(b.total_ghs - b.amount_paid - COALESCE(b.debited_ghs,0)) FROM ap_bills b
                        WHERE b.vendor_id=v.id AND b.status IN ('Posted','Part-Paid')),0) AS outstanding_ghs,
              COALESCE((SELECT COUNT(*) FROM ap_bills b WHERE b.vendor_id=v.id),0) AS bill_count
            FROM vendors v ORDER BY v.vendor_name""").fetchall()]
        return ok({'vendors': rows})
    finally:
        conn.close()

def api_ap_bills(session, vendor_id=None):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn)
        q = """SELECT b.*, v.vendor_name, v.vendor_code, p.project_code, coa.account_name AS expense_account,
                 (b.total_ghs - b.amount_paid - COALESCE(b.debited_ghs,0)) AS balance_ghs
               FROM ap_bills b LEFT JOIN vendors v ON v.id=b.vendor_id
               LEFT JOIN projects p ON p.id=b.project_id
               LEFT JOIN chart_of_accounts coa ON coa.id=b.expense_coa_id"""
        args = []
        if vendor_id:
            q += " WHERE b.vendor_id=?"; args.append(vendor_id)
        q += " ORDER BY b.bill_date DESC, b.created_at DESC"
        rows = [dict(r) for r in conn.execute(q, args).fetchall()]
        return ok({'bills': rows})
    finally:
        conn.close()

