def api_ap_save_bill(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn)
        if not data.get('vendor_id'): return err('Select a vendor')
        raw_lines = data.get('lines')
        norm = []
        if isinstance(raw_lines, list) and raw_lines:
            for ln in raw_lines:
                a = round(float(ln.get('amount_ghs') or 0), 2)
                if a <= 0 or not ln.get('expense_coa_id'): continue
                norm.append({'expense_coa_id': ln.get('expense_coa_id'), 'amount_ghs': a, 'description': (ln.get('description') or '')})
            if not norm: return err('Add at least one valid bill line (expense account + amount)')
        else:
            if not data.get('expense_coa_id'): return err('Select the expense account to debit')
            a = round(float(data.get('amount_ghs') or 0), 2)
            if a <= 0: return err('Bill amount must be greater than zero')
            norm = [{'expense_coa_id': data.get('expense_coa_id'), 'amount_ghs': a, 'description': (data.get('description') or '')}]
        amount = round(sum(l['amount_ghs'] for l in norm), 2)
        first_coa = norm[0]['expense_coa_id']
        total = amount
        bid = data.get('id') or str(uuid.uuid4())
        existing = conn.execute("SELECT status FROM ap_bills WHERE id=?", (bid,)).fetchone()
        if existing and existing['status'] != 'Draft':
            return err('Only draft bills can be edited')
        num = data.get('bill_number') or _ap_next(conn, 'ap_bills', 'BILL')
        if existing:
            conn.execute("UPDATE ap_bills SET vendor_id=?,vendor_invoice_no=?,bill_date=?,due_date=?,project_id=?,expense_coa_id=?,description=?,amount_ghs=?,tax_ghs=0,total_ghs=? WHERE id=?",
                (data['vendor_id'], data.get('vendor_invoice_no', ''), data.get('bill_date'), data.get('due_date'), data.get('project_id') or None, first_coa, data.get('description', ''), amount, total, bid))
        else:
            conn.execute("INSERT INTO ap_bills(id,bill_number,vendor_invoice_no,vendor_id,bill_date,due_date,project_id,expense_coa_id,description,amount_ghs,tax_ghs,total_ghs,amount_paid,status,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,0,?,0,'Draft',?)",
                (bid, num, data.get('vendor_invoice_no', ''), data['vendor_id'], data.get('bill_date') or date.today().isoformat(), data.get('due_date'), data.get('project_id') or None, first_coa, data.get('description', ''), amount, total, session.get('username', 'system')))
        conn.execute("DELETE FROM ap_bill_lines WHERE bill_id=?", (bid,))
        for i, l in enumerate(norm, 1):
            conn.execute("INSERT INTO ap_bill_lines(id,bill_id,line_number,description,expense_coa_id,amount_ghs) VALUES(?,?,?,?,?,?)",
                (str(uuid.uuid4()), bid, i, l['description'], l['expense_coa_id'], l['amount_ghs']))
        # UCC unit attribution: stamp the bill's unit_id (explicit pick → home unit).
        try:
            _bu = (_ucc_resolve_write_unit(conn, data, session)
                   if '_ucc_resolve_write_unit' in globals() else (data or {}).get('unit_id'))
            if _bu and 'unit_id' in [r[1] for r in conn.execute("PRAGMA table_info(ap_bills)").fetchall()]:
                conn.execute("UPDATE ap_bills SET unit_id=? WHERE id=?", (_bu, bid))
        except Exception:
            pass
        _audit(conn, session, 'SAVE_AP_BILL', 'ap_bills', bid, num)
        conn.commit()
        return ok({'id': bid, 'bill_number': num})
    finally:
        conn.close()

def api_ap_post_bill(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn)
        bid = data.get('id') or data.get('bill_id')
        bill = conn.execute("SELECT * FROM ap_bills WHERE id=?", (bid,)).fetchone()
        if not bill: return err('Bill not found')
        bill = dict(bill)
        if bill['status'] != 'Draft': return err('Bill is already posted')
        ap_coa = _ap_control_coa(conn)
        if not ap_coa: return err('No payables control account (e.g. 21100021 Sundry Creditors Control) found in the chart of accounts')
        total = round(float(bill['total_ghs'] or 0), 2)
        ven = conn.execute("SELECT vendor_name FROM vendors WHERE id=?", (bill['vendor_id'],)).fetchone()
        desc = 'Bill %s - %s' % (bill['bill_number'], (ven['vendor_name'] if ven else ''))
        lines = []
        _b_unit = bill.get('unit_id') if hasattr(bill, 'get') else None
        blines = [dict(r) for r in conn.execute("SELECT description,expense_coa_id,amount_ghs FROM ap_bill_lines WHERE bill_id=? ORDER BY line_number", (bid,)).fetchall()]
        if blines:
            for bl in blines:
                lines.append({'coa_id': bl['expense_coa_id'], 'debit_amount': round(float(bl['amount_ghs'] or 0), 2), 'credit_amount': 0, 'description': (bl['description'] or desc), 'project_id': bill['project_id'], 'unit_id': _b_unit})
        else:
            lines.append({'coa_id': bill['expense_coa_id'], 'debit_amount': total, 'credit_amount': 0, 'description': desc, 'project_id': bill['project_id'], 'unit_id': _b_unit})
        lines.append({'coa_id': ap_coa, 'debit_amount': 0, 'credit_amount': total, 'description': desc, 'project_id': bill['project_id'], 'unit_id': _b_unit})
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', bill.get('bill_date') or date.today().isoformat(), desc, bill.get('vendor_invoice_no') or bill['bill_number'], bill['project_id'], None, 'ap_bills', bid, lines)
        except Exception as e:
            return err('Could not post bill: %s' % e)
        conn.execute("UPDATE ap_bills SET status='Posted', jv_id=?, jv_number=?, posted_at=datetime('now') WHERE id=?", (jv_id, jv_num, bid))
        _audit(conn, session, 'POST_AP_BILL', 'ap_bills', bid, '%s posted as %s GHS %.2f' % (bill['bill_number'], jv_num, total))
        conn.commit()
        return ok({'id': bid, 'jv_number': jv_num, 'message': '%s posted as %s' % (bill['bill_number'], jv_num)})
    finally:
        conn.close()

def api_ap_payment(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn)
        bid = data.get('bill_id') or data.get('id')
        bill = conn.execute("SELECT * FROM ap_bills WHERE id=?", (bid,)).fetchone()
        if not bill: return err('Bill not found')
        bill = dict(bill)
        if bill['status'] not in ('Posted', 'Part-Paid'): return err('Only a posted bill can be paid')
        amount = round(float(data.get('amount_ghs') or 0), 2)
        if amount <= 0: return err('Payment amount must be greater than zero')
        balance = round(float(bill['total_ghs'] or 0) - float(bill['amount_paid'] or 0) - float(bill.get('debited_ghs') or 0), 2)
        if amount > balance + 0.01: return err('Payment GHS %.2f exceeds the outstanding balance GHS %.2f' % (amount, balance))
        bank_id = data.get('bank_account_id')
        if not bank_id: return err('Select the bank account paying the bill')
        bank_coa = _ap_bank_coa(conn, bank_id)
        ap_coa = _ap_control_coa(conn)
        if not bank_coa or not ap_coa: return err('Bank or payables control account could not be resolved')
        ref = (data.get('reference') or '').strip()
        pdate = data.get('payment_date') or date.today().isoformat()
        ven = conn.execute("SELECT vendor_name FROM vendors WHERE id=?", (bill['vendor_id'],)).fetchone()
        desc = 'Payment for %s — %s' % (bill['bill_number'], (ven['vendor_name'] if ven else ''))
        lines = [{'coa_id': ap_coa, 'debit_amount': amount, 'credit_amount': 0, 'description': desc, 'project_id': bill['project_id']},
                 {'coa_id': bank_coa, 'debit_amount': 0, 'credit_amount': amount, 'description': desc, 'project_id': bill['project_id'], 'bank_account_id': bank_id}]
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'PV', pdate, desc, ref, bill['project_id'], bank_id, 'ap_payments', bid, lines)
        except Exception as e:
            return err('Could not post payment: %s' % e)
        pid = str(uuid.uuid4()); pnum = _ap_next(conn, 'ap_payments', 'APP')
        conn.execute("INSERT INTO ap_payments(id,payment_number,bill_id,vendor_id,payment_date,amount_ghs,bank_account_id,payment_method,reference,jv_id,jv_number,notes,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
            (pid, pnum, bid, bill['vendor_id'], pdate, amount, bank_id, data.get('payment_method', 'Bank Transfer'), ref, jv_id, jv_num, data.get('notes', ''), session.get('username', 'system')))
        new_paid = round(float(bill['amount_paid'] or 0) + amount, 2)
        new_status = 'Paid' if new_paid >= float(bill['total_ghs'] or 0) - 0.01 else 'Part-Paid'
        conn.execute("UPDATE ap_bills SET amount_paid=?, status=? WHERE id=?", (new_paid, new_status, bid))
        _audit(conn, session, 'AP_PAYMENT', 'ap_bills', bid, '%s paid GHS %.2f (%s) -> %s' % (bill['bill_number'], amount, jv_num, new_status))
        conn.commit()
        return ok({'id': pid, 'jv_number': jv_num, 'status': new_status, 'message': 'Payment posted as %s' % jv_num})
    finally:
        conn.close()

def api_ap_debit_note(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn)
        bid = data.get('bill_id') or data.get('id')
        bill = conn.execute("SELECT * FROM ap_bills WHERE id=?", (bid,)).fetchone()
        if not bill: return err('Bill not found')
        bill = dict(bill)
        if bill['status'] not in ('Posted', 'Part-Paid'): return err('Only a posted (unpaid/part-paid) bill can be debited')
        amount = round(float(data.get('amount_ghs') or 0), 2)
        if amount <= 0: return err('Debit amount must be greater than zero')
        debited = round(float(bill.get('debited_ghs') or 0), 2)
        outstanding = round(float(bill['total_ghs'] or 0) - float(bill['amount_paid'] or 0) - debited, 2)
        if amount > outstanding + 0.01: return err('Debit GHS %.2f exceeds the outstanding balance GHS %.2f' % (amount, outstanding))
        ap_coa = _ap_control_coa(conn)
        if not ap_coa: return err('Payables control account not found')
        reason = (data.get('reason') or '').strip() or 'Debit note'
        ddate = data.get('debit_date') or date.today().isoformat()
        desc = 'Debit note for %s - %s' % (bill['bill_number'], reason)
        lines = [{'coa_id': ap_coa, 'debit_amount': amount, 'credit_amount': 0, 'description': desc, 'project_id': bill['project_id']},
                 {'coa_id': bill['expense_coa_id'], 'debit_amount': 0, 'credit_amount': amount, 'description': desc, 'project_id': bill['project_id']}]
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', ddate, desc, bill['bill_number'], bill['project_id'], None, 'ap_debit_notes', bid, lines)
        except Exception as e:
            return err('Could not post debit note: %s' % e)
        dnid = str(uuid.uuid4()); dnnum = _ap_next(conn, 'ap_debit_notes', 'DN')
        conn.execute("INSERT INTO ap_debit_notes(id,debit_number,bill_id,vendor_id,debit_date,amount_ghs,reason,jv_id,jv_number,created_by) VALUES(?,?,?,?,?,?,?,?,?,?)",
            (dnid, dnnum, bid, bill['vendor_id'], ddate, amount, reason, jv_id, jv_num, session.get('username', 'system')))
        new_debited = round(debited + amount, 2)
        settled = round(float(bill['amount_paid'] or 0) + new_debited, 2)
        new_status = 'Paid' if settled >= float(bill['total_ghs'] or 0) - 0.01 else 'Part-Paid'
        conn.execute("UPDATE ap_bills SET debited_ghs=?, status=? WHERE id=?", (new_debited, new_status, bid))
        _audit(conn, session, 'AP_DEBIT_NOTE', 'ap_bills', bid, '%s debited GHS %.2f (%s)' % (bill['bill_number'], amount, jv_num))
        conn.commit()
        return ok({'id': dnid, 'debit_number': dnnum, 'jv_number': jv_num, 'status': new_status, 'message': 'Debit note posted as %s' % jv_num})
    finally:
        conn.close()

def api_ap_aging(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn)
        rows = [dict(r) for r in conn.execute("""
            SELECT b.id, b.bill_number, b.bill_date, b.due_date, b.total_ghs, b.amount_paid,
                   (b.total_ghs - b.amount_paid - COALESCE(b.debited_ghs,0)) AS balance, v.vendor_name, v.vendor_code
            FROM ap_bills b LEFT JOIN vendors v ON v.id=b.vendor_id
            WHERE b.status IN ('Posted','Part-Paid') AND (b.total_ghs - b.amount_paid - COALESCE(b.debited_ghs,0)) > 0.01
            ORDER BY v.vendor_name, b.due_date""").fetchall()]
        import datetime as _d
        today = _d.date.today()
        buckets = {'current': 0.0, 'b1_30': 0.0, 'b31_60': 0.0, 'b61_90': 0.0, 'b90_plus': 0.0}
        per_ven = {}
        for r in rows:
            bal = round(float(r['balance'] or 0), 2)
            days = 0
            try:
                if r.get('due_date'): days = (today - _d.date.fromisoformat(str(r['due_date'])[:10])).days
            except Exception:
                days = 0
            key = 'current' if days <= 0 else ('b1_30' if days <= 30 else ('b31_60' if days <= 60 else ('b61_90' if days <= 90 else 'b90_plus')))
            buckets[key] += bal
            ven = r.get('vendor_name') or '—'
            pv = per_ven.setdefault(ven, {'vendor': ven, 'current': 0, 'b1_30': 0, 'b31_60': 0, 'b61_90': 0, 'b90_plus': 0, 'total': 0})
            pv[key] += bal; pv['total'] += bal
            r['days_overdue'] = max(0, days); r['bucket'] = key
        for k in buckets: buckets[k] = round(buckets[k], 2)
        for pv in per_ven.values():
            for k in pv:
                if k != 'vendor': pv[k] = round(pv[k], 2)
        return ok({'buckets': buckets, 'by_vendor': list(per_ven.values()), 'bills': rows, 'total_outstanding': round(sum(buckets.values()), 2)})
    finally:
        conn.close()

def api_ap_statement(session, vendor_id=None):
    if not session: return err('Not authenticated')
    if not vendor_id: return err('vendor_id is required')
    conn = get_db()
    try:
        _ap_migration(conn)
        ven = conn.execute("SELECT * FROM vendors WHERE id=?", (vendor_id,)).fetchone()
        if not ven: return err('Vendor not found')
        bills = [dict(r) for r in conn.execute("SELECT bill_number,bill_date,due_date,total_ghs,description,status FROM ap_bills WHERE vendor_id=? AND status!='Draft'", (vendor_id,)).fetchall()]
        pays = [dict(r) for r in conn.execute("SELECT payment_number,payment_date,amount_ghs,reference FROM ap_payments WHERE vendor_id=?", (vendor_id,)).fetchall()]
        dnotes = [dict(r) for r in conn.execute("SELECT debit_number,debit_date,amount_ghs,reason FROM ap_debit_notes WHERE vendor_id=?", (vendor_id,)).fetchall()]
        events = []
        for b in bills: events.append({'date': b['bill_date'], 'ref': b['bill_number'], 'type': 'Bill', 'credit': round(float(b['total_ghs'] or 0), 2), 'debit': 0, 'desc': b.get('description', '')})
        for p in pays: events.append({'date': p['payment_date'], 'ref': p['payment_number'], 'type': 'Payment', 'credit': 0, 'debit': round(float(p['amount_ghs'] or 0), 2), 'desc': p.get('reference', '')})
        for dn in dnotes: events.append({'date': dn['debit_date'], 'ref': dn['debit_number'], 'type': 'Debit Note', 'credit': 0, 'debit': round(float(dn['amount_ghs'] or 0), 2), 'desc': dn.get('reason', '')})
        events.sort(key=lambda e: (str(e['date'] or ''), e['type'] != 'Bill'))
        bal = 0.0
        for e in events:
            bal = round(bal + e['credit'] - e['debit'], 2); e['balance'] = bal
        return ok({'vendor': dict(ven), 'events': events, 'balance': bal})
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# RECURRING SUPPLIER BILLS — standing templates (rent, utilities, subscriptions)
# that generate AP bills on a schedule. "Generate due" creates one ap_bill per
# missed period up to the run date, optionally auto-posting (Dr Expense / Cr
# Payables). Advances next_due_date by the template frequency. Builds on the AP
# module and posts through _create_posted_journal.
# ═══════════════════════════════════════════════════════════════════════════
def _aprec_migration(conn):
    conn.execute("""CREATE TABLE IF NOT EXISTS ap_recurring(
        id TEXT PRIMARY KEY, vendor_id TEXT, description TEXT, expense_coa_id TEXT,
        amount_ghs REAL DEFAULT 0, project_id TEXT, frequency TEXT DEFAULT 'Monthly',
        start_date TEXT, end_date TEXT, next_due_date TEXT, day_offset INTEGER DEFAULT 0,
        auto_post INTEGER DEFAULT 0, active INTEGER DEFAULT 1, last_generated TEXT,
        bills_generated INTEGER DEFAULT 0, created_by TEXT, created_at TEXT DEFAULT(datetime('now')))""")
    conn.commit()

def _aprec_advance(iso, frequency):
    import datetime as _d, calendar as _cal
    try:
        d = _d.date.fromisoformat(str(iso)[:10])
    except Exception:
        return iso
    months = {'Monthly': 1, 'Quarterly': 3, 'Semi-Annual': 6, 'Annually': 12}.get(frequency, 1)
    if frequency == 'Weekly':
        nd = d + _d.timedelta(days=7)
        return nd.isoformat()
    m0 = d.month - 1 + months
    y = d.year + m0 // 12
    m = m0 % 12 + 1
    day = min(d.day, _cal.monthrange(y, m)[1])
    return _d.date(y, m, day).isoformat()

def api_ap_recurring(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn); _aprec_migration(conn)
        rows = [dict(r) for r in conn.execute("""
            SELECT t.*, v.vendor_name, v.vendor_code, coa.account_name AS expense_account, coa.code AS expense_code, p.project_code
            FROM ap_recurring t LEFT JOIN vendors v ON v.id=t.vendor_id
            LEFT JOIN chart_of_accounts coa ON coa.id=t.expense_coa_id
            LEFT JOIN projects p ON p.id=t.project_id
            ORDER BY t.active DESC, t.next_due_date""").fetchall()]
        return ok({'templates': rows})
    finally:
        conn.close()

def api_ap_save_recurring(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn); _aprec_migration(conn)
        if not data.get('vendor_id'): return err('Select a vendor')
        if not data.get('expense_coa_id'): return err('Select the expense account to debit')
        amount = round(float(data.get('amount_ghs') or 0), 2)
        if amount <= 0: return err('Amount must be greater than zero')
        freq = data.get('frequency') or 'Monthly'
        start = data.get('start_date') or date.today().isoformat()
        tid = data.get('id') or str(uuid.uuid4())
        existing = conn.execute("SELECT next_due_date FROM ap_recurring WHERE id=?", (tid,)).fetchone()
        next_due = data.get('next_due_date') or (existing['next_due_date'] if existing else None) or start
        offset = int(data.get('day_offset') or 0)
        auto = 1 if data.get('auto_post') else 0
        active = 0 if (data.get('active') in (0, '0', False, 'false')) else 1
        if existing:
            conn.execute("""UPDATE ap_recurring SET vendor_id=?,description=?,expense_coa_id=?,amount_ghs=?,project_id=?,
                frequency=?,start_date=?,end_date=?,next_due_date=?,day_offset=?,auto_post=?,active=? WHERE id=?""",
                (data['vendor_id'], data.get('description', ''), data['expense_coa_id'], amount, data.get('project_id') or None,
                 freq, start, data.get('end_date') or None, next_due, offset, auto, active, tid))
        else:
            conn.execute("""INSERT INTO ap_recurring(id,vendor_id,description,expense_coa_id,amount_ghs,project_id,frequency,
                start_date,end_date,next_due_date,day_offset,auto_post,active,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (tid, data['vendor_id'], data.get('description', ''), data['expense_coa_id'], amount, data.get('project_id') or None,
                 freq, start, data.get('end_date') or None, next_due, offset, auto, active, session.get('username', 'system')))
        _audit(conn, session, 'SAVE_AP_RECURRING', 'ap_recurring', tid, data.get('description', ''))
        conn.commit()
        return ok({'id': tid})
    finally:
        conn.close()

