def api_ap_recurring_generate(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn); _aprec_migration(conn)
        as_of = data.get('as_of') or date.today().isoformat()
        only_id = data.get('id')
        ap_coa = _ap_control_coa(conn)
        if not ap_coa: return err('No payables control account (21100021) found')
        q = "SELECT * FROM ap_recurring WHERE active=1 AND next_due_date IS NOT NULL AND next_due_date<=?"
        params = [as_of]
        if only_id:
            q += " AND id=?"; params.append(only_id)
        templates = [dict(r) for r in conn.execute(q, params).fetchall()]
        generated = []
        for t in templates:
            guard = 0
            nd = t.get('next_due_date')
            while nd and str(nd)[:10] <= str(as_of)[:10] and guard < 60:
                if t.get('end_date') and str(nd)[:10] > str(t['end_date'])[:10]:
                    break
                guard += 1
                amount = round(float(t.get('amount_ghs') or 0), 2)
                ven = conn.execute("SELECT vendor_name FROM vendors WHERE id=?", (t['vendor_id'],)).fetchone()
                bid = str(uuid.uuid4())
                num = _ap_next(conn, 'ap_bills', 'BILL')
                offset = int(t.get('day_offset') or 0)
                import datetime as _d
                try:
                    due = (_d.date.fromisoformat(str(nd)[:10]) + _d.timedelta(days=offset)).isoformat()
                except Exception:
                    due = nd
                desc = (t.get('description') or 'Recurring bill') + ' (' + str(nd)[:10] + ')'
                conn.execute("""INSERT INTO ap_bills(id,bill_number,vendor_invoice_no,vendor_id,bill_date,due_date,project_id,
                    expense_coa_id,description,amount_ghs,tax_ghs,total_ghs,amount_paid,status,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,0,?,0,'Draft',?)""",
                    (bid, num, '', t['vendor_id'], nd, due, t.get('project_id') or None, t['expense_coa_id'], desc, amount, amount, session.get('username', 'system')))
                conn.execute("INSERT INTO ap_bill_lines(id,bill_id,line_number,description,expense_coa_id,amount_ghs) VALUES(?,?,1,?,?,?)",
                    (str(uuid.uuid4()), bid, desc, t['expense_coa_id'], amount))
                jv_num = None
                if t.get('auto_post'):
                    pdesc = 'Bill %s - %s' % (num, (ven['vendor_name'] if ven else ''))
                    lines = [{'coa_id': t['expense_coa_id'], 'debit_amount': amount, 'credit_amount': 0, 'description': desc, 'project_id': t.get('project_id')},
                             {'coa_id': ap_coa, 'debit_amount': 0, 'credit_amount': amount, 'description': pdesc, 'project_id': t.get('project_id')}]
                    try:
                        jv_id, jv_num = _create_posted_journal(conn, session, 'JV', nd, pdesc, num, t.get('project_id'), None, 'ap_bills', bid, lines)
                        conn.execute("UPDATE ap_bills SET status='Posted', jv_id=?, jv_number=?, posted_at=datetime('now') WHERE id=?", (jv_id, jv_num, bid))
                    except Exception as e:
                        # leave as Draft if posting fails (e.g. closed period) and stop advancing this template
                        generated.append({'template_id': t['id'], 'bill_number': num, 'due': nd, 'amount': amount, 'posted': False, 'note': str(e)})
                        nd = None
                        break
                generated.append({'template_id': t['id'], 'bill_number': num, 'due': nd, 'amount': amount, 'posted': bool(jv_num), 'jv_number': jv_num})
                nd = _aprec_advance(nd, t.get('frequency'))
            if nd:
                conn.execute("UPDATE ap_recurring SET next_due_date=?, last_generated=?, bills_generated=bills_generated+? WHERE id=?",
                    (nd, as_of, guard, t['id']))
            else:
                conn.execute("UPDATE ap_recurring SET last_generated=?, bills_generated=bills_generated+? WHERE id=?",
                    (as_of, guard, t['id']))
        _audit(conn, session, 'GENERATE_AP_RECURRING', 'ap_recurring', only_id or 'all', '%d bill(s) generated' % len(generated))
        conn.commit()
        return ok({'generated': generated, 'count': len(generated)})
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# RECURRING SALES INVOICES — standing templates (rent, tuition, subscriptions)
# that generate AR invoices on a schedule. Mirror of the recurring-AP engine.
# Generate creates one ar_invoice per missed period up to the run date,
# optionally auto-posting (Dr Receivables / Cr Income). Reuses _aprec_advance.
# ═══════════════════════════════════════════════════════════════════════════
def _arrec_migration(conn):
    conn.execute("""CREATE TABLE IF NOT EXISTS ar_recurring(
        id TEXT PRIMARY KEY, customer_id TEXT, description TEXT, income_coa_id TEXT,
        amount_ghs REAL DEFAULT 0, project_id TEXT, frequency TEXT DEFAULT 'Monthly',
        start_date TEXT, end_date TEXT, next_due_date TEXT, day_offset INTEGER DEFAULT 0,
        auto_post INTEGER DEFAULT 0, active INTEGER DEFAULT 1, last_generated TEXT,
        invoices_generated INTEGER DEFAULT 0, created_by TEXT, created_at TEXT DEFAULT(datetime('now')))""")
    conn.commit()

def api_ar_recurring(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn); _arrec_migration(conn)
        rows = [dict(r) for r in conn.execute("""
            SELECT t.*, c.customer_name, c.customer_code, coa.account_name AS income_account, coa.code AS income_code, p.project_code
            FROM ar_recurring t LEFT JOIN ar_customers c ON c.id=t.customer_id
            LEFT JOIN chart_of_accounts coa ON coa.id=t.income_coa_id
            LEFT JOIN projects p ON p.id=t.project_id
            ORDER BY t.active DESC, t.next_due_date""").fetchall()]
        return ok({'templates': rows})
    finally:
        conn.close()

def api_ar_save_recurring(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn); _arrec_migration(conn)
        if not data.get('customer_id'): return err('Select a customer')
        if not data.get('income_coa_id'): return err('Select the income account to credit')
        amount = round(float(data.get('amount_ghs') or 0), 2)
        if amount <= 0: return err('Amount must be greater than zero')
        freq = data.get('frequency') or 'Monthly'
        start = data.get('start_date') or date.today().isoformat()
        tid = data.get('id') or str(uuid.uuid4())
        existing = conn.execute("SELECT next_due_date FROM ar_recurring WHERE id=?", (tid,)).fetchone()
        next_due = data.get('next_due_date') or (existing['next_due_date'] if existing else None) or start
        offset = int(data.get('day_offset') or 0)
        auto = 1 if data.get('auto_post') else 0
        active = 0 if (data.get('active') in (0, '0', False, 'false')) else 1
        if existing:
            conn.execute("""UPDATE ar_recurring SET customer_id=?,description=?,income_coa_id=?,amount_ghs=?,project_id=?,
                frequency=?,start_date=?,end_date=?,next_due_date=?,day_offset=?,auto_post=?,active=? WHERE id=?""",
                (data['customer_id'], data.get('description', ''), data['income_coa_id'], amount, data.get('project_id') or None,
                 freq, start, data.get('end_date') or None, next_due, offset, auto, active, tid))
        else:
            conn.execute("""INSERT INTO ar_recurring(id,customer_id,description,income_coa_id,amount_ghs,project_id,frequency,
                start_date,end_date,next_due_date,day_offset,auto_post,active,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (tid, data['customer_id'], data.get('description', ''), data['income_coa_id'], amount, data.get('project_id') or None,
                 freq, start, data.get('end_date') or None, next_due, offset, auto, active, session.get('username', 'system')))
        _audit(conn, session, 'SAVE_AR_RECURRING', 'ar_recurring', tid, data.get('description', ''))
        conn.commit()
        return ok({'id': tid})
    finally:
        conn.close()

def api_ar_recurring_toggle(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _arrec_migration(conn)
        tid = data.get('id')
        t = conn.execute("SELECT active FROM ar_recurring WHERE id=?", (tid,)).fetchone()
        if not t: return err('Template not found')
        new = 0 if t['active'] else 1
        conn.execute("UPDATE ar_recurring SET active=? WHERE id=?", (new, tid))
        _audit(conn, session, 'TOGGLE_AR_RECURRING', 'ar_recurring', tid, 'active=%s' % new)
        conn.commit()
        return ok({'id': tid, 'active': new})
    finally:
        conn.close()

def api_ar_recurring_generate(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn); _arrec_migration(conn)
        as_of = data.get('as_of') or date.today().isoformat()
        only_id = data.get('id')
        ar_coa = _ar_control_coa(conn)
        if not ar_coa: return err('No receivables control account (123xxxxx) found')
        q = "SELECT * FROM ar_recurring WHERE active=1 AND next_due_date IS NOT NULL AND next_due_date<=?"
        params = [as_of]
        if only_id:
            q += " AND id=?"; params.append(only_id)
        templates = [dict(r) for r in conn.execute(q, params).fetchall()]
        generated = []
        for t in templates:
            guard = 0
            nd = t.get('next_due_date')
            while nd and str(nd)[:10] <= str(as_of)[:10] and guard < 60:
                if t.get('end_date') and str(nd)[:10] > str(t['end_date'])[:10]:
                    break
                guard += 1
                amount = round(float(t.get('amount_ghs') or 0), 2)
                cust = conn.execute("SELECT customer_name FROM ar_customers WHERE id=?", (t['customer_id'],)).fetchone()
                iid = str(uuid.uuid4())
                num = _ar_next(conn, 'ar_invoices', 'INV')
                offset = int(t.get('day_offset') or 0)
                import datetime as _d
                try:
                    due = (_d.date.fromisoformat(str(nd)[:10]) + _d.timedelta(days=offset)).isoformat()
                except Exception:
                    due = nd
                desc = (t.get('description') or 'Recurring invoice') + ' (' + str(nd)[:10] + ')'
                conn.execute("""INSERT INTO ar_invoices(id,invoice_number,customer_id,invoice_date,due_date,project_id,income_coa_id,
                    description,amount_ghs,tax_ghs,total_ghs,amount_received,status,created_by) VALUES(?,?,?,?,?,?,?,?,?,0,?,0,'Draft',?)""",
                    (iid, num, t['customer_id'], nd, due, t.get('project_id') or None, t['income_coa_id'], desc, amount, amount, session.get('username', 'system')))
                conn.execute("INSERT INTO ar_invoice_lines(id,invoice_id,line_number,description,income_coa_id,amount_ghs) VALUES(?,?,1,?,?,?)",
                    (str(uuid.uuid4()), iid, desc, t['income_coa_id'], amount))
                jv_num = None
                if t.get('auto_post'):
                    idesc = 'Invoice %s - %s' % (num, (cust['customer_name'] if cust else ''))
                    lines = [{'coa_id': ar_coa, 'debit_amount': amount, 'credit_amount': 0, 'description': idesc, 'project_id': t.get('project_id')},
                             {'coa_id': t['income_coa_id'], 'debit_amount': 0, 'credit_amount': amount, 'description': desc, 'project_id': t.get('project_id')}]
                    try:
                        jv_id, jv_num = _create_posted_journal(conn, session, 'JV', nd, idesc, num, t.get('project_id'), None, 'ar_invoices', iid, lines)
                        conn.execute("UPDATE ar_invoices SET status='Posted', jv_id=?, jv_number=?, posted_at=datetime('now') WHERE id=?", (jv_id, jv_num, iid))
                    except Exception as e:
                        generated.append({'template_id': t['id'], 'invoice_number': num, 'due': nd, 'amount': amount, 'posted': False, 'note': str(e)})
                        nd = None
                        break
                generated.append({'template_id': t['id'], 'invoice_number': num, 'due': nd, 'amount': amount, 'posted': bool(jv_num), 'jv_number': jv_num})
                nd = _aprec_advance(nd, t.get('frequency'))
            if nd:
                conn.execute("UPDATE ar_recurring SET next_due_date=?, last_generated=?, invoices_generated=invoices_generated+? WHERE id=?",
                    (nd, as_of, guard, t['id']))
            else:
                conn.execute("UPDATE ar_recurring SET last_generated=?, invoices_generated=invoices_generated+? WHERE id=?",
                    (as_of, guard, t['id']))
        _audit(conn, session, 'GENERATE_AR_RECURRING', 'ar_recurring', only_id or 'all', '%d invoice(s) generated' % len(generated))
        conn.commit()
        return ok({'generated': generated, 'count': len(generated)})
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# WORKING CAPITAL / LIQUIDITY — a read-only roll-up that ties the subledgers
# together: cash & bank (GL), receivables (AR), payables (AP), inventory value,
# net working capital and current/quick ratios, with AR & AP aging snapshots.
# ═══════════════════════════════════════════════════════════════════════════
def api_working_capital(session):
    if not session: return err('Not authenticated')
    ar = api_ar_aging(session) if 'api_ar_aging' in globals() else {}
    ap = api_ap_aging(session) if 'api_ap_aging' in globals() else {}
    ar_out = round(float(ar.get('total_outstanding') or 0), 2) if ar.get('ok') else 0.0
    ap_out = round(float(ap.get('total_outstanding') or 0), 2) if ap.get('ok') else 0.0
    ar_buckets = ar.get('buckets') or {} if ar.get('ok') else {}
    ap_buckets = ap.get('buckets') or {} if ap.get('ok') else {}
    ar_overdue = round(ar_out - float(ar_buckets.get('current') or 0), 2)
    ap_overdue = round(ap_out - float(ap_buckets.get('current') or 0), 2)
    conn = get_db()
    try:
        try: _inv_migration(conn)
        except Exception: pass
        def sc(q, default=0.0):
            try:
                r = conn.execute(q).fetchone()
                return float(r[0]) if r and r[0] is not None else default
            except Exception:
                return default
        cash = round(sc("""SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0)
            FROM general_ledger WHERE coa_code LIKE '126%' OR coa_code LIKE '127%' OR coa_code LIKE '128%' OR coa_code LIKE '129%' OR coa_code='1001'
            OR coa_id IN (SELECT coa_id FROM bank_accounts WHERE coa_id IS NOT NULL)"""), 2)
        inv_val = round(sc("SELECT COALESCE(SUM(COALESCE(qty_on_hand,0)*COALESCE(avg_cost,0)),0) FROM inv_items"), 2)
        ca = round(cash + ar_out + inv_val, 2)
        cl = round(ap_out, 2)
        nwc = round(ca - cl, 2)
        current_ratio = round(ca / cl, 2) if cl > 0.005 else None
        quick_ratio = round((cash + ar_out) / cl, 2) if cl > 0.005 else None
        return ok({
            'cash_and_bank_ghs': cash,
            'receivables_ghs': ar_out, 'receivables_overdue_ghs': ar_overdue,
            'payables_ghs': ap_out, 'payables_overdue_ghs': ap_overdue,
            'inventory_value_ghs': inv_val,
            'current_assets_ghs': ca, 'current_liabilities_ghs': cl,
            'net_working_capital_ghs': nwc,
            'current_ratio': current_ratio, 'quick_ratio': quick_ratio,
            'ar_buckets': ar_buckets, 'ap_buckets': ap_buckets,
            'as_of': date.today().isoformat(),
        })
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# MONTH-END FLASH PACK — one-call executive summary: financial position (SFP),
# income vs expenditure for the period, working-capital roll-up and AR/AP aging,
# plus a trial-balance health check. Read-only; powers a printable one-pager.
# ═══════════════════════════════════════════════════════════════════════════
def api_flash_pack(session, period=None):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        period = (period or '').strip()
        if not period:
            r = conn.execute("SELECT period FROM general_ledger ORDER BY period DESC LIMIT 1").fetchone()
            period = (r[0] if r and r[0] else date.today().strftime('%Y-%m'))
        year = str(period)[:4]
        def sc(q, args=()):
            try:
                r = conn.execute(q, args).fetchone()
                return round(float(r[0]), 2) if r and r[0] is not None else 0.0
            except Exception:
                return 0.0
        # Statement of financial position (cumulative, all dates)
        assets = sc("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '1%'")
        liabilities = sc("SELECT COALESCE(SUM(COALESCE(credit_amount,0)-COALESCE(debit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '2%'")
        funds = sc("SELECT COALESCE(SUM(COALESCE(credit_amount,0)-COALESCE(debit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '3%'")
        # Income & expenditure — for the period and year-to-date
        inc_p = sc("SELECT COALESCE(SUM(COALESCE(credit_amount,0)-COALESCE(debit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '4%' AND period LIKE ?", (period + '%',))
        exp_p = sc("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '6%' AND period LIKE ?", (period + '%',))
        inc_y = sc("SELECT COALESCE(SUM(COALESCE(credit_amount,0)-COALESCE(debit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '4%' AND period LIKE ?", (year + '%',))
        exp_y = sc("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) FROM general_ledger WHERE coa_code LIKE '6%' AND period LIKE ?", (year + '%',))
        # Trial-balance health
        tb_dr = sc("SELECT COALESCE(SUM(COALESCE(debit_amount,0)),0) FROM general_ledger")
        tb_cr = sc("SELECT COALESCE(SUM(COALESCE(credit_amount,0)),0) FROM general_ledger")
        # Top 5 expenditure lines for the period
        try:
            top_exp = [dict(r) for r in conn.execute(
                "SELECT coa_code, account_name, SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)) AS amount "
                "FROM general_ledger WHERE coa_code LIKE '6%' AND period LIKE ? GROUP BY coa_code, account_name "
                "HAVING amount > 0 ORDER BY amount DESC LIMIT 5", (period + '%',)).fetchall()]
        except Exception:
            top_exp = []
    finally:
        conn.close()
    wc = api_working_capital(session) if 'api_working_capital' in globals() else {}
    wc = wc if wc.get('ok') else {}
    return ok({
        'period': period, 'year': year, 'as_of': date.today().isoformat(),
        'sfp': {'assets': assets, 'liabilities': liabilities, 'funds_and_reserves': funds,
                'net_assets': round(assets - liabilities, 2),
                'presentation_difference': round(assets - liabilities - funds + round(inc_y - exp_y, 2), 2)},
        'income_expenditure': {'income_period': inc_p, 'expenditure_period': exp_p, 'surplus_period': round(inc_p - exp_p, 2),
                                'income_ytd': inc_y, 'expenditure_ytd': exp_y, 'surplus_ytd': round(inc_y - exp_y, 2)},
        'trial_balance': {'total_debit': tb_dr, 'total_credit': tb_cr, 'balanced': abs(tb_dr - tb_cr) < 0.05,
                           'difference': round(tb_dr - tb_cr, 2)},
        'working_capital': {k: wc.get(k) for k in ('cash_and_bank_ghs', 'receivables_ghs', 'receivables_overdue_ghs',
                            'payables_ghs', 'payables_overdue_ghs', 'inventory_value_ghs', 'current_assets_ghs',
                            'current_liabilities_ghs', 'net_working_capital_ghs', 'current_ratio', 'quick_ratio')},
        'ar_buckets': wc.get('ar_buckets') or {}, 'ap_buckets': wc.get('ap_buckets') or {},
        'top_expenditure': top_exp,
    })


# ═══════════════════════════════════════════════════════════════════════════
# GENERIC EXPORT ENGINE — turns {title, columns, rows} into a real .xlsx
# (openpyxl), .pdf (reportlab) or .csv, returned as base64 for client download.
# One endpoint powers Excel/PDF export for statements and every report.
# ═══════════════════════════════════════════════════════════════════════════
def _exp_norm(data):
    cols = data.get('columns') or []
    norm_cols = []
    for c in cols:
        if isinstance(c, dict):
            norm_cols.append({'key': c.get('key') or c.get('label'), 'label': c.get('label') or c.get('key'),
                              'align': c.get('align') or 'left'})
        else:
            norm_cols.append({'key': c, 'label': c, 'align': 'left'})
    raw = data.get('rows') or []
    out = []
    for r in raw:
        if isinstance(r, dict):
            out.append([r.get(c['key'], '') for c in norm_cols])
        elif isinstance(r, (list, tuple)):
            out.append(list(r))
        else:
            out.append([r])
    return norm_cols, out

def api_export_file(data, session):
    if not session: return err('Not authenticated')
    fmt = (data.get('format') or 'xlsx').lower()
    title = (data.get('title') or 'Export').strip()
    subtitle = (data.get('subtitle') or '').strip()
    cols, rows = _exp_norm(data)
    base = (data.get('filename') or title or 'export')
    base = ''.join(ch for ch in base if ch.isalnum() or ch in ' -_').strip().replace(' ', '_') or 'export'
    import base64 as _b64, io as _io
    try:
        if fmt == 'csv':
            import csv as _csv
            sio = _io.StringIO(); w = _csv.writer(sio)
            w.writerow([c['label'] for c in cols])
            for r in rows: w.writerow(['' if v is None else v for v in r])
            payload = ('﻿' + sio.getvalue()).encode('utf-8')
            return ok({'filename': base + '.csv', 'mime': 'text/csv', 'b64': _b64.b64encode(payload).decode()})
        if fmt in ('xlsx', 'excel', 'xls'):
            import openpyxl as _ox
            from openpyxl.styles import Font as _F, PatternFill as _PF, Alignment as _AL
            wb = _ox.Workbook(); ws = wb.active; ws.title = (title[:28] or 'Sheet1')
            r0 = 1
            if title:
                ws.cell(row=r0, column=1, value=title).font = _F(bold=True, size=14); r0 += 1
            if subtitle:
                ws.cell(row=r0, column=1, value=subtitle).font = _F(size=10, italic=True); r0 += 1
            if title or subtitle: r0 += 1
            hdr_fill = _PF(start_color='0F766E', end_color='0F766E', fill_type='solid')
            for j, c in enumerate(cols, 1):
                cell = ws.cell(row=r0, column=j, value=c['label'])
                cell.font = _F(bold=True, color='FFFFFF'); cell.fill = hdr_fill
                cell.alignment = _AL(horizontal=('right' if c['align'] == 'right' else 'left'))
            for i, r in enumerate(rows, 1):
                for j, v in enumerate(r, 1):
                    cell = ws.cell(row=r0 + i, column=j, value=(v if v is not None else ''))
                    if cols[j-1]['align'] == 'right' and isinstance(v, (int, float)):
                        cell.alignment = _AL(horizontal='right')
            # column widths
            for j, c in enumerate(cols, 1):
                width = max(len(str(c['label'])), *( [len(str(r[j-1])) for r in rows] or [0])) + 2
                ws.column_dimensions[_ox.utils.get_column_letter(j)].width = min(max(width, 10), 48)
            bio = _io.BytesIO(); wb.save(bio)
            return ok({'filename': base + '.xlsx', 'mime': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', 'b64': _b64.b64encode(bio.getvalue()).decode()})
        if fmt == 'pdf':
            from reportlab.lib import colors as _col
            from reportlab.lib.pagesizes import A4, landscape as _ls
            from reportlab.lib.units import mm as _mm
            from reportlab.platypus import SimpleDocTemplate as _SDT, Table as _T, TableStyle as _TS, Paragraph as _P, Spacer as _S
            from reportlab.lib.styles import getSampleStyleSheet as _styles
            bio = _io.BytesIO()
            land = len(cols) > 5
            doc = _SDT(bio, pagesize=(_ls(A4) if land else A4), leftMargin=14*_mm, rightMargin=14*_mm, topMargin=14*_mm, bottomMargin=14*_mm)
            sty = _styles(); el = []
            el.append(_P('<b>%s</b>' % _exp_esc(title), sty['Title']))
            if subtitle: el.append(_P(_exp_esc(subtitle), sty['Normal']))
            el.append(_S(1, 6*_mm))
            tdata = [[c['label'] for c in cols]] + [['' if v is None else str(v) for v in r] for r in rows]
            tbl = _T(tdata, repeatRows=1)
            ts = [('BACKGROUND', (0, 0), (-1, 0), _col.HexColor('#0F766E')),
                  ('TEXTCOLOR', (0, 0), (-1, 0), _col.white),
                  ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
                  ('FONTSIZE', (0, 0), (-1, -1), 8),
                  ('ROWBACKGROUNDS', (0, 1), (-1, -1), [_col.white, _col.HexColor('#F1F5F9')]),
                  ('GRID', (0, 0), (-1, -1), 0.4, _col.HexColor('#E2E8F0')),
                  ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
                  ('TOPPADDING', (0, 0), (-1, -1), 3), ('BOTTOMPADDING', (0, 0), (-1, -1), 3)]
            for j, c in enumerate(cols):
                if c['align'] == 'right': ts.append(('ALIGN', (j, 0), (j, -1), 'RIGHT'))
            tbl.setStyle(_TS(ts)); el.append(tbl)
            el.append(_S(1, 6*_mm))
            el.append(_P('<font size=7 color="#94a3b8">Generated %s</font>' % date.today().isoformat(), sty['Normal']))
            doc.build(el)
            return ok({'filename': base + '.pdf', 'mime': 'application/pdf', 'b64': _b64.b64encode(bio.getvalue()).decode()})
        return err('Unsupported format: %s' % fmt)
    except Exception as e:
        return err('Export failed: %s' % e)

def _exp_esc(s):
    return str(s or '').replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')


# ═══════════════════════════════════════════════════════════════════════════
# BATCH SETTLEMENT RUNS — pay many AP bills (one PV) or receipt many AR invoices
# (one RV) in a single balanced posting, with a per-document settlement record.
# ═══════════════════════════════════════════════════════════════════════════
def api_ap_batch_pay(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn)
        items = data.get('items') or ([{'bill_id': b} for b in (data.get('bill_ids') or [])])
        if not items: return err('Select at least one bill to pay')
        bank_id = data.get('bank_account_id')
        if not bank_id: return err('Select the bank account to pay from')
        bank_coa = _ap_bank_coa(conn, bank_id); ap_coa = _ap_control_coa(conn)
        if not bank_coa or not ap_coa: return err('Bank or payables control account could not be resolved')
        pdate = data.get('payment_date') or date.today().isoformat()
        ref = (data.get('reference') or '').strip() or ('Batch payment ' + pdate)
        plans = []; total = 0.0
        for it in items:
            bid = it.get('bill_id') or it.get('id')
            row = conn.execute("SELECT * FROM ap_bills WHERE id=?", (bid,)).fetchone()
            if not row: return err('Bill not found: %s' % bid)
            bill = dict(row)
            if bill['status'] not in ('Posted', 'Part-Paid'): continue
            bal = round(float(bill['total_ghs'] or 0) - float(bill['amount_paid'] or 0) - float(bill.get('debited_ghs') or 0), 2)
            amt = round(float(it['amount_ghs']) if it.get('amount_ghs') is not None else bal, 2)
            if amt <= 0: continue
            if amt > bal + 0.01: return err('Payment GHS %.2f exceeds balance GHS %.2f on %s' % (amt, bal, bill['bill_number']))
            plans.append((bill, amt)); total += amt
        total = round(total, 2)
        if not plans: return err('No payable bills selected (only posted/part-paid bills can be paid)')
        lines = [{'coa_id': ap_coa, 'debit_amount': amt, 'credit_amount': 0, 'description': 'Payment ' + bill['bill_number'], 'project_id': bill['project_id']} for bill, amt in plans]
        lines.append({'coa_id': bank_coa, 'debit_amount': 0, 'credit_amount': total, 'description': ref, 'project_id': None, 'bank_account_id': bank_id})
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'PV', pdate, 'Batch supplier payment (%d bills)' % len(plans), ref, None, bank_id, 'ap_batch', None, lines)
        except Exception as e:
            return err('Could not post batch payment: %s' % e)
        results = []
        for bill, amt in plans:
            pid = str(uuid.uuid4()); pnum = _ap_next(conn, 'ap_payments', 'APP')
            conn.execute("INSERT INTO ap_payments(id,payment_number,bill_id,vendor_id,payment_date,amount_ghs,bank_account_id,payment_method,reference,jv_id,jv_number,notes,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                (pid, pnum, bill['id'], bill['vendor_id'], pdate, amt, bank_id, 'Batch', ref, jv_id, jv_num, 'batch', session.get('username', 'system')))
            new_paid = round(float(bill['amount_paid'] or 0) + amt, 2)
            new_status = 'Paid' if new_paid >= float(bill['total_ghs'] or 0) - 0.01 else 'Part-Paid'
            conn.execute("UPDATE ap_bills SET amount_paid=?, status=? WHERE id=?", (new_paid, new_status, bill['id']))
            results.append({'bill_number': bill['bill_number'], 'amount': amt, 'status': new_status})
        _audit(conn, session, 'AP_BATCH_PAY', 'ap_bills', 'batch', '%d bills total %.2f (%s)' % (len(plans), total, jv_num))
        conn.commit()
        return ok({'count': len(plans), 'total': total, 'jv_number': jv_num, 'results': results, 'message': 'Paid %d bill(s) as %s, total GHS %.2f' % (len(plans), jv_num, total)})
    finally:
        conn.close()

def api_ar_batch_receipt(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn)
        items = data.get('items') or ([{'invoice_id': i} for i in (data.get('invoice_ids') or [])])
        if not items: return err('Select at least one invoice to receipt')
        bank_id = data.get('bank_account_id')
        if not bank_id: return err('Select the bank account receiving payment')
        bank_coa = _ar_bank_coa(conn, bank_id); ar_coa = _ar_control_coa(conn)
        if not bank_coa or not ar_coa: return err('Bank or receivables control account could not be resolved')
        rdate = data.get('receipt_date') or date.today().isoformat()
        ref = (data.get('reference') or '').strip() or ('Batch receipt ' + rdate)
        plans = []; total = 0.0
        for it in items:
            iid = it.get('invoice_id') or it.get('id')
            row = conn.execute("SELECT * FROM ar_invoices WHERE id=?", (iid,)).fetchone()
            if not row: return err('Invoice not found: %s' % iid)
            inv = dict(row)
            if inv['status'] not in ('Posted', 'Part-Paid'): continue
            bal = round(float(inv['total_ghs'] or 0) - float(inv['amount_received'] or 0) - float(inv.get('credited_ghs') or 0), 2)
            amt = round(float(it['amount_ghs']) if it.get('amount_ghs') is not None else bal, 2)
            if amt <= 0: continue
            if amt > bal + 0.01: return err('Receipt GHS %.2f exceeds balance GHS %.2f on %s' % (amt, bal, inv['invoice_number']))
            plans.append((inv, amt)); total += amt
        total = round(total, 2)
        if not plans: return err('No receivable invoices selected (only posted/part-paid invoices can be receipted)')
        lines = [{'coa_id': bank_coa, 'debit_amount': total, 'credit_amount': 0, 'description': ref, 'project_id': None, 'bank_account_id': bank_id}]
        for inv, amt in plans:
            lines.append({'coa_id': ar_coa, 'debit_amount': 0, 'credit_amount': amt, 'description': 'Receipt ' + inv['invoice_number'], 'project_id': inv['project_id']})
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'RV', rdate, 'Batch customer receipt (%d invoices)' % len(plans), ref, None, bank_id, 'ar_batch', None, lines)
        except Exception as e:
            return err('Could not post batch receipt: %s' % e)
        results = []
        for inv, amt in plans:
            rid = str(uuid.uuid4()); rnum = _ar_next(conn, 'ar_receipts', 'ARR')
            conn.execute("INSERT INTO ar_receipts(id,receipt_number,invoice_id,customer_id,receipt_date,amount_ghs,bank_account_id,payment_method,reference,jv_id,jv_number,notes,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                (rid, rnum, inv['id'], inv['customer_id'], rdate, amt, bank_id, 'Batch', ref, jv_id, jv_num, 'batch', session.get('username', 'system')))
            new_recv = round(float(inv['amount_received'] or 0) + amt, 2)
            new_status = 'Paid' if new_recv >= float(inv['total_ghs'] or 0) - 0.01 else 'Part-Paid'
            conn.execute("UPDATE ar_invoices SET amount_received=?, status=? WHERE id=?", (new_recv, new_status, inv['id']))
            results.append({'invoice_number': inv['invoice_number'], 'amount': amt, 'status': new_status})
        _audit(conn, session, 'AR_BATCH_RECEIPT', 'ar_invoices', 'batch', '%d invoices total %.2f (%s)' % (len(plans), total, jv_num))
        conn.commit()
        return ok({'count': len(plans), 'total': total, 'jv_number': jv_num, 'results': results, 'message': 'Receipted %d invoice(s) as %s, total GHS %.2f' % (len(plans), jv_num, total)})
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# BULK INVOICE / BILL IMPORT — load a list of debtor invoices (AR) or creditor
# bills (AP) from Excel (.xlsx), Word (.docx, first table) or CSV. Customers /
# vendors are matched by name (created if new); COA resolved by code or name.
# Rows become Draft documents, optionally auto-posted.
# ═══════════════════════════════════════════════════════════════════════════
def _imp_num(v):
    if v is None: return 0.0
    s = str(v).replace(',', '').replace('GHS', '').replace('GH₵', '').replace('₵', '').strip()
    try: return round(float(s), 2)
    except Exception: return 0.0

def _imp_date(v):
    if not v: return None
    s = str(v).strip()
    import re as _re
    if _re.match(r'^\d{4}-\d{2}-\d{2}', s): return s[:10]
    m = _re.match(r'^(\d{1,2})[/\-.](\d{1,2})[/\-.](\d{2,4})$', s)
    if m:
        d, mo, y = m.groups(); y = ('20' + y) if len(y) == 2 else y
        try: return '%04d-%02d-%02d' % (int(y), int(mo), int(d))
        except Exception: return None
    return None

def _cf_docx_rows(b64):
    import base64 as _b64, io as _io
    raw = _b64.b64decode(b64.split(',')[-1])
    try:
        from docx import Document
    except Exception:
        raise ValueError('Word parsing needs python-docx on the server. Save the list as Excel or CSV instead.')
    doc = Document(_io.BytesIO(raw))
    if not doc.tables:
        raise ValueError('No table found in the Word document. Put the invoice list in a table (first row = column headers), or upload Excel/CSV.')
    t = doc.tables[0]
    if len(t.rows) < 2:
        raise ValueError('The Word table needs a header row plus at least one data row.')
    headers = [c.text.strip() for c in t.rows[0].cells]
    out = []
    for r in t.rows[1:]:
        cells = [c.text.strip() for c in r.cells]
        if not any(cells): continue
        out.append({(headers[i] if i < len(headers) and headers[i] else ('col%d' % i)): (cells[i] if i < len(cells) else '') for i in range(len(cells))})
    return out

def _import_rows(data):
    fn = (data.get('filename') or '').lower()
    b64 = data.get('file_b64') or data.get('xlsx_b64')
    if b64 and (fn.endswith('.docx') or fn.endswith('.doc')):
        return _cf_docx_rows(b64)
    return _cf_ingest_rows(data)

def _imp_coa(conn, code, name):
    if code:
        r = conn.execute("SELECT id FROM chart_of_accounts WHERE code=?", (str(code).strip(),)).fetchone()
        if r: return r['id']
    if name:
        nm = str(name).strip().lower()
        r = conn.execute("SELECT id FROM chart_of_accounts WHERE LOWER(account_name)=?", (nm,)).fetchone()
        if r: return r['id']
        r = conn.execute("SELECT id FROM chart_of_accounts WHERE LOWER(account_name) LIKE ?", ('%' + nm + '%',)).fetchone()
        if r: return r['id']
    return None

def api_ar_import_invoices(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn)
        try: rows = _import_rows(data)
        except Exception as e: return err(str(e))
        if not rows: return err('No rows found in the uploaded file')
        dft = conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '4%' ORDER BY code LIMIT 1").fetchone()
        dft = dft['id'] if dft else None
        created = 0; errors = []; new_ids = []
        for i, r0 in enumerate(rows, 1):
            try:
                r = _cf_lc_row(r0)
                cname = (r.get('customer') or r.get('customer_name') or r.get('debtor') or r.get('client') or r.get('name') or '')
                cname = str(cname).strip()
                if not cname: errors.append('Row %d: missing customer name' % i); continue
                amt = _imp_num(r.get('amount') or r.get('amount_ghs') or r.get('total') or r.get('total_ghs') or r.get('value'))
                if amt <= 0: errors.append('Row %d (%s): missing/invalid amount' % (i, cname)); continue
                inc = _imp_coa(conn, r.get('income_code') or r.get('account_code') or r.get('income_account_code') or r.get('coa_code'),
                               r.get('income_account') or r.get('account') or r.get('account_name')) or dft
                if not inc: errors.append('Row %d: no income account resolved' % i); continue
                cust = conn.execute("SELECT id FROM ar_customers WHERE LOWER(customer_name)=?", (cname.lower(),)).fetchone()
                if cust: cid = cust['id']
                else:
                    cid = str(uuid.uuid4()); conn.execute("INSERT INTO ar_customers(id,customer_code,customer_name,created_by) VALUES(?,?,?,?)",
                        (cid, _ar_next(conn, 'ar_customers', 'CUST'), cname, session.get('username', 'system')))
                iid = str(uuid.uuid4()); num = (str(r.get('invoice_no') or r.get('invoice_number') or '')).strip() or _ar_next(conn, 'ar_invoices', 'INV')
                idate = _imp_date(r.get('invoice_date') or r.get('date')) or date.today().isoformat()
                ddate = _imp_date(r.get('due_date') or r.get('due')) or idate
                desc = str(r.get('description') or r.get('narration') or r.get('details') or '').strip()
                conn.execute("INSERT INTO ar_invoices(id,invoice_number,customer_id,invoice_date,due_date,income_coa_id,description,amount_ghs,tax_ghs,total_ghs,amount_received,status,created_by) VALUES(?,?,?,?,?,?,?,?,0,?,0,'Draft',?)",
                    (iid, num, cid, idate, ddate, inc, desc, amt, amt, session.get('username', 'system')))
                conn.execute("INSERT INTO ar_invoice_lines(id,invoice_id,line_number,description,income_coa_id,amount_ghs) VALUES(?,?,1,?,?,?)",
                    (str(uuid.uuid4()), iid, desc or num, inc, amt))
                created += 1; new_ids.append(iid)
            except Exception as e:
                errors.append('Row %d: %s' % (i, e))
        conn.commit()
        posted = 0
        if data.get('post'):
            for iid in new_ids:
                try:
                    res = api_ar_post_invoice({'id': iid}, session)
                    if res.get('ok'): posted += 1
                    else: errors.append('Post %s: %s' % (iid[:8], res.get('error')))
                except Exception as e: errors.append('Post error: %s' % e)
        try:
            c2 = get_db(); _audit(c2, session, 'IMPORT_AR_INVOICES', 'ar_invoices', 'bulk', '%d created, %d posted' % (created, posted)); c2.commit(); c2.close()
        except Exception: pass
        return ok({'created': created, 'posted': posted, 'errors': errors[:40], 'error_count': len(errors),
                   'message': 'Imported %d invoice(s)%s' % (created, (', %d posted' % posted) if data.get('post') else ' as drafts')})
    except Exception as e:
        return err('Import failed: %s' % e)
    finally:
        conn.close()

def api_ap_import_bills(data, session):
    if not session: return err('Not authenticated')
