# ═══════════════════════════════════════════════════════════════════════════
# EMAIL STATEMENT — send an AR/AP account statement (PDF attached) to the
# customer/vendor via the configured SMTP. User-initiated; if SMTP isn't set up
# it is queued with a clear message (nothing leaves the server).
# ═══════════════════════════════════════════════════════════════════════════
def api_email_statement(data, session):
    if not session: return err('Not authenticated')
    typ = (data.get('type') or 'ar').lower()
    rid = data.get('id') or data.get('customer_id') or data.get('vendor_id')
    if not rid: return err('Missing customer/vendor id')
    if typ == 'ap':
        st = api_ap_statement(session, rid); who = st.get('vendor') or {}; name = who.get('vendor_name', ''); label = 'Payables'
    else:
        st = api_ar_statement(session, rid); who = st.get('customer') or {}; name = who.get('customer_name', ''); label = 'Receivables'
    if not st.get('ok'): return err(st.get('error', 'Could not build statement'))
    email = (data.get('to') or who.get('email') or '').strip()
    if not email or '@' not in email:
        return err('No valid email on file for %s. Add an email to the account, or provide one.' % (name or 'this account'))
    ev = st.get('events') or []; bal = float(st.get('balance') or 0)
    pdf_payload = {'title': 'Statement — ' + (name or ''), 'subtitle': label + ' account statement', 'format': 'pdf',
        'filename': 'Statement_' + (name or 'account'),
        'columns': [{'key': 'date', 'label': 'Date'}, {'key': 'ref', 'label': 'Ref'}, {'key': 'type', 'label': 'Type'},
                    {'key': 'debit', 'label': 'Debit', 'align': 'right'}, {'key': 'credit', 'label': 'Credit', 'align': 'right'},
                    {'key': 'balance', 'label': 'Balance', 'align': 'right'}],
        'rows': [{'date': e.get('date'), 'ref': e.get('ref'), 'type': e.get('type'),
                  'debit': ('%.2f' % e['debit'] if e.get('debit') else ''), 'credit': ('%.2f' % e['credit'] if e.get('credit') else ''),
                  'balance': '%.2f' % (e.get('balance') or 0)} for e in ev]}
    import base64 as _b64
    pres = api_export_file(pdf_payload, session)
    pdf_bytes = _b64.b64decode(pres['b64']) if pres.get('ok') and pres.get('b64') else None
    appname = globals().get('V42_APP_NAME') or globals().get('APP_NAME') or 'Finance Office'
    subject = '%s — Account Statement (balance GHS %.2f)' % (appname, bal)
    body = ('Dear %s,\n\nPlease find attached your account statement as at %s.\n'
            'Outstanding balance: GHS %.2f.\n\nKind regards,\n%s'
            % (name or 'Sir/Madam', date.today().isoformat(), bal, appname))
    conn = get_db()
    try:
        try: _v42_migration()
        except Exception: pass
        eid = _v42_queue_email(conn, email, subject, body)
        host = os.environ.get('SMTP_HOST', '').strip()
        if not host:
            conn.execute("UPDATE email_outbox SET status='Queued - SMTP not configured', error=? WHERE id=?",
                ('Set SMTP_HOST, SMTP_PORT, SMTP_USER, SMTP_PASSWORD and SMTP_FROM to enable sending.', eid))
            _audit(conn, session, 'EMAIL_STATEMENT', 'email_outbox', eid, '%s statement queued for %s (SMTP off)' % (label, email))
            conn.commit()
            return ok({'queued': True, 'sent': False, 'to': email,
                       'message': 'Statement for %s queued to %s. Ask an admin to configure SMTP (SMTP_HOST/PORT/USER/PASSWORD/FROM) to send automatically.' % (name or 'account', email)})
        port = int(os.environ.get('SMTP_PORT', '587') or 587); usr = os.environ.get('SMTP_USER', '').strip(); pwd = os.environ.get('SMTP_PASSWORD', '').strip()
        sender = os.environ.get('SMTP_FROM', '').strip() or usr or ('noreply@local')
        try:
            msg = _V42EmailMessage(); msg['From'] = sender; msg['To'] = email; msg['Subject'] = subject; msg.set_content(body)
            if pdf_bytes:
                msg.add_attachment(pdf_bytes, maintype='application', subtype='pdf', filename='Statement_%s.pdf' % (name or 'account').replace(' ', '_'))
            with _v42_smtplib.SMTP(host, port, timeout=20) as smtp:
                smtp.starttls()
                if usr: smtp.login(usr, pwd)
                smtp.send_message(msg)
            conn.execute("UPDATE email_outbox SET status='Sent', sent_at=datetime('now'), error=NULL WHERE id=?", (eid,))
            _audit(conn, session, 'EMAIL_STATEMENT', 'email_outbox', eid, '%s statement sent to %s' % (label, email))
            conn.commit()
            return ok({'sent': True, 'to': email, 'message': 'Statement emailed to %s' % email})
        except Exception as e:
            conn.execute("UPDATE email_outbox SET status='Failed', error=? WHERE id=?", (str(e)[:400], eid)); conn.commit()
            return err('Email send failed: %s' % e)
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# RECURRING JOURNALS — standing multi-line JVs (depreciation, accruals,
# prepayments) generated on a schedule and posted via _create_posted_journal.
# ═══════════════════════════════════════════════════════════════════════════
def _recjv_migration(conn):
    conn.execute("""CREATE TABLE IF NOT EXISTS rec_journals(
        id TEXT PRIMARY KEY, name TEXT, description TEXT, frequency TEXT DEFAULT 'Monthly',
        start_date TEXT, end_date TEXT, next_due_date TEXT, project_id TEXT,
        active INTEGER DEFAULT 1, jvs_generated INTEGER DEFAULT 0,
        created_by TEXT, created_at TEXT DEFAULT(datetime('now')))""")
    conn.execute("""CREATE TABLE IF NOT EXISTS rec_journal_lines(
        id TEXT PRIMARY KEY, rec_id TEXT, line_no INTEGER, coa_id TEXT,
        debit REAL DEFAULT 0, credit REAL DEFAULT 0, description TEXT)""")
    conn.commit()

def api_rec_journals(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _recjv_migration(conn)
        rows = [dict(r) for r in conn.execute("""SELECT t.*, p.project_code,
            (SELECT COALESCE(SUM(debit),0) FROM rec_journal_lines WHERE rec_id=t.id) AS total_debit,
            (SELECT COUNT(*) FROM rec_journal_lines WHERE rec_id=t.id) AS line_count
            FROM rec_journals t LEFT JOIN projects p ON p.id=t.project_id
            ORDER BY t.active DESC, t.next_due_date""").fetchall()]
        return ok({'templates': rows})
    finally:
        conn.close()

def api_rec_journal_lines(session, rec_id=None):
    if not session: return err('Not authenticated')
    if not rec_id: return err('rec_id required')
    conn = get_db()
    try:
        _recjv_migration(conn)
        rows = [dict(r) for r in conn.execute("SELECT l.*, c.code AS coa_code, c.account_name FROM rec_journal_lines l LEFT JOIN chart_of_accounts c ON c.id=l.coa_id WHERE l.rec_id=? ORDER BY l.line_no", (rec_id,)).fetchall()]
        return ok({'lines': rows})
    finally:
        conn.close()

def api_save_rec_journal(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _recjv_migration(conn)
        name = (data.get('name') or '').strip()
        if not name: return err('Template name is required')
        raw = data.get('lines') or []
        norm = []
        for ln in raw:
            d = round(float(ln.get('debit') or 0), 2); c = round(float(ln.get('credit') or 0), 2)
            if not ln.get('coa_id') or (d == 0 and c == 0): continue
            norm.append({'coa_id': ln.get('coa_id'), 'debit': d, 'credit': c, 'description': (ln.get('description') or '')})
        if len(norm) < 2: return err('Add at least two lines')
        tot_d = round(sum(l['debit'] for l in norm), 2); tot_c = round(sum(l['credit'] for l in norm), 2)
        if abs(tot_d - tot_c) > 0.01: return err('Journal not balanced: debits GHS %.2f ≠ credits GHS %.2f' % (tot_d, tot_c))
        freq = data.get('frequency') or 'Monthly'
        start = data.get('start_date') or date.today().isoformat()
        tid = data.get('id') or str(uuid.uuid4())
        ex = conn.execute("SELECT next_due_date FROM rec_journals WHERE id=?", (tid,)).fetchone()
        nd = data.get('next_due_date') or (ex['next_due_date'] if ex else None) or start
        active = 0 if (data.get('active') in (0, '0', False, 'false')) else 1
        if ex:
            conn.execute("UPDATE rec_journals SET name=?,description=?,frequency=?,start_date=?,end_date=?,next_due_date=?,project_id=?,active=? WHERE id=?",
                (name, data.get('description', ''), freq, start, data.get('end_date') or None, nd, data.get('project_id') or None, active, tid))
        else:
            conn.execute("INSERT INTO rec_journals(id,name,description,frequency,start_date,end_date,next_due_date,project_id,active,created_by) VALUES(?,?,?,?,?,?,?,?,?,?)",
                (tid, name, data.get('description', ''), freq, start, data.get('end_date') or None, nd, data.get('project_id') or None, active, session.get('username', 'system')))
        conn.execute("DELETE FROM rec_journal_lines WHERE rec_id=?", (tid,))
        for i, l in enumerate(norm, 1):
            conn.execute("INSERT INTO rec_journal_lines(id,rec_id,line_no,coa_id,debit,credit,description) VALUES(?,?,?,?,?,?,?)",
                (str(uuid.uuid4()), tid, i, l['coa_id'], l['debit'], l['credit'], l['description']))
        _audit(conn, session, 'SAVE_REC_JOURNAL', 'rec_journals', tid, name)
        conn.commit()
        return ok({'id': tid})
    finally:
        conn.close()

def api_rec_journal_toggle(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _recjv_migration(conn)
        tid = data.get('id'); t = conn.execute("SELECT active FROM rec_journals WHERE id=?", (tid,)).fetchone()
        if not t: return err('Template not found')
        new = 0 if t['active'] else 1
        conn.execute("UPDATE rec_journals SET active=? WHERE id=?", (new, tid))
        conn.commit(); return ok({'id': tid, 'active': new})
    finally:
        conn.close()

def api_rec_journal_generate(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _recjv_migration(conn)
        as_of = data.get('as_of') or date.today().isoformat()
        only = data.get('id')
        q = "SELECT * FROM rec_journals WHERE active=1 AND next_due_date IS NOT NULL AND next_due_date<=?"
        params = [as_of]
        if only: q += " AND id=?"; params.append(only)
        templates = [dict(r) for r in conn.execute(q, params).fetchall()]
        generated = []
        for t in templates:
            lines_t = [dict(r) for r in conn.execute("SELECT * FROM rec_journal_lines WHERE rec_id=? ORDER BY line_no", (t['id'],)).fetchall()]
            if not lines_t: continue
            nd = t['next_due_date']; guard = 0
            while nd and str(nd)[:10] <= str(as_of)[:10] and guard < 60:
                if t.get('end_date') and str(nd)[:10] > str(t['end_date'])[:10]: break
                guard += 1
                lines = [{'coa_id': l['coa_id'], 'debit_amount': round(float(l['debit'] or 0), 2), 'credit_amount': round(float(l['credit'] or 0), 2), 'description': l.get('description') or t['name'], 'project_id': t.get('project_id')} for l in lines_t]
                try:
                    jv_id, jv_num = _create_posted_journal(conn, session, 'JV', nd, (t['name'] or 'Recurring journal') + ' (' + str(nd)[:10] + ')', 'REC', t.get('project_id'), None, 'rec_journal', t['id'], lines)
                    generated.append({'template_id': t['id'], 'jv_number': jv_num, 'due': nd})
                except Exception as e:
                    generated.append({'template_id': t['id'], 'due': nd, 'error': str(e)}); nd = None; break
                nd = _aprec_advance(nd, t.get('frequency'))
            if nd:
                conn.execute("UPDATE rec_journals SET next_due_date=?, jvs_generated=jvs_generated+? WHERE id=?", (nd, guard, t['id']))
            else:
                conn.execute("UPDATE rec_journals SET jvs_generated=jvs_generated+? WHERE id=?", (guard, t['id']))
        _audit(conn, session, 'GENERATE_REC_JOURNAL', 'rec_journals', only or 'all', '%d JV(s)' % len([g for g in generated if g.get('jv_number')]))
        conn.commit()
        posted = [g for g in generated if g.get('jv_number')]
        return ok({'generated': generated, 'count': len(posted), 'message': 'Posted %d journal(s)' % len(posted) if posted else 'No journals due'})
    finally:
        conn.close()

# ═══════════════════════════════════════════════════════════════════════════
# STATUTORY TAX PACK — WHT / VAT-withholding / PAYE / SSNIT / UCF schedules from
# the GL for a period: accrued (credit), remitted (debit), outstanding balance.
# ═══════════════════════════════════════════════════════════════════════════
def api_tax_schedules(session, period=None):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        period = (period or '').strip()
        if not period:
            r = conn.execute("SELECT period FROM general_ledger ORDER BY period DESC LIMIT 1").fetchone()
            period = (r[0] if r and r[0] else date.today().strftime('%Y-%m'))
        taxes = [
            {'key': 'wht', 'label': 'Withholding Tax (GRA)', 'codes': ['21100014']},
            {'key': 'whvat', 'label': 'VAT Withholding', 'codes': ['21100024']},
            {'key': 'paye', 'label': 'PAYE', 'codes': ['21100017']},
            {'key': 'ssnit', 'label': 'SSNIT / Social Security', 'codes': ['21100015']},
            {'key': 'ucf', 'label': 'UCC Common Fund', 'codes': ['21100027']},
            {'key': 'vat', 'label': 'VAT Returns', 'codes': ['21100022']},
        ]
        def sc(q, args=()):
            try:
                r = conn.execute(q, args).fetchone(); return round(float(r[0]), 2) if r and r[0] is not None else 0.0
            except Exception: return 0.0
        summary = []; detail = {}
        for t in taxes:
            codes = t['codes']
            inlist = "(" + ",".join("'%s'" % c for c in codes) + ")"
            opening = sc("SELECT COALESCE(SUM(COALESCE(credit_amount,0)-COALESCE(debit_amount,0)),0) FROM general_ledger WHERE coa_code IN %s AND period < ?" % inlist, (period,))
            accrued = sc("SELECT COALESCE(SUM(COALESCE(credit_amount,0)),0) FROM general_ledger WHERE coa_code IN %s AND period LIKE ?" % inlist, (period + '%',))
            remitted = sc("SELECT COALESCE(SUM(COALESCE(gl.debit_amount,0)),0) FROM general_ledger gl WHERE gl.coa_code IN " + inlist + " AND gl.period LIKE ? AND COALESCE(gl.debit_amount,0)>0 AND EXISTS(SELECT 1 FROM general_ledger g2 WHERE g2.jv_id=gl.jv_id AND COALESCE(g2.credit_amount,0)>0 AND (g2.coa_code LIKE '126%' OR g2.coa_code LIKE '127%' OR g2.coa_code LIKE '128%' OR g2.coa_code LIKE '129%' OR g2.coa_code='1001'))", (period + '%',))
            adjustments = sc("SELECT COALESCE(SUM(COALESCE(gl.debit_amount,0)),0) FROM general_ledger gl WHERE gl.coa_code IN " + inlist + " AND gl.period LIKE ? AND COALESCE(gl.debit_amount,0)>0 AND NOT EXISTS(SELECT 1 FROM general_ledger g2 WHERE g2.jv_id=gl.jv_id AND COALESCE(g2.credit_amount,0)>0 AND (g2.coa_code LIKE '126%' OR g2.coa_code LIKE '127%' OR g2.coa_code LIKE '128%' OR g2.coa_code LIKE '129%' OR g2.coa_code='1001'))", (period + '%',))
            # Remittance reversals: credits to the liability whose journal DEBITS a bank account
            # (cash came back / a settlement was reversed). Net them out of accrued AND remitted so
            # "Remitted" reflects net cash actually paid, while Outstanding still ties to the GL.
            _revq = " AND COALESCE(gl.credit_amount,0)>0 AND EXISTS(SELECT 1 FROM general_ledger g2 WHERE g2.jv_id=gl.jv_id AND COALESCE(g2.debit_amount,0)>0 AND (g2.coa_code LIKE '126%' OR g2.coa_code LIKE '127%' OR g2.coa_code LIKE '128%' OR g2.coa_code LIKE '129%' OR g2.coa_code='1001'))"
            remit_reversal = sc("SELECT COALESCE(SUM(COALESCE(gl.credit_amount,0)),0) FROM general_ledger gl WHERE gl.coa_code IN " + inlist + " AND gl.period LIKE ?" + _revq, (period + '%',))
            remit_reversal_td = sc("SELECT COALESCE(SUM(COALESCE(gl.credit_amount,0)),0) FROM general_ledger gl WHERE gl.coa_code IN " + inlist + _revq)
            accrued = round(accrued - remit_reversal, 2)
            remitted = round(remitted - remit_reversal, 2)
            outstanding = round(opening + accrued - remitted - adjustments, 2)
            remitted_to_date = sc("SELECT COALESCE(SUM(COALESCE(gl.debit_amount,0)),0) FROM general_ledger gl WHERE gl.coa_code IN " + inlist + " AND COALESCE(gl.debit_amount,0)>0 AND EXISTS(SELECT 1 FROM general_ledger g2 WHERE g2.jv_id=gl.jv_id AND COALESCE(g2.credit_amount,0)>0 AND (g2.coa_code LIKE '126%' OR g2.coa_code LIKE '127%' OR g2.coa_code LIKE '128%' OR g2.coa_code LIKE '129%' OR g2.coa_code='1001'))")
            remitted_to_date = round(remitted_to_date - remit_reversal_td, 2)
            rows = []
            try:
                _bankcr = "EXISTS(SELECT 1 FROM general_ledger g2 WHERE g2.jv_id=gl.jv_id AND COALESCE(g2.credit_amount,0)>0 AND (g2.coa_code LIKE '126%' OR g2.coa_code LIKE '127%' OR g2.coa_code LIKE '128%' OR g2.coa_code LIKE '129%' OR g2.coa_code='1001'))"
                _bankdr = "EXISTS(SELECT 1 FROM general_ledger g2 WHERE g2.jv_id=gl.jv_id AND COALESCE(g2.debit_amount,0)>0 AND (g2.coa_code LIKE '126%' OR g2.coa_code LIKE '127%' OR g2.coa_code LIKE '128%' OR g2.coa_code LIKE '129%' OR g2.coa_code='1001'))"
                rows = [dict(r) for r in conn.execute(
                    "SELECT ledger_date, jv_number, description, "
                    "CASE WHEN COALESCE(credit_amount,0)>0 AND NOT " + _bankdr + " THEN COALESCE(credit_amount,0) ELSE 0 END AS accrued, "
                    "CASE WHEN COALESCE(debit_amount,0)>0 AND " + _bankcr + " THEN COALESCE(debit_amount,0) ELSE 0 END AS remitted, "
                    "CASE WHEN (COALESCE(debit_amount,0)>0 AND NOT " + _bankcr + ") THEN COALESCE(debit_amount,0) WHEN (COALESCE(credit_amount,0)>0 AND " + _bankdr + ") THEN COALESCE(credit_amount,0) ELSE 0 END AS reversal "
                    "FROM general_ledger gl WHERE gl.coa_code IN %s AND gl.period LIKE ? ORDER BY ledger_date" % inlist, (period + '%',)).fetchall()]
            except Exception as _se:
                import sys as _sx; print('tax_schedules lines query warning: %s' % _se, file=_sx.stderr); rows = []
            summary.append({'key': t['key'], 'label': t['label'], 'code': codes[0], 'opening': opening, 'accrued': accrued, 'remitted': remitted, 'remitted_to_date': remitted_to_date, 'adjustments': adjustments, 'outstanding': outstanding, 'lines': len(rows)})
            detail[t['key']] = rows
        return ok({'period': period, 'summary': summary, 'detail': detail,
                   'total_outstanding': round(sum(s['outstanding'] for s in summary), 2),
                   'total_accrued': round(sum(s['accrued'] for s in summary), 2)})
    finally:
        conn.close()

# ═══════════════════════════════════════════════════════════════════════════
# DUNNING — overdue receivables reminders. Preview groups overdue invoices by
# customer; run emails each customer their statement via the SMTP/outbox system.
# ═══════════════════════════════════════════════════════════════════════════
def api_dunning_preview(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ar_migration(conn)
        import datetime as _d; today = _d.date.today()
        rows = [dict(r) for r in conn.execute("""
            SELECT c.id AS customer_id, c.customer_name, c.email,
              SUM(i.total_ghs - i.amount_received - COALESCE(i.credited_ghs,0)) AS overdue,
              COUNT(*) AS invoices, MIN(i.due_date) AS oldest_due
            FROM ar_invoices i JOIN ar_customers c ON c.id=i.customer_id
            WHERE i.status IN ('Posted','Part-Paid') AND (i.total_ghs - i.amount_received - COALESCE(i.credited_ghs,0)) > 0.01
              AND i.due_date IS NOT NULL AND date(i.due_date) < date(?)
            GROUP BY c.id ORDER BY overdue DESC""", (today.isoformat(),)).fetchall()]
        for r in rows:
            try: r['days_overdue'] = (today - _d.date.fromisoformat(str(r['oldest_due'])[:10])).days
            except Exception: r['days_overdue'] = 0
            r['overdue'] = round(float(r['overdue'] or 0), 2)
            r['has_email'] = bool((r.get('email') or '').strip())
        return ok({'customers': rows, 'total_overdue': round(sum(r['overdue'] for r in rows), 2), 'count': len(rows)})
    finally:
        conn.close()

def api_dunning_run(data, session):
    if not session: return err('Not authenticated')
    ids = data.get('customer_ids')
    prev = api_dunning_preview(session)
    if not prev.get('ok'): return prev
    targets = prev['customers']
    if ids: targets = [c for c in targets if c['customer_id'] in ids]
    targets = [c for c in targets if c.get('has_email')]
    if not targets: return err('No overdue customers with an email address to remind')
    sent = 0; queued = 0; results = []
    for c in targets:
        try:
            res = api_email_statement({'type': 'ar', 'id': c['customer_id']}, session)
            if res.get('ok'):
                if res.get('sent'): sent += 1
                else: queued += 1
                results.append({'customer': c['customer_name'], 'to': res.get('to'), 'status': 'sent' if res.get('sent') else 'queued'})
            else:
                results.append({'customer': c['customer_name'], 'status': 'error', 'error': res.get('error')})
        except Exception as e:
            results.append({'customer': c['customer_name'], 'status': 'error', 'error': str(e)})
    try:
        c2 = get_db(); _audit(c2, session, 'DUNNING_RUN', 'ar_invoices', 'bulk', '%d sent, %d queued' % (sent, queued)); c2.commit(); c2.close()
    except Exception: pass
    return ok({'sent': sent, 'queued': queued, 'results': results,
               'message': 'Dunning: %d sent, %d queued (configure SMTP to send)' % (sent, queued)})


# ═══════════════════════════════════════════════════════════════════════════
# PROCUREMENT-TO-PAY — turn a received PO into an AP bill, and a 3-way match
# view (Ordered [PO] vs Received [GRN] vs Billed [AP]) with variance flags.
# ═══════════════════════════════════════════════════════════════════════════
def _ensure_ap_po_col(conn):
    try: conn.execute("ALTER TABLE ap_bills ADD COLUMN po_id TEXT")
    except Exception: pass

def api_po_to_bill(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn); _ensure_ap_po_col(conn)
        try: _f53_migrate()
        except Exception: pass
        po_id = data.get('po_id')
        if not po_id: return err('Select a purchase order')
        po = conn.execute("SELECT * FROM purchase_orders WHERE id=?", (po_id,)).fetchone()
        if not po: return err('Purchase order not found')
        po = dict(po)
        exists = conn.execute("SELECT id FROM ap_bills WHERE po_id=?", (po_id,)).fetchone()
        if exists and not data.get('force'):
            return err('A bill already exists for %s. Use the AP module to view it.' % po.get('po_number'))
        # vendor: PO has vendor_id (may reference a different vendor table) — match by name into AP vendors
        vid = None
        vname = po.get('vendor_name') or ''
        if vname:
            vrow = conn.execute("SELECT id FROM vendors WHERE LOWER(vendor_name)=?", (vname.strip().lower(),)).fetchone()
            if vrow: vid = vrow['id']
        if not vid and po.get('vendor_id'):
            vrow = conn.execute("SELECT id FROM vendors WHERE id=?", (po.get('vendor_id'),)).fetchone()
            if vrow: vid = vrow['id']
        if not vid:
            vid = str(uuid.uuid4())
            conn.execute("INSERT INTO vendors(id,vendor_code,vendor_name,vendor_type,created_by) VALUES(?,?,?,?,?)",
                (vid, _seq_code(conn, 'vendors', 'vendor_code', 'VEND-', 5), vname or 'PO Vendor', 'Supplier', session.get('username', 'system')))
        polines = [dict(r) for r in conn.execute("SELECT * FROM po_line_items WHERE po_id=?", (po_id,)).fetchall()]
        dflt = data.get('expense_coa_id')
        if not dflt:
            r = conn.execute("SELECT id FROM chart_of_accounts WHERE code='61300001'").fetchone() or conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '6%' ORDER BY code LIMIT 1").fetchone()
            dflt = r['id'] if r else None
        lines = []
        for l in polines:
            amt = round(float(l.get('total_ghs') or (float(l.get('quantity') or 0) * float(l.get('unit_price_ghs') or 0))), 2)
            if amt <= 0: continue
            coa = l.get('coa_id') or dflt
            lines.append({'coa_id': coa, 'amount_ghs': amt, 'description': l.get('description') or po.get('po_number')})
        if not lines:
            tot = round(float(po.get('total_amount_ghs') or 0), 2)
            if tot <= 0: return err('PO has no line amounts to bill')
            lines = [{'coa_id': dflt, 'amount_ghs': tot, 'description': 'Goods/services per ' + (po.get('po_number') or '')}]
        if not dflt and any(not l['coa_id'] for l in lines):
            return err('No expense account resolved — select one')
        bid = str(uuid.uuid4()); num = _ap_next(conn, 'ap_bills', 'BILL')
        total = round(sum(l['amount_ghs'] for l in lines), 2)
        bdate = data.get('bill_date') or date.today().isoformat()
        ddate = data.get('due_date') or bdate
        conn.execute("INSERT INTO ap_bills(id,bill_number,vendor_invoice_no,vendor_id,bill_date,due_date,project_id,expense_coa_id,description,amount_ghs,tax_ghs,total_ghs,amount_paid,status,created_by,po_id) VALUES(?,?,?,?,?,?,?,?,?,?,0,?,0,'Draft',?,?)",
            (bid, num, po.get('po_number') or '', vid, bdate, ddate, po.get('project_id') or None, lines[0]['coa_id'], 'Bill for ' + (po.get('po_number') or ''), total, total, session.get('username', 'system'), po_id))
        for i, l in enumerate(lines, 1):
            conn.execute("INSERT INTO ap_bill_lines(id,bill_id,line_number,description,expense_coa_id,amount_ghs) VALUES(?,?,?,?,?,?)",
                (str(uuid.uuid4()), bid, i, l['description'], l['coa_id'], l['amount_ghs']))
        conn.execute("UPDATE purchase_orders SET status='Billed' WHERE id=?", (po_id,))
        _audit(conn, session, 'PO_TO_BILL', 'ap_bills', bid, '%s -> %s (%.2f)' % (po.get('po_number'), num, total))
        conn.commit()
        jv_num = None
        if data.get('post'):
            try:
                res = api_ap_post_bill({'id': bid}, session)
                jv_num = res.get('jv_number')
            except Exception: pass
        return ok({'id': bid, 'bill_number': num, 'total': total, 'jv_number': jv_num,
                   'message': 'Created bill %s for %s (GHS %.2f)%s' % (num, po.get('po_number'), total, (' — posted ' + jv_num) if jv_num else ' as draft')})
    finally:
        conn.close()

def api_three_way_match(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _ap_migration(conn); _ensure_ap_po_col(conn)
        try: _f53_migrate()
        except Exception: pass
        pos = [dict(r) for r in conn.execute("SELECT * FROM purchase_orders ORDER BY created_at DESC").fetchall()]
        out = []; counts = {'matched': 0, 'received_unbilled': 0, 'billed_no_grn': 0, 'ordered': 0, 'variance': 0}
        for po in pos:
            ordered = round(float(po.get('total_amount_ghs') or 0), 2)
            grn = conn.execute("SELECT grn_number, received_date FROM goods_received_notes WHERE po_id=? ORDER BY received_date DESC LIMIT 1", (po['id'],)).fetchone()
            received = bool(grn)
            billed = round(float(conn.execute("SELECT COALESCE(SUM(total_ghs),0) FROM ap_bills WHERE po_id=?", (po['id'],)).fetchone()[0] or 0), 2)
            variance = round(billed - ordered, 2)
            if billed > 0 and received and abs(variance) < 0.01:
                status = 'Matched'; counts['matched'] += 1
            elif billed > 0 and not received:
                status = 'Billed, no GRN'; counts['billed_no_grn'] += 1
            elif billed > 0 and abs(variance) >= 0.01:
                status = 'Variance'; counts['variance'] += 1
            elif received and billed == 0:
                status = 'Received, not billed'; counts['received_unbilled'] += 1
            else:
                status = 'Ordered'; counts['ordered'] += 1
            out.append({'po_id': po['id'], 'po_number': po.get('po_number'), 'vendor_name': po.get('vendor_name'),
                        'po_date': po.get('po_date'), 'ordered': ordered, 'received': received,
                        'grn_number': (grn['grn_number'] if grn else ''), 'received_date': (grn['received_date'] if grn else ''),
                        'billed': billed, 'variance': variance, 'status': status, 'po_status': po.get('status')})
        return ok({'rows': out, 'counts': counts, 'count': len(out)})
    finally:
        conn.close()

# ═══════════════════════════════════════════════════════════════════════════
# TRENDS (fast) — monthly income vs expenditure in a single GL query.
# ═══════════════════════════════════════════════════════════════════════════
def api_trends(session, months=None):
    if not session: return err('Not authenticated')
    try: n = max(1, min(24, int(months or 6)))
    except Exception: n = 6
    conn = get_db()
    try:
        import datetime as _d
        today = _d.date.today()
        periods = []
        y, m = today.year, today.month
        for _ in range(n):
            periods.append('%04d-%02d' % (y, m))
            m -= 1
            if m == 0: m = 12; y -= 1
        periods = list(reversed(periods))
        # Bucket by the MONTH of the ledger date (robust to how `period` is tagged —
        # SBS uses YYYY-MM, AOI uses YYYY — and avoids the %-format trap that the
        # old `... LIKE \'4%\' ... IN %s` build hit). Account class is taken from the
        # GL code, falling back to the joined chart code. Income = 4/7, expense = 5/6.
        rows = {}
        try:
            for r in conn.execute(
                "SELECT substr(gl.ledger_date,1,7) AS mo, "
                "SUM(CASE WHEN substr(COALESCE(NULLIF(gl.coa_code,''),c.code,''),1,1) IN ('4','7') "
                "         THEN COALESCE(gl.credit_amount,0)-COALESCE(gl.debit_amount,0) ELSE 0 END) AS inc, "
                "SUM(CASE WHEN substr(COALESCE(NULLIF(gl.coa_code,''),c.code,''),1,1) IN ('5','6') "
                "         THEN COALESCE(gl.debit_amount,0)-COALESCE(gl.credit_amount,0) ELSE 0 END) AS exp "
                "FROM general_ledger gl LEFT JOIN chart_of_accounts c ON c.id=gl.coa_id "
                "LEFT JOIN journal_vouchers jv ON jv.id=gl.jv_id "
                "WHERE substr(gl.ledger_date,1,7) BETWEEN ? AND ? "
                "AND (jv.status IS NULL OR jv.status='Posted') "
                "GROUP BY substr(gl.ledger_date,1,7)", (periods[0], periods[-1])).fetchall():
                rows[r[0]] = (round(float(r[1] or 0), 2), round(float(r[2] or 0), 2))
        except Exception as _te:
            import sys as _s; print('trends query warning: %s' % _te, file=_s.stderr); rows = {}
        series = []
        for p in periods:
            inc, exp = rows.get(p, (0.0, 0.0))
            series.append({'period': p, 'income': inc, 'expenditure': exp, 'surplus': round(inc - exp, 2)})
        return ok({'series': series})
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# INVENTORY REORDER — items at/below reorder level, with a suggested order qty,
# and a one-click "raise draft PO" that feeds the P2P chain (PO→GRN→bill).
# ═══════════════════════════════════════════════════════════════════════════
def api_inv_reorder(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _inv_migration(conn)
        rows = [dict(r) for r in conn.execute(
            "SELECT * FROM inv_items WHERE COALESCE(reorder_level,0) > 0 AND COALESCE(qty_on_hand,0) <= reorder_level ORDER BY (reorder_level - qty_on_hand) DESC").fetchall()]
        out = []
        for r in rows:
            roll = round(float(r.get('reorder_level') or 0), 2); onhand = round(float(r.get('qty_on_hand') or 0), 2)
            cost = round(float(r.get('avg_cost') or 0), 2)
            suggested = round(max(roll * 2 - onhand, roll), 2)
            out.append({'id': r['id'], 'item_code': r.get('item_code'), 'item_name': r.get('item_name'),
                        'unit': r.get('unit') or 'each', 'qty_on_hand': onhand, 'reorder_level': roll,
                        'avg_cost': cost, 'suggested_qty': suggested, 'est_cost': round(suggested * cost, 2)})
        return ok({'items': out, 'count': len(out), 'total_est': round(sum(x['est_cost'] for x in out), 2)})
    finally:
        conn.close()

def api_inv_create_reorder_po(data, session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _inv_migration(conn)
        try: _f53_migrate()
        except Exception: pass
        items = data.get('items') or []
        if not items: return err('Select at least one item to reorder')
        lines = []; total = 0.0
        for it in items:
            iid = it.get('item_id') or it.get('id'); qty = round(float(it.get('qty') or 0), 2)
            if qty <= 0: continue
            row = conn.execute("SELECT * FROM inv_items WHERE id=?", (iid,)).fetchone()
            if not row: continue
            row = dict(row); cost = round(float(row.get('avg_cost') or 0), 2); lt = round(qty * cost, 2)
            lines.append({'desc': row.get('item_name'), 'qty': qty, 'unit': row.get('unit') or 'each',
                          'price': cost, 'total': lt, 'coa_id': row.get('inventory_coa_id')})
            total += lt
        if not lines: return err('No valid items/quantities to order')
        pid = str(uuid.uuid4())
        num = _seq_code(conn, 'purchase_orders', 'po_number', 'PO-', 4)
        conn.execute("INSERT INTO purchase_orders(id,po_number,vendor_name,po_date,total_amount_ghs,currency,status,notes,created_by) VALUES(?,?,?,?,?,?,?,?,?)",
            (pid, num, (data.get('vendor_name') or 'Stock reorder'), date.today().isoformat(), round(total, 2), 'GHS', 'Draft', 'Auto-raised from inventory reorder', session.get('username', 'system')))
        for l in lines:
            conn.execute("INSERT INTO po_line_items(id,po_id,description,quantity,unit,unit_price_ghs,total_ghs,coa_id) VALUES(?,?,?,?,?,?,?,?)",
                (str(uuid.uuid4()), pid, l['desc'], l['qty'], l['unit'], l['price'], l['total'], l['coa_id']))
        _audit(conn, session, 'INV_REORDER_PO', 'purchase_orders', pid, '%s (%d lines, %.2f)' % (num, len(lines), total))
        conn.commit()
        return ok({'po_id': pid, 'po_number': num, 'total': round(total, 2), 'lines': len(lines),
                   'message': 'Draft %s raised for %d item(s), GHS %.2f — receive it in Procurement to flow GRN → bill.' % (num, len(lines), round(total, 2))})
    finally:
        conn.close()


