# FINANCE SUITE OVERVIEW — one-call command center rolling up cash, AR, AP,
# inventory, procurement and tax across the modules. Read-only.
# ═══════════════════════════════════════════════════════════════════════════
def api_finance_overview(session):
    if not session: return err('Not authenticated')
    def safe(fn, *a):
        try:
            r = fn(*a); return r if isinstance(r, dict) and r.get('ok') else {}
        except Exception as _se:
            import sys as _sx; print('finance_overview query warning: %s' % _se, file=_sx.stderr); return {}
    wc = safe(api_working_capital, session)
    dun = safe(api_dunning_preview, session)
    ro = safe(api_inv_reorder, session)
    tw = safe(api_three_way_match, session)
    tax = safe(api_tax_schedules, session, None)
    ub = safe(api_unbudgeted_spend, session)
    counts = tw.get('counts') or {}
    return ok({
        'cash': wc.get('cash_and_bank_ghs', 0),
        'receivables': wc.get('receivables_ghs', 0), 'receivables_overdue': wc.get('receivables_overdue_ghs', 0),
        'payables': wc.get('payables_ghs', 0), 'payables_overdue': wc.get('payables_overdue_ghs', 0),
        'inventory_value': wc.get('inventory_value_ghs', 0),
        'net_working_capital': wc.get('net_working_capital_ghs', 0), 'current_ratio': wc.get('current_ratio'),
        'overdue_customers': dun.get('count', 0), 'overdue_total': dun.get('total_overdue', 0),
        'low_stock_items': ro.get('count', 0), 'reorder_value': ro.get('total_est', 0),
        'pos_to_bill': counts.get('received_unbilled', 0), 'po_variances': counts.get('variance', 0),
        'tax_period': tax.get('period'), 'tax_outstanding': tax.get('total_outstanding', 0),
        'unbudgeted_total': ub.get('unbudgeted_total', 0), 'unbudgeted_count': ub.get('unbudgeted_count', 0),
        'as_of': date.today().isoformat(),
    })


# ═══════════════════════════════════════════════════════════════════════════
# UNBUDGETED SPEND — actual expenditure not tied to a budget line (budget_id
# empty). Invisible to Budget-vs-Actual, so it overstates availability. This
# reconciles total actuals vs budget-linked spend and lists the offenders.
# ═══════════════════════════════════════════════════════════════════════════
def api_unbudgeted_spend(session):
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        cols = [r[1] for r in conn.execute("PRAGMA table_info(actuals)").fetchall()]
        post = " AND COALESCE(is_posted,0)=1" if 'is_posted' in cols else ""
        def sc(where):
            try:
                r = conn.execute("SELECT COALESCE(SUM(amount_ghs),0) FROM actuals WHERE (" + where + ")" + post).fetchone()
                return round(float(r[0]), 2) if r and r[0] is not None else 0.0
            except Exception:
                return 0.0
        total = sc("1=1")
        linked = sc("budget_id IS NOT NULL AND budget_id!=''")
        unbudgeted = sc("budget_id IS NULL OR budget_id=''")
        try:
            ucount = conn.execute("SELECT COUNT(*) FROM actuals WHERE (budget_id IS NULL OR budget_id='')" + post).fetchone()[0] or 0
        except Exception:
            ucount = 0
        items = []
        try:
            for r in conn.execute(
                "SELECT a.actual_code, a.payee, a.description, a.amount_ghs, a.expense_date, p.project_code "
                "FROM actuals a LEFT JOIN projects p ON p.id=a.project_id "
                "WHERE (a.budget_id IS NULL OR a.budget_id='')" + (" AND COALESCE(a.is_posted,0)=1" if 'is_posted' in cols else "") +
                " ORDER BY a.amount_ghs DESC LIMIT 250").fetchall():
                items.append({'code': r[0], 'payee': r[1], 'description': r[2], 'amount': round(float(r[3] or 0), 2),
                              'date': r[4], 'project_code': r[5]})
        except Exception:
            items = []
        pct = round(unbudgeted / total * 100, 1) if total else 0.0
        return ok({'unbudgeted_total': unbudgeted, 'unbudgeted_count': ucount, 'total_actuals': total,
                   'budget_linked': linked, 'pct_unbudgeted': pct, 'items': items})
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# STORES BULK IMPORT — load stock purchases (receipts) from Excel/Word/CSV.
# Each row: item, qty, unit_cost (+ optional unit/category/reorder_level). New
# items are created; every row posts a stock receipt (Dr Inventory / Cr Bank).
# ═══════════════════════════════════════════════════════════════════════════
def api_inv_import(data, session):
    if not session: return err('Not authenticated')
    bank_id = data.get('bank_account_id')
    if not bank_id: return err('Select the bank account that paid for the stock')
    try: rows = _import_rows(data)
    except Exception as e: return err(str(e))
    if not rows: return err('No rows found in the uploaded file')
    conn = get_db()
    try:
        _inv_migration(conn)
        dft = data.get('expense_coa_id')
        if not dft:
            r = conn.execute("SELECT id FROM chart_of_accounts WHERE code='61300001'").fetchone() or conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '6%' ORDER BY code LIMIT 1").fetchone()
            dft = r['id'] if r else None
        existing = {}
        for r in conn.execute("SELECT id, LOWER(item_name) AS n FROM inv_items").fetchall():
            existing[r['n']] = r['id']
    finally:
        conn.close()
    created = 0; received = 0; errors = []
    for i, r0 in enumerate(rows, 1):
        try:
            r = _cf_lc_row(r0)
            name = str(r.get('item') or r.get('item_name') or r.get('description') or r.get('name') or '').strip()
            if not name: errors.append('Row %d: missing item name' % i); continue
            qty = _imp_num(r.get('qty') or r.get('quantity') or r.get('units') or r.get('qty_received'))
            cost = _imp_num(r.get('unit_cost') or r.get('cost') or r.get('price') or r.get('unit_price'))
            if qty <= 0: errors.append('Row %d (%s): missing/invalid quantity' % (i, name)); continue
            iid = existing.get(name.lower())
            if not iid:
                res = api_inv_save_item({'item_name': name, 'unit': (r.get('unit') or 'each'), 'category': (r.get('category') or ''),
                                         'reorder_level': _imp_num(r.get('reorder_level') or r.get('reorder') or 0), 'expense_coa_id': dft}, session)
                if not res.get('ok'): errors.append('Row %d: %s' % (i, res.get('error'))); continue
                iid = res.get('id'); existing[name.lower()] = iid; created += 1
            rec = api_inv_receipt({'item_id': iid, 'qty': qty, 'unit_cost': cost, 'bank_account_id': bank_id,
                                   'reference': (r.get('reference') or r.get('grn') or 'Bulk import')}, session)
            if rec.get('ok'): received += 1
            else: errors.append('Row %d receipt (%s): %s' % (i, name, rec.get('error')))
        except Exception as e:
            errors.append('Row %d: %s' % (i, e))
    return ok({'created': created, 'received': received, 'errors': errors[:40], 'error_count': len(errors),
               'message': 'Imported %d new item(s) and posted %d stock receipt(s).' % (created, received)})


