# ═════════════════════════════════════════════════════════════════════════════
# OPS PACK 2026-06-10 — PPE schedule · Cash book · External Audit Pack ·
# Payment run bank file · Asset revaluation/impairment · Flash email ·
# Approval email notifications
# ═════════════════════════════════════════════════════════════════════════════

def api_ppe_schedule(session, fy=None):
    """GET /api/ppe-schedule?fy=YYYY — IPSAS 17 PPE movement (roll-forward) by
    asset category: cost b/f + additions - disposals +/- revaluation = cost c/f;
    accumulated depreciation b/f + charge - released on disposal + impairment =
    accum c/f; NBV b/f and c/f. Also returns the GL balances on 111x (cost) and
    119x (accumulated) so the register can be tied to the ledger."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        from datetime import datetime as _dt
        fy = str(fy or _dt.now().year)[:4]
        d1, d2 = fy + '-01-01', fy + '-12-31'
        assets = [dict(r) for r in conn.execute(
            "SELECT asset_category, acquisition_date, acquisition_cost, accumulated_depreciation, "
            "COALESCE(revaluation_amount,0) AS reval, COALESCE(impairment_amount,0) AS impair, "
            "COALESCE(last_valuation_date,'') AS val_date, status, COALESCE(disposal_date,'') AS disposal_date "
            "FROM asset_register").fetchall()]
        charge = {}
        try:
            for r in conn.execute(
                "SELECT ar.asset_category AS cat, SUM(dr.monthly_dep) AS amt FROM depreciation_runs dr "
                "JOIN asset_register ar ON ar.id=dr.asset_id WHERE dr.run_month LIKE ? GROUP BY ar.asset_category",
                (fy + '%',)).fetchall():
                charge[r['cat'] or 'General'] = round(float(r['amt'] or 0), 2)
        except Exception:
            pass
        cats = {}
        def C(name):
            return cats.setdefault(name or 'General', {
                'category': name or 'General', 'cost_bf': 0.0, 'additions': 0.0, 'disposals_cost': 0.0,
                'revaluation': 0.0, 'impairment': 0.0, 'cost_cf': 0.0,
                'dep_bf': 0.0, 'dep_charge': 0.0, 'dep_released': 0.0, 'dep_cf': 0.0,
                'nbv_bf': 0.0, 'nbv_cf': 0.0})
        for a in assets:
            c = C(a['asset_category'])
            cost = round(float(a['acquisition_cost'] or 0), 2)
            acq = str(a['acquisition_date'] or '')
            disp = str(a['disposal_date'] or '')
            disposed_in_fy = bool(disp) and d1 <= disp[:10] <= d2
            disposed_before = bool(disp) and disp[:10] < d1
            if disposed_before:
                continue
            if acq[:10] < d1:
                c['cost_bf'] += cost
            elif acq[:10] <= d2:
                c['additions'] += cost
            if disposed_in_fy:
                c['disposals_cost'] += cost
                c['dep_released'] += round(float(a['accumulated_depreciation'] or 0), 2)
            if a['val_date'][:4] == fy:
                c['revaluation'] += round(float(a['reval'] or 0), 2)
                c['impairment'] += round(float(a['impair'] or 0), 2)
            if not disposed_in_fy:
                c['dep_cf'] += round(float(a['accumulated_depreciation'] or 0), 2)
        for name, c in cats.items():
            c['dep_charge'] = charge.get(name, 0.0)
            c['cost_cf'] = round(c['cost_bf'] + c['additions'] - c['disposals_cost'] + c['revaluation'], 2)
            c['dep_bf'] = round(c['dep_cf'] + c['dep_released'] - c['dep_charge'] - c['impairment'], 2)
            c['dep_cf'] = round(c['dep_cf'] + c['impairment'], 2)
            c['nbv_bf'] = round(c['cost_bf'] - c['dep_bf'], 2)
            c['nbv_cf'] = round(c['cost_cf'] - c['dep_cf'], 2)
            for k in c:
                if isinstance(c[k], float): c[k] = round(c[k], 2)
        rows = sorted(cats.values(), key=lambda x: x['category'])
        tot = {}
        for k in ('cost_bf','additions','disposals_cost','revaluation','impairment','cost_cf',
                  'dep_bf','dep_charge','dep_released','dep_cf','nbv_bf','nbv_cf'):
            tot[k] = round(sum(r[k] for r in rows), 2)
        def _glsum(prefix, nature):
            r = conn.execute(
                "SELECT COALESCE(SUM(COALESCE(debit_amount,0)),0), COALESCE(SUM(COALESCE(credit_amount,0)),0) "
                "FROM general_ledger WHERE coa_code LIKE ? AND ledger_date <= ?", (prefix, d2)).fetchone()
            d, cr = float(r[0] or 0), float(r[1] or 0)
            return round((d - cr) if nature == 'debit' else (cr - d), 2)
        gl = {'gl_cost_111x': _glsum('111%', 'debit'), 'gl_accum_119x': _glsum('119%', 'credit')}
        gl['register_vs_gl_cost'] = round(tot['cost_cf'] - gl['gl_cost_111x'], 2)
        gl['register_vs_gl_accum'] = round(tot['dep_cf'] - gl['gl_accum_119x'], 2)
        return ok({'fy': fy, 'rows': rows, 'totals': tot, 'gl_tie': gl,
                   'note': 'Register is the PPE subledger; the GL carries assets capitalised through '
                           'payment vouchers coded to 111x. A difference can be legitimate (e.g. donated '
                           'assets in the register only) and should be explained in the notes.'})
    finally:
        conn.close()


def api_cashbook(session, bank_account_id=None, date_from=None, date_to=None, net=None):
    """GET /api/cashbook?bank_account_id=&date_from=&date_to= — classic per-bank
    cash book from the general ledger: opening balance, receipts (Dr), payments
    (Cr), running balance, closing balance."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        from datetime import date as _d
        if not date_to: date_to = _d.today().isoformat()
        if not date_from: date_from = date_to[:7] + '-01'
        bank = None
        if bank_account_id:
            bank = conn.execute("SELECT * FROM bank_accounts WHERE id=?", (bank_account_id,)).fetchone()
            if not bank: return err('Bank account not found')
            bank = dict(bank)
        if bank and bank.get('coa_id'):
            where = "gl.coa_id=?"; params = [bank['coa_id']]
        else:
            where = "(gl.coa_code LIKE '126%' OR gl.coa_code LIKE '127%' OR gl.coa_code LIKE '128%' OR gl.coa_code LIKE '129%' OR gl.coa_code='1001')"
            params = []
        net_on = str(net if net is not None else '1') not in ('0', 'false', 'no', '')
        hidden = 0
        # Net view hides a reversed entry TOGETHER WITH its reversal, but only
        # when BOTH legs fall inside the displayed window/scope — so the closing
        # balance is never distorted (the pair nets to zero). This is computed in
        # Python after the gross rows are fetched: window-correct, and free of the
        # SQL "NOT IN (subquery with a NULL)" trap that silently hid nothing.
        op = conn.execute(
            "SELECT COALESCE(SUM(COALESCE(gl.debit_amount,0)-COALESCE(gl.credit_amount,0)),0) FROM general_ledger gl "
            "WHERE " + where + " AND gl.ledger_date < ?", params + [date_from]).fetchone()
        opening = round(float(op[0] or 0), 2)
        rows = [dict(r) for r in conn.execute(
            "SELECT gl.ledger_date, gl.jv_number, gl.description, COALESCE(gl.debit_amount,0) AS receipt, "
            "COALESCE(gl.credit_amount,0) AS payment, COALESCE(a.actual_code,'') AS voucher_code "
            "FROM general_ledger gl "
            "LEFT JOIN journal_vouchers j2 ON j2.jv_number = gl.jv_number "
            "LEFT JOIN actuals a ON j2.source_module='actuals' AND a.id = j2.source_id "
            "WHERE " + where +
            " AND gl.ledger_date BETWEEN ? AND ? ORDER BY gl.ledger_date, gl.jv_number",
            params + [date_from, date_to]).fetchall()]
        if net_on and rows:
            present = {r['jv_number'] for r in rows if r.get('jv_number')}
            hide = set()
            for pr in conn.execute(
                    "SELECT o.jv_number AS onum, r.jv_number AS rnum "
                    "FROM journal_vouchers r JOIN journal_vouchers o ON r.reversal_of = o.id "
                    "WHERE COALESCE(r.is_reversal,0)=1 AND o.jv_number IS NOT NULL "
                    "AND r.jv_number IS NOT NULL").fetchall():
                onum, rnum = pr[0], pr[1]
                if onum in present and rnum in present:
                    hide.add(onum); hide.add(rnum)
            if hide:
                kept = [r for r in rows if r['jv_number'] not in hide]
                hidden = len(rows) - len(kept)
                rows = kept
        bal = opening
        for r in rows:
            r['receipt'] = round(float(r['receipt'] or 0), 2)
            r['payment'] = round(float(r['payment'] or 0), 2)
            bal = round(bal + r['receipt'] - r['payment'], 2)
            r['balance'] = bal
        t_in = round(sum(r['receipt'] for r in rows), 2)
        t_out = round(sum(r['payment'] for r in rows), 2)
        return ok({'bank': ({'id': bank['id'], 'bank_name': bank.get('bank_name'),
                             'account_number': bank.get('account_number')} if bank else
                            {'id': None, 'bank_name': 'ALL CASH & BANK ACCOUNTS', 'account_number': ''}),
                   'date_from': date_from, 'date_to': date_to, 'opening_balance': opening,
                   'rows': rows, 'total_receipts': t_in, 'total_payments': t_out,
                   'closing_balance': round(opening + t_in - t_out, 2), 'basis': 'general_ledger',
                   'net_view': net_on, 'hidden_cancelled_lines': hidden})
    finally:
        conn.close()


def api_audit_pack(session, fy=None):
    """GET /api/audit-pack?fy=YYYY — one-click external-audit bundle. Builds a
    ZIP (base64) of CSV schedules + an index: trial balance, GL detail, I&E
    summary, SFP, AR/AP aging, PPE movement, tax schedules, IPSAS 24 statement,
    bank reconciliation register. Every section is best-effort: a failed
    section is reported in the manifest, never kills the pack."""
    if not session: return err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer', 'Auditor'):
        return err('Admin, Finance Officer or Auditor role required')
    import io as _io, zipfile as _zip, csv as _csv, base64 as _b64, json as _json
    from datetime import datetime as _dt
    fy = str(fy or _dt.now().year)[:4]
    d1, d2 = fy + '-01-01', fy + '-12-31'
    conn = get_db()
    sections = []
    buf = _io.BytesIO()
    zf = _zip.ZipFile(buf, 'w', _zip.ZIP_DEFLATED)
    def _csv_bytes(headers, rows):
        s = _io.StringIO(); w = _csv.writer(s)
        w.writerow(headers)
        for r in rows: w.writerow(r)
        return ('\ufeff' + s.getvalue()).encode('utf-8')
    def add(name, fn):
        try:
            headers, rows = fn()
            zf.writestr(name, _csv_bytes(headers, rows))
            sections.append({'name': name, 'ok': True, 'rows': len(rows)})
        except Exception as e:
            sections.append({'name': name, 'ok': False, 'error': str(e)[:160]})
    try:
        def _tb():
            rows = conn.execute(
                "SELECT gl.coa_code, COALESCE(MAX(gl.account_name),'') , "
                "ROUND(SUM(COALESCE(gl.debit_amount,0)),2), ROUND(SUM(COALESCE(gl.credit_amount,0)),2) "
                "FROM general_ledger gl WHERE gl.ledger_date <= ? GROUP BY gl.coa_code ORDER BY gl.coa_code",
                (d2,)).fetchall()
            out = []
            for r in rows:
                d, c = float(r[2] or 0), float(r[3] or 0)
                out.append([r[0], r[1], r[2], r[3], round(max(d - c, 0), 2), round(max(c - d, 0), 2)])
            out.append(['TOTAL', '', round(sum(float(r[2]) for r in rows), 2), round(sum(float(r[3]) for r in rows), 2), '', ''])
            return ['Account Code', 'Account Name', 'Total Debits', 'Total Credits', 'Debit Balance', 'Credit Balance'], out
        add('01_trial_balance_%s.csv' % fy, _tb)
        def _gl():
            rows = conn.execute(
                "SELECT ledger_date, jv_number, coa_code, account_name, description, "
                "COALESCE(debit_amount,0), COALESCE(credit_amount,0), COALESCE(project_code,''), COALESCE(posted_by,'') "
                "FROM general_ledger WHERE ledger_date BETWEEN ? AND ? ORDER BY ledger_date, jv_number",
                (d1, d2)).fetchall()
            return ['Date', 'Voucher', 'Account', 'Account Name', 'Description', 'Debit', 'Credit', 'Project', 'Posted By'], [list(r) for r in rows]
        add('02_general_ledger_detail_%s.csv' % fy, _gl)
        def _ie():
            rows = conn.execute(
                "SELECT coa_code, COALESCE(MAX(account_name),''), "
                "ROUND(SUM(CASE WHEN coa_code LIKE '4%' THEN COALESCE(credit_amount,0)-COALESCE(debit_amount,0) "
                "ELSE COALESCE(debit_amount,0)-COALESCE(credit_amount,0) END),2) "
                "FROM general_ledger WHERE (coa_code LIKE '4%' OR coa_code LIKE '6%') "
                "AND ledger_date BETWEEN ? AND ? GROUP BY coa_code ORDER BY coa_code", (d1, d2)).fetchall()
            return ['Account', 'Name', 'Amount (income +, expenditure +)'], [list(r) for r in rows]
        add('03_income_expenditure_%s.csv' % fy, _ie)
        def _sfp():
            s = api_sfp_v556(session)
            if not (isinstance(s, dict) and s.get('ok')): raise Exception(str(s.get('error') if isinstance(s, dict) else s)[:120])
            out = []
            def flat(prefix, d):
                for k, v in (d or {}).items():
                    if isinstance(v, (int, float)): out.append([prefix, k, round(float(v), 2)])
            flat('Assets', s.get('assets')); flat('Liabilities', s.get('liabilities')); flat('Equity', s.get('equity'))
            out.append(['Check', 'presentation_difference', s.get('presentation_difference')])
            return ['Section', 'Line', 'Amount'], out
        add('04_financial_position.csv', _sfp)
        def _ar():
            a = api_ar_aging(session)
            rows = (a.get('by_customer') or a.get('rows') or []) if isinstance(a, dict) else []
            return ['Customer', 'Current', '1-30', '31-60', '61-90', '90+', 'Total'], [
                [r.get('customer_name') or r.get('name'), r.get('current'), r.get('b1_30') or r.get('d1_30'),
                 r.get('b31_60') or r.get('d31_60'), r.get('b61_90') or r.get('d61_90'),
                 r.get('b90_plus') or r.get('d90_plus'), r.get('total')] for r in rows]
        add('05_receivables_aging.csv', _ar)
        def _ap():
            a = api_ap_aging(session)
            rows = (a.get('by_vendor') or a.get('rows') or []) if isinstance(a, dict) else []
            return ['Vendor', 'Current', '1-30', '31-60', '61-90', '90+', 'Total'], [
                [r.get('vendor_name') or r.get('name'), r.get('current'), r.get('b1_30') or r.get('d1_30'),
                 r.get('b31_60') or r.get('d31_60'), r.get('b61_90') or r.get('d61_90'),
                 r.get('b90_plus') or r.get('d90_plus'), r.get('total')] for r in rows]
        add('06_payables_aging.csv', _ap)
        def _ppe():
            p = api_ppe_schedule(session, fy)
            if not p.get('ok'): raise Exception(p.get('error'))
            rows = [[r['category'], r['cost_bf'], r['additions'], r['disposals_cost'], r['revaluation'],
                     r['cost_cf'], r['dep_bf'], r['dep_charge'], r['dep_released'], r['impairment'],
                     r['dep_cf'], r['nbv_bf'], r['nbv_cf']] for r in p['rows']]
            t = p['totals']
            rows.append(['TOTAL', t['cost_bf'], t['additions'], t['disposals_cost'], t['revaluation'],
                         t['cost_cf'], t['dep_bf'], t['dep_charge'], t['dep_released'], t['impairment'],
                         t['dep_cf'], t['nbv_bf'], t['nbv_cf']])
            return ['Category', 'Cost b/f', 'Additions', 'Disposals', 'Revaluation', 'Cost c/f',
                    'Accum Dep b/f', 'Charge', 'Released', 'Impairment', 'Accum Dep c/f', 'NBV b/f', 'NBV c/f'], rows
        add('07_ppe_movement_%s.csv' % fy, _ppe)
        def _tax():
            t = api_tax_schedules(session, fy)
            rows = (t.get('summary') or []) if isinstance(t, dict) else []
            return ['Tax Head', 'Account', 'Opening', 'Accrued', 'Remitted', 'Adjustments', 'Outstanding'], [
                [r.get('label'), r.get('code'), r.get('opening'), r.get('accrued'), r.get('remitted'),
                 r.get('adjustments'), r.get('outstanding')] for r in rows]
        add('08_tax_schedules_%s.csv' % fy, _tax)
        def _i24():
            s = api_ipsas24(session, fy)
            if not s.get('ok'): raise Exception(s.get('error'))
            rows = [[r['coa_code'], r['account_name'], r['original'], r['final'], r['actual'],
                     r['variance'], r['utilisation_pct']] for r in s['by_account']]
            t = s['totals']
            rows.append(['TOTAL', '', t['original'], t['final'], t['actual'], t['variance'], t['utilisation_pct']])
            rc = s['gl_reconciliation']
            rows.append([]); rows.append(['RECONCILIATION (IPSAS 24.47)', '', '', '', '', '', ''])
            rows.append(['Budget-linked actual', '', '', '', rc['budget_linked_actual'], '', ''])
            rows.append(['Unbudgeted payments', '', '', '', rc['unbudgeted_actual'], '', ''])
            rows.append(['Journal-based expenditure', '', '', '', rc['other_journal_expenditure'], '', ''])
            rows.append(['Total GL expenditure', '', '', '', rc['gl_expenditure'], '', ''])
            return ['Account', 'Name', 'Original Budget', 'Final Budget', 'Actual', 'Variance', 'Utilisation %'], rows
        add('09_budget_vs_actual_ipsas24_%s.csv' % fy, _i24)
        def _brec():
            rows = conn.execute(
                "SELECT recon_date, COALESCE(statement_balance,0), COALESCE(cashbook_balance,0), "
                "COALESCE(recon_difference,0), COALESCE(status,'') FROM bank_reconciliations "
                "WHERE recon_date BETWEEN ? AND ? ORDER BY recon_date", (d1, d2)).fetchall()
            return ['Date', 'Statement Balance', 'Cashbook Balance', 'Difference', 'Status'], [list(r) for r in rows]
        add('10_bank_reconciliations_%s.csv' % fy, _brec)
        manifest = ('EXTERNAL AUDIT PACK — FY %s\nGenerated: %s by %s\n\nContents:\n' % (
            fy, _dt.now().strftime('%Y-%m-%d %H:%M'), session.get('username', '')))
        for s in sections:
            manifest += ' - %s : %s\n' % (s['name'], ('%d rows' % s['rows']) if s.get('ok') else ('FAILED: ' + s.get('error', '')))
        manifest += ('\nBasis: double-entry general ledger; statements per IPSAS. '
                     'CSV files open in Excel (UTF-8 BOM).\n')
        zf.writestr('00_INDEX.txt', manifest)
        zf.close()
        data_b64 = _b64.b64encode(buf.getvalue()).decode('ascii')
        try:
            _audit(conn, session, 'AUDIT_PACK', 'reports', fy, 'External audit pack generated for FY %s (%d sections)' % (fy, len(sections)))
            conn.commit()
        except Exception:
            pass
        return ok({'fy': fy, 'filename': 'audit_pack_FY%s.zip' % fy, 'zip_b64': data_b64,
                   'sections': sections, 'size_bytes': len(buf.getvalue())})
    finally:
        conn.close()


