def api_payment_run_file(data, session):
    """POST /api/ap/payment-run-file {jv_number, email_remittance?} — bank
    transfer instruction for one payment run: per-vendor rows with bank details
    from the vendor master, a bank-upload CSV (base64), a printable transfer
    letter, and optional remittance-advice emails to each vendor."""
    if not session: return err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return err('Admin or Finance Officer role required')
    jvn = (data.get('jv_number') or '').strip()
    if not jvn: return err('jv_number of the payment run is required')
    import io as _io, csv as _csv, base64 as _b64
    conn = get_db()
    try:
        _ap_migration(conn)
        pays = [dict(r) for r in conn.execute(
            "SELECT p.*, v.vendor_name, COALESCE(v.bank_name,'') AS v_bank, COALESCE(v.account_name,'') AS v_acct_name, "
            "COALESCE(v.account_number,'') AS v_acct_no, COALESCE(v.email,'') AS v_email, "
            "COALESCE(b.bill_number,'') AS bill_number, COALESCE(b.vendor_invoice_no,'') AS vendor_invoice_no "
            "FROM ap_payments p LEFT JOIN vendors v ON v.id=p.vendor_id "
            "LEFT JOIN ap_bills b ON b.id=p.bill_id WHERE p.jv_number=? ORDER BY v.vendor_name", (jvn,)).fetchall()]
        if not pays: return err('No payments found for run %s' % jvn)
        byv = {}
        for p in pays:
            v = byv.setdefault(p.get('vendor_id'), {
                'vendor_name': p.get('vendor_name') or '(unknown vendor)', 'bank_name': p.get('v_bank'),
                'account_name': p.get('v_acct_name') or p.get('vendor_name'), 'account_number': p.get('v_acct_no'),
                'email': p.get('v_email'), 'amount_ghs': 0.0, 'bills': []})
            v['amount_ghs'] = round(v['amount_ghs'] + float(p.get('amount_ghs') or 0), 2)
            v['bills'].append({'bill_number': p.get('bill_number'), 'vendor_invoice_no': p.get('vendor_invoice_no'),
                               'amount_ghs': round(float(p.get('amount_ghs') or 0), 2),
                               'payment_number': p.get('payment_number')})
        rows = sorted(byv.values(), key=lambda x: x['vendor_name'])
        missing = [r['vendor_name'] for r in rows if not (r['bank_name'] and r['account_number'])]
        s = _io.StringIO(); w = _csv.writer(s)
        w.writerow(['Beneficiary Name', 'Bank', 'Account Name', 'Account Number', 'Amount (GHS)', 'Narration'])
        for r in rows:
            w.writerow([r['vendor_name'], r['bank_name'], r['account_name'], r['account_number'],
                        '%.2f' % r['amount_ghs'], 'Payment run %s' % jvn])
        csv_b64 = _b64.b64encode(('\ufeff' + s.getvalue()).encode('utf-8')).decode('ascii')
        total = round(sum(r['amount_ghs'] for r in rows), 2)
        emailed = 0
        if data.get('email_remittance'):
            for r in rows:
                if not r['email']: continue
                lines = '\n'.join(' - %s%s : GHS %.2f' % (
                    b['bill_number'], (' (your invoice %s)' % b['vendor_invoice_no']) if b['vendor_invoice_no'] else '',
                    b['amount_ghs']) for b in r['bills'])
                body = ('Dear %s,\n\nWe have processed a payment of GHS %.2f to your account '
                        '%s (%s).\n\nSettled bills:\n%s\n\nPayment reference: %s\n\nThis is an automated '
                        'remittance advice.\n' % (r['vendor_name'], r['amount_ghs'],
                        r['account_number'] or 'on file', r['bank_name'] or 'your bank', lines, jvn))
                try:
                    eid = _v42_queue_email(conn, r['email'], 'Remittance advice — payment %s (GHS %.2f)' % (jvn, r['amount_ghs']), body)
                    try: _v42_send_email_now(conn, eid)
                    except Exception: pass
                    emailed += 1
                except Exception:
                    pass
            conn.commit()
        try:
            _audit(conn, session, 'PAYMENT_RUN_FILE', 'ap_payments', jvn,
                   'Bank file generated: %d beneficiaries, GHS %.2f%s' % (len(rows), total,
                   (', %d remittance advices emailed' % emailed) if emailed else ''))
            conn.commit()
        except Exception:
            pass
        return ok({'jv_number': jvn, 'rows': rows, 'total_ghs': total, 'beneficiaries': len(rows),
                   'csv_b64': csv_b64, 'filename': 'bank_schedule_%s.csv' % jvn.replace('/', '-'),
                   'missing_bank_details': missing, 'remittance_emailed': emailed})
    finally:
        conn.close()


def _reval_coa(conn, kind):
    """Find or create the chart accounts needed for revaluation / impairment."""
    import uuid as _u
    def find(sql, params=()):
        r = conn.execute(sql, params).fetchone()
        return r['id'] if r else None
    def create(code, name, category, sub, atype):
        n = int(code)
        while conn.execute("SELECT 1 FROM chart_of_accounts WHERE code=?", (str(n),)).fetchone():
            n += 1
        cid = str(_u.uuid4())
        conn.execute("INSERT INTO chart_of_accounts(id,code,category,sub_category,account_name,account_type,vat_applicable) "
                     "VALUES(?,?,?,?,?,?,0)", (cid, str(n), category, sub, name, atype))
        return cid
    if kind == 'surplus':
        return (find("SELECT id FROM chart_of_accounts WHERE code LIKE '3%' AND LOWER(account_name) LIKE '%revaluation%' ORDER BY code LIMIT 1")
                or create('31200001', 'Revaluation Surplus', 'Equity', 'Reserves', 'Equity'))
    if kind == 'loss':
        return (find("SELECT id FROM chart_of_accounts WHERE code LIKE '6%' AND LOWER(account_name) LIKE '%impair%' ORDER BY code LIMIT 1")
                or create('61900031', 'Impairment Loss', 'Expenses', 'Depreciation & Impairment', 'Expense'))
    if kind == 'accum_impair':
        return (find("SELECT id FROM chart_of_accounts WHERE code LIKE '119%' AND LOWER(account_name) LIKE '%impair%' ORDER BY code LIMIT 1")
                or create('11912001', 'Accumulated Impairment', 'Assets', 'Accumulated Depreciation', 'Asset'))
    return None


def api_asset_revalue(data, session):
    """POST /api/assets/revalue {asset_id, new_value, valuation_date?, reason} —
    IPSAS 17/21 revaluation or impairment of an active asset. Upward: Dr asset
    cost / Cr Revaluation Surplus (equity). Downward: Dr Impairment Loss /
    Cr Accumulated Impairment (contra-asset). Posts a balanced journal and
    updates the register's carrying amount."""
    if not session: return err('Not authenticated')
    if session.get('role') != 'Admin':
        return err('Admin access required for revaluation / impairment')
    asset_id = data.get('asset_id')
    reason = (data.get('reason') or '').strip()
    if not asset_id: return err('asset_id is required')
    if len(reason) < 5: return err('A justification of at least 5 characters is required')
    try:
        new_value = round(float(data.get('new_value')), 2)
    except Exception:
        return err('new_value must be a number')
    if new_value < 0: return err('new_value cannot be negative')
    from datetime import date as _d
    vdate = (data.get('valuation_date') or _d.today().isoformat())[:10]
    conn = get_db()
    try:
        a = conn.execute("SELECT * FROM asset_register WHERE id=?", (asset_id,)).fetchone()
        if not a: return err('Asset not found')
        a = dict(a)
        if (a.get('status') or 'Active') != 'Active':
            return err('Only an Active asset can be revalued (this one is %s)' % a.get('status'))
        nbv = round(float(a.get('carrying_amount') if a.get('carrying_amount') is not None else
                          (float(a.get('acquisition_cost') or 0) - float(a.get('accumulated_depreciation') or 0))), 2)
        delta = round(new_value - nbv, 2)
        if abs(delta) < 0.005: return err('New value equals the current carrying amount — nothing to post')
        if delta > 0:
            if not a.get('asset_coa_id'):
                r = conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '111%' ORDER BY code LIMIT 1").fetchone()
                cost_coa = r['id'] if r else None
            else:
                cost_coa = a.get('asset_coa_id')
            if not cost_coa: return err('No PPE cost account (111x) found in the chart of accounts')
            surplus = _reval_coa(conn, 'surplus')
            lines = [{'coa_id': cost_coa, 'debit_amount': delta, 'credit_amount': 0,
                      'description': 'Revaluation uplift %s' % a.get('asset_code')},
                     {'coa_id': surplus, 'debit_amount': 0, 'credit_amount': delta,
                      'description': 'Revaluation surplus %s' % a.get('asset_code')}]
            kind = 'Revaluation'
        else:
            loss = _reval_coa(conn, 'loss'); accum = _reval_coa(conn, 'accum_impair')
            lines = [{'coa_id': loss, 'debit_amount': abs(delta), 'credit_amount': 0,
                      'description': 'Impairment loss %s' % a.get('asset_code')},
                     {'coa_id': accum, 'debit_amount': 0, 'credit_amount': abs(delta),
                      'description': 'Accumulated impairment %s' % a.get('asset_code')}]
            kind = 'Impairment'
        desc = '%s of %s (%s): carrying GHS %.2f -> GHS %.2f. %s' % (
            kind, a.get('asset_name'), a.get('asset_code'), nbv, new_value, reason)
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', vdate, desc,
                                                   a.get('asset_code'), a.get('project_id'), None,
                                                   'asset_revaluation', asset_id, lines)
        except Exception as e:
            return err('Could not post the %s journal: %s' % (kind.lower(), e))
        if delta > 0:
            conn.execute("UPDATE asset_register SET carrying_amount=?, revaluation_amount=COALESCE(revaluation_amount,0)+?, "
                         "last_valuation_date=?, notes=COALESCE(notes,'')||? WHERE id=?",
                         (new_value, delta, vdate, '\n[%s] %s (%s)' % (vdate, desc, jv_num), asset_id))
        else:
            conn.execute("UPDATE asset_register SET carrying_amount=?, impairment_amount=COALESCE(impairment_amount,0)+?, "
                         "last_valuation_date=?, notes=COALESCE(notes,'')||? WHERE id=?",
                         (new_value, abs(delta), vdate, '\n[%s] %s (%s)' % (vdate, desc, jv_num), asset_id))
        _audit(conn, session, 'ASSET_' + kind.upper(), 'asset_register', asset_id, desc + ' [' + jv_num + ']')
        conn.commit()
        return ok({'asset_id': asset_id, 'kind': kind, 'previous_carrying': nbv, 'new_carrying': new_value,
                   'movement': delta, 'jv_number': jv_num,
                   'message': '%s posted as %s (GHS %.2f)' % (kind, jv_num, abs(delta))})
    finally:
        conn.close()


