def api_send_flash_email(session, period=None):
    """Email the Month-End Flash summary to the configured recipients. Used by
    the manual button and by the daily cron on the 1st of the month."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        rec = [e.strip() for e in (_ice_setting(conn, 'flash_recipients', '') or '').split(',') if e.strip()]
        if not rec:
            return ok({'sent': 0, 'skipped': True, 'message': 'No recipients configured (Month-End Flash -> Email settings)'})
        f = api_flash_pack(session, period)
        if not (isinstance(f, dict) and f.get('ok')):
            return err('Could not build the flash pack: %s' % (f.get('error') if isinstance(f, dict) else f))
        p = f.get('period') or (period or '')
        def g(*keys):
            d = f
            for k in keys:
                d = (d or {}).get(k) if isinstance(d, dict) else None
            try: return float(d or 0)
            except Exception: return 0.0
        body = ('MONTH-END FLASH — %s\n%s\n\n'
                'Income (period): GHS %.2f\nExpenditure (period): GHS %.2f\nSurplus/(Deficit): GHS %.2f\n\n'
                'Cash & bank: GHS %.2f\nReceivables: GHS %.2f\nPayables: GHS %.2f\nNet working capital: GHS %.2f\n\n'
                'Trial balance: %s\n\nOpen the system for the full flash pack, statements and drill-down.\n') % (
            p, '=' * 40,
            g('income') or g('performance', 'income'), g('expenditure') or g('performance', 'expenditure'),
            g('surplus') or g('performance', 'surplus'),
            g('cash') or g('liquidity', 'cash'), g('receivables') or g('liquidity', 'receivables'),
            g('payables') or g('liquidity', 'payables'), g('net_working_capital') or g('liquidity', 'net_working_capital'),
            'BALANCED' if (f.get('tb_balanced') or (f.get('tb') or {}).get('balanced')) else 'see system')
        sent = 0
        for e in rec:
            try:
                eid = _v42_queue_email(conn, e, 'Month-End Flash — %s' % p, body)
                try: _v42_send_email_now(conn, eid)
                except Exception: pass
                sent += 1
            except Exception:
                pass
        conn.commit()
        return ok({'sent': sent, 'period': p, 'recipients': rec})
    finally:
        conn.close()


