# ═════════════════════════════════════════════════════════════════════════════
# AUTH PACK 2026-06-10 — Auditor read-only role + TOTP authenticator MFA
# ═════════════════════════════════════════════════════════════════════════════

def _roles_migration(conn):
    """Allow the 'Auditor' role in users.role. The CHECK constraint is edited
    IN PLACE via writable_schema (no table rebuild, no data movement — a prior
    rebuild approach proved destructive under WAL). Idempotent; verified with
    integrity_check; fail-safe."""
    import sys as _sys
    try:
        row = conn.execute("SELECT sql FROM sqlite_master WHERE type='table' AND name='users'").fetchone()
        sql = (row[0] or '') if row else ''
        if not sql or "'Auditor'" in sql or "'Project Leader'" not in sql:
            return
        sv = conn.execute('PRAGMA schema_version').fetchone()[0]
        conn.execute('PRAGMA writable_schema=ON')
        conn.execute("UPDATE sqlite_master SET sql=replace(sql, \"'Project Leader'\", \"'Project Leader','Auditor'\") WHERE type='table' AND name='users'")
        conn.execute('PRAGMA writable_schema=OFF')
        conn.execute('PRAGMA schema_version=%d' % (int(sv) + 1))
        conn.commit()
        chk = conn.execute('PRAGMA integrity_check').fetchone()[0]
        if chk != 'ok':
            print('roles migration integrity check:', chk, file=_sys.stderr); _sys.stderr.flush()
        else:
            print('users.role CHECK extended: Auditor role enabled', file=_sys.stderr); _sys.stderr.flush()
    except Exception as exc:
        try: conn.rollback()
        except Exception: pass
        print('roles migration warning:', exc, file=_sys.stderr); _sys.stderr.flush()

def _totp_new_secret():
    import base64 as _b, os as _os
    return _b.b32encode(_os.urandom(20)).decode('ascii').rstrip('=')


def _totp_code_at(secret, counter):
    import base64 as _b, hmac as _h, hashlib as _hl, struct as _s
    pad = '=' * ((8 - len(secret) % 8) % 8)
    key = _b.b32decode((secret + pad).upper())
    msg = _s.pack('>Q', counter)
    dig = _h.new(key, msg, _hl.sha1).digest()
    off = dig[-1] & 0x0F
    val = (_s.unpack('>I', dig[off:off + 4])[0] & 0x7FFFFFFF) % 1000000
    return '%06d' % val


def _totp_check(secret, code):
    import time as _t
    code = str(code or '').strip().replace(' ', '')
    if not (secret and code.isdigit() and len(code) == 6):
        return False
    ctr = int(_t.time() // 30)
    for off in (-1, 0, 1):
        try:
            if _totp_code_at(secret, ctr + off) == code:
                return True
        except Exception:
            return False
    return False


def _mfa_totp_column(conn):
    try:
        conn.execute("ALTER TABLE mfa_settings ADD COLUMN totp_secret TEXT")
        conn.commit()
    except Exception:
        pass


def api_mfa_totp_setup(data, session):
    """POST /api/mfa/totp-setup {user_id?} — generate (or regenerate) a TOTP
    secret for yourself, or — Admin only — for another user. The secret only
    takes effect after totp-confirm proves the authenticator works (so nobody
    can be locked out by a half-finished setup)."""
    if not session: return err('Not authenticated')
    _v42_migration()
    conn = get_db()
    try:
        _mfa_totp_column(conn)
        target = (data.get('user_id') or '').strip() or session.get('id')
        if target != session.get('id') and session.get('role') != 'Admin':
            return err('Only an Admin can set up MFA for another user')
        u = conn.execute("SELECT id, username FROM users WHERE id=?", (target,)).fetchone()
        if not u: return err('User not found')
        secret = _totp_new_secret()
        conn.execute("INSERT INTO mfa_settings(user_id, enabled, delivery, totp_secret, updated_by) VALUES(?,COALESCE((SELECT enabled FROM mfa_settings WHERE user_id=?),0),'totp',?,?) "
                     "ON CONFLICT(user_id) DO UPDATE SET totp_secret=excluded.totp_secret, updated_by=excluded.updated_by, updated_at=datetime('now')",
                     (target, target, secret, session.get('username', '')))
        _v42_audit(conn, session, 'MFA_TOTP_SETUP', 'security', target, 'TOTP secret generated for %s (pending confirmation)' % u['username'])
        conn.commit()
        issuer = (V42_APP_NAME or 'ERP').replace(' ', '%20')
        return ok({'user_id': target, 'username': u['username'], 'secret': secret,
                   'otpauth': 'otpauth://totp/%s:%s?secret=%s&issuer=%s&algorithm=SHA1&digits=6&period=30' % (
                       issuer, u['username'], secret, issuer),
                   'message': 'Scan/enter the secret in your authenticator app, then confirm with a code.'})
    finally:
        conn.close()


def api_mfa_totp_confirm(data, session):
    """POST /api/mfa/totp-confirm {user_id?, code} — verify a code from the
    authenticator; on success switch the user to TOTP delivery and enable MFA."""
    if not session: return err('Not authenticated')
    _v42_migration()
    conn = get_db()
    try:
        _mfa_totp_column(conn)
        target = (data.get('user_id') or '').strip() or session.get('id')
        if target != session.get('id') and session.get('role') != 'Admin':
            return err('Only an Admin can confirm MFA for another user')
        row = conn.execute("SELECT totp_secret FROM mfa_settings WHERE user_id=?", (target,)).fetchone()
        if not (row and row['totp_secret']): return err('Run TOTP setup first')
        if not _totp_check(row['totp_secret'], data.get('code')):
            return err('Invalid authenticator code — check the app and try again')
        conn.execute("UPDATE mfa_settings SET enabled=1, delivery='totp', updated_at=datetime('now'), updated_by=? WHERE user_id=?",
                     (session.get('username', ''), target))
        _v42_audit(conn, session, 'MFA_TOTP_ENABLED', 'security', target, 'Authenticator (TOTP) MFA enabled')
        conn.commit()
        return ok({'enabled': True, 'message': 'Authenticator MFA is now active for this account. Next login requires a 6-digit code.'})
    finally:
        conn.close()


