# ═════════════════════════════════════════════════════════════════════════════
# REVERSAL DATING TOOLS 2026-06-11 — re-date a reversal journal + flag backfill
# ═════════════════════════════════════════════════════════════════════════════

def _backfill_reversal_flags(conn):
    """Older edit-reversals were posted without is_reversal=1, hiding them from
    the Reversals Register and the tax-pack netting. Idempotent backfill."""
    try:
        cur = conn.execute("UPDATE journal_vouchers SET is_reversal=1 "
                           "WHERE jv_number LIKE 'RJV-%' AND COALESCE(is_reversal,0)=0")
        n1 = cur.rowcount or 0
        # resolve reversal_of links from the narration where missing (older reversals)
        import re as _re
        n2 = 0
        for r in conn.execute("SELECT id, description FROM journal_vouchers "
                              "WHERE COALESCE(is_reversal,0)=1 AND reversal_of IS NULL").fetchall():
            m = _re.search(r'[Rr]eversal of ([A-Z0-9/\-]+)', r['description'] or '')
            if not m:
                continue
            o = conn.execute("SELECT id FROM journal_vouchers WHERE jv_number=?", (m.group(1),)).fetchone()
            if o:
                conn.execute("UPDATE journal_vouchers SET reversal_of=? WHERE id=?", (o['id'], r['id']))
                n2 += 1
        if n1 or n2:
            conn.commit()
            import sys as _sys
            print('reversal backfill: %d flag(s), %d link(s)' % (n1, n2), file=_sys.stderr); _sys.stderr.flush()
    except Exception:
        try: conn.rollback()
        except Exception: pass


def api_redate_reversal(data, session):
    """POST /api/journals/redate {jv_number, new_date?, reason} — Admin-only.
    Moves a POSTED REVERSAL journal (and its ledger lines) to a different date,
    typically the ORIGINAL transaction's date, so the reversal cancels the
    error in the month it happened instead of distorting a later month's cash
    book. If new_date is omitted it defaults to the reversed journal's own
    date. Audit-logged; the target period must be open."""
    if not session: return err('Not authenticated')
    if session.get('role') != 'Admin': return err('Admin access required')
    jvn = (data.get('jv_number') or '').strip()
    actual_id = (data.get('actual_id') or '').strip()
    reason = (data.get('reason') or '').strip()
    if len(reason) < 5: return err('A reason of at least 5 characters is required (kept in the audit trail)')
    conn = get_db()
    try:
        src_actual = None
        if actual_id and not jvn:
            src_actual = conn.execute("SELECT * FROM actuals WHERE id=?", (actual_id,)).fetchone()
            if not src_actual: return err('Transaction not found')
            src_actual = dict(src_actual)
            jvrow = conn.execute("SELECT jv_number FROM journal_vouchers WHERE id=?", (src_actual.get('jv_id'),)).fetchone()
            if not jvrow: return err('This voucher has no posted journal to re-date')
            jvn = jvrow['jv_number']
        if not jvn: return err('jv_number or actual_id is required')
        jv = conn.execute("SELECT * FROM journal_vouchers WHERE jv_number=?", (jvn,)).fetchone()
        if not jv: return err('Journal %s not found' % jvn)
        jv = dict(jv)
        if jv.get('status') != 'Posted':
            return err('Only a POSTED journal can be re-dated (this one is %s)' % jv.get('status'))
        _is_rev = (int(jv.get('is_reversal') or 0) == 1 or jvn.startswith('RJV'))
        _is_voucher = False
        if not _is_rev and jv.get('source_module') == 'actuals' and jv.get('source_id'):
            _cur = conn.execute("SELECT * FROM actuals WHERE id=? AND jv_id=?", (jv.get('source_id'), jv.get('id'))).fetchone()
            if _cur:
                src_actual = dict(_cur)
                _is_voucher = True
        if not (_is_rev or _is_voucher):
            return err('Re-dating is allowed for reversal journals and for a voucher\'s own ACTIVE posting — other journals are immutable')
        if _is_voucher and not (data.get('new_date') or '').strip():
            return err('Pass new_date (YYYY-MM-DD) — the corrected transaction date')
        new_date = (data.get('new_date') or '').strip()[:10]
        if not new_date:
            orig = None
            if jv.get('reversal_of'):
                orig = conn.execute("SELECT jv_date FROM journal_vouchers WHERE id=?", (jv.get('reversal_of'),)).fetchone()
            if not orig:
                import re as _re
                m = _re.search(r'[Rr]eversal of ([A-Z0-9/\-]+)', jv.get('description') or '')
                if m:
                    orig = conn.execute("SELECT jv_date FROM journal_vouchers WHERE jv_number=?", (m.group(1),)).fetchone()
            if orig and orig['jv_date']:
                new_date = str(orig['jv_date'])[:10]
            else:
                return err('Could not resolve the original transaction date — pass new_date explicitly')
        import re as _re2
        if not _re2.match(r'^\d{4}-\d{2}-\d{2}$', new_date):
            return err('new_date must be YYYY-MM-DD')
        old_period = str(jv.get('period') or '')
        new_period = new_date[:7] if len(old_period) == 7 else (new_date[:4] if len(old_period) == 4 else new_date[:7])
        pr = conn.execute("SELECT status FROM accounting_periods WHERE period=?", (new_period,)).fetchone()
        if pr and (pr['status'] or 'Open') != 'Open':
            return err('Accounting period %s is %s — re-open it before re-dating into it' % (new_period, pr['status']))
        old_date = str(jv.get('jv_date') or '')[:10]
        conn.execute("UPDATE journal_vouchers SET jv_date=?, period=? WHERE id=?", (new_date, new_period, jv['id']))
        moved = conn.execute("UPDATE general_ledger SET ledger_date=?, period=? WHERE jv_id=? OR jv_number=?",
                             (new_date, new_period, jv['id'], jvn)).rowcount
        if _is_voucher and src_actual:
            _acols = [c[1] for c in conn.execute("PRAGMA table_info(actuals)").fetchall()]
            _sets = ["expense_date=?"]; _vals = [new_date]
            if 'payment_date' in _acols:
                _sets.append("payment_date=?"); _vals.append(new_date)
            conn.execute("UPDATE actuals SET %s WHERE id=?" % ', '.join(_sets), _vals + [src_actual['id']])
            try:
                _sync_withholding_payables_for_actual(conn, session, src_actual['id'])
            except Exception:
                pass
        _audit(conn, session, 'REDATE_REVERSAL', 'journal_vouchers', jv['id'],
               '%s re-dated %s -> %s (period %s -> %s), %d ledger line(s). Reason: %s' % (
                   jvn, old_date, new_date, old_period, new_period, moved, reason))
        conn.commit()
        return ok({'jv_number': jvn, 'old_date': old_date, 'new_date': new_date,
                   'old_period': old_period, 'new_period': new_period, 'ledger_lines_moved': moved,
                   'message': '%s moved from %s to %s — the cash book now reflects the correction in the right month' % (jvn, old_date, new_date)})
    finally:
        conn.close()


# ═════════════════════════════════════════════════════════════════════════════
# PETTY CASH 2.0 (2026-06-11) — full imprest system wired to the general ledger
# Float establishment: Dr Petty Cash (12x) / Cr Bank
# Voucher (disbursement): Dr Expense / Cr Petty Cash   (continuous method —
#   the petty-cash GL balance is live, so SFP/cash book/TB always tie)
# Replenishment: Dr Petty Cash / Cr Bank (top-up to the imprest level)
# Count & reconciliation: physical cash vs book; variance optionally posted.
# ═════════════════════════════════════════════════════════════════════════════

def _pc2_migration(conn):
    conn.execute("""CREATE TABLE IF NOT EXISTS petty_cash_floats (
        id TEXT PRIMARY KEY, name TEXT NOT NULL, custodian TEXT DEFAULT '',
        imprest_amount REAL NOT NULL DEFAULT 0, coa_id TEXT, bank_account_id TEXT,
        established_date TEXT, jv_number TEXT, status TEXT DEFAULT 'Active',
        created_by TEXT, created_at TEXT DEFAULT (datetime('now')))""")
    conn.execute("""CREATE TABLE IF NOT EXISTS petty_cash_vouchers (
        id TEXT PRIMARY KEY, float_id TEXT NOT NULL, pcv_number TEXT,
        voucher_date TEXT NOT NULL, payee TEXT NOT NULL, description TEXT DEFAULT '',
        expense_coa_id TEXT NOT NULL, amount_ghs REAL NOT NULL,
        receipt_ref TEXT DEFAULT '', status TEXT DEFAULT 'Posted',
        jv_id TEXT, jv_number TEXT, created_by TEXT, created_at TEXT DEFAULT (datetime('now')))""")
    conn.execute("""CREATE TABLE IF NOT EXISTS petty_cash_replenishments (
        id TEXT PRIMARY KEY, float_id TEXT NOT NULL, repl_date TEXT NOT NULL,
        amount_ghs REAL NOT NULL, bank_account_id TEXT, jv_id TEXT, jv_number TEXT,
        created_by TEXT, created_at TEXT DEFAULT (datetime('now')))""")
    conn.execute("""CREATE TABLE IF NOT EXISTS petty_cash_counts (
        id TEXT PRIMARY KEY, float_id TEXT NOT NULL, count_date TEXT NOT NULL,
        counted_cash REAL NOT NULL, book_balance REAL NOT NULL, variance REAL NOT NULL,
        notes TEXT DEFAULT '', variance_jv_number TEXT,
        created_by TEXT, created_at TEXT DEFAULT (datetime('now')))""")
    conn.execute("""CREATE TABLE IF NOT EXISTS petty_cash_voucher_lines (
        id TEXT PRIMARY KEY, voucher_id TEXT NOT NULL, line_no INTEGER DEFAULT 0,
        expense_coa_id TEXT NOT NULL, amount_ghs REAL NOT NULL, description TEXT DEFAULT '',
        created_at TEXT DEFAULT (datetime('now')))""")
    for _ddl in ("ALTER TABLE petty_cash_floats ADD COLUMN department_code TEXT",
                 "ALTER TABLE petty_cash_floats ADD COLUMN project_id TEXT",
                 "ALTER TABLE petty_cash_vouchers ADD COLUMN department_code TEXT",
                 "ALTER TABLE petty_cash_vouchers ADD COLUMN project_id TEXT"):
        try: conn.execute(_ddl)
        except Exception: pass
    _pc2_cleanup_auto_coa(conn)


def _pc2_coa(conn, coa_id=None):
    """Resolve the GL account a petty-cash float lives on. The OFFICIAL UCC
    chart carries a 129x 'Imprest - …' family — that is the preferred home
    (selected per float). Falls back to any imprest/petty account; only
    creates one as a last resort."""
    if coa_id:
        r = conn.execute("SELECT id, code FROM chart_of_accounts WHERE id=?", (coa_id,)).fetchone()
        if r and (str(r['code'] or '').startswith('12') or str(r['code'] or '') == '1001'):
            return r['id']
    r = conn.execute("SELECT id FROM chart_of_accounts WHERE LOWER(account_name) LIKE '%imprest%' "
                     "AND code LIKE '129%' ORDER BY CASE WHEN LOWER(account_name) LIKE '%other%' THEN 0 ELSE 1 END, code LIMIT 1").fetchone()
    if r: return r['id']
    r = conn.execute("SELECT id FROM chart_of_accounts WHERE (LOWER(account_name) LIKE '%imprest%' "
                     "OR LOWER(account_name) LIKE '%petty%') AND code LIKE '12%' ORDER BY code LIMIT 1").fetchone()
    if r: return r['id']
    import uuid as _u
    n = 12901001
    while conn.execute("SELECT 1 FROM chart_of_accounts WHERE code=?", (str(n),)).fetchone():
        n += 1
    cid = str(_u.uuid4())
    conn.execute("INSERT INTO chart_of_accounts(id,code,category,sub_category,account_name,account_type,vat_applicable) "
                 "VALUES(?,?,?,?,?,?,0)", (cid, str(n), 'Assets', 'Imprest', 'Imprest - Petty Cash', 'Asset'))
    return cid


def _pc2_cleanup_auto_coa(conn):
    """Remove the earlier auto-created 'Petty Cash (Imprest)' account when it
    is unused (no ledger lines, no float) so the chart stays official."""
    try:
        r = conn.execute("SELECT id FROM chart_of_accounts WHERE account_name='Petty Cash (Imprest)'").fetchone()
        if not r: return
        used = conn.execute("SELECT 1 FROM general_ledger WHERE coa_id=? LIMIT 1", (r['id'],)).fetchone()
        if not used:
            used = conn.execute("SELECT 1 FROM petty_cash_floats WHERE coa_id=? LIMIT 1", (r['id'],)).fetchone()
        if not used:
            conn.execute("DELETE FROM chart_of_accounts WHERE id=?", (r['id'],))
            conn.commit()
    except Exception:
        try: conn.rollback()
        except Exception: pass


def _pc2_book_balance(conn, float_id):
    f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (float_id,)).fetchone()
    if not f: return 0.0
    est = float(f['imprest_amount'] or 0) if f['jv_number'] else 0.0
    repl = float(conn.execute("SELECT COALESCE(SUM(amount_ghs),0) FROM petty_cash_replenishments WHERE float_id=?", (float_id,)).fetchone()[0] or 0)
    vch = float(conn.execute("SELECT COALESCE(SUM(amount_ghs),0) FROM petty_cash_vouchers WHERE float_id=? AND status='Posted'", (float_id,)).fetchone()[0] or 0)
    return round(est + repl - vch, 2)


def api_pc2_state(session):
    """GET /api/petty-cash2 — floats with book balances, GL balance of the petty
    account (tie check), and recent vouchers/replenishments/counts."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _pc2_migration(conn)
        floats = [dict(r) for r in conn.execute("SELECT * FROM petty_cash_floats ORDER BY created_at").fetchall()]
        for f in floats:
            f['book_balance'] = _pc2_book_balance(conn, f['id'])
        # GL balance of the imprest account(s) actually in use — sum across every
        # float's own imprest GL (each department's float lives on its own account),
        # so the tie check is correct when several departmental imprests run at once.
        _float_coas = list({f.get('coa_id') for f in floats if f.get('coa_id')})
        if _float_coas:
            _qm = ','.join('?' * len(_float_coas))
            glr = conn.execute("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) "
                               "FROM general_ledger WHERE coa_id IN (" + _qm + ")", _float_coas).fetchone()
        else:
            glr = conn.execute("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) "
                               "FROM general_ledger WHERE coa_id=?", (_pc2_coa(conn),)).fetchone()
        gl_balance = round(float(glr[0] or 0), 2)
        vouchers = [dict(r) for r in conn.execute(
            "SELECT v.*, c.code AS coa_code, c.account_name FROM petty_cash_vouchers v "
            "LEFT JOIN chart_of_accounts c ON c.id=v.expense_coa_id ORDER BY v.voucher_date DESC, v.created_at DESC LIMIT 100").fetchall()]
        # attach the per-voucher expense lines (multi-line disbursements)
        for _v in vouchers:
            _v['lines'] = [dict(r) for r in conn.execute(
                "SELECT vl.line_no, vl.expense_coa_id, vl.amount_ghs, vl.description, "
                "c.code AS coa_code, c.account_name FROM petty_cash_voucher_lines vl "
                "LEFT JOIN chart_of_accounts c ON c.id=vl.expense_coa_id "
                "WHERE vl.voucher_id=? ORDER BY vl.line_no", (_v['id'],)).fetchall()]
        # all imprest GL accounts (official 129x family + any imprest/petty-named
        # asset account) so every department — incl. the Dean's office — can pick its own
        imprest_accounts = [dict(r) for r in conn.execute(
            "SELECT id, code, account_name FROM chart_of_accounts "
            "WHERE (code LIKE '129%' OR LOWER(account_name) LIKE '%imprest%' OR LOWER(account_name) LIKE '%petty%') "
            "AND code LIKE '12%' ORDER BY code").fetchall()]
        repls = [dict(r) for r in conn.execute("SELECT * FROM petty_cash_replenishments ORDER BY repl_date DESC LIMIT 30").fetchall()]
        counts = [dict(r) for r in conn.execute("SELECT * FROM petty_cash_counts ORDER BY count_date DESC LIMIT 30").fetchall()]
        legacy = conn.execute("SELECT COUNT(*) FROM petty_cash").fetchone()[0] if conn.execute(
            "SELECT 1 FROM sqlite_master WHERE type='table' AND name='petty_cash'").fetchone() else 0
        total_book = round(sum(f['book_balance'] for f in floats), 2)
        return ok({'floats': floats, 'gl_balance': gl_balance, 'total_book_balance': total_book,
                   'gl_tie_ok': abs(gl_balance - total_book) < 0.01,
                   'vouchers': vouchers, 'replenishments': repls, 'counts': counts, 'imprest_accounts': imprest_accounts,
                   'legacy_entries': int(legacy)})
    finally:
        conn.close()


def api_pc2_setup_float(data, session):
    """POST /api/petty-cash2/float — establish (or top up the imprest of) a
    petty cash float: Dr Petty Cash / Cr Bank for the imprest amount."""
    if not session: return err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return err('Admin or Finance Officer role required')
    name = (data.get('name') or 'Main Petty Cash').strip()
    custodian = (data.get('custodian') or '').strip()
    try:
        imprest = round(float(data.get('imprest_amount')), 2)
    except Exception:
        return err('imprest_amount must be a number')
    if imprest <= 0: return err('The imprest amount must be greater than zero')
    bank_id = data.get('bank_account_id')
    if not bank_id: return err('Select the bank account funding the float')
    dept = (data.get('department_code') or data.get('department') or data.get('unit_code') or '').strip()
    if not dept and not data.get('project_id'):
        return err('Tie the float to a department/unit (or a project) — a custodian name alone is not enough for accountability')
    from datetime import date as _d
    edate = (data.get('date') or _d.today().isoformat())[:10]
    conn = get_db()
    try:
        _pc2_migration(conn)
        pc_coa = _pc2_coa(conn, data.get('coa_id'))
        bank_coa = _ar_bank_coa(conn, bank_id)
        if not bank_coa: return err('The selected bank account has no linked GL account')
        import uuid as _u
        fid = str(_u.uuid4())
        lines = [{'coa_id': pc_coa, 'debit_amount': imprest, 'credit_amount': 0,
                  'description': 'Petty cash float established — %s (%s)' % (name, custodian or 'no custodian')},
                 {'coa_id': bank_coa, 'debit_amount': 0, 'credit_amount': imprest,
                  'description': 'Cash drawn for petty cash float %s' % name}]
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', edate,
                'Petty cash float establishment — %s%s' % (name, (' [' + dept + ']') if dept else ''),
                name, data.get('project_id'), bank_id, 'petty_cash_float', fid, lines)
        except Exception as e:
            return err('Could not post the float establishment: %s' % e)
        conn.execute("INSERT INTO petty_cash_floats(id,name,custodian,imprest_amount,coa_id,bank_account_id,established_date,jv_number,created_by,department_code,project_id) "
                     "VALUES(?,?,?,?,?,?,?,?,?,?,?)",
                     (fid, name, custodian, imprest, pc_coa, bank_id, edate, jv_num, session.get('username', ''),
                      dept, data.get('project_id')))
        _audit(conn, session, 'PETTY_FLOAT_SETUP', 'petty_cash_floats', fid,
               '%s GHS %.2f custodian %s (%s)' % (name, imprest, custodian, jv_num))
        conn.commit()
        return ok({'id': fid, 'jv_number': jv_num,
                   'message': 'Float "%s" established at GHS %.2f (%s)' % (name, imprest, jv_num)})
    finally:
        conn.close()


def api_pc2_voucher(data, session):
    """POST /api/petty-cash2/voucher — petty-cash disbursement, now MULTI-LINE.
    A single disbursement can be split across several expense accounts:
    Dr Expense 1, Dr Expense 2, … / Cr the float's imprest account (one credit
    for the total). Blocks spending beyond the cash on hand. Backward-compatible
    with the old single {expense_coa_id, amount_ghs} shape."""
    if not session: return err('Not authenticated')
    float_id = data.get('float_id')
    payee = (data.get('payee') or '').strip()
    if not float_id: return err('Select the imprest / float this voucher is drawn from')
    if not payee: return err('Who was paid? Enter the payee')
    # normalise lines: prefer an explicit lines[] array, else the legacy single pair
    raw = data.get('lines')
    norm = []
    if isinstance(raw, list) and raw:
        for ln in raw:
            try: a = round(float(ln.get('amount_ghs') or ln.get('amount') or 0), 2)
            except Exception: a = 0
            coa = ln.get('expense_coa_id') or ln.get('coa_id')
            if a > 0 and coa:
                norm.append({'coa_id': coa, 'amount': a, 'description': (ln.get('description') or '').strip()})
        if not norm:
            return err('Add at least one expense line (account + amount greater than zero)')
    else:
        exp = data.get('expense_coa_id')
        try: a = round(float(data.get('amount_ghs')), 2)
        except Exception: return err('amount_ghs must be a number')
        if not exp: return err('Select the expense account this spending belongs to')
        if a <= 0: return err('Amount must be greater than zero')
        norm = [{'coa_id': exp, 'amount': a, 'description': (data.get('description') or '').strip()}]
    total = round(sum(l['amount'] for l in norm), 2)
    if total <= 0: return err('The total disbursement must be greater than zero')
    from datetime import date as _d
    vdate = (data.get('voucher_date') or _d.today().isoformat())[:10]
    conn = get_db()
    try:
        _pc2_migration(conn)
        f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (float_id,)).fetchone()
        if not f: return err('Petty cash float not found')
        f = dict(f)
        dept = (data.get('department_code') or data.get('department') or f.get('department_code') or '').strip()
        proj = data.get('project_id') or f.get('project_id')
        bal = _pc2_book_balance(conn, float_id)
        if total > bal + 0.005:
            return err('Insufficient petty cash: float "%s" holds GHS %.2f, this voucher totals GHS %.2f. Replenish first.' % (f['name'], bal, total))
        for l in norm:
            if not conn.execute("SELECT 1 FROM chart_of_accounts WHERE id=?", (l['coa_id'],)).fetchone():
                return err('An expense account on one of the lines was not found')
        imprest_coa = f['coa_id'] or _pc2_coa(conn)
        import uuid as _u
        vid = str(_u.uuid4())
        from datetime import datetime as _dt
        pcv = _seq_code(conn, 'petty_cash_vouchers', 'pcv_number', 'PCV-%d-' % _dt.now().year, 4)
        hdr = 'Petty cash: %s — %s' % (payee, (data.get('description') or '').strip() or 'sundry expenses')
        lines = []
        for l in norm:
            lines.append({'coa_id': l['coa_id'], 'debit_amount': l['amount'], 'credit_amount': 0,
                          'description': (l['description'] or hdr) + ((' [' + dept + ']') if dept else ''),
                          'project_id': proj})
        lines.append({'coa_id': imprest_coa, 'debit_amount': 0, 'credit_amount': total,
                      'description': 'Petty cash paid out (%s)' % pcv, 'project_id': proj})
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', vdate, hdr, pcv,
                                                   proj, None, 'petty_cash_vouchers', vid, lines)
        except Exception as e:
            return err('Could not post the voucher: %s' % e)
        conn.execute("INSERT INTO petty_cash_vouchers(id,float_id,pcv_number,voucher_date,payee,description,"
                     "expense_coa_id,amount_ghs,receipt_ref,status,jv_id,jv_number,created_by,department_code,project_id) "
                     "VALUES(?,?,?,?,?,?,?,?,?,'Posted',?,?,?,?,?)",
                     (vid, float_id, pcv, vdate, payee, (data.get('description') or '').strip(),
                      norm[0]['coa_id'], total, (data.get('receipt_ref') or '').strip(), jv_id, jv_num,
                      session.get('username', ''), dept, proj))
        for i, l in enumerate(norm):
            conn.execute("INSERT INTO petty_cash_voucher_lines(id,voucher_id,line_no,expense_coa_id,amount_ghs,description) "
                         "VALUES(?,?,?,?,?,?)", (str(_u.uuid4()), vid, i + 1, l['coa_id'], l['amount'], l['description']))
        _audit(conn, session, 'PETTY_VOUCHER', 'petty_cash_vouchers', vid,
               '%s %s GHS %.2f, %d line(s) (%s)' % (pcv, payee, total, len(norm), jv_num))
        conn.commit()
        return ok({'id': vid, 'pcv_number': pcv, 'jv_number': jv_num, 'lines': len(norm), 'total_ghs': total,
                   'balance_after': _pc2_book_balance(conn, float_id),
                   'message': '%s posted — GHS %.2f to %s across %d line(s)' % (pcv, total, payee, len(norm))})
    finally:
        conn.close()


def api_pc2_replenish(data, session):
    """POST /api/petty-cash2/replenish — top the float back up to its imprest
    level (or a chosen amount): Dr Petty Cash / Cr Bank."""
    if not session: return err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return err('Admin or Finance Officer role required')
    float_id = data.get('float_id')
    if not float_id: return err('float_id is required')
    bank_id = data.get('bank_account_id')
    from datetime import date as _d
    rdate = (data.get('date') or _d.today().isoformat())[:10]
    conn = get_db()
    try:
        _pc2_migration(conn)
        f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (float_id,)).fetchone()
        if not f: return err('Petty cash float not found')
        bank_id = bank_id or f['bank_account_id']
        if not bank_id: return err('Select the bank account funding the replenishment')
        bal = _pc2_book_balance(conn, float_id)
        amt = data.get('amount_ghs')
        amt = round(float(amt), 2) if amt not in (None, '') else round(float(f['imprest_amount'] or 0) - bal, 2)
        if amt <= 0: return err('The float already stands at or above its imprest level (balance GHS %.2f)' % bal)
        bank_coa = _ar_bank_coa(conn, bank_id)
        if not bank_coa: return err('The selected bank account has no linked GL account')
        import uuid as _u
        rid = str(_u.uuid4())
        lines = [{'coa_id': f['coa_id'] or _pc2_coa(conn), 'debit_amount': amt, 'credit_amount': 0,
                  'description': 'Petty cash replenishment — %s' % f['name']},
                 {'coa_id': bank_coa, 'debit_amount': 0, 'credit_amount': amt,
                  'description': 'Cash drawn to replenish %s' % f['name']}]
        try:
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', rdate,
                'Petty cash replenishment — %s' % f['name'], f['name'], None, bank_id,
                'petty_cash_replenishments', rid, lines)
        except Exception as e:
            return err('Could not post the replenishment: %s' % e)
        conn.execute("INSERT INTO petty_cash_replenishments(id,float_id,repl_date,amount_ghs,bank_account_id,jv_id,jv_number,created_by) "
                     "VALUES(?,?,?,?,?,?,?,?)",
                     (rid, float_id, rdate, amt, bank_id, jv_id, jv_num, session.get('username', '')))
        _audit(conn, session, 'PETTY_REPLENISH', 'petty_cash_replenishments', rid,
               '%s GHS %.2f (%s)' % (f['name'], amt, jv_num))
        conn.commit()
        return ok({'id': rid, 'jv_number': jv_num, 'amount_ghs': amt,
                   'balance_after': _pc2_book_balance(conn, float_id),
                   'message': 'Replenished GHS %.2f — float back to GHS %.2f' % (amt, _pc2_book_balance(conn, float_id))})
    finally:
        conn.close()


def api_pc2_reconcile(data, session):
    """POST /api/petty-cash2/reconcile — record a physical cash count against
    the book balance. A shortage/overage can optionally be posted to the GL
    (Dr Other Expenses for a shortage / Cr Other Income for an overage)."""
    if not session: return err('Not authenticated')
    float_id = data.get('float_id')
    if not float_id: return err('float_id is required')
    try:
        counted = round(float(data.get('counted_cash')), 2)
    except Exception:
        return err('counted_cash must be a number')
    from datetime import date as _d
    cdate = (data.get('date') or _d.today().isoformat())[:10]
    conn = get_db()
    try:
        _pc2_migration(conn)
        f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (float_id,)).fetchone()
        if not f: return err('Petty cash float not found')
        book = _pc2_book_balance(conn, float_id)
        variance = round(counted - book, 2)
        import uuid as _u
        cid = str(_u.uuid4())
        vjv = None
        if abs(variance) >= 0.01 and data.get('post_variance'):
            pc_coa = f['coa_id'] or _pc2_coa(conn)
            if variance < 0:
                other = conn.execute("SELECT id FROM chart_of_accounts WHERE code='61800003' OR (code LIKE '618%' AND LOWER(account_name) LIKE '%other%') ORDER BY code LIMIT 1").fetchone()
                if not other:
                    other = conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '6%' ORDER BY code LIMIT 1").fetchone()
                lines = [{'coa_id': other['id'], 'debit_amount': abs(variance), 'credit_amount': 0,
                          'description': 'Petty cash shortage on count — %s' % f['name']},
                         {'coa_id': pc_coa, 'debit_amount': 0, 'credit_amount': abs(variance),
                          'description': 'Petty cash written down to counted cash'}]
            else:
                inc = conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '42%' AND LOWER(account_name) LIKE '%other%' ORDER BY code LIMIT 1").fetchone()
                if not inc:
                    inc = conn.execute("SELECT id FROM chart_of_accounts WHERE code LIKE '4%' ORDER BY code LIMIT 1").fetchone()
                lines = [{'coa_id': pc_coa, 'debit_amount': variance, 'credit_amount': 0,
                          'description': 'Petty cash overage on count — %s' % f['name']},
                         {'coa_id': inc['id'], 'debit_amount': 0, 'credit_amount': variance,
                          'description': 'Cash overage recognised'}]
            try:
                _jvid, vjv = _create_posted_journal(conn, session, 'JV', cdate,
                    'Petty cash count variance — %s' % f['name'], f['name'], None, None,
                    'petty_cash_counts', cid, lines)
                conn.execute("UPDATE petty_cash_vouchers SET id=id WHERE 0")
            except Exception as e:
                return err('Could not post the variance: %s' % e)
        conn.execute("INSERT INTO petty_cash_counts(id,float_id,count_date,counted_cash,book_balance,variance,notes,variance_jv_number,created_by) "
                     "VALUES(?,?,?,?,?,?,?,?,?)",
                     (cid, float_id, cdate, counted, book, variance, (data.get('notes') or '').strip(), vjv, session.get('username', '')))
        _audit(conn, session, 'PETTY_COUNT', 'petty_cash_counts', cid,
               '%s counted GHS %.2f vs book GHS %.2f (variance %.2f)%s' % (f['name'], counted, book, variance, (' posted ' + vjv) if vjv else ''))
        conn.commit()
        return ok({'id': cid, 'book_balance': book, 'counted_cash': counted, 'variance': variance,
                   'variance_jv_number': vjv,
                   'message': ('Count recorded — cash agrees with the book balance' if abs(variance) < 0.01 else
                               'Count recorded — variance of GHS %.2f %s' % (abs(variance), '(shortage)' if variance < 0 else '(overage)'))})
    finally:
        conn.close()


def api_pc2_ledger(session, float_id=None):
    """GET /api/petty-cash2/ledger?float_id= — chronological imprest ledger with
    running balance (establishment, vouchers out, replenishments in, counts)."""
    if not session: return err('Not authenticated')
    conn = get_db()
    try:
        _pc2_migration(conn)
        f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (float_id,)).fetchone() if float_id else             conn.execute("SELECT * FROM petty_cash_floats ORDER BY created_at LIMIT 1").fetchone()
        if not f: return ok({'rows': [], 'float': None})
        fid = f['id']
        rows = []
        if f['jv_number']:
            rows.append({'date': f['established_date'], 'ref': f['jv_number'], 'type': 'Float established',
                         'detail': '%s (custodian: %s)' % (f['name'], f['custodian'] or '—'),
                         'inflow': float(f['imprest_amount'] or 0), 'outflow': 0.0})
        for r in conn.execute("SELECT * FROM petty_cash_replenishments WHERE float_id=?", (fid,)).fetchall():
            rows.append({'date': r['repl_date'], 'ref': r['jv_number'], 'type': 'Replenishment',
                         'detail': 'Top-up from bank', 'inflow': float(r['amount_ghs'] or 0), 'outflow': 0.0})
        for v in conn.execute("SELECT v.*, c.code AS coa_code FROM petty_cash_vouchers v LEFT JOIN chart_of_accounts c ON c.id=v.expense_coa_id WHERE v.float_id=? AND v.status='Posted'", (fid,)).fetchall():
            rows.append({'date': v['voucher_date'], 'ref': v['pcv_number'], 'type': 'Voucher',
                         'detail': '%s — %s (%s)' % (v['payee'], v['description'] or '', v['coa_code'] or ''),
                         'inflow': 0.0, 'outflow': float(v['amount_ghs'] or 0)})
        for cnt in conn.execute("SELECT * FROM petty_cash_counts WHERE float_id=?", (fid,)).fetchall():
            rows.append({'date': cnt['count_date'], 'ref': cnt['variance_jv_number'] or '—', 'type': 'Cash count',
                         'detail': 'Counted GHS %.2f vs book GHS %.2f (variance %.2f)' % (cnt['counted_cash'], cnt['book_balance'], cnt['variance']),
                         'inflow': 0.0, 'outflow': 0.0})
        rows.sort(key=lambda x: (str(x['date'] or ''), x['type'] != 'Float established'))
        bal = 0.0
        for r in rows:
            bal = round(bal + r['inflow'] - r['outflow'], 2)
            r['balance'] = bal
        return ok({'rows': rows, 'float': {'id': f['id'], 'name': f['name'], 'custodian': f['custodian'],
                   'imprest_amount': f['imprest_amount'], 'book_balance': _pc2_book_balance(conn, fid)}})
    finally:
        conn.close()


