# ── Multi-line PV EDITING (2026-06-12) ───────────────────────────────────────
def _ml_update_multiline(data, session):
    """Update a multi-line PV: replaces its payment lines, recomputes per-line
    taxes and header totals, and — when the voucher was already POSTED —
    auto-reverses the old journal and reposts the corrected one from the new
    lines (same immutable-ledger treatment as a single-line PV edit). The
    pending withholding payables are then re-synced IN PLACE (no duplicates)."""
    if not session: return err('Not authenticated')
    aid = data.get('id')
    conn = get_db()
    try:
        existing = conn.execute("SELECT * FROM actuals WHERE id=?", (aid,)).fetchone()
        if not existing: return err('Transaction not found')
        existing = dict(existing)
        if not _ml_has_lines(conn, aid):
            return err('This voucher has no payment lines — edit it with the normal payment form')
        was_posted = int(existing.get('is_posted') or 0) == 1
        edit_reason = (data.get('edit_reason') or data.get('reason') or '').strip()
        if was_posted:
            if (session.get('role') or '') != 'Admin':
                return err('Only an Admin can amend a POSTED voucher')
            if len(edit_reason) < 5:
                return err('Admin edit reason is required for posted transactions')
            try:
                _wp_paid = float((conn.execute("SELECT COALESCE(SUM(amount_ghs),0) FROM withholding_payables "
                                               "WHERE actual_id=? AND status='Paid'", (aid,)).fetchone() or [0])[0] or 0)
            except Exception:
                _wp_paid = 0
            if _wp_paid > 0.005:
                return err('Cannot amend this posted voucher — GHS %.2f of withholding tax on it has already '
                           'been remitted to the authority. Reverse that remittance first, then amend.' % _wp_paid)
        raw_lines = data.get('lines')
        if not (isinstance(raw_lines, list) and raw_lines):
            return err('Provide the corrected payment lines')
        import uuid as _u
        clean = []
        t_vat = t_whvat = t_ucf = t_wht = 0.0
        first_wht_rate = 0.0
        for i, ln in enumerate(raw_lines, 1):
            try:
                amt = round(float(ln.get('amount_ghs')), 2)
            except Exception:
                return err('Line %d: amount must be a number' % i)
            if amt <= 0: return err('Line %d: amount must be greater than zero' % i)
            coa_id = ln.get('coa_id')
            if not coa_id or not conn.execute("SELECT 1 FROM chart_of_accounts WHERE id=?", (coa_id,)).fetchone():
                return err('Line %d: select a valid account' % i)
            hv, hw, hu = int(ln.get('has_vat') or 0), int(ln.get('has_whvat') or 0), int(ln.get('has_ucf') or 0)
            wt = ln.get('wht_type') or 'None'
            tax = _compute_pv_tax(amt, hv, hw, hu, wt)
            if tax['wht_amount'] and not first_wht_rate:
                first_wht_rate = tax['wht_rate']
            t_vat += tax['vat_amount']; t_whvat += tax['whvat_amount']
            t_ucf += tax['ucf_amount']; t_wht += tax['wht_amount']
            clean.append({'coa_id': coa_id, 'description': (ln.get('description') or '').strip(),
                          'amount_ghs': amt, 'has_vat': hv, 'has_whvat': hw, 'has_ucf': hu, 'wht_type': wt,
                          'dept_code': (ln.get('dept_code') or ln.get('department_code') or '').strip(),
                          'project_id': ln.get('project_id') or existing.get('project_id'),
                          'budget_id': ln.get('budget_id'), **tax})
        total = round(sum(l['amount_ghs'] for l in clean), 2)
        payee = (data.get('payee') or existing.get('payee') or '').strip()
        desc = (data.get('description') or existing.get('description') or '').strip()
        edate = (data.get('expense_date') or existing.get('expense_date') or '')[:10]
        conn.execute("DELETE FROM actual_lines WHERE actual_id=?", (aid,))
        for n, l in enumerate(clean, 1):
            conn.execute("""INSERT INTO actual_lines(id,actual_id,line_no,project_id,dept_code,coa_id,description,
                amount_ghs,is_taxable,has_vat,has_whvat,has_ucf,wht_type,vat_amount,whvat_amount,ucf_amount,wht_amount,budget_id)
                VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (str(_u.uuid4()), aid, n, l['project_id'], l['dept_code'], l['coa_id'], l['description'],
                 l['amount_ghs'], 1 if (l['has_vat'] or l['has_whvat'] or l['has_ucf'] or l['wht_type'] != 'None') else 0,
                 l['has_vat'], l['has_whvat'], l['has_ucf'], l['wht_type'],
                 l['vat_amount'], l['whvat_amount'], l['ucf_amount'], l['wht_amount'], l['budget_id']))
        _acols = [c[1] for c in conn.execute("PRAGMA table_info(actuals)").fetchall()]
        sets = {'payee': payee, 'description': desc, 'expense_date': edate,
                'amount_fcy': total, 'amount_ghs': total,
                'vat_amount': round(t_vat, 2), 'whvat_amount': round(t_whvat, 2),
                'ucf_amount': round(t_ucf, 2), 'wht_amount': round(t_wht, 2),
                'has_vat': 1 if t_vat else 0, 'has_whvat': 1 if t_whvat else 0, 'has_ucf': 1 if t_ucf else 0,
                'wht_rate': first_wht_rate,
                'wht_type': next((l['wht_type'] for l in clean if l['wht_type'] != 'None'), 'None')}
        for opt in ('bank_account_id', 'payment_method', 'payment_reference', 'vendor_id', 'beneficiary_id', 'edit_reason'):
            if data.get(opt) is not None and opt in _acols:
                sets[opt] = data.get(opt) if opt != 'edit_reason' else edit_reason
        applicable = {k: v for k, v in sets.items() if k in _acols}
        conn.execute("UPDATE actuals SET " + ", ".join("%s=?" % k for k in applicable) + " WHERE id=?",
                     list(applicable.values()) + [aid])
        new_jv = None
        if was_posted:
            txn = dict(conn.execute("SELECT * FROM actuals WHERE id=?", (aid,)).fetchone())
            if '_reverse_voucher' in globals():
                _reverse_voucher(conn, session, existing.get('jv_id'), edit_reason or 'Multi-line correction')
                jv_id, new_jv = _insert_voucher_posted(conn, session, jv_type='PV', jv_date=txn['expense_date'],
                    description=f"Corrected payment: {txn['payee']} — {txn['description']} [voucher {txn['actual_code']} — replaces reversed entry]",
                    project_id=txn.get('project_id'), bank_account_id=txn.get('bank_account_id'),
                    source_module='actuals', source_id=aid,
                    reference=txn.get('payment_reference') or '', lines=_expense_lines_for_actual(conn, txn),
                    notes='Multi-line admin correction reposted after reversal')
                conn.execute("UPDATE actuals SET is_posted=1, jv_id=?, posted_by=?, posted_at=datetime('now') WHERE id=?",
                             (jv_id, session.get('username', ''), aid))
            else:
                _auto_reverse_posted_journal(conn, session, existing.get('jv_id'), 'actuals', aid, edit_reason)
                jv_id, new_jv = _post_actual_to_gl(conn, session, aid)
                try:
                    _amk = ' [voucher %s — replaces reversed entry]' % (existing.get('actual_code') or '')
                    conn.execute("UPDATE journal_vouchers SET description = description || ? WHERE id=?", (_amk, jv_id))
                    conn.execute("UPDATE general_ledger SET description = description || ? WHERE jv_id=?", (_amk, jv_id))
                except Exception:
                    pass
                conn.execute("UPDATE actuals SET is_posted=1, jv_id=?, posted_by=?, posted_at=datetime('now') WHERE id=?",
                             (jv_id, session.get('username', ''), aid))
            try:
                _sync_withholding_payables_for_actual(conn, session, aid)
            except Exception:
                pass
        _audit(conn, session, 'AMEND_MULTILINE_PV', 'actuals', aid,
               '%s: %d line(s), total GHS %.2f%s%s' % (existing.get('actual_code'), len(clean), total,
               (' reposted as %s' % new_jv) if new_jv else '', (' — %s' % edit_reason) if edit_reason else ''))
        conn.commit()
        return ok({'id': aid, 'lines': len(clean), 'total_ghs': total, 'jv_number': new_jv,
                   'message': '%s updated (%d lines, GHS %.2f)%s' % (existing.get('actual_code'), len(clean), total,
                   (' and reposted as %s' % new_jv) if new_jv else '')})
    except Exception as exc:
        try: conn.rollback()
        except Exception: pass
        return err('Multi-line update failed: %s' % exc)
    finally:
        conn.close()


# ── Lifecycle integrity pack (pre-UCC scenario round, 2026-06-12) ────────────
# Closes four field-realistic gaps found by scenario probing:
#   B/F  deleting a draft PV left its withholding payables alive ('Awaiting
#        Posting' ghosts in the remittance register) and orphaned its itemised
#        lines — now payables are Cancelled and lines removed with the PV.
#   D    reversing a remittance journal left the payable marked 'Paid' — the
#        liability reappeared in the GL but the register said settled, and the
#        source PV stayed un-amendable forever. Reversal now returns the
#        payable to 'Pending' (settlement fields cleared, audit-logged).
#   G    rejecting a PV in the approval workflow left its approval-stage
#        payables alive — now they are Cancelled on rejection.
#   J    a withholding could be remitted DATED BEFORE the payment voucher that
#        created it (liability account driven debit before the credit exists).
#        Settlement now requires payment_date >= source PV date.

def _lcp_err(msg):
    return {'ok': False, 'error': msg}

def _lcp_cancel_payables(conn, session, actual_id, why):
    try:
        rows = conn.execute("SELECT id, payable_type, amount_ghs FROM withholding_payables "
                            "WHERE actual_id=? AND status IN ('Pending','Awaiting Posting')",
                            (actual_id,)).fetchall()
    except Exception:
        return 0
    n = 0
    for r in rows:
        conn.execute("UPDATE withholding_payables SET status='Cancelled' WHERE id=?", (r['id'],))
        try:
            _audit(conn, session or {}, 'CANCEL_WITHHOLDING_PAYABLE', 'withholding_payables', r['id'],
                   '%s GHS %.2f cancelled — %s' % (r['payable_type'], float(r['amount_ghs'] or 0), why))
        except Exception:
            pass
        n += 1
    return n

try:
    _lcp_prev_delete_actual = api_delete_actual
    def api_delete_actual(actual_id, session):
        res = _lcp_prev_delete_actual(actual_id, session)
        try:
            if isinstance(res, dict) and res.get('ok'):
                conn = get_db()
                try:
                    _lcp_cancel_payables(conn, session, actual_id, 'source payment voucher deleted')
                    try:
                        conn.execute("DELETE FROM actual_lines WHERE actual_id=?", (actual_id,))
                    except Exception:
                        pass
                    conn.commit()
                finally:
                    conn.close()
        except Exception as _e:
            import sys as _s; print('lifecycle delete-cleanup warning: %s' % _e, file=_s.stderr)
        return res
except Exception as _lcp_exc:
    print('lifecycle pack (delete) warning:', _lcp_exc)

try:
    _lcp_prev_jv_workflow = api_jv_workflow
    def api_jv_workflow(data, session):
        src = None
        try:
            if str((data or {}).get('action') or '') == 'reverse' and (data or {}).get('jv_id'):
                conn = get_db()
                try:
                    r = conn.execute("SELECT source_module, source_id FROM journal_vouchers WHERE id=?",
                                     ((data or {}).get('jv_id'),)).fetchone()
                    if r:
                        src = (r['source_module'], r['source_id'])
                finally:
                    conn.close()
        except Exception:
            src = None
        res = _lcp_prev_jv_workflow(data, session)
        try:
            if isinstance(res, dict) and res.get('ok') and src and (src[0] or '') == 'withholding_payables' and src[1]:
                conn = get_db()
                try:
                    wp = conn.execute("SELECT id FROM withholding_payables WHERE id=? AND status='Paid'",
                                      (src[1],)).fetchone()
                    if wp:
                        cols = {c[1] for c in conn.execute('PRAGMA table_info(withholding_payables)').fetchall()}
                        sets = ["status='Pending'"]
                        for c in ('settlement_jv_id', 'settlement_pv_number', 'settlement_date',
                                  'payment_method', 'payment_reference', 'paid_by', 'paid_at'):
                            if c in cols:
                                sets.append('%s=NULL' % c)
                        conn.execute('UPDATE withholding_payables SET %s WHERE id=?' % ', '.join(sets), (src[1],))
                        try:
                            _audit(conn, session or {}, 'UNSETTLE_WITHHOLDING_PAYABLE', 'withholding_payables', src[1],
                                   'Remittance journal reversed — payable returned to Pending for re-settlement')
                        except Exception:
                            pass
                        conn.commit()
                finally:
                    conn.close()
        except Exception as _e:
            import sys as _s; print('lifecycle unsettle warning: %s' % _e, file=_s.stderr)
        return res
except Exception as _lcp_exc:
    print('lifecycle pack (jv reverse) warning:', _lcp_exc)

