def api_pc2_void_voucher(data, session):
    """POST /api/petty-cash2/voucher/void — correct a wrong petty-cash voucher:
    posts a same-date reversing journal (Dr Petty Cash / Cr Expense), marks the
    voucher Voided, and the float's book balance is restored automatically."""
    if not session:
        return _fip_err('Not authenticated')
    if (session or {}).get('role') not in ('Admin', 'Finance Officer'):
        return _fip_err('Admin or Finance Officer access required to void a petty cash voucher')
    vid = (data or {}).get('id') or (data or {}).get('voucher_id')
    reason = str((data or {}).get('reason') or '').strip()
    if not vid:
        return _fip_err('Voucher id is required')
    if len(reason) < 5:
        return _fip_err('A void reason of at least 5 characters is required (kept in the audit trail)')
    conn = get_db()
    try:
        v = conn.execute("SELECT * FROM petty_cash_vouchers WHERE id=?", (vid,)).fetchone()
        if not v:
            return _fip_err('Petty cash voucher not found')
        v = dict(v)
        if (v.get('status') or '') == 'Voided':
            return _fip_err('This voucher has already been voided')
        vdate = str(v.get('voucher_date') or '')[:10]
        amt = round(float(v.get('amount_ghs') or 0), 2)
        desc = 'VOID %s — %s (%s)' % (v.get('pcv_number'), v.get('payee'), reason)
        # Reverse by flipping the ORIGINAL voucher journal's GL lines — robust for
        # both single- and multi-line vouchers (Dr imprest / Cr each expense).
        gl = conn.execute("SELECT coa_id, COALESCE(debit_amount,0) d, COALESCE(credit_amount,0) c, project_id "
                          "FROM general_ledger WHERE jv_id=?", (v.get('jv_id'),)).fetchall() if v.get('jv_id') else []
        lines = []
        for r in gl:
            r = dict(r)
            lines.append({'coa_id': r['coa_id'], 'debit_amount': round(float(r['c']), 2),
                          'credit_amount': round(float(r['d']), 2), 'description': desc,
                          'project_id': r.get('project_id') or v.get('project_id')})
        if not lines:
            # Fallback for legacy vouchers with no GL detail: single expense vs imprest
            f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (v.get('float_id'),)).fetchone()
            pc_coa = (dict(f).get('coa_id') if f else None) or (_pc2_coa(conn) if '_pc2_coa' in globals() else None)
            if not pc_coa or not v.get('expense_coa_id'):
                return _fip_err('Could not resolve the petty cash / expense accounts for the reversing journal')
            lines = [{'coa_id': pc_coa, 'debit_amount': amt, 'credit_amount': 0, 'description': desc, 'project_id': v.get('project_id')},
                     {'coa_id': v.get('expense_coa_id'), 'debit_amount': 0, 'credit_amount': amt, 'description': desc, 'project_id': v.get('project_id')}]
        jv_id, jv_num = _create_posted_journal(conn, session, 'JV', vdate, desc, v.get('pcv_number'),
                                               v.get('project_id'), None, 'petty_cash_vouchers', vid, lines)
        try:
            if v.get('jv_id'):
                conn.execute("UPDATE journal_vouchers SET is_reversal=1, reversal_of=? WHERE id=?", (v['jv_id'], jv_id))
                conn.execute("UPDATE journal_vouchers SET status='Reversed', reversed_by=? WHERE id=?", (jv_num, v['jv_id']))
        except Exception:
            pass
        conn.execute("UPDATE petty_cash_vouchers SET status='Voided' WHERE id=?", (vid,))
        _audit(conn, session, 'VOID_PETTY_VOUCHER', 'petty_cash_vouchers', vid,
               '%s GHS %.2f voided: %s (reversing journal %s)' % (v.get('pcv_number'), amt, reason, jv_num))
        conn.commit()
        bal = _pc2_book_balance(conn, v.get('float_id')) if '_pc2_book_balance' in globals() else None
        return {'ok': True, 'id': vid, 'jv_number': jv_num, 'balance_after': bal,
                'message': '%s voided — the float balance has been restored (reversing journal %s)' % (v.get('pcv_number'), jv_num)}
    except Exception as e:
        conn.rollback()
        return _fip_err('Void failed: %s' % e)
    finally:
        conn.close()

