# ═════════════════════════════════════════════════════════════════════════════
# PETTY CASH CORRECTIONS (2026-06-13) — edit/adjust a float, edit a disbursement,
# all audit-safe: posted journals are never mutated; corrections post adjustment
# or reversing journals with a reason, so the GL stays balanced and the trail is
# complete.
# ═════════════════════════════════════════════════════════════════════════════
def _pcx_err(m): return {'ok': False, 'error': m}

def api_pc2_edit_float(data, session):
    """POST /api/petty-cash2/float/edit — correct a float.
       • Metadata (name / custodian / department) — no ledger impact.
       • Imprest LEVEL — posts the difference as a real cash movement:
         raise → Dr Imprest / Cr Bank (more cash drawn);
         lower → Dr Bank / Cr Imprest (surplus cash returned). A reason is kept."""
    if not session: return _pcx_err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return _pcx_err('Admin or Finance Officer role required to edit a float')
    fid = data.get('float_id') or data.get('id')
    if not fid: return _pcx_err('float_id is required')
    conn = get_db()
    try:
        _pc2_migration(conn)
        f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (fid,)).fetchone()
        if not f: return _pcx_err('Float not found')
        f = dict(f)
        # 1) metadata (no GL)
        name = (data.get('name') or f.get('name') or '').strip() or f.get('name')
        custodian = data.get('custodian') if data.get('custodian') is not None else f.get('custodian')
        dept = (data.get('department_code') or data.get('department') or f.get('department_code') or '')
        conn.execute("UPDATE petty_cash_floats SET name=?, custodian=?, department_code=? WHERE id=?",
                     (name, custodian, dept, fid))
        # 2) imprest level change (optional)
        jv_num = None; moved = 0.0
        if data.get('new_imprest_amount') not in (None, ''):
            try: new_amt = round(float(data.get('new_imprest_amount')), 2)
            except Exception: return _pcx_err('new_imprest_amount must be a number')
            if new_amt <= 0: return _pcx_err('The imprest amount must be greater than zero')
            cur = round(float(f.get('imprest_amount') or 0), 2)
            diff = round(new_amt - cur, 2)
            if abs(diff) > 0.005:
                reason = str(data.get('reason') or '').strip()
                if len(reason) < 5:
                    return _pcx_err('A reason (≥5 characters) is required to change the imprest level — it is kept in the audit trail')
                bank_id = data.get('bank_account_id') or f.get('bank_account_id')
                if not bank_id: return _pcx_err('Select the bank account for the cash movement')
                bank_coa = _ar_bank_coa(conn, bank_id)
                imp_coa = f.get('coa_id') or _pc2_coa(conn)
                if not bank_coa or not imp_coa:
                    return _pcx_err('Bank or imprest GL account could not be resolved')
                from datetime import date as _d
                adate = (data.get('date') or _d.today().isoformat())[:10]
                if diff < 0:
                    book = _pc2_book_balance(conn, fid)
                    if abs(diff) > book + 0.005:
                        return _pcx_err('Cannot lower the imprest by GHS %.2f — only GHS %.2f cash is on hand. Spend or leave more, or lower by less.' % (abs(diff), book))
                desc = 'Petty cash imprest %s — %s (%s): %s' % (
                    'increase' if diff > 0 else 'reduction', name, dept or 'no dept', reason)
                if diff > 0:
                    lines = [{'coa_id': imp_coa, 'debit_amount': diff, 'credit_amount': 0, 'description': desc},
                             {'coa_id': bank_coa, 'debit_amount': 0, 'credit_amount': diff, 'description': desc, 'bank_account_id': bank_id}]
                else:
                    lines = [{'coa_id': bank_coa, 'debit_amount': abs(diff), 'credit_amount': 0, 'description': desc, 'bank_account_id': bank_id},
                             {'coa_id': imp_coa, 'debit_amount': 0, 'credit_amount': abs(diff), 'description': desc}]
                jv_id, jv_num = _create_posted_journal(conn, session, 'JV', adate, desc, name,
                    f.get('project_id'), bank_id, 'petty_cash_float_adjust', fid, lines)
                # Changing the imprest LEVEL alone drives the book balance
                # (book = imprest_amount + replenishments - vouchers); the journal
                # above drives the GL. The two stay tied — so do NOT also record a
                # replenishment row (that would double-count the cash movement).
                conn.execute("UPDATE petty_cash_floats SET imprest_amount=? WHERE id=?", (new_amt, fid))
                moved = diff
        _audit(conn, session, 'EDIT_PETTY_FLOAT', 'petty_cash_floats', fid,
               'Float "%s" edited%s' % (name, ('; imprest moved GHS %.2f (%s)' % (moved, jv_num)) if jv_num else ' (details only)'))
        conn.commit()
        return {'ok': True, 'id': fid, 'jv_number': jv_num, 'book_balance': _pc2_book_balance(conn, fid),
                'message': ('Float updated; imprest moved GHS %.2f (%s)' % (moved, jv_num)) if jv_num else 'Float details updated'}
    except Exception as e:
        conn.rollback(); return _pcx_err('Edit failed: %s' % e)
    finally:
        conn.close()


def api_pc2_close_float(data, session):
    """POST /api/petty-cash2/float/close — undo a float created in error. Only
       when it is untouched (no live vouchers, cash on hand = imprest): reverses
       the establishment journal (Dr Bank / Cr Imprest) and marks it Closed."""
    if not session: return _pcx_err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return _pcx_err('Admin or Finance Officer role required to close a float')
    fid = data.get('float_id') or data.get('id')
    reason = str(data.get('reason') or '').strip()
    if not fid: return _pcx_err('float_id is required')
    if len(reason) < 5: return _pcx_err('A reason (≥5 characters) is required to close a float')
    conn = get_db()
    try:
        _pc2_migration(conn)
        f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (fid,)).fetchone()
        if not f: return _pcx_err('Float not found')
        f = dict(f)
        live = conn.execute("SELECT COUNT(*) FROM petty_cash_vouchers WHERE float_id=? AND status='Posted'", (fid,)).fetchone()[0]
        if live: return _pcx_err('This float has %d posted voucher(s). Void them first, then close the float.' % live)
        book = _pc2_book_balance(conn, fid)
        imp_coa = f.get('coa_id') or _pc2_coa(conn)
        bank_id = f.get('bank_account_id'); bank_coa = _ar_bank_coa(conn, bank_id)
        if not bank_coa: return _pcx_err('Bank GL account could not be resolved to return the cash')
        from datetime import date as _d
        cdate = (data.get('date') or _d.today().isoformat())[:10]
        desc = 'Petty cash float closed — %s: %s' % (f.get('name'), reason)
        amt = round(float(book), 2)
        jv_num = None
        if amt > 0.005:
            lines = [{'coa_id': bank_coa, 'debit_amount': amt, 'credit_amount': 0, 'description': desc, 'bank_account_id': bank_id},
                     {'coa_id': imp_coa, 'debit_amount': 0, 'credit_amount': amt, 'description': desc}]
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', cdate, desc, f.get('name'),
                f.get('project_id'), bank_id, 'petty_cash_float_close', fid, lines)
        conn.execute("UPDATE petty_cash_floats SET status='Closed' WHERE id=?", (fid,))
        _audit(conn, session, 'CLOSE_PETTY_FLOAT', 'petty_cash_floats', fid,
               'Float "%s" closed: %s (cash GHS %.2f returned%s)' % (f.get('name'), reason, amt, (' ' + jv_num) if jv_num else ''))
        conn.commit()
        return {'ok': True, 'id': fid, 'jv_number': jv_num,
                'message': 'Float "%s" closed; GHS %.2f returned to bank%s' % (f.get('name'), amt, (' (' + jv_num + ')') if jv_num else '')}
    except Exception as e:
        conn.rollback(); return _pcx_err('Close failed: %s' % e)
    finally:
        conn.close()


def api_pc2_edit_voucher(data, session):
    """POST /api/petty-cash2/voucher/edit — correct a disbursement in one step:
       voids the original (same-date reversing journal, marks it Voided) and
       issues a corrected NEW voucher from the supplied lines. The original PCV
       stays in the audit trail, cross-referenced to the correction."""
    if not session: return _pcx_err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return _pcx_err('Admin or Finance Officer role required to edit a disbursement')
    vid = data.get('id') or data.get('voucher_id')
    reason = str(data.get('reason') or '').strip()
    if not vid: return _pcx_err('Voucher id is required')
    if len(reason) < 5: return _pcx_err('A reason (≥5 characters) is required to edit a voucher')
    # normalise corrected lines (same rules as a fresh voucher)
    raw = data.get('lines'); norm = []
    if isinstance(raw, list) and raw:
        for ln in raw:
            try: a = round(float(ln.get('amount_ghs') or ln.get('amount') or 0), 2)
            except Exception: a = 0
            coa = ln.get('expense_coa_id') or ln.get('coa_id')
            if a > 0 and coa: norm.append({'coa_id': coa, 'amount': a, 'description': (ln.get('description') or '').strip()})
    if not norm: return _pcx_err('Add at least one corrected expense line (account + amount)')
    new_total = round(sum(l['amount'] for l in norm), 2)
    conn = get_db()
    try:
        _pc2_migration(conn)
        v = conn.execute("SELECT * FROM petty_cash_vouchers WHERE id=?", (vid,)).fetchone()
        if not v: return _pcx_err('Voucher not found')
        v = dict(v)
        if (v.get('status') or '') == 'Voided':
            return _pcx_err('This voucher is already voided — record a fresh voucher instead')
        f = conn.execute("SELECT * FROM petty_cash_floats WHERE id=?", (v.get('float_id'),)).fetchone()
        if not f: return _pcx_err('Parent float not found')
        f = dict(f)
        imp_coa = f.get('coa_id') or _pc2_coa(conn)
        from datetime import datetime as _dt, date as _d
        old_amt = round(float(v.get('amount_ghs') or 0), 2)
        # sufficiency: after the void restores the old amount, can the float cover the new total?
        book_after_void = round(_pc2_book_balance(conn, v.get('float_id')) + old_amt, 2)
        if new_total > book_after_void + 0.005:
            return _pcx_err('Corrected total GHS %.2f exceeds the cash available after reinstating the original (GHS %.2f). Replenish first.' % (new_total, book_after_void))
        # 1) VOID the original — flip its journal's GL lines
        vdate = str(v.get('voucher_date') or '')[:10]
        vdesc = 'VOID %s (edited): %s' % (v.get('pcv_number'), reason)
        gl = conn.execute("SELECT coa_id, COALESCE(debit_amount,0) d, COALESCE(credit_amount,0) c, project_id "
                          "FROM general_ledger WHERE jv_id=?", (v.get('jv_id'),)).fetchall() if v.get('jv_id') else []
        rlines = [{'coa_id': dict(r)['coa_id'], 'debit_amount': round(float(dict(r)['c']), 2),
                   'credit_amount': round(float(dict(r)['d']), 2), 'description': vdesc,
                   'project_id': dict(r).get('project_id') or v.get('project_id')} for r in gl]
        if not rlines:
            rlines = [{'coa_id': imp_coa, 'debit_amount': old_amt, 'credit_amount': 0, 'description': vdesc, 'project_id': v.get('project_id')},
                      {'coa_id': v.get('expense_coa_id'), 'debit_amount': 0, 'credit_amount': old_amt, 'description': vdesc, 'project_id': v.get('project_id')}]
        rjv_id, rjv_num = _create_posted_journal(conn, session, 'JV', vdate, vdesc, v.get('pcv_number'),
            v.get('project_id'), None, 'petty_cash_vouchers', vid, rlines)
        try:
            if v.get('jv_id'):
                conn.execute("UPDATE journal_vouchers SET is_reversal=1, reversal_of=? WHERE id=?", (v['jv_id'], rjv_id))
                conn.execute("UPDATE journal_vouchers SET status='Reversed', reversed_by=? WHERE id=?", (rjv_num, v['jv_id']))
        except Exception: pass
        conn.execute("UPDATE petty_cash_vouchers SET status='Voided' WHERE id=?", (vid,))
        # 2) issue the CORRECTED new voucher
        payee = (data.get('payee') or v.get('payee') or '').strip()
        dept = (data.get('department_code') or v.get('department_code') or f.get('department_code') or '')
        proj = data.get('project_id') or v.get('project_id') or f.get('project_id')
        ndate = (data.get('voucher_date') or vdate)[:10]
        for l in norm:
            if not conn.execute("SELECT 1 FROM chart_of_accounts WHERE id=?", (l['coa_id'],)).fetchone():
                return _pcx_err('An expense account on a corrected line was not found')
        nid = str(uuid.uuid4())
        pcv = _seq_code(conn, 'petty_cash_vouchers', 'pcv_number', 'PCV-%d-' % _dt.now().year, 4)
        hdr = 'Petty cash (corrects %s): %s — %s' % (v.get('pcv_number'), payee, (data.get('description') or '').strip() or 'sundry expenses')
        nlines = [{'coa_id': l['coa_id'], 'debit_amount': l['amount'], 'credit_amount': 0,
                   'description': (l['description'] or hdr) + ((' [' + dept + ']') if dept else ''), 'project_id': proj} for l in norm]
        nlines.append({'coa_id': imp_coa, 'debit_amount': 0, 'credit_amount': new_total,
                       'description': 'Petty cash paid out (%s)' % pcv, 'project_id': proj})
        njv_id, njv_num = _create_posted_journal(conn, session, 'JV', ndate, hdr, pcv, proj, None, 'petty_cash_vouchers', nid, nlines)
        conn.execute("INSERT INTO petty_cash_vouchers(id,float_id,pcv_number,voucher_date,payee,description,"
                     "expense_coa_id,amount_ghs,receipt_ref,status,jv_id,jv_number,created_by,department_code,project_id) "
                     "VALUES(?,?,?,?,?,?,?,?,?,'Posted',?,?,?,?,?)",
                     (nid, v.get('float_id'), pcv, ndate, payee, (data.get('description') or '').strip(),
                      norm[0]['coa_id'], new_total, (data.get('receipt_ref') or v.get('receipt_ref') or '').strip(),
                      njv_id, njv_num, session.get('username', ''), dept, proj))
        for i, l in enumerate(norm):
            conn.execute("INSERT INTO petty_cash_voucher_lines(id,voucher_id,line_no,expense_coa_id,amount_ghs,description) "
                         "VALUES(?,?,?,?,?,?)", (str(uuid.uuid4()), nid, i + 1, l['coa_id'], l['amount'], l['description']))
        _audit(conn, session, 'EDIT_PETTY_VOUCHER', 'petty_cash_vouchers', vid,
               '%s voided (%s) and corrected as %s GHS %.2f: %s' % (v.get('pcv_number'), rjv_num, pcv, new_total, reason))
        conn.commit()
        return {'ok': True, 'voided': v.get('pcv_number'), 'id': nid, 'pcv_number': pcv, 'jv_number': njv_num,
                'lines': len(norm), 'total_ghs': new_total, 'balance_after': _pc2_book_balance(conn, v.get('float_id')),
                'message': '%s corrected — reissued as %s (GHS %.2f, %d line(s))' % (v.get('pcv_number'), pcv, new_total, len(norm))}
    except Exception as e:
        conn.rollback(); return _pcx_err('Edit failed: %s' % e)
    finally:
        conn.close()


# ═════════════════════════════════════════════════════════════════════════════
# FX RETRANSLATION (IAS 21 / IPSAS 4) — 2026-06-14
# Period-end retranslation of foreign-currency MONETARY balances (foreign bank
# accounts) at the closing rate. The difference between the cedi carrying amount
# and (foreign-currency balance × closing rate) is recognised in surplus/deficit
# as an unrealised exchange gain (42300028) or loss (61700019). Reversible.
# ═════════════════════════════════════════════════════════════════════════════
def _fxr_err(m): return {'ok': False, 'error': m}

def _fxr_migration(conn):
    conn.execute("""CREATE TABLE IF NOT EXISTS fx_revaluations (
        id TEXT PRIMARY KEY, period TEXT, reval_date TEXT, bank_account_id TEXT,
        currency TEXT, fcy_balance REAL, closing_rate REAL,
        cedi_before REAL, cedi_after REAL, gain_loss REAL,
        jv_id TEXT, jv_number TEXT, status TEXT DEFAULT 'Posted',
        reason TEXT, created_by TEXT, created_at TEXT DEFAULT (datetime('now')))""")

def _fxr_coa_balance(conn, coa_id):
    r = conn.execute("SELECT COALESCE(SUM(COALESCE(debit_amount,0)-COALESCE(credit_amount,0)),0) "
                     "FROM general_ledger WHERE coa_id=?", (coa_id,)).fetchone()
    return round(float(r[0] or 0), 2)

def _fxr_rate(conn, currency, as_at=None):
    q = "SELECT rate_to_ghs FROM exchange_rates WHERE currency=?"
    a = [currency]
    if as_at:
        q += " AND rate_date<=?"; a.append(as_at)
    q += " ORDER BY rate_date DESC LIMIT 1"
    r = conn.execute(q, a).fetchone()
    return float(r[0]) if r and r[0] else None

def api_fx_revaluation_state(session, period=None):
    """GET /api/fx-revaluation?period= — foreign-currency bank accounts with their
    cedi book balance and the closing rate, plus revaluations already posted."""
    if not session: return _fxr_err('Not authenticated')
    conn = get_db()
    try:
        _fxr_migration(conn)
        rows = []
        for b in conn.execute("SELECT id, bank_name, account_number, currency, coa_id FROM bank_accounts "
                              "WHERE UPPER(COALESCE(currency,'GHS'))<>'GHS' ORDER BY currency, bank_name").fetchall():
            b = dict(b)
            if not b.get('coa_id'): continue
            cedi = _fxr_coa_balance(conn, b['coa_id'])
            rate = _fxr_rate(conn, b['currency'])
            rows.append({'bank_account_id': b['id'], 'bank_name': b['bank_name'],
                         'account_number': b['account_number'], 'currency': b['currency'],
                         'coa_id': b['coa_id'], 'cedi_balance': cedi, 'closing_rate': rate,
                         'implied_fcy': round(cedi / rate, 2) if rate else None})
        hist = [dict(r) for r in conn.execute(
            "SELECT fr.*, b.bank_name FROM fx_revaluations fr LEFT JOIN bank_accounts b ON b.id=fr.bank_account_id "
            "ORDER BY fr.created_at DESC LIMIT 100").fetchall()]
        gain = conn.execute("SELECT 1 FROM chart_of_accounts WHERE code='42300028'").fetchone()
        loss = conn.execute("SELECT 1 FROM chart_of_accounts WHERE code='61700019'").fetchone()
        return ok({'accounts': rows, 'revaluations': hist,
                   'gain_account': '42300028 Gain on Foreign Exchange' if gain else None,
                   'loss_account': '61700019 Loss on Foreign Exchange' if loss else None})
    finally:
        conn.close()

def api_fx_revaluation_run(data, session):
    """POST /api/fx-revaluation — retranslate foreign bank balances at period end.
    Body: {period, reval_date, lines:[{bank_account_id, fcy_balance, closing_rate}]}.
    For each: revalued = fcy_balance × closing_rate; the difference vs the cedi book
    balance is posted Dr/Cr bank vs the FX gain/loss account."""
    if not session: return _fxr_err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return _fxr_err('Admin or Finance Officer role required to post a revaluation')
    lines = data.get('lines') or []
    if not isinstance(lines, list) or not lines:
        return _fxr_err('Provide at least one account line to revalue')
    from datetime import date as _d
    period = (data.get('period') or '').strip()
    rdate = (data.get('reval_date') or data.get('date') or _d.today().isoformat())[:10]
    if not period:
        period = rdate[:7]
    conn = get_db()
    try:
        _fxr_migration(conn)
        gain_coa = conn.execute("SELECT id FROM chart_of_accounts WHERE code='42300028'").fetchone()
        loss_coa = conn.execute("SELECT id FROM chart_of_accounts WHERE code='61700019'").fetchone()
        if not gain_coa or not loss_coa:
            return _fxr_err('FX gain (42300028) / loss (61700019) accounts are missing from the chart')
        gain_id = gain_coa['id']; loss_id = loss_coa['id']
        results = []; posted = 0; net = 0.0
        for ln in lines:
            bid = ln.get('bank_account_id')
            b = conn.execute("SELECT id, bank_name, currency, coa_id FROM bank_accounts WHERE id=?", (bid,)).fetchone() if bid else None
            if not b: continue
            b = dict(b)
            if not b.get('coa_id'): continue
            try:
                fcy = round(float(ln.get('fcy_balance')), 2)
                rate = round(float(ln.get('closing_rate') or _fxr_rate(conn, b['currency']) or 0), 6)
            except Exception:
                return _fxr_err('Each line needs a numeric foreign-currency balance and closing rate')
            if rate <= 0:
                return _fxr_err('A closing rate is required for %s' % b['currency'])
            cedi_before = _fxr_coa_balance(conn, b['coa_id'])
            revalued = round(fcy * rate, 2)
            diff = round(revalued - cedi_before, 2)
            if abs(diff) < 0.005:
                results.append({'bank': b['bank_name'], 'currency': b['currency'], 'gain_loss': 0.0, 'note': 'no adjustment'})
                continue
            desc = 'FX revaluation %s — %s %s @ %.4f (IAS 21)' % (period, b['currency'], ('%.2f' % fcy), rate)
            if diff > 0:
                jlines = [{'coa_id': b['coa_id'], 'debit_amount': diff, 'credit_amount': 0, 'description': desc},
                          {'coa_id': gain_id, 'debit_amount': 0, 'credit_amount': diff, 'description': desc}]
            else:
                jlines = [{'coa_id': loss_id, 'debit_amount': -diff, 'credit_amount': 0, 'description': desc},
                          {'coa_id': b['coa_id'], 'debit_amount': 0, 'credit_amount': -diff, 'description': desc}]
            jv_id, jv_num = _create_posted_journal(conn, session, 'JV', rdate, desc, 'FXR-' + period,
                None, b['id'], 'fx_revaluation', bid, jlines)
            import uuid as _u
            conn.execute("INSERT INTO fx_revaluations(id,period,reval_date,bank_account_id,currency,fcy_balance,closing_rate,"
                         "cedi_before,cedi_after,gain_loss,jv_id,jv_number,status,reason,created_by) "
                         "VALUES(?,?,?,?,?,?,?,?,?,?,?,?,'Posted',?,?)",
                         (str(_u.uuid4()), period, rdate, bid, b['currency'], fcy, rate, cedi_before, revalued,
                          diff, jv_id, jv_num, (data.get('reason') or '').strip(), session.get('username', '')))
            posted += 1; net += diff
            results.append({'bank': b['bank_name'], 'currency': b['currency'], 'cedi_before': cedi_before,
                            'cedi_after': revalued, 'gain_loss': diff, 'jv_number': jv_num})
        _audit(conn, session, 'FX_REVALUATION', 'fx_revaluations', period,
               '%d account(s) retranslated for %s; net GHS %.2f' % (posted, period, round(net, 2)))
        conn.commit()
        return ok({'period': period, 'posted': posted, 'net_gain_loss': round(net, 2), 'results': results,
                   'message': '%d account(s) revalued for %s — net %s GHS %.2f' % (
                       posted, period, 'gain' if net >= 0 else 'loss', abs(round(net, 2)))})
    except Exception as e:
        conn.rollback(); return _fxr_err('Revaluation failed: %s' % e)
    finally:
        conn.close()

def api_fx_revaluation_reverse(data, session):
    """POST /api/fx-revaluation/reverse — reverse a posted revaluation (error fix)."""
    if not session: return _fxr_err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return _fxr_err('Admin or Finance Officer role required')
    rid = data.get('id'); reason = str(data.get('reason') or '').strip()
    if not rid: return _fxr_err('Revaluation id is required')
    if len(reason) < 5: return _fxr_err('A reason (≥5 characters) is required')
    conn = get_db()
    try:
        _fxr_migration(conn)
        r = conn.execute("SELECT * FROM fx_revaluations WHERE id=?", (rid,)).fetchone()
        if not r: return _fxr_err('Revaluation not found')
        r = dict(r)
        if (r.get('status') or '') == 'Reversed': return _fxr_err('Already reversed')
        gl = conn.execute("SELECT coa_id, COALESCE(debit_amount,0) d, COALESCE(credit_amount,0) c FROM general_ledger WHERE jv_id=?",
                          (r.get('jv_id'),)).fetchall()
        if not gl: return _fxr_err('Original revaluation journal not found')
        desc = 'Reversal of FX revaluation %s %s: %s' % (r.get('period'), r.get('currency'), reason)
        jlines = [{'coa_id': dict(x)['coa_id'], 'debit_amount': round(float(dict(x)['c']), 2),
                   'credit_amount': round(float(dict(x)['d']), 2), 'description': desc} for x in gl]
        jv_id, jv_num = _create_posted_journal(conn, session, 'JV', str(r.get('reval_date'))[:10], desc,
            'FXR-REV-' + str(r.get('period')), None, r.get('bank_account_id'), 'fx_revaluation', rid, jlines)
        try:
            if r.get('jv_id'):
                conn.execute("UPDATE journal_vouchers SET is_reversal=1, reversal_of=? WHERE id=?", (r['jv_id'], jv_id))
                conn.execute("UPDATE journal_vouchers SET status='Reversed', reversed_by=? WHERE id=?", (jv_num, r['jv_id']))
        except Exception: pass
        conn.execute("UPDATE fx_revaluations SET status='Reversed' WHERE id=?", (rid,))
        _audit(conn, session, 'FX_REVALUATION_REVERSE', 'fx_revaluations', rid, desc)
        conn.commit()
        return ok({'id': rid, 'jv_number': jv_num, 'message': 'Revaluation reversed (%s)' % jv_num})
    except Exception as e:
        conn.rollback(); return _fxr_err('Reverse failed: %s' % e)
    finally:
        conn.close()


# ═════════════════════════════════════════════════════════════════════════════
# TAMPER-EVIDENT AUDIT LOG (2026-06-14) — hash-chained audit trail.
# Each audit row carries row_hash = SHA-256(prev_hash | id | ts | user | role |
# action | module | record_id | details). Any later edit or deletion of a row
# breaks the chain, which /api/audit/verify detects and pinpoints. This makes the
# audit trail tamper-EVIDENT (an auditor can prove it was not altered).
# ═════════════════════════════════════════════════════════════════════════════
import hashlib as _ach_hashlib

def _audit_chain_migrate(conn):
    try:
        cols = {c[1] for c in conn.execute("PRAGMA table_info(audit_log)").fetchall()}
        if 'row_hash' not in cols:
            conn.execute("ALTER TABLE audit_log ADD COLUMN row_hash TEXT")
        if 'prev_hash' not in cols:
            conn.execute("ALTER TABLE audit_log ADD COLUMN prev_hash TEXT")
    except Exception:
        pass

_AUDIT_CHAIN_READY = [False]

def _audit_row_hash(prev_hash, aid, ts, uname, role, action, module, record_id, details):
    payload = '|'.join([str(x) for x in (prev_hash, aid, ts, uname, role, action,
                                         module or '', record_id or '', details or '')])
    return _ach_hashlib.sha256(payload.encode('utf-8')).hexdigest()

def _audit(conn, session, action, module, record_id, details):
    """Hash-chained audit write (tamper-evident). Same signature as before."""
    if not _AUDIT_CHAIN_READY[0]:
        _audit_chain_migrate(conn); _AUDIT_CHAIN_READY[0] = True
    from datetime import datetime as _dt
    aid = str(uuid.uuid4())
    ts = _dt.utcnow().strftime('%Y-%m-%d %H:%M:%S')
    uname = (session or {}).get('username', 'system'); role = (session or {}).get('role', '')
    try:
        prev = conn.execute("SELECT row_hash FROM audit_log WHERE row_hash IS NOT NULL AND row_hash<>'' ORDER BY timestamp DESC, rowid DESC LIMIT 1").fetchone()
        prev_hash = (prev[0] if prev and prev[0] else 'GENESIS')
    except Exception:
        prev_hash = 'GENESIS'
    rh = _audit_row_hash(prev_hash, aid, ts, uname, role, action, module, record_id, details)
    try:
        conn.execute("INSERT INTO audit_log(id,timestamp,username,user_role,action,module,record_id,details,row_hash,prev_hash) "
                     "VALUES(?,?,?,?,?,?,?,?,?,?)",
                     (aid, ts, uname, role, action, module, record_id, details, rh, prev_hash))
    except Exception:
        # last-resort fallback to the original columns if hash columns are unavailable
        conn.execute("INSERT INTO audit_log(id,username,user_role,action,module,record_id,details) VALUES(?,?,?,?,?,?,?)",
                     (aid, uname, role, action, module, record_id, details))

def api_audit_verify(session):
    """GET /api/audit/verify — recompute the hash chain and report integrity.
    Detects any row that was edited, inserted out of band, or deleted."""
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    if (session.get('role') or '') not in ('Admin', 'Finance Officer', 'Auditor'):
        return {'ok': False, 'error': 'Admin, Finance Officer or Auditor role required'}
    conn = get_db()
    try:
        _audit_chain_migrate(conn)
        rows = conn.execute("SELECT id,timestamp,username,user_role,action,module,record_id,details,row_hash,prev_hash "
                            "FROM audit_log ORDER BY timestamp ASC, rowid ASC").fetchall()
        total = len(rows); checked = 0; unhashed = 0
        prev_hash = 'GENESIS'; first_broken = None
        for r in rows:
            r = dict(r)
            if not r.get('row_hash'):
                unhashed += 1
                # legacy rows pre-dating chaining: skip but keep walking
                continue
            expect = _audit_row_hash(prev_hash if r.get('prev_hash') in (None, '') else r['prev_hash'],
                                     r['id'], r['timestamp'], r['username'], r.get('user_role') or '',
                                     r['action'], r.get('module'), r.get('record_id'), r.get('details'))
            link_ok = (r.get('prev_hash') == prev_hash) or (prev_hash == 'GENESIS' and r.get('prev_hash') in (None, '', 'GENESIS'))
            if r['row_hash'] != expect or not link_ok:
                if not first_broken:
                    first_broken = {'id': r['id'], 'timestamp': r['timestamp'], 'action': r['action'],
                                    'username': r['username'], 'reason': 'content altered' if r['row_hash'] != expect else 'chain link broken'}
            checked += 1
            prev_hash = r['row_hash']
        intact = first_broken is None
        return ok({'verified': intact, 'total_entries': total, 'hash_chained': checked,
                   'legacy_unhashed': unhashed, 'first_broken': first_broken,
                   'message': ('Audit chain intact — %d hash-linked entries verified' % checked) if intact
                              else ('TAMPERING DETECTED at entry %s (%s)' % (first_broken['id'][:8], first_broken['reason']))})
    finally:
        conn.close()


# ═════════════════════════════════════════════════════════════════════════════
# BANK RECONCILIATION — PERSISTENT CLEARING (2026-06-14)
# Transaction-level reconciliation: tick each cash-book line that has cleared the
# bank; the cleared state persists, so cleared items never reappear and the
# outstanding (uncleared) items are the reconciling difference between the book
# balance and the bank-statement balance.
# ═════════════════════════════════════════════════════════════════════════════
def _brc_err(m): return {'ok': False, 'error': m}

def _brc_migration(conn):
    conn.execute("""CREATE TABLE IF NOT EXISTS bank_recon_cleared (
        gl_id TEXT PRIMARY KEY, bank_account_id TEXT, cleared_date TEXT,
        cleared_by TEXT, created_at TEXT DEFAULT (datetime('now')))""")

def api_bank_recon_worklist(session, bank_account_id=None, as_at=None):
    """GET /api/bank-recon/worklist?bank_account_id=&as_at= — the bank's cash-book
    lines with their cleared/outstanding state and the reconciliation totals."""
    if not session: return _brc_err('Not authenticated')
    if not bank_account_id: return _brc_err('Select a bank account')
    conn = get_db()
    try:
        _brc_migration(conn)
        from datetime import date as _d
        as_at = (as_at or _d.today().isoformat())[:10]
        b = conn.execute("SELECT id, bank_name, account_number, coa_id FROM bank_accounts WHERE id=?", (bank_account_id,)).fetchone()
        if not b: return _brc_err('Bank account not found')
        b = dict(b)
        if not b.get('coa_id'): return _brc_err('This bank account has no linked GL account')
        cleared = {r[0] for r in conn.execute("SELECT gl_id FROM bank_recon_cleared WHERE bank_account_id=?", (bank_account_id,)).fetchall()}
        rows = []
        book = 0.0; cleared_total = 0.0; outstanding_total = 0.0
        for r in conn.execute(
                "SELECT gl.id, gl.ledger_date, gl.jv_number, gl.description, "
                "COALESCE(gl.debit_amount,0) dr, COALESCE(gl.credit_amount,0) cr "
                "FROM general_ledger gl WHERE gl.coa_id=? AND gl.ledger_date<=? "
                "ORDER BY gl.ledger_date, gl.jv_number", (b['coa_id'], as_at)).fetchall():
            r = dict(r); amt = round(float(r['dr']) - float(r['cr']), 2)
            is_cl = r['id'] in cleared
            book += amt
            if is_cl: cleared_total += amt
            else: outstanding_total += amt
            rows.append({'gl_id': r['id'], 'date': r['ledger_date'], 'voucher': r['jv_number'],
                         'description': r['description'], 'amount': amt, 'cleared': is_cl})
        return ok({'bank': {'id': b['id'], 'name': b['bank_name'], 'account_number': b['account_number']},
                   'as_at': as_at, 'lines': rows,
                   'book_balance': round(book, 2),
                   'cleared_balance': round(cleared_total, 2),
                   'outstanding_total': round(outstanding_total, 2),
                   'outstanding_count': sum(1 for x in rows if not x['cleared']),
                   'note': 'Bank-statement balance should equal the cleared balance; outstanding items reconcile it to the book balance.'})
    finally:
        conn.close()

def api_bank_recon_clear(data, session):
    """POST /api/bank-recon/clear — mark cash-book lines cleared/uncleared.
    Body: {bank_account_id, gl_ids:[...], cleared: true|false, cleared_date}"""
    if not session: return _brc_err('Not authenticated')
    if (session.get('role') or '') not in ('Admin', 'Finance Officer'):
        return _brc_err('Admin or Finance Officer role required')
    bid = data.get('bank_account_id'); gl_ids = data.get('gl_ids') or []
    if not bid: return _brc_err('bank_account_id is required')
    if not isinstance(gl_ids, list) or not gl_ids: return _brc_err('Select at least one line')
    cleared = bool(data.get('cleared', True))
    from datetime import date as _d
    cdate = (data.get('cleared_date') or _d.today().isoformat())[:10]
    conn = get_db()
    try:
        _brc_migration(conn)
        n = 0
        for gid in gl_ids:
            if cleared:
                conn.execute("INSERT OR REPLACE INTO bank_recon_cleared(gl_id,bank_account_id,cleared_date,cleared_by) "
                             "VALUES(?,?,?,?)", (gid, bid, cdate, session.get('username', '')))
            else:
                conn.execute("DELETE FROM bank_recon_cleared WHERE gl_id=?", (gid,))
            n += 1
        _audit(conn, session, 'BANK_RECON_CLEAR' if cleared else 'BANK_RECON_UNCLEAR', 'bank_recon_cleared', bid,
               '%d line(s) marked %s' % (n, 'cleared' if cleared else 'outstanding'))
        conn.commit()
        return ok({'updated': n, 'cleared': cleared, 'message': '%d line(s) %s' % (n, 'cleared' if cleared else 'set outstanding')})
    except Exception as e:
        conn.rollback(); return _brc_err('Update failed: %s' % e)
    finally:
        conn.close()


# ═════════════════════════════════════════════════════════════════════════════
# UCC-WIDE CONSOLIDATION (2026-06-14) — export this entity's trial balance in a
# normalised form so another entity (SBS, AOI, any unit) can merge them into one
# institutional trial balance / statements. Each app exports; the consolidation
# view sums by account code across entities.
# ═════════════════════════════════════════════════════════════════════════════
def api_consolidation_export(session, period_from=None, period_to=None):
    """GET /api/consolidation/export — this entity's trial balance by account code,
    tagged with the entity name, for combining into a UCC-wide consolidation."""
    if not session: return {'ok': False, 'error': 'Not authenticated'}
    import datetime as _dtm
    yr = _dtm.date.today().strftime('%Y')
    period_from = period_from or (yr + '-01-01')
    period_to = period_to or _dtm.date.today().isoformat()
    try:
        prof = _v523_invoice_profile() if '_v523_invoice_profile' in globals() else {'code': 'ENTITY', 'name': 'Entity'}
    except Exception:
        prof = {'code': 'ENTITY', 'name': 'Entity'}
    tb = api_trial_balance_v556(session, period_from, period_to, None, None)
    tb = tb.get('data', tb) if isinstance(tb, dict) else {}
    lines = []
    for a in (tb.get('accounts') or []):
        code = a.get('coa_code') or a.get('code') or ''
        if not code:
            continue
        lines.append({'code': code, 'name': a.get('name') or a.get('account_name') or '',
                      'debit': round(float(a.get('debit') or 0), 2), 'credit': round(float(a.get('credit') or 0), 2)})
    return ok({'entity_code': prof.get('code'), 'entity_name': prof.get('name'),
               'period_from': period_from, 'period_to': period_to,
               'total_debit': round(float(tb.get('total_debit') or 0), 2),
               'total_credit': round(float(tb.get('total_credit') or 0), 2),
               'lines': lines,
               'format': 'ucc-consolidation-v1'})


# ═════════════════════════════════════════════════════════════════════════════
# PERFORMANCE INDEXES (2026-06-14) — the general_ledger and related tables had no
# indexes on the columns every report filters/joins/sums (coa_id, jv_id,
# ledger_date, period, jv_number, source_module/source_id …). Without them each
# report is a full table scan that slows as the ledger grows. These are created
# idempotently at startup and backfill existing databases on deploy.
# ═════════════════════════════════════════════════════════════════════════════
def _perf_create_indexes(conn):
    stmts = [
        "CREATE INDEX IF NOT EXISTS idx_gl_coa ON general_ledger(coa_id)",
        "CREATE INDEX IF NOT EXISTS idx_gl_jv ON general_ledger(jv_id)",
        "CREATE INDEX IF NOT EXISTS idx_gl_date ON general_ledger(ledger_date)",
        "CREATE INDEX IF NOT EXISTS idx_gl_period ON general_ledger(period)",
        "CREATE INDEX IF NOT EXISTS idx_gl_jvnum ON general_ledger(jv_number)",
        "CREATE INDEX IF NOT EXISTS idx_gl_coacode ON general_ledger(coa_code)",
        "CREATE INDEX IF NOT EXISTS idx_jv_source ON journal_vouchers(source_module, source_id)",
        "CREATE INDEX IF NOT EXISTS idx_jv_revof ON journal_vouchers(reversal_of)",
        "CREATE INDEX IF NOT EXISTS idx_jv_status ON journal_vouchers(status)",
        "CREATE INDEX IF NOT EXISTS idx_jv_date ON journal_vouchers(jv_date)",
        "CREATE INDEX IF NOT EXISTS idx_actuals_jv ON actuals(jv_id)",
        "CREATE INDEX IF NOT EXISTS idx_actuals_posted ON actuals(is_posted)",
        "CREATE INDEX IF NOT EXISTS idx_fundrcpt_jv ON fund_receipts(jv_id)",
        "CREATE INDEX IF NOT EXISTS idx_audit_ts ON audit_log(timestamp)",
        "CREATE INDEX IF NOT EXISTS idx_pcv_float ON petty_cash_vouchers(float_id)",
    ]
    made = 0
    for s in stmts:
        try:
            conn.execute(s); made += 1
        except Exception:
            pass  # table may not exist yet on a brand-new DB; init_db creates them first
    try: conn.execute("ANALYZE")
    except Exception: pass
    return made

try:
    _perf_prev_init_db = init_db
    def init_db():
        res = _perf_prev_init_db()
        try:
            _c = get_db()
            try:
                n = _perf_create_indexes(_c); _c.commit()
                import sys as _ps; print('  Performance indexes ensured (%d)' % n, file=_ps.stderr)
            finally:
                _c.close()
        except Exception as _pe:
            import sys as _ps; print('Performance index warning: %s' % _pe, file=_ps.stderr)
        return res
except Exception as _pe:
    print('Performance index wrapper warning:', _pe)

# Belt-and-braces: also ensure indexes once on the first request, in case this
# deploy's init_db already ran before the wrapper was installed.
_PERF_IDX_READY = [False]
try:
    _perf_prev_getdb = get_db
    def get_db():
        conn = _perf_prev_getdb()
        if not _PERF_IDX_READY[0]:
            _PERF_IDX_READY[0] = True
            try:
                _perf_create_indexes(conn); conn.commit()
            except Exception:
                pass
        return conn
except Exception as _pe:
    print('Performance get_db wrapper warning:', _pe)


