def _ucc_seed_org_units(conn):
    """Seed the UCC tree only when org_units is empty (idempotent)."""
    try:
        existing = conn.execute("SELECT COUNT(*) FROM org_units").fetchone()[0] or 0
    except Exception:
        existing = 0
    if existing:
        return 0
    n = 0
    for code, name, utype, parent, title in UCC_ORG_UNITS:
        conn.execute(
            "INSERT OR IGNORE INTO org_units(id, code, name, unit_type, parent_code, head_title) "
            "VALUES(?,?,?,?,?,?)",
            (str(uuid.uuid4()), code, name, utype, parent, title))
        n += 1
    # Hard-require: give the bootstrap/system accounts a Central Administration (REG)
    # home unit now that the tree exists, so their writes attribute to Central (never
    # NULL, never the consolidation root). Idempotent — only fills a blank home unit.
    try:
        _dc = conn.execute("SELECT value FROM settings WHERE key='default_unit_code'").fetchone()
        _code = (_dc[0] if _dc else None) or 'REG'
        _reg = conn.execute("SELECT id FROM org_units WHERE code=? LIMIT 1", (_code,)).fetchone() \
               or conn.execute("SELECT id FROM org_units WHERE code='REG' LIMIT 1").fetchone()
        if _reg:
            conn.execute("UPDATE users SET home_unit_id=? WHERE username IN ('admin','demo') AND (home_unit_id IS NULL OR home_unit_id='')", (_reg[0],))
    except Exception:
        pass
    return n


def _ucc_init_org_units():
    conn = get_db()
    try:
        conn.executescript("""
        CREATE TABLE IF NOT EXISTS org_units (
            id TEXT PRIMARY KEY,
            code TEXT UNIQUE NOT NULL,
            name TEXT NOT NULL,
            unit_type TEXT NOT NULL,
            parent_code TEXT,
            head_name TEXT,
            head_title TEXT,
            head_email TEXT,
            status TEXT DEFAULT 'Active',
            created_at TEXT DEFAULT (datetime('now'))
        );
        CREATE INDEX IF NOT EXISTS idx_org_units_parent ON org_units(parent_code);
        """)
        seeded = _ucc_seed_org_units(conn)
        conn.commit()
        if seeded:
            import sys as _s; print('  UCC org_units seeded (%d nodes)' % seeded, file=_s.stderr)
    finally:
        conn.close()


try:
    _ucc_orgunits_prev_init_db = init_db
    def init_db():
        _ucc_orgunits_prev_init_db()
        try:
            _ucc_init_org_units()
        except Exception as exc:
            import sys as _s; print('UCC org_units migration warning:', exc, file=_s.stderr)
except Exception as _e:
    print('UCC org_units wrapper warning:', _e)


def api_org_units(session):
    """GET /api/org-units — the full UCC organisational hierarchy as a flat list
    (each node carries its parent_code; the client builds the tree). Read-only;
    this is the addressing backbone for unit scoping and node roll-up reporting."""
    if not session:
        return {'ok': False, 'error': 'Not authenticated'}
    conn = get_db()
    try:
        rows = conn.execute(
            "SELECT id, code, name, unit_type, parent_code, head_name, head_title, "
            "       head_email, status "
            "FROM org_units ORDER BY COALESCE(parent_code, ''), code").fetchall()
        return ok({'units': [dict(r) for r in rows], 'count': len(rows)})
    finally:
        conn.close()


def _upsert_org_unit(conn, data):
    """Idempotently upsert one node into org_units, keyed on the natural `code`.
    Only overwrites a column when a non-empty value is supplied, so a mirror
    upsert from a lean department save never blanks out richer org-tree fields
    (e.g. parent_code / unit_type) already present on an existing node. Returns
    the row id. Caller owns the transaction/commit."""
    code = (data.get('code') or '').strip().upper()
    if not code:
        raise ValueError('code is required')
    name = (data.get('name') or '').strip()
    existing = conn.execute(
        "SELECT id, name, unit_type, parent_code, head_name, head_title, head_email, status "
        "FROM org_units WHERE code=?", (code,)).fetchone()
    if existing:
        existing = dict(existing)
        def pick(key, cur):
            v = data.get(key)
            return v if (v is not None and str(v) != '') else cur
        conn.execute(
            "UPDATE org_units SET name=?, unit_type=?, parent_code=?, head_name=?, "
            "head_title=?, head_email=?, status=? WHERE code=?",
            (pick('name', existing['name']),
             pick('unit_type', existing['unit_type']),
             # parent_code may legitimately be cleared, so only replace when the
             # caller explicitly provided the key.
             (data.get('parent_code') if 'parent_code' in data else existing['parent_code']),
             pick('head_name', existing['head_name']),
             pick('head_title', existing['head_title']),
             pick('head_email', existing['head_email']),
             pick('status', existing['status'] or 'Active'),
             code))
        return existing['id']
    uid = str(uuid.uuid4())
    conn.execute(
        "INSERT INTO org_units(id, code, name, unit_type, parent_code, head_name, "
        "head_title, head_email, status) VALUES(?,?,?,?,?,?,?,?,?)",
        (uid, code, name or code, data.get('unit_type') or 'Department',
         data.get('parent_code'), data.get('head_name', ''),
         data.get('head_title', ''), data.get('head_email', ''),
         data.get('status') or 'Active'))
    return uid


def api_save_org_unit(data, session):
    """POST /api/org-units — create or update a node in the UCC organisational
    tree (keyed on `code`). Admin / Finance only. Additive: does not touch the
    legacy departments table or the projects.division join graph."""
    if not session:
        return {"error": "Not authenticated"}
    if session.get('role') not in ('Admin', 'Finance Officer'):
        return {"error": "Insufficient permissions"}
    conn = get_db()
    try:
        uid = _upsert_org_unit(conn, data)
        _audit(conn, session, 'SAVE_ORG_UNIT', 'org_units', uid,
               (data.get('code') or '').strip().upper())
        conn.commit()
        return ok({'id': uid, 'code': (data.get('code') or '').strip().upper()})
    except ValueError as ve:
        return err(str(ve))
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════════
# UCC INSTITUTIONAL ROLL-OUT — unit_id column propagation (Phase 0)
# Adds a nullable unit_id (→ org_units.id) to every transactional table so a
# posting can be attributed to its operating unit and rolled up at any node.
# Strictly additive: the column is nullable and is NOT yet read or written by
# any existing code path, so current single-entity behaviour is unchanged. We
# ensure the columns on the first DB request (mirroring the perf-index wrapper)
# because target tables are created across several init_* functions and later
# migrations; by the first request they all exist.
#
# NOTE — backfill: a fresh per-unit UCC deployment starts with no transactions
# (institutional_reset clears them), so there is nothing to backfill. Backfill
# from a legacy populated single-entity DB is a separate, explicit migration
# performed at cut-over once each unit's org_units node is assigned.
# ═══════════════════════════════════════════════════════════════════════════
_UCC_UNITID_TABLES = [
    'general_ledger', 'journal_vouchers', 'jv_lines', 'actuals', 'fund_receipts',
    'payroll_register', 'asset_register', 'budgets', 'dept_allocations', 'commitments',
    'ar_invoices', 'ar_receipts', 'ar_credit_notes', 'ap_bills', 'ap_payments',
    'purchase_orders', 'purchase_requisitions', 'goods_received_notes',
    'petty_cash_vouchers', 'petty_cash_floats', 'inv_movements', 'bank_accounts', 'interunit_transfers',
    'projects', 'quarterly_budgets', 'employees',
]


_UCC_UNITID_DONE = set()


def _ucc_ensure_unit_id_columns(conn):
    """Add a nullable unit_id column to each transactional table that lacks it.
    Self-correcting and idempotent: a table is processed only once (recorded in
    _UCC_UNITID_DONE the moment it has the column); tables that do not yet exist
    (the AR/AP/inventory/petty-cash modules create theirs lazily on first use)
    are simply retried on a later call. Table names come from a fixed,
    code-controlled allow-list (PRAGMA/ALTER cannot be parameterised)."""
    added = 0
    for t in _UCC_UNITID_TABLES:
        if t in _UCC_UNITID_DONE:
            continue
        try:
            if not conn.execute(
                    "SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (t,)).fetchone():
                continue  # not created yet — retry on a later get_db()
            cols = [r[1] for r in conn.execute("PRAGMA table_info(%s)" % t).fetchall()]
            if 'unit_id' not in cols:
                conn.execute("ALTER TABLE %s ADD COLUMN unit_id TEXT" % t)
                added += 1
            # Interunit transfers carry a sending and a receiving unit; the single
            # unit_id is left for compatibility but from/to drive the clearing JV.
            if t == 'interunit_transfers':
                for _c in ('from_unit_id', 'to_unit_id'):
                    if _c not in cols:
                        conn.execute("ALTER TABLE interunit_transfers ADD COLUMN %s TEXT" % _c)
                        added += 1
            # Fixed assets carry an owner/custodian code in addition to unit_id.
            if t == 'asset_register' and 'owner_code' not in cols:
                conn.execute("ALTER TABLE asset_register ADD COLUMN owner_code TEXT")
                added += 1
            _UCC_UNITID_DONE.add(t)  # column present (added or pre-existing) — never re-check
        except Exception:
            pass
    if added:
        try:
            conn.commit()
            import sys as _s; print('  UCC unit_id columns ensured (+%d)' % added, file=_s.stderr)
        except Exception:
            pass
    return added


_UCC_USERSCOPE_DONE = [False]


def _ucc_ensure_user_scope_columns(conn):
    """Add user↔unit assignment columns: home_unit_id (→ org_units.id) and scope
    (own_unit | subtree | university). Additive and idempotent. Existing Admin
    accounts are defaulted to 'university' scope and everyone else to 'own_unit'
    so that when enforcement is switched on, administrators already see the whole
    institution. Nothing reads these columns yet, so behaviour is unchanged."""
    try:
        cols = [r[1] for r in conn.execute("PRAGMA table_info(users)").fetchall()]
    except Exception:
        return False
    if not cols:
        return False  # users table not created yet
    changed = False
    if 'home_unit_id' not in cols:
        conn.execute("ALTER TABLE users ADD COLUMN home_unit_id TEXT")
        changed = True
    if 'scope' not in cols:
        conn.execute("ALTER TABLE users ADD COLUMN scope TEXT")
        changed = True
    # Default any unfilled scope (idempotent). Runs until no NULLs remain so that
    # accounts force-created late in startup (e.g. the demo Admin) are also covered;
    # then the latch trips and this becomes a single fast count query.
    try:
        unfilled = conn.execute(
            "SELECT COUNT(*) FROM users WHERE scope IS NULL OR scope=''").fetchone()[0] or 0
    except Exception:
        unfilled = 0
    if unfilled:
        conn.execute("UPDATE users SET scope='university' WHERE role='Admin' AND (scope IS NULL OR scope='')")
        conn.execute("UPDATE users SET scope='own_unit' WHERE scope IS NULL OR scope=''")
        changed = True
    if changed:
        try:
            conn.commit()
            import sys as _s; print('  UCC user scope columns ensured', file=_s.stderr)
        except Exception:
            pass
    # Latch only once columns exist AND every user has a scope.
    if not unfilled:
        _UCC_USERSCOPE_DONE[0] = True
    return changed


try:
    _ucc_prev_getdb_unitid = get_db
    def get_db():
        conn = _ucc_prev_getdb_unitid()
        # Steady state is a single boolean/length compare (zero overhead once all
        # columns exist). Before that, ensure columns as tables appear.
        if len(_UCC_UNITID_DONE) < len(_UCC_UNITID_TABLES):
            try:
                _ucc_ensure_unit_id_columns(conn)
            except Exception:
                pass
        if not _UCC_USERSCOPE_DONE[0]:
            try:
                _ucc_ensure_user_scope_columns(conn)
            except Exception:
                pass
        return conn
except Exception as _e:
    print('UCC unit_id get_db wrapper warning:', _e)


def _ucc_default_unit_id(conn):
    """The institutional default org unit (University / Central level) used when a
    transaction specifies no unit and the poster has no home unit. Configurable via
    the 'default_unit_code' setting; otherwise the root (parent-less) node, else 'UCC'.
    Cached on the connection to avoid repeat lookups. Returns None only if org_units
    is empty (pure single-entity install), preserving legacy NULL behaviour."""
    try:
        cached = getattr(conn, '_ucc_default_unit', '__unset__')
        if cached != '__unset__':
            return cached
    except Exception:
        cached = '__unset__'
    val = None
    try:
        code = None
        try:
            r = conn.execute("SELECT value FROM settings WHERE key='default_unit_code'").fetchone()
            code = (r['value'] if r else None) or None
        except Exception:
            code = None
        if code:
            r = conn.execute("SELECT id FROM org_units WHERE code=?", (code,)).fetchone()
            if r:
                val = r['id']
        if not val:
            r = conn.execute("SELECT id FROM org_units WHERE parent_code IS NULL OR parent_code='' ORDER BY rowid LIMIT 1").fetchone()
            if r:
                val = r['id']
        if not val:
            r = conn.execute("SELECT id FROM org_units WHERE code='UCC' LIMIT 1").fetchone()
            val = r['id'] if r else None
    except Exception:
        val = None
    try:
        conn._ucc_default_unit = val
    except Exception:
        pass
    return val


def _ucc_resolve_write_unit(conn, data, session):
    """Resolve the org unit to stamp on a new transaction (Phase 1b).
    Precedence: an explicit unit_id in the request (a university/Admin user posting
    on behalf of a unit) → the creating user's home unit → the institutional default
    (University / Central node). Never leaves the entry unattributed when an org
    structure exists, so consolidation is complete (no NULL leakage)."""
    try:
        u = (data or {}).get('unit_id')
        if u:
            return u
        uname = (session or {}).get('username')
        role = (session or {}).get('role', '')
        scope = None
        if uname:
            row = conn.execute("SELECT home_unit_id, scope FROM users WHERE username=?", (uname,)).fetchone()
            if row:
                hv = row['home_unit_id'] if 'home_unit_id' in row.keys() else None
                if hv:
                    return hv
                scope = row['scope'] if 'scope' in row.keys() else None
        # Admin / university-scope users not bound to a single unit are posting at the
        # CENTRAL level, so default them to the Central Administration node. This is the
        # only auto-attribution: it is role-justified (they answer for the centre), and
        # it keeps the admin-run acceptance suites and system jobs working.
        if role == 'Admin' or scope == 'university':
            return _ucc_default_unit_id(conn)
        # Hard-require: an ordinary user with no explicit unit and no home unit → None,
        # so the write path rejects with a clear "select a unit" error (no silent default).
        return None
    except Exception:
        return None


def _ucc_require_unit_guard(data, session, doc='transaction'):
    """Hard-require an org unit for a write. Mirrors the proven JV guard: opens a
    short-lived connection, asks _ucc_resolve_write_unit, and returns a clear reject
    envelope when it resolves to None — i.e. ONLY an ordinary user with no explicit
    unit_id and no home unit is blocked. Admin / university-scope posters resolve to
    the Central node, so admin-run suites and system jobs are never blocked. Returns
    None when the write may proceed."""
    try:
        if '_ucc_resolve_write_unit' not in globals():
            return None
        conn = get_db()
        try:
            if not _ucc_resolve_write_unit(conn, data, session):
                return {'ok': False,
                        'error': 'A unit / cost centre must be selected for this %s.' % doc}
        finally:
            conn.close()
    except Exception:
        # Fail open on guard error (never break a save because the guard itself raised);
        # the resolver already fails safe, and admin/system paths must keep working.
        return None
    return None


# ═══════════════════════════════════════════════════════════════════════════
# UCC INSTITUTIONAL ROLL-OUT — read-side scope + node roll-up (Phase 1c / 3e)
# One mechanism serves both: it constrains the General Ledger read surface to the
# org units a viewer is entitled to (enforcement) and/or to a requested node's
# subtree (consolidation drill-down). Admins and university-scope users are
# unrestricted; everyone else sees only their unit (own_unit) or their unit and
# all descendants (subtree). All financial statements derive from the GL, so
# filtering the GL cascades to every report.
# ═══════════════════════════════════════════════════════════════════════════
def _ucc_subtree_unit_ids(conn, root):
    """Set of org_units.id for `root` (id or code) and all its descendants."""
    if not root:
        return set()
    try:
        row = conn.execute("SELECT id, code FROM org_units WHERE id=? OR code=?", (root, root)).fetchone()
        if not row:
            return set()
        codes = {row['code']}
        frontier = [row['code']]
        while frontier:
            qs = ','.join('?' * len(frontier))
            nxt = []
            for r in conn.execute(
                    "SELECT code FROM org_units WHERE parent_code IN (%s)" % qs, frontier).fetchall():
                if r['code'] not in codes:
                    codes.add(r['code']); nxt.append(r['code'])
            frontier = nxt
        qs = ','.join('?' * len(codes))
        return {r['id'] for r in conn.execute(
            "SELECT id FROM org_units WHERE code IN (%s)" % qs, list(codes)).fetchall()}
    except Exception:
        return set()


def _ucc_resolve_read_scope(conn, session):
    """Enforced read scope for the session. Returns None for UNRESTRICTED
    (Admin role or scope='university'); otherwise the set of org_units.id the
    user may read. A non-university user with no home unit assigned returns an
    EMPTY set (sees nothing) — onboarding must assign a home unit."""
    if not session:
        return set()
    try:
        if (session.get('role') or '') == 'Admin':
            return None
        uname = session.get('username')
        row = conn.execute("SELECT home_unit_id, scope FROM users WHERE username=?", (uname,)).fetchone() if uname else None
        scope = (row['scope'] if row and 'scope' in row.keys() else None) or 'own_unit'
        if scope == 'university':
            return None
        home = row['home_unit_id'] if row and 'home_unit_id' in row.keys() else None
        if not home:
            return set()
        if scope == 'subtree':
            return _ucc_subtree_unit_ids(conn, home)
        return {home}
    except Exception:
        # [M3] FAIL CLOSED for non-Admin. Admins are already returned None
        # (unrestricted) earlier in this function, so reaching here means the
        # session is non-Admin (or unknown): deny by returning an EMPTY scope
        # rather than failing open to the whole institution.
        return set()


def _ucc_gl_scope_clause(conn, session, requested=None, alias='gl'):
    """Build an ' AND <alias>.unit_id IN (...)' clause combining the viewer's
    enforced scope with an optionally requested node (subtree). Returns
    (sql_fragment, params). Empty fragment = no restriction."""
    enforced = _ucc_resolve_read_scope(conn, session)          # None=unrestricted, else set
    req = _ucc_subtree_unit_ids(conn, requested) if requested else None
    if enforced is None and req is None:
        return '', []
    if enforced is None:
        eff = req
    elif req is None:
        eff = enforced
    else:
        eff = enforced & req
    eff = eff or set()
    if not eff:
        return ' AND 1=0', []
    ids = list(eff)
    return ' AND %s.unit_id IN (%s)' % (alias, ','.join('?' * len(ids))), ids


# ═══════════════════════════════════════════════════════════════════════════
# UCC INSTITUTIONAL ROLL-OUT — source-document unit scoping (refinement)
# Stamp unit_id on operational source rows (payment vouchers, fund receipts) at
# save and filter their LIST endpoints to the viewer's scope, so a unit user's
# transaction lists match their unit-scoped ledger. Uses the existing
# wrap-and-delegate idiom; the (heavily patched) base inserts are untouched.
# Admin/university viewers are unrestricted, so admin-run suites are unaffected.
# ═══════════════════════════════════════════════════════════════════════════
def _ucc_stamp_source_unit(table, row_id, data, session):
    """Best-effort: set <table>.unit_id once (never overwrite) on a saved row."""
    if not row_id:
        return
    try:
        conn = get_db()
        try:
            wu = _ucc_resolve_write_unit(conn, data, session)
            if wu:
                conn.execute("UPDATE %s SET unit_id=? WHERE id=? AND (unit_id IS NULL OR unit_id='')" % table,
                             (wu, row_id))
                conn.commit()
        finally:
            conn.close()
    except Exception:
        pass


def _ucc_filter_rows_by_scope(rows, session):
    """Restrict rows to the viewer's unit scope. Handles both a flat list of row
    dicts AND an envelope dict (e.g. {'ok':True,'invoices':[...]}) by filtering any
    contained list-of-rows that carries unit_id. Admin/university viewers are
    unrestricted; rows without a unit are hidden from scoped users."""
    try:
        conn = get_db()
        try:
            enforced = _ucc_resolve_read_scope(conn, session)
        finally:
            conn.close()
        if enforced is None:
            return rows
        def _filt(lst):
            return [r for r in lst if isinstance(r, dict) and r.get('unit_id') in enforced]
        if isinstance(rows, list):
            return _filt(rows)
        if isinstance(rows, dict):
            out = dict(rows)
            for k, v in list(out.items()):
                if (isinstance(v, list) and v and all(isinstance(x, dict) for x in v)
                        and any('unit_id' in x for x in v)):
                    out[k] = _filt(v)
            return out
        return rows
    except Exception:
        return rows


try:
    def _ucc_general_project_id():
        """Id of the standing 'General / Non-Grant Operations' cost centre, created once.
        A general (non-grant) expense has no research project; the form posts project_id=''
        which previously failed (FK, then NOT NULL on actuals.project_id). Attributing such
        spend to a real General Operations cost centre lets it save AND report correctly."""
        conn = get_db()
        try:
            row = conn.execute("SELECT id FROM projects WHERE project_code=?", ('UCC-GENERAL',)).fetchone()
            if row:
                return row['id']
            import uuid as _u
            pid = str(_u.uuid4())
            conn.execute(
                "INSERT INTO projects(id,project_code,title,donor,division,start_date,end_date,currency,budget_fcy,fx_rate,budget_ghs,status,created_by) "
                "VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                (pid, 'UCC-GENERAL', 'General / Non-Grant Operations', 'University of Cape Coast', 'General Operations',
                 '2020-01-01', '2099-12-31', 'GHS', 0, 1, 0, 'Active', 'system'))
            conn.commit()
            return pid
        except Exception:
            try:
                row = conn.execute("SELECT id FROM projects WHERE project_code=?", ('UCC-GENERAL',)).fetchone()
                return row['id'] if row else None
            except Exception:
                return None
        finally:
            conn.close()

    _ucc_prev_save_actual = api_save_actual
    def api_save_actual(data, session):
        _g = _ucc_require_unit_guard(data, session, 'payment voucher')
        if _g: return _g
        # Attribute a general (non-grant) expense to the standing General Operations
        # cost centre so it satisfies the NOT NULL actuals.project_id and reports cleanly.
        try:
            if isinstance(data, dict) and not str(data.get('project_id') or '').strip():
                data['project_id'] = _ucc_general_project_id()
        except Exception:
            pass
        res = _ucc_prev_save_actual(data, session)
        try:
            if isinstance(res, dict) and res.get('ok') and res.get('id'):
                _ucc_stamp_source_unit('actuals', res.get('id'), data, session)
        except Exception:
            pass
        return res
except Exception as _e:
    print('UCC actual unit-stamp wrapper warning:', _e)

