def _ucc_scope_pc2_state(env, session):
    """Tailored scope filter for the petty-cash state payload: floats and vouchers
    by unit; replenishments/counts by their surviving float ids."""
    try:
        if not isinstance(env, dict):
            return env
        conn = get_db()
        try:
            enforced = _ucc_resolve_read_scope(conn, session)
        finally:
            conn.close()
        if enforced is None:
            return env
        out = dict(env)
        floats = [f for f in env.get('floats', []) if isinstance(f, dict) and f.get('unit_id') in enforced]
        fids = {f.get('id') for f in floats}
        out['floats'] = floats
        out['vouchers'] = [v for v in env.get('vouchers', [])
                           if isinstance(v, dict) and (v.get('unit_id') in enforced or v.get('float_id') in fids)]
        out['replenishments'] = [r for r in env.get('replenishments', [])
                                 if isinstance(r, dict) and r.get('float_id') in fids]
        out['counts'] = [c for c in env.get('counts', []) if isinstance(c, dict) and c.get('float_id') in fids]
        out['total_book_balance'] = round(sum(float(f.get('book_balance') or 0) for f in floats), 2)
        return out
    except Exception:
        return env


